pub(crate) fn maybe_prepare<'data>(
    args: &impl platform::Args,
    file_loader: &FileLoader<'data>,
) -> Result<PreparedState<'data>> {
    if !args.common().incremental {
        return Ok(PreparedState {
            mode: IncrementalMode::Disabled,
            current: CurrentState {
                state_dir: state_dir_for_output(args.output()),
                args_hash: String::new(),
                link_options_hash: String::new(),
                input_order_hash: String::new(),
                sld_version: String::new(),
                link_start: None,
                input_files: Vec::new(),
            },
            retained_output_to_restore: None,
            reusable_inputs: HashSet::new(),
            reusable_changed_sections: HashSet::new(),
            previous_sections: HashSet::new(),
            previous_relocations: Vec::new(),
            previous_macho_symbol_resolutions_file: None,
            previous_fdes: Vec::new(),
            previous_dynamic_relocations: Vec::new(),
            previous_reserved_ranges: Vec::new(),
            current_sections: RecordBuffers::default(),
            current_relocations: RecordBuffers::default(),
            current_macho_symbol_resolutions: RecordBuffers::default(),
            current_fdes: RecordBuffers::default(),
            current_dynamic_relocations: RecordBuffers::default(),
            current_reserved_ranges: RecordBuffers::default(),
            record_texts: RecordTextInterner::default(),
            reused_sections: AtomicUsize::new(0),
            prepared_fast_build_id_state: Mutex::new(None),
        });
    }

    timing_phase!("Prepare incremental link");

    let state_dir = state_dir_for_output(args.output());
    let previous_metadata = PersistedState::read_metadata(&state_dir);
    let retained_output_to_restore = if args.should_retain_output_snapshot()
        && let Ok(Some(previous)) = &previous_metadata
        && !args.output().try_exists().unwrap_or(false)
    {
        match retained_output_snapshot_matches_previous(&state_dir, &previous.output, args.output())
        {
            Ok(true) => Some(previous.output.clone()),
            Ok(false) => None,
            Err(error) => {
                append_log(
                    &state_dir,
                    &format!("retained output restoration unavailable: {error:?}"),
                )?;
                None
            }
        }
    } else {
        None
    };
    let current = CurrentState::new(
        args,
        file_loader,
        previous_metadata.as_ref().ok().and_then(|p| p.as_ref()),
    );
    log_incremental_link_options_if_requested(
        args,
        &state_dir,
        std::env::var(LOG_INCREMENTAL_LINK_OPTIONS_ENV).is_ok_and(|value| value == "1"),
        std::env::var(LOG_INCREMENTAL_EXACT_ARGS_ENV).is_ok_and(|value| value == "1"),
    )?;
    let (mut mode, previous_metadata) = match previous_metadata {
        Ok(Some(previous)) => (
            classify_incremental_mode_with_output_policy(
                args.output(),
                &current,
                &previous,
                args.should_trust_persistent_output_data_identity(),
                retained_output_to_restore.is_some(),
            ),
            Some(previous),
        ),
        Ok(None) => (
            IncrementalMode::Relink {
                reason: "no previous incremental state".to_owned(),
                can_reuse_unchanged_sections: false,
            },
            None,
        ),
        Err(error) => (
            IncrementalMode::Relink {
                reason: format!("could not read previous incremental state: {error:?}"),
                can_reuse_unchanged_sections: false,
            },
            None,
        ),
    };

    let mut previous_sections = HashSet::new();
    let mut previous_relocations = Vec::new();
    let mut previous_macho_symbol_resolutions_file = None;
    let mut previous_fdes = Vec::new();
    let mut previous_dynamic_relocations = Vec::new();
    let mut previous_reserved_ranges = Vec::new();
    if mode_needs_previous_sections(&mode) {
        match PersistedState::read(&state_dir) {
            Ok(Some(previous)) => {
                previous_sections = previous.sections.iter().cloned().collect();
                previous_relocations = previous.relocations;
                previous_macho_symbol_resolutions_file = previous.macho_symbol_resolutions_file;
                previous_fdes = previous.fdes;
                previous_dynamic_relocations = previous.dynamic_relocations;
                previous_reserved_ranges = previous.reserved_ranges;
            }
            Ok(None) => {
                mode = IncrementalMode::Relink {
                    reason: "no previous incremental state".to_owned(),
                    can_reuse_unchanged_sections: false,
                };
            }
            Err(error) => {
                mode = IncrementalMode::Relink {
                    reason: format!("could not read previous incremental state: {error:?}"),
                    can_reuse_unchanged_sections: false,
                };
            }
        }
    }

    current.log_mode(&mode)?;

    let reusable_inputs = previous_metadata
        .as_ref()
        .map(|previous| reusable_input_files(&current.input_files, &previous.input_files))
        .unwrap_or_default();
    let reusable_changed_sections = if mode_needs_previous_sections(&mode)
        && rustc_work_product_provenance_enabled()
        && let Some(previous) = previous_metadata.as_ref()
    {
        match reusable_changed_rust_archive_sections(
            file_loader,
            &current.input_files,
            &previous.input_files,
            &previous_sections,
        ) {
            Ok(sections) => {
                if !sections.is_empty() {
                    append_log(
                        &state_dir,
                        &format!(
                            "prepared {} unchanged Rust archive member section{} for relink reuse",
                            sections.len(),
                            if sections.len() == 1 { "" } else { "s" },
                        ),
                    )?;
                }
                sections
            }
            Err(error) => {
                append_log(
                    &state_dir,
                    &format!("Rust archive member relink reuse unavailable: {error:?}"),
                )?;
                HashSet::new()
            }
        }
    } else {
        HashSet::new()
    };
    let retained_output_to_restore = matches!(mode, IncrementalMode::Reuse)
        .then_some(retained_output_to_restore)
        .flatten();

    Ok(PreparedState {
        mode,
        current,
        retained_output_to_restore,
        reusable_inputs,
        reusable_changed_sections,
        previous_sections,
        previous_relocations,
        previous_macho_symbol_resolutions_file,
        previous_fdes,
        previous_dynamic_relocations,
        previous_reserved_ranges,
        current_sections: RecordBuffers::default(),
        current_relocations: RecordBuffers::default(),
        current_macho_symbol_resolutions: RecordBuffers::default(),
        current_fdes: RecordBuffers::default(),
        current_dynamic_relocations: RecordBuffers::default(),
        current_reserved_ranges: RecordBuffers::default(),
        record_texts: RecordTextInterner::default(),
        reused_sections: AtomicUsize::new(0),
        prepared_fast_build_id_state: Mutex::new(None),
    })
}

fn mode_needs_previous_sections(mode: &IncrementalMode) -> bool {
    matches!(
        mode,
        IncrementalMode::Reuse
            | IncrementalMode::Relink {
                can_reuse_unchanged_sections: true,
                ..
            }
    )
}

pub(crate) fn maybe_reuse_output_before_loading(args: &impl platform::Args) -> Result<bool> {
    maybe_reuse_output_before_loading_with_rustc_link_content_digest_trust(
        args,
        rustc_work_product_provenance_enabled(),
    )
}

fn maybe_reuse_output_before_loading_with_rustc_link_content_digest_trust(
    args: &impl platform::Args,
    trust_rustc_link_content_digests: bool,
) -> Result<bool> {
    if !args.common().incremental {
        return Ok(false);
    }

    let state_dir = state_dir_for_output(args.output());
    if maybe_reuse_output_during_publication(args, &state_dir)? {
        return Ok(true);
    }
    let _state_lock = acquire_incremental_state_lock(&state_dir)?;
    let current_link_start = write_link_start_marker(&state_dir)?;

    if args.should_write_trace_file() || args.common().save_dir.is_active() {
        return Ok(false);
    }
    if args
        .dependency_file()
        .is_some_and(|dependency_file| !dependency_file.exists())
    {
        return Ok(false);
    }

    timing_phase!("Check incremental fast path");

    if let Some(reason) = interrupted_update_relink_reason(&state_dir) {
        append_log(
            &state_dir,
            &format!("incremental fast path unavailable before loading inputs: {reason}"),
        )?;
        return Ok(false);
    }

    let Some(mut previous) = ({
        timing_phase!("Read incremental fast-path metadata");
        PersistedState::read_metadata(&state_dir).unwrap_or_default()
    }) else {
        return Ok(false);
    };

    if previous.args_hash != args_hash(args) {
        return Ok(false);
    }
    let current_sld_version = sld_version(args);
    if sld_version_relink_reason(previous.sld_version.as_deref(), &current_sld_version).is_some() {
        return Ok(false);
    }
    if previous.needs_indexed_macho_resolution_migration() {
        append_log(
            &state_dir,
            "incremental fast path unavailable before loading inputs: indexed records need Mach-O resolution migration",
        )?;
        return Ok(false);
    }
    let retained_output_to_restore = if args.should_retain_output_snapshot()
        && !args.output().try_exists().unwrap_or(false)
    {
        match retained_output_snapshot_matches_previous(&state_dir, &previous.output, args.output())
        {
            Ok(true) => Some(previous.output.clone()),
            Ok(false) => return Ok(false),
            Err(error) => {
                append_log(
                    &state_dir,
                    &format!("retained output restoration unavailable: {error:?}"),
                )?;
                return Ok(false);
            }
        }
    } else {
        None
    };
    if retained_output_to_restore.is_none()
        && !{
            timing_phase!("Validate incremental fast-path output content");
            output_content_matches_previous(
                &previous.output,
                args.output(),
                args.should_trust_persistent_output_data_identity(),
            )?
        }
    {
        return Ok(false);
    }

    let mut changed_inputs = Vec::new();
    let mut rewritten_inputs = Vec::new();
    let mut checked_ambiguous_inputs = false;
    let input_checks = {
        timing_phase!("Check incremental fast-path input contents");
        previous
            .input_files
            .par_iter()
            .enumerate()
            .map(|(index, input)| {
                let path = decode_path(&input.path)?;
                if input.content.identity_matches_path(&path)? {
                    if input_content_is_anchored_before_link_start(
                        input,
                        previous.link_start.as_ref(),
                    ) || !input
                        .content
                        .identity_is_ambiguous_since(previous.link_start.as_ref())
                    {
                        return Ok((None, None, false));
                    }
                    if input_content_matches_previous(&state_dir, input, &path)? {
                        return Ok((None, None, true));
                    }
                    return Ok((Some((index, path)), None, true));
                }
                if args.should_patch_changed_inputs_before_loading()
                    && (input.patch.is_some()
                        || (trust_rustc_link_content_digests
                            && input.rustc_link_content_digest.is_some()))
                {
                    // The patcher must read a changed input under a stable identity anyway. Let it
                    // classify patchable identity replacements during that read instead of hashing
                    // the same large archive first.
                    return Ok((Some((index, path)), None, false));
                }
                if input_content_matches_previous(&state_dir, input, &path)? {
                    return Ok((None, Some((index, path)), false));
                }
                Ok((Some((index, path)), None, false))
            })
            .collect::<Result<Vec<_>>>()?
    };
    for (changed_input, rewritten_input, checked_ambiguous_input) in input_checks {
        if let Some(changed_input) = changed_input {
            changed_inputs.push(changed_input);
        }
        if let Some(rewritten_input) = rewritten_input {
            rewritten_inputs.push(rewritten_input);
        }
        checked_ambiguous_inputs |= checked_ambiguous_input;
    }

    if !rewritten_inputs.is_empty() {
        timing_phase!("Snapshot rewritten incremental inputs");
        snapshot_input_paths(
            &state_dir,
            rewritten_inputs
                .iter()
                .filter(|(input_index, _)| {
                    previous
                        .input_files
                        .get(*input_index)
                        .is_none_or(|input| input.snapshot_identity.is_none())
                })
                .map(|(_, path)| path.as_path()),
        )?;
        refresh_snapshotted_rewritten_input_metadata(&state_dir, &mut previous, &rewritten_inputs);
    }

    if !changed_inputs.is_empty() {
        if retained_output_to_restore.is_some() {
            append_log(
                &state_dir,
                "changed-input patch unavailable before loading inputs: missing retained output requires full relink",
            )?;
            return Ok(false);
        }
        if !args.should_patch_changed_inputs_before_loading() {
            append_log(
                &state_dir,
                "changed-input patch unavailable before loading inputs: signed Mach-O output requires full relink",
            )?;
            return Ok(false);
        }
        let preclassified_unchanged_inputs =
            preclassify_unchanged_rustc_rlibs_by_link_content_digest(
                args,
                &previous,
                &changed_inputs,
                trust_rustc_link_content_digests,
            );
        apply_preclassified_unchanged_rustc_rlibs(&mut previous, &preclassified_unchanged_inputs);
        if !preclassified_unchanged_inputs.is_empty() {
            append_log(
                &state_dir,
                &format!(
                    "classified {} unchanged Rust archive input file{} by rustc link-content digest before loading indexed records",
                    preclassified_unchanged_inputs.len(),
                    if preclassified_unchanged_inputs.len() == 1 {
                        ""
                    } else {
                        "s"
                    },
                ),
            )?;
        }
        let changed_inputs_to_patch = changed_inputs
            .iter()
            .filter(|(input_index, _)| !preclassified_unchanged_inputs.contains_key(input_index))
            .cloned()
            .collect::<Vec<_>>();
        let changed_input_indices = changed_inputs_to_patch
            .iter()
            .map(|(input_index, _)| *input_index)
            .collect::<HashSet<_>>();
        let metadata_update_input_indices =
            metadata_update_indices_for_inputs(&changed_inputs, &rewritten_inputs);
        if changed_input_indices.iter().any(|index| {
            previous.input_files[*index]
                .patch
                .as_ref()
                .is_some_and(|patch| patch.sections.is_empty() && patch.raw_sections.is_none())
        }) {
            timing_phase!("Read changed-input patch metadata");
            previous.read_patch_metadata_for_input_indices(&state_dir, &changed_input_indices)?;
        }
        let should_filter_records = previous.patch_records_file.is_some()
            || previous
                .sections_file
                .as_deref()
                .is_some_and(|sections_file| {
                    should_filter_sections_sidecar(&state_dir, sections_file)
                });
        let should_retry_with_full_state = should_filter_records;
        let mut attempted_filtered_records = false;
        let changed_input_files = changed_inputs_to_patch
            .iter()
            .map(|(input_index, _)| previous.input_files[*input_index].path.clone())
            .collect::<HashSet<_>>();
        let should_start_with_filtered_records = should_filter_records
            && (changed_inputs_have_macho_text_patch_sections(&previous, &changed_inputs_to_patch)
                || changed_inputs_need_records_to_derive_patch_metadata(
                    &previous,
                    &changed_inputs_to_patch,
                ));
        let changed_archive_member_set = should_start_with_filtered_records
            && changed_inputs_have_archive_member_set_changes(
                &previous,
                &changed_inputs_to_patch,
                args.should_normalize_rust_archive_patch_inputs(),
            )?;
        let result = if changed_archive_member_set {
            let Some(mut full_previous) = PersistedState::read(&state_dir)? else {
                return Ok(false);
            };
            refresh_snapshotted_rewritten_input_metadata(
                &state_dir,
                &mut full_previous,
                &rewritten_inputs,
            );
            apply_preclassified_unchanged_rustc_rlibs(
                &mut full_previous,
                &preclassified_unchanged_inputs,
            );
            append_log(
                &state_dir,
                "loaded complete records for changed archive member set before loading inputs",
            )?;
            patch_changed_inputs(
                args,
                &state_dir,
                full_previous,
                current_link_start.clone(),
                ChangedInputRecordCoverage::Complete,
                &changed_inputs_to_patch,
                &metadata_update_input_indices,
            )?
        } else if should_start_with_filtered_records {
            let complete_macho_symbol_resolutions =
                previous.read_records_for_input_files(&state_dir, &changed_input_files)?;
            append_log(
                &state_dir,
                &format!(
                    "loaded records for {} changed input file{} before loading inputs",
                    changed_input_files.len(),
                    if changed_input_files.len() == 1 {
                        ""
                    } else {
                        "s"
                    },
                ),
            )?;
            attempted_filtered_records = true;
            patch_changed_inputs(
                args,
                &state_dir,
                previous,
                current_link_start.clone(),
                if complete_macho_symbol_resolutions {
                    ChangedInputRecordCoverage::ChangedInputsWithCompleteMachOResolutions
                } else {
                    ChangedInputRecordCoverage::ChangedInputs
                },
                &changed_inputs_to_patch,
                &metadata_update_input_indices,
            )?
        } else if should_filter_records {
            let result = patch_changed_inputs(
                args,
                &state_dir,
                previous,
                current_link_start.clone(),
                ChangedInputRecordCoverage::MetadataOnly,
                &changed_inputs_to_patch,
                &metadata_update_input_indices,
            )?;
            if changed_input_patch_should_retry_with_filtered_records(&result) {
                let reason = match result {
                    ChangedInputPatchResult::Unsupported(reason)
                    | ChangedInputPatchResult::RequiresChangedInputRecords(reason) => reason,
                    _ => unreachable!("filtered-record retry requires a record-dependent result"),
                };
                append_log(
                    &state_dir,
                    &format!(
                        "metadata-only changed-input patch unavailable before loading inputs: {reason}"
                    ),
                )?;
                let Some(mut previous) = PersistedState::read_metadata(&state_dir)? else {
                    return Ok(false);
                };
                refresh_snapshotted_rewritten_input_metadata(
                    &state_dir,
                    &mut previous,
                    &rewritten_inputs,
                );
                apply_preclassified_unchanged_rustc_rlibs(
                    &mut previous,
                    &preclassified_unchanged_inputs,
                );
                previous
                    .read_patch_metadata_for_input_indices(&state_dir, &changed_input_indices)?;
                let complete_macho_symbol_resolutions =
                    previous.read_records_for_input_files(&state_dir, &changed_input_files)?;
                append_log(
                    &state_dir,
                    &format!(
                        "loaded records for {} changed input file{} before loading inputs",
                        changed_input_files.len(),
                        if changed_input_files.len() == 1 {
                            ""
                        } else {
                            "s"
                        },
                    ),
                )?;
                attempted_filtered_records = true;
                patch_changed_inputs(
                    args,
                    &state_dir,
                    previous,
                    current_link_start.clone(),
                    if complete_macho_symbol_resolutions {
                        ChangedInputRecordCoverage::ChangedInputsWithCompleteMachOResolutions
                    } else {
                        ChangedInputRecordCoverage::ChangedInputs
                    },
                    &changed_inputs_to_patch,
                    &metadata_update_input_indices,
                )?
            } else {
                result
            }
        } else {
            let mut record_coverage = previous
                .sections_file
                .is_none()
                .then_some(ChangedInputRecordCoverage::Complete)
                .unwrap_or(ChangedInputRecordCoverage::MetadataOnly);
            if previous.sections_file.is_some()
                && let Some(mut full_previous) = PersistedState::read(&state_dir)?
            {
                full_previous.input_files = previous.input_files;
                previous = full_previous;
                record_coverage = ChangedInputRecordCoverage::Complete;
            }
            patch_changed_inputs(
                args,
                &state_dir,
                previous,
                current_link_start.clone(),
                record_coverage,
                &changed_inputs_to_patch,
                &metadata_update_input_indices,
            )?
        };
        let result = match result {
            ChangedInputPatchResult::RequiresCompleteMachOResolutions(reason)
                if attempted_filtered_records =>
            {
                append_log(
                    &state_dir,
                    &format!(
                        "filtered-record changed-input patch requires complete Mach-O \
                         resolutions before loading inputs: {reason}"
                    ),
                )?;
                let Some(mut previous) = PersistedState::read_metadata(&state_dir)? else {
                    return Ok(false);
                };
                refresh_snapshotted_rewritten_input_metadata(
                    &state_dir,
                    &mut previous,
                    &rewritten_inputs,
                );
                apply_preclassified_unchanged_rustc_rlibs(
                    &mut previous,
                    &preclassified_unchanged_inputs,
                );
                previous
                    .read_patch_metadata_for_input_indices(&state_dir, &changed_input_indices)?;
                previous.read_records_for_input_files(&state_dir, &changed_input_files)?;
                patch_changed_inputs(
                    args,
                    &state_dir,
                    previous,
                    current_link_start.clone(),
                    ChangedInputRecordCoverage::ChangedInputsWithCompleteMachOResolutions,
                    &changed_inputs_to_patch,
                    &metadata_update_input_indices,
                )?
            }
            result => result,
        };
        let result = match result {
            ChangedInputPatchResult::RequiresChangedInputRecords(reason)
            | ChangedInputPatchResult::RequiresCompleteMachOResolutions(reason)
            | ChangedInputPatchResult::RequiresCompleteRecords(reason) => {
                if attempted_filtered_records {
                    append_log(
                        &state_dir,
                        &format!(
                            "filtered-record changed-input patch unavailable before loading inputs: {reason}"
                        ),
                    )?;
                }
                if should_retry_with_full_state
                    && let Some(mut full_previous) = PersistedState::read(&state_dir)?
                {
                    refresh_snapshotted_rewritten_input_metadata(
                        &state_dir,
                        &mut full_previous,
                        &rewritten_inputs,
                    );
                    apply_preclassified_unchanged_rustc_rlibs(
                        &mut full_previous,
                        &preclassified_unchanged_inputs,
                    );
                    patch_changed_inputs(
                        args,
                        &state_dir,
                        full_previous,
                        current_link_start,
                        ChangedInputRecordCoverage::Complete,
                        &changed_inputs_to_patch,
                        &metadata_update_input_indices,
                    )?
                } else {
                    ChangedInputPatchResult::Unsupported(reason)
                }
            }
            ChangedInputPatchResult::Unsupported(reason) => {
                if attempted_filtered_records {
                    append_log(
                        &state_dir,
                        &format!(
                            "filtered-record changed-input patch unavailable before loading inputs: {reason}"
                        ),
                    )?;
                }
                if should_retry_with_full_state
                    && changed_input_patch_retry_may_benefit_from_complete_records(&reason)
                    && let Some(mut full_previous) = PersistedState::read(&state_dir)?
                {
                    refresh_snapshotted_rewritten_input_metadata(
                        &state_dir,
                        &mut full_previous,
                        &rewritten_inputs,
                    );
                    apply_preclassified_unchanged_rustc_rlibs(
                        &mut full_previous,
                        &preclassified_unchanged_inputs,
                    );
                    patch_changed_inputs(
                        args,
                        &state_dir,
                        full_previous,
                        current_link_start,
                        ChangedInputRecordCoverage::Complete,
                        &changed_inputs_to_patch,
                        &metadata_update_input_indices,
                    )?
                } else {
                    ChangedInputPatchResult::Unsupported(reason)
                }
            }
            result => result,
        };
        match result {
            ChangedInputPatchResult::Patched => return Ok(true),
            ChangedInputPatchResult::Unsupported(reason)
            | ChangedInputPatchResult::RequiresChangedInputRecords(reason)
            | ChangedInputPatchResult::RequiresCompleteMachOResolutions(reason)
            | ChangedInputPatchResult::RequiresCompleteRecords(reason) => {
                append_log(
                    &state_dir,
                    &format!("changed-input patch unavailable before loading inputs: {reason}"),
                )?;
            }
            ChangedInputPatchResult::StartedUnsupported(reason) => {
                append_log(
                    &state_dir,
                    &format!(
                        "changed-input patch failed after starting update before loading inputs: {reason}"
                    ),
                )?;
            }
        }
        return Ok(false);
    }

    if let Some(reason) = input_identity_mismatch_reason(&previous.input_files)? {
        append_log(
            &state_dir,
            &format!("incremental fast path unavailable before loading inputs: {reason}"),
        )?;
        return Ok(false);
    }

    if (!rewritten_inputs.is_empty() || checked_ambiguous_inputs)
        && let Some(mut metadata) = PersistedState::read_metadata(&state_dir)?
    {
        refresh_snapshotted_rewritten_input_metadata(&state_dir, &mut metadata, &rewritten_inputs);
        metadata.link_start = current_link_start;
        metadata.write_metadata_update(&state_dir)?;
    }
    if !rewritten_inputs.is_empty() {
        append_log(
            &state_dir,
            &format!(
                "updated {} rewritten input file{} before loading inputs",
                rewritten_inputs.len(),
                if rewritten_inputs.len() == 1 { "" } else { "s" }
            ),
        )?;
    }
    if let Some(previous_output) = retained_output_to_restore.as_ref()
        && !restore_missing_output_snapshot(&state_dir, previous_output, args.output())?
    {
        return Ok(false);
    }
    append_log(&state_dir, "reused existing output before loading inputs")?;
    Ok(true)
}

fn refresh_snapshotted_rewritten_input_metadata(
    state_dir: &Path,
    previous: &mut PersistedState,
    rewritten_inputs: &[(usize, PathBuf)],
) {
    refresh_rewritten_input_identities(previous, rewritten_inputs);
    refresh_input_snapshot_identities_at_indices(
        state_dir,
        &mut previous.input_files,
        rewritten_inputs.iter().map(|(input_index, _)| *input_index),
    );
}

fn maybe_reuse_output_during_publication(
    args: &impl platform::Args,
    state_dir: &Path,
) -> Result<bool> {
    if !update_marker_path(state_dir).try_exists().unwrap_or(false)
        || args.should_write_trace_file()
        || args.common().save_dir.is_active()
        || args
            .dependency_file()
            .is_some_and(|dependency_file| !dependency_file.exists())
    {
        return Ok(false);
    }
    let Some(previous) = PersistedState::read_metadata(state_dir).unwrap_or_default() else {
        return Ok(false);
    };
    if previous.sections_file.as_deref() != Some(PUBLISHING_SECTIONS_FILE)
        || previous.patch_records_file.is_some()
        || previous.args_hash != args_hash(args)
        || sld_version_relink_reason(previous.sld_version.as_deref(), &sld_version(args)).is_some()
        || !output_content_matches_previous(
            &previous.output,
            args.output(),
            args.should_trust_persistent_output_data_identity(),
        )?
    {
        return Ok(false);
    }
    let inputs_match = previous
        .input_files
        .par_iter()
        .map(|input| -> Result<bool> {
            let path = decode_path(&input.path)?;
            if !input.content.identity_matches_path(&path)? {
                return Ok(false);
            }
            if input_content_is_anchored_before_link_start(input, previous.link_start.as_ref())
                || !input
                    .content
                    .identity_is_ambiguous_since(previous.link_start.as_ref())
            {
                return Ok(true);
            }
            input_content_matches_previous(state_dir, input, &path)
        })
        .try_reduce(|| true, |left, right| Ok(left && right))?;
    if !inputs_match {
        return Ok(false);
    }
    if input_identity_mismatch_reason(&previous.input_files)?.is_some() {
        return Ok(false);
    }
    append_log(
        state_dir,
        "reused existing output before loading inputs while incremental state publication was pending",
    )?;
    Ok(true)
}

fn input_identity_is_anchored_by_snapshot(input: &FileState) -> bool {
    input
        .snapshot_identity
        .as_ref()
        .zip(input.content.identity.as_ref())
        .is_some_and(|(snapshot, content)| snapshot == content)
}

// Creating a hardlink advances ctime without changing bytes. Only use that anchor when mtime
// proves the content predates this link; otherwise the stored hash must validate the input.
fn input_content_is_anchored_before_link_start(
    input: &FileState,
    link_start: Option<&FileIdentity>,
) -> bool {
    input_identity_is_anchored_by_snapshot(input)
        && input
            .content
            .identity
            .as_ref()
            .zip(link_start)
            .is_some_and(|(identity, link_start)| !identity.modified_on_or_after(link_start))
}

pub(crate) fn stabilize_rustc_transient_inputs(args: &mut crate::args::Args) -> Result<()> {
    remove_empty_rustc_raw_dylib_search_paths(args);

    let (common, output) = match args {
        crate::args::Args::Elf(args) if args.common.incremental => {
            (&mut args.common, args.output.clone())
        }
        crate::args::Args::MachO(args)
            if args.common.incremental
                && std::env::var_os(STABILIZE_RUSTC_TRANSIENT_INPUTS_ENV)
                    .is_some_and(|value| value == "1") =>
        {
            (&mut args.common, args.output.clone())
        }
        _ => return Ok(()),
    };

    let state_dir = state_dir_for_output(&output);
    timing_phase!("Stabilize rustc transient inputs");
    let stable_dir = state_dir.join(STABLE_RUSTC_INPUT_DIR);
    let (provenance, provenance_file) = rustc_work_product_provenance_from_env();
    let previous = provenance
        .as_ref()
        .and_then(|_| PersistedState::read_metadata(&state_dir).unwrap_or_default());
    let previous_inputs_by_path = previous_input_files_by_path(previous.as_ref());
    let mut stabilized = 0;
    let mut matched_producer_digests = 0;
    let mut reused_isolated = 0;
    for input in &mut common.inputs {
        let InputSpec::File(source) = &input.spec else {
            continue;
        };
        let Some(stable_name) = stable_rustc_input_name(source, &output) else {
            continue;
        };
        let source = source.to_path_buf();
        let target = stable_dir.join(stable_name);
        let producer_digest = provenance
            .as_ref()
            .and_then(|provenance| provenance.get(&source));
        if producer_digest.is_some() {
            matched_producer_digests += 1;
        }
        let reused_producer_digest = producer_digest.is_some_and(|digest| {
            stable_rustc_input_matches_previous_producer_digest(
                &previous_inputs_by_path,
                &target,
                digest,
            )
        });
        if reused_producer_digest {
            reused_isolated += 1;
        }

        let already_stable = if provenance.is_some() {
            reused_producer_digest
        } else {
            stable_rustc_input_already_names_source_data(&source, &target)
        };
        if !already_stable {
            std::fs::create_dir_all(&stable_dir).with_context(|| {
                format!(
                    "Failed to create stable rustc input directory `{}`",
                    stable_dir.display()
                )
            })?;
            let tmp = target.with_file_name(format!(
                "{}.{}.tmp",
                target
                    .file_name()
                    .and_then(|name| name.to_str())
                    .unwrap_or("input"),
                std::process::id()
            ));
            let _ = std::fs::remove_file(&tmp);
            if provenance.is_some() {
                copy_isolated_snapshot_bytes(&source, &tmp)?;
            } else {
                copy_snapshot_bytes(&source, &tmp)?;
            }
            let _ = std::fs::remove_file(&target);
            std::fs::rename(&tmp, &target).with_context(|| {
                format!(
                    "Failed to install stable rustc input `{}`",
                    target.display()
                )
            })?;
        }
        input.spec = InputSpec::File(target.into_boxed_path());
        stabilized += 1;
    }

    if stabilized > 0 {
        append_log(
            &state_dir,
            &format!(
                "stabilized {stabilized} rustc transient input{} before loading inputs",
                if stabilized == 1 { "" } else { "s" }
            ),
        )?;
    }
    if reused_isolated > 0 {
        append_log(
            &state_dir,
            &format!(
                "reused {reused_isolated} isolated rustc work-product input{} by producer digest",
                if reused_isolated == 1 { "" } else { "s" }
            ),
        )?;
    }
    if let Some(provenance) = provenance {
        append_log(
            &state_dir,
            &format!(
                "loaded {} rustc work-product producer digest record{}; matched \
                 {matched_producer_digests} stabilized input{}; reused {reused_isolated} isolated \
                 input{}; manifest path present: {}; readable: {}; parsed: {}",
                provenance.len(),
                if provenance.len() == 1 { "" } else { "s" },
                if matched_producer_digests == 1 {
                    ""
                } else {
                    "s"
                },
                if reused_isolated == 1 { "" } else { "s" },
                provenance_file.path_present,
                provenance_file.readable,
                provenance_file.parsed,
            ),
        )?;
    }
    Ok(())
}

struct RustcWorkProductProvenanceFile {
    path_present: bool,
    readable: bool,
    parsed: bool,
}

fn rustc_work_product_provenance_from_env() -> (
    Option<HashMap<PathBuf, String>>,
    RustcWorkProductProvenanceFile,
) {
    let requested = rustc_work_product_provenance_enabled();
    let path = std::env::var_os(RUSTC_WORK_PRODUCT_PROVENANCE_FILE_ENV);
    let contents = path
        .as_ref()
        .and_then(|path| std::fs::read_to_string(path).ok());
    let parsed = contents
        .as_deref()
        .and_then(parse_rustc_work_product_provenance);
    (
        rustc_work_product_provenance(contents.as_deref(), requested || path.is_some()),
        RustcWorkProductProvenanceFile {
            path_present: path.is_some(),
            readable: contents.is_some(),
            parsed: parsed.is_some(),
        },
    )
}

fn rustc_work_product_provenance(
    contents: Option<&str>,
    requested: bool,
) -> Option<HashMap<PathBuf, String>> {
    if !requested {
        return None;
    }
    Some(
        contents
            .and_then(parse_rustc_work_product_provenance)
            .unwrap_or_default(),
    )
}

fn parse_rustc_work_product_provenance(contents: &str) -> Option<HashMap<PathBuf, String>> {
    let mut lines = contents.lines();
    if lines.next()? != RUSTC_WORK_PRODUCT_PROVENANCE_VERSION {
        return None;
    }
    let mut provenance = HashMap::new();
    for line in lines {
        let (digest, path) = line.split_once('\t')?;
        if !is_blake3_hex_digest(digest) || path.contains('\t') {
            return None;
        }
        if provenance
            .insert(decode_path(path).ok()?, digest.to_owned())
            .is_some()
        {
            return None;
        }
    }
    Some(provenance)
}

fn rustc_work_product_provenance_enabled() -> bool {
    std::env::var_os(RUSTC_WORK_PRODUCT_PROVENANCE_ENV).as_deref() == Some("1".as_ref())
}

fn is_blake3_hex_digest(digest: &str) -> bool {
    digest.len() == 64
        && digest
            .bytes()
            .all(|byte| byte.is_ascii_digit() || (b'a'..=b'f').contains(&byte))
}

fn parse_blake3_hex_digest(digest: &str) -> Option<[u8; blake3::OUT_LEN]> {
    if !is_blake3_hex_digest(digest) {
        return None;
    }
    let mut bytes = [0; blake3::OUT_LEN];
    hex::decode_to_slice(digest, &mut bytes).ok()?;
    Some(bytes)
}

fn previous_input_files_by_path(previous: Option<&PersistedState>) -> HashMap<&str, &FileState> {
    let Some(previous) = previous else {
        return HashMap::new();
    };
    let mut inputs_by_path = HashMap::with_capacity(previous.input_files.len());
    for input in &previous.input_files {
        inputs_by_path.entry(input.path.as_str()).or_insert(input);
    }
    inputs_by_path
}

fn stable_rustc_input_matches_previous_producer_digest(
    previous_inputs_by_path: &HashMap<&str, &FileState>,
    target: &Path,
    digest: &str,
) -> bool {
    let encoded_target = encode_path(target);
    previous_inputs_by_path
        .get(encoded_target.as_str())
        .is_some_and(|input| {
            input.content.hash == digest
                && input.content.identity_matches_path(target).unwrap_or(false)
        })
}

fn stable_rustc_input_already_names_source_data(source: &Path, target: &Path) -> bool {
    if !is_atomic_replacement_rust_input(source) {
        return false;
    }

    FileIdentity::from_path(source)
        .ok()
        .flatten()
        .zip(FileIdentity::from_path(target).ok().flatten())
        .is_some_and(|(source, target)| source.matches_same_data_ignoring_change_time(&target))
}

fn remove_empty_rustc_raw_dylib_search_paths(args: &mut crate::args::Args) {
    let crate::args::Args::Elf(args) = args else {
        return;
    };
    if !args.common.incremental {
        return;
    }

    args.lib_search_path
        .retain(|path| !is_empty_rustc_raw_dylib_search_path(path));
}

fn is_empty_rustc_raw_dylib_search_path(path: &Path) -> bool {
    path.file_name().and_then(|name| name.to_str()) == Some("raw-dylibs")
        && path
            .parent()
            .and_then(Path::file_name)
            .and_then(|name| name.to_str())
            .is_some_and(|name| name.starts_with("rustc"))
        && std::fs::read_dir(path).is_ok_and(|mut entries| entries.next().is_none())
}

fn stable_rustc_input_name(path: &Path, output: &Path) -> Option<PathBuf> {
    let output_dir = output.parent()?;
    let filename = path.file_name()?.to_str()?;
    if filename == "symbols.o"
        && path.parent()?.parent() == Some(output_dir)
        && path.parent()?.file_name()?.to_str()?.starts_with("rustc")
    {
        return Some(PathBuf::from("rustc-symbols.o"));
    }
    let output_name = output.file_name()?.to_str()?;
    if path.parent() != Some(output_dir)
        || !filename.starts_with(&format!("{output_name}."))
        || !filename.ends_with(".rcgu.o")
    {
        return None;
    }

    let parts = filename.split('.').collect::<Vec<_>>();
    let [crate_name, codegen_unit, invocation, "rcgu", "o"] = parts.as_slice() else {
        return None;
    };
    if crate_name.is_empty() || codegen_unit.is_empty() || invocation.is_empty() {
        return None;
    }
    Some(PathBuf::from(format!("{crate_name}.{codegen_unit}.rcgu.o")))
}

fn metadata_update_indices_for_inputs(
    changed_inputs: &[(usize, PathBuf)],
    rewritten_inputs: &[(usize, PathBuf)],
) -> Vec<usize> {
    let mut indices = changed_inputs
        .iter()
        .chain(rewritten_inputs)
        .map(|(input_index, _)| *input_index)
        .collect::<Vec<_>>();
    indices.sort_unstable();
    indices.dedup();
    indices
}

fn preclassify_unchanged_rustc_rlibs_by_link_content_digest(
    args: &impl platform::Args,
    previous: &PersistedState,
    changed_inputs: &[(usize, PathBuf)],
    trust_rustc_link_content_digests: bool,
) -> HashMap<usize, FileContentState> {
    if !trust_rustc_link_content_digests {
        return HashMap::new();
    }
    let matches = {
        timing_phase!("Preclassify unchanged rustc rlibs");
        changed_inputs
            .par_iter()
            .filter_map(|(input_index, path)| {
                if !can_reuse_rustc_link_content_digest(args, path) {
                    return None;
                }
                let input = previous.input_files.get(*input_index)?;
                previous_rustc_rlib_link_content_digest(input)?;
                rustc_rlib_link_content_digest_matches_previous_path(input, path)
                    .map(|content| (*input_index, content))
            })
            .collect::<Vec<_>>()
    };
    matches.into_iter().collect()
}

fn apply_preclassified_unchanged_rustc_rlibs(
    previous: &mut PersistedState,
    preclassified_unchanged_inputs: &HashMap<usize, FileContentState>,
) {
    for (input_index, input_content) in preclassified_unchanged_inputs {
        let input = &mut previous.input_files[*input_index];
        let rustc_link_content_digest =
            previous_rustc_rlib_link_content_digest(input).map(str::to_owned);
        input.content = input_content.clone();
        input.snapshot_identity = None;
        input.rustc_link_content_digest = rustc_link_content_digest;
    }
}

fn refresh_rewritten_input_identities(
    previous: &mut PersistedState,
    rewritten_inputs: &[(usize, PathBuf)],
) {
    refresh_input_file_identities_at_indices(
        &mut previous.input_files,
        rewritten_inputs.iter().map(|(input_index, _)| *input_index),
    );
}

enum ChangedInputPatchResult {
    Patched,
    Unsupported(String),
    RequiresChangedInputRecords(String),
    RequiresCompleteMachOResolutions(String),
    RequiresCompleteRecords(String),
    StartedUnsupported(String),
}

const MACHO_TEXT_RELOCATION_RECORDS_REQUIRED: &str =
    "changed input needs Mach-O text relocation records";
const MACHO_SYMBOL_RESOLUTIONS_REQUIRED: &str = "missing Mach-O symbol resolution";

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum ChangedInputRecordCoverage {
    MetadataOnly,
    ChangedInputs,
    ChangedInputsWithCompleteMachOResolutions,
    Complete,
}

impl ChangedInputRecordCoverage {
    fn has_changed_input_records(self) -> bool {
        self != Self::MetadataOnly
    }

    fn has_complete_macho_symbol_resolutions(self) -> bool {
        self != Self::ChangedInputs
    }

    fn is_complete(self) -> bool {
        self == Self::Complete
    }
}

fn changed_input_patch_should_retry_with_filtered_records(
    result: &ChangedInputPatchResult,
) -> bool {
    matches!(
        result,
        ChangedInputPatchResult::Unsupported(_)
            | ChangedInputPatchResult::RequiresChangedInputRecords(_)
    )
}

fn changed_input_patch_retry_may_benefit_from_complete_records(reason: &str) -> bool {
    // The anonymous-section identity result is independent of global record coverage. Other
    // refusals remain conservative: complete generated-section state can enable dynamic changes.
    !reason.starts_with("could not match anonymous patch sections in `")
}

fn changed_inputs_have_macho_text_patch_sections(
    previous: &PersistedState,
    changed_inputs: &[(usize, PathBuf)],
) -> bool {
    changed_inputs.iter().any(|(input_index, path)| {
        previous
            .input_files
            .get(*input_index)
            .and_then(|input| patch_sections_from_previous_state(input, path).ok())
            .is_some_and(|patch| {
                patch
                    .sections
                    .iter()
                    .any(|section| section.section_name.as_deref() == Some("__TEXT,__text"))
            })
    })
}

fn changed_inputs_have_archive_member_set_changes(
    previous: &PersistedState,
    changed_inputs: &[(usize, PathBuf)],
    normalize_rust_archive_patch_inputs: bool,
) -> Result<bool> {
    for (input_index, path) in changed_inputs {
        let previous_input = &previous.input_files[*input_index];
        let previous_proof = previous_input
            .patch
            .as_ref()
            .and_then(|patch| patch.archive_member_set_proof.as_ref());
        if previous_proof.is_none() && previous_input.rustc_raw_object_manifest.is_none() {
            continue;
        }
        let Some((bytes, _)) = read_file_with_stable_identity(path)? else {
            return Ok(true);
        };
        let current_manifest =
            rustc_rlib_provenance(&bytes).and_then(|provenance| provenance.raw_object_manifest);
        if let (Some(previous_manifest), Some(current_manifest)) = (
            previous_input.rustc_raw_object_manifest.as_ref(),
            current_manifest.as_ref(),
        ) && rustc_rlib_raw_object_delta(previous_manifest, current_manifest)
            .is_some_and(|delta| !delta.added.is_empty() || !delta.removed.is_empty())
        {
            return Ok(true);
        }
        let Some(previous_proof) = previous_proof else {
            continue;
        };
        let Some(current_proof) = archive_member_set_proof(&bytes)? else {
            return Ok(true);
        };
        let hashes_match = if normalize_rust_archive_patch_inputs {
            previous_proof.normalized_ordered_hash == current_proof.normalized_ordered_hash
        } else {
            previous_proof.raw_ordered_hash == current_proof.raw_ordered_hash
        };
        if previous_proof.member_count != current_proof.member_count || !hashes_match {
            return Ok(true);
        }
    }
    Ok(false)
}

fn changed_inputs_need_records_to_derive_patch_metadata(
    previous: &PersistedState,
    changed_inputs: &[(usize, PathBuf)],
) -> bool {
    changed_inputs.iter().any(|(input_index, _)| {
        previous.input_files.get(*input_index).is_some_and(|input| {
            input.patch.as_ref().is_none_or(|patch| {
                patch.sections.is_empty() && patch.raw_sections.as_deref().is_none_or(str::is_empty)
            })
        })
    })
}

fn relocation_target_patches_for_input(
    relocations: &mut [RelocationRecord],
    input: &FileState,
    bytes: &[u8],
) -> Result<std::result::Result<RelocationTargetPatches, String>> {
    let macho_archive_symbol_inputs = MachOArchiveSymbolInputLookup::new(bytes)?;
    let mut input_ranges = Vec::new();
    let mut output_patches = Vec::new();
    let mut output_symbols = Vec::new();
    let mut macho_target_moves = Vec::new();
    let mut macho_cross_input_target_moves = Vec::new();
    let mut changed_relocation_indices = Vec::new();
    for (relocation_index, relocation) in relocations.iter_mut().enumerate() {
        let Some(target) = relocation.target.as_mut() else {
            continue;
        };
        if target.input_file != input.path {
            continue;
        }
        let Some(target_name) = relocation.target_name.as_deref() else {
            continue;
        };
        let input_bytes = if let Some(lookup) = macho_archive_symbol_inputs.as_ref() {
            if let Some(input_bytes) = lookup.get(target_name) {
                Some(input_bytes)
            } else if !lookup.contains(target_name)
                && relocation.input_file == input.path
                && stable_rust_mangled_name(target_name)
                && !archive_member_reference_contains_symbol(
                    bytes,
                    input.path.as_str(),
                    relocation.input.as_str(),
                    target_name,
                )?
            {
                // The source CGU and its local target were both retired. Current section replay
                // will rediscover any replacement relocation from the repartitioned archive.
                changed_relocation_indices.push(relocation_index);
                continue;
            } else {
                patch_input_bytes(bytes, input.path.as_str(), &target.input)?
            }
        } else {
            patch_input_bytes(bytes, input.path.as_str(), &target.input)?
        };
        let Some(input_bytes) = input_bytes else {
            continue;
        };
        let current_target_input =
            resolved_patch_input_ref(input.path.as_str(), target.input.as_str(), input_bytes)?;
        let target_input_changed = target.input != current_target_input;
        let file = match object::File::parse(input_bytes.bytes) {
            Ok(file) => file,
            Err(error) => {
                return Ok(Err(format!(
                    "Failed to parse changed relocation target input `{}` for symbol `{}` from `{}` at {:#x} ({} bytes, magic {:02x?}): {error}",
                    display_hex_text(&target.input),
                    display_hex_text(target_name),
                    display_hex_text(&relocation.input),
                    input_bytes.file_offset,
                    input_bytes.bytes.len(),
                    &input_bytes.bytes[..input_bytes.bytes.len().min(8)],
                )));
            }
        };
        let cross_input_macho_relocation = relocation.input_file != input.path
            && file.format() == object::BinaryFormat::MachO
            && file.architecture() == object::Architecture::Aarch64
            && decode_macho_aarch64_relocation_kind(relocation.kind).is_some();
        if relocation.input_file == input.path
            && relocation.input == target.input
            && file.format() == object::BinaryFormat::MachO
            && file.architecture() == object::Architecture::Aarch64
            && decode_macho_aarch64_relocation_kind(relocation.kind).is_some()
        {
            // Same-object Mach-O targets must be resolved together with the current relocation
            // site. Rust-generated local names can be reused for semantically different constants.
            continue;
        }
        let current = if cross_input_macho_relocation {
            match unique_symbol_position_by_name(
                input_bytes.bytes,
                input_bytes.file_offset,
                &file,
                target_name,
            )? {
                Ok(current) => current,
                Err(reason) => return Ok(Err(reason)),
            }
        } else {
            symbol_position_by_name(
                input_bytes.bytes,
                input_bytes.file_offset,
                &file,
                target_name,
            )?
        };
        let Some(current) = current else {
            continue;
        };
        if let Some(value_range) = current.value_range {
            input_ranges.push(value_range);
        }
        if current.section_index.0 as u32 == target.section_index
            && current.section_offset == target.section_offset
        {
            if target_input_changed {
                target.input = current_target_input.into();
                changed_relocation_indices.push(relocation_index);
            }
            continue;
        }
        if current.section_index.0 as u32 != target.section_index {
            return Ok(Err(format!(
                "relocation target `{}` moved from section {} offset {:#x} to section {} offset {:#x} in {}",
                display_hex_text(target_name),
                target.section_index,
                target.section_offset,
                current.section_index.0,
                current.section_offset,
                display_hex_path(&input.path)
            )));
        }

        let Some(previous_written_value) = relocation.written_value else {
            return Ok(Err(format!(
                "missing written relocation value for target in {}",
                display_hex_path(&input.path)
            )));
        };
        let delta = i128::from(current.section_offset) - i128::from(target.section_offset);
        let previous_target_value = relocation.target_value;
        let Some(target_value) = add_signed_delta_u64(previous_target_value, delta) else {
            return Ok(Err(format!(
                "relocation target value overflowed in {}",
                display_hex_path(&input.path)
            )));
        };
        changed_relocation_indices.push(relocation_index);
        if file.format() == object::BinaryFormat::MachO
            && file.architecture() == object::Architecture::Aarch64
            && let Some(raw_relocation) = decode_macho_aarch64_relocation_kind(relocation.kind)
        {
            if relocation.input_file != input.path
                && !macho_aarch64_cross_input_relocation_is_supported(
                    raw_relocation,
                    relocation.size,
                )
            {
                return Ok(Err(format!(
                    "unsupported cross-input Mach-O relocation target patch in {}",
                    display_hex_path(&input.path)
                )));
            }
            if relocation.input_file != input.path {
                macho_cross_input_target_moves.push(MachORelocationTargetMove {
                    relocation_index,
                    current_section_offset: current.section_offset,
                    current_target_value: target_value,
                    current_input: target_input_changed
                        .then(|| current_target_input.clone().into()),
                });
                continue;
            }
            macho_target_moves.push(MachORelocationTargetMove {
                relocation_index,
                current_section_offset: current.section_offset,
                current_target_value: target_value,
                current_input: target_input_changed.then(|| current_target_input.clone().into()),
            });
            // A grown section may be rematerialized elsewhere. Defer the symbol patch until
            // text replay can reconcile this provisional offset with the final output mapping.
            continue;
        }

        let written_value = add_encoded_delta_u64(previous_written_value, delta);
        let Some(rel_info) = relocation_kind_info(&file, relocation.kind) else {
            return Ok(Err(format!(
                "unsupported relocation target patch kind in {}",
                display_hex_path(&input.path)
            )));
        };
        let deferred_relocation =
            deferred_instruction_relocation_patch(rel_info, previous_written_value, written_value);
        let data = if deferred_relocation.is_some() {
            let Ok(size) = usize::try_from(relocation.size) else {
                return Ok(Err(format!(
                    "unsupported relocation target patch size in {}",
                    display_hex_path(&input.path)
                )));
            };
            vec![0; size]
        } else {
            let Ok(size) = usize::try_from(relocation.size) else {
                return Ok(Err(format!(
                    "unsupported relocation target patch size in {}",
                    display_hex_path(&input.path)
                )));
            };
            let mut data = vec![0; size];
            if rel_info.write_to_buffer(written_value, &mut data).is_err() {
                return Ok(Err(format!(
                    "relocation target patch overflowed in {}",
                    display_hex_path(&input.path)
                )));
            }
            data
        };
        let previous_target_value = relocation.target_value;
        let Some(target_value) = add_signed_delta_u64(previous_target_value, delta) else {
            return Ok(Err(format!(
                "relocation target value overflowed in {}",
                display_hex_path(&input.path)
            )));
        };
        output_patches.push(SectionPatch {
            output_offset: relocation.output_offset,
            size: relocation.size,
            data,
            deferred_relocation,
            preserve_ranges: Vec::new(),
            adjustments: Vec::new(),
        });
        relocation.written_value = Some(written_value);
        relocation.target_value = target_value;
        if target_input_changed {
            target.input = current_target_input.into();
        }
        target.section_offset = current.section_offset;
        output_symbols.push(RelocationTargetSymbolPatch {
            target_name: target_name.to_owned(),
            previous_target_value,
            target_value,
            allow_missing: false,
            source: "relocation target movement",
        });
    }
    dedup_ranges(&mut input_ranges);
    Ok(Ok(RelocationTargetPatches {
        input_ranges,
        output_patches,
        output_symbols,
        macho_target_moves,
        macho_cross_input_target_moves,
        changed_relocation_indices,
    }))
}

fn matching_macho_symbol_resolution_move<'a>(
    resolution_moves: &'a [MachOSymbolResolutionMove],
    target_name: &str,
    previous_target: &RelocationTargetRecord,
    previous_target_value: u64,
    current_section_offset: u64,
) -> std::result::Result<Option<&'a MachOSymbolResolutionMove>, ()> {
    let mut matching_moves = resolution_moves.iter().filter(|moved| {
        moved.name.as_str() == target_name
            && moved.previous_target == *previous_target
            && moved.previous_value == previous_target_value
            && moved.current_target.section_offset == current_section_offset
    });
    let matching_move = matching_moves.next();
    if matching_moves.next().is_some() {
        return Err(());
    }
    Ok(matching_move)
}

fn resolved_macho_relocation_target(
    previous_target_value: u64,
    mut target: Option<RelocationTargetRecord>,
    target_move: Option<MachORelocationTargetMove>,
    resolution_move: Option<&MachOSymbolResolutionMove>,
) -> (u64, Option<RelocationTargetRecord>) {
    if let Some(moved) = resolution_move {
        return (moved.current_value, Some(moved.current_target.clone()));
    }
    if let Some(target_move) = target_move.as_ref()
        && let Some(target) = target.as_mut()
    {
        target.section_offset = target_move.current_section_offset;
        if let Some(current_input) = target_move.current_input.as_ref() {
            target.input = current_input.clone();
        }
    }
    (
        target_move.map_or(previous_target_value, |target_move| {
            target_move.current_target_value
        }),
        target,
    )
}

fn finish_macho_cross_input_target_moves(
    relocations: &mut [RelocationRecord],
    target_patches: &mut RelocationTargetPatches,
    resolution_moves: &[MachOSymbolResolutionMove],
    reusable_branch_targets: &[MachOReusableBranchTarget],
    reuse_previous_target: bool,
    finish_unmatched: bool,
    input: &FileState,
) -> Result<std::result::Result<(), String>> {
    let mut remaining_moves = Vec::new();
    for target_move in std::mem::take(&mut target_patches.macho_cross_input_target_moves) {
        let Some(relocation) = relocations.get_mut(target_move.relocation_index) else {
            return Ok(Err(format!(
                "missing cross-input Mach-O relocation for moved target in {}",
                display_hex_path(&input.path)
            )));
        };
        let Some(target_name) = relocation.target_name.as_deref().map(str::to_owned) else {
            return Ok(Err(format!(
                "missing cross-input Mach-O relocation target name in {}",
                display_hex_path(&input.path)
            )));
        };
        let Some(previous_target) = relocation.target.clone() else {
            return Ok(Err(format!(
                "missing cross-input Mach-O relocation target in {}",
                display_hex_path(&input.path)
            )));
        };
        let previous_target_value = relocation.target_value;
        let previous_applied_target_value = relocation
            .applied_target_value
            .unwrap_or(previous_target_value);
        let Some(previous_written_value) = relocation.written_value else {
            return Ok(Err(format!(
                "missing written cross-input Mach-O relocation value in {}",
                display_hex_path(&input.path)
            )));
        };
        let Some(raw_relocation) = decode_macho_aarch64_relocation_kind(relocation.kind) else {
            return Ok(Err(format!(
                "invalid cross-input Mach-O relocation kind in {}",
                display_hex_path(&input.path)
            )));
        };

        let forwarding_move = match matching_macho_symbol_resolution_move(
            resolution_moves,
            target_name.as_str(),
            &previous_target,
            previous_target_value,
            target_move.current_section_offset,
        ) {
            Ok(moved) => moved,
            Err(()) => {
                return Ok(Err(format!(
                    "ambiguous moved Mach-O symbol for cross-input relocation in {}",
                    display_hex_path(&input.path)
                )));
            }
        };
        if let Some(moved) = forwarding_move {
            if reuse_previous_target
                && reusable_branch_targets.iter().any(|reusable| {
                    reusable.moved == *moved
                        && reusable.applied_target_value == previous_applied_target_value
                })
            {
                if raw_relocation.r_type != object::macho::ARM64_RELOC_BRANCH26 {
                    return Ok(Err(format!(
                        "unsupported moved Mach-O forwarding target in {}",
                        display_hex_path(&input.path)
                    )));
                }
                relocation.target_value = moved.current_value;
                relocation.applied_target_value = Some(previous_applied_target_value);
                relocation.target = Some(moved.current_target.clone());
                continue;
            }
        }
        if !finish_unmatched {
            remaining_moves.push(target_move);
            continue;
        }

        if previous_applied_target_value != previous_target_value {
            return Ok(Err(format!(
                "moved Mach-O stub or thunk target in {}",
                display_hex_path(&input.path)
            )));
        }
        let current_target_value = forwarding_move
            .map_or(target_move.current_target_value, |moved| {
                moved.current_value
            });
        let Some(written_value) = macho_aarch64_relocated_value_after_target_move(
            raw_relocation.r_type,
            previous_written_value,
            previous_target_value,
            current_target_value,
            relocation.addend,
        ) else {
            return Ok(Err(format!(
                "unsupported cross-input Mach-O relocation target patch in {}",
                display_hex_path(&input.path)
            )));
        };
        let rel_info =
            <crate::macho_aarch64::MachOAArch64 as crate::platform::Arch>::relocation_from_raw(
                raw_relocation,
            )
            .map_err(|error| {
                crate::error!("Failed to decode recorded Mach-O target relocation: {error:#?}")
            })?;
        let Some(deferred_relocation) =
            deferred_instruction_relocation_patch(rel_info, previous_written_value, written_value)
        else {
            return Ok(Err(format!(
                "unsupported cross-input Mach-O relocation instruction in {}",
                display_hex_path(&input.path)
            )));
        };
        let Ok(size) = usize::try_from(relocation.size) else {
            return Ok(Err(format!(
                "unsupported cross-input Mach-O relocation size in {}",
                display_hex_path(&input.path)
            )));
        };
        target_patches.output_patches.push(SectionPatch {
            output_offset: relocation.output_offset,
            size: relocation.size,
            data: vec![0; size],
            deferred_relocation: Some(deferred_relocation),
            preserve_ranges: Vec::new(),
            adjustments: Vec::new(),
        });
        relocation.written_value = Some(written_value);
        relocation.target_value = current_target_value;
        relocation.applied_target_value = Some(current_target_value);
        if let Some(moved) = forwarding_move {
            relocation.target = Some(moved.current_target.clone());
        } else if let Some(target) = relocation.target.as_mut() {
            target.section_offset = target_move.current_section_offset;
            if let Some(current_input) = target_move.current_input {
                target.input = current_input;
            }
        }
        target_patches
            .output_symbols
            .push(RelocationTargetSymbolPatch {
                target_name,
                previous_target_value,
                target_value: current_target_value,
                allow_missing: true,
                source: "cross-input Mach-O relocation target movement",
            });
    }
    target_patches.macho_cross_input_target_moves = remaining_moves;
    Ok(Ok(()))
}

fn update_macho_symbol_resolutions_for_input(
    resolutions: &mut [MachOSymbolResolutionRecord],
    input: &FileState,
    bytes: &[u8],
    allow_added_archive_retirement: bool,
    output_context: Option<(&[MatchedPatchSection], &[u8])>,
) -> Result<std::result::Result<MachOSymbolResolutionUpdates, String>> {
    let output_file = output_context
        .map(|(_, output)| object::File::parse(output))
        .transpose()
        .context("Failed to parse previous Mach-O output for symbol catalog refresh")?;
    let mut input_ranges = Vec::new();
    let mut output_symbols = Vec::new();
    let mut moves = Vec::new();
    let mut thunk_patches = Vec::new();
    let mut reusable_branch_targets = Vec::new();
    let mut retiring_names = Vec::new();
    let mut changed = false;
    let mut requested_names = Vec::new();
    for resolution in resolutions.iter() {
        let Some(target) = resolution
            .target
            .as_ref()
            .filter(|target| target.input_file == input.path)
        else {
            continue;
        };
        requested_names.push((resolution.name.clone(), target.input.clone()));
    }
    let resolver = (!requested_names.is_empty())
        .then(|| PatchInputResolver::new(bytes, true))
        .transpose()?;
    let archive_symbol_inputs = MachOArchiveSymbolInputLookup::new(bytes)?;
    let mut resolved_inputs_by_name = HashMap::new();
    let mut requested_names_by_current_input = HashMap::<String, Vec<SharedText>>::new();
    for (name, previous_input) in requested_names {
        let input_bytes = if let Some(input_bytes) = archive_symbol_inputs
            .as_ref()
            .and_then(|lookup| lookup.get(name.as_str()))
        {
            Some(input_bytes)
        } else {
            resolver
                .as_ref()
                .expect("requested Mach-O symbol names require an input resolver")
                .resolve(
                    input.path.as_str(),
                    previous_input.as_str(),
                    PatchInputLookup::MatchArchiveMember,
                )?
        };
        let Some(input_bytes) = input_bytes else {
            continue;
        };
        let current_input =
            resolved_patch_input_ref(input.path.as_str(), previous_input.as_str(), input_bytes)?;
        requested_names_by_current_input
            .entry(current_input.clone())
            .or_default()
            .push(name.clone());
        resolved_inputs_by_name.insert(name, (input_bytes, current_input));
    }
    let mut indexed_inputs = HashMap::<String, IndexedMachOSymbolCatalogInput<'_>>::new();
    for resolution in resolutions {
        let Some(target) = resolution
            .target
            .as_mut()
            .filter(|target| target.input_file == input.path)
        else {
            continue;
        };
        let previous_input = target.input.clone();
        let Some((input_bytes, current_input)) = resolved_inputs_by_name.get(&resolution.name)
        else {
            if allow_added_archive_retirement
                && resolution.direct_value.is_some()
                && resolution.got_address.is_none()
                && resolution.stub_address.is_none()
                && resolution.thunk_addresses.is_empty()
            {
                retiring_names.push(resolution.name.clone());
                continue;
            }
            return Ok(Err(format!(
                "could not resolve Mach-O symbol catalog input {} for {} in {}",
                display_hex_text(&previous_input),
                display_hex_text(&resolution.name),
                display_hex_path(&input.path),
            )));
        };
        if !indexed_inputs.contains_key(current_input) {
            let file = match object::File::parse(input_bytes.bytes) {
                Ok(file) => file,
                Err(error) => {
                    if allow_added_archive_retirement
                        && resolution.direct_value.is_some()
                        && resolution.got_address.is_none()
                        && resolution.stub_address.is_none()
                        && resolution.thunk_addresses.is_empty()
                    {
                        retiring_names.push(resolution.name.clone());
                        continue;
                    }
                    return Err(error)
                        .context("Failed to parse changed Mach-O symbol catalog input");
                }
            };
            let positions = indexed_unique_symbol_positions(
                input_bytes.bytes,
                input_bytes.file_offset,
                &file,
                requested_names_by_current_input
                    .get(current_input)
                    .expect("resolved input has requested Mach-O symbol names"),
            )?;
            indexed_inputs.insert(
                current_input.clone(),
                IndexedMachOSymbolCatalogInput {
                    file,
                    current_input: current_input.clone(),
                    positions,
                },
            );
        }
        let indexed_input = indexed_inputs
            .get(current_input)
            .expect("requested Mach-O symbol input was indexed");
        let current = match indexed_input.positions.get(&resolution.name) {
            Some(IndexedSymbolPosition::Unique(current)) => current.clone(),
            None => {
                if allow_added_archive_retirement
                    && resolution.direct_value.is_some()
                    && resolution.got_address.is_none()
                    && resolution.stub_address.is_none()
                    && resolution.thunk_addresses.is_empty()
                {
                    retiring_names.push(resolution.name.clone());
                    continue;
                }
                return Ok(Err(format!(
                    "missing Mach-O symbol catalog target in {}",
                    display_hex_path(&input.path)
                )));
            }
            Some(IndexedSymbolPosition::Ambiguous) => {
                return Ok(Err(
                    "ambiguous cross-input Mach-O relocation target symbol".to_owned()
                ));
            }
        };
        if let Some(value_range) = current.value_range {
            input_ranges.push(value_range);
        }
        if current.section_index.0 as u32 != target.section_index {
            return Ok(Err(format!(
                "Mach-O symbol catalog target changed sections in {}",
                display_hex_path(&input.path)
            )));
        }
        let Some(previous_value) = resolution.direct_value else {
            return Ok(Err(format!(
                "missing direct Mach-O symbol catalog target in {}",
                display_hex_path(&input.path)
            )));
        };
        let current_value = if let Some((matched_sections, _)) = output_context {
            let mut current_value = macho_output_address_for_current_section_offset(
                output_file
                    .as_ref()
                    .expect("output context requires parsed output"),
                matched_sections,
                &indexed_input.file,
                indexed_input.current_input.as_str(),
                current.section_index,
                current.section_offset,
            );
            if current_value.is_none()
                && current.section_index.0 as u32 == target.section_index
                && current.section_offset == target.section_offset
                && normalized_archive_input_refs_match(
                    input.path.as_str(),
                    target.input.as_str(),
                    indexed_input.current_input.as_str(),
                )?
            {
                current_value = Some(previous_value);
            }
            if current_value.is_none()
                && allow_added_archive_retirement
                && resolution.got_address.is_none()
                && resolution.stub_address.is_none()
                && resolution.thunk_addresses.is_empty()
            {
                retiring_names.push(resolution.name.clone());
                continue;
            }
            let Some(current_value) = current_value else {
                let current_section_index =
                    patch_section_record_index(&indexed_input.file, current.section_index)?;
                let section_inputs = matched_sections
                    .iter()
                    .filter(|section| section.current.section_index == current_section_index)
                    .map(|section| display_hex_path(&section.current.input).replace('\0', "\\0"))
                    .collect::<Vec<_>>()
                    .join(", ");
                return Ok(Err(format!(
                    "Mach-O symbol catalog target `{}` has no current output address in {}: current input `{}`, section {}, offset {:#x}; matched section inputs: [{}]",
                    display_hex_text(resolution.name.as_str()),
                    display_hex_path(&input.path),
                    display_hex_path(&indexed_input.current_input).replace('\0', "\\0"),
                    current_section_index,
                    current.section_offset,
                    section_inputs
                )));
            };
            current_value
        } else {
            let delta = i128::from(current.section_offset) - i128::from(target.section_offset);
            let Some(current_value) = add_signed_delta_u64(previous_value, delta) else {
                return Ok(Err(format!(
                    "Mach-O symbol catalog target value overflowed in {}",
                    display_hex_path(&input.path)
                )));
            };
            current_value
        };
        let position_changed = current.section_offset != target.section_offset;
        let value_changed = current_value != previous_value;
        let input_changed = target.input != indexed_input.current_input
            && !normalized_archive_input_refs_match(
                input.path.as_str(),
                target.input.as_str(),
                indexed_input.current_input.as_str(),
            )?;
        if !position_changed && !value_changed && !input_changed {
            continue;
        }
        if value_changed && resolution.got_address.is_some() {
            return Ok(Err(format!(
                "moved Mach-O GOT target `{}` in {}: previous value {previous_value:#x}, \
                 current value {current_value:#x}, previous section offset {:#x}, current section \
                 offset {:#x}, GOT address {:?}",
                display_hex_text(resolution.name.as_str()),
                display_hex_path(&input.path),
                target.section_offset,
                current.section_offset,
                resolution.got_address,
            )));
        }
        let previous_target = target.clone();
        let mut current_target = previous_target.clone();
        current_target.input = indexed_input.current_input.clone().into();
        current_target.section_offset = current.section_offset;
        if value_changed {
            output_symbols.push(RelocationTargetSymbolPatch {
                target_name: resolution.name.to_string(),
                previous_target_value: previous_value,
                target_value: current_value,
                allow_missing: true,
                source: "Mach-O symbol catalog refresh",
            });
            let moved = MachOSymbolResolutionMove {
                name: resolution.name.clone(),
                previous_value,
                current_value,
                previous_target,
                current_target: current_target.clone(),
            };
            if !resolution.thunk_addresses.is_empty() {
                let Some(output_file) = output_file.as_ref() else {
                    return Ok(Err(format!(
                        "moved Mach-O thunk target `{}` has no previous output",
                        display_hex_text(resolution.name.as_str())
                    )));
                };
                let Some((_, previous_output)) = output_context else {
                    unreachable!("parsed output requires output context");
                };
                let retargets = match recorded_macho_thunk_retargets(
                    resolution.name.as_str(),
                    &resolution.thunk_addresses,
                    previous_value,
                    current_value,
                    output_file,
                    previous_output,
                ) {
                    Ok(retargets) => retargets,
                    Err(reason) => return Ok(Err(reason)),
                };
                resolution
                    .thunk_addresses
                    .retain(|address| !retargets.retired_addresses.contains(address));
                thunk_patches.extend(retargets.patches);
                reusable_branch_targets.extend(retargets.reusable_branch_targets.into_iter().map(
                    |applied_target_value| MachOReusableBranchTarget {
                        moved: moved.clone(),
                        applied_target_value,
                    },
                ));
            }
            moves.push(moved);
        }
        resolution.direct_value = Some(current_value);
        *target = current_target;
        changed = true;
    }
    retiring_names.sort_unstable();
    if retiring_names.windows(2).any(|names| names[0] == names[1]) {
        return Ok(Err(
            "ambiguous missing Mach-O symbol catalog target".to_owned()
        ));
    }
    dedup_ranges(&mut input_ranges);
    Ok(Ok(MachOSymbolResolutionUpdates {
        input_ranges,
        output_symbols,
        moves,
        thunk_patches,
        reusable_branch_targets,
        retiring_names,
        changed,
    }))
}

fn recorded_macho_thunk_retargets(
    name: &str,
    thunk_addresses: &[u64],
    previous_target: u64,
    current_target: u64,
    output_file: &object::File<'_>,
    previous_output: &[u8],
) -> std::result::Result<MachORecordedThunkRetargets, String> {
    let config = <crate::macho_aarch64::MachOAArch64 as crate::platform::Arch>::thunk_config()
        .ok_or_else(|| "Mach-O recorded thunks are unavailable for this architecture".to_owned())?;
    let thunk_size = usize::try_from(config.thunk_size)
        .map_err(|_| "Mach-O recorded thunk size does not fit usize".to_owned())?;
    let mut addresses = thunk_addresses.to_vec();
    addresses.sort_unstable();
    addresses.dedup();
    let mut retargets = MachORecordedThunkRetargets::default();
    for thunk_address in addresses {
        if thunk_address % 4 != 0 {
            return Err(format!(
                "recorded Mach-O thunk for `{}` is not instruction-aligned",
                display_hex_text(name)
            ));
        }
        if !macho_aarch64_thunk_target_is_reachable(thunk_address, previous_target) {
            return Err(format!(
                "recorded Mach-O thunk for `{}` has an old target outside ADRP range",
                display_hex_text(name)
            ));
        }
        let Some(output_offset) =
            macho_output_file_offset_for_address(output_file, thunk_address, config.thunk_size)?
        else {
            return Err(format!(
                "recorded Mach-O thunk for `{}` has no output file range",
                display_hex_text(name)
            ));
        };
        let start = usize::try_from(output_offset)
            .map_err(|_| "recorded Mach-O thunk output offset does not fit usize".to_owned())?;
        let end = start
            .checked_add(thunk_size)
            .ok_or_else(|| "recorded Mach-O thunk output range overflowed".to_owned())?;
        let previous_bytes = previous_output.get(start..end).ok_or_else(|| {
            "recorded Mach-O thunk output range is outside the previous output".to_owned()
        })?;
        let mut expected_previous = vec![0; thunk_size];
        <crate::macho_aarch64::MachOAArch64 as crate::platform::Arch>::write_thunk(
            thunk_address,
            previous_target,
            &mut expected_previous,
        );
        if previous_bytes != expected_previous {
            return Err(format!(
                "recorded Mach-O thunk encoding changed for `{}` at {thunk_address:#x}",
                display_hex_text(name)
            ));
        }

        retargets.reusable_branch_targets.push(thunk_address);
        if thunk_address == current_target {
            retargets.retired_addresses.push(thunk_address);
            continue;
        }
        if !macho_aarch64_thunk_target_is_reachable(thunk_address, current_target) {
            return Err(format!(
                "recorded Mach-O thunk target for `{}` is outside ADRP range",
                display_hex_text(name)
            ));
        }
        let mut data = vec![0; thunk_size];
        <crate::macho_aarch64::MachOAArch64 as crate::platform::Arch>::write_thunk(
            thunk_address,
            current_target,
            &mut data,
        );
        retargets.patches.push(SectionPatch {
            output_offset,
            size: config.thunk_size,
            data,
            deferred_relocation: None,
            preserve_ranges: Vec::new(),
            adjustments: Vec::new(),
        });
    }
    Ok(retargets)
}

fn macho_forwarding_thunk_patch(
    moved: &MachOSymbolResolutionMove,
    previous_file: &object::File<'_>,
    matched_sections: &[MatchedPatchSection],
    output_file: &object::File<'_>,
) -> Result<std::result::Result<SectionPatch, String>> {
    let target_section_index = object::SectionIndex(moved.previous_target.section_index as usize);
    let target_section = previous_file
        .section_by_index(target_section_index)
        .context("Missing previous Mach-O forwarding thunk section")?;
    let target_section_address = target_section.address();
    let decoded_name =
        hex::decode(moved.name.as_str()).context("Malformed moved Mach-O symbol name")?;
    let mut matching_definition_count = 0;
    let mut next_definition_offset = None;
    for symbol in previous_file.symbols() {
        if symbol.section_index() != Some(target_section_index) {
            continue;
        }
        let Some(section_offset) = symbol.address().checked_sub(target_section_address) else {
            return Ok(Err(
                "previous Mach-O symbol precedes its forwarding thunk section".to_owned(),
            ));
        };
        if symbol.name_bytes()? == decoded_name
            && section_offset == moved.previous_target.section_offset
        {
            matching_definition_count += 1;
        }
        if section_offset > moved.previous_target.section_offset {
            next_definition_offset = Some(
                next_definition_offset.map_or(section_offset, |next: u64| next.min(section_offset)),
            );
        }
    }
    if matching_definition_count != 1 {
        return Ok(Err(
            "moved Mach-O symbol has no unique previous definition".to_owned()
        ));
    }

    let section_record_index = patch_section_record_index(previous_file, target_section_index)?;
    let mut matching_sections = matched_sections.iter().filter(|section| {
        section.previous.input == moved.previous_target.input.as_str()
            && section.previous.section_index == section_record_index
    });
    let Some(matched_section) = matching_sections.next() else {
        return Ok(Err(
            "moved Mach-O symbol has no previous output section".to_owned()
        ));
    };
    if matching_sections.next().is_some() {
        return Ok(Err(
            "moved Mach-O symbol has ambiguous previous output sections".to_owned(),
        ));
    }

    let Some(config) =
        <crate::macho_aarch64::MachOAArch64 as crate::platform::Arch>::thunk_config()
    else {
        return Ok(Err(
            "Mach-O forwarding thunks are unavailable for this architecture".to_owned(),
        ));
    };
    let slot_end = next_definition_offset.unwrap_or(matched_section.previous.output_size);
    let Some(slot_size) = slot_end.checked_sub(moved.previous_target.section_offset) else {
        return Ok(Err(
            "moved Mach-O forwarding thunk slot has an invalid boundary".to_owned(),
        ));
    };
    if slot_size < config.thunk_size {
        return Ok(Err(format!(
            "moved Mach-O forwarding thunk slot is too small: {slot_size} bytes available, {} required",
            config.thunk_size
        )));
    }
    let Some(output_offset) = matched_section
        .previous
        .output_offset
        .checked_add(moved.previous_target.section_offset)
    else {
        return Ok(Err(
            "moved Mach-O forwarding thunk output offset overflowed".to_owned(),
        ));
    };
    let Some(slot_output_end) = output_offset.checked_add(config.thunk_size) else {
        return Ok(Err(
            "moved Mach-O forwarding thunk output range overflowed".to_owned()
        ));
    };
    let Some(section_output_end) = matched_section
        .previous
        .output_offset
        .checked_add(matched_section.previous.output_size)
    else {
        return Ok(Err(
            "previous Mach-O forwarding thunk section range overflowed".to_owned(),
        ));
    };
    if slot_output_end > section_output_end {
        return Ok(Err(
            "moved Mach-O forwarding thunk exceeds its previous output section".to_owned(),
        ));
    }
    let Some(thunk_address) = macho_output_address_for_file_offset(output_file, output_offset)
    else {
        return Ok(Err(
            "moved Mach-O forwarding thunk has no output address".to_owned()
        ));
    };
    if thunk_address != moved.previous_value {
        return Ok(Err(
            "moved Mach-O forwarding thunk address does not match its previous value".to_owned(),
        ));
    }
    let thunk_page = thunk_address & !linker_utils::elf::PAGE_MASK_4KB;
    let target_page = moved.current_value & !linker_utils::elf::PAGE_MASK_4KB;
    let page_delta = i128::from(target_page) - i128::from(thunk_page);
    let page_count = page_delta / i128::from(linker_utils::elf::SIZE_4KB);
    if !(-(1_i128 << 20)..(1_i128 << 20)).contains(&page_count) {
        return Ok(Err(
            "moved Mach-O forwarding thunk target is out of ADRP range".to_owned(),
        ));
    }

    let size = usize::try_from(config.thunk_size)
        .context("Mach-O forwarding thunk size does not fit usize")?;
    let mut data = vec![0; size];
    <crate::macho_aarch64::MachOAArch64 as crate::platform::Arch>::write_thunk(
        thunk_address,
        moved.current_value,
        &mut data,
    );
    Ok(Ok(SectionPatch {
        output_offset,
        size: config.thunk_size,
        data,
        deferred_relocation: None,
        preserve_ranges: Vec::new(),
        adjustments: Vec::new(),
    }))
}

fn macho_forwarding_thunk_patches(
    previous_bytes: &[u8],
    input_file_path: &str,
    normalize_rust_archive_patch_inputs: bool,
    moves: &[MachOSymbolResolutionMove],
    forwarded_section: &MatchedPatchSection,
    matched_sections: &[MatchedPatchSection],
    previous_output: &[u8],
) -> Result<std::result::Result<MachOForwardingThunkPatches, String>> {
    let previous_resolver =
        PatchInputResolver::new(previous_bytes, normalize_rust_archive_patch_inputs)?;
    let output_file = object::File::parse(previous_output)
        .context("Failed to parse previous Mach-O output for forwarding thunks")?;
    let mut patches = Vec::with_capacity(moves.len());
    let mut forwarded_moves = Vec::with_capacity(moves.len());
    for moved in moves {
        let Some(previous_input) = previous_resolver.resolve(
            input_file_path,
            moved.previous_target.input.as_str(),
            PatchInputLookup::MatchArchiveMember,
        )?
        else {
            return Ok(Err(
                "could not resolve previous moved Mach-O symbol input".to_owned()
            ));
        };
        let previous_file = object::File::parse(previous_input.bytes)
            .context("Failed to parse previous moved Mach-O symbol input")?;
        let target_section_index =
            object::SectionIndex(moved.previous_target.section_index as usize);
        let target_section_record_index =
            patch_section_record_index(&previous_file, target_section_index)?;
        if moved.previous_target.input.as_str() != forwarded_section.previous.input
            || moved.current_target.input.as_str() != forwarded_section.current.input
            || target_section_record_index != forwarded_section.previous.section_index
        {
            continue;
        }
        match macho_forwarding_thunk_patch(moved, &previous_file, matched_sections, &output_file)? {
            Ok(patch) => {
                patches.push(patch);
                forwarded_moves.push(moved.clone());
            }
            Err(reason) => return Ok(Err(reason)),
        }
    }
    Ok(Ok(MachOForwardingThunkPatches {
        patches,
        moves: forwarded_moves,
    }))
}

fn record_macho_forwarding_thunk_addresses(
    resolutions: &mut [MachOSymbolResolutionRecord],
    moves: &[MachOSymbolResolutionMove],
) -> std::result::Result<(), String> {
    for moved in moves {
        let matching_indices = resolutions
            .iter()
            .enumerate()
            .filter_map(|(index, resolution)| {
                (resolution.name == moved.name
                    && resolution.direct_value == Some(moved.current_value)
                    && resolution.target.as_ref() == Some(&moved.current_target))
                .then_some(index)
            })
            .collect::<Vec<_>>();
        let [resolution_index] = matching_indices.as_slice() else {
            return Err(
                "moved Mach-O symbol has no unique current resolution for forwarding thunk"
                    .to_owned(),
            );
        };
        let thunk_addresses = &mut resolutions[*resolution_index].thunk_addresses;
        thunk_addresses.push(moved.previous_value);
        thunk_addresses.sort_unstable();
        thunk_addresses.dedup();
    }
    Ok(())
}

fn reconcile_migrated_added_macho_symbol_resolutions(
    resolutions: &mut Vec<MachOSymbolResolutionRecord>,
    activation: &mut AddedMachOArchiveTextActivations,
    retiring_names: &mut Vec<SharedText>,
) -> std::result::Result<Vec<MachOSymbolResolutionMove>, String> {
    let mut migrations = Vec::new();
    let mut migrated_names = HashSet::new();
    let mut consumed_activation_indices = Vec::new();
    for name in retiring_names.iter() {
        let matching_new_indices = activation
            .symbol_resolutions
            .iter()
            .enumerate()
            .filter_map(|(index, resolution)| (resolution.name == *name).then_some(index))
            .collect::<Vec<_>>();
        let [new_index] = matching_new_indices.as_slice() else {
            continue;
        };
        let Some(old_index) = macho_symbol_resolution_index_for_name(resolutions, name.as_str())?
        else {
            return Err("missing migrated Mach-O symbol resolution catalog entry".to_owned());
        };
        let old_resolution = resolutions[old_index].clone();
        let new_resolution = activation.symbol_resolutions[*new_index].clone();
        let (Some(previous_value), Some(current_value)) =
            (old_resolution.direct_value, new_resolution.direct_value)
        else {
            return Err("migrated Mach-O symbol resolution has no direct value".to_owned());
        };
        if old_resolution.got_address.is_some()
            || old_resolution.stub_address.is_some()
            || !old_resolution.thunk_addresses.is_empty()
        {
            return Err("migrated Mach-O symbol resolution uses an indirect target".to_owned());
        }
        let (Some(previous_target), Some(current_target)) =
            (old_resolution.target, new_resolution.target.clone())
        else {
            return Err("migrated Mach-O symbol resolution has no direct owner".to_owned());
        };
        resolutions[old_index] = new_resolution;
        migrations.push(MachOSymbolResolutionMove {
            name: name.clone(),
            previous_value,
            current_value,
            previous_target,
            current_target,
        });
        migrated_names.insert(name.clone());
        consumed_activation_indices.push(*new_index);
    }

    consumed_activation_indices.sort_unstable();
    consumed_activation_indices.dedup();
    for index in consumed_activation_indices.into_iter().rev() {
        activation.symbol_resolutions.remove(index);
    }
    retiring_names.retain(|name| !migrated_names.contains(name));
    Ok(migrations)
}

fn finalize_retired_macho_archive_symbol_resolutions(
    resolutions: &mut Vec<MachOSymbolResolutionRecord>,
    retired: &[RetiredMachOArchiveActivation],
) -> std::result::Result<(), String> {
    for state in retired {
        for owned in &state.symbol_resolutions {
            let Some(index) =
                macho_symbol_resolution_index_for_name(resolutions, owned.name.as_str())?
            else {
                continue;
            };
            if resolutions[index].target == owned.target {
                resolutions.remove(index);
            }
        }
        for rollback in &state.rollback_symbol_resolutions {
            match macho_symbol_resolution_index_for_name(resolutions, rollback.name.as_str())? {
                None => resolutions.push(rollback.clone()),
                Some(index) if resolutions[index] == *rollback => {}
                Some(index)
                    if state.symbol_resolutions.iter().any(|owned| {
                        owned.name == rollback.name && resolutions[index].target != owned.target
                    }) => {}
                Some(_) => {
                    return Err(
                        "removed Mach-O archive member rollback symbol conflicts with a live resolution"
                            .to_owned(),
                    );
                }
            }
        }
    }
    resolutions.sort_unstable();
    resolutions.dedup();
    Ok(())
}

fn combined_macho_text_relocation_retiring_names(
    retiring_names: &[SharedText],
    retired: &[RetiredMachOArchiveActivation],
    migrations: &[MachOSymbolResolutionMove],
) -> Vec<SharedText> {
    let migrated_names = migrations
        .iter()
        .map(|migration| &migration.name)
        .collect::<HashSet<_>>();
    let mut names = retiring_names
        .iter()
        .chain(retired.iter().flat_map(|state| {
            state
                .symbol_resolutions
                .iter()
                .map(|resolution| &resolution.name)
        }))
        .filter(|name| !migrated_names.contains(name))
        .cloned()
        .collect::<Vec<_>>();
    names.sort_unstable();
    names.dedup();
    names
}

fn restored_macho_archive_resolution_names(
    retired: &[RetiredMachOArchiveActivation],
    migrations: &[MachOSymbolResolutionMove],
) -> Vec<SharedText> {
    let migrated_names = migrations
        .iter()
        .map(|migration| &migration.name)
        .collect::<HashSet<_>>();
    retired
        .iter()
        .flat_map(|state| &state.rollback_symbol_resolutions)
        .filter(|resolution| !migrated_names.contains(&resolution.name))
        .map(|resolution| resolution.name.clone())
        .collect()
}

fn migrated_macho_archive_rollback_symbol_resolutions(
    retired: &[RetiredMachOArchiveActivation],
    migrations: &[MachOSymbolResolutionMove],
) -> std::result::Result<Vec<MachOSymbolResolutionRecord>, String> {
    let migrated_names = migrations
        .iter()
        .map(|migration| &migration.name)
        .collect::<HashSet<_>>();
    let mut transferred = Vec::<MachOSymbolResolutionRecord>::new();
    for resolution in retired
        .iter()
        .flat_map(|state| &state.rollback_symbol_resolutions)
        .filter(|resolution| migrated_names.contains(&resolution.name))
    {
        match macho_symbol_resolution_index_for_name(&transferred, resolution.name.as_str())? {
            None => transferred.push(resolution.clone()),
            Some(index) if transferred[index] == *resolution => {}
            Some(_) => {
                return Err(
                    "migrated Mach-O symbol has conflicting rollback resolutions".to_owned(),
                );
            }
        }
    }
    transferred.sort_unstable();
    Ok(transferred)
}

fn stored_macho_archive_rollback_patch(
    forward: &StoredOutputPatch,
    previous_output: &[u8],
    retired: &[RetiredMachOArchiveActivation],
) -> std::result::Result<StoredOutputPatch, String> {
    let start = usize::try_from(forward.output_offset)
        .map_err(|_| "Mach-O archive rollback patch offset is too large".to_owned())?;
    let end = start
        .checked_add(forward.data.len())
        .ok_or_else(|| "Mach-O archive rollback patch range overflowed".to_owned())?;
    let mut composed = None::<&[u8]>;
    for rollback in retired.iter().flat_map(|state| &state.rollback_patches) {
        let rollback_start = usize::try_from(rollback.output_offset)
            .map_err(|_| "retired Mach-O archive rollback offset is too large".to_owned())?;
        let rollback_end = rollback_start
            .checked_add(rollback.data.len())
            .ok_or_else(|| "retired Mach-O archive rollback range overflowed".to_owned())?;
        if start >= rollback_end || rollback_start >= end {
            continue;
        }
        if start != rollback_start || end != rollback_end {
            return Err(
                "new Mach-O archive ownership partially overlaps a retired rollback patch"
                    .to_owned(),
            );
        }
        if composed.is_some_and(|data| data != rollback.data.as_slice()) {
            return Err("retired Mach-O archive rollback patches conflict".to_owned());
        }
        composed = Some(&rollback.data);
    }
    let data = match composed {
        Some(data) => data.to_vec(),
        None => previous_output
            .get(start..end)
            .ok_or_else(|| "Mach-O archive rollback patch is outside output".to_owned())?
            .to_vec(),
    };
    Ok(StoredOutputPatch {
        output_offset: forward.output_offset,
        data,
    })
}

fn deferred_instruction_relocation_patch(
    rel_info: RelocationKindInfo,
    previous_written_value: u64,
    written_value: u64,
) -> Option<DeferredRelocationPatch> {
    matches!(rel_info.size, RelocationSize::BitMasking(_)).then_some(DeferredRelocationPatch {
        rel_info,
        previous_written_value,
        written_value,
    })
}

fn relocation_kind_info(
    file: &object::File<'_>,
    relocation_kind: u32,
) -> Option<RelocationKindInfo> {
    Some(match file.architecture() {
        object::Architecture::X86_64 => x86_64::relocation_from_raw(relocation_kind)?,
        object::Architecture::Aarch64 => aarch64::relocation_type_from_raw(relocation_kind)?,
        object::Architecture::LoongArch64 => {
            loongarch64::relocation_type_from_raw(relocation_kind)?
        }
        object::Architecture::Riscv64 => riscv64::relocation_type_from_raw(relocation_kind)?,
        _ => return None,
    })
}

const MACHO_AARCH64_RELOCATION_KIND_TAG: u32 = 0xa000_0000;
const MACHO_RELOCATION_KIND_TAG_MASK: u32 = 0xf000_0000;

pub(crate) fn encode_macho_aarch64_relocation_kind(
    relocation: object::macho::RelocationInfo,
) -> u32 {
    MACHO_AARCH64_RELOCATION_KIND_TAG
        | u32::from(relocation.r_type & 0xf)
        | (u32::from(relocation.r_pcrel) << 4)
        | (u32::from(relocation.r_length & 0x3) << 5)
        | (u32::from(relocation.r_extern) << 7)
}

fn decode_macho_aarch64_relocation_kind(kind: u32) -> Option<object::macho::RelocationInfo> {
    (kind & MACHO_RELOCATION_KIND_TAG_MASK == MACHO_AARCH64_RELOCATION_KIND_TAG).then_some(
        object::macho::RelocationInfo {
            r_address: 0,
            r_symbolnum: 0,
            r_pcrel: kind & (1 << 4) != 0,
            r_length: ((kind >> 5) & 0x3) as u8,
            r_extern: kind & (1 << 7) != 0,
            r_type: (kind & 0xf) as u8,
        },
    )
}

fn macho_aarch64_relocated_value(
    r_type: u8,
    target_value: u64,
    addend: i64,
    place: u64,
) -> Option<u64> {
    let target_value = target_value.wrapping_add(addend as u64);
    Some(match r_type {
        object::macho::ARM64_RELOC_UNSIGNED => target_value,
        object::macho::ARM64_RELOC_BRANCH26 => target_value.wrapping_sub(place),
        object::macho::ARM64_RELOC_PAGE21 => (target_value & !linker_utils::elf::PAGE_MASK_4KB)
            .wrapping_sub(place & !linker_utils::elf::PAGE_MASK_4KB),
        object::macho::ARM64_RELOC_PAGEOFF12 => target_value,
        _ => return None,
    })
}

fn macho_aarch64_cross_input_relocation_is_supported(
    relocation: object::macho::RelocationInfo,
    size: u64,
) -> bool {
    if size != 4 || relocation.r_length != 2 || !relocation.r_extern {
        return false;
    }
    match relocation.r_type {
        object::macho::ARM64_RELOC_BRANCH26 | object::macho::ARM64_RELOC_PAGE21 => {
            relocation.r_pcrel
        }
        object::macho::ARM64_RELOC_PAGEOFF12 => !relocation.r_pcrel,
        _ => false,
    }
}

fn macho_aarch64_relocated_value_after_target_move(
    r_type: u8,
    previous_written_value: u64,
    previous_target_value: u64,
    current_target_value: u64,
    addend: i64,
) -> Option<u64> {
    let previous_target_component =
        macho_aarch64_relocated_value(r_type, previous_target_value, addend, 0)?;
    let current_target_component =
        macho_aarch64_relocated_value(r_type, current_target_value, addend, 0)?;
    Some(
        previous_written_value
            .wrapping_add(current_target_component.wrapping_sub(previous_target_component)),
    )
}

fn dedup_ranges(ranges: &mut Vec<std::ops::Range<usize>>) {
    ranges.sort_by_key(|range| (range.start, range.end));
    ranges.dedup_by(|left, right| left.start == right.start && left.end == right.end);
}

fn add_signed_delta_u64(value: u64, delta: i128) -> Option<u64> {
    let adjusted = i128::from(value).checked_add(delta)?;
    u64::try_from(adjusted).ok()
}

fn add_encoded_delta_u64(value: u64, delta: i128) -> u64 {
    let modulus = i128::from(u64::MAX) + 1;
    let adjusted = (i128::from(value) + delta).rem_euclid(modulus);
    adjusted as u64
}

#[derive(Clone)]
struct SymbolPosition {
    section_index: object::SectionIndex,
    section_offset: u64,
    value_range: Option<std::ops::Range<usize>>,
}

enum IndexedSymbolPosition {
    Unique(SymbolPosition),
    Ambiguous,
}

struct IndexedMachOSymbolCatalogInput<'data> {
    file: object::File<'data>,
    current_input: String,
    positions: HashMap<SharedText, IndexedSymbolPosition>,
}

fn indexed_unique_symbol_positions(
    bytes: &[u8],
    file_offset: usize,
    file: &object::File<'_>,
    encoded_names: &[SharedText],
) -> Result<HashMap<SharedText, IndexedSymbolPosition>> {
    let mut requested = HashMap::with_capacity(encoded_names.len());
    for encoded_name in encoded_names {
        requested.insert(
            hex::decode(encoded_name.as_str())
                .context("Malformed incremental relocation target name")?,
            encoded_name.clone(),
        );
    }
    let mut positions = HashMap::with_capacity(requested.len());
    for symbol in file.symbols() {
        let name = symbol.name_bytes()?;
        let Some(encoded_name) = requested.get(name) else {
            continue;
        };
        let Some(section_index) = symbol.section_index() else {
            continue;
        };
        let section_address = file.section_by_index(section_index)?.address();
        let section_offset = symbol
            .address()
            .checked_sub(section_address)
            .context("Mach-O symbol address precedes its section")?;
        let value_range = symbol_value_field_range(bytes, symbol.index())
            .map(|range| file_offset + range.start..file_offset + range.end);
        match positions.entry(encoded_name.clone()) {
            hashbrown::hash_map::Entry::Vacant(entry) => {
                entry.insert(IndexedSymbolPosition::Unique(SymbolPosition {
                    section_index,
                    section_offset,
                    value_range,
                }));
            }
            hashbrown::hash_map::Entry::Occupied(mut entry) => {
                entry.insert(IndexedSymbolPosition::Ambiguous);
            }
        }
    }
    Ok(positions)
}

fn symbol_position_by_name(
    bytes: &[u8],
    file_offset: usize,
    file: &object::File<'_>,
    encoded_name: &str,
) -> Result<Option<SymbolPosition>> {
    let name = hex::decode(encoded_name).context("Malformed incremental relocation target name")?;
    for symbol in file.symbols() {
        if symbol.name_bytes()? != name {
            continue;
        }
        let Some(section_index) = symbol.section_index() else {
            return Ok(None);
        };
        let section_offset = if file.format() == object::BinaryFormat::MachO {
            let section_address = file.section_by_index(section_index)?.address();
            symbol
                .address()
                .checked_sub(section_address)
                .context("Mach-O symbol address precedes its section")?
        } else {
            symbol.address()
        };
        let value_range = symbol_value_field_range(bytes, symbol.index())
            .map(|range| file_offset + range.start..file_offset + range.end);
        return Ok(Some(SymbolPosition {
            section_index,
            section_offset,
            value_range,
        }));
    }
    Ok(None)
}

fn unique_symbol_position_by_name(
    bytes: &[u8],
    file_offset: usize,
    file: &object::File<'_>,
    encoded_name: &str,
) -> Result<std::result::Result<Option<SymbolPosition>, String>> {
    let name = hex::decode(encoded_name).context("Malformed incremental relocation target name")?;
    let mut matched = None;
    for symbol in file.symbols() {
        if symbol.name_bytes()? != name {
            continue;
        }
        let Some(section_index) = symbol.section_index() else {
            continue;
        };
        if matched.is_some() {
            return Ok(Err(
                "ambiguous cross-input Mach-O relocation target symbol".to_owned()
            ));
        }
        let section_address = file.section_by_index(section_index)?.address();
        let section_offset = symbol
            .address()
            .checked_sub(section_address)
            .context("Mach-O symbol address precedes its section")?;
        let value_range = symbol_value_field_range(bytes, symbol.index())
            .map(|range| file_offset + range.start..file_offset + range.end);
        matched = Some(SymbolPosition {
            section_index,
            section_offset,
            value_range,
        });
    }
    Ok(Ok(matched))
}

fn symbol_position_by_name_and_value(
    bytes: &[u8],
    file_offset: usize,
    file: &object::File<'_>,
    encoded_name: &str,
    value: u64,
) -> Result<std::result::Result<Option<SymbolPosition>, String>> {
    let name = hex::decode(encoded_name).context("Malformed incremental relocation target name")?;
    let mut matched_symbol = None;
    let mut name_was_present = false;
    for symbol in file.symbols() {
        if symbol.name_bytes()? != name {
            continue;
        }
        name_was_present = true;
        if symbol.address() != value {
            continue;
        }
        if matched_symbol.is_some() {
            return Ok(Err(
                "ambiguous output symbol for incremental value patch".to_owned()
            ));
        }
        let Some(section_index) = symbol.section_index() else {
            return Ok(Ok(None));
        };
        let value_range = symbol_value_field_range(bytes, symbol.index())
            .map(|range| file_offset + range.start..file_offset + range.end);
        matched_symbol = Some(SymbolPosition {
            section_index,
            section_offset: symbol.address(),
            value_range,
        });
    }
    if matched_symbol.is_none() && name_was_present {
        return Ok(Err(
            "output symbol value changed before incremental patch".to_owned()
        ));
    }
    Ok(Ok(matched_symbol))
}

fn output_symbol_value_patches(
    output: &[u8],
    symbols: &[RelocationTargetSymbolPatch],
) -> Result<std::result::Result<Vec<SectionPatch>, String>> {
    if symbols.is_empty() {
        return Ok(Ok(Vec::new()));
    }

    let file = object::File::parse(output)
        .context("Failed to parse output for incremental symbol value patching")?;
    let mut values_by_previous_name_and_value =
        HashMap::<(&str, u64), (u64, bool, &'static str)>::new();
    for symbol in symbols {
        let key = (symbol.target_name.as_str(), symbol.previous_target_value);
        match values_by_previous_name_and_value.entry(key) {
            hashbrown::hash_map::Entry::Vacant(entry) => {
                entry.insert((symbol.target_value, symbol.allow_missing, symbol.source));
            }
            hashbrown::hash_map::Entry::Occupied(mut entry) => {
                if entry.get().0 != symbol.target_value {
                    return Ok(Err(format!(
                        "conflicting incremental symbol value patches for `{}` from {:#x} to \
                         {:#x} ({}) and {:#x} ({})",
                        display_hex_text(symbol.target_name.as_str()),
                        symbol.previous_target_value,
                        entry.get().0,
                        entry.get().2,
                        symbol.target_value,
                        symbol.source,
                    )));
                }
                entry.get_mut().1 &= symbol.allow_missing;
            }
        }
    }

    let mut patches = Vec::with_capacity(values_by_previous_name_and_value.len());
    for ((target_name, previous_target_value), (target_value, allow_missing, source)) in
        values_by_previous_name_and_value
    {
        let symbol = symbol_position_by_name_and_value(
            output,
            0,
            &file,
            target_name,
            previous_target_value,
        )?;
        let symbol = match symbol {
            Ok(Some(symbol)) => symbol,
            Ok(None) if allow_missing => continue,
            Ok(None) => {
                return Ok(Err(
                    "missing output symbol for incremental value patch".to_owned()
                ));
            }
            Err(_)
                if allow_missing
                    && matches!(
                        symbol_position_by_name_and_value(
                            output,
                            0,
                            &file,
                            target_name,
                            target_value,
                        )?,
                        Ok(Some(_))
                    ) =>
            {
                continue;
            }
            Err(error) => {
                return Ok(Err(format!(
                    "{error} for `{}` at {previous_target_value:#x} from {source}",
                    display_hex_text(target_name),
                )));
            }
        };
        let Some(value_range) = symbol.value_range else {
            return Ok(Err(
                "missing output symbol value range for incremental patch".to_owned(),
            ));
        };
        let data = match value_range.len() {
            4 => {
                let Ok(value) = u32::try_from(target_value) else {
                    return Ok(Err(
                        "incremental output symbol value patch overflowed".to_owned()
                    ));
                };
                value.to_le_bytes().to_vec()
            }
            8 => target_value.to_le_bytes().to_vec(),
            _ => {
                return Ok(Err(
                    "unsupported output symbol value size for incremental patch".to_owned(),
                ));
            }
        };
        patches.push(SectionPatch {
            output_offset: value_range.start as u64,
            size: value_range.len() as u64,
            data,
            deferred_relocation: None,
            preserve_ranges: Vec::new(),
            adjustments: Vec::new(),
        });
    }

    Ok(Ok(patches))
}

fn patch_changed_inputs(
    args: &impl platform::Args,
    state_dir: &Path,
    previous: PersistedState,
    current_link_start: Option<FileIdentity>,
    record_coverage: ChangedInputRecordCoverage,
    changed_inputs: &[(usize, PathBuf)],
    metadata_update_input_indices: &[usize],
) -> Result<ChangedInputPatchResult> {
    // The embedded digest is a rustc producer assertion. Trust it only inside the
    // Cargo-managed provenance lane; all other callers keep the byte classifier fallback.
    patch_changed_inputs_with_rustc_link_content_digest_trust(
        args,
        state_dir,
        previous,
        current_link_start,
        record_coverage,
        changed_inputs,
        metadata_update_input_indices,
        rustc_work_product_provenance_enabled(),
    )
}

#[allow(clippy::too_many_arguments)]
fn patch_changed_inputs_with_rustc_link_content_digest_trust(
    args: &impl platform::Args,
    state_dir: &Path,
    previous: PersistedState,
    current_link_start: Option<FileIdentity>,
    record_coverage: ChangedInputRecordCoverage,
    changed_inputs: &[(usize, PathBuf)],
    metadata_update_input_indices: &[usize],
    trust_rustc_link_content_digests: bool,
) -> Result<ChangedInputPatchResult> {
    timing_phase!("Patch changed incremental inputs");

    let records_complete = record_coverage.is_complete();
    let mut previous = previous;
    if record_coverage == ChangedInputRecordCoverage::ChangedInputsWithCompleteMachOResolutions {
        previous.macho_symbol_resolutions.clear();
    }
    if record_coverage.has_complete_macho_symbol_resolutions() {
        previous.load_macho_symbol_resolutions(state_dir)?;
    }
    let mut patches = Vec::new();
    let mut output_symbol_patches = Vec::new();
    let mut eh_frame_hdr_changes = Vec::new();
    let mut fde_add_candidates = Vec::new();
    let mut expected_changed_inputs = Vec::new();
    let mut rewritten_input_count = 0;
    let mut normalized_unchanged_input_count = 0;
    let mut rustc_link_content_digest_unchanged_input_count = 0;
    let mut rustc_link_content_digest_unchanged_input_indices = HashSet::new();
    let mut deferred_loaded_input_content_hashes = Vec::new();
    let mut hashless_atomic_replacement_snapshot_count = 0;
    let mut patched_input_count = 0;
    let mut patched_section_count = 0;
    let mut record_override_input_files = HashSet::new();
    let changed_input_files = changed_inputs
        .iter()
        .map(|(input_index, _)| previous.input_files[*input_index].path.clone())
        .collect::<HashSet<_>>();
    let changed_input_paths = changed_inputs
        .iter()
        .map(|(_, path)| path.clone())
        .collect::<Vec<_>>();
    let mut indexed_changed_input_macho_definitions = None;
    let mut previous_output = LazyOutputBytes::new(|| read_output_bytes(args.output()));
    for (input_index, path) in changed_inputs {
        let mut loaded_input = None;
        let normalize_rust_archive_patch_inputs = args.should_normalize_rust_archive_patch_inputs();
        let can_reuse_rustc_link_content_digest = can_reuse_rustc_link_content_digest(args, path);
        let can_normalize_rust_archive_patch =
            can_normalize_rust_archive_patch(args, &previous, *input_index, path);
        if can_reuse_rustc_link_content_digest
            && trust_rustc_link_content_digests
            && previous_rustc_rlib_link_content_digest(&previous.input_files[*input_index])
                .is_some()
            && let Some(input_content) = ({
                timing_phase!("Read rustc rlib link-content digest");
                rustc_rlib_link_content_digest_matches_previous_path(
                    &previous.input_files[*input_index],
                    path,
                )
            })
        {
            let rustc_link_content_digest =
                previous_rustc_rlib_link_content_digest(&previous.input_files[*input_index])
                    .map(str::to_owned);
            expected_changed_inputs.push(ExpectedInputContent::from_content(path, &input_content));
            previous.input_files[*input_index].content = input_content;
            previous.input_files[*input_index].snapshot_identity = None;
            previous.input_files[*input_index].rustc_link_content_digest =
                rustc_link_content_digest;
            normalized_unchanged_input_count += 1;
            rustc_link_content_digest_unchanged_input_count += 1;
            rustc_link_content_digest_unchanged_input_indices.insert(*input_index);
            continue;
        }
        if previous.input_files[*input_index].patch.is_some() {
            let Some((bytes, input_content)) = ({
                timing_phase!("Read changed incremental input");
                read_file_with_stable_identity_and_hashing(path, !can_normalize_rust_archive_patch)
                    .with_context(|| {
                        format!(
                            "Failed to read changed incremental input `{}`",
                            path.display()
                        )
                    })?
            }) else {
                return Ok(ChangedInputPatchResult::Unsupported(format!(
                    "changed input changed while being read: {}",
                    path.display()
                )));
            };
            if content_state_matches_previous(
                &previous.input_files[*input_index].content,
                &input_content,
            ) {
                expected_changed_inputs
                    .push(ExpectedInputContent::from_content(path, &input_content));
                previous.input_files[*input_index].content = input_content;
                previous.input_files[*input_index].snapshot_identity = None;
                rewritten_input_count += 1;
                continue;
            }
            loaded_input = Some((bytes, input_content));
        }
        if previous.input_files[*input_index]
            .patch
            .as_ref()
            .is_none_or(|patch| {
                patch.sections.is_empty() && patch.raw_sections.as_deref().is_none_or(str::is_empty)
            })
            && previous
                .sections
                .iter()
                .any(|section| section.input_file == previous.input_files[*input_index].path)
        {
            let patch = current_patch_state_from_snapshot_with_rustc_work_product_provenance(
                state_dir,
                &previous.input_files[*input_index],
                previous_output.get()?,
                &previous.sections,
                &previous.relocations,
                &previous.macho_symbol_resolutions,
                &previous.fdes,
                &previous.dynamic_relocations,
                args.should_normalize_rust_archive_patch_inputs(),
                trust_rustc_link_content_digests,
            )?;
            previous.input_files[*input_index].patch = patch;
        }
        let mut previous_patch = {
            let input = &previous.input_files[*input_index];
            match patch_sections_from_previous_state(input, path) {
                Ok(previous_patch) => previous_patch,
                Err(reason) => return Ok(ChangedInputPatchResult::Unsupported(reason)),
            }
        };
        let (bytes, mut input_content) = if let Some(loaded_input) = loaded_input {
            loaded_input
        } else {
            let Some(loaded_input) = ({
                timing_phase!("Read changed incremental input");
                read_file_with_stable_identity(path).with_context(|| {
                    format!(
                        "Failed to read changed incremental input `{}`",
                        path.display()
                    )
                })?
            }) else {
                return Ok(ChangedInputPatchResult::Unsupported(format!(
                    "changed input changed while being read: {}",
                    path.display()
                )));
            };
            loaded_input
        };
        let rustc_provenance = (can_reuse_rustc_link_content_digest
            && trust_rustc_link_content_digests)
            .then(|| rustc_rlib_provenance(&bytes))
            .flatten();
        let input = &previous.input_files[*input_index];
        if can_reuse_rustc_link_content_digest
            && trust_rustc_link_content_digests
            && rustc_provenance.as_ref().is_some_and(|provenance| {
                rustc_rlib_link_content_digest_value_matches_previous(
                    input,
                    &provenance.link_content_digest,
                )
            })
        {
            let rustc_link_content_digest =
                previous_rustc_rlib_link_content_digest(input).map(str::to_owned);
            expected_changed_inputs.push(ExpectedInputContent::from_content(path, &input_content));
            previous.input_files[*input_index].content = input_content;
            previous.input_files[*input_index].snapshot_identity = None;
            previous.input_files[*input_index].rustc_link_content_digest =
                rustc_link_content_digest;
            normalized_unchanged_input_count += 1;
            rustc_link_content_digest_unchanged_input_count += 1;
            rustc_link_content_digest_unchanged_input_indices.insert(*input_index);
            continue;
        }
        let normalized_rust_archive_patch_state = if can_normalize_rust_archive_patch {
            classify_normalized_rust_archive_patch_state(input, &bytes, &previous_patch)?
        } else {
            NormalizedRustArchivePatchState::Unknown
        };
        let normalized_rust_archive_matched_sections = match normalized_rust_archive_patch_state {
            NormalizedRustArchivePatchState::Unchanged(patch) => {
                expected_changed_inputs
                    .push(ExpectedInputContent::from_content(path, &input_content));
                previous.input_files[*input_index].content = input_content;
                previous.input_files[*input_index].snapshot_identity = None;
                previous.input_files[*input_index].rustc_link_content_digest = rustc_provenance
                    .as_ref()
                    .map(|provenance| provenance.link_content_digest.clone());
                previous.input_files[*input_index].rustc_raw_object_manifest = rustc_provenance
                    .as_ref()
                    .and_then(|provenance| provenance.raw_object_manifest.clone());
                previous.input_files[*input_index].patch = Some(patch);
                normalized_unchanged_input_count += 1;
                continue;
            }
            NormalizedRustArchivePatchState::MatchedButNotUnchanged(matched) => Some(matched),
            NormalizedRustArchivePatchState::Unknown => None,
        };
        let retain_hashless_atomic_replacement_snapshot =
            can_retain_hashless_atomic_replacement_snapshot(
                path,
                normalized_rust_archive_matched_sections.is_some(),
                trust_rustc_link_content_digests,
            ) && input_content.hash.is_empty();
        if retain_hashless_atomic_replacement_snapshot {
            hashless_atomic_replacement_snapshot_count += 1;
        }
        let defer_loaded_input_content_hash = normalized_rust_archive_matched_sections.is_some()
            && input_content.hash.is_empty()
            && !retain_hashless_atomic_replacement_snapshot;
        if !defer_loaded_input_content_hash && !retain_hashless_atomic_replacement_snapshot {
            ensure_loaded_input_content_hash(&bytes, &mut input_content);
        }
        let expected_changed_input_index = expected_changed_inputs.len();
        expected_changed_inputs.push(ExpectedInputContent::from_content(path, &input_content));
        patched_input_count += 1;

        let (
            fingerprint,
            archive_member_patch_fingerprints,
            archive_member_set_proof,
            matched_sections,
            current_sections,
            resolved_patches,
            fde_eh_frame_hdr_changes,
            input_fde_add_candidates,
            added_dynamic_relocations,
            removed_dynamic_relocations,
            removed_fdes,
            updated_fdes,
            macho_text_section_activation,
            changed_macho_definition_activation,
            changed_macho_archive_unwind_activation,
            added_macho_archive_text_activation,
            retired_macho_archive_activations,
        ) = {
            let input = &previous.input_files[*input_index];
            let retained_macho_archive_members = input
                .patch
                .as_ref()
                .map(|patch| patch.macho_archive_members.clone())
                .unwrap_or_default();
            let mut previous_snapshot_bytes =
                LazyInputSnapshotBytes::new(|| read_verified_input_snapshot(state_dir, input));
            timing_phase!("Resolve changed incremental patches");
            let current_resolver = {
                timing_phase!("Parse changed patch input");
                PatchInputResolver::new(&bytes, normalize_rust_archive_patch_inputs)?
            };
            let archive_member_set_proof = archive_member_set_proof(&bytes)?;
            let archive_members_match = {
                timing_phase!("Compare changed archive members");
                if archive_member_set_proof_matches_current(
                    input,
                    &previous_patch,
                    archive_member_set_proof.as_ref(),
                    normalize_rust_archive_patch_inputs,
                ) == Some(true)
                {
                    true
                } else {
                    let previous_bytes = {
                        timing_phase!("Read previous incremental input snapshot");
                        previous_snapshot_bytes.get()?
                    };
                    archive_members_match_snapshot(
                        state_dir,
                        input,
                        previous_bytes,
                        &bytes,
                        normalize_rust_archive_patch_inputs,
                    )?
                }
            };
            let archive_member_delta = if archive_members_match {
                None
            } else if args.should_activate_macho_archive_members() {
                let previous_bytes = {
                    timing_phase!("Read previous incremental input snapshot");
                    previous_snapshot_bytes.get()?
                };
                if let Some(previous_bytes) = previous_bytes {
                    archive_member_identifier_delta(
                        previous_bytes,
                        &bytes,
                        normalize_rust_archive_patch_inputs,
                    )?
                } else {
                    None
                }
            } else {
                None
            };
            let added_archive_member_identifiers = archive_member_delta
                .as_ref()
                .filter(|delta| !delta.added.is_empty())
                .map(|delta| delta.added.clone());
            let mut retired_macho_archive_activations = Vec::new();
            if let Some(delta) = archive_member_delta
                .as_ref()
                .filter(|delta| !delta.removed.is_empty())
            {
                let Some(stored_patch) = input.patch.as_ref() else {
                    return Ok(ChangedInputPatchResult::Unsupported(
                        "removed Mach-O archive member has no patch state".to_owned(),
                    ));
                };
                let ownership =
                    match owned_macho_archive_removal_indices(stored_patch, &delta.removed) {
                        Ok(ownership) => ownership,
                        Err(reason) => return Ok(ChangedInputPatchResult::Unsupported(reason)),
                    };
                if (!ownership.tracked_indices.is_empty()
                    || !ownership.initially_owned_identifiers.is_empty())
                    && !records_complete
                {
                    return Ok(ChangedInputPatchResult::RequiresCompleteRecords(
                        "removed Mach-O archive members need complete records".to_owned(),
                    ));
                }
                let Some(previous_bytes) = previous_snapshot_bytes.get()? else {
                    return Ok(ChangedInputPatchResult::Unsupported(
                        "removed Mach-O archive member needs the previous input snapshot"
                            .to_owned(),
                    ));
                };
                let mut retirements = ownership
                    .tracked_indices
                    .into_iter()
                    .map(|index| RetiredMachOArchiveActivation {
                        state: stored_patch.macho_archive_members[index].clone(),
                        newly_tracked: false,
                    })
                    .collect::<Vec<_>>();
                for identifier in ownership.initially_owned_identifiers {
                    let state = match initially_owned_macho_archive_removal_state(
                        previous_bytes,
                        input.path.as_str(),
                        stored_patch,
                        &identifier,
                    )? {
                        Ok(state) => state,
                        Err(reason) => {
                            return Ok(ChangedInputPatchResult::Unsupported(reason));
                        }
                    };
                    retirements.push(RetiredMachOArchiveActivation {
                        state,
                        newly_tracked: true,
                    });
                }
                for mut retirement in retirements {
                    let state = &mut retirement.state;
                    let normalized_identifiers = state
                        .members
                        .iter()
                        .map(|member| member.normalized_identifier.clone())
                        .collect::<HashSet<_>>();
                    for member in &state.members {
                        let matched = match patch_archive_member_bytes(
                            previous_bytes,
                            &member.normalized_identifier,
                        )? {
                            ArchiveMemberMatch::Unique(member) => member,
                            ArchiveMemberMatch::Unavailable | ArchiveMemberMatch::Ambiguous => {
                                return Ok(ChangedInputPatchResult::Unsupported(
                                    "could not validate removed Mach-O archive member ownership"
                                        .to_owned(),
                                ));
                            }
                        };
                        if hash_bytes(matched.bytes) != member.object_hash {
                            return Ok(ChangedInputPatchResult::Unsupported(
                                "removed Mach-O archive member changed after activation".to_owned(),
                            ));
                        }
                    }
                    let mut member_inputs = state
                        .sections
                        .iter()
                        .map(|section| section.input.clone())
                        .collect::<HashSet<String>>();
                    let candidate_inputs =
                        previous_patch
                            .sections
                            .iter()
                            .map(|section| section.input.as_str())
                            .chain(
                                previous
                                    .sections
                                    .iter()
                                    .filter(|record| record.input_file == input.path)
                                    .map(|record| record.input.as_str()),
                            )
                            .chain(
                                previous
                                    .relocations
                                    .iter()
                                    .filter(|record| record.input_file == input.path)
                                    .map(|record| record.input.as_str()),
                            )
                            .chain(previous.relocations.iter().filter_map(|record| {
                                record
                                    .target
                                    .as_ref()
                                    .filter(|target| target.input_file == input.path)
                                    .map(|target| target.input.as_str())
                            }))
                            .chain(previous.macho_symbol_resolutions.iter().filter_map(
                                |resolution| {
                                    resolution
                                        .target
                                        .as_ref()
                                        .filter(|target| target.input_file == input.path)
                                        .map(|target| target.input.as_str())
                                },
                            ))
                            .chain(
                                previous
                                    .dynamic_relocations
                                    .iter()
                                    .filter(|record| record.input_file == input.path)
                                    .map(|record| record.input.as_str()),
                            )
                            .chain(
                                previous
                                    .fdes
                                    .iter()
                                    .filter(|record| record.input_file == input.path)
                                    .map(|record| record.input.as_str()),
                            )
                            .map(str::to_owned)
                            .collect::<Vec<_>>();
                    for candidate in candidate_inputs {
                        if normalized_archive_input_ref_matches_identifiers(
                            input.path.as_str(),
                            &candidate,
                            &normalized_identifiers,
                        )? {
                            member_inputs.insert(candidate);
                        }
                    }
                    let current_member_sections = previous_patch
                        .sections
                        .iter()
                        .filter(|section| member_inputs.contains(section.input.as_str()))
                        .map(file_patch_section_state)
                        .collect::<Vec<_>>();
                    if current_member_sections.len() != state.sections.len() {
                        return Ok(ChangedInputPatchResult::Unsupported(
                            "removed Mach-O archive member ownership sections changed".to_owned(),
                        ));
                    }
                    state.sections = current_member_sections;
                    if previous.dynamic_relocations.iter().any(|record| {
                        record.input_file == input.path
                            && member_inputs.contains(record.input.as_str())
                    }) || previous.fdes.iter().any(|record| {
                        record.input_file == input.path
                            && member_inputs.contains(record.input.as_str())
                    }) {
                        return Ok(ChangedInputPatchResult::Unsupported(
                            "removed Mach-O archive member owns unsupported persisted records"
                                .to_owned(),
                        ));
                    }
                    previous.relocations.retain(|record| {
                        if record.input_file == input.path
                            && member_inputs.contains(record.input.as_str())
                        {
                            state.relocations.push(record.clone());
                            false
                        } else {
                            true
                        }
                    });
                    for resolution in &previous.macho_symbol_resolutions {
                        if resolution.target.as_ref().is_some_and(|target| {
                            target.input_file == input.path
                                && member_inputs.contains(target.input.as_str())
                        }) {
                            state.symbol_resolutions.push(resolution.clone());
                        }
                    }
                    if retirement.newly_tracked {
                        if let Err(reason) = retain_initial_macho_archive_removal_transaction(
                            state,
                            previous_output.get()?,
                        ) {
                            return Ok(ChangedInputPatchResult::Unsupported(reason));
                        }
                    }
                    previous_patch
                        .sections
                        .retain(|section| !member_inputs.contains(section.input.as_str()));
                    state.active = false;
                    retired_macho_archive_activations.push(retirement);
                }
                previous.sections_file = None;
                previous.macho_symbol_resolutions_file = None;
            }
            if !archive_members_match
                && added_archive_member_identifiers.is_none()
                && retired_macho_archive_activations.is_empty()
            {
                return Ok(ChangedInputPatchResult::Unsupported(format!(
                    "archive members changed in `{}`",
                    path.display()
                )));
            }
            let normalized_rust_archive_matched_sections =
                if retired_macho_archive_activations.is_empty() {
                    normalized_rust_archive_matched_sections
                } else {
                    None
                };
            let mut relocation_target_patches = {
                timing_phase!("Resolve changed relocation targets");
                match relocation_target_patches_for_input(&mut previous.relocations, input, &bytes)?
                {
                    Ok(patches) => patches,
                    Err(reason) => return Ok(ChangedInputPatchResult::Unsupported(reason)),
                }
            };
            match changed_relocation_target_record_owners(
                &relocation_target_patches,
                &previous.relocations,
                &changed_input_files,
                records_complete,
            ) {
                Ok(changed_record_owners) => {
                    record_override_input_files.extend(changed_record_owners);
                }
                Err(RelocationTargetRecordCoverageError::MissingOwner) => {
                    return Ok(ChangedInputPatchResult::Unsupported(
                        "changed relocation target has no recorded owner".to_owned(),
                    ));
                }
                Err(RelocationTargetRecordCoverageError::RequiresCompleteRecords) => {
                    return Ok(ChangedInputPatchResult::RequiresCompleteRecords(
                        "changed relocation targets need complete relocation records".to_owned(),
                    ));
                }
            }
            if input_has_records_requiring_previous_bytes(&previous, input) {
                timing_phase!("Read previous incremental input snapshot");
                previous_snapshot_bytes.get()?;
            }
            let relocation_addend_patches = {
                timing_phase!("Resolve changed relocation addends");
                match relocation_addend_patches_for_input(
                    &mut previous.relocations,
                    input,
                    &bytes,
                    previous_snapshot_bytes.get_if_loaded(),
                    &previous.dynamic_relocations,
                )? {
                    Ok(patches) => patches,
                    Err(reason) => return Ok(ChangedInputPatchResult::Unsupported(reason)),
                }
            };
            if relocation_addend_patches.records_changed {
                if !record_coverage.has_changed_input_records() {
                    return Ok(ChangedInputPatchResult::RequiresChangedInputRecords(
                        "changed relocation addends need relocation records".to_owned(),
                    ));
                }
                record_override_input_files.insert(previous.input_files[*input_index].path.clone());
            }

            let matched_patch_sections = {
                timing_phase!("Match changed patch sections");
                if let Some(matched) = normalized_rust_archive_matched_sections {
                    Some(matched)
                } else if let Some(matched) =
                    match_patch_sections_from_current_hashes_with_resolver(
                        input.path.as_str(),
                        &previous_patch.sections,
                        &current_resolver,
                    )?
                {
                    Some(matched)
                } else {
                    let previous_bytes = {
                        timing_phase!("Read previous incremental input snapshot");
                        previous_snapshot_bytes.get()?
                    };
                    let previous_resolver = {
                        timing_phase!("Parse previous patch input");
                        previous_bytes
                            .map(|bytes| {
                                PatchInputResolver::new(bytes, normalize_rust_archive_patch_inputs)
                            })
                            .transpose()?
                    };
                    if let Some(previous_resolver) = previous_resolver.as_ref() {
                        match_patch_sections_with_resolvers(
                            input,
                            previous_resolver,
                            &current_resolver,
                            &previous_patch.sections,
                        )?
                    } else {
                        None
                    }
                }
            };

            let (mut matched_sections, matched_changed_sections) = match matched_patch_sections {
                Some(matched_sections) => (
                    matched_sections.sections,
                    Some(matched_sections.changed_sections),
                ),
                None if previous_patch
                    .sections
                    .iter()
                    .any(|section| section.section_name.is_none()) =>
                {
                    return Ok(ChangedInputPatchResult::Unsupported(format!(
                        "could not match anonymous patch sections in `{}`",
                        path.display()
                    )));
                }
                None => (
                    previous_patch
                        .sections
                        .iter()
                        .cloned()
                        .map(MatchedPatchSection::same)
                        .collect(),
                    None,
                ),
            };
            let matched_from_snapshot = matched_changed_sections.is_some();
            let mut current_sections = matched_sections
                .iter()
                .map(|section| section.current.clone())
                .collect::<Vec<_>>();
            let mut macho_text_section_activation = if args.should_activate_macho_text_sections()
                || args.should_activate_macho_archive_members()
            {
                let previous_bytes = {
                    timing_phase!("Read previous incremental input snapshot");
                    previous_snapshot_bytes.get()?
                };
                if let Some(previous_bytes) = previous_bytes {
                    match macho_text_section_activation(
                        previous_bytes,
                        &bytes,
                        input.path.as_str(),
                        &matched_sections,
                        &previous.reserved_ranges,
                        args.common().incremental_padding_percent,
                        normalize_rust_archive_patch_inputs,
                        args.should_activate_macho_text_sections(),
                    )? {
                        Ok(activation) => activation,
                        Err(reason) => {
                            return Ok(ChangedInputPatchResult::Unsupported(reason));
                        }
                    }
                } else {
                    None
                }
            } else {
                None
            };
            if let Some(activation) = &macho_text_section_activation {
                for activated in &activation.text_sections {
                    if let Some(index) = activated.matched_section_index {
                        matched_sections[index].current = activated.section.clone();
                        current_sections[index] = activated.section.clone();
                    } else {
                        current_sections.push(activated.section.clone());
                    }
                }
                current_sections.extend(activation.auxiliary_sections.iter().cloned());
            }
            let mut macho_resolution_updates = {
                timing_phase!("Refresh changed Mach-O symbol resolutions");
                let owns_active_changed_definitions = retained_macho_archive_members
                    .iter()
                    .any(|state| state.kind.is_changed_definitions() && state.active);
                match update_macho_symbol_resolutions_for_input(
                    &mut previous.macho_symbol_resolutions,
                    input,
                    &bytes,
                    added_archive_member_identifiers.is_some()
                        || !retired_macho_archive_activations.is_empty()
                        || owns_active_changed_definitions,
                    Some((&matched_sections, previous_output.get()?)),
                )? {
                    Ok(updates) => updates,
                    Err(reason) => return Ok(ChangedInputPatchResult::Unsupported(reason)),
                }
            };
            let macho_forwarding_thunk_patches = if macho_text_section_activation
                .as_ref()
                .is_some_and(|activation| activation.grew_existing_sections)
                && !macho_resolution_updates.moves.is_empty()
            {
                let Some(previous_bytes) = previous_snapshot_bytes.get()? else {
                    return Ok(ChangedInputPatchResult::Unsupported(
                        "moved Mach-O symbol needs the previous input snapshot".to_owned(),
                    ));
                };
                let mut all_patches = MachOForwardingThunkPatches::default();
                for activated in &macho_text_section_activation
                    .as_ref()
                    .expect("checked above")
                    .text_sections
                {
                    let Some(forwarded_section) = activated
                        .matched_section_index
                        .and_then(|index| matched_sections.get(index))
                    else {
                        return Ok(ChangedInputPatchResult::Unsupported(
                            "grown Mach-O text activation has no matched section".to_owned(),
                        ));
                    };
                    match macho_forwarding_thunk_patches(
                        previous_bytes,
                        input.path.as_str(),
                        normalize_rust_archive_patch_inputs,
                        &macho_resolution_updates.moves,
                        forwarded_section,
                        &matched_sections,
                        previous_output.get()?,
                    )? {
                        Ok(patches) => {
                            if patches.moves.iter().any(|moved| {
                                all_patches.moves.iter().any(|existing| existing == moved)
                            }) {
                                return Ok(ChangedInputPatchResult::Unsupported(
                                    "moved Mach-O symbol matched multiple grown text sections"
                                        .to_owned(),
                                ));
                            }
                            all_patches.patches.extend(patches.patches);
                            all_patches.moves.extend(patches.moves);
                        }
                        Err(reason) => return Ok(ChangedInputPatchResult::Unsupported(reason)),
                    }
                }
                if let Err(reason) = record_macho_forwarding_thunk_addresses(
                    &mut previous.macho_symbol_resolutions,
                    &all_patches.moves,
                ) {
                    return Ok(ChangedInputPatchResult::Unsupported(reason));
                }
                all_patches
            } else {
                MachOForwardingThunkPatches::default()
            };
            let mut reusable_macho_branch_targets =
                macho_resolution_updates.reusable_branch_targets.clone();
            reusable_macho_branch_targets.extend(macho_forwarding_thunk_patches.moves.iter().map(
                |moved| MachOReusableBranchTarget {
                    moved: moved.clone(),
                    applied_target_value: moved.previous_value,
                },
            ));
            let had_macho_cross_input_target_moves = !relocation_target_patches
                .macho_cross_input_target_moves
                .is_empty();
            match finish_macho_cross_input_target_moves(
                &mut previous.relocations,
                &mut relocation_target_patches,
                &macho_resolution_updates.moves,
                &reusable_macho_branch_targets,
                true,
                false,
                input,
            )? {
                Ok(()) => {}
                Err(reason) => return Ok(ChangedInputPatchResult::Unsupported(reason)),
            }
            relocation_target_patches
                .input_ranges
                .extend(macho_resolution_updates.input_ranges.iter().cloned());
            relocation_target_patches
                .output_symbols
                .extend(macho_resolution_updates.output_symbols.iter().cloned());
            if macho_resolution_updates.changed {
                if !records_complete {
                    return Ok(ChangedInputPatchResult::RequiresCompleteRecords(
                        "changed Mach-O symbol resolutions need complete relocation records"
                            .to_owned(),
                    ));
                }
                previous.macho_symbol_resolutions_file = None;
                previous.sections_file = None;
            }
            let text_activation_reserved_ranges = macho_text_section_activation
                .as_ref()
                .map_or(previous.reserved_ranges.as_slice(), |activation| {
                    activation.remaining_reserved_ranges.as_slice()
                });
            let mut changed_macho_definition_activation = if args
                .should_activate_macho_archive_members()
            {
                let Some(previous_bytes) = previous_snapshot_bytes.get()? else {
                    return Ok(ChangedInputPatchResult::Unsupported(
                        "changed Mach-O definition needs the previous input snapshot".to_owned(),
                    ));
                };
                match changed_macho_definition_activation(
                    previous_bytes,
                    input.path.as_str(),
                    &matched_sections,
                    &current_resolver,
                    normalize_rust_archive_patch_inputs,
                    previous_output.get()?,
                    &previous.macho_symbol_resolutions,
                    &retained_macho_archive_members,
                    &macho_resolution_updates.retiring_names,
                    text_activation_reserved_ranges,
                )? {
                    Ok(activation) => activation,
                    Err(reason) => {
                        return Ok(ChangedInputPatchResult::Unsupported(reason));
                    }
                }
            } else {
                None
            };
            if let Some(activation) = &changed_macho_definition_activation {
                if !record_coverage.has_complete_macho_symbol_resolutions() {
                    return Ok(ChangedInputPatchResult::RequiresCompleteMachOResolutions(
                        "changed Mach-O definitions need the complete resolution catalog"
                            .to_owned(),
                    ));
                }
                previous
                    .macho_symbol_resolutions
                    .extend(activation.symbol_resolutions.iter().cloned());
                previous.macho_symbol_resolutions.sort_unstable();
                previous.macho_symbol_resolutions.dedup();
                previous.macho_symbol_resolutions_file = None;
                previous.sections_file = None;
            }
            let activation_reserved_ranges = changed_macho_definition_activation
                .as_ref()
                .map_or(text_activation_reserved_ranges, |activation| {
                    activation.remaining_reserved_ranges.as_slice()
                });
            let mut added_macho_archive_text_activation =
                if let Some(added_identifiers) = added_archive_member_identifiers.as_deref() {
                    let reactivated = if let Some(stored_patch) = input.patch.as_ref() {
                        match reactivated_macho_archive_text_activation(
                            &bytes,
                            input.path.as_str(),
                            added_identifiers,
                            &current_resolver,
                            stored_patch,
                            &previous.macho_symbol_resolutions,
                            activation_reserved_ranges,
                        )? {
                            Ok(activation) => activation,
                            Err(reason) => {
                                return Ok(ChangedInputPatchResult::Unsupported(reason));
                            }
                        }
                    } else {
                        None
                    };
                    if let Some(activation) = reactivated {
                        Some(activation)
                    } else {
                        let Some(previous_bytes) = previous_snapshot_bytes.get()? else {
                            return Ok(ChangedInputPatchResult::Unsupported(
                                "added Mach-O archive member needs the previous input snapshot"
                                    .to_owned(),
                            ));
                        };
                        match added_macho_archive_text_activations(
                            previous_bytes,
                            &bytes,
                            input.path.as_str(),
                            added_identifiers,
                            &matched_sections,
                            &current_sections,
                            &current_resolver,
                            &[],
                            activation_reserved_ranges,
                            args.common().incremental_padding_percent,
                            previous_output.get()?,
                            &previous.relocations,
                            &previous.macho_symbol_resolutions,
                            &macho_resolution_updates.retiring_names,
                        )? {
                            Ok(activation) => Some(activation),
                            Err(reason) => {
                                return Ok(ChangedInputPatchResult::Unsupported(reason));
                            }
                        }
                    }
                } else {
                    None
                };
            let migrated_macho_resolution_moves = if let Some(activation) =
                added_macho_archive_text_activation.as_mut()
            {
                let migrations = match reconcile_migrated_added_macho_symbol_resolutions(
                    &mut previous.macho_symbol_resolutions,
                    activation,
                    &mut macho_resolution_updates.retiring_names,
                ) {
                    Ok(migrations) => migrations,
                    Err(reason) => return Ok(ChangedInputPatchResult::Unsupported(reason)),
                };
                let mut rollback_symbol_resolutions =
                    Vec::with_capacity(macho_resolution_updates.retiring_names.len());
                for name in &macho_resolution_updates.retiring_names {
                    let index = match macho_symbol_resolution_index_for_name(
                        &previous.macho_symbol_resolutions,
                        name.as_str(),
                    ) {
                        Ok(Some(index)) => index,
                        Ok(None) => {
                            return Ok(ChangedInputPatchResult::Unsupported(
                                "retiring Mach-O symbol has no rollback catalog entry".to_owned(),
                            ));
                        }
                        Err(reason) => {
                            return Ok(ChangedInputPatchResult::Unsupported(reason));
                        }
                    };
                    rollback_symbol_resolutions
                        .push(previous.macho_symbol_resolutions[index].clone());
                }
                match migrated_macho_archive_rollback_symbol_resolutions(
                    &retired_macho_archive_activations,
                    &migrations,
                ) {
                    Ok(transferred) => rollback_symbol_resolutions.extend(transferred),
                    Err(reason) => return Ok(ChangedInputPatchResult::Unsupported(reason)),
                }
                rollback_symbol_resolutions.sort_unstable();
                rollback_symbol_resolutions.dedup();
                let [state] = activation.member_states.as_mut_slice() else {
                    return Ok(ChangedInputPatchResult::Unsupported(
                        "added Mach-O archive activation has no unique ownership state".to_owned(),
                    ));
                };
                if activation.reactivated
                    && state.rollback_symbol_resolutions != rollback_symbol_resolutions
                {
                    return Ok(ChangedInputPatchResult::Unsupported(
                        "reactivated Mach-O archive rollback catalog changed while dormant"
                            .to_owned(),
                    ));
                }
                state.rollback_symbol_resolutions = rollback_symbol_resolutions;
                migrations
            } else {
                Vec::new()
            };
            if let Err(reason) = finalize_retired_macho_archive_symbol_resolutions(
                &mut previous.macho_symbol_resolutions,
                &retired_macho_archive_activations,
            ) {
                return Ok(ChangedInputPatchResult::Unsupported(reason));
            }
            if !migrated_macho_resolution_moves.is_empty() {
                previous.macho_symbol_resolutions_file = None;
                previous.sections_file = None;
            }
            let macho_resolution_moves = macho_resolution_updates
                .moves
                .iter()
                .chain(&migrated_macho_resolution_moves)
                .cloned()
                .collect::<Vec<_>>();
            let macho_text_relocation_retiring_names =
                combined_macho_text_relocation_retiring_names(
                    &macho_resolution_updates.retiring_names,
                    &retired_macho_archive_activations,
                    &migrated_macho_resolution_moves,
                );
            if let Err(reason) = restore_deferred_macho_symbol_resolutions(
                &mut previous.macho_symbol_resolutions,
                retired_macho_archive_activations
                    .iter()
                    .flat_map(|state| &state.symbol_resolutions),
            ) {
                return Ok(ChangedInputPatchResult::Unsupported(reason));
            }
            if !records_complete && !macho_text_relocation_retiring_names.is_empty() {
                return Ok(ChangedInputPatchResult::RequiresCompleteRecords(
                    "retiring Mach-O symbols needs complete relocation records".to_owned(),
                ));
            }
            match finish_macho_cross_input_target_moves(
                &mut previous.relocations,
                &mut relocation_target_patches,
                &migrated_macho_resolution_moves,
                &[],
                false,
                true,
                input,
            )? {
                Ok(()) => {}
                Err(reason) => return Ok(ChangedInputPatchResult::Unsupported(reason)),
            }
            if let Some(activation) = &added_macho_archive_text_activation {
                previous
                    .macho_symbol_resolutions
                    .extend(activation.symbol_resolutions.iter().cloned());
                previous.macho_symbol_resolutions.sort_unstable();
                previous.macho_symbol_resolutions.dedup();
                previous.macho_symbol_resolutions_file = None;
                previous.sections_file = None;
                current_sections.extend(activation.sections.iter().cloned());
            }
            let retired_macho_archive_identifiers = retired_macho_archive_activations
                .iter()
                .flat_map(|state| {
                    state
                        .members
                        .iter()
                        .map(|member| member.normalized_identifier.clone())
                })
                .collect::<Vec<_>>();
            let reactivated_macho_archive_identifiers = added_macho_archive_text_activation
                .as_ref()
                .filter(|activation| activation.reactivated)
                .into_iter()
                .flat_map(|activation| activation.normalized_identifiers.iter().cloned())
                .collect::<Vec<_>>();
            let mut changed_macho_archive_unwind_activation = if args
                .should_activate_macho_archive_members()
                && added_macho_archive_text_activation
                    .as_ref()
                    .is_none_or(|activation| activation.reactivated)
            {
                let Some(previous_bytes) = previous_snapshot_bytes.get()? else {
                    return Ok(ChangedInputPatchResult::Unsupported(
                        "changed Mach-O unwind metadata needs the previous input snapshot"
                            .to_owned(),
                    ));
                };
                match changed_macho_archive_unwind_activation(
                    previous_bytes,
                    &bytes,
                    input.path.as_str(),
                    &matched_sections,
                    &current_sections,
                    &current_resolver,
                    previous_output.get()?,
                    &previous.macho_symbol_resolutions,
                    activation_reserved_ranges,
                    changed_macho_definition_activation
                        .as_ref()
                        .map_or(&[], |activation| activation.added_names.as_slice()),
                    changed_macho_definition_activation
                        .as_ref()
                        .map_or(&[], |activation| activation.retired_names.as_slice()),
                    changed_macho_definition_activation
                        .as_ref()
                        .is_some_and(ChangedMachODefinitionActivation::owns_changed_unwind),
                    &retired_macho_archive_identifiers,
                    &reactivated_macho_archive_identifiers,
                )? {
                    Ok(activation) => activation,
                    Err(reason) => {
                        return Ok(ChangedInputPatchResult::Unsupported(reason));
                    }
                }
            } else {
                None
            };
            let stable_relocation_count = previous.relocations.len();
            if let Some(activation) = &mut added_macho_archive_text_activation {
                if !records_complete {
                    return Ok(ChangedInputPatchResult::RequiresCompleteRecords(
                        "added Mach-O archive member needs complete relocation records".to_owned(),
                    ));
                }
                let reactivated_relocations = !activation.reactivated_relocations.is_empty();
                previous
                    .relocations
                    .append(&mut activation.reactivated_relocations);
                if reactivated_relocations {
                    previous.relocations.sort_unstable();
                    previous.relocations.dedup();
                    previous.sections_file = None;
                }
                for (replay_index, record) in
                    std::mem::take(&mut activation.provisional_relocations)
                {
                    let relocation_index = previous.relocations.len();
                    let Some(replay) = activation.relocation_replays.get_mut(replay_index) else {
                        return Ok(ChangedInputPatchResult::Unsupported(
                            "added Mach-O archive relocation replay index is invalid".to_owned(),
                        ));
                    };
                    replay.relocation_index = Some(relocation_index);
                    previous.relocations.push(record);
                }
                if activation
                    .relocation_replays
                    .iter()
                    .any(|replay| replay.chained_rebase_output_offset.is_some())
                {
                    previous.sections_file = None;
                }
            }
            if args.should_validate_macho_cstring_patches() {
                let mut boundaries_are_stable = matched_cstring_literal_boundaries_are_stable(
                    input.path.as_str(),
                    &matched_sections,
                    None,
                    &current_resolver,
                )?;
                if !boundaries_are_stable {
                    let previous_bytes = {
                        timing_phase!("Read previous incremental input snapshot");
                        previous_snapshot_bytes.get()?
                    };
                    let previous_resolver = previous_bytes
                        .map(|bytes| {
                            PatchInputResolver::new(bytes, normalize_rust_archive_patch_inputs)
                        })
                        .transpose()?;
                    boundaries_are_stable = matched_cstring_literal_boundaries_are_stable(
                        input.path.as_str(),
                        &matched_sections,
                        previous_resolver.as_ref(),
                        &current_resolver,
                    )?;
                }
                if !boundaries_are_stable {
                    return Ok(ChangedInputPatchResult::Unsupported(format!(
                        "changed Mach-O cstring literal boundaries in `{}`",
                        path.display()
                    )));
                }
            }
            let mut macho_text_relocation_replays = {
                let previous_bytes = {
                    timing_phase!("Read previous incremental input snapshot");
                    previous_snapshot_bytes.get()?
                };
                let previous_resolver = previous_bytes
                    .map(|bytes| {
                        PatchInputResolver::new(bytes, normalize_rust_archive_patch_inputs)
                    })
                    .transpose()?;
                if let Some(previous_resolver) = previous_resolver.as_ref() {
                    if indexed_changed_input_macho_definitions.is_none() {
                        timing_phase!("Index changed Mach-O definitions");
                        indexed_changed_input_macho_definitions =
                            Some(changed_input_macho_definitions(&changed_input_paths)?);
                    }
                    let replays = {
                        timing_phase!("Replay changed Mach-O text relocations");
                        match macho_text_relocation_replays_for_input(
                            &previous.relocations,
                            &mut previous.macho_symbol_resolutions,
                            &macho_text_relocation_retiring_names,
                            input,
                            indexed_changed_input_macho_definitions
                                .as_ref()
                                .and_then(Option::as_ref),
                            &matched_sections,
                            previous_resolver,
                            &current_resolver,
                            previous_output.get()?,
                            &mut relocation_target_patches,
                            &macho_resolution_moves,
                            record_coverage.has_changed_input_records(),
                        )? {
                            Ok(replays) => replays,
                            Err(reason) if reason == MACHO_TEXT_RELOCATION_RECORDS_REQUIRED => {
                                return Ok(ChangedInputPatchResult::RequiresChangedInputRecords(
                                    reason,
                                ));
                            }
                            Err(reason)
                                if !record_coverage.has_complete_macho_symbol_resolutions()
                                    && reason.starts_with(MACHO_SYMBOL_RESOLUTIONS_REQUIRED) =>
                            {
                                return Ok(
                                    ChangedInputPatchResult::RequiresCompleteMachOResolutions(
                                        reason,
                                    ),
                                );
                            }
                            Err(reason) => return Ok(ChangedInputPatchResult::Unsupported(reason)),
                        }
                    };
                    let data_relocations_are_stable = {
                        timing_phase!("Validate changed Mach-O data relocations");
                        validate_macho_data_relocations_are_stable(
                            &mut previous.relocations[..stable_relocation_count],
                            &previous.macho_symbol_resolutions,
                            input,
                            &matched_sections,
                            previous_resolver,
                            &current_resolver,
                            previous_output.get()?,
                            &relocation_target_patches.macho_target_moves,
                        )?
                    };
                    match data_relocations_are_stable {
                        Ok(changed) => {
                            if changed {
                                if !records_complete {
                                    return Ok(ChangedInputPatchResult::RequiresCompleteRecords(
                                        "changed Mach-O data relocations need complete \
                                             relocation records"
                                            .to_owned(),
                                    ));
                                }
                                previous.sections_file = None;
                            }
                        }
                        Err(reason) => {
                            return Ok(ChangedInputPatchResult::Unsupported(reason));
                        }
                    }
                    replays
                } else {
                    MachOTextRelocationReplays {
                        replays: Vec::new(),
                        rematerialized_sections: Vec::new(),
                        normalize_rust_archive_patch_inputs: false,
                        symbol_resolutions_changed: false,
                    }
                }
            };
            if let Some(activation) = &added_macho_archive_text_activation {
                macho_text_relocation_replays
                    .replays
                    .extend(activation.relocation_replays.iter().cloned());
            }
            let recycled_resolution_names = added_macho_archive_text_activation
                .as_ref()
                .into_iter()
                .flat_map(|activation| activation.recycled_symbol_resolution_names.iter().cloned())
                .chain(
                    changed_macho_definition_activation
                        .as_ref()
                        .into_iter()
                        .flat_map(|activation| activation.recycled_names.iter().cloned()),
                )
                .chain(retired_macho_archive_activations.iter().flat_map(|state| {
                    state
                        .symbol_resolutions
                        .iter()
                        .map(|resolution| resolution.name.clone())
                }))
                .collect::<HashSet<_>>();
            match retire_missing_macho_symbol_resolutions(
                &mut previous.macho_symbol_resolutions,
                &previous.relocations,
                &macho_text_relocation_replays.replays,
                &macho_text_relocation_replays.rematerialized_sections,
                macho_text_relocation_replays.normalize_rust_archive_patch_inputs,
                &macho_text_relocation_retiring_names,
                &recycled_resolution_names,
                &changed_input_files,
                input,
                previous_output.get()?,
            ) {
                Ok(true) => {
                    macho_text_relocation_replays.symbol_resolutions_changed = true;
                }
                Ok(false) => {}
                Err(reason) => return Ok(ChangedInputPatchResult::Unsupported(reason)),
            }
            if macho_text_relocation_replays.symbol_resolutions_changed {
                if !record_coverage.has_complete_macho_symbol_resolutions() {
                    return Ok(ChangedInputPatchResult::RequiresCompleteMachOResolutions(
                        "changed Mach-O text symbol resolutions need the complete resolution \
                             catalog"
                            .to_owned(),
                    ));
                }
                previous.macho_symbol_resolutions_file = None;
                if records_complete {
                    previous.sections_file = None;
                }
            }
            output_symbol_patches.extend(relocation_target_patches.output_symbols.iter().cloned());
            if args.should_validate_x86_64_elf_got_relaxation_contexts() {
                let mut got_contexts_are_stable = {
                    timing_phase!("Validate changed ELF GOT contexts");
                    matched_x86_64_elf_got_relaxation_contexts_are_stable(
                        previous_snapshot_bytes.get_if_loaded(),
                        &bytes,
                        input.path.as_str(),
                        &matched_sections,
                    )?
                };
                if !got_contexts_are_stable {
                    let previous_bytes = {
                        timing_phase!("Read previous incremental input snapshot");
                        previous_snapshot_bytes.get()?
                    };
                    got_contexts_are_stable =
                        matched_x86_64_elf_got_relaxation_contexts_are_stable(
                            previous_bytes,
                            &bytes,
                            input.path.as_str(),
                            &matched_sections,
                        )?;
                }
                if !got_contexts_are_stable {
                    return Ok(ChangedInputPatchResult::Unsupported(format!(
                        "changed x86-64 ELF GOT relaxation context in `{}`",
                        path.display()
                    )));
                }
            }

            let mut dynamic_relocation_patches = dynamic_relocation_patches_for_input(
                &bytes,
                input.path.as_str(),
                previous
                    .dynamic_relocations
                    .iter()
                    .filter(|record| record.input_file == input.path),
            )?;
            if let Some(previous_bytes) = previous_snapshot_bytes.get_if_loaded() {
                dynamic_relocation_patches.extend(added_dynamic_relocation_patches_for_input(
                    &bytes,
                    previous_bytes,
                    input.path.as_str(),
                    &matched_sections,
                    &previous.dynamic_relocations,
                    &previous.sections,
                ));
            }
            let eh_frame_patches =
                if let Some(previous_bytes) = previous_snapshot_bytes.get_if_loaded() {
                    fde_relocation_patches_for_input(
                        &bytes,
                        previous_bytes,
                        input.path.as_str(),
                        previous
                            .fdes
                            .iter()
                            .filter(|record| record.input_file == input.path),
                    )?
                } else {
                    Vec::new()
                };
            let input_fde_add_candidates =
                if let Some(previous_bytes) = previous_snapshot_bytes.get_if_loaded() {
                    added_fde_candidates_for_input(
                        &bytes,
                        previous_bytes,
                        input.path.as_str(),
                        &matched_sections,
                        previous
                            .fdes
                            .iter()
                            .filter(|record| record.input_file == input.path),
                    )?
                } else {
                    Vec::new()
                };
            let fingerprint_extra_ranges = dynamic_relocation_patches
                .iter()
                .filter_map(|patch| patch.input_range.clone())
                .chain(relocation_addend_patches.input_ranges.iter().cloned())
                .chain(relocation_target_patches.input_ranges.iter().cloned())
                .chain(
                    eh_frame_patches
                        .iter()
                        .flat_map(|patch| patch.input_ranges.iter().map(Clone::clone)),
                )
                .chain(
                    input_fde_add_candidates
                        .iter()
                        .flat_map(|candidate| candidate.input_ranges.iter().cloned()),
                )
                .chain(
                    added_macho_archive_text_activation
                        .as_ref()
                        .into_iter()
                        .flat_map(|activation| {
                            activation.current_unwind_input_ranges.iter().cloned()
                        }),
                )
                .chain(
                    changed_macho_archive_unwind_activation
                        .as_ref()
                        .into_iter()
                        .flat_map(|activation| activation.current_input_ranges.iter().cloned()),
                )
                .collect::<Vec<_>>();
            let Some((mut fingerprint, mut archive_member_patch_fingerprints)) = ({
                timing_phase!("Fingerprint changed patch input");
                patch_fingerprint_with_resolver_and_archive_member_patch_fingerprints(
                    &bytes,
                    input.path.as_str(),
                    current_sections.iter().cloned(),
                    fingerprint_extra_ranges.iter().cloned(),
                    &current_resolver,
                    PatchInputLookup::MatchArchiveMember,
                    normalize_rust_archive_patch_inputs,
                    previous_patch.archive_member_patch_fingerprints.as_deref(),
                )?
            }) else {
                return Ok(ChangedInputPatchResult::Unsupported(format!(
                    "could not resolve patchable sections in `{}`",
                    path.display()
                )));
            };
            let replaced_archive_identifiers = macho_text_section_activation
                .as_ref()
                .into_iter()
                .flat_map(|activation| activation.normalized_archive_identifiers.iter().cloned())
                .collect::<Vec<_>>();
            let ignored_archive_identifiers = added_macho_archive_text_activation
                .as_ref()
                .into_iter()
                .flat_map(|activation| activation.normalized_identifiers.iter().cloned())
                .collect::<Vec<_>>();
            let activated_archive_base_fingerprint = if !replaced_archive_identifiers.is_empty()
                || !ignored_archive_identifiers.is_empty()
            {
                if normalize_rust_archive_patch_inputs {
                    patch_fingerprint_ignoring_archive_members_with_resolver(
                        &bytes,
                        input.path.as_str(),
                        current_sections.iter().cloned(),
                        fingerprint_extra_ranges.iter().cloned(),
                        &current_resolver,
                        PatchInputLookup::MatchArchiveMember,
                        previous_patch.archive_member_patch_fingerprints.as_deref(),
                        &ignored_archive_identifiers,
                        &replaced_archive_identifiers,
                    )?
                } else {
                    None
                }
            } else {
                None
            };
            let activated_archive_base_fingerprint_matches = activated_archive_base_fingerprint
                .as_deref()
                == Some(previous_patch.fingerprint.as_str());
            let activated_archive_base_diff_is_changed_definitions =
                if changed_macho_definition_activation.is_some()
                    && !activated_archive_base_fingerprint_matches
                {
                    let previous_bytes = {
                        timing_phase!("Read previous incremental input snapshot");
                        previous_snapshot_bytes.get()?
                    };
                    if let Some(previous_bytes) = previous_bytes {
                        let definition_activation = changed_macho_definition_activation
                            .as_ref()
                            .expect("checked above");
                        let previous_unwind_input_ranges = added_macho_archive_text_activation
                            .as_ref()
                            .into_iter()
                            .flat_map(|activation| {
                                activation.previous_unwind_input_ranges.iter().cloned()
                            })
                            .chain(
                                changed_macho_archive_unwind_activation
                                    .as_ref()
                                    .into_iter()
                                    .flat_map(|activation| {
                                        activation.previous_input_ranges.iter().cloned()
                                    }),
                            )
                            .collect::<Vec<_>>();
                        let current_unwind_input_ranges = added_macho_archive_text_activation
                            .as_ref()
                            .into_iter()
                            .flat_map(|activation| {
                                activation.current_unwind_input_ranges.iter().cloned()
                            })
                            .chain(
                                changed_macho_archive_unwind_activation
                                    .as_ref()
                                    .into_iter()
                                    .flat_map(|activation| {
                                        activation.current_input_ranges.iter().cloned()
                                    }),
                            )
                            .collect::<Vec<_>>();
                        archive_diff_allows_changed_macho_symbols(
                            previous_bytes,
                            &bytes,
                            input.path.as_str(),
                            &matched_sections,
                            &current_resolver,
                            &replaced_archive_identifiers,
                            &replaced_archive_identifiers
                                .iter()
                                .chain(&ignored_archive_identifiers)
                                .cloned()
                                .collect::<Vec<_>>(),
                            &previous_unwind_input_ranges,
                            &current_unwind_input_ranges,
                            &definition_activation.added_names,
                            &definition_activation.retired_names,
                            changed_macho_archive_unwind_activation.is_some(),
                        )?
                    } else {
                        false
                    }
                } else {
                    false
                };
            let activated_archive_base_diff_is_member_addition = if let Some(activation) =
                added_macho_archive_text_activation.as_ref()
                && !activated_archive_base_fingerprint_matches
            {
                let previous_bytes = {
                    timing_phase!("Read previous incremental input snapshot");
                    previous_snapshot_bytes.get()?
                };
                if let Some(previous_bytes) = previous_bytes {
                    let previous_unwind_input_ranges = activation
                        .previous_unwind_input_ranges
                        .iter()
                        .cloned()
                        .chain(
                            changed_macho_archive_unwind_activation
                                .as_ref()
                                .into_iter()
                                .flat_map(|activation| {
                                    activation.previous_input_ranges.iter().cloned()
                                }),
                        )
                        .collect::<Vec<_>>();
                    let current_unwind_input_ranges = activation
                        .current_unwind_input_ranges
                        .iter()
                        .cloned()
                        .chain(
                            changed_macho_archive_unwind_activation
                                .as_ref()
                                .into_iter()
                                .flat_map(|activation| {
                                    activation.current_input_ranges.iter().cloned()
                                }),
                        )
                        .collect::<Vec<_>>();
                    let removed_identifiers = retired_macho_archive_activations
                        .iter()
                        .flat_map(|state| {
                            state
                                .members
                                .iter()
                                .map(|member| member.normalized_identifier.clone())
                        })
                        .collect::<Vec<_>>();
                    let restored_names = restored_macho_archive_resolution_names(
                        &retired_macho_archive_activations,
                        &migrated_macho_resolution_moves,
                    );
                    archive_diff_allows_owned_macho_member_exchange(
                        previous_bytes,
                        &bytes,
                        input.path.as_str(),
                        &matched_sections,
                        &current_resolver,
                        &removed_identifiers,
                        &ignored_archive_identifiers,
                        &restored_names,
                        &previous_unwind_input_ranges,
                        &current_unwind_input_ranges,
                    )?
                } else {
                    false
                }
            } else {
                false
            };
            if (added_macho_archive_text_activation.is_some()
                || changed_macho_definition_activation.is_some()
                || !replaced_archive_identifiers.is_empty())
                && !activated_archive_base_fingerprint_matches
                && !activated_archive_base_diff_is_changed_definitions
                && !activated_archive_base_diff_is_member_addition
            {
                return Ok(ChangedInputPatchResult::Unsupported(format!(
                    "changed archive members outside activated Mach-O text members in `{}`: base={:?}, previous={}, added={}, changed-definitions={}, replaced={}, ignored={}",
                    path.display(),
                    activated_archive_base_fingerprint,
                    previous_patch.fingerprint,
                    added_macho_archive_text_activation.is_some(),
                    changed_macho_definition_activation.is_some(),
                    replaced_archive_identifiers.len(),
                    ignored_archive_identifiers.len(),
                )));
            }
            if fingerprint != previous_patch.fingerprint {
                let previous_snapshot_bytes = {
                    timing_phase!("Read previous incremental input snapshot");
                    previous_snapshot_bytes.get()?
                };
                let allows_unowned_macho_text_changes = if normalize_rust_archive_patch_inputs {
                    if let Some(previous_bytes) = previous_snapshot_bytes {
                        archive_diff_allows_unowned_macho_text_changes(
                            previous_bytes,
                            &bytes,
                            input.path.as_str(),
                            &matched_sections,
                            &current_resolver,
                        )?
                    } else {
                        false
                    }
                } else {
                    false
                };
                let dynamic_relocation_removed = dynamic_relocation_patches
                    .iter()
                    .any(|patch| patch.input_range.is_none());
                let allows_dynamic_relocation_removal = if dynamic_relocation_removed {
                    if let Some(previous_bytes) = previous_snapshot_bytes {
                        object_diff_allows_dynamic_relocation_removal(
                            previous_bytes,
                            &bytes,
                            input.path.as_str(),
                            &matched_sections,
                            &dynamic_relocation_patches,
                        )?
                    } else {
                        false
                    }
                } else {
                    false
                };
                let dynamic_relocation_added = dynamic_relocation_patches
                    .iter()
                    .any(|patch| patch.input_range.is_some());
                let allows_dynamic_relocation_addition = if dynamic_relocation_added {
                    if let Some(previous_bytes) = previous_snapshot_bytes {
                        object_diff_allows_dynamic_relocation_addition(
                            previous_bytes,
                            &bytes,
                            input.path.as_str(),
                            &matched_sections,
                            &dynamic_relocation_patches,
                        )?
                    } else {
                        false
                    }
                } else {
                    false
                };
                let fde_removed = eh_frame_patches.iter().any(|patch| {
                    matches!(patch.eh_frame_hdr_change, Some(EhFrameHdrChange::Remove(_)))
                });
                let allows_fde_removal = if fde_removed {
                    if let Some(previous_bytes) = previous_snapshot_bytes {
                        object_diff_allows_fde_removal(
                            previous_bytes,
                            &bytes,
                            input.path.as_str(),
                            &matched_sections,
                            &eh_frame_patches,
                        )?
                    } else {
                        false
                    }
                } else {
                    false
                };
                let allows_fde_addition = if input_fde_add_candidates.is_empty() {
                    false
                } else {
                    if let Some(previous_bytes) = previous_snapshot_bytes {
                        object_diff_allows_fde_addition(
                            previous_bytes,
                            &bytes,
                            input.path.as_str(),
                            &matched_sections,
                            &input_fde_add_candidates,
                        )?
                    } else {
                        false
                    }
                };
                let metadata_only_fingerprint_matches = !records_complete
                    && previous.sections.is_empty()
                    && previous.relocations.is_empty()
                    && previous.fdes.is_empty()
                    && previous.dynamic_relocations.is_empty()
                    && if let Some(previous_bytes) = previous_snapshot_bytes {
                        patch_fingerprint_matches_previous_without_extra_ranges(
                            previous_bytes,
                            fingerprint.as_str(),
                            input.path.as_str(),
                            &matched_sections,
                            normalize_rust_archive_patch_inputs,
                        )?
                    } else {
                        false
                    };
                let allows_owned_macho_member_removal =
                    if retired_macho_archive_activations.is_empty() {
                        false
                    } else if let Some(previous_bytes) = previous_snapshot_bytes {
                        let removed_identifiers = retired_macho_archive_activations
                            .iter()
                            .flat_map(|state| {
                                state
                                    .members
                                    .iter()
                                    .map(|member| member.normalized_identifier.clone())
                            })
                            .collect::<Vec<_>>();
                        let restored_names = restored_macho_archive_resolution_names(
                            &retired_macho_archive_activations,
                            &migrated_macho_resolution_moves,
                        );
                        let previous_unwind_input_ranges = added_macho_archive_text_activation
                            .as_ref()
                            .into_iter()
                            .flat_map(|activation| {
                                activation.previous_unwind_input_ranges.iter().cloned()
                            })
                            .chain(
                                changed_macho_archive_unwind_activation
                                    .as_ref()
                                    .into_iter()
                                    .flat_map(|activation| {
                                        activation.previous_input_ranges.iter().cloned()
                                    }),
                            )
                            .collect::<Vec<_>>();
                        let current_unwind_input_ranges = added_macho_archive_text_activation
                            .as_ref()
                            .into_iter()
                            .flat_map(|activation| {
                                activation.current_unwind_input_ranges.iter().cloned()
                            })
                            .chain(
                                changed_macho_archive_unwind_activation
                                    .as_ref()
                                    .into_iter()
                                    .flat_map(|activation| {
                                        activation.current_input_ranges.iter().cloned()
                                    }),
                            )
                            .collect::<Vec<_>>();
                        let added_identifiers = added_macho_archive_text_activation
                            .as_ref()
                            .map(|activation| activation.normalized_identifiers.as_slice())
                            .unwrap_or_default();
                        archive_diff_allows_owned_macho_member_exchange(
                            previous_bytes,
                            &bytes,
                            input.path.as_str(),
                            &matched_sections,
                            &current_resolver,
                            &removed_identifiers,
                            added_identifiers,
                            &restored_names,
                            &previous_unwind_input_ranges,
                            &current_unwind_input_ranges,
                        )?
                    } else {
                        false
                    };
                if !allows_dynamic_relocation_removal
                    && !allows_dynamic_relocation_addition
                    && !allows_fde_removal
                    && !allows_fde_addition
                    && !metadata_only_fingerprint_matches
                    && !allows_owned_macho_member_removal
                    && !allows_unowned_macho_text_changes
                    && macho_text_section_activation.is_none()
                    && !activated_archive_base_diff_is_changed_definitions
                    && added_macho_archive_text_activation.is_none()
                    && changed_macho_archive_unwind_activation.is_none()
                {
                    return Ok(ChangedInputPatchResult::Unsupported(format!(
                        "changed bytes outside patchable sections in `{}`",
                        path.display()
                    )));
                }
            }

            let mut patch_sections = if let Some(changed_sections) = matched_changed_sections {
                changed_sections
            } else {
                let previous_bytes = {
                    timing_phase!("Read previous incremental input snapshot");
                    previous_snapshot_bytes.get()?
                };
                let previous_resolver = previous_bytes
                    .map(|bytes| {
                        PatchInputResolver::new(bytes, normalize_rust_archive_patch_inputs)
                    })
                    .transpose()?;
                if let Some(previous_resolver) = previous_resolver.as_ref() {
                    changed_patch_sections_with_resolvers(
                        input,
                        previous_resolver,
                        &current_resolver,
                        &matched_sections,
                    )?
                    .unwrap_or_else(|| current_sections.clone())
                } else {
                    current_sections.clone()
                }
            };
            if let Some(activation) = &added_macho_archive_text_activation
                && !activation.reactivated
            {
                patch_sections.extend(activation.sections.iter().cloned());
            }
            for replay in &macho_text_relocation_replays.replays {
                if patch_sections.iter().any(|section| {
                    section.input == replay.input && section.section_index == replay.section_index
                }) {
                    continue;
                }
                let Some(section) = matched_sections.iter().find(|section| {
                    section.current.input == replay.input
                        && section.current.section_index == replay.section_index
                }) else {
                    return Ok(ChangedInputPatchResult::Unsupported(format!(
                        "missing Mach-O text section for relocation replay in `{}`",
                        path.display()
                    )));
                };
                patch_sections.push(section.current.clone());
            }
            if let Some(activation) = &macho_text_section_activation {
                for activated in &activation.text_sections {
                    patch_sections.retain(|section| {
                        section.input != activated.section.input
                            || section.section_index != activated.section.section_index
                    });
                    patch_sections.push(activated.section.clone());
                }
            }
            patched_section_count += patch_sections.len();

            let mut resolved_patches = match {
                timing_phase!("Materialize changed section patches");
                resolved_patch_sections_for_input_with_resolver_detailed(
                    input.path.as_str(),
                    patch_sections,
                    dynamic_relocation_patches.iter().map(|patch| &patch.record),
                    previous
                        .relocations
                        .iter()
                        .filter(|record| record.input_file == input.path),
                    &current_resolver,
                )?
            } {
                Ok(patches) => patches,
                Err(reason) => {
                    return Ok(ChangedInputPatchResult::Unsupported(format!(
                        "{reason} in `{}`",
                        path.display(),
                    )));
                }
            };
            let filtered_records_cover_macho_text_replays = !had_macho_cross_input_target_moves
                && !macho_resolution_updates.changed
                && macho_resolution_moves.is_empty()
                && macho_text_relocation_retiring_names.is_empty()
                && relocation_target_patches.macho_target_moves.is_empty()
                && macho_text_section_activation.is_none()
                && changed_macho_definition_activation.is_none()
                && added_macho_archive_text_activation.is_none()
                && changed_macho_archive_unwind_activation.is_none()
                && macho_text_relocation_replays
                    .uses_only_records_owned_by_input(&previous.relocations, input.path.as_str());
            if (!macho_text_relocation_replays.replays.is_empty()
                || !macho_text_relocation_replays
                    .rematerialized_sections
                    .is_empty())
                && !record_coverage.has_changed_input_records()
            {
                return Ok(ChangedInputPatchResult::RequiresChangedInputRecords(
                    MACHO_TEXT_RELOCATION_RECORDS_REQUIRED.to_owned(),
                ));
            }
            if (!macho_text_relocation_replays.replays.is_empty()
                || !macho_text_relocation_replays
                    .rematerialized_sections
                    .is_empty())
                && !records_complete
                && !filtered_records_cover_macho_text_replays
            {
                return Ok(ChangedInputPatchResult::RequiresCompleteRecords(
                    "changed Mach-O text relocation replay needs complete relocation records"
                        .to_owned(),
                ));
            }
            let mut macho_reserved_thunk_patches = Vec::new();
            let remaining_reserved_ranges =
                if let Some(activation) = added_macho_archive_text_activation.as_mut() {
                    &mut activation.remaining_reserved_ranges
                } else if let Some(activation) = changed_macho_archive_unwind_activation.as_mut() {
                    &mut activation.remaining_reserved_ranges
                } else if let Some(activation) = changed_macho_definition_activation.as_mut() {
                    &mut activation.remaining_reserved_ranges
                } else if let Some(activation) = macho_text_section_activation.as_mut() {
                    &mut activation.remaining_reserved_ranges
                } else {
                    &mut previous.reserved_ranges
                };
            let relocation_records_changed = if !macho_text_relocation_replays.replays.is_empty()
                || !macho_text_relocation_replays
                    .rematerialized_sections
                    .is_empty()
            {
                match apply_macho_text_relocation_replays(
                    &mut resolved_patches,
                    &macho_text_relocation_replays,
                    previous_output.get()?,
                    &mut previous.relocations,
                    &mut previous.macho_symbol_resolutions,
                    remaining_reserved_ranges,
                    &mut macho_reserved_thunk_patches,
                ) {
                    Ok(changed) => changed,
                    Err(reason) => return Ok(ChangedInputPatchResult::Unsupported(reason)),
                }
            } else {
                false
            };
            if !macho_reserved_thunk_patches.is_empty() {
                if !records_complete {
                    return Ok(ChangedInputPatchResult::RequiresCompleteRecords(
                        "new Mach-O text thunk needs complete symbol resolutions".to_owned(),
                    ));
                }
                previous.macho_symbol_resolutions.sort_unstable();
                previous.macho_symbol_resolutions.dedup();
                previous.macho_symbol_resolutions_file = None;
                previous.sections_file = None;
            }
            if relocation_records_changed {
                previous.relocations.sort_unstable();
                previous.relocations.dedup();
                if filtered_records_cover_macho_text_replays {
                    record_override_input_files
                        .insert(previous.input_files[*input_index].path.clone());
                } else {
                    previous.sections_file = None;
                }
            }
            if !matched_from_snapshot {
                let auxiliary_section_keys = macho_text_section_activation
                    .as_ref()
                    .into_iter()
                    .flat_map(|activation| activation.auxiliary_sections.iter())
                    .chain(
                        added_macho_archive_text_activation
                            .as_ref()
                            .into_iter()
                            .flat_map(|activation| activation.sections.iter()),
                    )
                    .map(|section| (section.input.as_str(), section.section_index))
                    .collect::<HashSet<_>>();
                let sections_to_resolve = current_sections
                    .iter()
                    .filter(|section| {
                        !auxiliary_section_keys
                            .contains(&(section.input.as_str(), section.section_index))
                    })
                    .cloned()
                    .collect::<Vec<_>>();
                let Some(resolved_sections) = resolve_current_patch_sections_with_resolver(
                    input.path.as_str(),
                    sections_to_resolve,
                    dynamic_relocation_patches.iter().map(|patch| &patch.record),
                    previous
                        .relocations
                        .iter()
                        .filter(|record| record.input_file == input.path),
                    &current_resolver,
                )?
                else {
                    return Ok(ChangedInputPatchResult::Unsupported(format!(
                        "changed patchable section size in `{}`",
                        path.display()
                    )));
                };
                let mut resolved_sections = resolved_sections
                    .into_iter()
                    .map(|section| ((section.input.clone(), section.section_index), section))
                    .collect::<HashMap<_, _>>();
                for section in &mut current_sections {
                    if auxiliary_section_keys
                        .contains(&(section.input.as_str(), section.section_index))
                    {
                        continue;
                    }
                    let Some(resolved) =
                        resolved_sections.remove(&(section.input.clone(), section.section_index))
                    else {
                        return Ok(ChangedInputPatchResult::Unsupported(format!(
                            "missing resolved patchable section in `{}`",
                            path.display()
                        )));
                    };
                    *section = resolved;
                }
            }
            if changed_macho_definition_activation.is_some()
                || added_macho_archive_text_activation.is_some()
                || changed_macho_archive_unwind_activation.is_some()
                || !retired_macho_archive_activations.is_empty()
            {
                let dynamic_relocation_patches = dynamic_relocation_patches_for_input(
                    &bytes,
                    input.path.as_str(),
                    previous
                        .dynamic_relocations
                        .iter()
                        .filter(|record| record.input_file == input.path),
                )?;
                let relocation_addend_ranges = relocation_addend_ranges_for_input_with_lookup(
                    &bytes,
                    input.path.as_str(),
                    previous
                        .relocations
                        .iter()
                        .filter(|record| record.input_file == input.path),
                    PatchInputLookup::MatchArchiveMember,
                )?;
                let relocation_target_ranges = relocation_target_ranges_for_input_with_lookup(
                    &bytes,
                    input.path.as_str(),
                    previous.relocations.iter().filter(|record| {
                        record
                            .target
                            .as_ref()
                            .is_some_and(|target| target.input_file == input.path)
                    }),
                    PatchInputLookup::MatchArchiveMember,
                )?;
                let Some(macho_symbol_resolution_ranges) =
                    macho_symbol_resolution_ranges_for_records_with_lookup(
                        &bytes,
                        input.path.as_str(),
                        previous
                            .macho_symbol_resolutions
                            .iter()
                            .filter(|resolution| {
                                resolution
                                    .target
                                    .as_ref()
                                    .is_some_and(|target| target.input_file == input.path)
                            }),
                        PatchInputLookup::MatchArchiveMember,
                    )?
                else {
                    return Ok(ChangedInputPatchResult::Unsupported(
                        "could not refresh added Mach-O archive member fingerprint".to_owned(),
                    ));
                };
                let fde_relocation_ranges = fde_patch_input_ranges_for_input_with_lookup(
                    &bytes,
                    input.path.as_str(),
                    previous
                        .fdes
                        .iter()
                        .filter(|record| record.input_file == input.path),
                    PatchInputLookup::MatchArchiveMember,
                )?;
                let Some((refreshed_fingerprint, refreshed_member_fingerprints)) =
                    patch_fingerprint_for_current_records_with_extra_ranges_and_archive_member_patch_fingerprints(
                        &bytes,
                        input.path.as_str(),
                        current_sections.iter().cloned(),
                        dynamic_relocation_patches
                            .iter()
                            .filter_map(|patch| patch.input_range.clone())
                            .chain(relocation_addend_ranges)
                            .chain(relocation_target_ranges)
                            .chain(macho_symbol_resolution_ranges)
                            .chain(fde_relocation_ranges)
                            .chain(
                                added_macho_archive_text_activation
                                    .as_ref()
                                    .into_iter()
                                    .flat_map(|activation| {
                                        activation.current_unwind_input_ranges.iter().cloned()
                                    }),
                            )
                            .chain(
                                changed_macho_archive_unwind_activation
                                    .as_ref()
                                    .into_iter()
                                    .flat_map(|activation| {
                                        activation.current_input_ranges.iter().cloned()
                                    }),
                            ),
                        normalize_rust_archive_patch_inputs,
                    )?
                else {
                    return Ok(ChangedInputPatchResult::Unsupported(
                        "could not refresh added Mach-O archive member fingerprint".to_owned(),
                    ));
                };
                fingerprint = refreshed_fingerprint;
                archive_member_patch_fingerprints = refreshed_member_fingerprints;
            }
            let added_macho_archive_symbol_table_patches = added_macho_archive_text_activation
                .as_mut()
                .map(|activation| std::mem::take(&mut activation.symbol_table_patches))
                .unwrap_or_default();
            if let (Some(definition_activation), Some(unwind_activation)) = (
                changed_macho_definition_activation.as_mut(),
                changed_macho_archive_unwind_activation.as_ref(),
            ) && !definition_activation.owns_changed_unwind()
            {
                if let Err(reason) = definition_activation.attach_changed_unwind_transaction(
                    &unwind_activation.patches,
                    previous_output.get()?,
                ) {
                    return Ok(ChangedInputPatchResult::Unsupported(reason));
                }
            }
            let changed_macho_definition_patches = changed_macho_definition_activation
                .as_mut()
                .map(|activation| std::mem::take(&mut activation.output_patches))
                .unwrap_or_default();
            let added_macho_archive_chained_fixup_patches = added_macho_archive_text_activation
                .as_mut()
                .map(|activation| std::mem::take(&mut activation.chained_fixup_patches))
                .unwrap_or_default();
            let added_macho_archive_unwind_patches = added_macho_archive_text_activation
                .as_mut()
                .map(|activation| std::mem::take(&mut activation.unwind_patches))
                .unwrap_or_default();
            let reactivated_macho_archive_output_patches = added_macho_archive_text_activation
                .as_mut()
                .map(|activation| std::mem::take(&mut activation.reactivated_output_patches))
                .unwrap_or_default();
            if let Some(activation) = added_macho_archive_text_activation
                .as_mut()
                .filter(|activation| !activation.reactivated)
            {
                let activation_section_ranges = activation
                    .sections
                    .iter()
                    .map(|section| (section.output_offset, section.output_size))
                    .collect::<HashSet<_>>();
                let mut transaction_patches = resolved_patches
                    .iter()
                    .filter(|patch| {
                        activation_section_ranges
                            .contains(&(patch.patch.output_offset, patch.patch.size))
                    })
                    .map(|patch| &patch.patch)
                    .collect::<Vec<_>>();
                transaction_patches.extend(&macho_reserved_thunk_patches);
                transaction_patches.extend(&added_macho_archive_symbol_table_patches);
                transaction_patches.extend(&added_macho_archive_chained_fixup_patches);
                transaction_patches.extend(&added_macho_archive_unwind_patches);
                let previous_output = previous_output.get()?;
                let forward_patches = match transaction_patches
                    .iter()
                    .map(|patch| stored_output_patch(patch, previous_output))
                    .collect::<std::result::Result<Vec<_>, _>>()
                {
                    Ok(patches) => patches,
                    Err(reason) => return Ok(ChangedInputPatchResult::Unsupported(reason)),
                };
                let rollback_patches = match forward_patches
                    .iter()
                    .map(|patch| {
                        stored_macho_archive_rollback_patch(
                            patch,
                            previous_output,
                            &retired_macho_archive_activations,
                        )
                    })
                    .collect::<std::result::Result<Vec<_>, String>>()
                {
                    Ok(patches) => patches,
                    Err(reason) => return Ok(ChangedInputPatchResult::Unsupported(reason)),
                };
                let Some(state) = activation.member_states.first_mut() else {
                    return Ok(ChangedInputPatchResult::Unsupported(
                        "added Mach-O archive activation has no ownership state".to_owned(),
                    ));
                };
                state.forward_patches = forward_patches;
                state.rollback_patches = rollback_patches;
            }
            let changed_macho_archive_unwind_patches = changed_macho_archive_unwind_activation
                .as_mut()
                .map(|activation| std::mem::take(&mut activation.patches))
                .unwrap_or_default();
            let mut retired_macho_archive_rollback_patches = retired_macho_archive_activations
                .iter()
                .flat_map(|state| state.rollback_patches.iter())
                .map(|patch| SectionPatch {
                    output_offset: patch.output_offset,
                    size: patch.data.len() as u64,
                    data: patch.data.clone(),
                    deferred_relocation: None,
                    preserve_ranges: Vec::new(),
                    adjustments: Vec::new(),
                })
                .collect::<Vec<_>>();
            remove_plain_patches_shadowed_by_exact_current_ranges(
                &mut retired_macho_archive_rollback_patches,
                &changed_macho_archive_unwind_patches,
            );
            for current in [
                changed_macho_definition_patches.as_slice(),
                added_macho_archive_symbol_table_patches.as_slice(),
                added_macho_archive_chained_fixup_patches.as_slice(),
                added_macho_archive_unwind_patches.as_slice(),
                reactivated_macho_archive_output_patches.as_slice(),
            ] {
                remove_plain_patches_shadowed_by_exact_current_ranges(
                    &mut retired_macho_archive_rollback_patches,
                    current,
                );
            }
            let macho_text_auxiliary_patches = macho_text_section_activation
                .as_mut()
                .map(|activation| std::mem::take(&mut activation.auxiliary_patches))
                .unwrap_or_default();
            update_matched_patch_current_sections(&mut matched_sections, &current_sections);
            patched_section_count += macho_resolution_updates.thunk_patches.len();
            patched_section_count += macho_reserved_thunk_patches.len();
            patched_section_count += changed_macho_definition_patches.len();
            patched_section_count += macho_text_auxiliary_patches.len();
            patched_section_count += changed_macho_archive_unwind_patches.len();
            patched_section_count += reactivated_macho_archive_output_patches.len();
            patched_section_count += retired_macho_archive_rollback_patches.len();
            patched_section_count += dynamic_relocation_patches.len();
            patched_section_count += relocation_addend_patches.output_patches.len();
            patched_section_count += eh_frame_patches
                .iter()
                .filter(|patch| patch.patch.is_some())
                .count();
            let eh_frame_hdr_changes = eh_frame_patches
                .iter()
                .filter_map(|patch| patch.eh_frame_hdr_change.clone())
                .collect::<Vec<_>>();
            let removed_dynamic_relocations = dynamic_relocation_patches
                .iter()
                .filter_map(|patch| patch.input_range.is_none().then_some(patch.record.clone()))
                .collect::<HashSet<_>>();
            let added_dynamic_relocations = dynamic_relocation_patches
                .iter()
                .filter_map(|patch| {
                    (patch.input_range.is_some() && patch.is_new).then_some(patch.record.clone())
                })
                .collect::<HashSet<_>>();
            let removed_fdes = eh_frame_hdr_changes
                .iter()
                .filter_map(|change| match change {
                    EhFrameHdrChange::Remove(fde) => Some(fde.clone()),
                    EhFrameHdrChange::Adjust(_) | EhFrameHdrChange::Add(_) => None,
                })
                .collect::<HashSet<_>>();
            let updated_fdes = eh_frame_patches
                .iter()
                .filter_map(|patch| patch.record_update.clone())
                .collect::<Vec<_>>();

            (
                fingerprint,
                archive_member_patch_fingerprints,
                archive_member_set_proof,
                matched_sections,
                current_sections,
                resolved_patches
                    .into_iter()
                    .map(|resolved| resolved.patch)
                    .chain(
                        dynamic_relocation_patches
                            .into_iter()
                            .map(|relocation| relocation.patch),
                    )
                    .chain(relocation_addend_patches.output_patches)
                    .chain(relocation_target_patches.output_patches)
                    .chain(macho_resolution_updates.thunk_patches)
                    .chain(macho_forwarding_thunk_patches.patches)
                    .chain(macho_reserved_thunk_patches)
                    .chain(macho_text_auxiliary_patches)
                    .chain(eh_frame_patches.into_iter().filter_map(|fde| fde.patch))
                    .chain(changed_macho_definition_patches)
                    .chain(added_macho_archive_symbol_table_patches)
                    .chain(added_macho_archive_chained_fixup_patches)
                    .chain(added_macho_archive_unwind_patches)
                    .chain(reactivated_macho_archive_output_patches)
                    .chain(changed_macho_archive_unwind_patches)
                    .chain(retired_macho_archive_rollback_patches)
                    .collect::<Vec<_>>(),
                eh_frame_hdr_changes,
                input_fde_add_candidates,
                added_dynamic_relocations,
                removed_dynamic_relocations,
                removed_fdes,
                updated_fdes,
                macho_text_section_activation,
                changed_macho_definition_activation,
                changed_macho_archive_unwind_activation,
                added_macho_archive_text_activation,
                retired_macho_archive_activations,
            )
        };
        let mut macho_archive_members = previous.input_files[*input_index]
            .patch
            .as_ref()
            .map(|patch| patch.macho_archive_members.clone())
            .unwrap_or_default();
        if let Some(activation) = &changed_macho_definition_activation {
            for update in &activation.state_updates {
                match update {
                    MachOArchiveActivationStateUpdate::Replace(index, state) => {
                        let Some(stored) = macho_archive_members.get_mut(*index) else {
                            return Ok(ChangedInputPatchResult::Unsupported(
                                "changed Mach-O definition ownership moved".to_owned(),
                            ));
                        };
                        if !stored.kind.is_changed_definitions() {
                            return Ok(ChangedInputPatchResult::Unsupported(
                                "changed Mach-O definition ownership changed kind".to_owned(),
                            ));
                        }
                        *stored = state.clone();
                    }
                    MachOArchiveActivationStateUpdate::Add(state) => {
                        if macho_archive_members.iter().any(|stored| {
                            stored.kind.is_changed_definitions() && stored.members == state.members
                        }) {
                            return Ok(ChangedInputPatchResult::Unsupported(
                                "changed Mach-O definition already has retained ownership"
                                    .to_owned(),
                            ));
                        }
                        macho_archive_members.push(state.clone());
                    }
                }
            }
        }
        for retired in &retired_macho_archive_activations {
            let stored = macho_archive_members.iter_mut().find(|stored| {
                stored.active
                    && stored
                        .members
                        .iter()
                        .map(|member| member.normalized_identifier.as_slice())
                        .eq(retired
                            .members
                            .iter()
                            .map(|member| member.normalized_identifier.as_slice()))
            });
            if let Some(stored) = stored {
                *stored = retired.state.clone();
            } else if retired.newly_tracked
                && !macho_archive_members.iter().any(|stored| {
                    stored.members.iter().any(|stored_member| {
                        retired.members.iter().any(|retired_member| {
                            stored_member.normalized_identifier
                                == retired_member.normalized_identifier
                        })
                    })
                })
            {
                macho_archive_members.push(retired.state.clone());
            } else {
                return Ok(ChangedInputPatchResult::Unsupported(
                    "removed Mach-O archive activation ownership changed".to_owned(),
                ));
            }
        }
        if let Some(activation) = &added_macho_archive_text_activation {
            for member in &activation.member_states {
                if activation.reactivated {
                    let Some(stored) = macho_archive_members.iter_mut().find(|stored| {
                        !stored.active
                            && stored
                                .members
                                .iter()
                                .map(|identity| identity.normalized_identifier.as_slice())
                                .eq(member
                                    .members
                                    .iter()
                                    .map(|identity| identity.normalized_identifier.as_slice()))
                    }) else {
                        return Ok(ChangedInputPatchResult::Unsupported(
                            "reactivated Mach-O archive ownership changed".to_owned(),
                        ));
                    };
                    *stored = member.clone();
                } else {
                    if macho_archive_members.iter().any(|previous_member| {
                        previous_member.kind == MachOArchiveActivationKind::AddedMembers
                            && previous_member.members.iter().any(|previous_identity| {
                                member.members.iter().any(|identity| {
                                    previous_identity.normalized_identifier
                                        == identity.normalized_identifier
                                })
                            })
                    }) {
                        return Ok(ChangedInputPatchResult::Unsupported(
                            "added Mach-O archive member already has retained ownership".to_owned(),
                        ));
                    }
                    macho_archive_members.push(member.clone());
                }
            }
        }

        let sections_changed = update_section_records_for_matched_patches(
            previous.input_files[*input_index].path.as_str(),
            &matched_sections,
            &mut previous.sections,
            normalize_rust_archive_patch_inputs,
        )?;
        if sections_changed {
            if !records_complete {
                return Ok(ChangedInputPatchResult::RequiresCompleteRecords(
                    "changed input needs complete section records".to_owned(),
                ));
            }
            record_override_input_files.insert(previous.input_files[*input_index].path.clone());
        }
        if !retired_macho_archive_activations.is_empty() {
            let retired_section_keys = retired_macho_archive_activations
                .iter()
                .flat_map(|state| state.sections.iter())
                .map(|section| (section.input.as_str(), section.section_index))
                .collect::<HashSet<_>>();
            let input_path = previous.input_files[*input_index].path.as_str();
            previous.sections.retain(|record| {
                record.input_file != input_path
                    || !retired_section_keys
                        .contains(&(record.input.as_str(), record.section_index))
            });
            record_override_input_files.insert(previous.input_files[*input_index].path.clone());
        }
        if let Some(activation) = macho_text_section_activation {
            if !records_complete {
                return Ok(ChangedInputPatchResult::RequiresCompleteRecords(
                    "activated Mach-O text section needs complete section records".to_owned(),
                ));
            }
            let input_path = previous.input_files[*input_index].path.clone();
            for activated in &activation.text_sections {
                if activated.matched_section_index.is_none() {
                    continue;
                }
                let mut matching_record_count = 0;
                for record in &previous.sections {
                    if section_record_matches_patch_section(
                        input_path.as_str(),
                        record,
                        &activated.section,
                        normalize_rust_archive_patch_inputs,
                    )? {
                        matching_record_count += 1;
                    }
                }
                if matching_record_count != 1 {
                    return Ok(ChangedInputPatchResult::Unsupported(
                        "activated Mach-O text section has no unique section record".to_owned(),
                    ));
                }
            }
            previous.sections.retain(|record| {
                record.input_file != input_path
                    || !activation
                        .retired_record_keys
                        .iter()
                        .any(|(input, section_index)| {
                            record.input.as_str() == input && record.section_index == *section_index
                        })
            });
            previous.sections.extend(activation.appended_records);
            previous.sections.sort();
            previous.sections.dedup();
            previous.reserved_ranges = activation.remaining_reserved_ranges;
            validate_reserved_ranges_against_sections(
                &previous.reserved_ranges,
                &previous.sections,
            )?;
            record_override_input_files.insert(previous.input_files[*input_index].path.clone());
        }
        if let Some(activation) = changed_macho_definition_activation {
            previous.reserved_ranges = activation.remaining_reserved_ranges;
            validate_reserved_ranges_against_sections(
                &previous.reserved_ranges,
                &previous.sections,
            )?;
            previous.macho_symbol_resolutions_file = None;
            previous.sections_file = None;
        }
        if let Some(activation) = added_macho_archive_text_activation {
            if !records_complete {
                return Ok(ChangedInputPatchResult::RequiresCompleteRecords(
                    "added Mach-O archive member needs complete section records".to_owned(),
                ));
            }
            previous.sections.extend(activation.records);
            previous.sections.sort_unstable();
            previous.sections.dedup();
            previous.reserved_ranges = activation.remaining_reserved_ranges;
            validate_reserved_ranges_against_sections(
                &previous.reserved_ranges,
                &previous.sections,
            )?;
            record_override_input_files.insert(previous.input_files[*input_index].path.clone());
            previous.macho_symbol_resolutions_file = None;
            previous.sections_file = None;
        }
        if let Some(activation) = changed_macho_archive_unwind_activation {
            if !records_complete {
                return Ok(ChangedInputPatchResult::RequiresCompleteRecords(
                    "changed Mach-O unwind metadata needs complete section records".to_owned(),
                ));
            }
            previous.reserved_ranges = activation.remaining_reserved_ranges;
            validate_reserved_ranges_against_sections(
                &previous.reserved_ranges,
                &previous.sections,
            )?;
            record_override_input_files.insert(previous.input_files[*input_index].path.clone());
        }
        if !added_dynamic_relocations.is_empty() {
            if !records_complete {
                return Ok(ChangedInputPatchResult::RequiresCompleteRecords(
                    "changed input needs complete dynamic relocation records".to_owned(),
                ));
            }
            previous
                .dynamic_relocations
                .extend(added_dynamic_relocations);
            previous.dynamic_relocations.sort();
            previous.dynamic_relocations.dedup();
            record_override_input_files.insert(previous.input_files[*input_index].path.clone());
        }
        if !removed_dynamic_relocations.is_empty() {
            if !records_complete {
                return Ok(ChangedInputPatchResult::RequiresCompleteRecords(
                    "changed input needs complete dynamic relocation records".to_owned(),
                ));
            }
            previous.dynamic_relocations.retain(|record| {
                !removed_dynamic_relocations.contains(record)
                    || record.has_restorable_rela_output_info()
            });
            record_override_input_files.insert(previous.input_files[*input_index].path.clone());
        }
        if !removed_fdes.is_empty() {
            if !records_complete {
                return Ok(ChangedInputPatchResult::RequiresCompleteRecords(
                    "changed input needs complete FDE records".to_owned(),
                ));
            }
            previous
                .fdes
                .retain(|record| !removed_fdes.contains(record));
            record_override_input_files.insert(previous.input_files[*input_index].path.clone());
        }
        if !updated_fdes.is_empty() {
            if !records_complete {
                return Ok(ChangedInputPatchResult::RequiresCompleteRecords(
                    "changed input needs complete FDE records".to_owned(),
                ));
            }
            update_fde_records(&mut previous.fdes, updated_fdes);
            record_override_input_files.insert(previous.input_files[*input_index].path.clone());
        }
        previous.input_files[*input_index].content = input_content;
        previous.input_files[*input_index].snapshot_identity = None;
        previous.input_files[*input_index].rustc_link_content_digest = rustc_provenance
            .as_ref()
            .map(|provenance| provenance.link_content_digest.clone());
        previous.input_files[*input_index].rustc_raw_object_manifest = rustc_provenance
            .as_ref()
            .and_then(|provenance| provenance.raw_object_manifest.clone());
        previous.input_files[*input_index].patch = Some(FilePatchState {
            fingerprint: fingerprint.clone(),
            archive_member_set_proof,
            archive_member_patch_fingerprints,
            macho_archive_members,
            sections: current_sections
                .iter()
                .map(file_patch_section_state)
                .collect(),
            raw_sections: None,
        });
        patches.extend(resolved_patches);
        eh_frame_hdr_changes.extend(fde_eh_frame_hdr_changes);
        fde_add_candidates.extend(input_fde_add_candidates);
        if defer_loaded_input_content_hash {
            deferred_loaded_input_content_hashes.push((
                *input_index,
                expected_changed_input_index,
                bytes,
            ));
        }
    }

    if patched_input_count == 0 {
        if let Some(reason) = input_content_mismatch_reason(&expected_changed_inputs, None) {
            return Ok(ChangedInputPatchResult::Unsupported(reason));
        }
        if let Some(reason) = input_identity_mismatch_reason(&previous.input_files)? {
            return Ok(ChangedInputPatchResult::Unsupported(reason));
        }
        snapshot_input_paths(
            state_dir,
            changed_inputs_requiring_snapshot(
                changed_inputs,
                &rustc_link_content_digest_unchanged_input_indices,
            )
            .map(|(_, path)| path.as_path()),
        )?;
        refresh_input_snapshot_identities_at_indices(
            state_dir,
            &mut previous.input_files,
            changed_inputs_requiring_snapshot(
                changed_inputs,
                &rustc_link_content_digest_unchanged_input_indices,
            )
            .map(|(input_index, _)| *input_index),
        );
        refresh_input_file_identities_at_indices(
            &mut previous.input_files,
            changed_inputs.iter().map(|(input_index, _)| *input_index),
        );
        if let Some(reason) =
            input_content_mismatch_reason(&expected_changed_inputs, Some(state_dir))
        {
            return Ok(ChangedInputPatchResult::Unsupported(reason));
        }
        if let Some(reason) = input_identity_mismatch_reason(&previous.input_files)? {
            return Ok(ChangedInputPatchResult::Unsupported(reason));
        }
        previous.link_start = current_link_start;
        previous.write_metadata_update_for_inputs(state_dir, metadata_update_input_indices)?;
        if rewritten_input_count > 0 {
            append_log(
                state_dir,
                &format!(
                    "updated {rewritten_input_count} rewritten input file{} before loading inputs",
                    if rewritten_input_count == 1 { "" } else { "s" }
                ),
            )?;
        }
        if normalized_unchanged_input_count > 0 {
            append_log(
                state_dir,
                &format!(
                    "updated {normalized_unchanged_input_count} unchanged normalized Rust archive input file{} before loading inputs",
                    if normalized_unchanged_input_count == 1 {
                        ""
                    } else {
                        "s"
                    }
                ),
            )?;
        }
        if rustc_link_content_digest_unchanged_input_count > 0 {
            append_log(
                state_dir,
                &format!(
                    "reused {rustc_link_content_digest_unchanged_input_count} unchanged Rust archive input file{} by rustc link-content digest before loading inputs",
                    if rustc_link_content_digest_unchanged_input_count == 1 {
                        ""
                    } else {
                        "s"
                    }
                ),
            )?;
        }
        append_log(state_dir, "reused existing output before loading inputs")?;
        return Ok(ChangedInputPatchResult::Patched);
    }

    if let Some(reason) = input_content_mismatch_reason(&expected_changed_inputs, None) {
        return Ok(ChangedInputPatchResult::Unsupported(reason));
    }

    if let Some(reason) = input_identity_mismatch_reason(&previous.input_files)? {
        return Ok(ChangedInputPatchResult::Unsupported(reason));
    }

    deduplicate_identical_plain_section_patches(&mut patches);
    if let Some(reason) = patch_output_range_rejection_reason(&patches) {
        return Ok(ChangedInputPatchResult::Unsupported(reason));
    }

    let Some(mut directly_patched_output) = DirectlyPatchedOutput::new(
        args.output(),
        state_dir,
        args.should_replace_directly_patched_output(),
    ) else {
        return Ok(ChangedInputPatchResult::Unsupported(
            "could not clone directly patched output generation".to_owned(),
        ));
    };
    let should_invalidate_code_signature_cache =
        directly_patched_output.should_invalidate_code_signature_cache();
    let mut file = OpenOptions::new()
        .read(true)
        .write(true)
        .open(directly_patched_output.path())
        .with_context(|| {
            format!(
                "Failed to open output `{}` for incremental patching",
                directly_patched_output.path().display()
            )
        })?;
    let mut output = if directly_patched_output.is_generation() {
        // A shared writable mapping can leave the kernel's code-signing cache stale even after an
        // atomic rename. Patch private pages, then publish them with ordinary file writes.
        unsafe { MmapOptions::new().map_copy(&file) }
    } else {
        unsafe { MmapOptions::new().map_mut(&file) }
    }
    .with_context(|| {
        format!(
            "Failed to mmap output `{}` for incremental patching",
            directly_patched_output.path().display()
        )
    })?;
    match output_symbol_value_patches(&output, &output_symbol_patches)? {
        Ok(symbol_patches) => patches.extend(symbol_patches),
        Err(reason) => return Ok(ChangedInputPatchResult::Unsupported(reason)),
    }
    match fde_add_patches_for_output(&output, &fde_add_candidates, &previous.fdes)? {
        Ok(resolved_fdes) => {
            if !records_complete && !resolved_fdes.is_empty() {
                return Ok(ChangedInputPatchResult::RequiresCompleteRecords(
                    "changed input needs complete FDE records".to_owned(),
                ));
            }
            patched_section_count += resolved_fdes.len();
            for resolved in resolved_fdes {
                record_override_input_files.insert(resolved.record.input_file.to_string());
                previous.fdes.push(resolved.record);
                patches.push(resolved.patch);
                if let Some(change) = resolved.eh_frame_hdr_change {
                    eh_frame_hdr_changes.push(change);
                }
            }
        }
        Err(reason) => return Ok(ChangedInputPatchResult::Unsupported(reason)),
    }
    match eh_frame_hdr_patches_for_fde_changes(&output, &eh_frame_hdr_changes)? {
        Ok(header_patches) => patches.extend(header_patches),
        Err(reason) => return Ok(ChangedInputPatchResult::Unsupported(reason)),
    }
    if let Some(reason) = patch_output_range_rejection_reason(&patches) {
        return Ok(ChangedInputPatchResult::Unsupported(reason));
    }

    let build_id_range = build_id_note_range(&output)?;
    if build_id_range.is_some() && !args.has_incremental_fast_build_id() {
        return Ok(ChangedInputPatchResult::Unsupported(
            "output has a build ID that cannot be updated incrementally".to_owned(),
        ));
    }
    let mut build_id_tree = None;
    let mut build_id_hashes = None;
    if build_id_range.is_some() {
        let Some(previous_hashes) = previous.build_id_hashes.as_ref() else {
            return Ok(ChangedInputPatchResult::Unsupported(
                "missing build ID hash state".to_owned(),
            ));
        };
        let Ok(tree) = read_build_id_hash_tree(state_dir, previous_hashes) else {
            return Ok(ChangedInputPatchResult::Unsupported(
                "could not read build ID hash state".to_owned(),
            ));
        };
        build_id_tree = Some(tree);
        build_id_hashes = Some(previous_hashes.clone());
    }

    mark_incremental_update_started(state_dir, "patch changed inputs")?;

    let mut patched_ranges = Vec::new();
    {
        timing_phase!("Write changed incremental output ranges");
        for mut patch in patches {
            let start = patch.output_offset as usize;
            let end = start
                .checked_add(patch.size as usize)
                .context("Incremental patch output range overflow")?;
            let Some(output_range) = output.get_mut(start..end) else {
                return Ok(ChangedInputPatchResult::StartedUnsupported(
                    "changed patch output range is out of bounds".to_owned(),
                ));
            };
            if patch.data.len() > output_range.len() {
                return Ok(ChangedInputPatchResult::StartedUnsupported(
                    "changed patch data does not fit in the previous output range".to_owned(),
                ));
            }
            if let Some(deferred_relocation) = patch.deferred_relocation
                && let Err(reason) = materialize_deferred_relocation_patch(
                    &mut patch.data,
                    output_range,
                    deferred_relocation,
                )
            {
                return Ok(ChangedInputPatchResult::StartedUnsupported(reason));
            }
            for preserve_range in &patch.preserve_ranges {
                let Some(data_range) = patch.data.get_mut(preserve_range.clone()) else {
                    return Ok(ChangedInputPatchResult::StartedUnsupported(
                        "changed patch preserve range is out of bounds".to_owned(),
                    ));
                };
                let Some(previous_range) = output_range.get(preserve_range.clone()) else {
                    return Ok(ChangedInputPatchResult::StartedUnsupported(
                        "changed patch preserve range is out of bounds".to_owned(),
                    ));
                };
                data_range.copy_from_slice(previous_range);
            }
            for adjustment in &patch.adjustments {
                let Some(data_range) = patch.data.get_mut(adjustment.range.clone()) else {
                    return Ok(ChangedInputPatchResult::StartedUnsupported(
                        "changed patch adjustment range is out of bounds".to_owned(),
                    ));
                };
                if let Err(reason) = apply_addend_delta(data_range, adjustment.addend_delta) {
                    return Ok(ChangedInputPatchResult::StartedUnsupported(reason));
                }
            }
            let (data_out, padding) = output_range.split_at_mut(patch.data.len());
            data_out.copy_from_slice(&patch.data);
            padding.fill(0);
            patched_ranges.push(start..end);
        }
    }

    let mut flush_ranges = patched_ranges.clone();
    if let Some(range) = build_id_range {
        let previous_hashes = build_id_hashes
            .as_mut()
            .context("Missing incremental build ID hash state")?;
        let tree = build_id_tree
            .as_mut()
            .context("Missing incremental build ID hash tree")?;
        flush_ranges.push(range.clone());
        write_fast_build_id_from_state(&mut output, range, previous_hashes, tree, &patched_ranges)?;
    }
    let (changed_input_snapshot_result, deferred_loaded_input_content_hashes) =
        if args.should_snapshot_changed_inputs_while_finalizing_direct_patches() {
            let (deferred_loaded_input_content_hashes, snapshot_result) =
                std::thread::scope(|scope| -> Result<_> {
                    let background = std::thread::Builder::new()
                        .name("sld-input-snapshot".to_owned())
                        .spawn_scoped(scope, || {
                            let snapshot_result = {
                                timing_phase!("Snapshot changed incremental inputs");
                                snapshot_input_paths(
                                    state_dir,
                                    changed_inputs_requiring_snapshot(
                                        changed_inputs,
                                        &rustc_link_content_digest_unchanged_input_indices,
                                    )
                                    .map(|(_, path)| path.as_path()),
                                )
                            };
                            let deferred_loaded_input_content_hashes =
                                hash_deferred_loaded_input_contents(
                                    &deferred_loaded_input_content_hashes,
                                    false,
                                );
                            (deferred_loaded_input_content_hashes, snapshot_result)
                        })
                        .context("Failed to spawn incremental input snapshot thread")?;
                    let finalization_result = args.finalize_directly_patched_output(
                        &mut output,
                        &mut flush_ranges,
                        should_invalidate_code_signature_cache,
                    );
                    let background_result = background
                        .join()
                        .map_err(|_| crate::error!("Incremental input snapshot thread panicked"))?;
                    finalization_result?;
                    Ok(background_result)
                })?;
            (Some(snapshot_result), deferred_loaded_input_content_hashes)
        } else {
            args.finalize_directly_patched_output(
                &mut output,
                &mut flush_ranges,
                should_invalidate_code_signature_cache,
            )?;
            (
                None,
                hash_deferred_loaded_input_contents(&deferred_loaded_input_content_hashes, true),
            )
        };
    install_deferred_loaded_input_content_hashes(
        &mut previous.input_files,
        &mut expected_changed_inputs,
        deferred_loaded_input_content_hashes,
    )?;

    {
        timing_phase!("Flush changed incremental output ranges");
        if directly_patched_output.is_generation() {
            write_output_ranges(
                &output,
                &flush_ranges,
                &mut file,
                directly_patched_output.path(),
            )?;
        } else {
            flush_output_ranges(&output, &flush_ranges, directly_patched_output.path())?;
        }
    }
    drop(output);
    drop(file);
    directly_patched_output.install(&flush_ranges)?;

    let output = directly_patched_output_content_state(args, args.output()).with_context(|| {
        format!(
            "Failed to record patched output `{}` for incremental state",
            args.output().display()
        )
    })?;
    if args.should_retain_output_snapshot() {
        timing_phase!("Update incremental output snapshot");
        update_output_snapshot_from_ranges(state_dir, args.output(), &flush_ranges)?;
    }
    write_build_id_hash_tree(state_dir, build_id_tree.as_deref())?;
    {
        changed_input_snapshot_result.unwrap_or_else(|| {
            timing_phase!("Snapshot changed incremental inputs");
            snapshot_input_paths(
                state_dir,
                changed_inputs_requiring_snapshot(
                    changed_inputs,
                    &rustc_link_content_digest_unchanged_input_indices,
                )
                .map(|(_, path)| path.as_path()),
            )
        })?;
        refresh_input_snapshot_identities_at_indices(
            state_dir,
            &mut previous.input_files,
            changed_inputs_requiring_snapshot(
                changed_inputs,
                &rustc_link_content_digest_unchanged_input_indices,
            )
            .map(|(input_index, _)| *input_index),
        );
        refresh_input_file_identities_at_indices(
            &mut previous.input_files,
            changed_inputs.iter().map(|(input_index, _)| *input_index),
        );
    }
    if let Some(reason) = input_content_mismatch_reason(&expected_changed_inputs, Some(state_dir)) {
        return Ok(ChangedInputPatchResult::StartedUnsupported(reason));
    }
    if let Some(reason) = input_identity_mismatch_reason(&previous.input_files)? {
        return Ok(ChangedInputPatchResult::StartedUnsupported(reason));
    }
    {
        timing_phase!("Persist changed incremental patch metadata");
        let mut state = PersistedState {
            args_hash: previous.args_hash,
            link_options_hash: previous.link_options_hash,
            input_order_hash: previous.input_order_hash,
            sld_version: previous.sld_version,
            link_start: current_link_start,
            output,
            build_id_hashes,
            input_files: previous.input_files,
            sections: previous.sections,
            relocations: previous.relocations,
            macho_symbol_resolutions: previous.macho_symbol_resolutions,
            fdes: previous.fdes,
            dynamic_relocations: previous.dynamic_relocations,
            reserved_ranges: previous.reserved_ranges,
            sections_file: previous.sections_file,
            macho_symbol_resolutions_file: previous.macho_symbol_resolutions_file,
            indexed_macho_symbol_resolutions_file: previous.indexed_macho_symbol_resolutions_file,
            patch_records_file: previous.patch_records_file,
            patch_record_locations: previous.patch_record_locations,
            raw_patch_record_locations: previous.raw_patch_record_locations,
            record_overrides_file: previous.record_overrides_file,
            record_override_inputs: previous.record_override_inputs,
        };
        if state.sections_file.is_some() {
            state.persist_macho_symbol_resolutions_for_metadata_update(state_dir)?;
        }
        if state.sections_file.is_some() && !record_override_input_files.is_empty() {
            state.write_record_overrides_for_inputs(
                state_dir,
                record_override_input_files.into_iter(),
            )?;
        }
        state.write_metadata_update_for_inputs(state_dir, metadata_update_input_indices)?;
    }
    clear_incremental_update_marker(state_dir)?;

    append_log(
        state_dir,
        &format!(
            "patched {} changed input file{} before loading inputs",
            patched_input_count,
            if patched_input_count == 1 { "" } else { "s" }
        ),
    )?;
    if rewritten_input_count > 0 {
        append_log(
            state_dir,
            &format!(
                "updated {rewritten_input_count} rewritten input file{} before loading inputs",
                if rewritten_input_count == 1 { "" } else { "s" }
            ),
        )?;
    }
    if normalized_unchanged_input_count > 0 {
        append_log(
            state_dir,
            &format!(
                "updated {normalized_unchanged_input_count} unchanged normalized Rust archive input file{} before loading inputs",
                if normalized_unchanged_input_count == 1 {
                    ""
                } else {
                    "s"
                }
            ),
        )?;
    }
    if rustc_link_content_digest_unchanged_input_count > 0 {
        append_log(
            state_dir,
            &format!(
                "reused {rustc_link_content_digest_unchanged_input_count} unchanged Rust archive input file{} by rustc link-content digest before loading inputs",
                if rustc_link_content_digest_unchanged_input_count == 1 {
                    ""
                } else {
                    "s"
                }
            ),
        )?;
    }
    if hashless_atomic_replacement_snapshot_count > 0 {
        append_log(
            state_dir,
            &format!(
                "retained {hashless_atomic_replacement_snapshot_count} hashless atomic-replacement input snapshot{} before loading inputs",
                if hashless_atomic_replacement_snapshot_count == 1 {
                    ""
                } else {
                    "s"
                }
            ),
        )?;
    }
    append_log(
        state_dir,
        &format!("patched {patched_section_count} changed input sections before loading inputs"),
    )?;
    Ok(ChangedInputPatchResult::Patched)
}

fn directly_patched_output_content_state(
    args: &impl platform::Args,
    output: &Path,
) -> Result<FileContentState> {
    if args.should_hash_directly_patched_output() || args.should_retain_output_snapshot() {
        FileContentState::from_path(output)
    } else {
        FileContentState::from_path_identity_only(output)
    }
}

struct PreviousPatchState {
    fingerprint: String,
    archive_member_patch_fingerprints: Option<Vec<ArchiveMemberPatchFingerprint>>,
    sections: Vec<PatchSection>,
}

fn can_normalize_rust_archive_patch(
    args: &impl platform::Args,
    previous: &PersistedState,
    input_index: usize,
    path: &Path,
) -> bool {
    can_reuse_rustc_link_content_digest(args, path)
        && previous
            .input_files
            .get(input_index)
            .is_some_and(|input| !input_has_records_requiring_previous_bytes(previous, input))
}

fn can_reuse_rustc_link_content_digest(args: &impl platform::Args, path: &Path) -> bool {
    args.should_normalize_rust_archive_patch_inputs()
        && path
            .extension()
            .is_some_and(|extension| extension == "rlib")
}

fn can_retain_hashless_atomic_replacement_snapshot(
    path: &Path,
    normalized_rust_archive_matched_sections: bool,
    trust_rustc_link_content_digests: bool,
) -> bool {
    normalized_rust_archive_matched_sections
        && trust_rustc_link_content_digests
        && is_atomic_replacement_rust_input(path)
}

fn input_has_records_requiring_previous_bytes(
    previous: &PersistedState,
    input: &FileState,
) -> bool {
    previous.relocations.iter().any(|relocation| {
        relocation.input_file == input.path
            || relocation
                .target
                .as_ref()
                .is_some_and(|target| target.input_file == input.path)
    }) || previous
        .dynamic_relocations
        .iter()
        .any(|relocation| relocation.input_file == input.path)
        || previous
            .fdes
            .iter()
            .any(|record| record.input_file == input.path)
}

fn classify_normalized_rust_archive_patch_state(
    input: &FileState,
    bytes: &[u8],
    previous_patch: &PreviousPatchState,
) -> Result<NormalizedRustArchivePatchState> {
    verbose_timing_phase!("Classify normalized unchanged archive input");
    let resolver = PatchInputResolver::new(bytes, true)?;
    let Some(matched) = match_patch_sections_from_current_hashes_with_resolver(
        input.path.as_str(),
        &previous_patch.sections,
        &resolver,
    )?
    else {
        return Ok(NormalizedRustArchivePatchState::Unknown);
    };
    if !matched.changed_sections.is_empty() {
        return Ok(NormalizedRustArchivePatchState::MatchedButNotUnchanged(
            matched,
        ));
    }
    let current_sections = matched
        .sections
        .into_iter()
        .map(|section| section.current)
        .collect::<Vec<_>>();
    let Some((fingerprint, archive_member_patch_fingerprints)) =
        patch_fingerprint_with_resolver_and_archive_member_patch_fingerprints(
            bytes,
            input.path.as_str(),
            current_sections.iter().cloned(),
            std::iter::empty(),
            &resolver,
            PatchInputLookup::MatchArchiveMember,
            true,
            previous_patch.archive_member_patch_fingerprints.as_deref(),
        )?
    else {
        return Ok(NormalizedRustArchivePatchState::Unknown);
    };
    if fingerprint != previous_patch.fingerprint {
        return Ok(NormalizedRustArchivePatchState::Unknown);
    }
    Ok(NormalizedRustArchivePatchState::Unchanged(FilePatchState {
        fingerprint,
        archive_member_set_proof: archive_member_set_proof(bytes)?,
        archive_member_patch_fingerprints,
        macho_archive_members: input
            .patch
            .as_ref()
            .map(|patch| patch.macho_archive_members.clone())
            .unwrap_or_default(),
        sections: current_sections
            .iter()
            .map(|section| FilePatchSectionState {
                input: section.input.clone(),
                section_index: section.section_index,
                section_name: section.section_name.clone(),
                input_size: section.input_size,
                output_offset: section.output_offset,
                output_size: section.output_size,
                data_hash: section.data_hash.clone(),
                cstring_nul_boundaries_hash: section.cstring_nul_boundaries_hash.clone(),
            })
            .collect(),
        raw_sections: None,
    }))
}

fn patch_sections_from_previous_state(
    input: &FileState,
    path: &Path,
) -> std::result::Result<PreviousPatchState, String> {
    let Some(previous_patch) = input.patch.as_ref() else {
        return Err(format!("missing patch metadata for `{}`", path.display()));
    };
    let sections = if previous_patch.sections.is_empty() {
        previous_patch
            .raw_sections
            .as_ref()
            .map(|raw| parse_patch_sections(input.path.as_str(), raw))
            .transpose()
            .map_err(|error| format!("{error:?}"))?
            .unwrap_or_default()
    } else {
        previous_patch.sections.clone()
    };
    if sections.is_empty() {
        return Err(format!(
            "no patchable sections recorded for `{}`",
            path.display()
        ));
    }
    let patch_section_keys = sections
        .iter()
        .map(|section| (section.input.as_str(), section.section_index))
        .collect::<HashSet<_>>();
    if patch_section_keys.len() != sections.len() {
        return Err(format!(
            "duplicate patchable section metadata for `{}`",
            path.display()
        ));
    }
    Ok(PreviousPatchState {
        fingerprint: previous_patch.fingerprint.clone(),
        archive_member_patch_fingerprints: previous_patch.archive_member_patch_fingerprints.clone(),
        sections: sections
            .iter()
            .map(|section| PatchSection {
                input: section.input.clone(),
                section_index: section.section_index,
                section_name: section.section_name.clone(),
                input_size: section.input_size,
                output_offset: section.output_offset,
                output_size: section.output_size,
                data_hash: section.data_hash.clone(),
                cstring_nul_boundaries_hash: section.cstring_nul_boundaries_hash.clone(),
            })
            .collect(),
    })
}

struct SectionPatch {
    output_offset: u64,
    size: u64,
    data: Vec<u8>,
    deferred_relocation: Option<DeferredRelocationPatch>,
    preserve_ranges: Vec<std::ops::Range<usize>>,
    adjustments: Vec<PatchAdjustment>,
}

fn stored_output_patch(
    patch: &SectionPatch,
    previous_output: &[u8],
) -> std::result::Result<StoredOutputPatch, String> {
    let start = usize::try_from(patch.output_offset)
        .map_err(|_| "Mach-O archive transaction patch offset is too large".to_owned())?;
    let size = usize::try_from(patch.size)
        .map_err(|_| "Mach-O archive transaction patch size is too large".to_owned())?;
    let end = start
        .checked_add(size)
        .ok_or_else(|| "Mach-O archive transaction patch range overflowed".to_owned())?;
    let previous = previous_output
        .get(start..end)
        .ok_or_else(|| "Mach-O archive transaction patch is outside output".to_owned())?;
    if patch.data.len() > size {
        return Err("Mach-O archive transaction patch data exceeds its range".to_owned());
    }
    let mut data = patch.data.clone();
    if let Some(deferred_relocation) = patch.deferred_relocation {
        let data_len = data.len();
        materialize_deferred_relocation_patch(
            &mut data,
            &previous[..data_len],
            deferred_relocation,
        )?;
    }
    for preserve_range in &patch.preserve_ranges {
        let data_range = data
            .get_mut(preserve_range.clone())
            .ok_or_else(|| "Mach-O archive transaction preserve range is invalid".to_owned())?;
        let previous_range = previous
            .get(preserve_range.clone())
            .ok_or_else(|| "Mach-O archive transaction preserve range is invalid".to_owned())?;
        data_range.copy_from_slice(previous_range);
    }
    for adjustment in &patch.adjustments {
        let data_range = data
            .get_mut(adjustment.range.clone())
            .ok_or_else(|| "Mach-O archive transaction adjustment range is invalid".to_owned())?;
        apply_addend_delta(data_range, adjustment.addend_delta)?;
    }
    data.resize(size, 0);
    Ok(StoredOutputPatch {
        output_offset: patch.output_offset,
        data,
    })
}

