impl FileContentState {
    fn from_path_identity_only(path: &Path) -> Result<Self> {
        let Some(identity) = FileIdentity::from_path(path)? else {
            return Self::from_path(path);
        };
        Ok(Self {
            len: identity.len,
            hash: String::new(),
            identity: Some(identity),
        })
    }

    fn from_path(path: &Path) -> Result<Self> {
        let bytes =
            std::fs::read(path).with_context(|| format!("Failed to read `{}`", path.display()))?;
        let mut state = Self::from_bytes(&bytes);
        state.identity = FileIdentity::from_path(path).ok().flatten();
        Ok(state)
    }

    fn from_bytes(bytes: &[u8]) -> Self {
        Self {
            len: bytes.len() as u64,
            hash: hash_bytes(bytes),
            identity: None,
        }
    }

    fn from_input_file(
        input_file: &crate::input_data::InputFile,
        previous: Option<&FileContentState>,
    ) -> Self {
        let identity = FileIdentity::from_path(&input_file.filename).ok().flatten();
        if let (Some(identity), Some(previous)) = (identity.as_ref(), previous)
            && previous.identity.as_ref() == Some(identity)
        {
            let mut state = previous.clone();
            state.identity = Some(identity.clone());
            return state;
        }

        if let Some(identity) = identity.as_ref()
            && previous.is_none_or(|previous| previous.hash.is_empty())
        {
            return Self {
                len: identity.len,
                hash: String::new(),
                identity: Some(identity.clone()),
            };
        }

        let mut state = Self::from_bytes(input_file.full_data());
        state.identity = identity;
        state
    }

    fn identity_matches_path(&self, path: &Path) -> Result<bool> {
        let Some(previous) = self.identity.as_ref() else {
            return Ok(false);
        };
        Ok(FileIdentity::from_path(path)?.as_ref() == Some(previous))
    }

    fn data_identity_matches_path(&self, path: &Path) -> Result<bool> {
        let Some(previous) = self.identity.as_ref() else {
            return Ok(false);
        };
        Ok(FileIdentity::from_path(path)?
            .as_ref()
            .is_some_and(|current| previous.matches_same_data_ignoring_change_time(current)))
    }

    fn identity_is_ambiguous_since(&self, link_start: Option<&FileIdentity>) -> bool {
        self.identity
            .as_ref()
            .zip(link_start)
            .is_some_and(|(identity, link_start)| identity.may_have_changed_since(link_start))
    }

    fn render_identity(&self) -> String {
        self.identity
            .as_ref()
            .map_or_else(|| "-".to_owned(), FileIdentity::render)
    }
}

impl FileIdentity {
    fn matches_same_data_ignoring_change_time(&self, other: &Self) -> bool {
        self.len == other.len
            && self.dev == other.dev
            && self.ino == other.ino
            && self.modified_sec == other.modified_sec
            && self.modified_nsec == other.modified_nsec
    }

    fn modified_on_or_after(&self, lower_bound: &Self) -> bool {
        timestamp_on_or_after(
            self.modified_sec,
            self.modified_nsec,
            lower_bound.modified_sec,
            lower_bound.modified_nsec,
        )
    }

    fn may_have_changed_since(&self, lower_bound: &Self) -> bool {
        self.modified_on_or_after(lower_bound)
            || timestamp_on_or_after(
                self.changed_sec,
                self.changed_nsec,
                lower_bound.modified_sec,
                lower_bound.modified_nsec,
            )
    }

    fn from_path(path: &Path) -> Result<Option<Self>> {
        let metadata = std::fs::metadata(path)
            .with_context(|| format!("Failed to read metadata for `{}`", path.display()))?;
        #[cfg(unix)]
        {
            Ok(Some(Self::from_metadata(&metadata)))
        }
        #[cfg(not(unix))]
        {
            let _ = metadata;
            Ok(None)
        }
    }

    #[cfg(unix)]
    fn from_metadata(metadata: &Metadata) -> Self {
        Self {
            len: metadata.len(),
            dev: metadata.dev(),
            ino: metadata.ino(),
            modified_sec: metadata.mtime(),
            modified_nsec: metadata.mtime_nsec(),
            changed_sec: metadata.ctime(),
            changed_nsec: metadata.ctime_nsec(),
        }
    }

    fn render(&self) -> String {
        format!(
            "{}:{}:{}:{}:{}:{}:{}",
            self.len,
            self.dev,
            self.ino,
            self.modified_sec,
            self.modified_nsec,
            self.changed_sec,
            self.changed_nsec
        )
    }

    fn parse(value: &str) -> Result<Option<Self>> {
        if value == "-" {
            return Ok(None);
        }

        let mut parts = value.split(':');
        let mut next = |field| {
            parts
                .next()
                .with_context(|| format!("Malformed incremental file identity `{field}`"))
        };
        let identity = Self {
            len: next("len")?
                .parse()
                .context("Invalid incremental file identity length")?,
            dev: next("dev")?
                .parse()
                .context("Invalid incremental file identity device")?,
            ino: next("ino")?
                .parse()
                .context("Invalid incremental file identity inode")?,
            modified_sec: next("mtime")?
                .parse()
                .context("Invalid incremental file identity mtime")?,
            modified_nsec: next("mtime_nsec")?
                .parse()
                .context("Invalid incremental file identity mtime_nsec")?,
            changed_sec: next("ctime")?
                .parse()
                .context("Invalid incremental file identity ctime")?,
            changed_nsec: next("ctime_nsec")?
                .parse()
                .context("Invalid incremental file identity ctime_nsec")?,
        };
        if parts.next().is_some() {
            return Err(crate::error!("Malformed incremental file identity"));
        }
        Ok(Some(identity))
    }
}

fn timestamp_on_or_after(sec: i64, _nsec: i64, lower_sec: i64, _lower_nsec: i64) -> bool {
    // Some filesystems report coarse timestamps or fail to advance nanoseconds for rapid
    // rewrites. Treat the whole filesystem second as ambiguous once it overlaps the link start.
    sec >= lower_sec
}

struct LazyOutputBytes<F> {
    bytes: Option<memmap2::Mmap>,
    load: Option<F>,
}

impl<F> LazyOutputBytes<F>
where
    F: FnOnce() -> Result<memmap2::Mmap>,
{
    fn new(load: F) -> Self {
        Self {
            bytes: None,
            load: Some(load),
        }
    }

    fn get(&mut self) -> Result<&[u8]> {
        if self.bytes.is_none() {
            let load = self
                .load
                .take()
                .context("Incremental output bytes were already consumed")?;
            self.bytes = Some(load()?);
        }
        Ok(self.bytes.as_deref().unwrap_or_default())
    }
}

struct LazyInputSnapshotBytes<F> {
    bytes: Option<Option<Vec<u8>>>,
    load: Option<F>,
}

impl<F> LazyInputSnapshotBytes<F>
where
    F: FnOnce() -> Result<Option<Vec<u8>>>,
{
    fn new(load: F) -> Self {
        Self {
            bytes: None,
            load: Some(load),
        }
    }

    fn get(&mut self) -> Result<Option<&[u8]>> {
        if self.bytes.is_none() {
            let load = self
                .load
                .take()
                .context("Incremental input snapshot bytes were already consumed")?;
            self.bytes = Some(load()?);
        }
        Ok(self.get_if_loaded())
    }

    fn get_if_loaded(&self) -> Option<&[u8]> {
        self.bytes.as_ref().and_then(Option::as_deref)
    }
}

fn read_output_bytes(path: &Path) -> Result<memmap2::Mmap> {
    let file = OpenOptions::new().read(true).open(path).with_context(|| {
        format!(
            "Failed to read output `{}` for incremental state",
            path.display()
        )
    })?;
    unsafe { MmapOptions::new().map(&file) }.with_context(|| {
        format!(
            "Failed to mmap output `{}` for incremental state",
            path.display()
        )
    })
}

#[cfg(test)]
fn record_patch_fingerprints<F>(
    input_files: &mut [FileState],
    file_loader: &FileLoader<'_>,
    sections: &[SectionRecord],
    relocations: &[RelocationRecord],
    fdes: &[FdeRecord],
    dynamic_relocations: &[DynamicRelocationRecord],
    output: &mut LazyOutputBytes<F>,
) -> Result
where
    F: FnOnce() -> Result<memmap2::Mmap>,
{
    record_patch_fingerprints_for_inputs(
        input_files,
        file_loader,
        sections,
        relocations,
        fdes,
        dynamic_relocations,
        output,
        |_| true,
    )
}

#[cfg(test)]
fn record_patch_fingerprints_for_inputs<F, P>(
    input_files: &mut [FileState],
    file_loader: &FileLoader<'_>,
    sections: &[SectionRecord],
    relocations: &[RelocationRecord],
    fdes: &[FdeRecord],
    dynamic_relocations: &[DynamicRelocationRecord],
    output: &mut LazyOutputBytes<F>,
    should_record: P,
) -> Result
where
    F: FnOnce() -> Result<memmap2::Mmap>,
    P: Fn(&crate::input_data::InputFile) -> bool,
{
    let mut sections_by_file = HashMap::<&str, Vec<&SectionRecord>>::new();
    for section in sections {
        sections_by_file
            .entry(section.input_file.as_str())
            .or_default()
            .push(section);
    }

    let mut dynamic_relocations_by_file = HashMap::<&str, Vec<&DynamicRelocationRecord>>::new();
    for relocation in dynamic_relocations {
        dynamic_relocations_by_file
            .entry(relocation.input_file.as_str())
            .or_default()
            .push(relocation);
    }

    let mut relocations_by_file = HashMap::<&str, Vec<&RelocationRecord>>::new();
    for relocation in relocations {
        relocations_by_file
            .entry(relocation.input_file.as_str())
            .or_default()
            .push(relocation);
    }

    let mut relocation_targets_by_file = HashMap::<&str, Vec<&RelocationRecord>>::new();
    for relocation in relocations {
        if let Some(target) = &relocation.target {
            relocation_targets_by_file
                .entry(target.input_file.as_str())
                .or_default()
                .push(relocation);
        }
    }

    let mut fdes_by_file = HashMap::<&str, Vec<&FdeRecord>>::new();
    for fde in fdes {
        fdes_by_file
            .entry(fde.input_file.as_str())
            .or_default()
            .push(fde);
    }

    if sections_by_file.is_empty()
        && relocations_by_file.is_empty()
        && relocation_targets_by_file.is_empty()
        && dynamic_relocations_by_file.is_empty()
        && fdes_by_file.is_empty()
    {
        return Ok(());
    }

    let loaded_by_path = file_loader
        .loaded_files
        .iter()
        .map(|file| (encode_path(&file.filename), *file))
        .collect::<HashMap<_, _>>();

    for input in input_files {
        let Some(sections) = sections_by_file.get(input.path.as_str()) else {
            input.patch = None;
            continue;
        };
        let input_dynamic_relocations = dynamic_relocations_by_file.get(input.path.as_str());
        let input_relocations = relocations_by_file.get(input.path.as_str());
        let input_relocation_targets = relocation_targets_by_file.get(input.path.as_str());
        let input_fdes = fdes_by_file.get(input.path.as_str());
        if input
            .patch
            .as_ref()
            .is_some_and(|patch| patch_state_matches_section_records(patch, sections))
        {
            continue;
        }
        let Some(input_file) = loaded_by_path.get(&input.path) else {
            input.patch = None;
            continue;
        };
        if !should_record(input_file) {
            input.patch = None;
            continue;
        }
        let patch = current_patch_state(
            input_file.data(),
            input.path.as_str(),
            output.get()?,
            sections,
            input_dynamic_relocations
                .map(Vec::as_slice)
                .unwrap_or_default(),
            input_relocations.map(Vec::as_slice).unwrap_or_default(),
            input_relocation_targets
                .map(Vec::as_slice)
                .unwrap_or_default(),
            &[],
            input_fdes.map(Vec::as_slice).unwrap_or_default(),
            true,
        )?;
        if patch.is_some() && input.content.hash.is_empty() {
            input.content.hash = hash_bytes(input_file.full_data());
        }
        input.patch = patch;
    }

    Ok(())
}

fn current_patch_state(
    bytes: &[u8],
    input_file_path: &str,
    output: &[u8],
    sections: &[&SectionRecord],
    dynamic_relocations: &[&DynamicRelocationRecord],
    relocations: &[&RelocationRecord],
    relocation_targets: &[&RelocationRecord],
    macho_symbol_resolutions: &[&MachOSymbolResolutionRecord],
    fdes: &[&FdeRecord],
    normalize_rust_archive_patch_inputs: bool,
) -> Result<Option<FilePatchState>> {
    let archive_member_set_proof = archive_member_set_proof(bytes)?;
    let patch_sections = direct_copy_patch_sections(
        bytes,
        input_file_path,
        output,
        sections,
        dynamic_relocations.iter().copied(),
        relocations.iter().copied(),
    )?;
    let dynamic_relocation_patches = dynamic_relocation_patches_for_current_records(
        bytes,
        input_file_path,
        dynamic_relocations.iter().copied(),
    )?;
    let relocation_addend_ranges = relocation_addend_ranges_for_current_records(
        bytes,
        input_file_path,
        relocations.iter().copied(),
    )?;
    let relocation_target_ranges = relocation_target_ranges_for_current_records(
        bytes,
        input_file_path,
        relocation_targets.iter().copied(),
    )?;
    let Some(macho_symbol_resolution_ranges) = macho_symbol_resolution_ranges_for_current_records(
        bytes,
        input_file_path,
        macho_symbol_resolutions.iter().copied(),
    )?
    else {
        return Ok(None);
    };
    let fde_relocation_ranges =
        fde_patch_input_ranges_for_current_records(bytes, input_file_path, fdes.iter().copied())?;
    Ok(patch_fingerprint_for_current_records_with_extra_ranges_and_archive_member_patch_fingerprints(
        bytes,
        input_file_path,
        patch_sections.iter().cloned(),
        dynamic_relocation_patches
            .iter()
            .filter_map(|patch| patch.input_range.clone())
            .chain(relocation_addend_ranges)
            .chain(relocation_target_ranges)
            .chain(macho_symbol_resolution_ranges)
            .chain(fde_relocation_ranges),
        normalize_rust_archive_patch_inputs,
    )?
    .map(|(fingerprint, archive_member_patch_fingerprints)| FilePatchState {
        fingerprint,
        archive_member_set_proof,
        archive_member_patch_fingerprints,
        macho_archive_members: Vec::new(),
        sections: patch_sections
            .iter()
            .map(|section| FilePatchSectionState {
                input: section.input.clone(),
                section_index: section.section_index,
                section_name: section.section_name.clone(),
                input_size: section.input_size,
                output_offset: section.output_offset,
                output_size: section.output_size,
                data_hash: section.data_hash.clone(),
                cstring_nul_boundaries_hash: section.cstring_nul_boundaries_hash.clone(),
            })
            .collect(),
        raw_sections: None,
    }))
}

fn current_patch_state_from_snapshot(
    state_dir: &Path,
    input: &FileState,
    output: &[u8],
    sections: &[SectionRecord],
    relocations: &[RelocationRecord],
    macho_symbol_resolutions: &[MachOSymbolResolutionRecord],
    fdes: &[FdeRecord],
    dynamic_relocations: &[DynamicRelocationRecord],
    normalize_rust_archive_patch_inputs: bool,
) -> Result<Option<FilePatchState>> {
    current_patch_state_from_snapshot_with_rustc_work_product_provenance(
        state_dir,
        input,
        output,
        sections,
        relocations,
        macho_symbol_resolutions,
        fdes,
        dynamic_relocations,
        normalize_rust_archive_patch_inputs,
        rustc_work_product_provenance_enabled(),
    )
}

#[allow(clippy::too_many_arguments)]
fn current_patch_state_from_snapshot_with_rustc_work_product_provenance(
    state_dir: &Path,
    input: &FileState,
    output: &[u8],
    sections: &[SectionRecord],
    relocations: &[RelocationRecord],
    macho_symbol_resolutions: &[MachOSymbolResolutionRecord],
    fdes: &[FdeRecord],
    dynamic_relocations: &[DynamicRelocationRecord],
    normalize_rust_archive_patch_inputs: bool,
    trust_rustc_work_product_provenance: bool,
) -> Result<Option<FilePatchState>> {
    let Some(bytes) = read_verified_input_snapshot_with_rustc_work_product_provenance(
        state_dir,
        input,
        trust_rustc_work_product_provenance,
    )?
    else {
        return Ok(None);
    };
    let sections = sections
        .iter()
        .filter(|section| section.input_file == input.path)
        .collect::<Vec<_>>();
    let dynamic_relocations = dynamic_relocations
        .iter()
        .filter(|relocation| relocation.input_file == input.path)
        .collect::<Vec<_>>();
    let input_relocations = relocations
        .iter()
        .filter(|relocation| relocation.input_file == input.path)
        .collect::<Vec<_>>();
    let relocation_targets = relocations
        .iter()
        .filter(|relocation| {
            relocation
                .target
                .as_ref()
                .is_some_and(|target| target.input_file == input.path)
        })
        .collect::<Vec<_>>();
    let macho_symbol_resolutions = macho_symbol_resolutions
        .iter()
        .filter(|resolution| {
            resolution
                .target
                .as_ref()
                .is_some_and(|target| target.input_file == input.path)
        })
        .collect::<Vec<_>>();
    let fdes = fdes
        .iter()
        .filter(|record| record.input_file == input.path)
        .collect::<Vec<_>>();
    current_patch_state(
        &bytes,
        input.path.as_str(),
        output,
        &sections,
        &dynamic_relocations,
        &input_relocations,
        &relocation_targets,
        &macho_symbol_resolutions,
        &fdes,
        normalize_rust_archive_patch_inputs,
    )
}

#[cfg(test)]
fn patch_state_matches_section_records(
    patch: &FilePatchState,
    sections: &[&SectionRecord],
) -> bool {
    if patch.sections.is_empty() || patch.sections.len() != sections.len() {
        return false;
    }

    let mut patch_sections = patch
        .sections
        .iter()
        .map(|section| {
            (
                section.input.as_str(),
                section.section_index,
                section.output_offset,
                section.output_size,
            )
        })
        .collect::<Vec<_>>();
    patch_sections.sort();

    let mut section_records = sections
        .iter()
        .map(|section| {
            (
                section.input.as_str(),
                section.section_index,
                section.output_offset,
                section.size,
            )
        })
        .collect::<Vec<_>>();
    section_records.sort();

    patch_sections == section_records
}

fn direct_copy_patch_sections<'a>(
    bytes: &[u8],
    input_file_path: &str,
    output: &[u8],
    sections: &[&'a SectionRecord],
    dynamic_relocations: impl IntoIterator<Item = &'a DynamicRelocationRecord>,
    relocations: impl IntoIterator<Item = &'a RelocationRecord>,
) -> Result<Vec<PatchSection>> {
    let mut patch_sections = Vec::new();
    let dynamic_relocation_offsets =
        dynamic_relocation_offsets_by_input_section(dynamic_relocations);
    let relocation_offsets = relocation_offsets_by_input_section(relocations);

    let mut sections_by_input = HashMap::<&str, Vec<&SectionRecord>>::new();
    for record in sections {
        sections_by_input
            .entry(record.input.as_str())
            .or_default()
            .push(record);
    }

    for (input_ref, records) in sections_by_input {
        let Some(input_bytes) = patch_input_bytes_with_lookup(
            bytes,
            input_file_path,
            input_ref,
            PatchInputLookup::CurrentRecordedRange,
        )?
        else {
            continue;
        };
        let file = object::File::parse(input_bytes.bytes)
            .context("Failed to parse incremental patch candidate input")?;
        for record in records {
            let section = file
                .section_by_index(patch_section_object_index(&file, record.section_index)?)
                .context("Missing incremental patch candidate section")?;
            let data = section
                .data()
                .context("Failed to read incremental patch candidate section data")?;
            let dynamic_relocations =
                dynamic_relocation_offsets.get(&(input_ref, record.section_index));
            let relocations = relocation_offsets.get(&(input_ref, record.section_index));
            let Some(preserve_ranges) = section_direct_patch_preserve_ranges(
                &file,
                &section,
                data,
                dynamic_relocations,
                relocations,
            ) else {
                continue;
            };
            if data.len() > record.size as usize {
                continue;
            }
            let start = record.output_offset as usize;
            let end = start
                .checked_add(record.size as usize)
                .context("Incremental patch output range overflow")?;
            let Some(output_range) = output.get(start..end) else {
                continue;
            };
            let (data_out, padding) = output_range.split_at(data.len());
            if patchable_bytes_match(data_out, data, &preserve_ranges)
                && padding.iter().all(|byte| *byte == 0)
            {
                patch_sections.push(PatchSection {
                    input: record.input.to_string(),
                    section_index: record.section_index,
                    section_name: patch_section_name_for_matching(&section),
                    input_size: data.len() as u64,
                    output_offset: record.output_offset,
                    output_size: record.size,
                    data_hash: Some(hash_bytes(data)),
                    cstring_nul_boundaries_hash: cstring_nul_boundaries_hash_for_section(
                        section.name().ok(),
                        data,
                    ),
                });
            }
        }
    }
    Ok(patch_sections)
}

fn dynamic_relocation_offsets_by_input_section<'a>(
    dynamic_relocations: impl IntoIterator<Item = &'a DynamicRelocationRecord>,
) -> HashMap<(&'a str, u32), HashSet<u64>> {
    let mut offsets = HashMap::<(&str, u32), HashSet<u64>>::new();
    for relocation in dynamic_relocations {
        offsets
            .entry((relocation.input.as_str(), relocation.section_index))
            .or_default()
            .insert(relocation.relocation_offset);
    }
    offsets
}

fn relocation_offsets_by_input_section<'a>(
    relocations: impl IntoIterator<Item = &'a RelocationRecord>,
) -> HashMap<(&'a str, u32), HashSet<u64>> {
    let mut offsets = HashMap::<(&str, u32), HashSet<u64>>::new();
    for relocation in relocations {
        offsets
            .entry((relocation.input.as_str(), relocation.section_index))
            .or_default()
            .insert(relocation.relocation_offset);
    }
    offsets
}

fn section_flags_allow_patching(flags: object::SectionFlags) -> bool {
    match flags {
        object::SectionFlags::Elf { sh_flags } => {
            // Sections that sld actually merges are written by the merge-strings path, so they
            // don't produce direct-copy patch records. Merge-flagged sections that reach this
            // point were copied directly, for example under --no-string-merge.
            sh_flags & u64::from(object::elf::SHF_ALLOC) != 0
        }
        object::SectionFlags::MachO { flags } => {
            matches!(
                flags & object::macho::SECTION_TYPE,
                object::macho::S_REGULAR | object::macho::S_CSTRING_LITERALS
            )
        }
        _ => false,
    }
}

pub(crate) fn section_name_allows_direct_patching(name: &[u8]) -> bool {
    // Keep Mach-O patching to ordinary data, fixed-layout string literals, and fixed-size
    // relocation-free code. Mach-O exception tables are admitted below only when they have no
    // relocations; dependent unwind metadata is replaced separately.
    (!name.starts_with(b"__")
        || matches!(
            name,
            b"__data" | b"__const" | b"__cstring" | b"__text" | b"__gcc_except_tab"
        ))
        && !matches!(name, b".init" | b".fini")
        && !name.starts_with(b".eh_frame")
        && !name.starts_with(b".init_array")
        && !name.starts_with(b".fini_array")
        && !name.starts_with(b".preinit_array")
        && !name.starts_with(b".ctors")
        && !name.starts_with(b".dtors")
}

pub(crate) fn section_name_allows_incremental_padding(name: &[u8]) -> bool {
    (name.starts_with(b".") || matches!(name, b"__const" | b"__text"))
        && section_name_allows_direct_patching(name)
}

fn section_direct_patch_preserve_ranges<'data>(
    file: &object::File<'data>,
    section: &impl object::ObjectSection<'data>,
    section_data: &[u8],
    dynamic_relocation_offsets: Option<&HashSet<u64>>,
    relocation_offsets: Option<&HashSet<u64>>,
) -> Option<Vec<std::ops::Range<usize>>> {
    let section_name = section.name().ok().map(|name| name.as_bytes());
    let is_elf_debug_section = matches!(
        section.flags(),
        object::SectionFlags::Elf { sh_flags }
            if sh_flags & u64::from(object::elf::SHF_ALLOC) == 0
                && section_name.is_some_and(|name| name.starts_with(b".debug_"))
    );
    let is_macho_text = matches!(section.flags(), object::SectionFlags::MachO { .. })
        && section_name == Some(b"__text".as_slice());
    let is_macho_const = matches!(section.flags(), object::SectionFlags::MachO { .. })
        && section_name == Some(b"__const".as_slice());
    let is_macho_exception_table = matches!(section.flags(), object::SectionFlags::MachO { .. })
        && section_name == Some(b"__gcc_except_tab".as_slice());
    if !(section_flags_allow_patching(section.flags()) || is_elf_debug_section)
        || !section_name.is_none_or(section_name_allows_direct_patching)
        || ((section_name == Some(b"__cstring".as_slice())
            || (section_name == Some(b"__const".as_slice()) && !is_macho_const)
            || is_macho_exception_table)
            && section.relocations().next().is_some())
    {
        return None;
    }
    if is_macho_text && section.relocations().next().is_some() {
        return macho_aarch64_text_relocation_ranges(file, section, section_data);
    }
    if is_macho_const && section.relocations().next().is_some() {
        return macho_aarch64_data_relocation_ranges(
            file,
            section,
            section_data,
            relocation_offsets,
        );
    }
    let required_relocation_offsets = if is_elf_debug_section {
        Some(relocation_offsets?)
    } else {
        None
    };

    relocation_preserve_ranges(
        file,
        section,
        section_data,
        dynamic_relocation_offsets,
        required_relocation_offsets,
    )
}

#[derive(PartialEq, Eq)]
struct MachOTextRelocationContext {
    range: std::ops::Range<usize>,
    r_type: u8,
    r_pcrel: bool,
    target: object::RelocationTarget,
    subtractor: Option<object::SymbolIndex>,
    addend: i64,
    bytes: [u8; 4],
}

#[derive(Debug, Clone, PartialEq, Eq)]
struct MachODataRelocationContext {
    range: std::ops::Range<usize>,
    target: object::RelocationTarget,
    addend: i64,
}

#[derive(Debug, Clone)]
struct MachOTextRelocationReplay {
    relocation_index: Option<usize>,
    input_file: SharedText,
    input: String,
    section_index: u32,
    previous_output_offset: Option<u64>,
    previous_range: Option<std::ops::Range<usize>>,
    current_range: std::ops::Range<usize>,
    r_type: u8,
    kind: u32,
    rel_info: RelocationKindInfo,
    previous_written_value: Option<u64>,
    previous_applied_target_value: Option<u64>,
    current_target_value: u64,
    current_relocation_target_candidates: Vec<u64>,
    current_target_section_offset: u64,
    target_symbol_id: u32,
    target_name: Option<SharedText>,
    target_is_global: bool,
    target: Option<RelocationTargetRecord>,
    addend: i64,
    chained_rebase_output_offset: Option<u64>,
    chained_rebase_value: Option<u64>,
}

struct MachOTextRelocationReplays {
    replays: Vec<MachOTextRelocationReplay>,
    rematerialized_sections: Vec<(SharedText, String, u32, String, u32)>,
    normalize_rust_archive_patch_inputs: bool,
    symbol_resolutions_changed: bool,
}

impl MachOTextRelocationReplays {
    fn uses_only_records_owned_by_input(
        &self,
        relocations: &[RelocationRecord],
        input_file: &str,
    ) -> bool {
        self.rematerialized_sections
            .iter()
            .all(|(previous_input_file, _, _, _, _)| previous_input_file.as_str() == input_file)
            && self.replays.iter().all(|replay| {
                replay.input_file.as_str() == input_file
                    && replay.relocation_index.is_none_or(|index| {
                        relocations
                            .get(index)
                            .is_some_and(|relocation| relocation.input_file.as_str() == input_file)
                    })
            })
    }
}

fn macho_aarch64_text_relocation_contexts<'data>(
    file: &object::File<'data>,
    section: &impl object::ObjectSection<'data>,
    section_data: &[u8],
) -> Option<Vec<MachOTextRelocationContext>> {
    if file.architecture() != object::Architecture::Aarch64
        || !matches!(section.flags(), object::SectionFlags::MachO { .. })
        || section.name().ok() != Some("__text")
    {
        return None;
    }

    let mut contexts = Vec::new();
    for (offset, relocation) in section.relocations() {
        if relocation.kind() == object::RelocationKind::None {
            continue;
        }
        let object::RelocationFlags::MachO {
            r_type,
            r_pcrel,
            r_length: 2,
        } = relocation.flags()
        else {
            return None;
        };
        if !matches!(
            r_type,
            object::macho::ARM64_RELOC_BRANCH26
                | object::macho::ARM64_RELOC_PAGE21
                | object::macho::ARM64_RELOC_PAGEOFF12
        ) {
            return None;
        }
        let start = usize::try_from(offset).ok()?;
        if start % 4 != 0 {
            return None;
        }
        let end = start.checked_add(4)?;
        if end > section_data.len() {
            return None;
        }
        let bytes = section_data.get(start..end)?.try_into().ok()?;
        contexts.push(MachOTextRelocationContext {
            range: start..end,
            r_type,
            r_pcrel,
            target: relocation.target(),
            subtractor: relocation.subtractor(),
            addend: relocation.addend(),
            bytes,
        });
    }
    contexts.sort_by_key(|context| context.range.start);
    let mut previous_end = 0;
    for context in &contexts {
        if context.range.start < previous_end {
            return None;
        }
        previous_end = context.range.end;
    }
    Some(contexts)
}

fn macho_aarch64_data_relocation_contexts<'data>(
    file: &object::File<'data>,
    section: &impl object::ObjectSection<'data>,
    section_data: &[u8],
) -> Option<Vec<MachODataRelocationContext>> {
    if file.architecture() != object::Architecture::Aarch64
        || !matches!(section.flags(), object::SectionFlags::MachO { .. })
        || section.name().ok() != Some("__const")
        || section.segment_name().ok().flatten() != Some("__DATA")
    {
        return None;
    }

    let mut contexts = Vec::new();
    for (offset, relocation) in section.relocations() {
        if relocation.kind() == object::RelocationKind::None {
            continue;
        }
        let object::RelocationFlags::MachO {
            r_type: object::macho::ARM64_RELOC_UNSIGNED,
            r_pcrel: false,
            r_length: 3,
        } = relocation.flags()
        else {
            return None;
        };
        if relocation.subtractor().is_some() {
            return None;
        }
        let start = usize::try_from(offset).ok()?;
        if start % 8 != 0 {
            return None;
        }
        let end = start.checked_add(8)?;
        let bytes: [u8; 8] = section_data.get(start..end)?.try_into().ok()?;
        contexts.push(MachODataRelocationContext {
            range: start..end,
            target: relocation.target(),
            addend: i64::from_le_bytes(bytes).wrapping_add(relocation.addend()),
        });
    }
    contexts.sort_by_key(|context| context.range.start);
    let mut previous_end = 0;
    for context in &contexts {
        if context.range.start < previous_end {
            return None;
        }
        previous_end = context.range.end;
    }
    Some(contexts)
}

fn macho_aarch64_text_relocation_ranges<'data>(
    file: &object::File<'data>,
    section: &impl object::ObjectSection<'data>,
    section_data: &[u8],
) -> Option<Vec<std::ops::Range<usize>>> {
    Some(
        macho_aarch64_text_relocation_contexts(file, section, section_data)?
            .into_iter()
            .map(|context| context.range)
            .collect(),
    )
}

fn macho_aarch64_data_relocation_ranges<'data>(
    file: &object::File<'data>,
    section: &impl object::ObjectSection<'data>,
    section_data: &[u8],
    required_relocation_offsets: Option<&HashSet<u64>>,
) -> Option<Vec<std::ops::Range<usize>>> {
    let contexts = macho_aarch64_data_relocation_contexts(file, section, section_data)?;
    let required = required_relocation_offsets?;
    if contexts.len() != required.len()
        || contexts
            .iter()
            .any(|context| !required.contains(&(context.range.start as u64)))
    {
        return None;
    }
    Some(contexts.into_iter().map(|context| context.range).collect())
}

fn macho_relocation_target_identity(
    file: &object::File<'_>,
    target: object::RelocationTarget,
) -> Result<Option<(Vec<u8>, Option<object::SectionIndex>)>> {
    match target {
        object::RelocationTarget::Symbol(symbol_index) => {
            let symbol = file.symbol_by_index(symbol_index)?;
            let name = symbol.name_bytes()?.to_vec();
            Ok(Some((name, symbol.section_index())))
        }
        object::RelocationTarget::Section(section_index) => {
            Ok(Some((Vec::new(), Some(section_index))))
        }
        object::RelocationTarget::Absolute => Ok(Some((Vec::new(), None))),
        _ => Ok(None),
    }
}

fn macho_relocation_target_is_global(
    file: &object::File<'_>,
    target: object::RelocationTarget,
) -> bool {
    let object::RelocationTarget::Symbol(symbol_index) = target else {
        return false;
    };
    file.symbol_by_index(symbol_index)
        .is_ok_and(|symbol| symbol.is_global())
}

struct MachORelocationSymbolPosition {
    name: Vec<u8>,
    symbol_index: object::SymbolIndex,
    section_index: object::SectionIndex,
    section_offset: u64,
}

fn macho_relocation_symbol_position(
    file: &object::File<'_>,
    target: object::RelocationTarget,
) -> Result<Option<MachORelocationSymbolPosition>> {
    let object::RelocationTarget::Symbol(symbol_index) = target else {
        return Ok(None);
    };
    let symbol = file.symbol_by_index(symbol_index)?;
    let Some(section_index) = symbol.section_index() else {
        return Ok(None);
    };
    let section = file.section_by_index(section_index)?;
    let section_offset = symbol
        .address()
        .checked_sub(section.address())
        .context("Mach-O relocation target precedes its section")?;
    Ok(Some(MachORelocationSymbolPosition {
        name: symbol.name_bytes()?.to_vec(),
        symbol_index,
        section_index,
        section_offset,
    }))
}

struct MachODataRelocationTargetPosition {
    section_index: object::SectionIndex,
    section_offset: u64,
}

#[derive(Clone, Copy, Eq, Hash, PartialEq)]
enum MachORelocationTargetCacheKey {
    Symbol(usize),
    Section(usize),
    Absolute,
}

fn macho_relocation_target_cache_key(
    target: object::RelocationTarget,
) -> Option<MachORelocationTargetCacheKey> {
    match target {
        object::RelocationTarget::Symbol(index) => {
            Some(MachORelocationTargetCacheKey::Symbol(index.0))
        }
        object::RelocationTarget::Section(index) => {
            Some(MachORelocationTargetCacheKey::Section(index.0))
        }
        object::RelocationTarget::Absolute => Some(MachORelocationTargetCacheKey::Absolute),
        _ => None,
    }
}

#[derive(Eq, Hash, PartialEq)]
struct MachODataRelocationTargetStabilityKey {
    previous_relocation_target: MachORelocationTargetCacheKey,
    current_relocation_target: MachORelocationTargetCacheKey,
    previous_section_index: usize,
    previous_section_offset: u64,
    current_section_index: usize,
    current_section_offset: u64,
}

#[derive(PartialEq)]
struct MachORelocationSymbolIdentity {
    name: Vec<u8>,
    section: Option<(usize, u64)>,
    kind: object::SymbolKind,
    scope: object::SymbolScope,
    weak: bool,
}

fn macho_relocation_symbol_identity(
    file: &object::File<'_>,
    symbol_index: object::SymbolIndex,
) -> Result<MachORelocationSymbolIdentity> {
    let symbol = file.symbol_by_index(symbol_index)?;
    let section = symbol
        .section_index()
        .map(|section_index| -> Result<(usize, u64)> {
            let section = file.section_by_index(section_index)?;
            let offset = symbol
                .address()
                .checked_sub(section.address())
                .context("Mach-O relocation symbol precedes its section")?;
            Ok((section_index.0, offset))
        })
        .transpose()?;
    Ok(MachORelocationSymbolIdentity {
        name: symbol.name_bytes()?.to_vec(),
        section,
        kind: symbol.kind(),
        scope: symbol.scope(),
        weak: symbol.is_weak(),
    })
}

fn macho_relocation_targets_are_stable(
    previous_file: &object::File<'_>,
    previous_target: object::RelocationTarget,
    current_file: &object::File<'_>,
    current_target: object::RelocationTarget,
) -> Result<bool> {
    match (previous_target, current_target) {
        (object::RelocationTarget::Symbol(previous), object::RelocationTarget::Symbol(current)) => {
            Ok(macho_relocation_symbol_identity(previous_file, previous)?
                == macho_relocation_symbol_identity(current_file, current)?)
        }
        (
            object::RelocationTarget::Section(previous),
            object::RelocationTarget::Section(current),
        ) => Ok(previous == current),
        (object::RelocationTarget::Absolute, object::RelocationTarget::Absolute) => Ok(true),
        _ => Ok(false),
    }
}

fn macho_section_relocations_in_range_are_stable<'previous, 'current>(
    previous_file: &object::File<'_>,
    previous_section: &impl object::ObjectSection<'previous>,
    current_file: &object::File<'_>,
    current_section: &impl object::ObjectSection<'current>,
    range: std::ops::Range<u64>,
) -> Result<bool> {
    let previous_relocations = previous_section
        .relocations()
        .filter(|(offset, _)| range.contains(offset))
        .collect::<Vec<_>>();
    let current_relocations = current_section
        .relocations()
        .filter(|(offset, _)| range.contains(offset))
        .collect::<Vec<_>>();
    if previous_relocations.len() != current_relocations.len() {
        return Ok(false);
    }
    for ((previous_offset, previous), (current_offset, current)) in
        previous_relocations.iter().zip(&current_relocations)
    {
        if previous_offset != current_offset
            || previous.kind() != current.kind()
            || previous.encoding() != current.encoding()
            || previous.size() != current.size()
            || previous.addend() != current.addend()
            || previous.has_implicit_addend() != current.has_implicit_addend()
            || previous.flags() != current.flags()
            || !macho_relocation_targets_are_stable(
                previous_file,
                previous.target(),
                current_file,
                current.target(),
            )?
        {
            return Ok(false);
        }
        match (previous.subtractor(), current.subtractor()) {
            (Some(previous), Some(current))
                if macho_relocation_symbol_identity(previous_file, previous)?
                    == macho_relocation_symbol_identity(current_file, current)? => {}
            (None, None) => {}
            _ => return Ok(false),
        }
    }
    Ok(true)
}

fn macho_section_symbol_range_end<'data>(
    file: &object::File<'data>,
    section: &impl object::ObjectSection<'data>,
    start: u64,
) -> Result<u64> {
    let mut end = section.size();
    for symbol in file
        .symbols()
        .filter(|symbol| symbol.section_index() == Some(section.index()))
    {
        let offset = symbol
            .address()
            .checked_sub(section.address())
            .context("Mach-O relocation symbol precedes its section")?;
        if offset > start {
            end = end.min(offset);
        }
    }
    Ok(end)
}

fn macho_relocation_symbol_range_is_stable<'previous, 'current>(
    previous_file: &object::File<'previous>,
    previous_section: &impl object::ObjectSection<'previous>,
    previous_target: object::RelocationTarget,
    current_file: &object::File<'current>,
    current_section: &impl object::ObjectSection<'current>,
    current_target: object::RelocationTarget,
) -> Result<bool> {
    let (
        object::RelocationTarget::Symbol(previous_symbol_index),
        object::RelocationTarget::Symbol(current_symbol_index),
    ) = (previous_target, current_target)
    else {
        return Ok(false);
    };
    let previous_identity = macho_relocation_symbol_identity(previous_file, previous_symbol_index)?;
    let current_identity = macho_relocation_symbol_identity(current_file, current_symbol_index)?;
    if previous_identity != current_identity {
        return Ok(false);
    }
    let Some((previous_section_index, start)) = previous_identity.section else {
        return Ok(false);
    };
    let Some((current_section_index, current_start)) = current_identity.section else {
        return Ok(false);
    };
    if previous_section_index != previous_section.index().0
        || current_section_index != current_section.index().0
        || start != current_start
    {
        return Ok(false);
    }
    let previous_end = macho_section_symbol_range_end(previous_file, previous_section, start)?;
    let current_end = macho_section_symbol_range_end(current_file, current_section, start)?;
    if previous_end != current_end || previous_end <= start {
        return Ok(false);
    }
    let start = usize::try_from(start).context("Mach-O relocation symbol offset is too large")?;
    let end = usize::try_from(previous_end).context("Mach-O relocation symbol end is too large")?;
    if previous_section.data()?.get(start..end) != current_section.data()?.get(start..end) {
        return Ok(false);
    }
    macho_section_relocations_in_range_are_stable(
        previous_file,
        previous_section,
        current_file,
        current_section,
        start as u64..previous_end,
    )
}

fn unmatched_macho_data_relocation_target_is_stable(
    previous_file: &object::File<'_>,
    current_file: &object::File<'_>,
    previous_relocation_target: object::RelocationTarget,
    current_relocation_target: object::RelocationTarget,
    previous_target: &MachODataRelocationTargetPosition,
    current_target: &MachODataRelocationTargetPosition,
) -> Result<bool> {
    if previous_target.section_index != current_target.section_index
        || previous_target.section_offset != current_target.section_offset
    {
        return Ok(false);
    }
    let previous_section = previous_file.section_by_index(previous_target.section_index)?;
    let current_section = current_file.section_by_index(current_target.section_index)?;
    if previous_section.name()? != current_section.name()?
        || previous_section.segment_name()? != current_section.segment_name()?
        || previous_section.kind() != current_section.kind()
        || previous_section.flags() != current_section.flags()
        || previous_section.align() != current_section.align()
        || previous_section.size() != current_section.size()
    {
        return Ok(false);
    }
    if previous_section.data()? == current_section.data()?
        && macho_section_relocations_in_range_are_stable(
            previous_file,
            &previous_section,
            current_file,
            &current_section,
            0..previous_section.size(),
        )?
    {
        return Ok(true);
    }
    macho_relocation_symbol_range_is_stable(
        previous_file,
        &previous_section,
        previous_relocation_target,
        current_file,
        &current_section,
        current_relocation_target,
    )
}

fn macho_data_relocation_target_position(
    file: &object::File<'_>,
    target: object::RelocationTarget,
) -> Result<Option<MachODataRelocationTargetPosition>> {
    match target {
        object::RelocationTarget::Symbol(symbol_index) => {
            let symbol = file.symbol_by_index(symbol_index)?;
            let Some(section_index) = symbol.section_index() else {
                return Ok(None);
            };
            let section = file.section_by_index(section_index)?;
            let section_offset = symbol
                .address()
                .checked_sub(section.address())
                .context("Mach-O data relocation target precedes its section")?;
            Ok(Some(MachODataRelocationTargetPosition {
                section_index,
                section_offset,
            }))
        }
        object::RelocationTarget::Section(section_index) => {
            Ok(Some(MachODataRelocationTargetPosition {
                section_index,
                section_offset: 0,
            }))
        }
        _ => Ok(None),
    }
}

fn macho_relocation_instruction_shape(
    rel_info: RelocationKindInfo,
    bytes: &[u8; 4],
) -> Option<[u8; 4]> {
    let mut shape = *bytes;
    rel_info.write_to_buffer(0, &mut shape).ok()?;
    Some(shape)
}

type MachOTextRelocationSignature = (u8, bool, i64, Option<(Vec<u8>, Option<usize>)>);

fn macho_text_relocation_signature(
    file: &object::File<'_>,
    context: &MachOTextRelocationContext,
) -> Result<MachOTextRelocationSignature> {
    Ok((
        context.r_type,
        context.r_pcrel,
        context.addend,
        macho_relocation_target_identity(file, context.target)?
            .map(|(name, section)| (name, section.map(|section| section.0))),
    ))
}

fn missing_macho_replacement_resolution<'a>(
    previous_signatures: &[MachOTextRelocationSignature],
    current_signatures: &'a [MachOTextRelocationSignature],
    resolutions: &[MachOSymbolResolutionRecord],
    resolution_lookup: &MachOSymbolResolutionLookup<'_>,
    retained_output_resolutions: &[MachOSymbolResolutionRecord],
) -> Option<&'a [u8]> {
    previous_signatures
        .iter()
        .zip(current_signatures)
        .filter(|(previous, current)| previous != current)
        .filter_map(|(_, current)| {
            current
                .3
                .as_ref()
                .map(|(current_name, _)| current_name.as_slice())
        })
        .find(|current_name| {
            resolution_lookup
                .get_name(resolutions, current_name)
                .or_else(|| {
                    macho_symbol_resolution_for_name(retained_output_resolutions, current_name)
                })
                .is_none()
        })
}

struct MachOOutputTextDefinitionLookup {
    addresses_by_name: HashMap<Vec<u8>, Option<u64>>,
}

impl MachOOutputTextDefinitionLookup {
    fn new(output_file: &object::File<'_>) -> Option<Self> {
        let text_sections = output_file
            .sections()
            .filter(|section| {
                section.segment_name_bytes().ok().flatten() == Some(b"__TEXT".as_slice())
                    && section.name_bytes().ok() == Some(b"__text".as_slice())
            })
            .map(|section| section.index())
            .collect::<HashSet<_>>();
        let mut addresses_by_name = HashMap::new();
        for symbol in output_file.symbols() {
            if symbol.is_undefined() || !symbol.is_global() || symbol.is_weak() {
                continue;
            }
            let name = symbol.name_bytes().ok()?.to_vec();
            let address = symbol
                .section_index()
                .filter(|index| text_sections.contains(index))
                .map(|_| symbol.address());
            match addresses_by_name.entry(name) {
                hashbrown::hash_map::Entry::Vacant(entry) => {
                    entry.insert(address);
                }
                hashbrown::hash_map::Entry::Occupied(mut entry) => {
                    *entry.get_mut() = None;
                }
            }
        }
        Some(Self { addresses_by_name })
    }

    fn resolution(&self, name: &[u8]) -> Option<MachOSymbolResolutionRecord> {
        let direct_value = self.addresses_by_name.get(name).copied().flatten()?;
        Some(MachOSymbolResolutionRecord {
            name: hex::encode(name).into(),
            direct_value: Some(direct_value),
            got_address: None,
            stub_address: None,
            thunk_addresses: Vec::new(),
            target: None,
        })
    }
}

fn changed_input_macho_definitions(paths: &[PathBuf]) -> Result<Option<HashSet<Vec<u8>>>> {
    let mut definitions = HashSet::new();
    for path in paths {
        let Some((bytes, _)) = read_file_with_stable_identity(path)? else {
            return Ok(None);
        };
        if let Ok(archive) = object::read::archive::ArchiveFile::parse(bytes.as_slice()) {
            let Some(symbols) = archive.symbols()? else {
                return Ok(None);
            };
            for symbol in symbols {
                definitions.insert(symbol?.name().to_vec());
            }
            continue;
        }
        let Ok(file) = object::File::parse(bytes.as_slice()) else {
            return Ok(None);
        };
        definitions.extend(
            file.symbols()
                .filter(|symbol| !symbol.is_undefined() && symbol.is_global() && !symbol.is_weak())
                .map(|symbol| symbol.name_bytes().map(Vec::from))
                .collect::<Result<Vec<_>, _>>()?,
        );
    }
    Ok(Some(definitions))
}

struct MatchedCurrentSectionLookup<'a> {
    output_offsets: HashMap<(&'a str, u32), Option<u64>>,
}

impl<'a> MatchedCurrentSectionLookup<'a> {
    fn new(matched_sections: &'a [MatchedPatchSection]) -> Self {
        let mut output_offsets = HashMap::new();
        for section in matched_sections {
            let key = (
                section.current.input.as_str(),
                section.current.section_index,
            );
            match output_offsets.entry(key) {
                hashbrown::hash_map::Entry::Vacant(entry) => {
                    entry.insert(Some(section.current.output_offset));
                }
                hashbrown::hash_map::Entry::Occupied(mut entry) => {
                    *entry.get_mut() = None;
                }
            }
        }
        Self { output_offsets }
    }

    fn output_offset(&self, input: &str, section_index: u32) -> Option<u64> {
        self.output_offsets
            .get(&(input, section_index))
            .copied()
            .flatten()
    }
}

fn macho_output_address_for_current_section_offset(
    output_file: &object::File<'_>,
    matched_sections: &[MatchedPatchSection],
    current_file: &object::File<'_>,
    input: &str,
    section_index: object::SectionIndex,
    section_offset: u64,
) -> Option<u64> {
    macho_output_address_for_current_section_offset_with_lookup(
        output_file,
        &MatchedCurrentSectionLookup::new(matched_sections),
        current_file,
        input,
        section_index,
        section_offset,
    )
}

fn macho_output_address_for_current_section_offset_with_lookup(
    output_file: &object::File<'_>,
    matched_sections: &MatchedCurrentSectionLookup<'_>,
    current_file: &object::File<'_>,
    input: &str,
    section_index: object::SectionIndex,
    section_offset: u64,
) -> Option<u64> {
    let section_index = patch_section_record_index(current_file, section_index).ok()?;
    let file_offset = matched_sections
        .output_offset(input, section_index)?
        .checked_add(section_offset)?;
    macho_output_address_for_file_offset(output_file, file_offset)
}

fn unique_macho_target_value(values: impl IntoIterator<Item = u64>) -> Option<u64> {
    let mut values = values.into_iter();
    let value = values.next()?;
    values.all(|candidate| candidate == value).then_some(value)
}

#[cfg(test)]
fn macho_output_address_for_current_target(
    output_file: &object::File<'_>,
    current_file: &object::File<'_>,
    matched_sections: &[MatchedPatchSection],
    relocations: &[RelocationRecord],
    resolutions: &[MachOSymbolResolutionRecord],
    target: &RelocationTargetRecord,
    previous_target: &RelocationTargetRecord,
) -> Option<u64> {
    macho_output_address_for_current_target_with_lookup(
        output_file,
        current_file,
        &MatchedCurrentSectionLookup::new(matched_sections),
        relocations,
        resolutions,
        target,
        previous_target,
    )
}

fn macho_output_address_for_current_target_with_lookup(
    output_file: &object::File<'_>,
    current_file: &object::File<'_>,
    matched_sections: &MatchedCurrentSectionLookup<'_>,
    relocations: &[RelocationRecord],
    resolutions: &[MachOSymbolResolutionRecord],
    target: &RelocationTargetRecord,
    previous_target: &RelocationTargetRecord,
) -> Option<u64> {
    if let Some(value) = macho_output_address_for_current_section_offset_with_lookup(
        output_file,
        matched_sections,
        current_file,
        target.input.as_str(),
        object::SectionIndex(target.section_index as usize),
        target.section_offset,
    ) {
        return Some(value);
    }
    unique_macho_target_value(
        relocations
            .iter()
            .filter(|relocation| {
                relocation.target.as_ref() == Some(target)
                    || relocation.target.as_ref() == Some(previous_target)
            })
            .map(|relocation| relocation.target_value)
            .chain(
                resolutions
                    .iter()
                    .filter(|resolution| {
                        resolution.target.as_ref() == Some(target)
                            || resolution.target.as_ref() == Some(previous_target)
                    })
                    .filter_map(|resolution| resolution.direct_value),
            ),
    )
}

fn macho_symbol_resolution_for_name<'a>(
    resolutions: &'a [MachOSymbolResolutionRecord],
    name: &[u8],
) -> Option<&'a MachOSymbolResolutionRecord> {
    let encoded = hex::encode(name);
    let mut matches = resolutions
        .iter()
        .filter(|resolution| resolution.name.as_str() == encoded);
    let resolution = matches.next()?;
    matches.next().is_none().then_some(resolution)
}

struct MachOSymbolResolutionLookup<'a> {
    indices_by_name: HashMap<&'a str, Option<usize>>,
}

impl<'a> MachOSymbolResolutionLookup<'a> {
    fn new(resolutions: &'a [MachOSymbolResolutionRecord]) -> Self {
        let mut indices_by_name = HashMap::with_capacity(resolutions.len());
        for (index, resolution) in resolutions.iter().enumerate() {
            match indices_by_name.entry(resolution.name.as_str()) {
                hashbrown::hash_map::Entry::Vacant(entry) => {
                    entry.insert(Some(index));
                }
                hashbrown::hash_map::Entry::Occupied(mut entry) => {
                    *entry.get_mut() = None;
                }
            }
        }
        Self { indices_by_name }
    }

    fn get_encoded<'b>(
        &self,
        resolutions: &'b [MachOSymbolResolutionRecord],
        encoded_name: &str,
    ) -> Option<&'b MachOSymbolResolutionRecord> {
        self.indices_by_name
            .get(encoded_name)
            .copied()
            .flatten()
            .and_then(|index| resolutions.get(index))
    }

    fn unique_index_encoded(
        &self,
        encoded_name: &str,
    ) -> std::result::Result<Option<usize>, String> {
        match self.indices_by_name.get(encoded_name).copied() {
            Some(Some(index)) => Ok(Some(index)),
            Some(None) => Err("ambiguous Mach-O symbol resolution catalog entry".to_owned()),
            None => Ok(None),
        }
    }

    fn get_name<'b>(
        &self,
        resolutions: &'b [MachOSymbolResolutionRecord],
        name: &[u8],
    ) -> Option<&'b MachOSymbolResolutionRecord> {
        let encoded_name = hex::encode(name);
        self.get_encoded(resolutions, &encoded_name)
    }
}

fn macho_symbol_resolution_index_for_name(
    resolutions: &[MachOSymbolResolutionRecord],
    encoded_name: &str,
) -> std::result::Result<Option<usize>, String> {
    let mut matches = resolutions
        .iter()
        .enumerate()
        .filter_map(|(index, resolution)| (resolution.name == encoded_name).then_some(index));
    let index = matches.next();
    if matches.next().is_some() {
        return Err("ambiguous Mach-O symbol resolution catalog entry".to_owned());
    }
    Ok(index)
}

fn macho_text_relocation_target_candidates(
    resolutions: &[MachOSymbolResolutionRecord],
    resolution_lookup: &MachOSymbolResolutionLookup<'_>,
    target_name: Option<&str>,
    r_type: u8,
    target_value: u64,
    previous_applied_target_values: &[u64],
) -> Vec<u64> {
    let resolution = target_name.and_then(|name| resolution_lookup.get_encoded(resolutions, name));
    macho_text_relocation_target_candidates_for_resolution(
        resolution,
        r_type,
        target_value,
        previous_applied_target_values,
    )
}

fn macho_text_relocation_target_candidates_for_resolution(
    resolution: Option<&MachOSymbolResolutionRecord>,
    r_type: u8,
    target_value: u64,
    previous_applied_target_values: &[u64],
) -> Vec<u64> {
    let mut candidates = if r_type == object::macho::ARM64_RELOC_BRANCH26 {
        previous_applied_target_values.to_vec()
    } else {
        Vec::new()
    };
    candidates.push(if r_type == object::macho::ARM64_RELOC_BRANCH26 {
        resolution
            .and_then(|resolution| resolution.stub_address)
            .unwrap_or(target_value)
    } else {
        target_value
    });
    if r_type == object::macho::ARM64_RELOC_BRANCH26
        && let Some(resolution) = resolution
    {
        candidates.extend_from_slice(&resolution.thunk_addresses);
    }
    let mut seen = HashSet::new();
    candidates.retain(|candidate| seen.insert(*candidate));
    candidates
}

fn recorded_macho_branch_target_candidate(
    relocation: &RelocationRecord,
    target_name: Option<&SharedText>,
    target_is_global: bool,
    target: Option<&RelocationTargetRecord>,
    target_value: u64,
    addend: i64,
    previous_output: &[u8],
    output_file: &object::File<'_>,
) -> Option<u64> {
    let raw_relocation = decode_macho_aarch64_relocation_kind(relocation.kind)?;
    if raw_relocation.r_type != object::macho::ARM64_RELOC_BRANCH26
        || relocation.addend != addend
        || relocation.target_value != target_value
        || if target_is_global {
            target_name.is_none() || relocation.target_name.as_ref() != target_name
        } else {
            target.is_none() || relocation.target.as_ref() != target
        }
    {
        return None;
    }
    let applied_target_value = relocation.applied_target_value?;
    let written_value = relocation.written_value?;
    let start = usize::try_from(relocation.output_offset).ok()?;
    let size = usize::try_from(relocation.size).ok()?;
    let end = start.checked_add(size)?;
    let previous_bytes = previous_output.get(start..end)?;
    let rel_info =
        <crate::macho_aarch64::MachOAArch64 as crate::platform::Arch>::relocation_from_raw(
            raw_relocation,
        )
        .ok()?;
    let mut replayed_previous = previous_bytes.to_vec();
    rel_info
        .write_to_buffer(written_value, &mut replayed_previous)
        .ok()?;
    if replayed_previous != previous_bytes {
        return None;
    }
    let previous_place =
        macho_output_address_for_file_offset(output_file, relocation.output_offset)?;
    (macho_aarch64_relocated_value(
        raw_relocation.r_type,
        applied_target_value,
        macho_aarch64_applied_target_addend(
            raw_relocation.r_type,
            relocation.target_value,
            applied_target_value,
            relocation.addend,
        ),
        previous_place,
    ) == Some(written_value))
    .then_some(applied_target_value)
}

struct RecordedMachOBranchTargetCandidates<'a> {
    relocations: &'a [RelocationRecord],
    branch_indices_by_name: HashMap<&'a str, Vec<usize>>,
    indices_by_target: HashMap<&'a RelocationTargetRecord, Vec<usize>>,
}

impl<'a> RecordedMachOBranchTargetCandidates<'a> {
    fn new(relocations: &'a [RelocationRecord]) -> Self {
        let mut branch_indices_by_name = HashMap::<&str, Vec<usize>>::new();
        let mut indices_by_target = HashMap::<&RelocationTargetRecord, Vec<usize>>::new();
        for (index, relocation) in relocations.iter().enumerate() {
            if let Some(target) = relocation.target.as_ref() {
                indices_by_target.entry(target).or_default().push(index);
            }
            let Some(raw_relocation) = decode_macho_aarch64_relocation_kind(relocation.kind) else {
                continue;
            };
            if raw_relocation.r_type != object::macho::ARM64_RELOC_BRANCH26 {
                continue;
            }
            if let Some(target_name) = relocation.target_name.as_deref() {
                branch_indices_by_name
                    .entry(target_name)
                    .or_default()
                    .push(index);
            }
        }
        Self {
            relocations,
            branch_indices_by_name,
            indices_by_target,
        }
    }

    fn branch_targets(
        &self,
        target_name: Option<&SharedText>,
        target_is_global: bool,
        target: Option<&RelocationTargetRecord>,
        target_value: u64,
        addend: i64,
        previous_output: &[u8],
        output_file: &object::File<'_>,
    ) -> Vec<u64> {
        if target_is_global {
            let Some(indices) =
                target_name.and_then(|name| self.branch_indices_by_name.get(name.as_str()))
            else {
                return Vec::new();
            };
            indices
                .iter()
                .filter_map(|index| {
                    recorded_macho_branch_target_candidate(
                        &self.relocations[*index],
                        target_name,
                        true,
                        target,
                        target_value,
                        addend,
                        previous_output,
                        output_file,
                    )
                })
                .collect()
        } else {
            target
                .and_then(|target| self.indices_by_target.get(target))
                .into_iter()
                .flatten()
                .filter_map(|index| {
                    recorded_macho_branch_target_candidate(
                        &self.relocations[*index],
                        target_name,
                        false,
                        target,
                        target_value,
                        addend,
                        previous_output,
                        output_file,
                    )
                })
                .collect()
        }
    }

    fn import_stubs(
        &self,
        target_name: &SharedText,
        addend: i64,
        previous_output: &[u8],
        output_file: &object::File<'_>,
    ) -> Vec<u64> {
        self.branch_indices_by_name
            .get(target_name.as_str())
            .into_iter()
            .flatten()
            .filter_map(|index| {
                let relocation = &self.relocations[*index];
                (relocation.target.is_none())
                    .then(|| {
                        recorded_macho_branch_target_candidate(
                            relocation,
                            Some(target_name),
                            true,
                            None,
                            0,
                            addend,
                            previous_output,
                            output_file,
                        )
                    })
                    .flatten()
            })
            .filter(|candidate| *candidate != 0)
            .collect()
    }

    fn target_symbol_id(
        &self,
        target_name: Option<&SharedText>,
        target: Option<&RelocationTargetRecord>,
    ) -> u32 {
        if let Some(indices) =
            target_name.and_then(|name| self.branch_indices_by_name.get(name.as_str()))
            && let Some(relocation) = indices
                .iter()
                .map(|index| &self.relocations[*index])
                .find(|relocation| target.is_none() || relocation.target.as_ref() == target)
        {
            return relocation.target_symbol_id;
        }
        if let Some(indices) = target.and_then(|target| self.indices_by_target.get(target))
            && let Some(relocation) = indices
                .iter()
                .map(|index| &self.relocations[*index])
                .find(|relocation| relocation.target_name.as_ref() == target_name)
        {
            return relocation.target_symbol_id;
        }
        self.relocations
            .iter()
            .find(|relocation| {
                relocation.target_name.as_ref() == target_name
                    && (target.is_none() || relocation.target.as_ref() == target)
            })
            .map_or(0, |relocation| relocation.target_symbol_id)
    }

    #[cfg(test)]
    fn indexed_relocation_count(&self) -> usize {
        self.branch_indices_by_name.values().map(Vec::len).sum()
    }
}

#[cfg(test)]
fn recorded_macho_branch_target_candidates(
    relocations: &[RelocationRecord],
    target_name: Option<&SharedText>,
    target_is_global: bool,
    target: Option<&RelocationTargetRecord>,
    target_value: u64,
    addend: i64,
    previous_output: &[u8],
    output_file: &object::File<'_>,
) -> Vec<u64> {
    RecordedMachOBranchTargetCandidates::new(relocations).branch_targets(
        target_name,
        target_is_global,
        target,
        target_value,
        addend,
        previous_output,
        output_file,
    )
}

fn recorded_macho_import_stub_candidates(
    relocations: &[RelocationRecord],
    target_name: &SharedText,
    addend: i64,
    previous_output: &[u8],
    output_file: &object::File<'_>,
) -> Vec<u64> {
    RecordedMachOBranchTargetCandidates::new(relocations).import_stubs(
        target_name,
        addend,
        previous_output,
        output_file,
    )
}

fn macho_aarch64_applied_target_addend(
    r_type: u8,
    target_value: u64,
    applied_target_value: u64,
    addend: i64,
) -> i64 {
    if r_type == object::macho::ARM64_RELOC_BRANCH26 && applied_target_value != target_value {
        0
    } else {
        addend
    }
}

fn rematerialized_macho_text_relocation_replay(
    relocations: &[RelocationRecord],
    resolutions: &[MachOSymbolResolutionRecord],
    resolution_lookup: &MachOSymbolResolutionLookup<'_>,
    retained_output_resolutions: &[MachOSymbolResolutionRecord],
    recorded_branch_targets: &RecordedMachOBranchTargetCandidates<'_>,
    input: &FileState,
    patch_section: &MatchedPatchSection,
    current_file: &object::File<'_>,
    current_context: &MachOTextRelocationContext,
    matched_sections: &MatchedCurrentSectionLookup<'_>,
    previous_output: &[u8],
    output_file: &object::File<'_>,
) -> Result<std::result::Result<MachOTextRelocationReplay, String>> {
    if current_context.subtractor.is_some() {
        return Ok(Err(format!(
            "unsupported current Mach-O text relocation in {}",
            display_hex_path(&input.path)
        )));
    }
    let raw_relocation = object::macho::RelocationInfo {
        r_address: 0,
        r_symbolnum: 0,
        r_pcrel: current_context.r_pcrel,
        r_length: 2,
        r_extern: matches!(current_context.target, object::RelocationTarget::Symbol(_)),
        r_type: current_context.r_type,
    };
    let rel_info =
        <crate::macho_aarch64::MachOAArch64 as crate::platform::Arch>::relocation_from_raw(
            raw_relocation,
        )
        .map_err(|error| {
            crate::error!("Failed to decode current Mach-O text relocation: {error:#?}")
        })?;

    let mut target_name = None;
    let mut target_is_global = false;
    let target;
    let mut resolution = None;
    let mut recorded_import_stub_candidates = Vec::new();
    let current_target_value = match current_context.target {
        object::RelocationTarget::Symbol(symbol_index) => {
            let symbol = current_file
                .symbol_by_index(symbol_index)
                .context("Missing current Mach-O text relocation symbol")?;
            let name = symbol.name_bytes()?.to_vec();
            if !name.is_empty() {
                target_name = Some(SharedText::from(hex::encode(&name)));
                target_is_global = symbol.is_global();
                resolution = resolution_lookup.get_name(resolutions, &name).or_else(|| {
                    macho_symbol_resolution_for_name(retained_output_resolutions, &name)
                });
            }
            if let Some(section_index) = symbol.section_index() {
                let section = current_file.section_by_index(section_index)?;
                let section_offset = symbol
                    .address()
                    .checked_sub(section.address())
                    .context("Mach-O relocation target precedes its section")?;
                let current_target = RelocationTargetRecord {
                    input_file: input.path.clone().into(),
                    input: patch_section.current.input.clone().into(),
                    section_index: section_index.0 as u32,
                    section_offset,
                };
                let previous_target = RelocationTargetRecord {
                    input_file: current_target.input_file.clone(),
                    input: patch_section.previous.input.clone().into(),
                    section_index: current_target.section_index,
                    section_offset,
                };
                let Some(value) = macho_output_address_for_current_target_with_lookup(
                    output_file,
                    current_file,
                    matched_sections,
                    relocations,
                    resolutions,
                    &current_target,
                    &previous_target,
                ) else {
                    return Ok(Err(format!(
                        "could not resolve current Mach-O text relocation target {} in section {} \
                         at offset {section_offset} in {}",
                        display_hex_text(&hex::encode(&name)),
                        section_index.0,
                        display_hex_path(&input.path)
                    )));
                };
                target = Some(current_target);
                value
            } else {
                if let Some(value) = resolution.and_then(|resolution| resolution.direct_value) {
                    target = resolution.and_then(|resolution| resolution.target.clone());
                    value
                } else if symbol.is_undefined()
                    && symbol.is_global()
                    && symbol.address() == 0
                    && current_context.r_type == object::macho::ARM64_RELOC_BRANCH26
                    && current_context.r_pcrel
                    && let Some(encoded_name) = target_name.as_ref()
                {
                    if resolution
                        .and_then(|resolution| resolution.stub_address)
                        .is_none()
                    {
                        recorded_import_stub_candidates = recorded_branch_targets.import_stubs(
                            encoded_name,
                            current_context.addend,
                            previous_output,
                            output_file,
                        );
                        if recorded_import_stub_candidates.is_empty() {
                            return Ok(Err(format!(
                                "missing Mach-O symbol resolution for {} in {}",
                                display_hex_text(&hex::encode(&name)),
                                display_hex_path(&input.path)
                            )));
                        }
                    }
                    target = None;
                    0
                } else {
                    return Ok(Err(format!(
                        "missing Mach-O symbol resolution for {} in {}",
                        display_hex_text(&hex::encode(&name)),
                        display_hex_path(&input.path)
                    )));
                }
            }
        }
        object::RelocationTarget::Section(section_index) => {
            let current_target = RelocationTargetRecord {
                input_file: input.path.clone().into(),
                input: patch_section.current.input.clone().into(),
                section_index: section_index.0 as u32,
                section_offset: 0,
            };
            let previous_target = RelocationTargetRecord {
                input_file: current_target.input_file.clone(),
                input: patch_section.previous.input.clone().into(),
                section_index: current_target.section_index,
                section_offset: 0,
            };
            let Some(value) = macho_output_address_for_current_target_with_lookup(
                output_file,
                current_file,
                matched_sections,
                relocations,
                resolutions,
                &current_target,
                &previous_target,
            ) else {
                return Ok(Err(format!(
                    "could not resolve current Mach-O text relocation section {} in {}",
                    section_index.0,
                    display_hex_path(&input.path)
                )));
            };
            target = Some(current_target);
            value
        }
        _ => {
            return Ok(Err(format!(
                "unsupported current Mach-O text relocation target in {}",
                display_hex_path(&input.path)
            )));
        }
    };

    let recorded_target_candidates = if recorded_import_stub_candidates.is_empty() {
        recorded_branch_targets.branch_targets(
            target_name.as_ref(),
            target_is_global,
            target.as_ref(),
            current_target_value,
            current_context.addend,
            previous_output,
            output_file,
        )
    } else {
        recorded_import_stub_candidates
    };
    let current_relocation_target_candidates =
        macho_text_relocation_target_candidates_for_resolution(
            resolution,
            current_context.r_type,
            current_target_value,
            &recorded_target_candidates,
        );

    let target_symbol_id =
        recorded_branch_targets.target_symbol_id(target_name.as_ref(), target.as_ref());
    Ok(Ok(MachOTextRelocationReplay {
        relocation_index: None,
        input_file: input.path.clone().into(),
        input: patch_section.current.input.clone(),
        section_index: patch_section.current.section_index,
        previous_output_offset: None,
        previous_range: None,
        current_range: current_context.range.clone(),
        r_type: current_context.r_type,
        kind: encode_macho_aarch64_relocation_kind(raw_relocation),
        rel_info,
        previous_written_value: None,
        previous_applied_target_value: None,
        current_target_value,
        current_relocation_target_candidates,
        current_target_section_offset: target.as_ref().map_or(0, |target| target.section_offset),
        target_symbol_id,
        target_name,
        target_is_global,
        target,
        addend: current_context.addend,
        chained_rebase_output_offset: None,
        chained_rebase_value: None,
    }))
}

fn relocation_is_in_rematerialized_macho_text_section(
    relocation: &RelocationRecord,
    rematerialized_sections: &[(SharedText, String, u32, String, u32)],
    normalize_rust_archive_patch_inputs: bool,
) -> Result<bool> {
    for (previous_input_file, previous_input, previous_section_index, _, _) in
        rematerialized_sections
    {
        if relocation.input_file == *previous_input_file
            && relocation.section_index == *previous_section_index
            && patch_input_refs_match(
                previous_input_file.as_str(),
                relocation.input.as_str(),
                previous_input,
                normalize_rust_archive_patch_inputs,
            )?
        {
            return Ok(true);
        }
    }
    Ok(false)
}

fn reconcile_rematerialized_macho_symbol_resolutions(
    resolutions: &mut Vec<MachOSymbolResolutionRecord>,
    relocations: &[RelocationRecord],
    replays: &[MachOTextRelocationReplay],
    rematerialized_sections: &[(SharedText, String, u32, String, u32)],
    normalize_rust_archive_patch_inputs: bool,
    retiring_names: &[SharedText],
    input: &FileState,
) -> std::result::Result<(Vec<RelocationTargetSymbolPatch>, bool), String> {
    let mut affected_names = HashSet::<SharedText>::new();
    let relocation_section_index = MachORelocationSectionIndex::new(
        relocations,
        input.path.as_str(),
        normalize_rust_archive_patch_inputs,
    )
    .map_err(|error| error.to_string())?;
    let mut rematerialized_relocation_indices = HashSet::new();
    for (input_file, previous_input, previous_section_index, _, _) in rematerialized_sections {
        if input_file != &input.path {
            continue;
        }
        let indices = relocation_section_index
            .indices_for_ref(
                input.path.as_str(),
                previous_input,
                *previous_section_index,
                normalize_rust_archive_patch_inputs,
            )
            .map_err(|error| error.to_string())?;
        rematerialized_relocation_indices.extend(indices.iter().copied());
    }

    for relocation_index in &rematerialized_relocation_indices {
        if let Some(target_name) = relocations[*relocation_index].target_name.as_ref() {
            affected_names.insert(target_name.clone());
        }
    }
    for replay in replays
        .iter()
        .filter(|replay| replay.relocation_index.is_none() && replay.target_is_global)
    {
        let Some(target_name) = replay.target_name.as_ref() else {
            continue;
        };
        affected_names.insert(target_name.clone());
    }

    let mut current_references =
        HashMap::<SharedText, Vec<(u64, Option<RelocationTargetRecord>)>>::new();
    for (relocation_index, relocation) in relocations.iter().enumerate() {
        let Some(target_name) = relocation
            .target_name
            .as_ref()
            .filter(|target_name| affected_names.contains(*target_name))
        else {
            continue;
        };
        if !rematerialized_relocation_indices.contains(&relocation_index) {
            current_references
                .entry(target_name.clone())
                .or_default()
                .push((relocation.target_value, relocation.target.clone()));
        }
    }
    for replay in replays
        .iter()
        .filter(|replay| replay.relocation_index.is_none() && replay.target_is_global)
    {
        let Some(target_name) = replay.target_name.as_ref() else {
            continue;
        };
        current_references
            .entry(target_name.clone())
            .or_default()
            .push((replay.current_target_value, replay.target.clone()));
    }

    let mut output_symbols = Vec::new();
    let mut changed = false;
    for target_name in affected_names {
        let references = current_references
            .get(&target_name)
            .map(Vec::as_slice)
            .unwrap_or_default();
        let mut target_values = references.iter().map(|(value, _)| *value);
        let current_target_value = target_values.next();
        if current_target_value.is_some()
            && !target_values.all(|value| Some(value) == current_target_value)
        {
            return Err(format!(
                "conflicting current Mach-O symbol resolutions in {}",
                display_hex_path(&input.path)
            ));
        }
        let resolution_index =
            macho_symbol_resolution_index_for_name(resolutions, target_name.as_str())?;
        let catalog_has_owner = resolution_index
            .and_then(|index| resolutions[index].target.as_ref())
            .is_some();
        let mut targets = references.iter().filter_map(|(_, target)| target.as_ref());
        let current_target = targets.next().cloned();
        if !catalog_has_owner
            && current_target.is_some()
            && !targets.all(|target| Some(target) == current_target.as_ref())
        {
            return Err(format!(
                "conflicting current Mach-O symbol owners in {}",
                display_hex_path(&input.path)
            ));
        }

        let Some(current_target_value) = current_target_value else {
            let Some(resolution_index) = resolution_index else {
                continue;
            };
            let resolution = &resolutions[resolution_index];
            if retiring_names.contains(&target_name)
                && resolution.direct_value.is_some()
                && resolution.got_address.is_none()
                && resolution.stub_address.is_none()
                && resolution.thunk_addresses.is_empty()
                && resolution
                    .target
                    .as_ref()
                    .is_some_and(|target| target.input_file == input.path)
            {
                continue;
            }
            if resolution.direct_value.unwrap_or_default() != 0
                && resolution.got_address.is_none()
                && resolution.stub_address.is_none()
                && resolution.thunk_addresses.is_empty()
            {
                return Err(format!(
                    "removed Mach-O text relocation target may change symbol liveness in {}",
                    display_hex_path(&input.path)
                ));
            }
            continue;
        };
        if current_target_value == 0
            && current_target.is_none()
            && resolution_index.is_none_or(|index| {
                resolutions[index].direct_value.is_none()
                    && resolutions[index].stub_address.is_some()
            })
        {
            continue;
        }

        if let Some(resolution_index) = resolution_index {
            let resolution = &mut resolutions[resolution_index];
            if resolution.direct_value != Some(current_target_value) {
                output_symbols.push(RelocationTargetSymbolPatch {
                    target_name: target_name.to_string(),
                    previous_target_value: resolution.direct_value.unwrap_or_default(),
                    target_value: current_target_value,
                    allow_missing: true,
                    source: "rematerialized Mach-O symbol resolution",
                });
                resolution.direct_value = Some(current_target_value);
                if resolution.target.is_none() {
                    resolution.target = current_target;
                }
                changed = true;
            }
        } else {
            let Some(current_target) = current_target else {
                return Err(format!(
                    "missing current Mach-O symbol owner in {}",
                    display_hex_path(&input.path)
                ));
            };
            output_symbols.push(RelocationTargetSymbolPatch {
                target_name: target_name.to_string(),
                previous_target_value: 0,
                target_value: current_target_value,
                allow_missing: true,
                source: "new rematerialized Mach-O symbol resolution",
            });
            resolutions.push(MachOSymbolResolutionRecord {
                name: target_name,
                direct_value: Some(current_target_value),
                got_address: None,
                stub_address: None,
                thunk_addresses: Vec::new(),
                target: Some(current_target),
            });
            changed = true;
        }
    }
    Ok((output_symbols, changed))
}

fn retire_missing_macho_symbol_resolutions(
    resolutions: &mut Vec<MachOSymbolResolutionRecord>,
    relocations: &[RelocationRecord],
    replays: &[MachOTextRelocationReplay],
    rematerialized_sections: &[(SharedText, String, u32, String, u32)],
    normalize_rust_archive_patch_inputs: bool,
    retiring_names: &[SharedText],
    recycled_names: &HashSet<SharedText>,
    changed_input_files: &HashSet<String>,
    input: &FileState,
    previous_output: &[u8],
) -> std::result::Result<bool, String> {
    if retiring_names.is_empty() {
        return Ok(false);
    }

    let output_file = object::File::parse(previous_output)
        .map_err(|_| "failed to parse previous output for Mach-O symbol retirement".to_owned())?;
    let mut retiring_indices = Vec::with_capacity(retiring_names.len());
    for name in retiring_names {
        if !recycled_names.contains(name) {
            return Err(format!(
                "missing Mach-O symbol resolution has no recycled output slot in {}",
                display_hex_path(&input.path)
            ));
        }
        let Some(resolution_index) =
            macho_symbol_resolution_index_for_name(resolutions, name.as_str())?
        else {
            return Err(format!(
                "missing deferred Mach-O symbol resolution catalog entry for `{}` during retirement",
                display_hex_text(name.as_str())
            ));
        };
        let resolution = &resolutions[resolution_index];
        if resolution.direct_value.is_none()
            || resolution.got_address.is_some()
            || resolution.stub_address.is_some()
            || !resolution.thunk_addresses.is_empty()
            || resolution
                .target
                .as_ref()
                .is_none_or(|target| target.input_file != input.path)
        {
            return Err(format!(
                "missing Mach-O symbol resolution cannot be retired in {}",
                display_hex_path(&input.path)
            ));
        }
        let mut has_live_relocation = false;
        for relocation in relocations {
            if relocation.target_name.as_ref() == Some(name)
                && (relocation.input_file == input.path
                    || !changed_input_files.contains(relocation.input_file.as_str()))
                && !relocation_is_in_rematerialized_macho_text_section(
                    relocation,
                    rematerialized_sections,
                    normalize_rust_archive_patch_inputs,
                )
                .map_err(|error| error.to_string())?
            {
                has_live_relocation = true;
                break;
            }
        }
        if has_live_relocation
            || replays
                .iter()
                .any(|replay| replay.target_name.as_ref() == Some(name))
        {
            return Err(format!(
                "missing Mach-O symbol resolution `{}` is still referenced in {}",
                display_hex_text(name.as_str()),
                display_hex_path(&input.path)
            ));
        }
        let decoded_name = hex::decode(name.as_str())
            .map_err(|_| "malformed Mach-O symbol resolution name".to_owned())?;
        let published_symbol_count = output_file
            .symbols()
            .filter(|symbol| {
                symbol
                    .name_bytes()
                    .is_ok_and(|candidate| candidate == decoded_name)
            })
            .count();
        if published_symbol_count != 1 {
            return Err(format!(
                "missing Mach-O symbol resolution has no unique recyclable output symbol in {}",
                display_hex_path(&input.path)
            ));
        }
        retiring_indices.push(resolution_index);
    }

    retiring_indices.sort_unstable();
    retiring_indices.dedup();
    for index in retiring_indices.into_iter().rev() {
        resolutions.remove(index);
    }
    Ok(true)
}

fn macho_text_relocation_replays_for_input(
    relocations: &[RelocationRecord],
    resolutions: &mut Vec<MachOSymbolResolutionRecord>,
    retiring_names: &[SharedText],
    input: &FileState,
    changed_input_macho_definitions: Option<&HashSet<Vec<u8>>>,
    matched_sections: &[MatchedPatchSection],
    previous_resolver: &PatchInputResolver<'_>,
    current_resolver: &PatchInputResolver<'_>,
    previous_output: &[u8],
    target_patches: &mut RelocationTargetPatches,
    resolution_moves: &[MachOSymbolResolutionMove],
    changed_input_records_loaded: bool,
) -> Result<std::result::Result<MachOTextRelocationReplays, String>> {
    let mut replays = Vec::new();
    let mut rematerialized_sections = Vec::new();
    let output_file = object::File::parse(previous_output)
        .context("Failed to parse previous Mach-O output for text relocation replay")?;
    let target_moves = target_patches
        .macho_target_moves
        .iter()
        .map(|target_move| (target_move.relocation_index, target_move.clone()))
        .collect::<HashMap<_, _>>();
    let mut target_resolution_moves = HashMap::new();
    for target_move in &target_patches.macho_target_moves {
        let Some(relocation) = relocations.get(target_move.relocation_index) else {
            return Ok(Err(format!(
                "missing Mach-O text relocation for moved target in {}",
                display_hex_path(&input.path)
            )));
        };
        let Some(target_name) = relocation.target_name.as_deref() else {
            return Ok(Err(format!(
                "missing Mach-O text relocation target name in {}",
                display_hex_path(&input.path)
            )));
        };
        let Some(previous_target) = relocation.target.as_ref() else {
            return Ok(Err(format!(
                "missing Mach-O text relocation target in {}",
                display_hex_path(&input.path)
            )));
        };
        match matching_macho_symbol_resolution_move(
            resolution_moves,
            target_name,
            previous_target,
            relocation.target_value,
            target_move.current_section_offset,
        ) {
            Ok(Some(moved)) => {
                target_resolution_moves.insert(target_move.relocation_index, moved.clone());
            }
            Ok(None) => {}
            Err(()) => {
                return Ok(Err(format!(
                    "ambiguous moved Mach-O symbol for text relocation in {}",
                    display_hex_path(&input.path)
                )));
            }
        }
    }
    let mut consumed_target_moves = HashSet::new();
    let mut same_object_target_moves = Vec::new();
    let mut target_input_ranges = Vec::new();
    let mut target_output_symbols = Vec::new();
    let mut retained_output_resolutions = Vec::new();
    let output_text_definitions = {
        timing_phase!("Index previous Mach-O output text definitions");
        MachOOutputTextDefinitionLookup::new(&output_file)
    };
    let normalize_rust_archive_patch_inputs = previous_resolver.normalize_rust_archive_patch_inputs
        && current_resolver.normalize_rust_archive_patch_inputs;
    let resolution_lookup = MachOSymbolResolutionLookup::new(resolutions);
    let matched_current_sections = MatchedCurrentSectionLookup::new(matched_sections);
    let relocation_section_index = {
        timing_phase!("Index persisted Mach-O text relocations");
        MachORelocationSectionIndex::new(
            relocations,
            input.path.as_str(),
            normalize_rust_archive_patch_inputs,
        )?
    };
    let recorded_branch_targets = std::cell::OnceCell::new();
    let mut sections_by_input = HashMap::<(&str, &str), Vec<&MatchedPatchSection>>::new();
    for section in matched_sections {
        sections_by_input
            .entry((
                section.previous.input.as_str(),
                section.current.input.as_str(),
            ))
            .or_default()
            .push(section);
    }

    let compare_changed_macho_text_sections =
        crate::timing_guard!("Compare changed Mach-O text sections");
    for ((previous_input_ref, current_input_ref), sections) in sections_by_input {
        let Some(current_input_bytes) = current_resolver.resolve(
            input.path.as_str(),
            current_input_ref,
            PatchInputLookup::MatchArchiveMember,
        )?
        else {
            return Ok(Err(format!(
                "could not resolve current Mach-O text patch input in {}",
                display_hex_path(&input.path)
            )));
        };
        let current_file = object::File::parse(current_input_bytes.bytes)
            .context("Failed to parse current Mach-O text replay input")?;
        let Some(previous_input_bytes) = previous_resolver.resolve(
            input.path.as_str(),
            previous_input_ref,
            PatchInputLookup::MatchArchiveMember,
        )?
        else {
            return Ok(Err(format!(
                "could not resolve previous Mach-O text patch input in {}",
                display_hex_path(&input.path)
            )));
        };
        let previous_file = object::File::parse(previous_input_bytes.bytes)
            .context("Failed to parse previous Mach-O text replay input")?;
        let current_section_indices = PatchSectionIndexLookup::new(&current_file);
        let previous_section_indices = PatchSectionIndexLookup::new(&previous_file);

        for patch_section in sections {
            let Some(current_index) =
                current_section_indices.index(&current_file, &patch_section.current)?
            else {
                return Ok(Err(format!(
                    "missing current Mach-O text patch section in {}",
                    display_hex_path(&input.path)
                )));
            };
            let current_section = current_file
                .section_by_index(current_index)
                .context("Missing current Mach-O text replay section")?;
            if current_file.architecture() != object::Architecture::Aarch64
                || !matches!(current_section.flags(), object::SectionFlags::MachO { .. })
                || current_section.name().ok() != Some("__text")
            {
                continue;
            }

            let Some(previous_index) =
                previous_section_indices.index(&previous_file, &patch_section.previous)?
            else {
                return Ok(Err(format!(
                    "missing previous Mach-O text patch section in {}",
                    display_hex_path(&input.path)
                )));
            };
            let previous_section = previous_file
                .section_by_index(previous_index)
                .context("Missing previous Mach-O text replay section")?;
            let previous_data = previous_section
                .data()
                .context("Failed to read previous Mach-O text replay section data")?;
            let current_data = current_section
                .data()
                .context("Failed to read current Mach-O text replay section data")?;
            let Some(previous_contexts) = macho_aarch64_text_relocation_contexts(
                &previous_file,
                &previous_section,
                previous_data,
            ) else {
                return Ok(Err(format!(
                    "unsupported previous Mach-O text relocations in {}",
                    display_hex_path(&input.path)
                )));
            };
            let Some(current_contexts) = macho_aarch64_text_relocation_contexts(
                &current_file,
                &current_section,
                current_data,
            ) else {
                return Ok(Err(format!(
                    "unsupported current Mach-O text relocations in {}",
                    display_hex_path(&input.path)
                )));
            };

            let relocation_indices = relocation_section_index
                .indices(
                    input.path.as_str(),
                    &patch_section.previous,
                    normalize_rust_archive_patch_inputs,
                )?
                .to_vec();
            let has_moved_target = relocation_indices
                .iter()
                .any(|index| target_moves.contains_key(index));
            if previous_contexts.len() != relocation_indices.len() {
                if !changed_input_records_loaded {
                    return Ok(Err(MACHO_TEXT_RELOCATION_RECORDS_REQUIRED.to_owned()));
                }
                let recorded_input_file_relocations = relocations
                    .iter()
                    .filter(|relocation| relocation.input_file == input.path)
                    .count();
                let mut recorded_input_relocations = 0;
                for relocation in relocations {
                    if relocation.input_file == input.path
                        && patch_input_refs_match(
                            input.path.as_str(),
                            relocation.input.as_str(),
                            patch_section.previous.input.as_str(),
                            normalize_rust_archive_patch_inputs,
                        )?
                    {
                        recorded_input_relocations += 1;
                    }
                }
                return Ok(Err(format!(
                    "changed Mach-O text relocation count in {}: object {}, recorded {} \
                     (input file {}, member {}, section {})",
                    display_hex_path(&input.path),
                    previous_contexts.len(),
                    relocation_indices.len(),
                    recorded_input_file_relocations,
                    recorded_input_relocations,
                    patch_section.previous.section_index,
                )));
            }
            let previous_signatures = previous_contexts
                .iter()
                .map(|context| macho_text_relocation_signature(&previous_file, context))
                .collect::<Result<Vec<_>>>()?;
            let current_signatures = current_contexts
                .iter()
                .map(|context| macho_text_relocation_signature(&current_file, context))
                .collect::<Result<Vec<_>>>()?;
            let relocation_set_changed = previous_signatures != current_signatures;
            let is_reordering = if previous_signatures.len() == current_signatures.len() {
                let mut previous = previous_signatures.clone();
                let mut current = current_signatures.clone();
                previous.sort_unstable();
                current.sort_unstable();
                previous == current
            } else {
                false
            };
            let replaces_external_target = previous_signatures.len() == current_signatures.len()
                && previous_signatures
                    .iter()
                    .zip(&current_signatures)
                    .any(|(previous, current)| previous != current)
                && previous_signatures.iter().zip(&current_signatures).all(
                    |(previous, current)| {
                        if previous == current {
                            return true;
                        }
                        let (
                            previous_type,
                            previous_pcrel,
                            previous_addend,
                            Some((_previous_name, previous_section)),
                        ) = previous
                        else {
                            return false;
                        };
                        let (
                            current_type,
                            current_pcrel,
                            current_addend,
                            Some((_current_name, current_section)),
                        ) = current
                        else {
                            return false;
                        };
                        previous_type == current_type
                            && previous_pcrel == current_pcrel
                            && previous_addend == current_addend
                            && previous_section.is_none()
                            && current_section.is_none()
                    },
                );
            while replaces_external_target {
                let Some(current_name) = missing_macho_replacement_resolution(
                    &previous_signatures,
                    &current_signatures,
                    resolutions,
                    &resolution_lookup,
                    &retained_output_resolutions,
                ) else {
                    break;
                };
                let retained_resolution = output_text_definitions
                    .as_ref()
                    .and_then(|definitions| definitions.resolution(current_name));
                if changed_input_macho_definitions
                    .is_none_or(|definitions| definitions.contains(current_name))
                    || retained_resolution.is_none()
                {
                    return Ok(Err(format!(
                        "{MACHO_SYMBOL_RESOLUTIONS_REQUIRED} for {} in {}",
                        String::from_utf8_lossy(current_name),
                        display_hex_path(&input.path)
                    )));
                }
                retained_output_resolutions
                    .push(retained_resolution.expect("checked retained Mach-O output definition"));
            }
            if relocation_set_changed
                && (previous_signatures.len() != current_signatures.len()
                    || is_reordering
                    || replaces_external_target)
            {
                for relocation_index in &relocation_indices {
                    if target_moves.contains_key(relocation_index) {
                        consumed_target_moves.insert(*relocation_index);
                    }
                }
                let recorded_branch_targets = recorded_branch_targets
                    .get_or_init(|| RecordedMachOBranchTargetCandidates::new(relocations));
                for current_context in &current_contexts {
                    let replay = match rematerialized_macho_text_relocation_replay(
                        relocations,
                        resolutions,
                        &resolution_lookup,
                        &retained_output_resolutions,
                        recorded_branch_targets,
                        input,
                        patch_section,
                        &current_file,
                        current_context,
                        &matched_current_sections,
                        previous_output,
                        &output_file,
                    )? {
                        Ok(replay) => replay,
                        Err(reason) => return Ok(Err(reason)),
                    };
                    replays.push(replay);
                }
                rematerialized_sections.push((
                    input.path.clone().into(),
                    patch_section.previous.input.clone(),
                    patch_section.previous.section_index,
                    patch_section.current.input.clone(),
                    patch_section.current.section_index,
                ));
                continue;
            }
            if previous_contexts.len() != current_contexts.len() {
                return Ok(Err(format!(
                    "changed Mach-O text relocation count in {}",
                    display_hex_path(&input.path)
                )));
            }

            let replay_start = replays.len();
            let mut section_has_moved_target = has_moved_target;
            for ((previous_context, current_context), relocation_index) in previous_contexts
                .iter()
                .zip(&current_contexts)
                .zip(relocation_indices)
            {
                let relocation = &relocations[relocation_index];
                let Some(raw_relocation) = decode_macho_aarch64_relocation_kind(relocation.kind)
                else {
                    return Ok(Err(format!(
                        "unsupported recorded Mach-O text relocation in {}",
                        display_hex_path(&input.path)
                    )));
                };
                if previous_context.range.start as u64 != relocation.relocation_offset
                    || previous_context.r_type != raw_relocation.r_type
                    || previous_context.r_pcrel != raw_relocation.r_pcrel
                    || current_context.r_type != previous_context.r_type
                    || current_context.r_pcrel != previous_context.r_pcrel
                    || previous_context.addend != relocation.addend
                    || current_context.addend != previous_context.addend
                    || previous_context.subtractor.is_some()
                    || current_context.subtractor.is_some()
                {
                    return Ok(Err(format!(
                        "changed Mach-O text relocation semantics in {}",
                        display_hex_path(&input.path)
                    )));
                }
                let previous_target =
                    macho_relocation_target_identity(&previous_file, previous_context.target)?;
                let current_target =
                    macho_relocation_target_identity(&current_file, current_context.target)?;
                if previous_target.is_none() || previous_target != current_target {
                    let previous_name = previous_target
                        .as_ref()
                        .map(|(name, _)| String::from_utf8_lossy(name).into_owned())
                        .unwrap_or_else(|| "<none>".to_owned());
                    let current_name = current_target
                        .as_ref()
                        .map(|(name, _)| String::from_utf8_lossy(name).into_owned())
                        .unwrap_or_else(|| "<none>".to_owned());
                    let retiring_names = retiring_names
                        .iter()
                        .map(|name| display_hex_text(name))
                        .collect::<Vec<_>>()
                        .join(", ");
                    return Ok(Err(format!(
                        "changed Mach-O text relocation target from {previous_name} to \
                         {current_name} in {} (retiring: {retiring_names})",
                        display_hex_path(&input.path),
                    )));
                }

                let mut replay_target = relocation.target.clone();
                let same_object_target = if let Some(target) = relocation.target.as_ref() {
                    (target.input_file == input.path
                        && patch_input_refs_match(
                            input.path.as_str(),
                            target.input.as_str(),
                            patch_section.previous.input.as_str(),
                            normalize_rust_archive_patch_inputs,
                        )?
                        && patch_input_refs_match(
                            input.path.as_str(),
                            relocation.input.as_str(),
                            target.input.as_str(),
                            normalize_rust_archive_patch_inputs,
                        )?)
                    .then_some(target)
                } else {
                    None
                };
                let same_object_target_move = if let Some(target) = same_object_target {
                    let Some(previous_position) =
                        macho_relocation_symbol_position(&previous_file, previous_context.target)?
                    else {
                        return Ok(Err(format!(
                            "missing previous Mach-O text relocation target in {}",
                            display_hex_path(&input.path)
                        )));
                    };
                    let Some(current_position) =
                        macho_relocation_symbol_position(&current_file, current_context.target)?
                    else {
                        return Ok(Err(format!(
                            "missing current Mach-O text relocation target in {}",
                            display_hex_path(&input.path)
                        )));
                    };
                    let recorded_name = relocation
                        .target_name
                        .as_deref()
                        .map(hex::decode)
                        .transpose()
                        .context("Malformed recorded Mach-O relocation target name")?;
                    if recorded_name.as_deref() != Some(previous_position.name.as_slice())
                        || previous_position.section_index.0 as u32 != target.section_index
                        || previous_position.section_offset != target.section_offset
                    {
                        return Ok(Err(format!(
                            "previous Mach-O text relocation target changed in {}",
                            display_hex_path(&input.path)
                        )));
                    }
                    let current_target = replay_target
                        .as_mut()
                        .context("Missing same-object Mach-O relocation target")?;
                    current_target.input = patch_section.current.input.clone().into();
                    current_target.section_index = current_position.section_index.0 as u32;
                    current_target.section_offset = current_position.section_offset;
                    if let Some(value_range) = macho_symbol_value_field_range(
                        current_input_bytes.bytes,
                        current_position.symbol_index,
                    ) {
                        target_input_ranges.push(
                            current_input_bytes.file_offset + value_range.start
                                ..current_input_bytes.file_offset + value_range.end,
                        );
                    }
                    let delta = i128::from(current_position.section_offset)
                        - i128::from(previous_position.section_offset);
                    let Some(current_target_value) =
                        add_signed_delta_u64(relocation.target_value, delta)
                    else {
                        return Ok(Err(format!(
                            "Mach-O text relocation target value overflowed in {}",
                            display_hex_path(&input.path)
                        )));
                    };
                    let target_move = MachORelocationTargetMove {
                        relocation_index,
                        current_section_offset: current_position.section_offset,
                        current_target_value,
                        current_input: None,
                    };
                    if current_target_value != relocation.target_value
                        || current_position.section_offset != target.section_offset
                    {
                        section_has_moved_target = true;
                        same_object_target_moves.push(target_move.clone());
                        target_output_symbols.push(RelocationTargetSymbolPatch {
                            target_name: relocation
                                .target_name
                                .as_deref()
                                .context("Missing recorded Mach-O relocation target name")?
                                .to_owned(),
                            previous_target_value: relocation.target_value,
                            target_value: current_target_value,
                            allow_missing: true,
                            source: "same-object Mach-O text relocation replay",
                        });
                        Some(target_move)
                    } else {
                        None
                    }
                } else {
                    None
                };

                let rel_info =
                    <crate::macho_aarch64::MachOAArch64 as crate::platform::Arch>::relocation_from_raw(
                        raw_relocation,
                    )
                    .map_err(|error| {
                        crate::error!(
                            "Failed to decode recorded Mach-O text relocation: {error:#?}"
                        )
                    })?;
                if previous_context.range.start == current_context.range.start
                    && previous_context.bytes != current_context.bytes
                {
                    return Ok(Err(format!(
                        "changed Mach-O text relocation bytes in {}",
                        display_hex_path(&input.path)
                    )));
                }
                if macho_relocation_instruction_shape(rel_info, &previous_context.bytes)
                    != macho_relocation_instruction_shape(rel_info, &current_context.bytes)
                {
                    return Ok(Err(format!(
                        "changed Mach-O text relocation instruction in {}",
                        display_hex_path(&input.path)
                    )));
                }

                let Some(previous_written_value) = relocation.written_value else {
                    return Ok(Err(format!(
                        "missing written Mach-O text relocation value in {}",
                        display_hex_path(&input.path)
                    )));
                };
                let recorded_target_move = target_moves.get(&relocation_index);
                if recorded_target_move.is_some() {
                    consumed_target_moves.insert(relocation_index);
                }
                let target_move = recorded_target_move.cloned().or(same_object_target_move);
                let resolution_move = target_resolution_moves.get(&relocation_index);
                let (current_target_value, current_target) = resolved_macho_relocation_target(
                    relocation.target_value,
                    replay_target,
                    target_move.clone(),
                    resolution_move,
                );
                replay_target = current_target;
                if recorded_target_move.is_some() {
                    target_output_symbols.push(RelocationTargetSymbolPatch {
                        target_name: relocation
                            .target_name
                            .as_deref()
                            .context("Missing recorded Mach-O relocation target name")?
                            .to_owned(),
                        previous_target_value: relocation.target_value,
                        target_value: current_target_value,
                        allow_missing: true,
                        source: "resolved Mach-O relocation target movement",
                    });
                }
                let previous_applied_target_value = relocation
                    .applied_target_value
                    .unwrap_or(relocation.target_value);
                if target_move.is_some() && previous_applied_target_value != relocation.target_value
                {
                    return Ok(Err(format!(
                        "moved Mach-O stub or thunk target in {}",
                        display_hex_path(&input.path)
                    )));
                }
                let previous_applied_target_values = target_move
                    .is_none()
                    .then_some(previous_applied_target_value)
                    .into_iter()
                    .collect::<Vec<_>>();
                let current_relocation_target_candidates = macho_text_relocation_target_candidates(
                    resolutions,
                    &resolution_lookup,
                    relocation.target_name.as_deref(),
                    raw_relocation.r_type,
                    current_target_value,
                    &previous_applied_target_values,
                );

                replays.push(MachOTextRelocationReplay {
                    relocation_index: Some(relocation_index),
                    input_file: input.path.clone().into(),
                    input: patch_section.current.input.clone(),
                    section_index: patch_section.current.section_index,
                    previous_output_offset: Some(patch_section.previous.output_offset),
                    previous_range: Some(previous_context.range.clone()),
                    current_range: current_context.range.clone(),
                    r_type: raw_relocation.r_type,
                    kind: relocation.kind,
                    rel_info,
                    previous_written_value: Some(previous_written_value),
                    previous_applied_target_value: Some(previous_applied_target_value),
                    current_target_value,
                    current_relocation_target_candidates,
                    current_target_section_offset: replay_target
                        .as_ref()
                        .map(|target| target.section_offset)
                        .unwrap_or_default(),
                    target_symbol_id: relocation.target_symbol_id,
                    target_name: relocation.target_name.clone(),
                    target_is_global: macho_relocation_target_is_global(
                        &current_file,
                        current_context.target,
                    ),
                    target: replay_target,
                    addend: relocation.addend,
                    chained_rebase_output_offset: None,
                    chained_rebase_value: None,
                });
            }
            if patch_section.previous.data_hash == patch_section.current.data_hash
                && !section_has_moved_target
                && matched_normalized_archive_section_preserves_relocation_record_locations(
                    input.path.as_str(),
                    patch_section,
                    normalize_rust_archive_patch_inputs,
                )?
                && replays[replay_start..]
                    .iter()
                    .all(|replay| replay.previous_range.as_ref() == Some(&replay.current_range))
            {
                replays.truncate(replay_start);
            }
        }
    }
    drop(compare_changed_macho_text_sections);

    if consumed_target_moves.len() != target_moves.len() {
        return Ok(Err(format!(
            "missing Mach-O text relocation for moved target in {}",
            display_hex_path(&input.path)
        )));
    }
    target_patches
        .macho_target_moves
        .extend(same_object_target_moves);
    target_patches.input_ranges.extend(target_input_ranges);
    dedup_ranges(&mut target_patches.input_ranges);
    target_patches.output_symbols.extend(target_output_symbols);
    drop(resolution_lookup);
    let retained_output_resolution_start = resolutions.len();
    resolutions.extend(retained_output_resolutions.iter().cloned());
    let reconciled = {
        timing_phase!("Reconcile rematerialized Mach-O symbol resolutions");
        reconcile_rematerialized_macho_symbol_resolutions(
            resolutions,
            relocations,
            &replays,
            &rematerialized_sections,
            normalize_rust_archive_patch_inputs,
            retiring_names,
            input,
        )
    };
    remove_temporary_macho_symbol_resolutions(
        resolutions,
        retained_output_resolution_start,
        retained_output_resolutions.len(),
    );
    let (resolution_output_symbols, symbol_resolutions_changed) = match reconciled {
        Ok(updates) => updates,
        Err(reason) => return Ok(Err(reason)),
    };
    target_patches
        .output_symbols
        .extend(resolution_output_symbols);
    Ok(Ok(MachOTextRelocationReplays {
        replays,
        rematerialized_sections,
        normalize_rust_archive_patch_inputs,
        symbol_resolutions_changed,
    }))
}

fn remove_temporary_macho_symbol_resolutions(
    resolutions: &mut Vec<MachOSymbolResolutionRecord>,
    start: usize,
    count: usize,
) {
    resolutions.drain(start..start + count);
}

fn restore_deferred_macho_symbol_resolutions<'a>(
    resolutions: &mut Vec<MachOSymbolResolutionRecord>,
    deferred: impl IntoIterator<Item = &'a MachOSymbolResolutionRecord>,
) -> std::result::Result<(), String> {
    for resolution in deferred {
        match macho_symbol_resolution_index_for_name(resolutions, resolution.name.as_str())? {
            Some(_) => {}
            None => resolutions.push(resolution.clone()),
        }
    }
    Ok(())
}

fn validate_macho_data_relocations_are_stable(
    relocations: &mut [RelocationRecord],
    resolutions: &[MachOSymbolResolutionRecord],
    input: &FileState,
    matched_sections: &[MatchedPatchSection],
    previous_resolver: &PatchInputResolver<'_>,
    current_resolver: &PatchInputResolver<'_>,
    previous_output: &[u8],
    target_moves: &[MachORelocationTargetMove],
) -> Result<std::result::Result<bool, String>> {
    let output_file = object::File::parse(previous_output)
        .context("Failed to parse previous Mach-O output for data relocation validation")?;
    let target_move_indices = target_moves
        .iter()
        .map(|target_move| target_move.relocation_index)
        .collect::<HashSet<_>>();
    let normalize_rust_archive_patch_inputs = previous_resolver.normalize_rust_archive_patch_inputs
        && current_resolver.normalize_rust_archive_patch_inputs;
    let resolution_lookup = MachOSymbolResolutionLookup::new(resolutions);
    let relocation_section_index = MachORelocationSectionIndex::new(
        relocations,
        input.path.as_str(),
        normalize_rust_archive_patch_inputs,
    )?;
    let mut changed = false;
    let mut sections_by_input = HashMap::<(&str, &str), Vec<&MatchedPatchSection>>::new();
    for section in matched_sections {
        sections_by_input
            .entry((
                section.previous.input.as_str(),
                section.current.input.as_str(),
            ))
            .or_default()
            .push(section);
    }

    for ((previous_input_ref, current_input_ref), sections) in sections_by_input {
        let Some(current_input_bytes) = current_resolver.resolve(
            input.path.as_str(),
            current_input_ref,
            PatchInputLookup::MatchArchiveMember,
        )?
        else {
            return Ok(Err(format!(
                "could not resolve current Mach-O data patch input in {}",
                display_hex_path(&input.path)
            )));
        };
        let current_file = object::File::parse(current_input_bytes.bytes)
            .context("Failed to parse current Mach-O data relocation input")?;
        let Some(previous_input_bytes) = previous_resolver.resolve(
            input.path.as_str(),
            previous_input_ref,
            PatchInputLookup::MatchArchiveMember,
        )?
        else {
            return Ok(Err(format!(
                "could not resolve previous Mach-O data patch input in {}",
                display_hex_path(&input.path)
            )));
        };
        let previous_file = object::File::parse(previous_input_bytes.bytes)
            .context("Failed to parse previous Mach-O data relocation input")?;
        let current_section_indices = PatchSectionIndexLookup::new(&current_file);
        let previous_section_indices = PatchSectionIndexLookup::new(&previous_file);
        let mut unmatched_target_stability =
            HashMap::<MachODataRelocationTargetStabilityKey, bool>::new();

        for patch_section in sections {
            let Some(current_index) =
                current_section_indices.index(&current_file, &patch_section.current)?
            else {
                return Ok(Err(format!(
                    "missing current Mach-O data patch section in {}",
                    display_hex_path(&input.path)
                )));
            };
            let current_section = current_file
                .section_by_index(current_index)
                .context("Missing current Mach-O data relocation section")?;

            let Some(previous_index) =
                previous_section_indices.index(&previous_file, &patch_section.previous)?
            else {
                return Ok(Err(format!(
                    "missing previous Mach-O data patch section in {}",
                    display_hex_path(&input.path)
                )));
            };
            let previous_section = previous_file
                .section_by_index(previous_index)
                .context("Missing previous Mach-O data relocation section")?;
            let relocation_indices = relocation_section_index
                .indices(
                    input.path.as_str(),
                    &patch_section.previous,
                    normalize_rust_archive_patch_inputs,
                )?
                .iter()
                .copied()
                .filter(|index| {
                    decode_macho_aarch64_relocation_kind(relocations[*index].kind).is_some_and(
                        |raw| {
                            raw.r_type == object::macho::ARM64_RELOC_UNSIGNED
                                && !raw.r_pcrel
                                && raw.r_length == 3
                        },
                    )
                })
                .collect::<Vec<_>>();
            // Newly activated sections are present in `matched_sections` before their
            // provisional relocation records are materialized. Only validate sections
            // with persisted relocation state; direct patch eligibility separately
            // rejects unrecorded Mach-O data relocations.
            if relocation_indices.is_empty() {
                continue;
            }
            let previous_is_data_const = previous_section.name().ok() == Some("__const")
                && previous_section.segment_name().ok().flatten() == Some("__DATA");
            let current_is_data_const = current_section.name().ok() == Some("__const")
                && current_section.segment_name().ok().flatten() == Some("__DATA");
            if !previous_is_data_const && !current_is_data_const {
                continue;
            }
            if previous_file.architecture() != object::Architecture::Aarch64
                || current_file.architecture() != object::Architecture::Aarch64
                || !matches!(previous_section.flags(), object::SectionFlags::MachO { .. })
                || !matches!(current_section.flags(), object::SectionFlags::MachO { .. })
                || !previous_is_data_const
                || !current_is_data_const
            {
                return Ok(Err(format!(
                    "changed Mach-O data relocation section kind in {}",
                    display_hex_path(&input.path),
                )));
            }
            let previous_data = previous_section
                .data()
                .context("Failed to read previous Mach-O data relocation section")?;
            let current_data = current_section
                .data()
                .context("Failed to read current Mach-O data relocation section")?;
            let Some(previous_contexts) = macho_aarch64_data_relocation_contexts(
                &previous_file,
                &previous_section,
                previous_data,
            ) else {
                return Ok(Err(format!(
                    "unsupported previous Mach-O data relocations in {}",
                    display_hex_path(&input.path)
                )));
            };
            let Some(current_contexts) = macho_aarch64_data_relocation_contexts(
                &current_file,
                &current_section,
                current_data,
            ) else {
                return Ok(Err(format!(
                    "unsupported current Mach-O data relocations in {}",
                    display_hex_path(&input.path)
                )));
            };
            if !macho_data_relocation_layout_is_stable(
                previous_contexts.len(),
                current_contexts.len(),
                relocation_indices.len(),
                matched_normalized_archive_section_preserves_relocation_record_locations(
                    input.path.as_str(),
                    patch_section,
                    normalize_rust_archive_patch_inputs,
                )?,
            ) {
                return Ok(Err(format!(
                    "changed Mach-O data relocation layout in {}: previous={}, current={}, \
                     records={}, input={}, section={}",
                    display_hex_path(&input.path),
                    previous_contexts.len(),
                    current_contexts.len(),
                    relocation_indices.len(),
                    display_hex_text(&patch_section.previous.input),
                    patch_section.previous.section_index,
                )));
            }

            for ((previous_context, current_context), relocation_index) in previous_contexts
                .iter()
                .zip(&current_contexts)
                .zip(relocation_indices)
            {
                if target_move_indices.contains(&relocation_index) {
                    return Ok(Err(format!(
                        "moved Mach-O data relocation target in {}",
                        display_hex_path(&input.path)
                    )));
                }
                let relocation = &mut relocations[relocation_index];
                let previous_identity =
                    macho_relocation_target_identity(&previous_file, previous_context.target)?;
                let current_identity =
                    macho_relocation_target_identity(&current_file, current_context.target)?;
                if !macho_data_relocation_semantics_are_stable(
                    previous_context,
                    current_context,
                    relocation,
                    &previous_identity,
                    &current_identity,
                ) {
                    return Ok(Err(format!(
                        "changed Mach-O data relocation semantics in {}",
                        display_hex_path(&input.path)
                    )));
                }
                let current_output_offset = patch_section
                    .current
                    .output_offset
                    .checked_add(current_context.range.start as u64)
                    .context("Mach-O data relocation output offset overflow")?;
                if relocation.output_offset != current_output_offset {
                    return Ok(Err(format!(
                        "moved Mach-O data relocation field in {}",
                        display_hex_path(&input.path)
                    )));
                }
                if macho_relocation_target_is_global(&previous_file, previous_context.target)
                    && macho_relocation_target_is_global(&current_file, current_context.target)
                    && macho_catalog_data_relocation_target_is_stable_with_lookup(
                        &previous_identity,
                        &current_identity,
                        relocation,
                        resolutions,
                        &resolution_lookup,
                        normalize_rust_archive_patch_inputs,
                    )?
                {
                    let previous_record = relocation.clone();
                    if relocation.input != patch_section.current.input {
                        relocation.input = patch_section.current.input.clone().into();
                    }
                    relocation.section_index = patch_section.current.section_index;
                    changed |= *relocation != previous_record;
                    continue;
                }
                let previous_target =
                    macho_data_relocation_target_position(&previous_file, previous_context.target)?;
                let current_target =
                    macho_data_relocation_target_position(&current_file, current_context.target)?;
                let (Some(previous_target), Some(current_target)) =
                    (previous_target, current_target)
                else {
                    return Ok(Err(format!(
                        "unsupported external Mach-O data relocation target in {}",
                        display_hex_path(&input.path)
                    )));
                };
                let previous_target_patch_section_index =
                    patch_section_record_index(&previous_file, previous_target.section_index)?;
                let current_target_patch_section_index =
                    patch_section_record_index(&current_file, current_target.section_index)?;
                let target_section = matched_sections.iter().find(|section| {
                    section.previous.input == patch_section.previous.input
                        && section.previous.section_index == previous_target_patch_section_index
                        && section.current.input == patch_section.current.input
                        && section.current.section_index == current_target_patch_section_index
                });
                let unmatched_target_is_stable = if target_section.is_none() {
                    let cache_key = macho_relocation_target_cache_key(previous_context.target)
                        .zip(macho_relocation_target_cache_key(current_context.target))
                        .map(|(previous_relocation_target, current_relocation_target)| {
                            MachODataRelocationTargetStabilityKey {
                                previous_relocation_target,
                                current_relocation_target,
                                previous_section_index: previous_target.section_index.0,
                                previous_section_offset: previous_target.section_offset,
                                current_section_index: current_target.section_index.0,
                                current_section_offset: current_target.section_offset,
                            }
                        });
                    if let Some(cache_key) = cache_key {
                        if let Some(stable) = unmatched_target_stability.get(&cache_key) {
                            *stable
                        } else {
                            let stable = unmatched_macho_data_relocation_target_is_stable(
                                &previous_file,
                                &current_file,
                                previous_context.target,
                                current_context.target,
                                &previous_target,
                                &current_target,
                            )?;
                            unmatched_target_stability.insert(cache_key, stable);
                            stable
                        }
                    } else {
                        unmatched_macho_data_relocation_target_is_stable(
                            &previous_file,
                            &current_file,
                            previous_context.target,
                            current_context.target,
                            &previous_target,
                            &current_target,
                        )?
                    }
                } else {
                    false
                };
                if target_section.is_none() && !unmatched_target_is_stable {
                    return Ok(Err(format!(
                        "missing Mach-O data relocation target section in {}",
                        display_hex_path(&input.path)
                    )));
                }
                if target_section.is_some_and(|target_section| {
                    target_section.previous.output_offset != target_section.current.output_offset
                }) {
                    return Ok(Err(format!(
                        "moved Mach-O data relocation target in {}",
                        display_hex_path(&input.path)
                    )));
                }
                let expected_target_section_index =
                    relocation_target_record_index(previous_target.section_index)?;
                let target_matches = if let Some(target) = relocation.target.as_ref() {
                    target.input_file == input.path
                        && target.section_index == expected_target_section_index
                        && target.section_offset == previous_target.section_offset
                        && patch_input_refs_match(
                            input.path.as_str(),
                            target.input.as_str(),
                            patch_section.previous.input.as_str(),
                            normalize_rust_archive_patch_inputs,
                        )?
                } else {
                    false
                };
                if !target_matches {
                    return Ok(Err(format!(
                        "previous Mach-O data relocation target changed in {}",
                        display_hex_path(&input.path)
                    )));
                }
                let target_address = if let Some(target_section) = target_section {
                    let Some(target_address) = macho_output_address_for_file_offset(
                        &output_file,
                        target_section
                            .current
                            .output_offset
                            .checked_add(current_target.section_offset)
                            .context("Mach-O data relocation target output offset overflow")?,
                    ) else {
                        return Ok(Err(format!(
                            "Mach-O data relocation target has no output address in {}",
                            display_hex_path(&input.path)
                        )));
                    };
                    target_address
                } else {
                    relocation.target_value
                };
                if target_address != relocation.target_value
                    || relocation.applied_target_value != Some(relocation.target_value)
                {
                    return Ok(Err(format!(
                        "Mach-O data relocation target value changed in {}",
                        display_hex_path(&input.path)
                    )));
                }
                let previous_record = relocation.clone();
                if relocation.input != patch_section.current.input {
                    relocation.input = patch_section.current.input.clone().into();
                }
                relocation.section_index = patch_section.current.section_index;
                let target = relocation.target.as_mut().unwrap();
                if target.input != patch_section.current.input {
                    target.input = patch_section.current.input.clone().into();
                }
                target.section_index =
                    relocation_target_record_index(current_target.section_index)?;
                target.section_offset = current_target.section_offset;
                changed |= *relocation != previous_record;
            }
        }
    }
    Ok(Ok(changed))
}

fn macho_data_relocation_semantics_are_stable(
    previous_context: &MachODataRelocationContext,
    current_context: &MachODataRelocationContext,
    relocation: &RelocationRecord,
    previous_identity: &Option<(Vec<u8>, Option<object::SectionIndex>)>,
    current_identity: &Option<(Vec<u8>, Option<object::SectionIndex>)>,
) -> bool {
    previous_context.range == current_context.range
        && previous_context.range.start as u64 == relocation.relocation_offset
        && previous_context.addend == current_context.addend
        && previous_context.addend == relocation.addend
        && previous_identity.is_some()
        && previous_identity == current_identity
}

#[cfg(test)]
fn macho_catalog_data_relocation_target_is_stable(
    previous_identity: &Option<(Vec<u8>, Option<object::SectionIndex>)>,
    current_identity: &Option<(Vec<u8>, Option<object::SectionIndex>)>,
    relocation: &RelocationRecord,
    resolutions: &[MachOSymbolResolutionRecord],
    normalize_rust_archive_patch_inputs: bool,
) -> std::result::Result<bool, String> {
    macho_catalog_data_relocation_target_is_stable_with_lookup(
        previous_identity,
        current_identity,
        relocation,
        resolutions,
        &MachOSymbolResolutionLookup::new(resolutions),
        normalize_rust_archive_patch_inputs,
    )
}

fn macho_relocation_target_records_are_stable(
    previous: Option<&RelocationTargetRecord>,
    current: Option<&RelocationTargetRecord>,
    normalize_rust_archive_patch_inputs: bool,
) -> std::result::Result<bool, String> {
    let (Some(previous), Some(current)) = (previous, current) else {
        return Ok(previous == current);
    };
    if previous.input_file != current.input_file
        || previous.section_index != current.section_index
        || previous.section_offset != current.section_offset
    {
        return Ok(false);
    }
    if previous.input == current.input {
        return Ok(true);
    }
    if !normalize_rust_archive_patch_inputs {
        return Ok(false);
    }
    normalized_archive_input_refs_match(
        previous.input_file.as_str(),
        previous.input.as_str(),
        current.input.as_str(),
    )
    .map_err(|error| format!("failed to compare Mach-O data relocation owners: {error:#?}"))
}

fn macho_catalog_data_relocation_target_is_stable_with_lookup(
    previous_identity: &Option<(Vec<u8>, Option<object::SectionIndex>)>,
    current_identity: &Option<(Vec<u8>, Option<object::SectionIndex>)>,
    relocation: &RelocationRecord,
    resolutions: &[MachOSymbolResolutionRecord],
    resolution_lookup: &MachOSymbolResolutionLookup<'_>,
    normalize_rust_archive_patch_inputs: bool,
) -> std::result::Result<bool, String> {
    let (Some((previous_name, _)), Some((current_name, _))) = (previous_identity, current_identity)
    else {
        return Ok(false);
    };
    if previous_name != current_name {
        return Ok(false);
    }
    let encoded_name = hex::encode(previous_name);
    let Some(resolution_index) = resolution_lookup.unique_index_encoded(&encoded_name)? else {
        return Ok(false);
    };
    let resolution = &resolutions[resolution_index];
    Ok(resolution.direct_value == Some(relocation.target_value)
        && macho_relocation_target_records_are_stable(
            resolution.target.as_ref(),
            relocation.target.as_ref(),
            normalize_rust_archive_patch_inputs,
        )?
        && relocation.applied_target_value == Some(relocation.target_value))
}

fn macho_data_relocation_layout_is_stable(
    previous_context_count: usize,
    current_context_count: usize,
    relocation_record_count: usize,
    preserves_record_locations: bool,
) -> bool {
    previous_context_count == current_context_count
        && previous_context_count == relocation_record_count
        && preserves_record_locations
}

fn macho_aarch64_thunk_target_is_reachable(thunk_address: u64, target_address: u64) -> bool {
    let thunk_page = thunk_address & !linker_utils::elf::PAGE_MASK_4KB;
    let target_page = target_address & !linker_utils::elf::PAGE_MASK_4KB;
    let page_delta = i128::from(target_page) - i128::from(thunk_page);
    let page_count = page_delta / i128::from(linker_utils::elf::SIZE_4KB);
    (-(1_i128 << 20)..(1_i128 << 20)).contains(&page_count)
}

fn macho_text_patch_thunk_range(
    patch: &ResolvedSectionPatch,
    output_file: &object::File<'_>,
    thunk_address: u64,
    thunk_size: usize,
) -> std::result::Result<Option<std::ops::Range<usize>>, String> {
    let Some(section_address) =
        macho_output_address_for_file_offset(output_file, patch.section.output_offset)
    else {
        return Err("Mach-O text patch section has no output address".to_owned());
    };
    let Some(start) = thunk_address.checked_sub(section_address) else {
        return Ok(None);
    };
    let Some(end) = start.checked_add(thunk_size as u64) else {
        return Err("Mach-O text thunk range overflowed".to_owned());
    };
    if end > patch.section.output_size {
        return Ok(None);
    }
    let start = usize::try_from(start)
        .map_err(|_| "Mach-O text thunk offset does not fit usize".to_owned())?;
    let end =
        usize::try_from(end).map_err(|_| "Mach-O text thunk end does not fit usize".to_owned())?;
    Ok(Some(start..end))
}

fn materialize_recorded_macho_text_thunk(
    patch: &mut ResolvedSectionPatch,
    output_file: &object::File<'_>,
    thunk_address: u64,
    target_address: u64,
    thunk_size: usize,
) -> std::result::Result<Option<std::ops::Range<usize>>, String> {
    let Some(range) = macho_text_patch_thunk_range(patch, output_file, thunk_address, thunk_size)?
    else {
        return Ok(None);
    };
    let input_size = usize::try_from(patch.section.input_size)
        .map_err(|_| "Mach-O text patch input size does not fit usize".to_owned())?;
    if range.start < input_size {
        return Err("recorded Mach-O text thunk overlaps the current input section".to_owned());
    }
    if thunk_address % 4 != 0 {
        return Err("recorded Mach-O text thunk is not instruction-aligned".to_owned());
    }
    if !macho_aarch64_thunk_target_is_reachable(thunk_address, target_address) {
        return Err("recorded Mach-O text thunk target is out of ADRP range".to_owned());
    }
    patch.patch.data.resize(range.end, 0);
    <crate::macho_aarch64::MachOAArch64 as crate::platform::Arch>::write_thunk(
        thunk_address,
        target_address,
        &mut patch.patch.data[range.clone()],
    );
    Ok(Some(range))
}

fn allocate_macho_text_thunk(
    patch: &mut ResolvedSectionPatch,
    output_file: &object::File<'_>,
    previous_output: &[u8],
    target_address: u64,
    thunk_size: usize,
) -> std::result::Result<Option<(u64, std::ops::Range<usize>)>, String> {
    let input_size = usize::try_from(patch.section.input_size)
        .map_err(|_| "Mach-O text patch input size does not fit usize".to_owned())?;
    let output_size = usize::try_from(patch.section.output_size)
        .map_err(|_| "Mach-O text patch output size does not fit usize".to_owned())?;
    let mut start = patch.patch.data.len().max(input_size).next_multiple_of(4);
    loop {
        let Some(end) = start.checked_add(thunk_size) else {
            return Err("Mach-O text thunk allocation overflowed".to_owned());
        };
        if end > output_size {
            return Ok(None);
        }
        let Some(output_start) = patch.section.output_offset.checked_add(start as u64) else {
            return Err("Mach-O text thunk output offset overflowed".to_owned());
        };
        let Some(output_end) = output_start.checked_add(thunk_size as u64) else {
            return Err("Mach-O text thunk output range overflowed".to_owned());
        };
        let output_start_usize = usize::try_from(output_start)
            .map_err(|_| "Mach-O text thunk output offset does not fit usize".to_owned())?;
        let output_end_usize = usize::try_from(output_end)
            .map_err(|_| "Mach-O text thunk output end does not fit usize".to_owned())?;
        let Some(previous_bytes) = previous_output.get(output_start_usize..output_end_usize) else {
            return Err("Mach-O text thunk output range is out of bounds".to_owned());
        };
        if previous_bytes.iter().all(|byte| *byte == 0) {
            let Some(thunk_address) =
                macho_output_address_for_file_offset(output_file, output_start)
            else {
                return Err("Mach-O text thunk has no output address".to_owned());
            };
            if macho_aarch64_thunk_target_is_reachable(thunk_address, target_address) {
                patch.patch.data.resize(end, 0);
                <crate::macho_aarch64::MachOAArch64 as crate::platform::Arch>::write_thunk(
                    thunk_address,
                    target_address,
                    &mut patch.patch.data[start..end],
                );
                return Ok(Some((thunk_address, start..end)));
            }
        }
        start = start
            .checked_add(4)
            .ok_or_else(|| "Mach-O text thunk allocation overflowed".to_owned())?;
    }
}

fn allocate_reserved_macho_text_thunk(
    reserved_ranges: &mut Vec<ReservedRangeRecord>,
    output_file: &object::File<'_>,
    previous_output: &[u8],
    replay: &MachOTextRelocationReplay,
    current_place: u64,
    current_bytes: &[u8],
    thunk_size: usize,
) -> std::result::Result<Option<(u64, SectionPatch)>, String> {
    if replay.r_type != object::macho::ARM64_RELOC_BRANCH26 || replay.chained_rebase_value.is_some()
    {
        return Ok(None);
    }
    let output_section_id = u32::try_from(crate::output_section_id::TEXT.as_usize())
        .map_err(|_| "Mach-O text output section ID does not fit u32".to_owned())?;
    let thunk_size =
        u64::try_from(thunk_size).map_err(|_| "Mach-O text thunk size is too large".to_owned())?;
    let mut candidates = Vec::new();
    for (range_index, range) in reserved_ranges.iter().enumerate() {
        if range.output_section_id != output_section_id || range.alignment_exponent < 2 {
            continue;
        }
        let alignment = crate::alignment::Alignment::from_exponent(range.alignment_exponent.into())
            .map_err(|_| "invalid Mach-O text thunk reserve alignment".to_owned())?;
        let allocation_size = thunk_size
            .checked_add(alignment.mask())
            .map(|size| alignment.align_down(size))
            .ok_or_else(|| "Mach-O text thunk reserve allocation overflowed".to_owned())?;
        if range.size < allocation_size {
            continue;
        }
        let output_end = range
            .output_offset
            .checked_add(allocation_size)
            .ok_or_else(|| "Mach-O text thunk reserve range overflowed".to_owned())?;
        let output_start = usize::try_from(range.output_offset)
            .map_err(|_| "Mach-O text thunk reserve offset does not fit usize".to_owned())?;
        let output_end = usize::try_from(output_end)
            .map_err(|_| "Mach-O text thunk reserve end does not fit usize".to_owned())?;
        let Some(previous_bytes) = previous_output.get(output_start..output_end) else {
            return Err("Mach-O text thunk reserve is outside the previous output".to_owned());
        };
        if previous_bytes.iter().any(|byte| *byte != 0) {
            continue;
        }
        let Some(thunk_address) =
            macho_output_address_for_file_offset(output_file, range.output_offset)
        else {
            continue;
        };
        if !macho_aarch64_thunk_target_is_reachable(thunk_address, replay.current_target_value) {
            continue;
        }
        let Some(relocated_value) =
            macho_aarch64_relocated_value(replay.r_type, thunk_address, 0, current_place)
        else {
            continue;
        };
        let mut relocated = current_bytes.to_vec();
        if replay
            .rel_info
            .write_to_buffer(relocated_value, &mut relocated)
            .is_err()
        {
            continue;
        }
        candidates.push((
            range_index,
            allocation_size,
            thunk_address,
            current_place.abs_diff(thunk_address),
            range.output_offset,
        ));
    }
    let Some((range_index, allocation_size, thunk_address, _, output_offset)) = candidates
        .into_iter()
        .min_by_key(|(_, allocation_size, _, distance, output_offset)| {
            (*allocation_size, *distance, *output_offset)
        })
    else {
        return Ok(None);
    };

    let range = &mut reserved_ranges[range_index];
    range.output_offset = range
        .output_offset
        .checked_add(allocation_size)
        .ok_or_else(|| "Mach-O text thunk reserve offset overflowed".to_owned())?;
    range.size -= allocation_size;
    if range.size == 0 {
        reserved_ranges.swap_remove(range_index);
    }
    reserved_ranges.sort_unstable();
    validate_reserved_ranges(reserved_ranges)
        .map_err(|error| format!("invalid Mach-O text thunk reserves: {error:#?}"))?;

    let mut data = vec![0; thunk_size as usize];
    <crate::macho_aarch64::MachOAArch64 as crate::platform::Arch>::write_thunk(
        thunk_address,
        replay.current_target_value,
        &mut data,
    );
    Ok(Some((
        thunk_address,
        SectionPatch {
            output_offset,
            size: allocation_size,
            data,
            deferred_relocation: None,
            preserve_ranges: Vec::new(),
            adjustments: Vec::new(),
        },
    )))
}

fn apply_macho_text_relocation_replays(
    patches: &mut [ResolvedSectionPatch],
    replays: &MachOTextRelocationReplays,
    previous_output: &[u8],
    relocations: &mut Vec<RelocationRecord>,
    resolutions: &mut [MachOSymbolResolutionRecord],
    reserved_ranges: &mut Vec<ReservedRangeRecord>,
    reserved_thunk_patches: &mut Vec<SectionPatch>,
) -> std::result::Result<bool, String> {
    let output_file = object::File::parse(previous_output)
        .map_err(|error| format!("failed to parse previous Mach-O output: {error}"))?;
    let thunk_size = <crate::macho_aarch64::MachOAArch64 as crate::platform::Arch>::thunk_config()
        .ok_or_else(|| "Mach-O text thunks are unavailable for this architecture".to_owned())?
        .thunk_size as usize;
    let mut records_changed = false;
    let mut local_thunks = Vec::<(usize, u64, u64, std::ops::Range<usize>)>::new();
    for replay in &replays.replays {
        if replay.r_type != object::macho::ARM64_RELOC_BRANCH26 {
            continue;
        }
        let Some(thunk_address) = replay
            .previous_applied_target_value
            .filter(|address| *address != replay.current_target_value)
        else {
            continue;
        };
        let Some(patch_index) = patches.iter().position(|patch| {
            patch.section.input == replay.input
                && patch.section.section_index == replay.section_index
        }) else {
            return Err("missing changed Mach-O text section for relocation replay".to_owned());
        };
        let Some(range) = materialize_recorded_macho_text_thunk(
            &mut patches[patch_index],
            &output_file,
            thunk_address,
            replay.current_target_value,
            thunk_size,
        )?
        else {
            continue;
        };
        if local_thunks
            .iter()
            .any(|(owner, address, target, existing)| {
                *owner == patch_index
                    && existing.start < range.end
                    && range.start < existing.end
                    && (*address != thunk_address || *target != replay.current_target_value)
            })
        {
            return Err("overlapping recorded Mach-O text thunks".to_owned());
        }
        if !local_thunks.iter().any(|(_, address, target, _)| {
            *address == thunk_address && *target == replay.current_target_value
        }) {
            local_thunks.push((
                patch_index,
                thunk_address,
                replay.current_target_value,
                range,
            ));
        }
    }
    let mut rematerialized_records = Vec::new();
    for replay in &replays.replays {
        let Some(patch_index) = patches.iter().position(|patch| {
            patch.section.input == replay.input
                && patch.section.section_index == replay.section_index
        }) else {
            return Err("missing changed Mach-O text section for relocation replay".to_owned());
        };
        let patch = &mut patches[patch_index];
        let current_output_offset = patch
            .section
            .output_offset
            .checked_add(replay.current_range.start as u64)
            .ok_or_else(|| "current Mach-O text relocation offset overflowed".to_owned())?;
        let current_place =
            macho_output_address_for_file_offset(&output_file, current_output_offset)
                .ok_or_else(|| "current Mach-O text relocation has no output address".to_owned())?;
        if let (
            Some(previous_output_offset),
            Some(previous_range),
            Some(previous_written_value),
            Some(previous_applied_target_value),
        ) = (
            replay.previous_output_offset,
            replay.previous_range.as_ref(),
            replay.previous_written_value,
            replay.previous_applied_target_value,
        ) {
            let previous_start = previous_output_offset
                .checked_add(previous_range.start as u64)
                .and_then(|offset| usize::try_from(offset).ok())
                .ok_or_else(|| "previous Mach-O text relocation range overflowed".to_owned())?;
            let previous_end = previous_start
                .checked_add(previous_range.len())
                .ok_or_else(|| "previous Mach-O text relocation range overflowed".to_owned())?;
            let previous_bytes = previous_output
                .get(previous_start..previous_end)
                .ok_or_else(|| {
                    "previous Mach-O text relocation range is out of bounds".to_owned()
                })?;
            let mut replayed_previous = previous_bytes.to_vec();
            replay
                .rel_info
                .write_to_buffer(previous_written_value, &mut replayed_previous)
                .map_err(|error| {
                    format!("failed to validate previous Mach-O text relocation: {error:#}")
                })?;
            if replayed_previous != previous_bytes {
                return Err("previous Mach-O text relocation encoding changed".to_owned());
            }
            let previous_place =
                macho_output_address_for_file_offset(&output_file, previous_start as u64)
                    .ok_or_else(|| {
                        "previous Mach-O text relocation has no output address".to_owned()
                    })?;
            if macho_aarch64_relocated_value(
                replay.r_type,
                previous_applied_target_value,
                macho_aarch64_applied_target_addend(
                    replay.r_type,
                    replay.current_target_value,
                    previous_applied_target_value,
                    replay.addend,
                ),
                previous_place,
            ) != Some(previous_written_value)
            {
                return Err("previous Mach-O text relocation value changed".to_owned());
            }
        }
        let mut candidates = replay.current_relocation_target_candidates.clone();
        candidates.extend(
            local_thunks
                .iter()
                .filter_map(|(owner, address, target, _)| {
                    (*owner == patch_index && *target == replay.current_target_value)
                        .then_some(*address)
                }),
        );
        let resolution_index = if replay.r_type == object::macho::ARM64_RELOC_BRANCH26
            && replay.target_is_global
            && let Some(target_name) = replay.target_name.as_deref()
        {
            macho_symbol_resolution_index_for_name(resolutions, target_name)?.filter(|index| {
                resolutions[*index].direct_value == Some(replay.current_target_value)
            })
        } else {
            None
        };
        if let Some(resolution_index) = resolution_index {
            candidates.extend_from_slice(&resolutions[resolution_index].thunk_addresses);
        }
        let mut seen = HashSet::new();
        candidates.retain(|candidate| seen.insert(*candidate));
        let mut selected = None;
        for target_value in &candidates {
            let Some(relocated_value) = macho_aarch64_relocated_value(
                replay.r_type,
                *target_value,
                macho_aarch64_applied_target_addend(
                    replay.r_type,
                    replay.current_target_value,
                    *target_value,
                    replay.addend,
                ),
                current_place,
            ) else {
                continue;
            };
            let written_value = replay.chained_rebase_value.unwrap_or(relocated_value);
            let mut relocated = patch
                .patch
                .data
                .get(replay.current_range.clone())
                .ok_or_else(|| "current Mach-O text relocation range is out of bounds".to_owned())?
                .to_vec();
            if replay
                .rel_info
                .write_to_buffer(written_value, &mut relocated)
                .is_ok()
            {
                selected = Some((*target_value, written_value, relocated));
                break;
            }
        }
        if selected.is_none()
            && replay.r_type == object::macho::ARM64_RELOC_BRANCH26
            && replay.current_target_value != 0
            && let Some((thunk_address, range)) = allocate_macho_text_thunk(
                patch,
                &output_file,
                previous_output,
                replay.current_target_value,
                thunk_size,
            )?
        {
            let relocated_value =
                macho_aarch64_relocated_value(replay.r_type, thunk_address, 0, current_place)
                    .ok_or_else(|| "Mach-O text thunk branch value overflowed".to_owned())?;
            let written_value = replay.chained_rebase_value.unwrap_or(relocated_value);
            let mut relocated = patch
                .patch
                .data
                .get(replay.current_range.clone())
                .ok_or_else(|| "current Mach-O text relocation range is out of bounds".to_owned())?
                .to_vec();
            if replay
                .rel_info
                .write_to_buffer(written_value, &mut relocated)
                .is_ok()
            {
                local_thunks.push((
                    patch_index,
                    thunk_address,
                    replay.current_target_value,
                    range,
                ));
                selected = Some((thunk_address, written_value, relocated));
            }
        }
        if selected.is_none()
            && let Some(resolution_index) = resolution_index
        {
            let current_bytes = patch
                .patch
                .data
                .get(replay.current_range.clone())
                .ok_or_else(|| "current Mach-O text relocation range is out of bounds".to_owned())?
                .to_vec();
            if let Some((thunk_address, thunk_patch)) = allocate_reserved_macho_text_thunk(
                reserved_ranges,
                &output_file,
                previous_output,
                replay,
                current_place,
                &current_bytes,
                thunk_size,
            )? {
                let relocated_value =
                    macho_aarch64_relocated_value(replay.r_type, thunk_address, 0, current_place)
                        .ok_or_else(|| "Mach-O text thunk branch value overflowed".to_owned())?;
                let mut relocated = current_bytes;
                replay
                    .rel_info
                    .write_to_buffer(relocated_value, &mut relocated)
                    .map_err(|error| {
                        format!("failed to encode reserved Mach-O text thunk branch: {error:#}")
                    })?;
                let thunk_addresses = &mut resolutions[resolution_index].thunk_addresses;
                thunk_addresses.push(thunk_address);
                thunk_addresses.sort_unstable();
                thunk_addresses.dedup();
                reserved_thunk_patches.push(thunk_patch);
                candidates.push(thunk_address);
                selected = Some((thunk_address, relocated_value, relocated));
            }
        }
        let Some((applied_target_value, written_value, relocated)) = selected else {
            let candidates = candidates
                .iter()
                .map(|candidate| format!("{candidate:#x}"))
                .collect::<Vec<_>>()
                .join(", ");
            return Err(format!(
                "no reachable target for Mach-O text relocation in {} section {} offset {}: \
                 type {}, place {current_place:#x}, target {:#x}, candidates [{candidates}]",
                display_hex_text(&replay.input),
                replay.section_index,
                replay.current_range.start,
                replay.r_type,
                replay.current_target_value,
            ));
        };
        let current_bytes = patch
            .patch
            .data
            .get_mut(replay.current_range.clone())
            .ok_or_else(|| "current Mach-O text relocation range is out of bounds".to_owned())?;
        current_bytes.copy_from_slice(&relocated);
        patch
            .patch
            .preserve_ranges
            .retain(|range| range != &replay.current_range);

        if let Some(relocation_index) = replay.relocation_index {
            let relocation = relocations
                .get_mut(relocation_index)
                .ok_or_else(|| "missing recorded Mach-O text relocation".to_owned())?;
            let previous_record = relocation.clone();
            let current_input: SharedText = replay.input.clone().into();
            if relocation.input != current_input
                && !normalized_archive_input_refs_match(
                    replay.input_file.as_str(),
                    relocation.input.as_str(),
                    current_input.as_str(),
                )
                .map_err(|error| {
                    format!(
                        "failed to compare normalized Mach-O relocation input identity: {error:#?}"
                    )
                })?
            {
                relocation.input = current_input;
            }
            relocation.section_index = replay.section_index;
            relocation.relocation_offset = replay.current_range.start as u64;
            relocation.output_offset = current_output_offset;
            relocation.written_value = Some(written_value);
            relocation.target_value = replay.current_target_value;
            relocation.applied_target_value = Some(applied_target_value);
            let previous_target = relocation.target.clone();
            relocation.target = replay.target.clone();
            if let (Some(previous_target), Some(current_target)) =
                (previous_target.as_ref(), relocation.target.as_mut())
                && previous_target.input_file == current_target.input_file
                && previous_target.input != current_target.input
                && normalized_archive_input_refs_match(
                    current_target.input_file.as_str(),
                    previous_target.input.as_str(),
                    current_target.input.as_str(),
                )
                .map_err(|error| {
                    format!(
                        "failed to compare normalized Mach-O relocation target identity: {error:#?}"
                    )
                })?
            {
                current_target.input = previous_target.input.clone();
            }
            if let Some(target) = relocation.target.as_mut() {
                target.section_offset = replay.current_target_section_offset;
            }
            records_changed |= *relocation != previous_record;
        } else {
            rematerialized_records.push(RelocationRecord {
                target_symbol_id: replay.target_symbol_id,
                written_value: Some(written_value),
                target_value: replay.current_target_value,
                applied_target_value: Some(applied_target_value),
                target_name: replay.target_name.clone(),
                target: replay.target.clone(),
                input_file: replay.input_file.clone(),
                input: replay.input.clone().into(),
                section_index: replay.section_index,
                relocation_offset: replay.current_range.start as u64,
                output_offset: current_output_offset,
                size: replay.current_range.len() as u64,
                kind: replay.kind,
                addend: replay.addend,
            });
        }
    }

    if patches.iter().any(|patch| {
        patch.section.section_name.as_deref() == Some("__TEXT,__text")
            && !patch.patch.preserve_ranges.is_empty()
    }) {
        return Err("missing recorded Mach-O text relocation for replay".to_owned());
    }
    if !replays.rematerialized_sections.is_empty() {
        let previous_len = relocations.len();
        let mut retained = Vec::with_capacity(previous_len);
        for relocation in relocations.drain(..) {
            let is_rematerialized = decode_macho_aarch64_relocation_kind(relocation.kind).is_some()
                && relocation_is_in_rematerialized_macho_text_section(
                    &relocation,
                    &replays.rematerialized_sections,
                    replays.normalize_rust_archive_patch_inputs,
                )
                .map_err(|error| error.to_string())?;
            if !is_rematerialized {
                retained.push(relocation);
            }
        }
        *relocations = retained;
        records_changed |= relocations.len() != previous_len;
    }
    if !rematerialized_records.is_empty() {
        records_changed = true;
        relocations.extend(rematerialized_records);
        relocations.sort_unstable();
        relocations.dedup();
    }
    Ok(records_changed)
}

fn macho_output_address_for_file_offset(file: &object::File<'_>, file_offset: u64) -> Option<u64> {
    for section in file.sections() {
        let Some((section_file_offset, section_size)) = section.file_range() else {
            continue;
        };
        let section_end = section_file_offset.checked_add(section_size)?;
        if file_offset >= section_file_offset && file_offset < section_end {
            return section
                .address()
                .checked_add(file_offset.checked_sub(section_file_offset)?);
        }
    }
    None
}

fn macho_output_file_offset_for_address(
    file: &object::File<'_>,
    address: u64,
    size: u64,
) -> std::result::Result<Option<u64>, String> {
    let end = address
        .checked_add(size)
        .ok_or_else(|| "Mach-O output address range overflowed".to_owned())?;
    let mut output_offset = None;
    for section in file.sections() {
        let section_address = section.address();
        let Some(section_end) = section_address.checked_add(section.size()) else {
            return Err("Mach-O output section address range overflowed".to_owned());
        };
        if address < section_address || end > section_end {
            continue;
        }
        let Some((section_file_offset, section_file_size)) = section.file_range() else {
            continue;
        };
        let relative = address - section_address;
        let Some(relative_end) = relative.checked_add(size) else {
            return Err("Mach-O output section-relative range overflowed".to_owned());
        };
        if relative_end > section_file_size {
            continue;
        }
        let Some(candidate) = section_file_offset.checked_add(relative) else {
            return Err("Mach-O output file offset overflowed".to_owned());
        };
        if output_offset.is_some_and(|existing| existing != candidate) {
            return Err("Mach-O output address maps to multiple file ranges".to_owned());
        }
        output_offset = Some(candidate);
    }
    Ok(output_offset)
}

fn section_size_allows_direct_patching(
    section_name: Option<&[u8]>,
    previous_input_size: u64,
    current_input_size: usize,
) -> bool {
    section_name != Some(b"__cstring".as_slice())
        || u64::try_from(current_input_size).is_ok_and(|size| size == previous_input_size)
}

fn cstring_literal_boundaries_are_stable(previous: &[u8], current: &[u8]) -> bool {
    previous.len() == current.len()
        && previous
            .iter()
            .zip(current)
            .all(|(previous, current)| (*previous == 0) == (*current == 0))
}

fn cstring_nul_boundaries_hash(bytes: &[u8]) -> String {
    let mut hasher = blake3::Hasher::new();
    hasher.update(b"sld-cstring-nul-boundaries-v1");
    hasher.update(&(bytes.len() as u64).to_le_bytes());
    for (offset, byte) in bytes.iter().enumerate() {
        if *byte == 0 {
            hasher.update(&(offset as u64).to_le_bytes());
        }
    }
    hasher.finalize().to_hex().to_string()
}

fn cstring_nul_boundaries_hash_for_section(
    section_name: Option<&str>,
    bytes: &[u8],
) -> Option<String> {
    (section_name == Some("__cstring")).then(|| cstring_nul_boundaries_hash(bytes))
}

fn relocation_preserve_ranges<'data>(
    file: &object::File<'data>,
    section: &impl object::ObjectSection<'data>,
    section_data: &[u8],
    dynamic_relocation_offsets: Option<&HashSet<u64>>,
    required_relocation_offsets: Option<&HashSet<u64>>,
) -> Option<Vec<std::ops::Range<usize>>> {
    let mut ranges = Vec::<std::ops::Range<usize>>::new();
    for (offset, relocation) in section.relocations() {
        if relocation.kind() == object::RelocationKind::None {
            continue;
        }
        if required_relocation_offsets.is_some_and(|offsets| !offsets.contains(&offset)) {
            return None;
        }
        let is_recorded_dynamic_relocation =
            dynamic_relocation_offsets.is_some_and(|offsets| offsets.contains(&offset));
        let start = usize::try_from(offset).ok()?;
        let len = usize::from(relocation.size() / 8);
        let end = start.checked_add(len)?;
        if end > section_data.len() {
            return None;
        }
        let generic_explicit_relocation = !relocation.has_implicit_addend()
            && relocation.encoding() == object::RelocationEncoding::Generic
            && relocation.size() != 0
            && relocation.size() % 8 == 0;
        // Mach-O absolute pointers encode their addend in-place. Preserve only
        // the zero-addend form targeting an unchanged input symbol.
        let zero_addend_macho_external_absolute =
            matches!(section.flags(), object::SectionFlags::MachO { .. })
                && relocation.has_implicit_addend()
                && relocation.kind() == object::RelocationKind::Absolute
                && relocation.size() != 0
                && relocation.size() % 8 == 0
                && section_data[start..end].iter().all(|byte| *byte == 0)
                && match relocation.target() {
                    object::RelocationTarget::Symbol(index) => file
                        .symbol_by_index(index)
                        .ok()
                        .is_some_and(|symbol| symbol.is_undefined()),
                    _ => false,
                };
        // These x86-64 ELF operands are contiguous four-byte fields. Standard GOTPCREL is
        // guarded on updates because one instruction form can be rewritten by relaxation.
        let preservable_x86_64_elf_pc_relative =
            matches!(section.flags(), object::SectionFlags::Elf { .. })
                && file.architecture() == object::Architecture::X86_64
                && relocation.size() == 32
                && match (relocation.kind(), relocation.encoding()) {
                    (object::RelocationKind::Relative, object::RelocationEncoding::Generic) => true,
                    (
                        object::RelocationKind::PltRelative,
                        object::RelocationEncoding::Generic | object::RelocationEncoding::X86Branch,
                    ) => true,
                    (object::RelocationKind::GotRelative, object::RelocationEncoding::Generic) => {
                        true
                    }
                    _ => false,
                };
        let explicit_relocation_field = generic_explicit_relocation
            || (!relocation.has_implicit_addend() && preservable_x86_64_elf_pc_relative);
        if !(explicit_relocation_field || zero_addend_macho_external_absolute)
            || (!is_recorded_dynamic_relocation
                && relocation.kind() != object::RelocationKind::Absolute
                && !preservable_x86_64_elf_pc_relative)
        {
            return None;
        }
        ranges.push(start..end);
    }
    ranges.sort_by_key(|range| range.start);
    let mut previous_end = 0;
    for range in &ranges {
        if range.start < previous_end {
            return None;
        }
        previous_end = range.end;
    }
    Some(ranges)
}

fn patchable_bytes_match(
    output: &[u8],
    input: &[u8],
    preserve_ranges: &[std::ops::Range<usize>],
) -> bool {
    if output.len() != input.len() {
        return false;
    }
    let mut position = 0;
    for range in preserve_ranges {
        if output[position..range.start] != input[position..range.start] {
            return false;
        }
        position = range.end;
    }
    output[position..] == input[position..]
}

fn patch_section_name_for_matching<'data>(
    section: &impl object::ObjectSection<'data>,
) -> Option<String> {
    let name = section.name().ok()?;
    if !section_name_is_stable_for_patch_matching(name) {
        return None;
    }
    if matches!(section.flags(), object::SectionFlags::MachO { .. }) {
        let segment = section.segment_name().ok().flatten()?;
        return Some(format!("{segment},{name}"));
    }
    Some(name.to_owned())
}

fn section_name_is_stable_for_patch_matching(name: &str) -> bool {
    !name.is_empty()
        && !name.contains("..L")
        && !name.contains(".L__")
        && !name.contains("__unnamed_")
}

fn patch_input_bytes<'data>(
    bytes: &'data [u8],
    input_file_path: &str,
    input_ref: &str,
) -> Result<Option<PatchInputBytes<'data>>> {
    patch_input_bytes_with_lookup(
        bytes,
        input_file_path,
        input_ref,
        PatchInputLookup::MatchArchiveMember,
    )
}

fn patch_input_bytes_with_lookup<'data>(
    bytes: &'data [u8],
    input_file_path: &str,
    input_ref: &str,
    lookup: PatchInputLookup,
) -> Result<Option<PatchInputBytes<'data>>> {
    let Some(parsed) = parse_patch_input_ref(input_file_path, input_ref)? else {
        return Ok(Some(PatchInputBytes {
            bytes,
            file_offset: 0,
            archive_identifier: None,
        }));
    };
    if parsed.range.is_empty() {
        return Ok(None);
    }

    if matches!(lookup, PatchInputLookup::CurrentRecordedRange) {
        let Some(input_bytes) = bytes.get(parsed.range.clone()) else {
            return Ok(None);
        };
        return Ok(Some(PatchInputBytes {
            bytes: input_bytes,
            file_offset: parsed.range.start,
            archive_identifier: None,
        }));
    }

    match patch_archive_member_bytes(bytes, &parsed.identifier)? {
        ArchiveMemberMatch::Unique(member) => return Ok(Some(member)),
        ArchiveMemberMatch::Ambiguous => return Ok(None),
        ArchiveMemberMatch::Unavailable => {}
    }

    let Some(input_bytes) = bytes.get(parsed.range.clone()) else {
        return Ok(None);
    };
    Ok(Some(PatchInputBytes {
        bytes: input_bytes,
        file_offset: parsed.range.start,
        archive_identifier: None,
    }))
}

#[cfg(test)]
fn patch_input_range(
    input_file_path: &str,
    input_ref: &str,
) -> Result<Option<std::ops::Range<usize>>> {
    Ok(parse_patch_input_ref(input_file_path, input_ref)?.map(|input_ref| input_ref.range))
}

fn parse_patch_input_ref(
    input_file_path: &str,
    input_ref: &str,
) -> Result<Option<ParsedPatchInputRef>> {
    let input_file_path_bytes =
        hex::decode(input_file_path).context("Malformed incremental input file path")?;
    let input_ref_bytes = hex::decode(input_ref).context("Malformed incremental input ref")?;
    if input_ref_bytes == input_file_path_bytes {
        return Ok(None);
    }

    let Some(rest) = input_ref_bytes
        .strip_prefix(input_file_path_bytes.as_slice())
        .and_then(|rest| rest.strip_prefix(&[0]))
    else {
        return Ok(Some(ParsedPatchInputRef {
            identifier: Vec::new(),
            range: 0..0,
        }));
    };
    let Some(separator) = rest.iter().position(|byte| *byte == 0) else {
        return Ok(Some(ParsedPatchInputRef {
            identifier: Vec::new(),
            range: 0..0,
        }));
    };
    let identifier = rest[..separator].to_vec();
    let range_bytes = &rest[separator + 1..];
    let range =
        std::str::from_utf8(range_bytes).context("Malformed incremental archive member range")?;
    let Some((start, end)) = range.split_once(':') else {
        return Ok(Some(ParsedPatchInputRef {
            identifier: Vec::new(),
            range: 0..0,
        }));
    };
    let start = start
        .parse()
        .context("Invalid incremental archive member start offset")?;
    let end = end
        .parse()
        .context("Invalid incremental archive member end offset")?;
    if start > end {
        return Ok(Some(ParsedPatchInputRef {
            identifier: Vec::new(),
            range: 0..0,
        }));
    }
    Ok(Some(ParsedPatchInputRef {
        identifier,
        range: start..end,
    }))
}

fn normalized_archive_input_refs_match(
    input_file_path: &str,
    previous_input_ref: &str,
    current_input_ref: &str,
) -> Result<bool> {
    let Some(previous) = parse_patch_input_ref(input_file_path, previous_input_ref)? else {
        return Ok(false);
    };
    let Some(current) = parse_patch_input_ref(input_file_path, current_input_ref)? else {
        return Ok(false);
    };
    if previous.identifier.is_empty() || current.identifier.is_empty() {
        return Ok(false);
    }
    Ok(archive_member_patch_identifier(&previous.identifier)
        == archive_member_patch_identifier(&current.identifier))
}

fn normalized_archive_input_ref_matches_identifiers(
    input_file_path: &str,
    input_ref: &str,
    normalized_identifiers: &HashSet<Vec<u8>>,
) -> Result<bool> {
    let Some(parsed) = parse_patch_input_ref(input_file_path, input_ref)? else {
        return Ok(false);
    };
    Ok(!parsed.identifier.is_empty()
        && normalized_identifiers.contains(&archive_member_patch_identifier(&parsed.identifier)))
}

fn patch_archive_member_bytes<'data>(
    bytes: &'data [u8],
    identifier: &[u8],
) -> Result<ArchiveMemberMatch<'data>> {
    if identifier.is_empty() {
        return Ok(ArchiveMemberMatch::Unavailable);
    }
    let patch_identifier = archive_member_patch_identifier(identifier);
    let Ok(archive) = ArchiveIterator::from_archive_bytes(bytes) else {
        return Ok(ArchiveMemberMatch::Unavailable);
    };
    let mut matched = None;
    let mut matched_rank = None;
    for entry in archive {
        match entry? {
            ArchiveEntry::Regular(content) => {
                let candidate = archive_member_patch_identifier(content.ident.as_slice());
                let rank = if candidate == identifier {
                    0
                } else if candidate == patch_identifier {
                    1
                } else {
                    continue;
                };
                if matched_rank.is_some_and(|matched_rank| rank > matched_rank) {
                    continue;
                }
                if matched_rank.is_some_and(|matched_rank| rank < matched_rank) {
                    matched = None;
                }
                let member = PatchInputBytes {
                    bytes: content.entry_data,
                    file_offset: content.data_offset,
                    archive_identifier: Some(content.ident.as_slice()),
                };
                if matched.replace(member).is_some() {
                    return Ok(ArchiveMemberMatch::Ambiguous);
                }
                matched_rank = Some(rank);
            }
            ArchiveEntry::Thin(_) => {}
        }
    }
    Ok(matched.map_or(ArchiveMemberMatch::Unavailable, ArchiveMemberMatch::Unique))
}

fn archive_members_match_snapshot(
    state_dir: &Path,
    previous_input: &FileState,
    previous_bytes: Option<&[u8]>,
    current_bytes: &[u8],
    normalize_rust_archive_patch_inputs: bool,
) -> Result<bool> {
    let current_members = if normalize_rust_archive_patch_inputs {
        archive_member_patch_identifiers(current_bytes)?
    } else {
        archive_member_identifiers(current_bytes)?
    };
    if current_members.is_none() && !stored_patch_state_references_archive_member(previous_input) {
        return Ok(true);
    }
    let Some(previous_bytes) = previous_bytes else {
        return Ok(false);
    };
    let previous_members = if normalize_rust_archive_patch_inputs {
        archive_member_patch_identifiers(previous_bytes)?
    } else {
        archive_member_identifiers(previous_bytes)?
    };
    let members_match = previous_members == current_members;
    if !members_match {
        if let (Some(previous), Some(current)) = (&previous_members, &current_members) {
            append_log(
                state_dir,
                &format!(
                    "archive member identifier sequence differed: previous={} current={}",
                    previous.len(),
                    current.len(),
                ),
            )?;
        }
    }
    Ok(members_match)
}

#[cfg(test)]
fn added_archive_member_identifiers(
    previous_bytes: &[u8],
    current_bytes: &[u8],
    normalize_rust_archive_patch_inputs: bool,
) -> Result<Option<Vec<Vec<u8>>>> {
    let Some(delta) = archive_member_identifier_delta(
        previous_bytes,
        current_bytes,
        normalize_rust_archive_patch_inputs,
    )?
    else {
        return Ok(None);
    };
    if !delta.removed.is_empty() || delta.added.is_empty() {
        return Ok(None);
    }
    Ok(Some(delta.added))
}

fn archive_member_identifier_delta(
    previous_bytes: &[u8],
    current_bytes: &[u8],
    normalize_rust_archive_patch_inputs: bool,
) -> Result<Option<ArchiveMemberIdentifierDelta>> {
    let Some(previous) = archive_member_identifiers(previous_bytes)? else {
        return Ok(None);
    };
    let Some(current) = archive_member_identifiers(current_bytes)? else {
        return Ok(None);
    };
    let normalize = |identifier: &[u8]| {
        if normalize_rust_archive_patch_inputs {
            archive_member_patch_identifier(identifier)
        } else {
            identifier.to_vec()
        }
    };
    let mut previous_positions = HashMap::with_capacity(previous.len());
    for (index, identifier) in previous.iter().enumerate() {
        if previous_positions
            .insert(normalize(identifier), index)
            .is_some()
        {
            return Ok(None);
        }
    }
    let mut current_positions = HashMap::with_capacity(current.len());
    for (index, identifier) in current.iter().enumerate() {
        if current_positions
            .insert(normalize(identifier), index)
            .is_some()
        {
            return Ok(None);
        }
    }

    let mut previous_common_position = None;
    for identifier in &previous {
        let identifier = normalize(identifier);
        let Some(&current_position) = current_positions.get(&identifier) else {
            continue;
        };
        if previous_common_position.is_some_and(|previous| current_position <= previous) {
            return Ok(None);
        }
        previous_common_position = Some(current_position);
    }

    let added = current
        .iter()
        .filter(|identifier| !previous_positions.contains_key(&normalize(identifier)))
        .cloned()
        .collect::<Vec<_>>();
    let removed = previous
        .iter()
        .filter(|identifier| !current_positions.contains_key(&normalize(identifier)))
        .cloned()
        .collect::<Vec<_>>();
    if added.is_empty() && removed.is_empty() {
        return Ok(None);
    }
    Ok(Some(ArchiveMemberIdentifierDelta { added, removed }))
}

fn owned_macho_archive_removal_indices(
    patch: &FilePatchState,
    removed_identifiers: &[Vec<u8>],
) -> std::result::Result<MachOArchiveRemovalOwnership, String> {
    let mut remaining = HashSet::with_capacity(removed_identifiers.len());
    for identifier in removed_identifiers {
        if !remaining.insert(archive_member_patch_identifier(identifier)) {
            return Err("removed Mach-O archive member identity is ambiguous".to_owned());
        }
    }
    let mut indices = Vec::new();
    for (index, state) in patch.macho_archive_members.iter().enumerate() {
        if state.kind != MachOArchiveActivationKind::AddedMembers
            || !state.active
            || !state
                .members
                .iter()
                .any(|member| remaining.contains(member.normalized_identifier.as_slice()))
        {
            continue;
        }
        if state
            .members
            .iter()
            .any(|member| !remaining.contains(member.normalized_identifier.as_slice()))
        {
            return Err("removed Mach-O archive members split an activation cohort".to_owned());
        }
        if !macho_archive_transaction_patches_match(state) {
            return Err("removed Mach-O archive activation transaction is incomplete".to_owned());
        }
        for member in &state.members {
            remaining.remove(member.normalized_identifier.as_slice());
        }
        indices.push(index);
    }
    let initially_owned_identifiers = removed_identifiers
        .iter()
        .map(|identifier| archive_member_patch_identifier(identifier))
        .filter(|identifier| remaining.contains(identifier.as_slice()))
        .collect();
    Ok(MachOArchiveRemovalOwnership {
        tracked_indices: indices,
        initially_owned_identifiers,
    })
}

fn macho_archive_transaction_patches_match(state: &MachOArchiveActivationState) -> bool {
    !state.forward_patches.is_empty()
        && state.forward_patches.len() == state.rollback_patches.len()
        && state
            .forward_patches
            .iter()
            .zip(&state.rollback_patches)
            .all(|(forward, rollback)| {
                forward.output_offset == rollback.output_offset
                    && forward.data.len() == rollback.data.len()
            })
}

fn initially_owned_macho_archive_removal_state(
    previous_bytes: &[u8],
    input_file_path: &str,
    patch: &FilePatchState,
    normalized_identifier: &[u8],
) -> Result<std::result::Result<MachOArchiveActivationState, String>> {
    let member = match patch_archive_member_bytes(previous_bytes, normalized_identifier)? {
        ArchiveMemberMatch::Unique(member) => member,
        ArchiveMemberMatch::Unavailable | ArchiveMemberMatch::Ambiguous => {
            return Ok(Err(
                "could not validate initially owned removed Mach-O archive member".to_owned(),
            ));
        }
    };
    let normalized_identifiers = HashSet::from([normalized_identifier.to_vec()]);
    let mut sections = Vec::new();
    for section in &patch.sections {
        if normalized_archive_input_ref_matches_identifiers(
            input_file_path,
            section.input.as_str(),
            &normalized_identifiers,
        )? {
            sections.push(section.clone());
        }
    }
    if sections.is_empty() {
        return Ok(Err(
            "removed Mach-O archive member has no active ownership record".to_owned(),
        ));
    }
    Ok(Ok(MachOArchiveActivationState {
        kind: MachOArchiveActivationKind::AddedMembers,
        members: vec![MachOArchiveMemberIdentity {
            normalized_identifier: normalized_identifier.to_vec(),
            object_hash: hash_bytes(member.bytes),
        }],
        active: true,
        sections,
        relocations: Vec::new(),
        symbol_resolutions: Vec::new(),
        rollback_symbol_resolutions: Vec::new(),
        forward_patches: Vec::new(),
        rollback_patches: Vec::new(),
    }))
}

fn retain_initial_macho_archive_removal_transaction(
    state: &mut MachOArchiveActivationState,
    previous_output: &[u8],
) -> std::result::Result<(), String> {
    let output_file = object::File::parse(previous_output)
        .map_err(|_| "failed to parse output for initial Mach-O member retirement".to_owned())?;
    let symbol_table_offset = macho_symbol_table_offset_for_recycling(previous_output)?;
    let mut forward_patches = Vec::new();
    let mut rollback_patches = Vec::new();
    for resolution in &state.symbol_resolutions {
        let Some(value) = resolution.direct_value else {
            return Err("initially owned removed Mach-O symbol has no direct value".to_owned());
        };
        if resolution.got_address.is_some()
            || resolution.stub_address.is_some()
            || !resolution.thunk_addresses.is_empty()
            || resolution.target.is_none()
        {
            return Err("initially owned removed Mach-O symbol uses an indirect target".to_owned());
        }
        let name = hex::decode(resolution.name.as_str())
            .map_err(|_| "malformed initially owned removed Mach-O symbol name".to_owned())?;
        let symbol_index = unique_macho_output_symbol_index(&output_file, &name, value)?;
        let range = macho_symbol_entry_range(previous_output, symbol_table_offset, symbol_index)?;
        let entry = previous_output
            .get(range.clone())
            .ok_or_else(|| "initial Mach-O member symbol entry is outside output".to_owned())?;
        if entry.len() != std::mem::size_of::<object::macho::Nlist64<object::Endianness>>()
            || entry[4] & object::macho::N_STAB != 0
            || entry[4] & object::macho::N_TYPE != object::macho::N_SECT
            || entry[4] & object::macho::N_EXT == 0
        {
            return Err(
                "initially owned removed Mach-O symbol is not an external definition".to_owned(),
            );
        }
        let mut retired_entry = entry.to_vec();
        retired_entry[..std::mem::size_of::<u32>()].fill(0);
        forward_patches.push(StoredOutputPatch {
            output_offset: range.start as u64,
            data: entry.to_vec(),
        });
        rollback_patches.push(StoredOutputPatch {
            output_offset: range.start as u64,
            data: retired_entry,
        });
    }
    if forward_patches.is_empty() {
        let Some(section) = state
            .sections
            .iter()
            .find(|section| section.output_size != 0)
        else {
            return Err("initially owned removed Mach-O member has no output bytes".to_owned());
        };
        let offset = usize::try_from(section.output_offset)
            .map_err(|_| "initial Mach-O member output offset is too large".to_owned())?;
        let byte = *previous_output
            .get(offset)
            .ok_or_else(|| "initial Mach-O member output is outside output".to_owned())?;
        forward_patches.push(StoredOutputPatch {
            output_offset: section.output_offset,
            data: vec![byte],
        });
        rollback_patches.push(StoredOutputPatch {
            output_offset: section.output_offset,
            data: vec![byte],
        });
    }
    state.forward_patches = forward_patches;
    state.rollback_patches = rollback_patches;
    Ok(())
}

fn dormant_macho_archive_reactivation_index(
    patch: &FilePatchState,
    added_identifiers: &[Vec<u8>],
) -> std::result::Result<Option<usize>, String> {
    let mut added = HashSet::with_capacity(added_identifiers.len());
    for identifier in added_identifiers {
        if !added.insert(archive_member_patch_identifier(identifier)) {
            return Err("added Mach-O archive member identity is ambiguous".to_owned());
        }
    }

    let mut matched = None;
    for (index, state) in patch.macho_archive_members.iter().enumerate() {
        if state.kind != MachOArchiveActivationKind::AddedMembers
            || !state
                .members
                .iter()
                .any(|member| added.contains(member.normalized_identifier.as_slice()))
        {
            continue;
        }
        if state.active {
            return Err("added Mach-O archive member already has active ownership".to_owned());
        }
        if state
            .members
            .iter()
            .any(|member| !added.contains(member.normalized_identifier.as_slice()))
        {
            return Err(
                "added Mach-O archive members split a dormant activation cohort".to_owned(),
            );
        }
        if !macho_archive_transaction_patches_match(state) {
            return Err("dormant Mach-O archive activation transaction is incomplete".to_owned());
        }
        if matched.replace(index).is_some() {
            return Err("added Mach-O archive members span dormant activation cohorts".to_owned());
        }
        for member in &state.members {
            added.remove(member.normalized_identifier.as_slice());
        }
    }
    if matched.is_some() && !added.is_empty() {
        return Err("added Mach-O archive members mix dormant and new ownership".to_owned());
    }
    Ok(matched)
}

fn refreshed_macho_archive_input_ref(
    input_file_path: &str,
    input_ref: &str,
    current_resolver: &PatchInputResolver<'_>,
    refreshed: &mut HashMap<String, String>,
) -> Result<std::result::Result<String, String>> {
    if let Some(current) = refreshed.get(input_ref) {
        return Ok(Ok(current.clone()));
    }
    let Some(parsed) = parse_patch_input_ref(input_file_path, input_ref)? else {
        return Ok(Ok(input_ref.to_owned()));
    };
    if parsed.identifier.is_empty() {
        return Ok(Err(
            "retained Mach-O archive record has no member identity".to_owned()
        ));
    }
    let Some(input) = current_resolver.resolve(
        input_file_path,
        input_ref,
        PatchInputLookup::MatchArchiveMember,
    )?
    else {
        return Ok(Err(
            "could not resolve retained Mach-O archive member".to_owned()
        ));
    };
    if input.archive_identifier.is_none() {
        return Ok(Err(
            "retained Mach-O archive member identity is no longer unique".to_owned(),
        ));
    }
    let current = resolved_patch_input_ref(input_file_path, input_ref, input)?;
    refreshed.insert(input_ref.to_owned(), current.clone());
    Ok(Ok(current))
}

fn reactivated_macho_archive_text_activation(
    current_bytes: &[u8],
    input_file_path: &str,
    added_identifiers: &[Vec<u8>],
    current_resolver: &PatchInputResolver<'_>,
    patch: &FilePatchState,
    resolutions: &[MachOSymbolResolutionRecord],
    reserved_ranges: &[ReservedRangeRecord],
) -> Result<std::result::Result<Option<AddedMachOArchiveTextActivations>, String>> {
    let Some(index) = dormant_macho_archive_reactivation_index(patch, added_identifiers)? else {
        return Ok(Ok(None));
    };
    let mut state = patch.macho_archive_members[index].clone();
    let normalized_identifiers = added_identifiers
        .iter()
        .map(|identifier| archive_member_patch_identifier(identifier))
        .collect::<Vec<_>>();
    if !state
        .members
        .iter()
        .map(|member| member.normalized_identifier.as_slice())
        .eq(normalized_identifiers.iter().map(Vec::as_slice))
    {
        return Ok(Err(
            "added Mach-O archive member order changed from dormant ownership".to_owned(),
        ));
    }
    for member in &state.members {
        let matched =
            match patch_archive_member_bytes(current_bytes, &member.normalized_identifier)? {
                ArchiveMemberMatch::Unique(member) => member,
                ArchiveMemberMatch::Unavailable | ArchiveMemberMatch::Ambiguous => {
                    return Ok(Err(
                        "could not validate reactivated Mach-O archive member ownership".to_owned(),
                    ));
                }
            };
        if hash_bytes(matched.bytes) != member.object_hash {
            return Ok(Err(
                "reactivated Mach-O archive member changed while dormant".to_owned(),
            ));
        }
    }

    let mut refreshed = HashMap::new();
    for section in &mut state.sections {
        section.input = match refreshed_macho_archive_input_ref(
            input_file_path,
            section.input.as_str(),
            current_resolver,
            &mut refreshed,
        )? {
            Ok(input) => input,
            Err(reason) => return Ok(Err(reason)),
        };
    }
    for relocation in &mut state.relocations {
        relocation.input = match refreshed_macho_archive_input_ref(
            input_file_path,
            relocation.input.as_str(),
            current_resolver,
            &mut refreshed,
        )? {
            Ok(input) => input.into(),
            Err(reason) => return Ok(Err(reason)),
        };
        if let Some(target) = relocation
            .target
            .as_mut()
            .filter(|target| target.input_file == input_file_path)
        {
            target.input = match refreshed_macho_archive_input_ref(
                input_file_path,
                target.input.as_str(),
                current_resolver,
                &mut refreshed,
            )? {
                Ok(input) => input.into(),
                Err(reason) => return Ok(Err(reason)),
            };
        }
    }
    for resolution in &mut state.symbol_resolutions {
        if let Some(target) = resolution
            .target
            .as_mut()
            .filter(|target| target.input_file == input_file_path)
        {
            target.input = match refreshed_macho_archive_input_ref(
                input_file_path,
                target.input.as_str(),
                current_resolver,
                &mut refreshed,
            )? {
                Ok(input) => input.into(),
                Err(reason) => return Ok(Err(reason)),
            };
        }
    }
    for rollback in &state.rollback_symbol_resolutions {
        let index =
            match macho_symbol_resolution_index_for_name(resolutions, rollback.name.as_str()) {
                Ok(Some(index)) => index,
                Ok(None) => {
                    return Ok(Err(
                        "reactivated Mach-O archive rollback symbol is no longer live".to_owned(),
                    ));
                }
                Err(reason) => return Ok(Err(reason)),
            };
        if resolutions[index] != *rollback {
            return Ok(Err(
                "reactivated Mach-O archive rollback symbol changed while dormant".to_owned(),
            ));
        }
    }

    let sections = state
        .sections
        .iter()
        .map(|section| PatchSection {
            input: section.input.clone(),
            section_index: section.section_index,
            section_name: section.section_name.clone(),
            input_size: section.input_size,
            output_offset: section.output_offset,
            output_size: section.output_size,
            data_hash: section.data_hash.clone(),
            cstring_nul_boundaries_hash: section.cstring_nul_boundaries_hash.clone(),
        })
        .collect::<Vec<_>>();
    let records = sections
        .iter()
        .map(|section| SectionRecord {
            input_file: input_file_path.into(),
            input: section.input.clone().into(),
            section_index: section.section_index,
            output_offset: section.output_offset,
            size: section.output_size,
        })
        .collect();
    let reactivated_relocations = std::mem::take(&mut state.relocations);
    let symbol_resolutions = std::mem::take(&mut state.symbol_resolutions);
    let recycled_symbol_resolution_names = state
        .rollback_symbol_resolutions
        .iter()
        .map(|resolution| resolution.name.clone())
        .collect();
    let reactivated_output_patches = state
        .forward_patches
        .iter()
        .map(|patch| SectionPatch {
            output_offset: patch.output_offset,
            size: patch.data.len() as u64,
            data: patch.data.clone(),
            deferred_relocation: None,
            preserve_ranges: Vec::new(),
            adjustments: Vec::new(),
        })
        .collect();
    state.active = true;

    Ok(Ok(Some(AddedMachOArchiveTextActivations {
        normalized_identifiers,
        member_states: vec![state],
        reactivated: true,
        reactivated_relocations,
        reactivated_output_patches,
        sections,
        records,
        symbol_resolutions,
        recycled_symbol_resolution_names,
        symbol_table_patches: Vec::new(),
        chained_fixup_patches: Vec::new(),
        unwind_patches: Vec::new(),
        relocation_replays: Vec::new(),
        provisional_relocations: Vec::new(),
        previous_unwind_input_ranges: Vec::new(),
        current_unwind_input_ranges: Vec::new(),
        remaining_reserved_ranges: reserved_ranges.to_vec(),
    })))
}

fn archive_member_set_proof_matches_current(
    previous_input: &FileState,
    previous_patch: &PreviousPatchState,
    current_proof: Option<&ArchiveMemberSetProof>,
    normalize_rust_archive_patch_inputs: bool,
) -> Option<bool> {
    let previous_proof = previous_input
        .patch
        .as_ref()
        .and_then(|patch| patch.archive_member_set_proof.as_ref());
    let Some(current_proof) = current_proof else {
        return Some(
            previous_proof.is_none()
                && !patch_state_references_archive_member(previous_input, previous_patch),
        );
    };
    let previous_proof = previous_proof?;
    let hashes_match = if normalize_rust_archive_patch_inputs {
        previous_proof.normalized_ordered_hash == current_proof.normalized_ordered_hash
    } else {
        previous_proof.raw_ordered_hash == current_proof.raw_ordered_hash
    };
    Some(previous_proof.member_count == current_proof.member_count && hashes_match)
}

fn patch_state_references_archive_member(
    previous_input: &FileState,
    previous_patch: &PreviousPatchState,
) -> bool {
    previous_patch
        .sections
        .iter()
        .any(|section| section.input != previous_input.path)
}

fn stored_patch_state_references_archive_member(previous_input: &FileState) -> bool {
    previous_input.patch.as_ref().is_some_and(|patch| {
        patch
            .sections
            .iter()
            .any(|section| section.input != previous_input.path)
    })
}

fn archive_member_identifiers(bytes: &[u8]) -> Result<Option<Vec<Vec<u8>>>> {
    let Ok(archive) = ArchiveIterator::from_archive_bytes(bytes) else {
        return Ok(None);
    };
    let mut identifiers = Vec::new();
    for entry in archive {
        match entry? {
            ArchiveEntry::Regular(content) => identifiers.push(content.ident.as_slice().to_vec()),
            ArchiveEntry::Thin(entry) => identifiers.push(entry.ident.as_slice().to_vec()),
        }
    }
    Ok(Some(identifiers))
}

fn archive_member_patch_identifiers(bytes: &[u8]) -> Result<Option<Vec<Vec<u8>>>> {
    Ok(archive_member_identifiers(bytes)?.map(|members| {
        members
            .iter()
            .map(|member| archive_member_patch_identifier(member))
            .collect()
    }))
}

fn archive_member_set_proof(bytes: &[u8]) -> Result<Option<ArchiveMemberSetProof>> {
    let Some(raw_members) = archive_member_identifiers(bytes)? else {
        return Ok(None);
    };
    let normalized_members = raw_members
        .iter()
        .map(|member| archive_member_patch_identifier(member))
        .collect::<Vec<_>>();
    Ok(Some(ArchiveMemberSetProof {
        raw_ordered_hash: archive_member_identifier_list_hash(
            b"sld-archive-members-raw-ordered-v1",
            &raw_members,
        ),
        normalized_ordered_hash: archive_member_identifier_list_hash(
            b"sld-archive-members-normalized-ordered-v2",
            &normalized_members,
        ),
        member_count: raw_members.len(),
        rustc_link_content_digest: rustc_rlib_link_content_digest(bytes),
    }))
}

#[cfg(test)]
fn rustc_rlib_link_content_digest_matches_previous(input: &FileState, bytes: &[u8]) -> bool {
    let Some(current_digest) = rustc_rlib_link_content_digest(bytes) else {
        return false;
    };
    rustc_rlib_link_content_digest_value_matches_previous(input, &current_digest)
}

fn rustc_rlib_link_content_digest_matches_previous_path(
    input: &FileState,
    path: &Path,
) -> Option<FileContentState> {
    #[cfg(not(unix))]
    {
        let _ = (input, path);
        None
    }
    #[cfg(unix)]
    {
        let before = FileIdentity::from_path(path).ok().flatten()?;
        let file = OpenOptions::new().read(true).open(path).ok()?;
        let opened = FileIdentity::from_metadata(&file.metadata().ok()?);
        if before != opened {
            return None;
        }
        let data = object::read::ReadCache::new(file);
        let archive = object::read::archive::ArchiveFile::parse(&data).ok()?;
        if archive.is_thin() {
            return None;
        }
        for member in archive.members() {
            let member = member.ok()?;
            if trim_archive_member_nul_padding(member.name()) != RUSTC_RLIB_LINK_METADATA_MEMBER {
                continue;
            }
            let (offset, size) = member.file_range();
            if size > RUSTC_RLIB_LINK_METADATA_WRAPPER_MAX_LEN {
                return None;
            }
            let current_digest =
                rustc_rlib_link_content_digest_from_wrapper(data.range(offset, size))?;
            if !rustc_rlib_link_content_digest_value_matches_previous(input, &current_digest) {
                return None;
            }
            let after = FileIdentity::from_path(path).ok().flatten()?;
            if opened != after {
                return None;
            }
            return Some(FileContentState {
                len: after.len,
                hash: String::new(),
                identity: Some(after),
            });
        }
        None
    }
}

fn trim_archive_member_nul_padding(name: &[u8]) -> &[u8] {
    let end = name
        .iter()
        .rposition(|byte| *byte != 0)
        .map_or(0, |index| index + 1);
    &name[..end]
}

fn rustc_rlib_link_content_digest_value_matches_previous(
    input: &FileState,
    current_digest: &str,
) -> bool {
    previous_rustc_rlib_link_content_digest(input) == Some(current_digest)
}

fn previous_rustc_rlib_link_content_digest(input: &FileState) -> Option<&str> {
    input.rustc_link_content_digest.as_deref().or_else(|| {
        input
            .patch
            .as_ref()
            .and_then(|patch| patch.archive_member_set_proof.as_ref())
            .and_then(|proof| proof.rustc_link_content_digest.as_deref())
    })
}

fn rustc_rlib_link_content_digest(bytes: &[u8]) -> Option<String> {
    rustc_rlib_provenance(bytes).map(|provenance| provenance.link_content_digest)
}

fn rustc_rlib_provenance(bytes: &[u8]) -> Option<RustcRlibProvenance> {
    let archive = ArchiveIterator::from_archive_bytes(bytes).ok()?;
    let mut metadata = None;
    let mut object_identifiers = Vec::new();
    for entry in archive {
        let ArchiveEntry::Regular(content) = entry.ok()? else {
            return None;
        };
        let identifier = content.ident.as_slice();
        if identifier == RUSTC_RLIB_LINK_METADATA_MEMBER {
            if metadata.replace(content.entry_data).is_some()
                || content.entry_data.len() as u64 > RUSTC_RLIB_LINK_METADATA_WRAPPER_MAX_LEN
            {
                return None;
            }
            continue;
        }
        if identifier.starts_with(b"__.SYMDEF") || identifier == b"lib.rmeta" {
            continue;
        }
        object_identifiers.push(identifier.to_vec());
    }
    rustc_rlib_provenance_from_wrapper(metadata?, &object_identifiers)
}

fn rustc_rlib_provenance_from_wrapper<'data, R: object::read::ReadRef<'data>>(
    data: R,
    object_identifiers: &[Vec<u8>],
) -> Option<RustcRlibProvenance> {
    let file = object::File::parse(data).ok()?;
    let section = file.section_by_name(RUSTC_RLIB_LINK_METADATA_SECTION)?;
    let metadata = section.data().ok()?;
    let link_content_digest = decode_rustc_rlib_link_content_digest(metadata)?;
    let raw_object_manifest =
        decode_rustc_rlib_raw_object_digests(metadata).and_then(|ordered_objects| {
            rustc_rlib_raw_object_manifest(
                link_content_digest.clone(),
                ordered_objects,
                object_identifiers,
            )
        });
    Some(RustcRlibProvenance {
        link_content_digest,
        raw_object_manifest,
    })
}

fn rustc_rlib_link_content_digest_from_wrapper<'data, R: object::read::ReadRef<'data>>(
    data: R,
) -> Option<String> {
    let file = object::File::parse(data).ok()?;
    let section = file.section_by_name(RUSTC_RLIB_LINK_METADATA_SECTION)?;
    decode_rustc_rlib_link_content_digest(section.data().ok()?)
}

fn rustc_rlib_raw_object_manifest(
    link_content_digest: String,
    ordered_objects: Vec<RustcRlibRawObjectDigest>,
    object_identifiers: &[Vec<u8>],
) -> Option<RustcRlibRawObjectManifest> {
    if ordered_objects.len() != object_identifiers.len()
        || ordered_objects
            .iter()
            .zip(object_identifiers)
            .any(|(object, identifier)| object.identifier != *identifier)
    {
        return None;
    }
    let mut normalized_identifiers = HashSet::with_capacity(ordered_objects.len());
    for object in &ordered_objects {
        if !normalized_identifiers.insert(archive_member_patch_identifier(&object.identifier)) {
            return None;
        }
    }
    if rustc_rlib_link_content_digest_from_raw_objects(&ordered_objects).as_deref()
        != Some(link_content_digest.as_str())
    {
        return None;
    }
    Some(RustcRlibRawObjectManifest {
        link_content_digest,
        ordered_objects,
    })
}

fn rustc_rlib_link_content_digest_from_raw_objects(
    objects: &[RustcRlibRawObjectDigest],
) -> Option<String> {
    let mut hasher = blake3::Hasher::new();
    hasher.update(b"rustc-rlib-link-content-v1");
    hasher.update(&(objects.len() as u64).to_le_bytes());
    for object in objects {
        let module_name = rustc_rlib_module_name_from_object_identifier(&object.identifier)?;
        if module_name.is_empty() || !is_blake3_hex_digest(&object.digest) {
            return None;
        }
        hasher.update(&(module_name.len() as u64).to_le_bytes());
        hasher.update(module_name);
        hasher.update(object.digest.as_bytes());
    }
    Some(hasher.finalize().to_hex().to_string())
}

fn rustc_rlib_module_name_from_object_identifier(identifier: &[u8]) -> Option<&[u8]> {
    let stem = identifier.strip_suffix(b".rcgu.o")?;
    let invocation_separator = stem.iter().rposition(|byte| *byte == b'.')?;
    let output_filestem_and_module = stem.get(..invocation_separator)?;
    let invocation = stem.get(invocation_separator + 1..)?;
    let module_separator = output_filestem_and_module
        .iter()
        .position(|byte| *byte == b'.')?;
    let module_name = output_filestem_and_module.get(module_separator + 1..)?;
    (module_separator > 0 && !module_name.is_empty() && !invocation.is_empty())
        .then_some(module_name)
}

fn rustc_rlib_raw_object_delta(
    previous: &RustcRlibRawObjectManifest,
    current: &RustcRlibRawObjectManifest,
) -> Option<RustcRlibRawObjectDelta> {
    let mut previous_positions = HashMap::with_capacity(previous.ordered_objects.len());
    for (index, object) in previous.ordered_objects.iter().enumerate() {
        if previous_positions
            .insert(archive_member_patch_identifier(&object.identifier), index)
            .is_some()
        {
            return None;
        }
    }
    let mut current_positions = HashMap::with_capacity(current.ordered_objects.len());
    for (index, object) in current.ordered_objects.iter().enumerate() {
        if current_positions
            .insert(archive_member_patch_identifier(&object.identifier), index)
            .is_some()
        {
            return None;
        }
    }

    let mut unchanged = Vec::new();
    let mut changed = Vec::new();
    let mut previous_common_position = None;
    for previous_object in &previous.ordered_objects {
        let identifier = archive_member_patch_identifier(&previous_object.identifier);
        let Some(&current_position) = current_positions.get(&identifier) else {
            continue;
        };
        if previous_common_position.is_some_and(|previous| current_position <= previous) {
            return None;
        }
        previous_common_position = Some(current_position);
        let object = &current.ordered_objects[current_position];
        if previous_object.digest == object.digest {
            unchanged.push(object.clone());
        } else {
            changed.push(object.clone());
        }
    }
    let added = current
        .ordered_objects
        .iter()
        .filter(|object| {
            let identifier = archive_member_patch_identifier(&object.identifier);
            !previous_positions.contains_key(&identifier)
        })
        .cloned()
        .collect();
    let removed = previous
        .ordered_objects
        .iter()
        .filter(|object| {
            let identifier = archive_member_patch_identifier(&object.identifier);
            !current_positions.contains_key(&identifier)
        })
        .cloned()
        .collect();
    Some(RustcRlibRawObjectDelta {
        unchanged,
        changed,
        added,
        removed,
    })
}

fn decode_rustc_rlib_link_content_digest(metadata: &[u8]) -> Option<String> {
    let metadata = metadata.strip_suffix(RUSTC_SERIALIZED_METADATA_END)?;
    let suffix_len = RUSTC_RLIB_LINK_CONTENT_DIGEST_PREFIX.len() + blake3::OUT_LEN * 2;
    let suffix = metadata.get(metadata.len().checked_sub(suffix_len)?..)?;
    let digest = suffix.strip_prefix(RUSTC_RLIB_LINK_CONTENT_DIGEST_PREFIX)?;
    let digest = std::str::from_utf8(digest).ok()?;
    is_blake3_hex_digest(digest).then(|| digest.to_owned())
}

fn rustc_rlib_raw_object_digests_from_wrapper<'data, R: object::read::ReadRef<'data>>(
    data: R,
) -> Option<Vec<RustcRlibRawObjectDigest>> {
    let file = object::File::parse(data).ok()?;
    let section = file.section_by_name(RUSTC_RLIB_LINK_METADATA_SECTION)?;
    decode_rustc_rlib_raw_object_digests(section.data().ok()?)
}

fn decode_rustc_rlib_raw_object_digests(metadata: &[u8]) -> Option<Vec<RustcRlibRawObjectDigest>> {
    let mut metadata = metadata.strip_suffix(RUSTC_SERIALIZED_METADATA_END)?;
    let link_content_suffix_len = RUSTC_RLIB_LINK_CONTENT_DIGEST_PREFIX.len() + blake3::OUT_LEN * 2;
    if let Some(suffix_start) = metadata.len().checked_sub(link_content_suffix_len)
        && let Some(suffix) = metadata.get(suffix_start..)
        && let Some(digest) = suffix.strip_prefix(RUSTC_RLIB_LINK_CONTENT_DIGEST_PREFIX)
        && let Ok(digest) = std::str::from_utf8(digest)
        && is_blake3_hex_digest(digest)
    {
        metadata = &metadata[..suffix_start];
    }

    let payload_len = usize::try_from(read_u64_le(
        metadata.get(metadata.len().checked_sub(8)?..)?,
    )?)
    .ok()?;
    let payload_end = metadata.len().checked_sub(8)?;
    let payload_start = payload_end.checked_sub(payload_len)?;
    let prefix_start = payload_start.checked_sub(RUSTC_RLIB_RAW_OBJECT_DIGESTS_PREFIX.len())?;
    if metadata.get(prefix_start..payload_start)? != RUSTC_RLIB_RAW_OBJECT_DIGESTS_PREFIX {
        return None;
    }
    let mut payload = metadata.get(payload_start..payload_end)?;
    let object_count = usize::try_from(take_u64_le(&mut payload)?).ok()?;
    if object_count > payload.len() / (8 + blake3::OUT_LEN * 2) {
        return None;
    }
    let mut objects = Vec::with_capacity(object_count);
    for _ in 0..object_count {
        let identifier_len = usize::try_from(take_u64_le(&mut payload)?).ok()?;
        let identifier = take_bytes(&mut payload, identifier_len)?.to_vec();
        if identifier.is_empty() {
            return None;
        }
        let digest = std::str::from_utf8(take_bytes(&mut payload, blake3::OUT_LEN * 2)?).ok()?;
        if !is_blake3_hex_digest(digest) {
            return None;
        }
        objects.push(RustcRlibRawObjectDigest {
            identifier,
            digest: digest.to_owned(),
        });
    }
    payload.is_empty().then_some(objects)
}

fn take_u64_le(bytes: &mut &[u8]) -> Option<u64> {
    read_u64_le(take_bytes(bytes, 8)?)
}

fn take_bytes<'a>(bytes: &mut &'a [u8], len: usize) -> Option<&'a [u8]> {
    let (taken, rest) = bytes.split_at_checked(len)?;
    *bytes = rest;
    Some(taken)
}

fn archive_member_identifier_list_hash(domain: &[u8], members: &[Vec<u8>]) -> String {
    let mut hasher = blake3::Hasher::new();
    hasher.update(domain);
    hasher.update(&(members.len() as u64).to_le_bytes());
    for member in members {
        hasher.update(&(member.len() as u64).to_le_bytes());
        hasher.update(member);
    }
    hasher.finalize().to_hex().to_string()
}

fn archive_member_patch_identifier(identifier: &[u8]) -> Vec<u8> {
    let Ok(filename) = std::str::from_utf8(identifier) else {
        return identifier.to_vec();
    };
    let Some(stem) = filename.strip_suffix(".rcgu.o") else {
        return identifier.to_vec();
    };
    let Some((module_name, invocation)) = stem.rsplit_once('.') else {
        return identifier.to_vec();
    };
    let mut module_parts = module_name.split('.');
    let Some(crate_name) = module_parts.next() else {
        return identifier.to_vec();
    };
    let Some(codegen_unit) = module_parts.next() else {
        return identifier.to_vec();
    };
    if crate_name.is_empty()
        || codegen_unit.is_empty()
        || invocation.is_empty()
        || module_parts.any(str::is_empty)
    {
        return identifier.to_vec();
    }
    format!("{module_name}.rcgu.o").into_bytes()
}

