fn archive_macho_semantic_patch_proof_fingerprint_with_options(
    bytes: &[u8],
    ranges: &[std::ops::Range<usize>],
    ignored_identifiers: &[Vec<u8>],
    ignored_defined_symbols: &HashSet<Vec<u8>>,
    ignore_masked_unwind_sections: bool,
    force_retirement_proof: bool,
) -> Result<Option<blake3::Hash>> {
    let Some(members) = archive_macho_semantic_patch_proof_members(
        bytes,
        ranges,
        ignored_identifiers,
        ignored_defined_symbols,
        ignore_masked_unwind_sections,
        force_retirement_proof,
    )?
    else {
        return Ok(None);
    };
    let mut hasher = blake3::Hasher::new();
    hasher.update(b"sld-archive-changed-macho-symbol-proof-v1");
    for (identifier, member_hash) in &members {
        hasher.update(&(identifier.len() as u64).to_le_bytes());
        hasher.update(identifier);
        hasher.update(member_hash.as_bytes());
    }
    hasher.update(&(members.len() as u64).to_le_bytes());
    Ok(Some(hasher.finalize()))
}

fn archive_macho_semantic_patch_proof_members(
    bytes: &[u8],
    ranges: &[std::ops::Range<usize>],
    ignored_identifiers: &[Vec<u8>],
    ignored_defined_symbols: &HashSet<Vec<u8>>,
    ignore_masked_unwind_sections: bool,
    force_retirement_proof: bool,
) -> Result<Option<Vec<(Vec<u8>, blake3::Hash)>>> {
    let Ok(archive) = ArchiveIterator::from_archive_bytes(bytes) else {
        return Ok(None);
    };
    let mut members = Vec::new();
    for entry in archive {
        let ArchiveEntry::Regular(content) = entry? else {
            return Ok(None);
        };
        let identifier = archive_member_patch_identifier(content.ident.as_slice());
        if ignored_identifiers
            .iter()
            .any(|ignored| ignored == &identifier)
            || identifier.starts_with(b"__.SYMDEF")
            || matches!(identifier.as_slice(), b"lib.rmeta" | b"lib.rmeta-link")
        {
            continue;
        }
        let Ok(file) = object::File::parse(content.entry_data) else {
            return Ok(None);
        };
        if file.format() != object::BinaryFormat::MachO {
            return Ok(None);
        }
        let mut ignored_sections = HashSet::new();
        if ignore_masked_unwind_sections {
            ignored_sections =
                fully_masked_macho_unwind_sections(&file, content.data_offset, ranges)?;
        }
        let Some(member_hash) = macho_object_semantic_patch_fingerprint(
            content.entry_data,
            content.data_offset,
            ranges,
            &ignored_sections,
            &HashSet::new(),
            ignored_defined_symbols,
            force_retirement_proof,
            true,
        ) else {
            return Ok(None);
        };
        members.push((identifier, member_hash));
    }
    Ok(Some(members))
}

fn fully_masked_macho_unwind_sections(
    file: &object::File<'_>,
    file_offset: usize,
    ranges: &[std::ops::Range<usize>],
) -> Result<HashSet<object::SectionIndex>> {
    let mut ignored = HashSet::new();
    for section in file.sections() {
        let segment_name = section.segment_name_bytes()?.unwrap_or_default();
        let section_name = section.name_bytes()?;
        if !matches!(
            (segment_name, section_name),
            (b"__LD", b"__compact_unwind") | (b"__TEXT", b"__eh_frame")
        ) {
            continue;
        }
        let Some((offset, size)) = section.file_range() else {
            continue;
        };
        let Ok(offset) = usize::try_from(offset) else {
            continue;
        };
        let Ok(size) = usize::try_from(size) else {
            continue;
        };
        let Some(start) = file_offset.checked_add(offset) else {
            continue;
        };
        let Some(end) = start.checked_add(size) else {
            continue;
        };
        if size != 0
            && ranges
                .iter()
                .any(|range| range.start <= start && range.end >= end)
        {
            ignored.insert(section.index());
        }
    }
    Ok(ignored)
}

fn macho_owned_archive_sections(
    input_file_path: &str,
    sections: impl IntoIterator<Item = PatchSection>,
) -> Result<Option<HashMap<Vec<u8>, HashSet<object::SectionIndex>>>> {
    let mut owned = HashMap::<Vec<u8>, HashSet<object::SectionIndex>>::new();
    for section in sections {
        let Some(parsed) = parse_patch_input_ref(input_file_path, section.input.as_str())? else {
            return Ok(None);
        };
        if parsed.identifier.is_empty() {
            return Ok(None);
        }
        let section_index = usize::try_from(section.section_index)
            .ok()
            .and_then(|index| index.checked_add(1))
            .map(object::SectionIndex)
            .context("Mach-O owned section index overflow")?;
        owned
            .entry(archive_member_patch_identifier(&parsed.identifier))
            .or_default()
            .insert(section_index);
    }
    Ok(Some(owned))
}

fn archive_macho_unowned_text_fingerprint(
    bytes: &[u8],
    ranges: &[std::ops::Range<usize>],
    owned_sections: &HashMap<Vec<u8>, HashSet<object::SectionIndex>>,
    ignored_identifiers: &[Vec<u8>],
    ignored_defined_symbols: &HashSet<Vec<u8>>,
    force_retirement_proof: bool,
) -> Result<Option<blake3::Hash>> {
    let Ok(archive) = ArchiveIterator::from_archive_bytes(bytes) else {
        return Ok(None);
    };
    let mut hasher = blake3::Hasher::new();
    hasher.update(b"sld-archive-unowned-macho-text-proof-v1");
    let mut member_count = 0_u64;
    let mut has_unowned_section = false;
    for entry in archive {
        let ArchiveEntry::Regular(content) = entry? else {
            return Ok(None);
        };
        let identifier = archive_member_patch_identifier(content.ident.as_slice());
        if ignored_identifiers
            .iter()
            .any(|ignored| ignored == &identifier)
            || identifier.starts_with(b"__.SYMDEF")
            || matches!(identifier.as_slice(), b"lib.rmeta" | b"lib.rmeta-link")
        {
            continue;
        }
        let Ok(file) = object::File::parse(content.entry_data) else {
            return Ok(None);
        };
        let all_sections = file
            .sections()
            .map(|section| section.index())
            .collect::<HashSet<_>>();
        let owned = owned_sections
            .get(identifier.as_slice())
            .cloned()
            .unwrap_or_default();
        if !owned.is_subset(&all_sections) {
            return Ok(None);
        }
        let unowned = file
            .sections()
            .filter(|section| {
                !owned.contains(&section.index())
                    && section.segment_name_bytes().ok().flatten() == Some(b"__TEXT".as_slice())
                    && section.name_bytes().ok() == Some(b"__text".as_slice())
            })
            .map(|section| section.index())
            .collect::<HashSet<_>>();
        has_unowned_section |= !unowned.is_empty();
        let ignored_sections = if force_retirement_proof {
            fully_masked_macho_unwind_sections(&file, content.data_offset, ranges)?
        } else {
            HashSet::new()
        };
        let Some(member_hash) = macho_object_semantic_patch_fingerprint(
            content.entry_data,
            content.data_offset,
            ranges,
            &ignored_sections,
            &unowned,
            ignored_defined_symbols,
            force_retirement_proof,
            true,
        ) else {
            return Ok(None);
        };
        hash_length_prefixed(&mut hasher, &identifier);
        hasher.update(member_hash.as_bytes());
        member_count += 1;
    }
    hasher.update(&member_count.to_le_bytes());
    Ok(has_unowned_section.then(|| hasher.finalize()))
}

fn archive_diff_allows_unowned_macho_text_changes(
    previous_bytes: &[u8],
    current_bytes: &[u8],
    input_file_path: &str,
    matched_sections: &[MatchedPatchSection],
    current_resolver: &PatchInputResolver<'_>,
) -> Result<bool> {
    let previous_resolver = PatchInputResolver::new(previous_bytes, true)?;
    let previous_sections = matched_sections
        .iter()
        .map(|section| section.previous.clone())
        .collect::<Vec<_>>();
    let current_sections = matched_sections
        .iter()
        .map(|section| section.current.clone())
        .collect::<Vec<_>>();
    let Some(previous_ranges) = patch_ranges_with_resolver(
        previous_bytes,
        input_file_path,
        previous_sections.iter().cloned(),
        &previous_resolver,
        PatchInputLookup::MatchArchiveMember,
    )?
    else {
        return Ok(false);
    };
    let Some(current_ranges) = patch_ranges_with_resolver(
        current_bytes,
        input_file_path,
        current_sections.iter().cloned(),
        current_resolver,
        PatchInputLookup::MatchArchiveMember,
    )?
    else {
        return Ok(false);
    };
    let Some(previous_owned) = macho_owned_archive_sections(input_file_path, previous_sections)?
    else {
        return Ok(false);
    };
    let Some(current_owned) = macho_owned_archive_sections(input_file_path, current_sections)?
    else {
        return Ok(false);
    };
    let previous_fingerprint = archive_macho_unowned_text_fingerprint(
        previous_bytes,
        &previous_ranges,
        &previous_owned,
        &[],
        &HashSet::new(),
        false,
    )?;
    let current_fingerprint = archive_macho_unowned_text_fingerprint(
        current_bytes,
        &current_ranges,
        &current_owned,
        &[],
        &HashSet::new(),
        false,
    )?;
    Ok(previous_fingerprint.is_some() && previous_fingerprint == current_fingerprint)
}

fn archive_diff_allows_changed_macho_symbols(
    previous_bytes: &[u8],
    current_bytes: &[u8],
    input_file_path: &str,
    matched_sections: &[MatchedPatchSection],
    current_resolver: &PatchInputResolver<'_>,
    ignored_previous_identifiers: &[Vec<u8>],
    ignored_current_identifiers: &[Vec<u8>],
    previous_extra_ranges: &[std::ops::Range<usize>],
    current_extra_ranges: &[std::ops::Range<usize>],
    added_names: &[SharedText],
    retiring_names: &[SharedText],
    ignore_masked_unwind_sections: bool,
) -> Result<bool> {
    if added_names.is_empty() && retiring_names.is_empty() {
        return Ok(false);
    }
    let added_names = added_names
        .iter()
        .map(|name| hex::decode(name.as_str()))
        .collect::<std::result::Result<HashSet<_>, _>>()
        .context("Malformed added Mach-O symbol resolution name")?;
    let retiring_names = retiring_names
        .iter()
        .map(|name| hex::decode(name.as_str()))
        .collect::<std::result::Result<HashSet<_>, _>>()
        .context("Malformed deferred Mach-O symbol resolution name")?;
    if !added_names.is_disjoint(&retiring_names) {
        return Ok(false);
    }
    let ignored_defined_symbols = added_names
        .iter()
        .chain(&retiring_names)
        .cloned()
        .collect::<HashSet<_>>();
    let Some(previous_definition_counts) = archive_macho_defined_symbol_counts(
        previous_bytes,
        ignored_previous_identifiers,
        &ignored_defined_symbols,
    )?
    else {
        return Ok(false);
    };
    let Some(current_definition_counts) = archive_macho_defined_symbol_counts(
        current_bytes,
        ignored_current_identifiers,
        &ignored_defined_symbols,
    )?
    else {
        return Ok(false);
    };
    if !macho_definition_counts_prove_restoration(
        &added_names,
        &previous_definition_counts,
        &current_definition_counts,
    ) || !macho_definition_counts_prove_retirement(
        &retiring_names,
        &previous_definition_counts,
        &current_definition_counts,
    ) {
        return Ok(false);
    }
    let previous_resolver = PatchInputResolver::new(previous_bytes, true)?;
    let Some(mut previous_ranges) = patch_ranges_with_resolver(
        previous_bytes,
        input_file_path,
        matched_sections
            .iter()
            .map(|section| section.previous.clone()),
        &previous_resolver,
        PatchInputLookup::MatchArchiveMember,
    )?
    else {
        return Ok(false);
    };
    let Some(mut current_ranges) = patch_ranges_with_resolver(
        current_bytes,
        input_file_path,
        matched_sections
            .iter()
            .map(|section| section.current.clone()),
        current_resolver,
        PatchInputLookup::MatchArchiveMember,
    )?
    else {
        return Ok(false);
    };
    previous_ranges.extend(previous_extra_ranges.iter().cloned());
    current_ranges.extend(current_extra_ranges.iter().cloned());
    let previous_fingerprint = if ignore_masked_unwind_sections {
        archive_macho_semantic_patch_proof_fingerprint_ignoring_masked_unwind_sections(
            previous_bytes,
            &previous_ranges,
            ignored_previous_identifiers,
            &ignored_defined_symbols,
        )?
    } else {
        archive_macho_semantic_patch_proof_fingerprint(
            previous_bytes,
            &previous_ranges,
            ignored_previous_identifiers,
            &ignored_defined_symbols,
        )?
    };
    let current_fingerprint = if ignore_masked_unwind_sections {
        archive_macho_semantic_patch_proof_fingerprint_ignoring_masked_unwind_sections(
            current_bytes,
            &current_ranges,
            ignored_current_identifiers,
            &ignored_defined_symbols,
        )?
    } else {
        archive_macho_semantic_patch_proof_fingerprint(
            current_bytes,
            &current_ranges,
            ignored_current_identifiers,
            &ignored_defined_symbols,
        )?
    };
    Ok(previous_fingerprint.is_some() && previous_fingerprint == current_fingerprint)
}

