#[allow(clippy::too_many_arguments)]
fn archive_diff_allows_owned_macho_member_exchange(
    previous_bytes: &[u8],
    current_bytes: &[u8],
    input_file_path: &str,
    matched_sections: &[MatchedPatchSection],
    current_resolver: &PatchInputResolver<'_>,
    removed_identifiers: &[Vec<u8>],
    added_identifiers: &[Vec<u8>],
    restored_names: &[SharedText],
    previous_extra_ranges: &[std::ops::Range<usize>],
    current_extra_ranges: &[std::ops::Range<usize>],
) -> Result<bool> {
    let restored_names = restored_names
        .iter()
        .map(|name| hex::decode(name.as_str()))
        .collect::<std::result::Result<HashSet<_>, _>>()
        .context("Malformed rollback Mach-O symbol resolution name")?;
    if !restored_names.is_empty() {
        let Some(previous_definition_counts) = archive_macho_defined_symbol_counts(
            previous_bytes,
            removed_identifiers,
            &restored_names,
        )?
        else {
            return Ok(false);
        };
        let Some(current_definition_counts) =
            archive_macho_defined_symbol_counts(current_bytes, added_identifiers, &restored_names)?
        else {
            return Ok(false);
        };
        if !macho_definition_counts_prove_restoration(
            &restored_names,
            &previous_definition_counts,
            &current_definition_counts,
        ) {
            return Ok(false);
        }
    }
    let previous_resolver = PatchInputResolver::new(previous_bytes, true)?;
    let Some(mut previous_ranges) = patch_ranges_with_resolver(
        previous_bytes,
        input_file_path,
        matched_sections
            .iter()
            .map(|section| section.previous.clone()),
        &previous_resolver,
        PatchInputLookup::MatchArchiveMember,
    )?
    else {
        return Ok(false);
    };
    let Some(mut current_ranges) = patch_ranges_with_resolver(
        current_bytes,
        input_file_path,
        matched_sections
            .iter()
            .map(|section| section.current.clone()),
        current_resolver,
        PatchInputLookup::MatchArchiveMember,
    )?
    else {
        return Ok(false);
    };
    previous_ranges.extend(previous_extra_ranges.iter().cloned());
    current_ranges.extend(current_extra_ranges.iter().cloned());
    let previous_fingerprint = archive_macho_member_retirement_fingerprint(
        previous_bytes,
        &previous_ranges,
        removed_identifiers,
        &restored_names,
    )?;
    let current_fingerprint = archive_macho_member_retirement_fingerprint(
        current_bytes,
        &current_ranges,
        added_identifiers,
        &restored_names,
    )?;
    if previous_fingerprint.is_some() && previous_fingerprint == current_fingerprint {
        return Ok(true);
    }

    let Some(previous_owned) = macho_owned_archive_sections(
        input_file_path,
        matched_sections
            .iter()
            .map(|section| section.previous.clone()),
    )?
    else {
        return Ok(false);
    };
    let Some(current_owned) = macho_owned_archive_sections(
        input_file_path,
        matched_sections
            .iter()
            .map(|section| section.current.clone()),
    )?
    else {
        return Ok(false);
    };
    let previous_fingerprint = archive_macho_unowned_text_fingerprint(
        previous_bytes,
        &previous_ranges,
        &previous_owned,
        removed_identifiers,
        &restored_names,
        true,
    )?;
    let current_fingerprint = archive_macho_unowned_text_fingerprint(
        current_bytes,
        &current_ranges,
        &current_owned,
        added_identifiers,
        &restored_names,
        true,
    )?;
    Ok(previous_fingerprint.is_some() && previous_fingerprint == current_fingerprint)
}

