fn macho_object_patch_fingerprint(
    bytes: &[u8],
    file_offset: usize,
    ranges: &[std::ops::Range<usize>],
) -> Option<blake3::Hash> {
    macho_object_semantic_patch_fingerprint(
        bytes,
        file_offset,
        ranges,
        &HashSet::new(),
        &HashSet::new(),
        &HashSet::new(),
        false,
        true,
    )
}

fn macho_object_semantic_patch_fingerprint(
    bytes: &[u8],
    file_offset: usize,
    ranges: &[std::ops::Range<usize>],
    ignored_sections: &HashSet<object::SectionIndex>,
    unowned_sections: &HashSet<object::SectionIndex>,
    ignored_defined_symbols: &HashSet<Vec<u8>>,
    force_retirement_proof: bool,
    require_masked_text: bool,
) -> Option<blake3::Hash> {
    let file = object::File::parse(bytes).ok()?;
    if file.format() != object::BinaryFormat::MachO
        || file.kind() != object::ObjectKind::Relocatable
        || file.architecture() != object::Architecture::Aarch64
        || !file.is_64()
        || !file.is_little_endian()
    {
        return None;
    }
    let object::FileFlags::MachO { flags } = file.flags() else {
        return None;
    };

    let mut hasher = blake3::Hasher::new();
    let retirement_proof = force_retirement_proof || !ignored_defined_symbols.is_empty();
    if !unowned_sections.is_empty() {
        hasher.update(b"sld-macho-object-unowned-section-proof-v1");
    } else if !retirement_proof {
        hasher.update(b"sld-macho-object-patch-fingerprint-v5");
    } else {
        hasher.update(b"sld-macho-object-retired-symbol-proof-v1");
    }
    hasher.update(bytes.get(4..12)?);
    hasher.update(&flags.to_le_bytes());

    let mut sections = Vec::new();
    for section in file.sections() {
        if ignored_sections.contains(&section.index()) {
            continue;
        }
        let segment_name = section.segment_name_bytes().ok().flatten()?;
        let object::SectionFlags::MachO { flags } = section.flags() else {
            return None;
        };
        if segment_name.starts_with(b"__DWARF") || flags & object::macho::S_ATTR_DEBUG != 0 {
            continue;
        }
        sections.push(section);
    }
    let section_indices = sections
        .iter()
        .map(|section| section.index())
        .collect::<HashSet<_>>();
    hasher.update(&(sections.len() as u64).to_le_bytes());
    let mut has_masked_text = false;
    let mut has_masked_section = false;
    let mut fully_masked_sections = HashSet::new();
    let mut masked_text_undefined_symbols = HashSet::new();
    let mut unowned_undefined_symbols = HashSet::new();
    let mut unmasked_relocation_symbols = HashSet::new();
    let mut hashed_relocation_symbols = HashSet::new();
    for section in sections {
        let segment_name = section.segment_name_bytes().ok().flatten()?;
        let section_name = section.name_bytes().ok()?;
        hash_length_prefixed(&mut hasher, segment_name);
        hash_length_prefixed(&mut hasher, section_name);
        let object::SectionFlags::MachO { flags } = section.flags() else {
            return None;
        };
        hasher.update(&flags.to_le_bytes());
        hasher.update(&section.align().to_le_bytes());

        let unowned = unowned_sections.contains(&section.index());
        let data = section.data().ok()?;
        let fully_masked = section.file_range().is_some_and(|(offset, size)| {
            let Ok(offset) = usize::try_from(offset) else {
                return false;
            };
            let Ok(size) = usize::try_from(size) else {
                return false;
            };
            let Some(start) = file_offset.checked_add(offset) else {
                return false;
            };
            let Some(end) = start.checked_add(size) else {
                return false;
            };
            size != 0
                && ranges
                    .iter()
                    .any(|range| range.start <= start && range.end >= end)
        });
        has_masked_section |= fully_masked || unowned;
        has_masked_text |= (fully_masked || unowned) && section_name == b"__text";
        if fully_masked {
            fully_masked_sections.insert(section.index());
        }
        hasher.update(&[if unowned { 2 } else { u8::from(fully_masked) }]);
        let relocations = section.relocations().collect::<Vec<_>>();
        if unowned {
            for (_, relocation) in relocations {
                if let object::RelocationTarget::Symbol(symbol_index) = relocation.target()
                    && file
                        .symbol_by_index(symbol_index)
                        .is_ok_and(|symbol| symbol.is_undefined())
                {
                    unowned_undefined_symbols.insert(symbol_index);
                }
                if let Some(symbol_index) = relocation.subtractor()
                    && file
                        .symbol_by_index(symbol_index)
                        .is_ok_and(|symbol| symbol.is_undefined())
                {
                    unowned_undefined_symbols.insert(symbol_index);
                }
            }
            continue;
        }
        if !fully_masked {
            hasher.update(&section.size().to_le_bytes());
            hasher.update(&(data.len() as u64).to_le_bytes());
            let (data_offset, _) = section.file_range().unwrap_or_default();
            let data_offset = file_offset.checked_add(usize::try_from(data_offset).ok()?)?;
            update_hash_with_ranges(&mut hasher, data, data_offset, ranges);
        }

        if fully_masked && section_name == b"__text" {
            for (_, relocation) in relocations {
                if let object::RelocationTarget::Symbol(symbol_index) = relocation.target()
                    && file
                        .symbol_by_index(symbol_index)
                        .is_ok_and(|symbol| symbol.is_undefined())
                {
                    masked_text_undefined_symbols.insert(symbol_index);
                }
            }
            continue;
        }
        hasher.update(&(relocations.len() as u64).to_le_bytes());
        for (offset, relocation) in relocations {
            if !(fully_masked && section_name == b"__text") {
                hasher.update(&offset.to_le_bytes());
            }
            let object::RelocationFlags::MachO {
                r_type,
                r_pcrel,
                r_length,
            } = relocation.flags()
            else {
                return None;
            };
            hasher.update(&[r_type, u8::from(r_pcrel), r_length]);
            hasher.update(&relocation.addend().to_le_bytes());
            hasher.update(&[u8::from(relocation.has_implicit_addend())]);
            if let object::RelocationTarget::Symbol(symbol) = relocation.target() {
                unmasked_relocation_symbols.insert(symbol);
            }
            if retirement_proof {
                if let object::RelocationTarget::Symbol(symbol) = relocation.target() {
                    hashed_relocation_symbols.insert(symbol);
                }
                hash_macho_semantic_relocation_target(&mut hasher, &file, relocation.target())?;
            } else {
                hash_macho_relocation_target(&mut hasher, relocation.target())?;
            }
            match relocation.subtractor() {
                Some(symbol) => {
                    hasher.update(&[1]);
                    unmasked_relocation_symbols.insert(symbol);
                    if retirement_proof {
                        hashed_relocation_symbols.insert(symbol);
                        hash_macho_relocation_symbol(&mut hasher, &file, symbol)?;
                    } else {
                        hasher.update(&(symbol.0 as u64).to_le_bytes());
                    }
                }
                None => {
                    hasher.update(&[0]);
                }
            }
        }
    }

    let symbols = file
        .symbols()
        .filter(|symbol| {
            !symbol.is_undefined()
                || unmasked_relocation_symbols.contains(&symbol.index())
                || (!masked_text_undefined_symbols.contains(&symbol.index())
                    && !unowned_undefined_symbols.contains(&symbol.index()))
        })
        .filter(|symbol| {
            symbol.is_undefined()
                || symbol
                    .name_bytes()
                    .is_ok_and(|name| !ignored_defined_symbols.contains(name))
        })
        .filter(|symbol| {
            !retirement_proof
                || symbol.scope() != object::SymbolScope::Compilation
                || symbol
                    .section_index()
                    .is_none_or(|section| !fully_masked_sections.contains(&section))
                || hashed_relocation_symbols.contains(&symbol.index())
        })
        .filter(|symbol| {
            symbol
                .section_index()
                .is_none_or(|section_index| section_indices.contains(&section_index))
        })
        .collect::<Vec<_>>();
    hasher.update(&(symbols.len() as u64).to_le_bytes());
    for symbol in symbols {
        hash_length_prefixed(&mut hasher, symbol.name_bytes().ok()?);
        hash_macho_symbol_section(&mut hasher, symbol.section())?;
        let value_range = macho_symbol_value_field_range(bytes, symbol.index())
            .map(|range| file_offset + range.start..file_offset + range.end);
        let address_is_masked = retirement_proof
            && symbol
                .section_index()
                .is_some_and(|section| fully_masked_sections.contains(&section))
            || value_range.is_some_and(|value_range| {
                ranges
                    .iter()
                    .any(|range| range.start <= value_range.start && range.end >= value_range.end)
            });
        hasher.update(&[u8::from(address_is_masked)]);
        if !address_is_masked {
            let address = if let Some(section_index) = symbol.section_index() {
                symbol
                    .address()
                    .checked_sub(file.section_by_index(section_index).ok()?.address())?
            } else {
                symbol.address()
            };
            hasher.update(&address.to_le_bytes());
        }
        hasher.update(&symbol.size().to_le_bytes());
        hasher.update(&[
            macho_symbol_kind_tag(symbol.kind())?,
            macho_symbol_scope_tag(symbol.scope()),
            u8::from(symbol.is_weak()),
        ]);
        let object::SymbolFlags::MachO { n_desc } = symbol.flags() else {
            return None;
        };
        hasher.update(&n_desc.to_le_bytes());
    }

    (retirement_proof || (has_masked_section && (!require_masked_text || has_masked_text)))
        .then(|| hasher.finalize())
}

fn macho_section_symbols_fingerprint(
    file: &object::File<'_>,
    section_index: object::SectionIndex,
) -> Option<blake3::Hash> {
    let section = file.section_by_index(section_index).ok()?;
    let symbols = file
        .symbols()
        .filter(|symbol| symbol.section_index() == Some(section_index))
        .collect::<Vec<_>>();
    let mut hasher = blake3::Hasher::new();
    hasher.update(b"sld-macho-section-symbols-v1");
    hasher.update(&(symbols.len() as u64).to_le_bytes());
    for symbol in symbols {
        let name = symbol.name_bytes().ok()?;
        if symbol.scope() != object::SymbolScope::Compilation
            || symbol.is_weak()
            || !name.starts_with(b"ltmp")
        {
            return None;
        }
        hash_length_prefixed(&mut hasher, name);
        hasher.update(
            &symbol
                .address()
                .checked_sub(section.address())?
                .to_le_bytes(),
        );
        hasher.update(&symbol.size().to_le_bytes());
        hasher.update(&[
            macho_symbol_kind_tag(symbol.kind())?,
            macho_symbol_scope_tag(symbol.scope()),
            u8::from(symbol.is_weak()),
        ]);
        let object::SymbolFlags::MachO { n_desc } = symbol.flags() else {
            return None;
        };
        hasher.update(&n_desc.to_le_bytes());
    }
    Some(hasher.finalize())
}

fn grown_macho_text_section_activation(
    previous_bytes: &[u8],
    current_bytes: &[u8],
    input_file_path: &str,
    matched_sections: &[MatchedPatchSection],
    reserved_ranges: &[ReservedRangeRecord],
    padding_percent: u32,
    normalize_rust_archive_patch_inputs: bool,
) -> Result<std::result::Result<Option<MachOTextSectionActivation>, String>> {
    let previous_resolver =
        PatchInputResolver::new(previous_bytes, normalize_rust_archive_patch_inputs)?;
    let current_resolver =
        PatchInputResolver::new(current_bytes, normalize_rust_archive_patch_inputs)?;
    let grown = matched_sections
        .iter()
        .enumerate()
        .filter(|(_, section)| {
            section.current.section_name.as_deref() == Some("__TEXT,__text")
                && section.previous.input_size != 0
                && section.previous.output_size != 0
                && section.current.input_size > section.current.output_size
        })
        .collect::<Vec<_>>();
    if grown.is_empty() {
        return Ok(Ok(None));
    }

    let mut remaining_reserved_ranges = reserved_ranges.to_vec();
    let mut text_sections = Vec::with_capacity(grown.len());
    let mut auxiliary_sections = Vec::new();
    let mut auxiliary_patches = Vec::new();
    let mut appended_records = Vec::new();
    let mut retired_record_keys = Vec::new();
    let mut normalized_archive_identifiers = Vec::new();
    let mut previous_inputs = HashSet::new();
    let mut current_inputs = HashSet::new();
    let mut normalized_identifiers = HashSet::new();

    for (matched_section_index, matched) in grown {
        if !previous_inputs.insert(matched.previous.input.as_str())
            || !current_inputs.insert(matched.current.input.as_str())
        {
            return Ok(Err(
                "changed Mach-O input has multiple grown text sections in one object".to_owned(),
            ));
        }
        let Some(previous_input) = previous_resolver.resolve(
            input_file_path,
            matched.previous.input.as_str(),
            PatchInputLookup::MatchArchiveMember,
        )?
        else {
            return Ok(Err(
                "could not resolve previous grown Mach-O text input".to_owned()
            ));
        };
        let Some(current_input) = current_resolver.resolve(
            input_file_path,
            matched.current.input.as_str(),
            PatchInputLookup::MatchArchiveMember,
        )?
        else {
            return Ok(Err(
                "could not resolve current grown Mach-O text input".to_owned()
            ));
        };
        let previous_file = object::File::parse(previous_input.bytes)
            .context("Failed to parse previous grown Mach-O text input")?;
        let current_file = object::File::parse(current_input.bytes)
            .context("Failed to parse current grown Mach-O text input")?;
        if !is_supported_incremental_macho_object(&previous_file)
            || !is_supported_incremental_macho_object(&current_file)
        {
            return Ok(Err(
                "grown Mach-O text input is not a supported arm64 object".to_owned(),
            ));
        }
        let Some(previous_index) = patch_section_index(&previous_file, &matched.previous)? else {
            return Ok(Err(
                "could not resolve previous grown Mach-O text section".to_owned()
            ));
        };
        let Some(current_index) = patch_section_index(&current_file, &matched.current)? else {
            return Ok(Err(
                "could not resolve current grown Mach-O text section".to_owned()
            ));
        };
        let previous_text = previous_file
            .section_by_index(previous_index)
            .context("Missing previous grown Mach-O text section")?;
        let current_text = current_file
            .section_by_index(current_index)
            .context("Missing current grown Mach-O text section")?;
        for text in [&previous_text, &current_text] {
            let object::SectionFlags::MachO { flags } = text.flags() else {
                return Ok(Err("grown text section is not a Mach-O section".to_owned()));
            };
            if text.segment_name_bytes().ok().flatten() != Some(b"__TEXT".as_slice())
                || text.name_bytes().ok() != Some(b"__text".as_slice())
                || flags & object::macho::SECTION_TYPE != object::macho::S_REGULAR
            {
                return Ok(Err(
                    "grown Mach-O section is not regular __TEXT,__text".to_owned()
                ));
            }
        }
        let previous_data = previous_text
            .data()
            .context("Failed to read previous grown Mach-O text section")?;
        let current_data = current_text
            .data()
            .context("Failed to read current grown Mach-O text section")?;
        if previous_data.len() as u64 != matched.previous.input_size
            || current_data.len() as u64 != matched.current.input_size
            || current_data.len() <= previous_data.len()
        {
            return Ok(Err(
                "grown Mach-O text section size is inconsistent".to_owned()
            ));
        }

        let alignment = crate::alignment::Alignment::new(current_text.align().max(1))
            .context("Invalid grown Mach-O text section alignment")?;
        let data_size =
            u64::try_from(current_data.len()).context("Grown Mach-O text section is too large")?;
        let padding = (u128::from(data_size) * u128::from(padding_percent)).div_ceil(100);
        let requested_size = u64::try_from(u128::from(data_size) + padding)
            .context("Grown Mach-O text section allocation size overflow")?;
        let output_section_id = u32::try_from(crate::output_section_id::TEXT.as_usize())
            .context("Mach-O text output section ID does not fit u32")?;
        let Some(allocation) = allocate_reserved_range(
            &mut remaining_reserved_ranges,
            output_section_id,
            alignment.exponent,
            requested_size,
        )?
        else {
            return Ok(Err(
                "insufficient incremental reserve for grown Mach-O text section".to_owned(),
            ));
        };
        let mut section = matched.current.clone();
        section.output_offset = allocation.output_offset;
        section.output_size = allocation.size;
        section.data_hash = Some(hash_bytes(current_data));
        text_sections.push(ActivatedMachOTextSection {
            section,
            matched_section_index: Some(matched_section_index),
        });

        let auxiliary = match grown_macho_text_auxiliary_section_activation(
            &previous_file,
            &current_file,
            input_file_path,
            matched.previous.input.as_str(),
            matched.current.input.as_str(),
            &mut remaining_reserved_ranges,
            padding_percent,
        )? {
            Ok(auxiliary) => auxiliary,
            Err(reason) => return Ok(Err(reason)),
        };
        auxiliary_sections.extend(auxiliary.sections);
        auxiliary_patches.extend(auxiliary.patches);
        appended_records.extend(auxiliary.records);
        retired_record_keys.extend(auxiliary.retired_record_keys);

        let normalized_archive_identifier = match (
            previous_input.archive_identifier,
            current_input.archive_identifier,
        ) {
            (None, None) => None,
            (Some(previous), Some(current)) => {
                let normalized_previous = archive_member_patch_identifier(previous);
                let normalized_current = archive_member_patch_identifier(current);
                if normalized_previous != normalized_current {
                    return Ok(Err(
                        "grown Mach-O text section changed archive identity".to_owned()
                    ));
                }
                if !normalized_identifiers.insert(normalized_current.clone()) {
                    return Ok(Err(
                        "grown Mach-O text sections have ambiguous archive identities".to_owned(),
                    ));
                }
                (previous != current).then_some(normalized_current)
            }
            _ => {
                return Ok(Err(
                    "grown Mach-O text section changed archive membership".to_owned()
                ));
            }
        };
        if let Some(identifier) = normalized_archive_identifier {
            normalized_archive_identifiers.push(identifier);
        }
    }

    let activated_ranges = text_sections
        .iter()
        .map(|activated| {
            let end = activated
                .section
                .output_offset
                .checked_add(activated.section.output_size)
                .context("Grown Mach-O text allocation range overflow")?;
            Ok(activated.section.output_offset..end)
        })
        .chain(auxiliary_sections.iter().map(|section| {
            let end = section
                .output_offset
                .checked_add(section.output_size)
                .context("Grown Mach-O auxiliary allocation range overflow")?;
            Ok(section.output_offset..end)
        }))
        .collect::<Result<Vec<_>>>()?;
    for (index, range) in activated_ranges.iter().enumerate() {
        if activated_ranges
            .iter()
            .skip(index + 1)
            .any(|other| range.start < other.end && other.start < range.end)
        {
            return Ok(Err(
                "grown Mach-O text activation allocations overlap".to_owned()
            ));
        }
    }

    Ok(Ok(Some(MachOTextSectionActivation {
        text_sections,
        auxiliary_sections,
        auxiliary_patches,
        appended_records,
        retired_record_keys,
        grew_existing_sections: true,
        normalized_archive_identifiers,
        remaining_reserved_ranges,
    })))
}

#[derive(Default)]
struct GrownMachOTextAuxiliarySectionActivation {
    sections: Vec<PatchSection>,
    patches: Vec<SectionPatch>,
    records: Vec<SectionRecord>,
    retired_record_keys: Vec<(String, u32)>,
}

#[allow(clippy::too_many_arguments)]
fn grown_macho_text_auxiliary_section_activation(
    previous_file: &object::File<'_>,
    current_file: &object::File<'_>,
    input_file_path: &str,
    previous_input_ref: &str,
    current_input_ref: &str,
    remaining_reserved_ranges: &mut Vec<ReservedRangeRecord>,
    padding_percent: u32,
) -> Result<std::result::Result<GrownMachOTextAuxiliarySectionActivation, String>> {
    let current_sections = current_file
        .sections()
        .filter(|section| {
            section.segment_name_bytes().ok().flatten() == Some(b"__TEXT".as_slice())
                && section.name_bytes().ok() == Some(b"__gcc_except_tab".as_slice())
        })
        .collect::<Vec<_>>();
    let current = match current_sections.as_slice() {
        [] => return Ok(Ok(GrownMachOTextAuxiliarySectionActivation::default())),
        [section] => section,
        _ => {
            return Ok(Err(
                "grown Mach-O text input has multiple __TEXT,__gcc_except_tab sections".to_owned(),
            ));
        }
    };
    let current_data = current
        .data()
        .context("Failed to read grown Mach-O exception table")?;
    if current_data.is_empty() {
        return Ok(Ok(GrownMachOTextAuxiliarySectionActivation::default()));
    }
    let object::SectionFlags::MachO { flags } = current.flags() else {
        return Ok(Err(
            "grown Mach-O exception table is not a Mach-O section".to_owned()
        ));
    };
    let Some(output_section_id) =
        added_macho_archive_output_section_id(b"__TEXT", b"__gcc_except_tab", flags)
    else {
        return Ok(Err(
            "grown Mach-O exception table has unsupported flags".to_owned()
        ));
    };
    if current.relocations().next().is_some() {
        return Ok(Err(
            "grown Mach-O exception table contains relocations".to_owned()
        ));
    }

    let previous_sections = previous_file
        .sections()
        .filter(|section| {
            section.segment_name_bytes().ok().flatten() == Some(b"__TEXT".as_slice())
                && section.name_bytes().ok() == Some(b"__gcc_except_tab".as_slice())
        })
        .collect::<Vec<_>>();
    let previous = match previous_sections.as_slice() {
        [] => None,
        [section] => Some(section),
        _ => {
            return Ok(Err(
                "previous grown Mach-O text input has multiple __TEXT,__gcc_except_tab sections"
                    .to_owned(),
            ));
        }
    };
    if let Some(previous) = previous {
        let previous_data = previous
            .data()
            .context("Failed to read previous grown Mach-O exception table")?;
        if !previous_data.is_empty() {
            if previous_data == current_data {
                return Ok(Ok(GrownMachOTextAuxiliarySectionActivation::default()));
            }
            return Ok(Err(
                "grown Mach-O text input changed an existing exception table".to_owned(),
            ));
        }
    }

    let alignment = crate::alignment::Alignment::new(current.align().max(1))
        .context("Invalid grown Mach-O exception table alignment")?;
    let data_size =
        u64::try_from(current_data.len()).context("Grown Mach-O exception table is too large")?;
    let padding = (u128::from(data_size) * u128::from(padding_percent)).div_ceil(100);
    let requested_size = u64::try_from(u128::from(data_size) + padding)
        .context("Grown Mach-O exception table allocation size overflow")?;
    let output_section_id = u32::try_from(output_section_id.as_usize())
        .context("Mach-O exception table output section ID does not fit u32")?;
    let Some(allocation) = allocate_reserved_range(
        remaining_reserved_ranges,
        output_section_id,
        alignment.exponent,
        requested_size,
    )?
    else {
        return Ok(Err(
            "insufficient incremental reserve for grown Mach-O exception table".to_owned(),
        ));
    };
    let section_index = patch_section_record_index(current_file, current.index())?;
    let section = PatchSection {
        input: current_input_ref.to_owned(),
        section_index,
        section_name: Some("__TEXT,__gcc_except_tab".to_owned()),
        input_size: data_size,
        output_offset: allocation.output_offset,
        output_size: allocation.size,
        data_hash: Some(hash_bytes(current_data)),
        cstring_nul_boundaries_hash: None,
    };
    let record = SectionRecord {
        input_file: input_file_path.into(),
        input: current_input_ref.into(),
        section_index,
        output_offset: allocation.output_offset,
        size: allocation.size,
    };
    let retired_record_keys = if let Some(previous) = previous {
        vec![(
            previous_input_ref.to_owned(),
            patch_section_record_index(previous_file, previous.index())?,
        )]
    } else {
        Vec::new()
    };
    Ok(Ok(GrownMachOTextAuxiliarySectionActivation {
        sections: vec![section],
        patches: vec![SectionPatch {
            output_offset: allocation.output_offset,
            size: allocation.size,
            data: current_data.to_owned(),
            deferred_relocation: None,
            preserve_ranges: Vec::new(),
            adjustments: Vec::new(),
        }],
        records: vec![record],
        retired_record_keys,
    }))
}

fn macho_text_section_activation(
    previous_bytes: &[u8],
    current_bytes: &[u8],
    input_file_path: &str,
    matched_sections: &[MatchedPatchSection],
    reserved_ranges: &[ReservedRangeRecord],
    padding_percent: u32,
    normalize_rust_archive_patch_inputs: bool,
    allow_dormant_text_activation: bool,
) -> Result<std::result::Result<Option<MachOTextSectionActivation>, String>> {
    match grown_macho_text_section_activation(
        previous_bytes,
        current_bytes,
        input_file_path,
        matched_sections,
        reserved_ranges,
        padding_percent,
        normalize_rust_archive_patch_inputs,
    )? {
        Ok(Some(activation)) => return Ok(Ok(Some(activation))),
        Ok(None) => {}
        Err(reason) => return Ok(Err(reason)),
    }
    if !allow_dormant_text_activation {
        return Ok(Ok(None));
    }
    let Ok(previous_file) = object::File::parse(previous_bytes) else {
        return Ok(Ok(None));
    };
    let Ok(current_file) = object::File::parse(current_bytes) else {
        return Ok(Ok(None));
    };
    if !is_supported_incremental_macho_object(&previous_file)
        || !is_supported_incremental_macho_object(&current_file)
    {
        return Ok(Ok(None));
    }
    if matched_sections.iter().any(|section| {
        section.previous.input != input_file_path || section.current.input != input_file_path
    }) {
        return Ok(Ok(None));
    }

    let previous_sections = previous_file.sections().collect::<Vec<_>>();
    let current_sections = current_file.sections().collect::<Vec<_>>();
    let (matched_section_index, previous_text_index, current_text_index, appended) =
        if current_sections.len() == previous_sections.len() {
            let mut dormant = Vec::new();
            for (matched_index, matched) in matched_sections.iter().enumerate() {
                if matched.previous.input_size != 0
                    || matched.previous.output_size != 0
                    || matched.previous.section_name.as_deref() != Some("__TEXT,__text")
                    || matched.current.section_name.as_deref() != Some("__TEXT,__text")
                {
                    continue;
                }
                let Some(previous_index) = patch_section_index(&previous_file, &matched.previous)?
                else {
                    continue;
                };
                let Some(current_index) = patch_section_index(&current_file, &matched.current)?
                else {
                    continue;
                };
                let previous_section = previous_file
                    .section_by_index(previous_index)
                    .context("Missing dormant Mach-O text section")?;
                let current_section = current_file
                    .section_by_index(current_index)
                    .context("Missing activated Mach-O text section")?;
                if previous_section
                    .data()
                    .context("Failed to read dormant Mach-O text section")?
                    .is_empty()
                    && !current_section
                        .data()
                        .context("Failed to read activated Mach-O text section")?
                        .is_empty()
                {
                    dormant.push((matched_index, previous_index, current_index));
                }
            }
            match dormant.as_slice() {
                [] => return Ok(Ok(None)),
                [candidate] => (Some(candidate.0), Some(candidate.1), candidate.2, false),
                _ => {
                    return Ok(Err(
                        "changed Mach-O object activated more than one text section".to_owned(),
                    ));
                }
            }
        } else if current_sections.len() == previous_sections.len() + 1 {
            let added = current_sections
                .last()
                .context("Missing appended Mach-O text section")?;
            if added.index().0 != current_sections.len() {
                return Ok(Err("added Mach-O text section was not appended".to_owned()));
            }
            (None, None, added.index(), true)
        } else {
            return Ok(Err(
                "changed Mach-O object added more than one section".to_owned()
            ));
        };
    let text = current_file
        .section_by_index(current_text_index)
        .context("Missing activated Mach-O text section")?;
    let segment_name = text.segment_name_bytes().ok().flatten();
    let section_name = text.name_bytes().ok();
    let object::SectionFlags::MachO { flags } = text.flags() else {
        return Ok(Err("activated section is not a Mach-O section".to_owned()));
    };
    if segment_name != Some(b"__TEXT".as_slice())
        || section_name != Some(b"__text".as_slice())
        || flags & object::macho::SECTION_TYPE != object::macho::S_REGULAR
    {
        return Ok(Err(
            "activated Mach-O section is not regular __TEXT,__text".to_owned()
        ));
    }
    let data = text
        .data()
        .context("Failed to read activated Mach-O text section data")?;
    if data.is_empty() {
        return Ok(Err("activated Mach-O text section is empty".to_owned()));
    }
    if text.relocations().next().is_some() {
        return Ok(Err(
            "activated Mach-O text section contains relocations".to_owned()
        ));
    }
    if let Some(previous_text_index) = previous_text_index {
        let previous_text = previous_file
            .section_by_index(previous_text_index)
            .context("Missing dormant Mach-O text section")?;
        if previous_text.relocations().next().is_some() {
            return Ok(Err(
                "dormant Mach-O text section contains relocations".to_owned()
            ));
        }
        let previous_symbols =
            macho_section_symbols_fingerprint(&previous_file, previous_text_index);
        let current_symbols = macho_section_symbols_fingerprint(&current_file, current_text_index);
        if previous_symbols.is_none() || previous_symbols != current_symbols {
            return Ok(Err(
                "activated Mach-O text section changed symbols".to_owned()
            ));
        }
    } else if current_file
        .symbols()
        .any(|symbol| symbol.section_index() == Some(current_text_index))
    {
        return Ok(Err("added Mach-O text section contains symbols".to_owned()));
    }
    for section in current_file.sections() {
        for (_, relocation) in section.relocations() {
            let targets_added_section = match relocation.target() {
                object::RelocationTarget::Section(index) => index == current_text_index,
                object::RelocationTarget::Symbol(index) => current_file
                    .symbol_by_index(index)
                    .is_ok_and(|symbol| symbol.section_index() == Some(current_text_index)),
                _ => false,
            } || relocation.subtractor().is_some_and(|index| {
                current_file
                    .symbol_by_index(index)
                    .is_ok_and(|symbol| symbol.section_index() == Some(current_text_index))
            });
            if targets_added_section {
                return Ok(Err(
                    "activated Mach-O text section is targeted by a relocation".to_owned(),
                ));
            }
        }
    }

    let proof_sections = matched_sections
        .iter()
        .enumerate()
        .filter(|(index, _)| Some(*index) != matched_section_index)
        .map(|(_, section)| section)
        .collect::<Vec<_>>();
    let previous_ranges = patch_ranges_with_lookup(
        previous_bytes,
        input_file_path,
        proof_sections
            .iter()
            .map(|section| section.previous.clone()),
        PatchInputLookup::MatchArchiveMember,
    )?
    .context("Could not resolve previous Mach-O patch sections")?;
    let current_ranges = patch_ranges_with_lookup(
        current_bytes,
        input_file_path,
        proof_sections.iter().map(|section| section.current.clone()),
        PatchInputLookup::MatchArchiveMember,
    )?
    .context("Could not resolve current Mach-O patch sections")?;
    let previous_fingerprint = macho_object_semantic_patch_fingerprint(
        previous_bytes,
        0,
        &previous_ranges,
        &previous_text_index.into_iter().collect(),
        &HashSet::new(),
        &HashSet::new(),
        false,
        false,
    );
    let current_fingerprint = macho_object_semantic_patch_fingerprint(
        current_bytes,
        0,
        &current_ranges,
        &HashSet::from([current_text_index]),
        &HashSet::new(),
        &HashSet::new(),
        false,
        false,
    );
    if previous_fingerprint.is_none() || previous_fingerprint != current_fingerprint {
        return Ok(Err(
            "changed Mach-O object outside activated __TEXT,__text section".to_owned(),
        ));
    }

    let alignment = crate::alignment::Alignment::new(text.align().max(1))
        .context("Invalid activated Mach-O text section alignment")?;
    let data_size =
        u64::try_from(data.len()).context("Activated Mach-O text section is too large")?;
    let padding = (u128::from(data_size) * u128::from(padding_percent)).div_ceil(100);
    let requested_size = u64::try_from(u128::from(data_size) + padding)
        .context("Added Mach-O text section allocation size overflow")?;
    let output_section_id = u32::try_from(crate::output_section_id::TEXT.as_usize())
        .context("Mach-O text output section ID does not fit u32")?;
    let mut remaining_reserved_ranges = reserved_ranges.to_vec();
    let Some(allocation) = allocate_reserved_range(
        &mut remaining_reserved_ranges,
        output_section_id,
        alignment.exponent,
        requested_size,
    )?
    else {
        return Ok(Err(
            "insufficient incremental reserve for activated Mach-O text section".to_owned(),
        ));
    };
    let section_index = patch_section_record_index(&current_file, current_text_index)?;
    let section = PatchSection {
        input: input_file_path.to_owned(),
        section_index,
        section_name: Some("__TEXT,__text".to_owned()),
        input_size: data_size,
        output_offset: allocation.output_offset,
        output_size: allocation.size,
        data_hash: Some(hash_bytes(data)),
        cstring_nul_boundaries_hash: None,
    };
    let appended_records = appended
        .then(|| SectionRecord {
            input_file: input_file_path.into(),
            input: input_file_path.into(),
            section_index,
            output_offset: allocation.output_offset,
            size: allocation.size,
        })
        .into_iter()
        .collect();
    Ok(Ok(Some(MachOTextSectionActivation {
        text_sections: vec![ActivatedMachOTextSection {
            section,
            matched_section_index,
        }],
        auxiliary_sections: Vec::new(),
        auxiliary_patches: Vec::new(),
        appended_records,
        retired_record_keys: Vec::new(),
        grew_existing_sections: false,
        normalized_archive_identifiers: Vec::new(),
        remaining_reserved_ranges,
    })))
}

fn macho_archive_unwind_input_ranges(
    input: PatchInputBytes<'_>,
    file: &object::File<'_>,
    unwind: &AddedMachOArchiveUnwind,
) -> Result<std::result::Result<Vec<std::ops::Range<usize>>, String>> {
    let mut ranges = Vec::new();
    for section_index in unwind
        .compact_unwind
        .iter()
        .map(|compact| compact.section_index)
        .chain(
            unwind
                .eh_frame
                .iter()
                .map(|eh_frame| eh_frame.section_index),
        )
    {
        let object_section_index = patch_section_object_index(file, section_index)?;
        let section = file.section_by_index(object_section_index)?;
        let Some((offset, size)) = section.file_range() else {
            return Ok(Err(
                "changed Mach-O unwind section has no input file range".to_owned()
            ));
        };
        let start = input
            .file_offset
            .checked_add(
                usize::try_from(offset)
                    .context("Changed Mach-O unwind section offset exceeds usize")?,
            )
            .context("Changed Mach-O unwind section offset overflow")?;
        let end = start
            .checked_add(
                usize::try_from(size)
                    .context("Changed Mach-O unwind section size exceeds usize")?,
            )
            .context("Changed Mach-O unwind section range overflow")?;
        ranges.push(start..end);
    }
    ranges.sort_by_key(|range| range.start);
    Ok(Ok(ranges))
}

fn macho_unwind_function_identities(
    input: &str,
    unwind: &AddedMachOArchiveUnwind,
    sections: &[PatchSection],
    output_file: &object::File<'_>,
) -> std::result::Result<Vec<MachOUnwindFunctionIdentity>, String> {
    let mut functions = Vec::new();
    if let Some(compact_unwind) = &unwind.compact_unwind {
        functions.extend(
            compact_unwind
                .entries
                .iter()
                .filter(|entry| {
                    entry.encoding & ADDED_MACHO_UNWIND_MODE_MASK != ADDED_MACHO_UNWIND_MODE_DWARF
                })
                .map(|entry| (entry.function.clone(), entry.function_length)),
        );
    }
    if let Some(eh_frame) = &unwind.eh_frame {
        functions.extend(eh_frame.fdes.iter().filter_map(|fde| {
            let has_compact_entry = unwind.compact_unwind.as_ref().is_some_and(|compact| {
                compact.entries.iter().any(|entry| {
                    entry.encoding & ADDED_MACHO_UNWIND_MODE_MASK != ADDED_MACHO_UNWIND_MODE_DWARF
                        && entry.function == fde.function
                        && entry.function_length == fde.function_length
                })
            });
            (!has_compact_entry).then(|| (fde.function.clone(), fde.function_length))
        }));
    }

    let mut identities = Vec::with_capacity(functions.len());
    for (function, length) in functions {
        let section = sections
            .iter()
            .find(|section| {
                section.input == input && section.section_index == function.section_index
            })
            .ok_or_else(|| {
                "changed Mach-O unwind function section has no previous output mapping".to_owned()
            })?;
        if function.section_offset >= section.input_size {
            return Err("changed Mach-O unwind function is outside its section".to_owned());
        }
        let section_address =
            macho_output_address_for_file_offset(output_file, section.output_offset).ok_or_else(
                || "changed Mach-O unwind function section has no output address".to_owned(),
            )?;
        let function_address = section_address
            .checked_add(function.section_offset)
            .ok_or_else(|| "changed Mach-O unwind function address overflowed".to_owned())?;
        identities.push(MachOUnwindFunctionIdentity {
            function_offset: added_macho_archive_image_offset(function_address)?,
            length,
        });
    }
    identities.sort_by_key(|identity| (identity.function_offset, identity.length));
    identities.dedup();
    for pair in identities.windows(2) {
        if added_macho_archive_unwind_ranges_overlap(
            pair[0].function_offset,
            pair[0].length,
            pair[1].function_offset,
            pair[1].length,
        ) {
            return Err("changed Mach-O unwind function identities overlap or conflict".to_owned());
        }
    }
    Ok(identities)
}

#[allow(clippy::too_many_arguments)]
fn changed_macho_archive_unwind_members(
    previous_bytes: &[u8],
    input_file_path: &str,
    matched_sections: &[MatchedPatchSection],
    current_resolver: &PatchInputResolver<'_>,
    output_file: &object::File<'_>,
    excluded_identifiers: &[Vec<u8>],
) -> Result<std::result::Result<ChangedMachOArchiveUnwindMembers, String>> {
    let previous_resolver = PatchInputResolver::new(previous_bytes, true)?;
    let mut input_pairs = matched_sections
        .iter()
        .map(|matched| {
            (
                matched.previous.input.clone(),
                matched.current.input.clone(),
            )
        })
        .collect::<Vec<_>>();
    input_pairs.sort_unstable();
    input_pairs.dedup();
    let previous_sections = matched_sections
        .iter()
        .map(|matched| matched.previous.clone())
        .collect::<Vec<_>>();

    let mut members = Vec::new();
    let mut retired_entries = Vec::new();
    let mut previous_input_ranges = Vec::new();
    let mut current_input_ranges = Vec::new();
    for (previous_input_ref, current_input_ref) in input_pairs {
        let Some(previous_input) = previous_resolver.resolve(
            input_file_path,
            previous_input_ref.as_str(),
            PatchInputLookup::MatchArchiveMember,
        )?
        else {
            return Ok(Err(
                "could not resolve previous changed Mach-O unwind member".to_owned(),
            ));
        };
        let Some(current_input) = current_resolver.resolve(
            input_file_path,
            current_input_ref.as_str(),
            PatchInputLookup::MatchArchiveMember,
        )?
        else {
            return Ok(Err(
                "could not resolve current changed Mach-O unwind member".to_owned(),
            ));
        };
        if current_input.archive_identifier.is_some_and(|identifier| {
            let identifier = archive_member_patch_identifier(identifier);
            excluded_identifiers
                .iter()
                .any(|excluded| excluded == &identifier)
        }) {
            continue;
        }

        let Ok(previous_file) = object::File::parse(previous_input.bytes) else {
            continue;
        };
        let Ok(current_file) = object::File::parse(current_input.bytes) else {
            continue;
        };
        if !is_supported_incremental_macho_object(&previous_file)
            || !is_supported_incremental_macho_object(&current_file)
        {
            continue;
        }
        let previous_unwind = match added_macho_archive_unwind(&previous_file)? {
            Ok(unwind) => unwind,
            Err(reason) => return Ok(Err(reason)),
        };
        let current_unwind = match added_macho_archive_unwind(&current_file)? {
            Ok(unwind) => unwind,
            Err(reason) => return Ok(Err(reason)),
        };
        if previous_unwind == current_unwind {
            continue;
        }
        let (Some(previous_unwind), Some(current_unwind)) = (previous_unwind, current_unwind)
        else {
            return Ok(Err(
                "changed Mach-O member added or removed all unwind metadata".to_owned(),
            ));
        };

        let previous_ranges = match macho_archive_unwind_input_ranges(
            previous_input,
            &previous_file,
            &previous_unwind,
        )? {
            Ok(ranges) => ranges,
            Err(reason) => return Ok(Err(reason)),
        };
        let current_ranges =
            match macho_archive_unwind_input_ranges(current_input, &current_file, &current_unwind)?
            {
                Ok(ranges) => ranges,
                Err(reason) => return Ok(Err(reason)),
            };
        previous_input_ranges.extend(previous_ranges);
        current_input_ranges.extend(current_ranges);
        retired_entries.extend(
            match macho_unwind_function_identities(
                previous_input_ref.as_str(),
                &previous_unwind,
                &previous_sections,
                output_file,
            ) {
                Ok(identities) => identities,
                Err(reason) => return Ok(Err(reason)),
            },
        );

        let Some(text) = current_file.section_by_name("__text") else {
            return Ok(Err(
                "changed Mach-O unwind member has no __text section".to_owned()
            ));
        };
        members.push(AddedMachOArchiveTextMember {
            input: current_input_ref,
            sections: Vec::new(),
            unwind: Some(current_unwind),
            text_section_index: patch_section_record_index(&current_file, text.index())?,
            text_object_section_index: relocation_target_record_index(text.index())?,
            definitions: Vec::new(),
            referenced_names: Vec::new(),
        });
    }

    retired_entries.sort_by_key(|identity| (identity.function_offset, identity.length));
    if retired_entries.windows(2).any(|pair| {
        added_macho_archive_unwind_ranges_overlap(
            pair[0].function_offset,
            pair[0].length,
            pair[1].function_offset,
            pair[1].length,
        )
    }) {
        return Ok(Err(
            "changed Mach-O unwind retirement identities overlap or are duplicated".to_owned(),
        ));
    }
    previous_input_ranges.sort_by_key(|range| range.start);
    current_input_ranges.sort_by_key(|range| range.start);
    Ok(Ok(ChangedMachOArchiveUnwindMembers {
        members,
        retired_entries,
        previous_input_ranges,
        current_input_ranges,
    }))
}

fn archive_diff_allows_changed_macho_unwind(
    previous_bytes: &[u8],
    current_bytes: &[u8],
    input_file_path: &str,
    matched_sections: &[MatchedPatchSection],
    current_resolver: &PatchInputResolver<'_>,
    changed: &ChangedMachOArchiveUnwindMembers,
    ignored_previous_identifiers: &[Vec<u8>],
    ignored_current_identifiers: &[Vec<u8>],
) -> Result<bool> {
    let previous_resolver = PatchInputResolver::new(previous_bytes, true)?;
    let Some(mut previous_ranges) = patch_ranges_with_resolver(
        previous_bytes,
        input_file_path,
        matched_sections
            .iter()
            .map(|section| section.previous.clone()),
        &previous_resolver,
        PatchInputLookup::MatchArchiveMember,
    )?
    else {
        return Ok(false);
    };
    let Some(mut current_ranges) = patch_ranges_with_resolver(
        current_bytes,
        input_file_path,
        matched_sections
            .iter()
            .map(|section| section.current.clone()),
        current_resolver,
        PatchInputLookup::MatchArchiveMember,
    )?
    else {
        return Ok(false);
    };
    previous_ranges.extend(changed.previous_input_ranges.iter().cloned());
    current_ranges.extend(changed.current_input_ranges.iter().cloned());
    dedup_ranges(&mut previous_ranges);
    dedup_ranges(&mut current_ranges);
    let Some((previous_fingerprint, _)) = archive_patch_fingerprint_with_previous(
        previous_bytes,
        &previous_ranges,
        None,
        false,
        ignored_previous_identifiers,
        &[],
    )?
    else {
        return Ok(false);
    };
    let Some((current_fingerprint, _)) = archive_patch_fingerprint_with_previous(
        current_bytes,
        &current_ranges,
        None,
        false,
        ignored_current_identifiers,
        &[],
    )?
    else {
        return Ok(false);
    };
    if previous_fingerprint == current_fingerprint {
        return Ok(true);
    }
    if ignored_previous_identifiers.is_empty() && ignored_current_identifiers.is_empty() {
        return Ok(false);
    }

    let previous_fingerprint = archive_macho_member_retirement_fingerprint(
        previous_bytes,
        &previous_ranges,
        ignored_previous_identifiers,
        &HashSet::new(),
    )?;
    let current_fingerprint = archive_macho_member_retirement_fingerprint(
        current_bytes,
        &current_ranges,
        ignored_current_identifiers,
        &HashSet::new(),
    )?;
    Ok(previous_fingerprint.is_some() && previous_fingerprint == current_fingerprint)
}

#[allow(clippy::too_many_arguments)]
fn changed_macho_archive_unwind_activation(
    previous_bytes: &[u8],
    current_bytes: &[u8],
    input_file_path: &str,
    matched_sections: &[MatchedPatchSection],
    current_sections: &[PatchSection],
    current_resolver: &PatchInputResolver<'_>,
    previous_output: &[u8],
    resolutions: &[MachOSymbolResolutionRecord],
    reserved_ranges: &[ReservedRangeRecord],
    added_definition_names: &[SharedText],
    retired_definition_names: &[SharedText],
    reuse_owned_output: bool,
    ignored_previous_identifiers: &[Vec<u8>],
    ignored_current_identifiers: &[Vec<u8>],
) -> Result<std::result::Result<Option<ChangedMachOArchiveUnwindActivation>, String>> {
    let output_file = object::File::parse(previous_output)
        .context("Failed to parse previous Mach-O output for changed unwind metadata")?;
    let changed = match changed_macho_archive_unwind_members(
        previous_bytes,
        input_file_path,
        matched_sections,
        current_resolver,
        &output_file,
        ignored_previous_identifiers,
    )? {
        Ok(changed) => changed,
        Err(reason) => return Ok(Err(reason)),
    };
    if changed.members.is_empty() {
        return Ok(Ok(None));
    }
    let allows_unwind_only = archive_diff_allows_changed_macho_unwind(
        previous_bytes,
        current_bytes,
        input_file_path,
        matched_sections,
        current_resolver,
        &changed,
        ignored_previous_identifiers,
        ignored_current_identifiers,
    )?;
    let allows_unwind_and_definitions = !allows_unwind_only
        && archive_diff_allows_changed_macho_symbols(
            previous_bytes,
            current_bytes,
            input_file_path,
            matched_sections,
            current_resolver,
            ignored_previous_identifiers,
            ignored_current_identifiers,
            &changed.previous_input_ranges,
            &changed.current_input_ranges,
            added_definition_names,
            retired_definition_names,
            true,
        )?;
    if !allows_unwind_only && !allows_unwind_and_definitions {
        return Ok(Err(
            "changed Mach-O archive member differs outside text and unwind metadata".to_owned(),
        ));
    }
    if reuse_owned_output {
        return Ok(Ok(Some(ChangedMachOArchiveUnwindActivation {
            patches: Vec::new(),
            previous_input_ranges: changed.previous_input_ranges,
            current_input_ranges: changed.current_input_ranges,
            remaining_reserved_ranges: reserved_ranges.to_vec(),
        })));
    }

    let selected_indices = (0..changed.members.len()).collect::<Vec<_>>();
    let mut remaining_reserved_ranges = reserved_ranges.to_vec();
    let activation = match added_macho_archive_unwind_activation(
        &changed.members,
        &selected_indices,
        current_sections,
        &output_file,
        resolutions,
        &changed.retired_entries,
        &mut remaining_reserved_ranges,
    )? {
        Ok(Some(activation)) => activation,
        Ok(None) => {
            return Ok(Err(
                "changed Mach-O archive unwind metadata produced no output patch".to_owned(),
            ));
        }
        Err(reason) => return Ok(Err(reason)),
    };
    Ok(Ok(Some(ChangedMachOArchiveUnwindActivation {
        patches: activation.patches,
        previous_input_ranges: changed.previous_input_ranges,
        current_input_ranges: changed.current_input_ranges,
        remaining_reserved_ranges,
    })))
}

fn added_macho_archive_text_activations(
    previous_bytes: &[u8],
    current_bytes: &[u8],
    input_file_path: &str,
    added_identifiers: &[Vec<u8>],
    matched_sections: &[MatchedPatchSection],
    existing_current_sections: &[PatchSection],
    current_resolver: &PatchInputResolver<'_>,
    excluded_unwind_identifiers: &[Vec<u8>],
    reserved_ranges: &[ReservedRangeRecord],
    padding_percent: u32,
    previous_output: &[u8],
    relocations: &[RelocationRecord],
    resolutions: &[MachOSymbolResolutionRecord],
    retiring_names: &[SharedText],
) -> Result<std::result::Result<AddedMachOArchiveTextActivations, String>> {
    let Ok(archive) = ArchiveIterator::from_archive_bytes(current_bytes) else {
        return Ok(Err(
            "added Mach-O text member input is not an archive".to_owned()
        ));
    };
    let added_identifier_set = added_identifiers
        .iter()
        .map(Vec::as_slice)
        .collect::<HashSet<_>>();
    let mut added_members = HashMap::with_capacity(added_identifiers.len());
    let mut other_members = Vec::new();
    for entry in archive {
        let ArchiveEntry::Regular(content) = entry? else {
            return Ok(Err(
                "added Mach-O text member requires a regular archive".to_owned()
            ));
        };
        if added_identifier_set.contains(content.ident.as_slice()) {
            let member = PatchInputBytes {
                bytes: content.entry_data,
                file_offset: content.data_offset,
                archive_identifier: Some(content.ident.as_slice()),
            };
            if added_members
                .insert(content.ident.as_slice().to_vec(), member)
                .is_some()
            {
                return Ok(Err(
                    "added Mach-O text archive member identifier is ambiguous".to_owned(),
                ));
            }
        } else {
            other_members.push(content.entry_data);
        }
    }
    if added_members.len() != added_identifiers.len() {
        return Ok(Err(
            "could not resolve added Mach-O text archive member".to_owned()
        ));
    }

    let mut members = Vec::with_capacity(added_identifiers.len());
    for identifier in added_identifiers {
        let added_member = added_members
            .get(identifier.as_slice())
            .context("Missing added Mach-O text archive member")?;
        let member = match added_macho_archive_text_member(
            input_file_path,
            *added_member,
            &other_members,
            resolutions,
            retiring_names,
        )? {
            Ok(member) => member,
            Err(reason) => return Ok(Err(reason)),
        };
        members.push(member);
    }

    let definition_count = members
        .iter()
        .map(|member| member.definitions.len())
        .sum::<usize>();
    let mut definitions = HashMap::<Vec<u8>, usize>::with_capacity(definition_count);
    for (member_index, member) in members.iter().enumerate() {
        for definition in &member.definitions {
            if definitions
                .insert(definition.name.clone(), member_index)
                .is_some()
            {
                return Ok(Err(
                    "added Mach-O archive member definition is ambiguous".to_owned()
                ));
            }
        }
    }
    let seed_references = match added_macho_archive_seed_references(
        input_file_path,
        matched_sections,
        current_resolver,
        &definitions,
    )? {
        Ok(references) => references,
        Err(reason) => return Ok(Err(reason)),
    };
    let selected_indices =
        selected_added_macho_archive_member_indices(&members, &definitions, seed_references);
    if selected_indices.is_empty() {
        return Ok(Err(
            "added Mach-O archive members are not referenced by changed text".to_owned(),
        ));
    }
    if selected_indices.len() != members.len() {
        return Ok(Err(
            "could not prove all added Mach-O archive members are selected".to_owned(),
        ));
    }
    let output_file = object::File::parse(previous_output)
        .context("Failed to parse previous Mach-O output for added archive members")?;
    let mut remaining_reserved_ranges = reserved_ranges.to_vec();
    let section_count = selected_indices
        .iter()
        .map(|&member_index| members[member_index].sections.len())
        .sum();
    let mut sections = Vec::with_capacity(section_count);
    let mut records = Vec::with_capacity(section_count);
    let mut selected_definitions = selected_indices
        .iter()
        .flat_map(|&member_index| {
            (0..members[member_index].definitions.len())
                .map(move |definition_index| (member_index, definition_index))
        })
        .collect::<Vec<_>>();
    for (retiring_index, retiring_name) in retiring_names.iter().enumerate() {
        let Some(matching_index) = selected_definitions
            .iter()
            .enumerate()
            .skip(retiring_index)
            .find_map(|(index, &(member_index, definition_index))| {
                (hex::encode(&members[member_index].definitions[definition_index].name)
                    == retiring_name.as_str())
                .then_some(index)
            })
        else {
            continue;
        };
        selected_definitions.swap(retiring_index, matching_index);
    }
    let mut symbol_resolutions = Vec::with_capacity(selected_definitions.len());
    for &member_index in &selected_indices {
        let member = &members[member_index];
        for source_section in &member.sections {
            let padding =
                (u128::from(source_section.data_size) * u128::from(padding_percent)).div_ceil(100);
            let requested_size = u64::try_from(u128::from(source_section.data_size) + padding)
                .context("Added Mach-O archive member section allocation size overflow")?;
            let Some(allocation) = allocate_reserved_range(
                &mut remaining_reserved_ranges,
                source_section.output_section_id,
                source_section.alignment_exponent,
                requested_size,
            )?
            else {
                return Ok(Err(format!(
                    "insufficient incremental reserve for added Mach-O archive member section {}",
                    source_section.section_name
                )));
            };
            sections.push(PatchSection {
                input: member.input.clone(),
                section_index: source_section.section_index,
                section_name: Some(source_section.section_name.clone()),
                input_size: source_section.data_size,
                output_offset: allocation.output_offset,
                output_size: allocation.size,
                data_hash: Some(source_section.data_hash.clone()),
                cstring_nul_boundaries_hash: None,
            });
            records.push(SectionRecord {
                input_file: input_file_path.into(),
                input: member.input.clone().into(),
                section_index: source_section.section_index,
                output_offset: allocation.output_offset,
                size: allocation.size,
            });
        }
        let Some(text_section) = sections.iter().find(|section| {
            section.input == member.input && section.section_index == member.text_section_index
        }) else {
            return Ok(Err(
                "added Mach-O archive member text section was not allocated".to_owned(),
            ));
        };
        let Some(section_address) =
            macho_output_address_for_file_offset(&output_file, text_section.output_offset)
        else {
            return Ok(Err(
                "added Mach-O archive member text reserve has no output address".to_owned(),
            ));
        };
        for definition in &member.definitions {
            let definition_value = section_address
                .checked_add(definition.offset)
                .context("Added Mach-O archive member definition address overflow")?;
            let target = RelocationTargetRecord {
                input_file: input_file_path.into(),
                input: member.input.clone().into(),
                section_index: member.text_object_section_index,
                section_offset: definition.offset,
            };
            symbol_resolutions.push(MachOSymbolResolutionRecord {
                name: hex::encode(&definition.name).into(),
                direct_value: Some(definition_value),
                got_address: None,
                stub_address: None,
                thunk_addresses: Vec::new(),
                target: Some(target),
            });
        }
    }
    if retiring_names.len() > symbol_resolutions.len() {
        return Ok(Err(
            "removed Mach-O symbols exceed selected new definitions".to_owned(),
        ));
    }
    let (mut symbol_table_patches, recycled_symbol_resolution_names) =
        match recycled_macho_symbol_table_patches(
            previous_output,
            &output_file,
            &members,
            &selected_definitions[..retiring_names.len()],
            &symbol_resolutions[..retiring_names.len()],
            retiring_names,
            resolutions,
            &mut remaining_reserved_ranges,
        )? {
            Ok(patches) => patches,
            Err(reason) => return Ok(Err(reason)),
        };
    let new_symbol_table_patches = match added_macho_symbol_table_patches(
        previous_output,
        &output_file,
        &members,
        &selected_definitions[retiring_names.len()..],
        &symbol_resolutions[retiring_names.len()..],
        &mut remaining_reserved_ranges,
    )? {
        Ok(patches) => patches,
        Err(reason) => return Ok(Err(reason)),
    };
    symbol_table_patches.extend(new_symbol_table_patches);

    let mut combined_resolutions = resolutions.to_vec();
    combined_resolutions.extend(symbol_resolutions.iter().cloned());
    let mut referenced_names = selected_indices
        .iter()
        .flat_map(|&member_index| members[member_index].referenced_names.iter().cloned())
        .collect::<Vec<_>>();
    referenced_names.sort_unstable();
    referenced_names.dedup();
    for referenced_name in referenced_names {
        let encoded_name = hex::encode(&referenced_name);
        match macho_symbol_resolution_index_for_name(&combined_resolutions, &encoded_name) {
            Ok(Some(_)) => continue,
            Ok(None) => {}
            Err(reason) => return Ok(Err(reason)),
        }
        let resolution = match matched_macho_definition_resolution(
            input_file_path,
            &referenced_name,
            matched_sections,
            current_resolver,
            &output_file,
        )? {
            Ok(resolution) => resolution,
            Err(reason) => return Ok(Err(reason)),
        };
        if let Some(resolution) = resolution {
            combined_resolutions.push(resolution.clone());
            symbol_resolutions.push(resolution);
        }
    }
    combined_resolutions.sort_unstable();
    let changed_unwind = match changed_macho_archive_unwind_members(
        previous_bytes,
        input_file_path,
        matched_sections,
        current_resolver,
        &output_file,
        excluded_unwind_identifiers,
    )? {
        Ok(changed) => changed,
        Err(reason) => return Ok(Err(reason)),
    };
    let changed_unwind_member_start = members.len();
    members.extend(changed_unwind.members);
    let unwind_selected_indices = selected_indices
        .iter()
        .copied()
        .chain(changed_unwind_member_start..members.len())
        .collect::<Vec<_>>();
    let mut unwind_sections = sections.clone();
    unwind_sections.extend(existing_current_sections.iter().cloned());
    let unwind_patches = match added_macho_archive_unwind_activation(
        &members,
        &unwind_selected_indices,
        &unwind_sections,
        &output_file,
        &combined_resolutions,
        &changed_unwind.retired_entries,
        &mut remaining_reserved_ranges,
    )? {
        Ok(activation) => activation
            .map(|activation| activation.patches)
            .unwrap_or_default(),
        Err(reason) => return Ok(Err(reason)),
    };
    let mut relocation_replays = match added_macho_archive_text_relocation_replays(
        current_bytes,
        input_file_path,
        &members,
        &selected_indices,
        &sections,
        previous_output,
        relocations,
        &combined_resolutions,
    )? {
        Ok(replays) => replays,
        Err(reason) => return Ok(Err(reason)),
    };
    let (chained_fixup_patches, provisional_relocations) = match added_macho_chained_fixup_patches(
        previous_output,
        &output_file,
        &mut relocation_replays,
    ) {
        Ok(patches) => patches,
        Err(reason) => return Ok(Err(reason)),
    };
    let mut member_identities = Vec::with_capacity(selected_indices.len());
    for &member_index in &selected_indices {
        let member = &members[member_index];
        let Some(input_bytes) = current_resolver.resolve(
            input_file_path,
            member.input.as_str(),
            PatchInputLookup::CurrentRecordedRange,
        )?
        else {
            return Ok(Err(
                "could not retain added Mach-O archive member ownership".to_owned(),
            ));
        };
        let Some(identifier) = parse_patch_input_ref(input_file_path, member.input.as_str())?
        else {
            return Ok(Err(
                "added Mach-O archive member ownership has no identifier".to_owned(),
            ));
        };
        if identifier.identifier.is_empty() {
            return Ok(Err(
                "added Mach-O archive member ownership has no identifier".to_owned(),
            ));
        }
        member_identities.push(MachOArchiveMemberIdentity {
            normalized_identifier: archive_member_patch_identifier(&identifier.identifier),
            object_hash: hash_bytes(input_bytes.bytes),
        });
    }
    let member_states = vec![MachOArchiveActivationState {
        kind: MachOArchiveActivationKind::AddedMembers,
        members: member_identities,
        active: true,
        sections: sections.iter().map(file_patch_section_state).collect(),
        relocations: Vec::new(),
        symbol_resolutions: Vec::new(),
        rollback_symbol_resolutions: Vec::new(),
        forward_patches: Vec::new(),
        rollback_patches: Vec::new(),
    }];

    Ok(Ok(AddedMachOArchiveTextActivations {
        normalized_identifiers: added_identifiers
            .iter()
            .map(|identifier| archive_member_patch_identifier(identifier))
            .collect(),
        member_states,
        reactivated: false,
        reactivated_relocations: Vec::new(),
        reactivated_output_patches: Vec::new(),
        sections,
        records,
        symbol_resolutions,
        recycled_symbol_resolution_names,
        symbol_table_patches,
        chained_fixup_patches,
        unwind_patches,
        relocation_replays,
        provisional_relocations,
        previous_unwind_input_ranges: changed_unwind.previous_input_ranges,
        current_unwind_input_ranges: changed_unwind.current_input_ranges,
        remaining_reserved_ranges,
    }))
}

fn file_patch_section_state(section: &PatchSection) -> FilePatchSectionState {
    FilePatchSectionState {
        input: section.input.clone(),
        section_index: section.section_index,
        section_name: section.section_name.clone(),
        input_size: section.input_size,
        output_offset: section.output_offset,
        output_size: section.output_size,
        data_hash: section.data_hash.clone(),
        cstring_nul_boundaries_hash: section.cstring_nul_boundaries_hash.clone(),
    }
}

fn matched_macho_definition_resolution(
    input_file_path: &str,
    name: &[u8],
    matched_sections: &[MatchedPatchSection],
    current_resolver: &PatchInputResolver<'_>,
    output_file: &object::File<'_>,
) -> Result<std::result::Result<Option<MachOSymbolResolutionRecord>, String>> {
    let mut visited_inputs = HashSet::new();
    let mut matched_resolution = None;
    for matched in matched_sections {
        if !visited_inputs.insert(matched.current.input.as_str()) {
            continue;
        }
        let Some(input_bytes) = current_resolver.resolve(
            input_file_path,
            matched.current.input.as_str(),
            PatchInputLookup::MatchArchiveMember,
        )?
        else {
            return Ok(Err(
                "could not resolve current Mach-O archive member definition".to_owned(),
            ));
        };
        let current_input_ref =
            resolved_patch_input_ref(input_file_path, matched.current.input.as_str(), input_bytes)?;
        let file = object::File::parse(input_bytes.bytes)
            .context("Failed to parse current Mach-O archive member definition")?;
        if !is_supported_incremental_macho_object(&file) {
            continue;
        }
        for symbol in file.symbols() {
            if symbol.is_undefined()
                || !symbol.is_global()
                || symbol.is_weak()
                || symbol.name_bytes()? != name
            {
                continue;
            }
            let Some(section_index) = symbol.section_index() else {
                return Ok(Err(
                    "current Mach-O archive member definition has no section".to_owned(),
                ));
            };
            let section_record_index = patch_section_record_index(&file, section_index)?;
            let Some(patch_section) = matched_sections.iter().find(|section| {
                section.current.input == matched.current.input
                    && section.current.section_index == section_record_index
            }) else {
                return Ok(Err(
                    "current Mach-O archive member definition is outside a matched section"
                        .to_owned(),
                ));
            };
            let input_section = file.section_by_index(section_index)?;
            let section_offset = symbol
                .address()
                .checked_sub(input_section.address())
                .context("Current Mach-O archive member definition precedes its section")?;
            let output_offset = patch_section
                .current
                .output_offset
                .checked_add(section_offset)
                .context("Current Mach-O archive member definition offset overflow")?;
            let Some(direct_value) =
                macho_output_address_for_file_offset(output_file, output_offset)
            else {
                return Ok(Err(
                    "current Mach-O archive member definition has no output address".to_owned(),
                ));
            };
            if matched_resolution.is_some() {
                return Ok(Err(
                    "current Mach-O archive member definition is ambiguous".to_owned()
                ));
            }
            matched_resolution = Some(MachOSymbolResolutionRecord {
                name: hex::encode(name).into(),
                direct_value: Some(direct_value),
                got_address: None,
                stub_address: None,
                thunk_addresses: Vec::new(),
                target: Some(RelocationTargetRecord {
                    input_file: input_file_path.into(),
                    input: current_input_ref.clone().into(),
                    section_index: relocation_target_record_index(section_index)?,
                    section_offset,
                }),
            });
        }
    }
    Ok(Ok(matched_resolution))
}

fn changed_macho_archive_text_definitions(
    previous_bytes: &[u8],
    input_file_path: &str,
    matched_sections: &[MatchedPatchSection],
    current_resolver: &PatchInputResolver<'_>,
    normalize_rust_archive_patch_inputs: bool,
    output_file: &object::File<'_>,
    resolutions: &[MachOSymbolResolutionRecord],
) -> Result<
    std::result::Result<
        Vec<(
            AddedMachOArchiveTextMember,
            MachOArchiveMemberIdentity,
            Vec<MachOSymbolResolutionRecord>,
        )>,
        String,
    >,
> {
    let previous_resolver =
        PatchInputResolver::new(previous_bytes, normalize_rust_archive_patch_inputs)?;
    let mut visited_inputs = HashSet::new();
    let mut changed = Vec::new();
    for matched in matched_sections {
        if matched.current.section_name.as_deref() != Some("__TEXT,__text")
            || !visited_inputs.insert(matched.current.input.as_str())
        {
            continue;
        }
        let Some(previous_input) = previous_resolver.resolve(
            input_file_path,
            matched.previous.input.as_str(),
            PatchInputLookup::MatchArchiveMember,
        )?
        else {
            return Ok(Err(
                "could not resolve previous Mach-O definition input".to_owned()
            ));
        };
        let Some(current_input) = current_resolver.resolve(
            input_file_path,
            matched.current.input.as_str(),
            PatchInputLookup::MatchArchiveMember,
        )?
        else {
            return Ok(Err(
                "could not resolve current Mach-O definition input".to_owned()
            ));
        };
        let (Some(previous_identifier), Some(current_identifier)) = (
            previous_input.archive_identifier,
            current_input.archive_identifier,
        ) else {
            continue;
        };
        let normalized_identifier = archive_member_patch_identifier(current_identifier);
        if archive_member_patch_identifier(previous_identifier) != normalized_identifier {
            return Ok(Err(
                "changed Mach-O definition moved between archive members".to_owned(),
            ));
        }

        let previous_file = object::File::parse(previous_input.bytes)
            .context("Failed to parse previous Mach-O definition input")?;
        let current_file = object::File::parse(current_input.bytes)
            .context("Failed to parse current Mach-O definition input")?;
        if !is_supported_incremental_macho_object(&previous_file)
            || !is_supported_incremental_macho_object(&current_file)
        {
            continue;
        }
        let current_text_index =
            patch_section_object_index(&current_file, matched.current.section_index)?;
        let current_text = current_file
            .section_by_index(current_text_index)
            .context("Missing changed Mach-O definition text section")?;
        let previous_names = previous_file
            .symbols()
            .filter(|symbol| symbol.is_global() && !symbol.is_undefined() && !symbol.is_weak())
            .map(|symbol| symbol.name_bytes().map(Vec::from))
            .collect::<Result<HashSet<_>, _>>()?;
        let mut definitions = Vec::new();
        for symbol in current_file.symbols().filter(|symbol| {
            symbol.is_global()
                && !symbol.is_undefined()
                && !symbol.is_weak()
                && symbol.section_index() == Some(current_text_index)
        }) {
            let name = symbol.name_bytes()?;
            if name.is_empty() || previous_names.contains(name) {
                continue;
            }
            let object::SymbolFlags::MachO { n_desc } = symbol.flags() else {
                return Ok(Err(
                    "changed Mach-O definition has non-Mach-O flags".to_owned()
                ));
            };
            let offset = symbol
                .address()
                .checked_sub(current_text.address())
                .context("Changed Mach-O definition precedes __text")?;
            if offset >= current_text.size() {
                return Ok(Err("changed Mach-O definition is outside __text".to_owned()));
            }
            definitions.push(AddedMachOArchiveDefinition {
                name: name.to_vec(),
                offset,
                desc: n_desc,
                private_external: symbol.scope() == object::SymbolScope::Linkage,
            });
        }
        definitions.sort_by(|left, right| left.name.cmp(&right.name));
        if definitions.is_empty() {
            continue;
        }
        if definitions
            .windows(2)
            .any(|pair| pair[0].name == pair[1].name)
        {
            return Ok(Err("changed Mach-O definition is ambiguous".to_owned()));
        }

        let mut definition_resolutions = Vec::with_capacity(definitions.len());
        for definition in &definitions {
            let encoded_name = hex::encode(&definition.name);
            if macho_symbol_resolution_index_for_name(resolutions, &encoded_name)?.is_some() {
                return Ok(Err(
                    "changed Mach-O definition already has a resolution".to_owned()
                ));
            }
            let resolution = match matched_macho_definition_resolution(
                input_file_path,
                &definition.name,
                matched_sections,
                current_resolver,
                output_file,
            )? {
                Ok(Some(resolution)) => resolution,
                Ok(None) => {
                    return Ok(Err(
                        "changed Mach-O definition has no matched output section".to_owned(),
                    ));
                }
                Err(reason) => return Ok(Err(reason)),
            };
            definition_resolutions.push(resolution);
        }
        let current_input_ref = resolved_patch_input_ref(
            input_file_path,
            matched.current.input.as_str(),
            current_input,
        )?;
        changed.push((
            AddedMachOArchiveTextMember {
                input: current_input_ref,
                sections: Vec::new(),
                unwind: None,
                text_section_index: matched.current.section_index,
                text_object_section_index: relocation_target_record_index(current_text_index)?,
                definitions,
                referenced_names: Vec::new(),
            },
            MachOArchiveMemberIdentity {
                normalized_identifier,
                object_hash: hash_bytes(current_input.bytes),
            },
            definition_resolutions,
        ));
    }
    Ok(Ok(changed))
}

fn macho_definition_resolutions_match(
    previous: &[MachOSymbolResolutionRecord],
    current: &[MachOSymbolResolutionRecord],
) -> bool {
    previous.len() == current.len()
        && previous.iter().zip(current).all(|(previous, current)| {
            previous.name == current.name
                && previous.direct_value == current.direct_value
                && previous.got_address.is_none()
                && current.got_address.is_none()
                && previous.stub_address.is_none()
                && current.stub_address.is_none()
                && previous.thunk_addresses.is_empty()
                && current.thunk_addresses.is_empty()
                && previous
                    .target
                    .as_ref()
                    .zip(current.target.as_ref())
                    .is_some_and(|(previous, current)| {
                        previous.input_file == current.input_file
                            && previous.section_index == current.section_index
                            && previous.section_offset == current.section_offset
                    })
        })
}

fn section_patches_from_stored(patches: &[StoredOutputPatch]) -> Vec<SectionPatch> {
    patches
        .iter()
        .map(|patch| SectionPatch {
            output_offset: patch.output_offset,
            size: patch.data.len() as u64,
            data: patch.data.clone(),
            deferred_relocation: None,
            preserve_ranges: Vec::new(),
            adjustments: Vec::new(),
        })
        .collect()
}

#[allow(clippy::too_many_arguments)]
fn changed_macho_definition_activation(
    previous_bytes: &[u8],
    input_file_path: &str,
    matched_sections: &[MatchedPatchSection],
    current_resolver: &PatchInputResolver<'_>,
    normalize_rust_archive_patch_inputs: bool,
    previous_output: &[u8],
    resolutions: &[MachOSymbolResolutionRecord],
    states: &[MachOArchiveActivationState],
    retiring_names: &[SharedText],
    reserved_ranges: &[ReservedRangeRecord],
) -> Result<std::result::Result<Option<ChangedMachODefinitionActivation>, String>> {
    let output_file = object::File::parse(previous_output)
        .context("Failed to parse previous output for changed Mach-O definitions")?;
    let changed = match changed_macho_archive_text_definitions(
        previous_bytes,
        input_file_path,
        matched_sections,
        current_resolver,
        normalize_rust_archive_patch_inputs,
        &output_file,
        resolutions,
    )? {
        Ok(changed) => changed,
        Err(reason) => return Ok(Err(reason)),
    };
    let retiring_names = retiring_names.iter().cloned().collect::<HashSet<_>>();
    let mut state_updates = Vec::new();
    let mut symbol_resolutions = Vec::new();
    let mut output_patches = Vec::new();
    let mut added_names = Vec::new();
    let mut retired_names = Vec::new();
    let mut recycled_names = Vec::new();
    let mut remaining_reserved_ranges = reserved_ranges.to_vec();

    for (index, state) in states.iter().enumerate() {
        if !state.kind.is_changed_definitions() || !state.active {
            continue;
        }
        let names = state
            .symbol_resolutions
            .iter()
            .map(|resolution| resolution.name.clone())
            .collect::<Vec<_>>();
        if !names.iter().any(|name| retiring_names.contains(name)) {
            continue;
        }
        if names.iter().any(|name| !retiring_names.contains(name))
            || !macho_archive_transaction_patches_match(state)
        {
            return Ok(Err(
                "changed Mach-O definitions split an activation transaction".to_owned(),
            ));
        }
        let [member] = state.members.as_slice() else {
            return Ok(Err(
                "changed Mach-O definition ownership is not unique".to_owned()
            ));
        };
        let previous_member =
            match patch_archive_member_bytes(previous_bytes, &member.normalized_identifier)? {
                ArchiveMemberMatch::Unique(member) => member,
                ArchiveMemberMatch::Unavailable | ArchiveMemberMatch::Ambiguous => {
                    return Ok(Err(
                        "could not validate changed Mach-O definition ownership".to_owned(),
                    ));
                }
            };
        if hash_bytes(previous_member.bytes) != member.object_hash {
            return Ok(Err(
                "changed Mach-O definition owner changed after activation".to_owned(),
            ));
        }
        let mut dormant = state.clone();
        dormant.active = false;
        output_patches.extend(section_patches_from_stored(&state.rollback_patches));
        retired_names.extend(names.iter().cloned());
        recycled_names.extend(names);
        state_updates.push(MachOArchiveActivationStateUpdate::Replace(index, dormant));
    }

    for (member, identity, current_resolutions) in changed {
        let names = current_resolutions
            .iter()
            .map(|resolution| resolution.name.clone())
            .collect::<Vec<_>>();
        added_names.extend(names.iter().cloned());
        let mut dormant_index = None;
        for (index, state) in states.iter().enumerate() {
            if !state.kind.is_changed_definitions()
                || state.active
                || state.members.as_slice() != std::slice::from_ref(&identity)
            {
                continue;
            }
            let state_names = state
                .symbol_resolutions
                .iter()
                .map(|resolution| resolution.name.clone())
                .collect::<Vec<_>>();
            if state_names != names {
                continue;
            }
            if dormant_index.replace(index).is_some() {
                return Ok(Err(
                    "changed Mach-O definition has ambiguous dormant ownership".to_owned(),
                ));
            }
        }
        if let Some(index) = dormant_index {
            let state = &states[index];
            if !macho_archive_transaction_patches_match(state)
                || !macho_definition_resolutions_match(
                    &state.symbol_resolutions,
                    &current_resolutions,
                )
            {
                return Ok(Err(
                    "reactivated Mach-O definition changed while dormant".to_owned()
                ));
            }
            let mut active = state.clone();
            active.active = true;
            active.symbol_resolutions = current_resolutions.clone();
            output_patches.extend(section_patches_from_stored(&state.forward_patches));
            symbol_resolutions.extend(current_resolutions);
            state_updates.push(MachOArchiveActivationStateUpdate::Replace(index, active));
            continue;
        }

        let members = vec![member];
        let selected_definitions = (0..members[0].definitions.len())
            .map(|definition_index| (0, definition_index))
            .collect::<Vec<_>>();
        let patches = match added_macho_symbol_table_patches(
            previous_output,
            &output_file,
            &members,
            &selected_definitions,
            &current_resolutions,
            &mut remaining_reserved_ranges,
        )? {
            Ok(patches) => patches,
            Err(reason) => return Ok(Err(reason)),
        };
        let forward_patches = match patches
            .iter()
            .map(|patch| stored_output_patch(patch, previous_output))
            .collect::<std::result::Result<Vec<_>, _>>()
        {
            Ok(patches) => patches,
            Err(reason) => return Ok(Err(reason)),
        };
        let rollback_patches = match forward_patches
            .iter()
            .map(|patch| {
                let start = usize::try_from(patch.output_offset)
                    .map_err(|_| "Mach-O definition rollback offset is too large".to_owned())?;
                let end = start
                    .checked_add(patch.data.len())
                    .ok_or_else(|| "Mach-O definition rollback range overflowed".to_owned())?;
                let data = previous_output.get(start..end).ok_or_else(|| {
                    "Mach-O definition rollback patch is outside output".to_owned()
                })?;
                Ok(StoredOutputPatch {
                    output_offset: patch.output_offset,
                    data: data.to_vec(),
                })
            })
            .collect::<std::result::Result<Vec<_>, String>>()
        {
            Ok(patches) => patches,
            Err(reason) => return Ok(Err(reason)),
        };
        output_patches.extend(patches);
        symbol_resolutions.extend(current_resolutions.iter().cloned());
        state_updates.push(MachOArchiveActivationStateUpdate::Add(
            MachOArchiveActivationState {
                kind: MachOArchiveActivationKind::ChangedDefinitions,
                members: vec![identity],
                active: true,
                sections: Vec::new(),
                relocations: Vec::new(),
                symbol_resolutions: current_resolutions,
                rollback_symbol_resolutions: Vec::new(),
                forward_patches,
                rollback_patches,
            },
        ));
    }

    if state_updates.is_empty() {
        return Ok(Ok(None));
    }
    added_names.sort_unstable();
    added_names.dedup();
    retired_names.sort_unstable();
    retired_names.dedup();
    recycled_names.sort_unstable();
    recycled_names.dedup();
    Ok(Ok(Some(ChangedMachODefinitionActivation {
        state_updates,
        symbol_resolutions,
        output_patches,
        added_names,
        retired_names,
        recycled_names,
        remaining_reserved_ranges,
    })))
}

fn macho_symbol_table_offset_for_recycling(bytes: &[u8]) -> std::result::Result<u64, String> {
    use object::read::macho::MachHeader as _;

    let header = object::macho::MachHeader64::<object::Endianness>::parse(bytes, 0)
        .map_err(|_| "failed to parse Mach-O output for symbol slot recycling".to_owned())?;
    let endian = header
        .endian()
        .map_err(|_| "unsupported Mach-O output endianness".to_owned())?;
    if endian != object::Endianness::Little {
        return Err("unsupported Mach-O output endianness".to_owned());
    }
    let mut commands = header
        .load_commands(endian, bytes, 0)
        .map_err(|_| "failed to parse Mach-O output load commands".to_owned())?;
    let mut symbol_table_offset = None;
    while let Some(command) = commands
        .next()
        .map_err(|_| "failed to parse Mach-O output load command".to_owned())?
    {
        if let Some(symtab) = command
            .symtab()
            .map_err(|_| "failed to parse Mach-O symbol table command".to_owned())?
        {
            if symbol_table_offset
                .replace(u64::from(symtab.symoff.get(endian)))
                .is_some()
            {
                return Err("Mach-O output has multiple symbol tables".to_owned());
            }
        }
        if command.cmd() == object::macho::LC_DYSYMTAB {
            return Err("Mach-O output has an indirect symbol table".to_owned());
        }
        if command.cmd() == object::macho::LC_DYLD_EXPORTS_TRIE {
            return Err("Mach-O output has an exports trie".to_owned());
        }
        if let Some(dyld_info) = command
            .dyld_info()
            .map_err(|_| "failed to parse Mach-O dyld info".to_owned())?
            && dyld_info.export_size.get(endian) != 0
        {
            return Err("Mach-O output has exported symbols".to_owned());
        }
    }
    symbol_table_offset.ok_or_else(|| "Mach-O output has no symbol table".to_owned())
}

fn unique_macho_output_symbol_index(
    output_file: &object::File<'_>,
    name: &[u8],
    value: u64,
) -> std::result::Result<usize, String> {
    let mut matching_symbol = None;
    for symbol in output_file.symbols() {
        if !symbol.name_bytes().is_ok_and(|candidate| candidate == name) {
            continue;
        }
        if matching_symbol
            .replace((symbol.index().0, symbol.address()))
            .is_some()
        {
            return Err("ambiguous Mach-O output symbol for slot recycling".to_owned());
        }
    }
    match matching_symbol {
        Some((index, current_value)) if current_value == value => Ok(index),
        Some(_) => Err("Mach-O output symbol value changed before slot recycling".to_owned()),
        None => Err("missing Mach-O output symbol for slot recycling".to_owned()),
    }
}

fn macho_symbol_entry_range(
    previous_output: &[u8],
    symbol_table_offset: u64,
    symbol_index: usize,
) -> std::result::Result<std::ops::Range<usize>, String> {
    let start = usize::try_from(symbol_table_offset)
        .map_err(|_| "Mach-O symbol table offset is too large".to_owned())?
        .checked_add(
            symbol_index
                .checked_mul(std::mem::size_of::<
                    object::macho::Nlist64<object::Endianness>,
                >())
                .ok_or_else(|| "Mach-O symbol entry offset overflowed".to_owned())?,
        )
        .ok_or_else(|| "Mach-O symbol entry offset overflowed".to_owned())?;
    let end = start
        .checked_add(std::mem::size_of::<
            object::macho::Nlist64<object::Endianness>,
        >())
        .ok_or_else(|| "Mach-O symbol entry range overflowed".to_owned())?;
    previous_output
        .get(start..end)
        .ok_or_else(|| "Mach-O symbol entry is outside output".to_owned())?;
    Ok(start..end)
}

fn added_macho_symbol_entry(
    definition: &AddedMachOArchiveDefinition,
    text_section_index: u8,
    string_index: u32,
    value: u64,
) -> Vec<u8> {
    let mut entry = Vec::with_capacity(std::mem::size_of::<
        object::macho::Nlist64<object::Endianness>,
    >());
    entry.extend_from_slice(&string_index.to_le_bytes());
    let mut symbol_type = object::macho::N_SECT | object::macho::N_EXT;
    if definition.private_external {
        symbol_type |= object::macho::N_PEXT;
    }
    entry.push(symbol_type);
    entry.push(text_section_index);
    entry.extend_from_slice(&definition.desc.to_le_bytes());
    entry.extend_from_slice(&value.to_le_bytes());
    entry
}

fn recycled_macho_symbol_table_patches(
    previous_output: &[u8],
    output_file: &object::File<'_>,
    members: &[AddedMachOArchiveTextMember],
    selected_definitions: &[(usize, usize)],
    resolutions: &[MachOSymbolResolutionRecord],
    retiring_names: &[SharedText],
    previous_resolutions: &[MachOSymbolResolutionRecord],
    remaining_reserved_ranges: &mut Vec<ReservedRangeRecord>,
) -> Result<std::result::Result<(Vec<SectionPatch>, Vec<SharedText>), String>> {
    if retiring_names.is_empty() {
        return Ok(Ok((Vec::new(), Vec::new())));
    }
    let symbol_table_offset = match macho_symbol_table_offset_for_recycling(previous_output) {
        Ok(offset) => offset,
        Err(reason) => return Ok(Err(reason)),
    };
    let Some(text_section) = output_file.sections().find(|section| {
        section.segment_name_bytes().ok().flatten() == Some(b"__TEXT".as_slice())
            && section.name_bytes().ok() == Some(b"__text".as_slice())
    }) else {
        return Ok(Err(
            "previous Mach-O output has no __TEXT,__text section".to_owned()
        ));
    };
    let text_section_index = u8::try_from(text_section.index().0)
        .context("Mach-O text output section index exceeds u8")?;
    let Some(string_table_offset) = macho_string_table_offset(previous_output) else {
        return Ok(Err(
            "previous Mach-O output has no usable symbol string table".to_owned(),
        ));
    };
    let string_output_section_id = u32::try_from(crate::output_section_id::STRTAB.as_usize())
        .context("Mach-O string table output section ID exceeds u32")?;
    let mut patches = Vec::with_capacity(retiring_names.len() * 2);

    for ((&(member_index, definition_index), resolution), retiring_name) in selected_definitions
        .iter()
        .zip(resolutions)
        .zip(retiring_names)
    {
        let member = &members[member_index];
        let definition = &member.definitions[definition_index];
        let Some(previous_resolution_index) =
            macho_symbol_resolution_index_for_name(previous_resolutions, retiring_name.as_str())?
        else {
            return Ok(Err(format!(
                "missing deferred Mach-O symbol resolution catalog entry for `{}` during archive activation",
                display_hex_text(retiring_name.as_str())
            )));
        };
        let previous_resolution = &previous_resolutions[previous_resolution_index];
        let Some(previous_value) = previous_resolution.direct_value else {
            return Ok(Err(
                "deferred Mach-O symbol resolution has no direct value".to_owned()
            ));
        };
        if previous_resolution.got_address.is_some()
            || previous_resolution.stub_address.is_some()
            || !previous_resolution.thunk_addresses.is_empty()
            || previous_resolution.target.is_none()
        {
            return Ok(Err(
                "deferred Mach-O symbol resolution uses an indirect target".to_owned(),
            ));
        }
        let decoded_retiring_name = hex::decode(retiring_name.as_str())
            .context("Malformed deferred Mach-O symbol resolution name")?;
        let symbol_index = match unique_macho_output_symbol_index(
            output_file,
            &decoded_retiring_name,
            previous_value,
        ) {
            Ok(index) => index,
            Err(reason) => return Ok(Err(reason)),
        };
        let symbol_range =
            match macho_symbol_entry_range(previous_output, symbol_table_offset, symbol_index) {
                Ok(range) => range,
                Err(reason) => return Ok(Err(reason)),
            };
        let old_entry = &previous_output[symbol_range.clone()];
        let old_type = old_entry[4];
        if old_type & object::macho::N_STAB != 0
            || old_type & object::macho::N_TYPE != object::macho::N_SECT
            || old_type & object::macho::N_EXT == 0
            || old_entry[5] != text_section_index
        {
            return Ok(Err(
                "removed Mach-O symbol is not a recyclable external text definition".to_owned(),
            ));
        }

        let same_name = definition.name == decoded_retiring_name;
        let (string_index, string_allocation) = if same_name {
            (
                u32::from_le_bytes(old_entry[..4].try_into().expect("checked symbol entry")),
                None,
            )
        } else {
            if output_file.symbols().any(|symbol| {
                symbol
                    .name_bytes()
                    .is_ok_and(|name| name == definition.name.as_slice())
            }) {
                return Ok(Err(
                    "added Mach-O archive member definition already exists in output".to_owned(),
                ));
            }
            let string_size = u64::try_from(definition.name.len() + 1)
                .context("Added Mach-O symbol name is too large")?;
            let Some(allocation) = allocate_reserved_range(
                remaining_reserved_ranges,
                string_output_section_id,
                0,
                string_size,
            )?
            else {
                return Ok(Err(
                    "insufficient incremental reserve for added Mach-O symbol name".to_owned(),
                ));
            };
            let Some(index) = allocation
                .output_offset
                .checked_sub(string_table_offset)
                .and_then(|offset| u32::try_from(offset).ok())
            else {
                return Ok(Err(
                    "added Mach-O symbol name is outside the string table".to_owned()
                ));
            };
            (index, Some(allocation))
        };
        let Some(value) = resolution.direct_value else {
            return Ok(Err(
                "added Mach-O archive member definition has no direct value".to_owned(),
            ));
        };
        patches.push(SectionPatch {
            output_offset: symbol_range.start as u64,
            size: symbol_range.len() as u64,
            data: added_macho_symbol_entry(definition, text_section_index, string_index, value),
            deferred_relocation: None,
            preserve_ranges: Vec::new(),
            adjustments: Vec::new(),
        });
        if let Some(string_allocation) = string_allocation {
            let mut name = definition.name.clone();
            name.push(0);
            patches.push(SectionPatch {
                output_offset: string_allocation.output_offset,
                size: string_allocation.size,
                data: name,
                deferred_relocation: None,
                preserve_ranges: Vec::new(),
                adjustments: Vec::new(),
            });
        }
    }
    Ok(Ok((patches, retiring_names.to_vec())))
}

fn added_macho_symbol_table_patches(
    previous_output: &[u8],
    output_file: &object::File<'_>,
    members: &[AddedMachOArchiveTextMember],
    selected_definitions: &[(usize, usize)],
    resolutions: &[MachOSymbolResolutionRecord],
    remaining_reserved_ranges: &mut Vec<ReservedRangeRecord>,
) -> Result<std::result::Result<Vec<SectionPatch>, String>> {
    let Some(text_section) = output_file.sections().find(|section| {
        section.segment_name_bytes().ok().flatten() == Some(b"__TEXT".as_slice())
            && section.name_bytes().ok() == Some(b"__text".as_slice())
    }) else {
        return Ok(Err(
            "previous Mach-O output has no __TEXT,__text section".to_owned()
        ));
    };
    let text_section_index = u8::try_from(text_section.index().0)
        .context("Mach-O text output section index exceeds u8")?;
    let Some(string_table_offset) = macho_string_table_offset(previous_output) else {
        return Ok(Err(
            "previous Mach-O output has no usable symbol string table".to_owned(),
        ));
    };
    let symbol_output_section_id =
        u32::try_from(crate::output_section_id::SYMTAB_GLOBAL.as_usize())
            .context("Mach-O symbol table output section ID exceeds u32")?;
    let string_output_section_id = u32::try_from(crate::output_section_id::STRTAB.as_usize())
        .context("Mach-O string table output section ID exceeds u32")?;
    let symbol_entry_size = u64::try_from(std::mem::size_of::<
        object::macho::Nlist64<object::Endianness>,
    >())
    .context("Mach-O symbol table entry size exceeds u64")?;
    let mut patches = Vec::with_capacity(selected_definitions.len() * 2);

    for (&(member_index, definition_index), resolution) in
        selected_definitions.iter().zip(resolutions)
    {
        let member = &members[member_index];
        let definition = &member.definitions[definition_index];
        let Some(value) = resolution.direct_value else {
            return Ok(Err(
                "added Mach-O archive member definition has no direct value".to_owned(),
            ));
        };
        if output_file.symbols().any(|symbol| {
            symbol
                .name_bytes()
                .is_ok_and(|name| name == definition.name.as_slice())
        }) {
            return Ok(Err(
                "added Mach-O archive member definition already exists in output".to_owned(),
            ));
        }
        let Some(symbol_allocation) = allocate_reserved_range(
            remaining_reserved_ranges,
            symbol_output_section_id,
            crate::alignment::SYMTAB_ENTRY.exponent,
            symbol_entry_size,
        )?
        else {
            return Ok(Err(
                "insufficient incremental reserve for added Mach-O symbol table entry".to_owned(),
            ));
        };
        let string_size = u64::try_from(definition.name.len() + 1)
            .context("Added Mach-O symbol name is too large")?;
        let Some(string_allocation) = allocate_reserved_range(
            remaining_reserved_ranges,
            string_output_section_id,
            0,
            string_size,
        )?
        else {
            return Ok(Err(
                "insufficient incremental reserve for added Mach-O symbol name".to_owned(),
            ));
        };
        let string_index = string_allocation
            .output_offset
            .checked_sub(string_table_offset)
            .and_then(|offset| u32::try_from(offset).ok());
        let Some(string_index) = string_index else {
            return Ok(Err(
                "added Mach-O symbol name is outside the string table".to_owned()
            ));
        };

        let entry = added_macho_symbol_entry(definition, text_section_index, string_index, value);
        debug_assert_eq!(entry.len() as u64, symbol_entry_size);
        patches.push(SectionPatch {
            output_offset: symbol_allocation.output_offset,
            size: symbol_allocation.size,
            data: entry,
            deferred_relocation: None,
            preserve_ranges: Vec::new(),
            adjustments: Vec::new(),
        });

        let mut name = definition.name.clone();
        name.push(0);
        patches.push(SectionPatch {
            output_offset: string_allocation.output_offset,
            size: string_allocation.size,
            data: name,
            deferred_relocation: None,
            preserve_ranges: Vec::new(),
            adjustments: Vec::new(),
        });
    }
    Ok(Ok(patches))
}

fn macho_string_table_offset(bytes: &[u8]) -> Option<u64> {
    use object::read::macho::MachHeader as _;

    let header = object::macho::MachHeader64::<object::Endianness>::parse(bytes, 0).ok()?;
    let endian = header.endian().ok()?;
    if endian != object::Endianness::Little {
        return None;
    }
    let mut commands = header.load_commands(endian, bytes, 0).ok()?;
    let mut string_table_offset = None;
    while let Some(command) = commands.next().ok()? {
        let Some(command) = command.symtab().ok()? else {
            continue;
        };
        if string_table_offset
            .replace(u64::from(command.stroff.get(endian)))
            .is_some()
        {
            return None;
        }
    }
    string_table_offset
}

const MACHO_CHAINED_PTR_FORMAT_64_OFFSET: u16 = 6;
const MACHO_CHAINED_PTR_START_NONE: u16 = 0xffff;
const MACHO_CHAINED_PTR_NEXT_SHIFT: u32 = 51;
const MACHO_CHAINED_PTR_NEXT_MASK: u64 = 0xfff << MACHO_CHAINED_PTR_NEXT_SHIFT;
const MACHO_DATA_SEGMENT_CHAIN_INDEX: usize = 2;

#[derive(Clone, Copy, Debug)]
struct MachOChainedFixupSlot {
    address: u64,
    output_offset: u64,
    value: u64,
}

struct MachOChainedFixupPlan {
    page_starts: Vec<u16>,
    existing_values: Vec<(u64, u64)>,
    new_values: Vec<(usize, u64)>,
}

#[derive(Clone, Copy, Debug)]
enum MachOChainedFixupPlanSlot {
    Existing { output_offset: u64, value: u64 },
    New { target: u64, replay_index: usize },
}

fn plan_macho_chained_fixup_slots(
    old_slots: &[MachOChainedFixupSlot],
    new_slots: &[(u64, u64, usize)],
    data_address: u64,
    data_size: u64,
) -> std::result::Result<MachOChainedFixupPlan, String> {
    let data_end = data_address
        .checked_add(data_size)
        .ok_or_else(|| "Mach-O __DATA address range overflowed".to_owned())?;
    let mut slots = old_slots
        .iter()
        .map(|slot| {
            (
                slot.address,
                MachOChainedFixupPlanSlot::Existing {
                    output_offset: slot.output_offset,
                    value: slot.value,
                },
            )
        })
        .collect::<Vec<_>>();
    for &(address, target, replay_index) in new_slots {
        if address < data_address || address.checked_add(8).is_none_or(|end| end > data_end) {
            return Err("added Mach-O chained rebase is outside __DATA".to_owned());
        }
        if !address.is_multiple_of(8) {
            return Err("added Mach-O chained rebase is not 8-byte aligned".to_owned());
        }
        slots.push((
            address,
            MachOChainedFixupPlanSlot::New {
                target,
                replay_index,
            },
        ));
    }
    slots.sort_by_key(|(address, _)| *address);
    if slots.windows(2).any(|pair| pair[0].0 == pair[1].0) {
        return Err("added Mach-O chained rebase overlaps an existing slot".to_owned());
    }

    let page_count = usize::try_from(data_size.div_ceil(crate::macho::MACHO_PAGE_SIZE).max(1))
        .map_err(|_| "Mach-O chained fixup page count is too large".to_owned())?;
    let mut page_starts = vec![MACHO_CHAINED_PTR_START_NONE; page_count];
    let mut existing_values = Vec::new();
    let mut new_values = Vec::new();
    for (slot_index, (address, slot)) in slots.iter().enumerate() {
        let offset_in_segment = address - data_address;
        let page_index = usize::try_from(offset_in_segment / crate::macho::MACHO_PAGE_SIZE)
            .map_err(|_| "Mach-O chained fixup page index is too large".to_owned())?;
        let offset_in_page = offset_in_segment % crate::macho::MACHO_PAGE_SIZE;
        if page_starts[page_index] == MACHO_CHAINED_PTR_START_NONE {
            page_starts[page_index] = u16::try_from(offset_in_page)
                .map_err(|_| "Mach-O chained fixup page start exceeds u16".to_owned())?;
        }
        let next_stride = if let Some((next, _)) = slots.get(slot_index + 1).filter(|(next, _)| {
            (*next - data_address) / crate::macho::MACHO_PAGE_SIZE == page_index as u64
        }) {
            let distance = next
                .checked_sub(*address)
                .ok_or_else(|| "Mach-O chained fixup slots are not ordered".to_owned())?;
            if !distance.is_multiple_of(4) {
                return Err("Mach-O chained fixup slots are not 4-byte aligned".to_owned());
            }
            distance / 4
        } else {
            0
        };
        if next_stride >= 0x1000 {
            return Err("Mach-O chained fixup next stride is invalid".to_owned());
        }
        match *slot {
            MachOChainedFixupPlanSlot::New {
                target,
                replay_index,
            } => {
                new_values.push((
                    replay_index,
                    encode_incremental_macho_chained_rebase(target, next_stride)?,
                ));
            }
            MachOChainedFixupPlanSlot::Existing {
                output_offset,
                value,
            } => {
                let updated = (value & !MACHO_CHAINED_PTR_NEXT_MASK)
                    | (next_stride << MACHO_CHAINED_PTR_NEXT_SHIFT);
                if updated != value {
                    existing_values.push((output_offset, updated));
                }
            }
        }
    }
    Ok(MachOChainedFixupPlan {
        page_starts,
        existing_values,
        new_values,
    })
}

fn macho_chained_fixup_table_range(bytes: &[u8]) -> Option<std::ops::Range<usize>> {
    use object::read::macho::MachHeader as _;

    let header = object::macho::MachHeader64::<object::Endianness>::parse(bytes, 0).ok()?;
    let endian = header.endian().ok()?;
    if endian != object::Endianness::Little {
        return None;
    }
    let mut commands = header.load_commands(endian, bytes, 0).ok()?;
    let mut range = None;
    while let Some(command) = commands.next().ok()? {
        if command.cmd() != object::macho::LC_DYLD_CHAINED_FIXUPS {
            continue;
        }
        let command = command
            .data::<object::macho::LinkeditDataCommand<object::Endianness>>()
            .ok()?;
        let start = usize::try_from(command.dataoff.get(endian)).ok()?;
        let size = usize::try_from(command.datasize.get(endian)).ok()?;
        let end = start.checked_add(size)?;
        bytes.get(start..end)?;
        if range.replace(start..end).is_some() {
            return None;
        }
    }
    range
}

fn macho_chained_fixup_data_segment(
    output_file: &object::File<'_>,
) -> Option<(u64, u64, u64, u64)> {
    let mut matches = output_file.segments().filter_map(|segment| {
        (segment.name_bytes().ok().flatten() == Some(b"__DATA".as_slice())).then(|| {
            let (file_offset, file_size) = segment.file_range();
            (segment.address(), segment.size(), file_offset, file_size)
        })
    });
    let segment = matches.next()?;
    matches.next().is_none().then_some(segment)
}

fn read_macho_chained_fixup_slots(
    previous_output: &[u8],
    table: &[u8],
    data_address: u64,
    data_size: u64,
    data_file_offset: u64,
    data_file_size: u64,
) -> std::result::Result<Vec<MachOChainedFixupSlot>, String> {
    let read_u16 = |offset: usize| {
        table
            .get(offset..offset + 2)
            .and_then(read_u16_le)
            .ok_or_else(|| "Mach-O chained fixup table is truncated".to_owned())
    };
    let read_u32 = |offset: usize| {
        table
            .get(offset..offset + 4)
            .and_then(read_u32_le)
            .ok_or_else(|| "Mach-O chained fixup table is truncated".to_owned())
    };
    if read_u32(0)? != 0 {
        return Err("unsupported Mach-O chained fixup version".to_owned());
    }
    let starts_offset = usize::try_from(read_u32(4)?)
        .map_err(|_| "Mach-O chained fixup starts offset is too large".to_owned())?;
    let segment_count = usize::try_from(read_u32(starts_offset)?)
        .map_err(|_| "Mach-O chained fixup segment count is too large".to_owned())?;
    if segment_count != crate::macho::DEFAULT_SEGMENT_COUNT {
        return Err("unsupported Mach-O chained fixup segment count".to_owned());
    }
    for segment_index in 0..segment_count {
        let segment_offset_location = starts_offset
            .checked_add(4 * (segment_index + 1))
            .ok_or_else(|| "Mach-O chained fixup segment offset overflowed".to_owned())?;
        let segment_offset = read_u32(segment_offset_location)?;
        if segment_index != MACHO_DATA_SEGMENT_CHAIN_INDEX && segment_offset != 0 {
            return Err("unsupported Mach-O chained fixups outside __DATA".to_owned());
        }
    }
    let segment_offset_location = starts_offset
        .checked_add(4 * (MACHO_DATA_SEGMENT_CHAIN_INDEX + 1))
        .ok_or_else(|| "Mach-O chained fixup segment offset overflowed".to_owned())?;
    let segment_offset = usize::try_from(read_u32(segment_offset_location)?)
        .map_err(|_| "Mach-O chained fixup segment offset is too large".to_owned())?;
    if segment_offset == 0 {
        return Ok(Vec::new());
    }
    let segment_start = starts_offset
        .checked_add(segment_offset)
        .ok_or_else(|| "Mach-O chained fixup segment range overflowed".to_owned())?;
    let segment_info_size = usize::try_from(read_u32(segment_start)?)
        .map_err(|_| "Mach-O chained fixup segment size is too large".to_owned())?;
    let segment_end = segment_start
        .checked_add(segment_info_size)
        .ok_or_else(|| "Mach-O chained fixup segment range overflowed".to_owned())?;
    if segment_end > table.len() {
        return Err("Mach-O chained fixup segment extends past its table".to_owned());
    }
    if read_u16(segment_start + 4)? != crate::macho::MACHO_PAGE_SIZE as u16
        || read_u16(segment_start + 6)? != MACHO_CHAINED_PTR_FORMAT_64_OFFSET
    {
        return Err("unsupported Mach-O chained fixup page or pointer format".to_owned());
    }
    let segment_runtime_offset = table
        .get(segment_start + 8..segment_start + 16)
        .and_then(read_u64_le)
        .ok_or_else(|| "Mach-O chained fixup segment is truncated".to_owned())?;
    if segment_runtime_offset
        != data_address
            .checked_sub(crate::macho::MACHO_START_MEM_ADDRESS)
            .ok_or_else(|| "Mach-O __DATA segment precedes the image base".to_owned())?
    {
        return Err("Mach-O chained fixup __DATA segment offset changed".to_owned());
    }
    let page_count = usize::from(read_u16(segment_start + 20)?);
    let expected_page_count =
        usize::try_from(data_size.div_ceil(crate::macho::MACHO_PAGE_SIZE).max(1))
            .map_err(|_| "Mach-O chained fixup page count is too large".to_owned())?;
    if page_count != expected_page_count {
        return Err("Mach-O chained fixup page count changed".to_owned());
    }
    let page_starts_offset = segment_start + 22;
    if page_starts_offset
        .checked_add(page_count * 2)
        .is_none_or(|end| end > segment_end)
    {
        return Err("Mach-O chained fixup page starts are truncated".to_owned());
    }

    let mut slots = Vec::new();
    let mut seen = HashSet::new();
    for page_index in 0..page_count {
        let page_start = read_u16(page_starts_offset + page_index * 2)?;
        if page_start == MACHO_CHAINED_PTR_START_NONE {
            continue;
        }
        if page_start & 0x8000 != 0
            || !page_start.is_multiple_of(4)
            || u64::from(page_start) >= crate::macho::MACHO_PAGE_SIZE
        {
            return Err("unsupported Mach-O chained fixup page start".to_owned());
        }
        let page_base = u64::try_from(page_index)
            .ok()
            .and_then(|index| index.checked_mul(crate::macho::MACHO_PAGE_SIZE))
            .ok_or_else(|| "Mach-O chained fixup page offset overflowed".to_owned())?;
        let mut offset_in_segment = page_base
            .checked_add(u64::from(page_start))
            .ok_or_else(|| "Mach-O chained fixup slot offset overflowed".to_owned())?;
        loop {
            if offset_in_segment >= data_size
                || offset_in_segment
                    .checked_add(8)
                    .is_none_or(|end| end > data_file_size)
                || offset_in_segment / crate::macho::MACHO_PAGE_SIZE
                    != u64::try_from(page_index).unwrap()
            {
                return Err("Mach-O chained fixup slot is outside __DATA".to_owned());
            }
            let output_offset = data_file_offset
                .checked_add(offset_in_segment)
                .ok_or_else(|| "Mach-O chained fixup file offset overflowed".to_owned())?;
            let start = usize::try_from(output_offset)
                .map_err(|_| "Mach-O chained fixup file offset is too large".to_owned())?;
            let value = previous_output
                .get(start..start + 8)
                .and_then(read_u64_le)
                .ok_or_else(|| "Mach-O chained fixup slot is outside the output".to_owned())?;
            let address = data_address
                .checked_add(offset_in_segment)
                .ok_or_else(|| "Mach-O chained fixup address overflowed".to_owned())?;
            if !seen.insert(address) {
                return Err("Mach-O chained fixup chain contains a cycle".to_owned());
            }
            slots.push(MachOChainedFixupSlot {
                address,
                output_offset,
                value,
            });
            let next = (value & MACHO_CHAINED_PTR_NEXT_MASK) >> MACHO_CHAINED_PTR_NEXT_SHIFT;
            if next == 0 {
                break;
            }
            offset_in_segment = offset_in_segment
                .checked_add(next * 4)
                .ok_or_else(|| "Mach-O chained fixup next offset overflowed".to_owned())?;
        }
    }
    slots.sort_by_key(|slot| slot.address);
    Ok(slots)
}

fn encode_incremental_macho_chained_rebase(
    target: u64,
    next_stride: u64,
) -> std::result::Result<u64, String> {
    let high8 = target >> 56;
    let address = target & ((1 << 56) - 1);
    let runtime_offset = address
        .checked_sub(crate::macho::MACHO_START_MEM_ADDRESS)
        .ok_or_else(|| format!("cannot encode Mach-O chained rebase target {target:#x}"))?;
    if runtime_offset >= (1 << 36) || next_stride >= 0x1000 {
        return Err("Mach-O chained rebase value exceeds its encoded range".to_owned());
    }
    Ok(runtime_offset | (high8 << 36) | (next_stride << MACHO_CHAINED_PTR_NEXT_SHIFT))
}

fn write_macho_chained_fixup_u16(
    table: &mut [u8],
    offset: usize,
    value: u16,
) -> std::result::Result<(), String> {
    let bytes = table
        .get_mut(offset..offset + 2)
        .ok_or_else(|| "Mach-O chained fixup table is too small".to_owned())?;
    bytes.copy_from_slice(&value.to_le_bytes());
    Ok(())
}

fn write_macho_chained_fixup_u32(
    table: &mut [u8],
    offset: usize,
    value: u32,
) -> std::result::Result<(), String> {
    let bytes = table
        .get_mut(offset..offset + 4)
        .ok_or_else(|| "Mach-O chained fixup table is too small".to_owned())?;
    bytes.copy_from_slice(&value.to_le_bytes());
    Ok(())
}

fn write_macho_chained_fixup_u64(
    table: &mut [u8],
    offset: usize,
    value: u64,
) -> std::result::Result<(), String> {
    let bytes = table
        .get_mut(offset..offset + 8)
        .ok_or_else(|| "Mach-O chained fixup table is too small".to_owned())?;
    bytes.copy_from_slice(&value.to_le_bytes());
    Ok(())
}

fn added_macho_chained_fixup_patches(
    previous_output: &[u8],
    output_file: &object::File<'_>,
    replays: &mut [MachOTextRelocationReplay],
) -> std::result::Result<(Vec<SectionPatch>, Vec<(usize, RelocationRecord)>), String> {
    let new_replay_indices = replays
        .iter()
        .enumerate()
        .filter_map(|(index, replay)| replay.chained_rebase_output_offset.map(|_| index))
        .collect::<Vec<_>>();
    if new_replay_indices.is_empty() {
        return Ok((Vec::new(), Vec::new()));
    }
    let table_range = macho_chained_fixup_table_range(previous_output)
        .ok_or_else(|| "previous Mach-O output has no usable chained fixup table".to_owned())?;
    let previous_table = previous_output
        .get(table_range.clone())
        .ok_or_else(|| "previous Mach-O chained fixup table is out of bounds".to_owned())?;
    let Some((data_address, data_size, data_file_offset, data_file_size)) =
        macho_chained_fixup_data_segment(output_file)
    else {
        return Err("previous Mach-O output has no unique __DATA segment".to_owned());
    };
    let old_slots = read_macho_chained_fixup_slots(
        previous_output,
        previous_table,
        data_address,
        data_size,
        data_file_offset,
        data_file_size,
    )?;
    let mut new_slots = Vec::with_capacity(new_replay_indices.len());
    for &replay_index in &new_replay_indices {
        let replay = &replays[replay_index];
        let output_offset = replay.chained_rebase_output_offset.unwrap();
        let offset_in_segment = output_offset
            .checked_sub(data_file_offset)
            .ok_or_else(|| "added Mach-O chained rebase precedes __DATA".to_owned())?;
        if offset_in_segment
            .checked_add(8)
            .is_none_or(|end| end > data_file_size || end > data_size)
        {
            return Err("added Mach-O chained rebase is outside __DATA".to_owned());
        }
        let address = data_address
            .checked_add(offset_in_segment)
            .ok_or_else(|| "added Mach-O chained rebase address overflowed".to_owned())?;
        let target = macho_aarch64_relocated_value(
            object::macho::ARM64_RELOC_UNSIGNED,
            replay.current_target_value,
            replay.addend,
            0,
        )
        .ok_or_else(|| "could not resolve added Mach-O chained rebase target".to_owned())?;
        new_slots.push((address, target, replay_index));
    }
    let plan = plan_macho_chained_fixup_slots(&old_slots, &new_slots, data_address, data_size)?;
    let page_count = plan.page_starts.len();
    let mut patches = Vec::new();
    for (output_offset, value) in plan.existing_values {
        patches.push(SectionPatch {
            output_offset,
            size: 8,
            data: value.to_le_bytes().to_vec(),
            deferred_relocation: None,
            preserve_ranges: Vec::new(),
            adjustments: Vec::new(),
        });
    }
    for (replay_index, value) in plan.new_values {
        replays[replay_index].chained_rebase_value = Some(value);
    }

    let read_table_u32 = |offset: usize| {
        previous_table
            .get(offset..offset + 4)
            .and_then(read_u32_le)
            .ok_or_else(|| "Mach-O chained fixup table is truncated".to_owned())
    };
    if read_table_u32(0)? != 0
        || read_table_u32(4)? != 32
        || read_table_u32(20)? != 1
        || read_table_u32(24)? != 0
    {
        return Err("unsupported Mach-O chained fixup table encoding".to_owned());
    }
    let old_imports_offset = usize::try_from(read_table_u32(8)?)
        .map_err(|_| "Mach-O chained fixup imports offset is too large".to_owned())?;
    let old_symbols_offset = usize::try_from(read_table_u32(12)?)
        .map_err(|_| "Mach-O chained fixup symbols offset is too large".to_owned())?;
    let imports_count = usize::try_from(read_table_u32(16)?)
        .map_err(|_| "Mach-O chained fixup import count is too large".to_owned())?;
    let imports_size = imports_count
        .checked_mul(4)
        .ok_or_else(|| "Mach-O chained fixup imports size overflowed".to_owned())?;
    let old_imports = previous_table
        .get(old_imports_offset..old_imports_offset + imports_size)
        .ok_or_else(|| "Mach-O chained fixup imports are out of bounds".to_owned())?;
    if old_symbols_offset < old_imports_offset + imports_size
        || old_symbols_offset >= previous_table.len()
    {
        return Err("Mach-O chained fixup symbol strings are out of bounds".to_owned());
    }
    let old_symbols = &previous_table[old_symbols_offset..];
    let mut symbol_strings_size = 1usize;
    for import in old_imports.chunks_exact(4) {
        let import = u32::from_le_bytes(import.try_into().unwrap());
        let name_offset = usize::try_from((import >> 9) & 0x7f_ffff)
            .map_err(|_| "Mach-O chained import name offset is too large".to_owned())?;
        let name = old_symbols
            .get(name_offset..)
            .and_then(|bytes| bytes.iter().position(|byte| *byte == 0).map(|end| end + 1))
            .ok_or_else(|| "Mach-O chained import name is unterminated".to_owned())?;
        symbol_strings_size = symbol_strings_size.max(name_offset + name);
    }
    let symbol_strings = old_symbols
        .get(..symbol_strings_size)
        .ok_or_else(|| "Mach-O chained import strings are out of bounds".to_owned())?;

    let starts_offset = 32usize;
    let starts_size = 4 * (crate::macho::DEFAULT_SEGMENT_COUNT + 1);
    let segment_offset = starts_size.next_multiple_of(8);
    let segment_size = (22 + page_count * 2).next_multiple_of(8);
    let segment_start = starts_offset + segment_offset;
    let imports_offset = segment_start + segment_size;
    let symbols_offset = imports_offset + imports_size;
    let required_size = symbols_offset
        .checked_add(symbol_strings.len())
        .ok_or_else(|| "Mach-O chained fixup table size overflowed".to_owned())?;
    if required_size > previous_table.len() {
        return Err("Mach-O chained fixup table allocation is too small".to_owned());
    }
    let mut table = vec![0; previous_table.len()];
    write_macho_chained_fixup_u32(&mut table, 0, 0)?;
    write_macho_chained_fixup_u32(&mut table, 4, starts_offset as u32)?;
    write_macho_chained_fixup_u32(&mut table, 8, imports_offset as u32)?;
    write_macho_chained_fixup_u32(&mut table, 12, symbols_offset as u32)?;
    write_macho_chained_fixup_u32(&mut table, 16, imports_count as u32)?;
    write_macho_chained_fixup_u32(&mut table, 20, 1)?;
    write_macho_chained_fixup_u32(&mut table, 24, 0)?;
    write_macho_chained_fixup_u32(
        &mut table,
        starts_offset,
        crate::macho::DEFAULT_SEGMENT_COUNT as u32,
    )?;
    write_macho_chained_fixup_u32(
        &mut table,
        starts_offset + 4 * (MACHO_DATA_SEGMENT_CHAIN_INDEX + 1),
        segment_offset as u32,
    )?;
    write_macho_chained_fixup_u32(&mut table, segment_start, segment_size as u32)?;
    write_macho_chained_fixup_u16(
        &mut table,
        segment_start + 4,
        crate::macho::MACHO_PAGE_SIZE as u16,
    )?;
    write_macho_chained_fixup_u16(
        &mut table,
        segment_start + 6,
        MACHO_CHAINED_PTR_FORMAT_64_OFFSET,
    )?;
    write_macho_chained_fixup_u64(
        &mut table,
        segment_start + 8,
        data_address
            .checked_sub(crate::macho::MACHO_START_MEM_ADDRESS)
            .ok_or_else(|| "Mach-O __DATA segment precedes the image base".to_owned())?,
    )?;
    write_macho_chained_fixup_u32(&mut table, segment_start + 16, 0)?;
    write_macho_chained_fixup_u16(
        &mut table,
        segment_start + 20,
        u16::try_from(page_count)
            .map_err(|_| "Mach-O chained fixup page count exceeds u16".to_owned())?,
    )?;
    for (page_index, page_start) in plan.page_starts.into_iter().enumerate() {
        write_macho_chained_fixup_u16(&mut table, segment_start + 22 + page_index * 2, page_start)?;
    }
    table[imports_offset..imports_offset + imports_size].copy_from_slice(old_imports);
    table[symbols_offset..symbols_offset + symbol_strings.len()].copy_from_slice(symbol_strings);
    patches.push(SectionPatch {
        output_offset: table_range.start as u64,
        size: table.len() as u64,
        data: table,
        deferred_relocation: None,
        preserve_ranges: Vec::new(),
        adjustments: Vec::new(),
    });

    let provisional_relocations = new_replay_indices
        .into_iter()
        .map(|replay_index| {
            let replay = &replays[replay_index];
            let written_value = replay
                .chained_rebase_value
                .expect("new chained rebase must be encoded");
            (
                replay_index,
                RelocationRecord {
                    target_symbol_id: replay.target_symbol_id,
                    written_value: Some(written_value),
                    target_value: replay.current_target_value,
                    applied_target_value: Some(replay.current_target_value),
                    target_name: replay.target_name.clone(),
                    target: replay.target.clone(),
                    input_file: replay.input_file.clone(),
                    input: replay.input.clone().into(),
                    section_index: replay.section_index,
                    relocation_offset: replay.current_range.start as u64,
                    output_offset: replay.chained_rebase_output_offset.unwrap(),
                    size: 8,
                    kind: replay.kind,
                    addend: replay.addend,
                },
            )
        })
        .collect();
    Ok((patches, provisional_relocations))
}

fn added_macho_archive_output_section_id(
    segment_name: &[u8],
    section_name: &[u8],
    flags: u32,
) -> Option<crate::output_section_id::OutputSectionId> {
    if flags & object::macho::SECTION_TYPE != object::macho::S_REGULAR {
        return None;
    }
    match (segment_name, section_name) {
        (b"__TEXT", b"__text") => Some(crate::output_section_id::TEXT),
        (b"__TEXT" | b"__DATA", b"__const") => Some(crate::output_section_id::RODATA),
        (b"__TEXT", b"__gcc_except_tab") => Some(crate::output_section_id::GCC_EXCEPT_TABLE),
        _ => None,
    }
}

struct AddedMachOArchiveUnwindActivation {
    patches: Vec<SectionPatch>,
}

#[derive(Clone, Copy, Debug, PartialEq, Eq, Hash)]
struct MachOUnwindFunctionIdentity {
    function_offset: u32,
    length: u32,
}

struct AddedMachOArchiveEhFrameBlock {
    member_index: usize,
    input_offset: usize,
    data_offset: usize,
    data_size: usize,
    output_offset: u64,
    output_address: u64,
}

fn added_macho_archive_unwind_target_address(
    target: &AddedMachOArchiveUnwindTarget,
    use_got: bool,
    member_index: usize,
    members: &[AddedMachOArchiveTextMember],
    sections: &[PatchSection],
    eh_frame_blocks: &[AddedMachOArchiveEhFrameBlock],
    output_file: &object::File<'_>,
    resolutions: &[MachOSymbolResolutionRecord],
) -> std::result::Result<u64, String> {
    match target {
        AddedMachOArchiveUnwindTarget::Section(position) => {
            if use_got {
                return Err(
                    "added Mach-O unwind defined target cannot resolve a GOT address".to_owned(),
                );
            }
            let member = &members[member_index];
            if member
                .unwind
                .as_ref()
                .and_then(|unwind| unwind.eh_frame.as_ref())
                .is_some_and(|eh_frame| eh_frame.section_index == position.section_index)
            {
                let block = eh_frame_blocks
                    .iter()
                    .find(|block| block.member_index == member_index)
                    .ok_or_else(|| {
                        "added Mach-O unwind target has no allocated __eh_frame block".to_owned()
                    })?;
                let section_offset = usize::try_from(position.section_offset)
                    .ok()
                    .and_then(|offset| offset.checked_sub(block.input_offset))
                    .filter(|offset| *offset < block.data_size)
                    .ok_or_else(|| {
                        "added Mach-O unwind target is outside the copied __eh_frame block"
                            .to_owned()
                    })?;
                return block
                    .output_address
                    .checked_add(section_offset as u64)
                    .ok_or_else(|| {
                        "added Mach-O unwind __eh_frame target address overflowed".to_owned()
                    });
            }

            let section = sections
                .iter()
                .find(|section| {
                    section.input == member.input && section.section_index == position.section_index
                })
                .ok_or_else(|| "added Mach-O unwind target section was not allocated".to_owned())?;
            if position.section_offset >= section.input_size {
                return Err("added Mach-O unwind target is outside its section".to_owned());
            }
            let section_address =
                macho_output_address_for_file_offset(output_file, section.output_offset)
                    .ok_or_else(|| {
                        "added Mach-O unwind target section has no output address".to_owned()
                    })?;
            section_address
                .checked_add(position.section_offset)
                .ok_or_else(|| "added Mach-O unwind target address overflowed".to_owned())
        }
        AddedMachOArchiveUnwindTarget::UndefinedSymbol(name) => {
            if !use_got {
                return Err("added Mach-O unwind undefined target does not use the GOT".to_owned());
            }
            macho_symbol_resolution_for_name(resolutions, name)
                .and_then(|resolution| resolution.got_address)
                .ok_or_else(|| {
                    format!(
                        "added Mach-O unwind personality `{}` has no existing GOT resolution",
                        String::from_utf8_lossy(name)
                    )
                })
        }
    }
}

fn added_macho_archive_unwind_field_addend(
    relocation: &AddedMachOArchiveUnwindRelocation,
    implicit_addend: bool,
    signed_implicit_addend: bool,
) -> std::result::Result<i128, String> {
    let field_addend = if implicit_addend {
        match (relocation.width, signed_implicit_addend) {
            (4, true) => i128::from(i32::from_le_bytes(
                (relocation.field_value as u32).to_le_bytes(),
            )),
            (4, false) => i128::from(relocation.field_value as u32),
            (8, true) => i128::from(i64::from_le_bytes(relocation.field_value.to_le_bytes())),
            (8, false) => i128::from(relocation.field_value),
            (width, _) => {
                return Err(format!(
                    "added Mach-O unwind relocation has unsupported field width {width}"
                ));
            }
        }
    } else {
        0
    };
    field_addend
        .checked_add(i128::from(relocation.explicit_addend))
        .ok_or_else(|| "added Mach-O unwind relocation addend overflowed".to_owned())
}

#[allow(clippy::too_many_arguments)]
fn added_macho_archive_unwind_pointer_target_value(
    field: &AddedMachOArchiveUnwindPointerField,
    personality_got: bool,
    implicit_field_addend: bool,
    allow_subtractor: bool,
    member_index: usize,
    members: &[AddedMachOArchiveTextMember],
    sections: &[PatchSection],
    eh_frame_blocks: &[AddedMachOArchiveEhFrameBlock],
    output_file: &object::File<'_>,
    resolutions: &[MachOSymbolResolutionRecord],
) -> std::result::Result<u64, String> {
    if field.relocation.subtractor_target.is_some() && !allow_subtractor {
        return Err("added Mach-O unwind metadata pointer uses a subtractor relocation".to_owned());
    }
    let primary = field
        .relocation
        .raw
        .last()
        .ok_or_else(|| "added Mach-O unwind relocation operation is empty".to_owned())?;
    let pointer_to_got = primary.r_type == object::macho::ARM64_RELOC_POINTER_TO_GOT;
    let use_got = pointer_to_got || personality_got;
    if !matches!(
        primary.r_type,
        object::macho::ARM64_RELOC_UNSIGNED | object::macho::ARM64_RELOC_POINTER_TO_GOT
    ) {
        return Err(format!(
            "added Mach-O unwind metadata pointer uses unsupported relocation type {}",
            primary.r_type
        ));
    }
    let target = added_macho_archive_unwind_target_address(
        &field.target,
        use_got,
        member_index,
        members,
        sections,
        eh_frame_blocks,
        output_file,
        resolutions,
    )?;
    let value = i128::from(target)
        .checked_add(added_macho_archive_unwind_field_addend(
            &field.relocation,
            implicit_field_addend && !pointer_to_got,
            false,
        )?)
        .ok_or_else(|| "added Mach-O unwind metadata pointer overflowed".to_owned())?;
    u64::try_from(value).map_err(|_| "added Mach-O unwind metadata pointer overflowed".to_owned())
}

#[allow(clippy::too_many_arguments)]
fn added_macho_archive_unwind_relocated_value(
    field: &AddedMachOArchiveUnwindPointerField,
    field_address: u64,
    member_index: usize,
    members: &[AddedMachOArchiveTextMember],
    sections: &[PatchSection],
    eh_frame_blocks: &[AddedMachOArchiveEhFrameBlock],
    output_file: &object::File<'_>,
    resolutions: &[MachOSymbolResolutionRecord],
) -> std::result::Result<(i128, bool), String> {
    let primary = field
        .relocation
        .raw
        .last()
        .ok_or_else(|| "added Mach-O unwind relocation operation is empty".to_owned())?;
    if !matches!(
        primary.r_type,
        object::macho::ARM64_RELOC_UNSIGNED | object::macho::ARM64_RELOC_POINTER_TO_GOT
    ) {
        return Err(format!(
            "added Mach-O unwind field uses unsupported relocation type {}",
            primary.r_type
        ));
    }
    let use_got = primary.r_type == object::macho::ARM64_RELOC_POINTER_TO_GOT;
    let target = added_macho_archive_unwind_target_address(
        &field.target,
        use_got,
        member_index,
        members,
        sections,
        eh_frame_blocks,
        output_file,
        resolutions,
    )?;
    let subtractor = if let Some(subtractor) = &field.relocation.subtractor_target {
        Some(added_macho_archive_unwind_target_address(
            subtractor,
            false,
            member_index,
            members,
            sections,
            eh_frame_blocks,
            output_file,
            resolutions,
        )?)
    } else {
        None
    };
    added_macho_archive_unwind_relocation_value(
        target,
        subtractor,
        field_address,
        &field.relocation,
    )
}

fn added_macho_archive_unwind_relocation_value(
    target: u64,
    subtractor: Option<u64>,
    field_address: u64,
    relocation: &AddedMachOArchiveUnwindRelocation,
) -> std::result::Result<(i128, bool), String> {
    let primary = relocation
        .raw
        .last()
        .ok_or_else(|| "added Mach-O unwind relocation operation is empty".to_owned())?;
    if !matches!(
        primary.r_type,
        object::macho::ARM64_RELOC_UNSIGNED | object::macho::ARM64_RELOC_POINTER_TO_GOT
    ) {
        return Err(format!(
            "added Mach-O unwind field uses unsupported relocation type {}",
            primary.r_type
        ));
    }
    let use_got = primary.r_type == object::macho::ARM64_RELOC_POINTER_TO_GOT;
    let mut value = i128::from(target)
        .checked_add(added_macho_archive_unwind_field_addend(
            relocation,
            !use_got,
            subtractor.is_some(),
        )?)
        .ok_or_else(|| "added Mach-O unwind relocated value overflowed".to_owned())?;
    let signed = if let Some(subtractor) = subtractor {
        value = value
            .checked_sub(i128::from(subtractor))
            .ok_or_else(|| "added Mach-O unwind subtractor relocation overflowed".to_owned())?;
        true
    } else if use_got || primary.r_pcrel {
        value = value
            .checked_sub(i128::from(field_address))
            .ok_or_else(|| "added Mach-O unwind PC-relative relocation overflowed".to_owned())?;
        true
    } else {
        false
    };
    Ok((value, signed))
}

fn write_added_macho_archive_unwind_value(
    data: &mut [u8],
    offset: usize,
    width: u8,
    value: i128,
    signed: bool,
) -> std::result::Result<(), String> {
    let bytes = data
        .get_mut(offset..offset + usize::from(width))
        .ok_or_else(|| "added Mach-O unwind relocation field is outside copied data".to_owned())?;
    match (width, signed) {
        (4, true) => bytes.copy_from_slice(
            &i32::try_from(value)
                .map_err(|_| "added Mach-O unwind signed 4-byte relocation overflowed".to_owned())?
                .to_le_bytes(),
        ),
        (4, false) => bytes.copy_from_slice(
            &u32::try_from(value)
                .map_err(|_| {
                    "added Mach-O unwind unsigned 4-byte relocation overflowed".to_owned()
                })?
                .to_le_bytes(),
        ),
        (8, true) => bytes.copy_from_slice(
            &i64::try_from(value)
                .map_err(|_| "added Mach-O unwind signed 8-byte relocation overflowed".to_owned())?
                .to_le_bytes(),
        ),
        (8, false) => bytes.copy_from_slice(
            &u64::try_from(value)
                .map_err(|_| {
                    "added Mach-O unwind unsigned 8-byte relocation overflowed".to_owned()
                })?
                .to_le_bytes(),
        ),
        _ => {
            return Err(format!(
                "added Mach-O unwind relocation has unsupported field width {width}"
            ));
        }
    }
    Ok(())
}

fn added_macho_archive_image_offset(address: u64) -> std::result::Result<u32, String> {
    address
        .checked_sub(crate::macho::MACHO_START_MEM_ADDRESS)
        .and_then(|offset| u32::try_from(offset).ok())
        .ok_or_else(|| "added Mach-O unwind address is outside the image-offset range".to_owned())
}

fn added_macho_archive_unwind_entry_ranges(
    eh_frame: &AddedMachOArchiveEhFrame,
) -> std::result::Result<Vec<std::ops::Range<usize>>, String> {
    let mut ranges = eh_frame
        .cies
        .iter()
        .map(|cie| cie.input_range.clone())
        .chain(eh_frame.fdes.iter().map(|fde| fde.input_range.clone()))
        .collect::<Vec<_>>();
    ranges.sort_by_key(|range| range.start);
    let mut offset = 0usize;
    for range in &ranges {
        if range.start != offset || range.end <= range.start || range.end > eh_frame.data.len() {
            return Err(
                "added Mach-O __eh_frame parsed entries are not one contiguous stream".to_owned(),
            );
        }
        offset = range.end;
    }
    if ranges.is_empty() || eh_frame.data[offset..].iter().any(|byte| *byte != 0) {
        return Err("added Mach-O __eh_frame has nonzero bytes outside parsed entries".to_owned());
    }
    if !offset.is_multiple_of(8) {
        return Err("added Mach-O __eh_frame entry stream size is not 8-byte aligned".to_owned());
    }
    Ok(ranges)
}

fn added_macho_archive_unique_output_section(
    output_file: &object::File<'_>,
    segment_name: &[u8],
    section_name: &[u8],
) -> std::result::Result<object::SectionIndex, String> {
    let mut matches = output_file.sections().filter(|section| {
        section.segment_name_bytes().ok().flatten() == Some(segment_name)
            && section.name_bytes().ok() == Some(section_name)
    });
    let section = matches.next().ok_or_else(|| {
        format!(
            "previous Mach-O output has no {},{} section",
            String::from_utf8_lossy(segment_name),
            String::from_utf8_lossy(section_name)
        )
    })?;
    if matches.next().is_some() {
        return Err(format!(
            "previous Mach-O output has multiple {},{} sections",
            String::from_utf8_lossy(segment_name),
            String::from_utf8_lossy(section_name)
        ));
    }
    Ok(section.index())
}

fn added_macho_archive_unwind_ranges_overlap(
    left_start: u32,
    left_length: u32,
    right_start: u32,
    right_length: u32,
) -> bool {
    let left_end = left_start.saturating_add(left_length.max(1));
    let right_end = right_start.saturating_add(right_length.max(1));
    left_start < right_end && right_start < left_end
}

fn merge_macho_unwind_info_entries(
    existing_entries: Vec<crate::macho_writer::UnwindInfoEntry>,
    retired_entries: &[MachOUnwindFunctionIdentity],
    mut added_entries: Vec<crate::macho_writer::UnwindInfoEntry>,
) -> std::result::Result<Vec<crate::macho_writer::UnwindInfoEntry>, String> {
    let retired = retired_entries.iter().copied().collect::<HashSet<_>>();
    if retired.len() != retired_entries.len() {
        return Err("replacement Mach-O unwind entries contain a duplicate identity".to_owned());
    }

    let mut retired_matches = HashMap::with_capacity(retired.len());
    let mut retained_entries = Vec::with_capacity(existing_entries.len() + added_entries.len());
    for existing in existing_entries
        .into_iter()
        .filter(|entry| entry.encoding != 0)
    {
        let identity = MachOUnwindFunctionIdentity {
            function_offset: existing.function_offset,
            length: existing.length,
        };
        if retired.contains(&identity) {
            *retired_matches.entry(identity).or_insert(0usize) += 1;
            continue;
        }
        if retired.iter().any(|retired| {
            added_macho_archive_unwind_ranges_overlap(
                existing.function_offset,
                existing.length,
                retired.function_offset,
                retired.length,
            )
        }) {
            return Err(
                "replacement Mach-O unwind identity partially overlaps an existing live entry"
                    .to_owned(),
            );
        }
        retained_entries.push(existing);
    }
    if retired
        .iter()
        .any(|identity| retired_matches.get(identity) != Some(&1))
    {
        return Err(
            "replacement Mach-O unwind identity does not match exactly one live entry".to_owned(),
        );
    }

    added_entries.sort_by_key(|entry| entry.function_offset);
    if added_entries.windows(2).any(|pair| {
        added_macho_archive_unwind_ranges_overlap(
            pair[0].function_offset,
            pair[0].length,
            pair[1].function_offset,
            pair[1].length,
        )
    }) {
        return Err("replacement Mach-O unwind entries overlap or are duplicated".to_owned());
    }
    for added in &added_entries {
        if retained_entries.iter().any(|existing| {
            added_macho_archive_unwind_ranges_overlap(
                existing.function_offset,
                existing.length,
                added.function_offset,
                added.length,
            )
        }) {
            return Err(
                "replacement Mach-O unwind entry overlaps an existing live entry".to_owned(),
            );
        }
    }

    retained_entries.extend(added_entries);
    retained_entries.sort_by_key(|entry| entry.function_offset);
    Ok(retained_entries)
}

fn allocate_added_macho_archive_eh_frame_range(
    reserved_ranges: &mut Vec<ReservedRangeRecord>,
    section_data: &[u8],
    section_file_offset: u64,
    terminator_offset: usize,
    data_size: u64,
) -> Result<std::result::Result<ReservedRangeAllocation, String>> {
    validate_reserved_ranges(reserved_ranges)?;
    let output_section_id = u32::try_from(crate::output_section_id::EH_FRAME.as_usize())
        .context("Mach-O EH_FRAME output section ID does not fit u32")?;
    let terminator_output_offset = section_file_offset
        .checked_add(terminator_offset as u64)
        .context("Previous Mach-O __eh_frame terminator offset overflow")?;
    let patch_end = terminator_output_offset
        .checked_add(data_size)
        .context("Added Mach-O __eh_frame patch end overflow")?;
    let alignment = crate::alignment::Alignment { exponent: 3 };
    let next_output_offset = alignment.align_up(patch_end);

    let candidates = reserved_ranges
        .iter()
        .enumerate()
        .filter_map(|(index, range)| {
            let range_end = range.output_offset.checked_add(range.size)?;
            (range.output_section_id == output_section_id
                && range.alignment_exponent == alignment.exponent
                && range.output_offset >= terminator_output_offset
                && range.output_offset - terminator_output_offset < alignment.value()
                && patch_end <= range_end
                && next_output_offset <= range_end)
                .then_some((index, range_end))
        })
        .collect::<Vec<_>>();
    let [(range_index, range_end)] = candidates.as_slice() else {
        return Ok(Err(
            "added Mach-O __eh_frame reserve is not adjacent to the current terminator".to_owned(),
        ));
    };

    let zero_start = terminator_offset;
    let zero_end = usize::try_from(
        next_output_offset
            .checked_sub(section_file_offset)
            .context("Added Mach-O __eh_frame allocation precedes its section")?,
    )
    .context("Added Mach-O __eh_frame allocation exceeds usize")?;
    if section_data
        .get(zero_start..zero_end)
        .is_none_or(|data| data.iter().any(|byte| *byte != 0))
    {
        return Ok(Err(
            "added Mach-O __eh_frame reserve or alignment gap is not zero-filled".to_owned(),
        ));
    }

    if next_output_offset == *range_end {
        reserved_ranges.swap_remove(*range_index);
    } else {
        let range = &mut reserved_ranges[*range_index];
        range.output_offset = next_output_offset;
        range.size = *range_end - next_output_offset;
    }
    reserved_ranges.sort_unstable();
    validate_reserved_ranges(reserved_ranges)?;
    Ok(Ok(ReservedRangeAllocation {
        output_offset: terminator_output_offset,
        size: data_size,
    }))
}

#[allow(clippy::too_many_arguments)]
fn added_macho_archive_unwind_activation(
    members: &[AddedMachOArchiveTextMember],
    selected_indices: &[usize],
    sections: &[PatchSection],
    output_file: &object::File<'_>,
    resolutions: &[MachOSymbolResolutionRecord],
    retired_entries: &[MachOUnwindFunctionIdentity],
    remaining_reserved_ranges: &mut Vec<ReservedRangeRecord>,
) -> Result<std::result::Result<Option<AddedMachOArchiveUnwindActivation>, String>> {
    if selected_indices
        .iter()
        .all(|&member_index| members[member_index].unwind.is_none())
    {
        return Ok(Ok(None));
    }
    let mut staged_reserved_ranges = remaining_reserved_ranges.clone();

    let mut eh_frame_data = Vec::new();
    let mut eh_frame_blocks = Vec::new();
    for &member_index in selected_indices {
        let Some(eh_frame) = members[member_index]
            .unwind
            .as_ref()
            .and_then(|unwind| unwind.eh_frame.as_ref())
        else {
            continue;
        };
        let ranges = match added_macho_archive_unwind_entry_ranges(eh_frame) {
            Ok(ranges) => ranges,
            Err(reason) => return Ok(Err(reason)),
        };
        let data_size = ranges.last().unwrap().end;
        let data_offset = eh_frame_data.len();
        if !data_offset.is_multiple_of(8) {
            return Ok(Err(
                "added Mach-O __eh_frame block does not start at 8-byte alignment".to_owned(),
            ));
        }
        eh_frame_data.extend_from_slice(&eh_frame.data[..data_size]);
        eh_frame_blocks.push(AddedMachOArchiveEhFrameBlock {
            member_index,
            input_offset: ranges[0].start,
            data_offset,
            data_size,
            output_offset: 0,
            output_address: 0,
        });
    }

    let mut patches = Vec::new();
    let mut eh_frame_section_file_offset = None;
    if !eh_frame_data.is_empty() {
        let eh_frame_section_index = match added_macho_archive_unique_output_section(
            output_file,
            b"__TEXT",
            b"__eh_frame",
        ) {
            Ok(section) => section,
            Err(reason) => return Ok(Err(reason)),
        };
        let eh_frame_section = output_file.section_by_index(eh_frame_section_index)?;
        let Some((section_file_offset, section_file_size)) = eh_frame_section.file_range() else {
            return Ok(Err(
                "previous Mach-O __eh_frame section has no file range".to_owned()
            ));
        };
        let section_data = eh_frame_section
            .data()
            .context("Failed to read previous Mach-O __eh_frame section")?;
        let Some(terminator_offset) = eh_frame_terminator_offset(section_data) else {
            return Ok(Err(
                "previous Mach-O __eh_frame section has no zero terminator".to_owned(),
            ));
        };
        let allocation = match allocate_added_macho_archive_eh_frame_range(
            &mut staged_reserved_ranges,
            section_data,
            section_file_offset,
            terminator_offset,
            u64::try_from(eh_frame_data.len())
                .context("Added Mach-O __eh_frame entry stream is too large")?,
        )? {
            Ok(allocation) => allocation,
            Err(reason) => return Ok(Err(reason)),
        };
        let section_file_end = section_file_offset
            .checked_add(section_file_size)
            .context("Previous Mach-O __eh_frame file range overflow")?;
        if allocation.size != eh_frame_data.len() as u64
            || allocation
                .output_offset
                .checked_add(allocation.size)
                .is_none_or(|end| end > section_file_end)
        {
            return Ok(Err(
                "added Mach-O __eh_frame reserve does not begin at the current terminator"
                    .to_owned(),
            ));
        }
        for block in &mut eh_frame_blocks {
            block.output_offset = allocation
                .output_offset
                .checked_add(block.data_offset as u64)
                .context("Added Mach-O __eh_frame block offset overflow")?;
            block.output_address =
                macho_output_address_for_file_offset(output_file, block.output_offset)
                    .context("Added Mach-O __eh_frame block has no output address")?;
        }
        eh_frame_section_file_offset = Some(section_file_offset);
        patches.push(SectionPatch {
            output_offset: allocation.output_offset,
            size: allocation.size,
            data: eh_frame_data,
            deferred_relocation: None,
            preserve_ranges: Vec::new(),
            adjustments: Vec::new(),
        });
    }

    let eh_frame_patch_index = (!patches.is_empty()).then_some(0);
    for block in &eh_frame_blocks {
        let member = &members[block.member_index];
        let eh_frame = member
            .unwind
            .as_ref()
            .and_then(|unwind| unwind.eh_frame.as_ref())
            .expect("EH-frame block requires parsed metadata");
        let data = &mut patches[eh_frame_patch_index.unwrap()].data;
        debug_assert_eq!(block.data_size, eh_frame.data[..block.data_size].len());

        for cie in &eh_frame.cies {
            let Some(personality) = &cie.personality else {
                continue;
            };
            let field_address = block
                .output_address
                .checked_add(personality.input_offset as u64)
                .context("Added Mach-O CIE personality address overflow")?;
            let (value, signed) = match added_macho_archive_unwind_relocated_value(
                personality,
                field_address,
                block.member_index,
                members,
                sections,
                &eh_frame_blocks,
                output_file,
                resolutions,
            ) {
                Ok(value) => value,
                Err(reason) => return Ok(Err(reason)),
            };
            if let Err(reason) = write_added_macho_archive_unwind_value(
                data,
                block.data_offset + personality.input_offset,
                personality.width,
                value,
                signed,
            ) {
                return Ok(Err(reason));
            }
        }

        for fde in &eh_frame.fdes {
            let cie = &eh_frame.cies[fde.cie_index];
            let fde_output_offset = block
                .output_offset
                .checked_add(fde.input_range.start as u64)
                .context("Added Mach-O FDE output offset overflow")?;
            let cie_output_offset = block
                .output_offset
                .checked_add(cie.input_range.start as u64)
                .context("Added Mach-O CIE output offset overflow")?;
            let cie_pointer = fde_output_offset
                .checked_add(4)
                .and_then(|offset| offset.checked_sub(cie_output_offset))
                .and_then(|offset| u32::try_from(offset).ok());
            let Some(cie_pointer) = cie_pointer else {
                return Ok(Err("added Mach-O FDE CIE pointer overflowed".to_owned()));
            };
            let cie_pointer_offset = block.data_offset + fde.input_range.start + 4;
            let Some(cie_pointer_bytes) = data.get_mut(cie_pointer_offset..cie_pointer_offset + 4)
            else {
                return Ok(Err(
                    "added Mach-O FDE CIE pointer is outside copied data".to_owned()
                ));
            };
            cie_pointer_bytes.copy_from_slice(&cie_pointer.to_le_bytes());

            for field in std::iter::once(&fde.pc_begin).chain(fde.lsda.iter()) {
                let field_address = block
                    .output_address
                    .checked_add(field.input_offset as u64)
                    .context("Added Mach-O FDE relocation address overflow")?;
                let (value, signed) = match added_macho_archive_unwind_relocated_value(
                    field,
                    field_address,
                    block.member_index,
                    members,
                    sections,
                    &eh_frame_blocks,
                    output_file,
                    resolutions,
                ) {
                    Ok(value) => value,
                    Err(reason) => return Ok(Err(reason)),
                };
                if let Err(reason) = write_added_macho_archive_unwind_value(
                    data,
                    block.data_offset + field.input_offset,
                    field.width,
                    value,
                    signed,
                ) {
                    return Ok(Err(reason));
                }
            }
        }
    }

    let mut added_entries = Vec::new();
    for &member_index in selected_indices {
        let member = &members[member_index];
        let Some(unwind) = &member.unwind else {
            continue;
        };
        if let Some(compact_unwind) = &unwind.compact_unwind {
            for entry in &compact_unwind.entries {
                if entry.encoding & ADDED_MACHO_UNWIND_MODE_MASK == ADDED_MACHO_UNWIND_MODE_DWARF {
                    continue;
                }
                let function_address = match added_macho_archive_unwind_target_address(
                    &AddedMachOArchiveUnwindTarget::Section(entry.function.clone()),
                    false,
                    member_index,
                    members,
                    sections,
                    &eh_frame_blocks,
                    output_file,
                    resolutions,
                ) {
                    Ok(address) => address,
                    Err(reason) => return Ok(Err(reason)),
                };
                let personality_offset = match entry.personality.as_ref() {
                    Some(personality) => {
                        let address = match added_macho_archive_unwind_pointer_target_value(
                            personality,
                            true,
                            true,
                            false,
                            member_index,
                            members,
                            sections,
                            &eh_frame_blocks,
                            output_file,
                            resolutions,
                        ) {
                            Ok(address) => address,
                            Err(reason) => return Ok(Err(reason)),
                        };
                        Some(match added_macho_archive_image_offset(address) {
                            Ok(offset) => offset,
                            Err(reason) => return Ok(Err(reason)),
                        })
                    }
                    None => None,
                };
                let lsda_offset = match entry.lsda.as_ref() {
                    Some(lsda) => {
                        let address = match added_macho_archive_unwind_pointer_target_value(
                            lsda,
                            false,
                            true,
                            false,
                            member_index,
                            members,
                            sections,
                            &eh_frame_blocks,
                            output_file,
                            resolutions,
                        ) {
                            Ok(address) => address,
                            Err(reason) => return Ok(Err(reason)),
                        };
                        Some(match added_macho_archive_image_offset(address) {
                            Ok(offset) => offset,
                            Err(reason) => return Ok(Err(reason)),
                        })
                    }
                    None => None,
                };
                added_entries.push(crate::macho_writer::UnwindInfoEntry {
                    function_offset: match added_macho_archive_image_offset(function_address) {
                        Ok(offset) => offset,
                        Err(reason) => return Ok(Err(reason)),
                    },
                    length: entry.function_length,
                    encoding: entry.encoding
                        & !(ADDED_MACHO_UNWIND_PERSONALITY_MASK | ADDED_MACHO_UNWIND_HAS_LSDA),
                    personality_offset,
                    lsda_offset,
                });
            }
        }
        if let Some(eh_frame) = &unwind.eh_frame {
            let block = eh_frame_blocks
                .iter()
                .find(|block| block.member_index == member_index)
                .expect("parsed EH frame requires output block");
            let eh_frame_section_file_offset =
                eh_frame_section_file_offset.expect("EH frame block requires output section");
            for (fde_index, fde) in eh_frame.fdes.iter().enumerate() {
                if unwind.compact_unwind.as_ref().is_some_and(|compact| {
                    compact.entries.iter().any(|entry| {
                        entry.encoding & ADDED_MACHO_UNWIND_MODE_MASK
                            != ADDED_MACHO_UNWIND_MODE_DWARF
                            && entry.function == fde.function
                            && entry.function_length == fde.function_length
                    })
                }) {
                    continue;
                }
                let dwarf_compact_entry = unwind.compact_unwind.as_ref().and_then(|compact| {
                    compact
                        .entries
                        .iter()
                        .find(|entry| entry.fde_index == Some(fde_index))
                });
                let function_address = match added_macho_archive_unwind_target_address(
                    &AddedMachOArchiveUnwindTarget::Section(fde.function.clone()),
                    false,
                    member_index,
                    members,
                    sections,
                    &eh_frame_blocks,
                    output_file,
                    resolutions,
                ) {
                    Ok(address) => address,
                    Err(reason) => return Ok(Err(reason)),
                };
                let cie = &eh_frame.cies[fde.cie_index];
                let personality = dwarf_compact_entry
                    .and_then(|entry| entry.personality.as_ref())
                    .or(cie.personality.as_ref());
                let personality_offset = match personality {
                    Some(personality) => {
                        let address = match added_macho_archive_unwind_pointer_target_value(
                            personality,
                            true,
                            false,
                            false,
                            member_index,
                            members,
                            sections,
                            &eh_frame_blocks,
                            output_file,
                            resolutions,
                        ) {
                            Ok(address) => address,
                            Err(reason) => return Ok(Err(reason)),
                        };
                        Some(match added_macho_archive_image_offset(address) {
                            Ok(offset) => offset,
                            Err(reason) => return Ok(Err(reason)),
                        })
                    }
                    None => None,
                };
                let lsda = dwarf_compact_entry
                    .and_then(|entry| entry.lsda.as_ref())
                    .or(fde.lsda.as_ref());
                let lsda_offset = match lsda {
                    Some(lsda) => {
                        let address = match added_macho_archive_unwind_pointer_target_value(
                            lsda,
                            false,
                            false,
                            true,
                            member_index,
                            members,
                            sections,
                            &eh_frame_blocks,
                            output_file,
                            resolutions,
                        ) {
                            Ok(address) => address,
                            Err(reason) => return Ok(Err(reason)),
                        };
                        Some(match added_macho_archive_image_offset(address) {
                            Ok(offset) => offset,
                            Err(reason) => return Ok(Err(reason)),
                        })
                    }
                    None => None,
                };
                let fde_output_offset = block
                    .output_offset
                    .checked_add(fde.input_range.start as u64)
                    .context("Added Mach-O FDE output offset overflow")?;
                let output_dwarf_offset = fde_output_offset
                    .checked_sub(eh_frame_section_file_offset)
                    .context("Added Mach-O FDE precedes output __eh_frame")?;
                added_entries.push(crate::macho_writer::UnwindInfoEntry {
                    function_offset: match added_macho_archive_image_offset(function_address) {
                        Ok(offset) => offset,
                        Err(reason) => return Ok(Err(reason)),
                    },
                    length: fde.function_length,
                    encoding: dwarf_compact_entry.map_or(ADDED_MACHO_UNWIND_MODE_DWARF, |entry| {
                        entry.encoding
                            & !(ADDED_MACHO_UNWIND_DWARF_OFFSET_MASK
                                | ADDED_MACHO_UNWIND_PERSONALITY_MASK
                                | ADDED_MACHO_UNWIND_HAS_LSDA)
                    }) | crate::macho_writer::compact_unwind_dwarf_offset_hint(
                        output_dwarf_offset,
                    ),
                    personality_offset,
                    lsda_offset,
                });
            }
        }
    }

    added_entries.sort_by_key(|entry| entry.function_offset);
    for pair in added_entries.windows(2) {
        if added_macho_archive_unwind_ranges_overlap(
            pair[0].function_offset,
            pair[0].length,
            pair[1].function_offset,
            pair[1].length,
        ) {
            return Ok(Err(
                "added Mach-O unwind function entries overlap or are duplicated".to_owned(),
            ));
        }
    }

    let unwind_info_section_index =
        match added_macho_archive_unique_output_section(output_file, b"__TEXT", b"__unwind_info") {
            Ok(section) => section,
            Err(reason) => return Ok(Err(reason)),
        };
    let unwind_info_section = output_file.section_by_index(unwind_info_section_index)?;
    let Some((unwind_info_file_offset, unwind_info_size)) = unwind_info_section.file_range() else {
        return Ok(Err(
            "previous Mach-O __unwind_info section has no file range".to_owned(),
        ));
    };
    let unwind_info_data = unwind_info_section
        .data()
        .context("Failed to read previous Mach-O __unwind_info section")?;
    let existing_entries = match crate::macho_writer::parse_macho_unwind_info(unwind_info_data) {
        Ok(entries) => entries,
        Err(error) => {
            return Ok(Err(format!(
                "failed to parse previous Mach-O __unwind_info: {error:?}"
            )));
        }
    };
    let existing_entries =
        match merge_macho_unwind_info_entries(existing_entries, retired_entries, added_entries) {
            Ok(entries) => entries,
            Err(reason) => return Ok(Err(reason)),
        };

    let text_section_index =
        match added_macho_archive_unique_output_section(output_file, b"__TEXT", b"__text") {
            Ok(section) => section,
            Err(reason) => return Ok(Err(reason)),
        };
    let text_section = output_file.section_by_index(text_section_index)?;
    let text_end_address = text_section
        .address()
        .checked_add(text_section.size())
        .context("Previous Mach-O text end address overflow")?;
    let text_end = match added_macho_archive_image_offset(text_end_address) {
        Ok(offset) => offset,
        Err(reason) => return Ok(Err(reason)),
    };
    let mut encoded_unwind_info = vec![0; unwind_info_data.len()];
    if let Err(error) = crate::macho_writer::serialize_macho_unwind_info(
        &mut encoded_unwind_info,
        existing_entries,
        text_end,
    ) {
        return Ok(Err(format!(
            "failed to serialize added Mach-O __unwind_info: {error:?}"
        )));
    }
    patches.push(SectionPatch {
        output_offset: unwind_info_file_offset,
        size: unwind_info_size,
        data: encoded_unwind_info,
        deferred_relocation: None,
        preserve_ranges: Vec::new(),
        adjustments: Vec::new(),
    });

    *remaining_reserved_ranges = staged_reserved_ranges;
    Ok(Ok(Some(AddedMachOArchiveUnwindActivation { patches })))
}

const ADDED_MACHO_UNWIND_MODE_MASK: u32 = 0x0f00_0000;
const ADDED_MACHO_UNWIND_MODE_DWARF: u32 = 0x0300_0000;
const ADDED_MACHO_UNWIND_DWARF_OFFSET_MASK: u32 = 0x00ff_ffff;
const ADDED_MACHO_UNWIND_PERSONALITY_MASK: u32 = 0x3000_0000;
const ADDED_MACHO_UNWIND_HAS_LSDA: u32 = 0x4000_0000;
const DW_EH_PE_ABSPTR: u8 = 0x00;
const DW_EH_PE_UDATA4: u8 = 0x03;
const DW_EH_PE_UDATA8: u8 = 0x04;
const DW_EH_PE_SDATA4: u8 = 0x0b;
const DW_EH_PE_SDATA8: u8 = 0x0c;
const DW_EH_PE_OMIT: u8 = 0xff;

fn added_macho_archive_unwind(
    file: &object::File<'_>,
) -> Result<std::result::Result<Option<AddedMachOArchiveUnwind>, String>> {
    let object::File::MachO64(macho_file) = file else {
        return Ok(Err(
            "added Mach-O archive member unwind metadata is not Mach-O 64-bit".to_owned(),
        ));
    };
    let mut compact_unwind_index = None;
    let mut eh_frame_index = None;
    for section in file.sections() {
        match (
            section.segment_name_bytes().ok().flatten(),
            section.name_bytes().ok(),
        ) {
            (Some(b"__LD"), Some(b"__compact_unwind")) => {
                if compact_unwind_index.replace(section.index()).is_some() {
                    return Ok(Err(
                        "added Mach-O archive member has multiple __compact_unwind sections"
                            .to_owned(),
                    ));
                }
            }
            (Some(b"__TEXT"), Some(b"__eh_frame")) => {
                if eh_frame_index.replace(section.index()).is_some() {
                    return Ok(Err(
                        "added Mach-O archive member has multiple __eh_frame sections".to_owned(),
                    ));
                }
            }
            _ => {}
        }
    }
    if compact_unwind_index.is_none() && eh_frame_index.is_none() {
        return Ok(Ok(None));
    }

    let compact_unwind = if let Some(section_index) = compact_unwind_index {
        let section = macho_file.section_by_index(section_index)?;
        match added_macho_archive_compact_unwind(file, &section)? {
            Ok(compact_unwind) => Some(compact_unwind),
            Err(reason) => return Ok(Err(reason)),
        }
    } else {
        None
    };
    let eh_frame = if let Some(section_index) = eh_frame_index {
        let section = macho_file.section_by_index(section_index)?;
        match added_macho_archive_eh_frame(file, &section)? {
            Ok(eh_frame) => Some(eh_frame),
            Err(reason) => return Ok(Err(reason)),
        }
    } else {
        None
    };

    let mut unwind = AddedMachOArchiveUnwind {
        compact_unwind,
        eh_frame,
    };
    if let Some(compact_unwind) = &mut unwind.compact_unwind {
        for entry in &mut compact_unwind.entries {
            if entry.encoding & ADDED_MACHO_UNWIND_MODE_MASK != ADDED_MACHO_UNWIND_MODE_DWARF {
                continue;
            }
            let matches = unwind
                .eh_frame
                .as_ref()
                .into_iter()
                .flat_map(|eh_frame| eh_frame.fdes.iter().enumerate())
                .filter(|(_, fde)| {
                    fde.function == entry.function && fde.function_length == entry.function_length
                })
                .map(|(index, _)| index)
                .collect::<Vec<_>>();
            match matches.as_slice() {
                [fde_index] => entry.fde_index = Some(*fde_index),
                [] => {
                    return Ok(Err(
                        "added Mach-O archive member DWARF compact unwind entry has no matching FDE"
                            .to_owned(),
                    ));
                }
                _ => {
                    return Ok(Err(
                        "added Mach-O archive member DWARF compact unwind entry has ambiguous FDEs"
                            .to_owned(),
                    ));
                }
            }
        }
    }
    Ok(Ok(Some(unwind)))
}

fn added_macho_archive_compact_unwind<'data>(
    file: &object::File<'data>,
    section: &object::read::macho::MachOSection64<'data, '_, object::Endianness>,
) -> Result<std::result::Result<AddedMachOArchiveCompactUnwind, String>> {
    let object::SectionFlags::MachO { flags } = section.flags() else {
        return Ok(Err(
            "added Mach-O archive member __compact_unwind has non-Mach-O flags".to_owned(),
        ));
    };
    if flags & object::macho::SECTION_TYPE != object::macho::S_REGULAR {
        return Ok(Err(
            "added Mach-O archive member __compact_unwind is not regular".to_owned(),
        ));
    }
    let data = section
        .data()
        .context("Failed to read added Mach-O archive member __compact_unwind")?;
    if data.is_empty()
        || !data
            .len()
            .is_multiple_of(crate::macho::MACHO_COMPACT_UNWIND_ENTRY_SIZE)
    {
        return Ok(Err(format!(
            "added Mach-O archive member __compact_unwind size is not a nonzero multiple of {}",
            crate::macho::MACHO_COMPACT_UNWIND_ENTRY_SIZE
        )));
    }
    let mut relocations = match added_macho_archive_unwind_relocations(section, data) {
        Ok(relocations) => relocations,
        Err(reason) => return Ok(Err(reason)),
    };
    let mut entries =
        Vec::with_capacity(data.len() / crate::macho::MACHO_COMPACT_UNWIND_ENTRY_SIZE);
    for entry_start in (0..data.len()).step_by(crate::macho::MACHO_COMPACT_UNWIND_ENTRY_SIZE) {
        let function_field = match added_macho_archive_unwind_pointer_field(
            file,
            data,
            &mut relocations,
            entry_start,
            8,
            None,
            true,
        )? {
            Ok(Some(field)) => field,
            Ok(None) => unreachable!("required compact unwind function field"),
            Err(reason) => return Ok(Err(reason)),
        };
        if added_macho_archive_unwind_subtractor(&function_field.relocation).is_some() {
            return Ok(Err(
                "added Mach-O archive member compact unwind function uses a subtractor relocation"
                    .to_owned(),
            ));
        }
        let function = match added_macho_archive_unwind_pointer_position(&function_field, true)? {
            Ok(function) => function,
            Err(reason) => return Ok(Err(reason)),
        };
        let function_length = read_u32_le(&data[entry_start + 8..entry_start + 12])
            .context("Added Mach-O compact unwind length is truncated")?;
        if function_length == 0 {
            return Ok(Err(
                "added Mach-O archive member compact unwind function has zero length".to_owned(),
            ));
        }
        let encoding = read_u32_le(&data[entry_start + 12..entry_start + 16])
            .context("Added Mach-O compact unwind encoding is truncated")?;
        let personality = match added_macho_archive_unwind_pointer_field(
            file,
            data,
            &mut relocations,
            entry_start + 16,
            8,
            None,
            false,
        )? {
            Ok(field) => field,
            Err(reason) => return Ok(Err(reason)),
        };
        let lsda = match added_macho_archive_unwind_pointer_field(
            file,
            data,
            &mut relocations,
            entry_start + 24,
            8,
            None,
            false,
        )? {
            Ok(field) => field,
            Err(reason) => return Ok(Err(reason)),
        };
        entries.push(AddedMachOArchiveCompactUnwindEntry {
            input_range: entry_start..entry_start + crate::macho::MACHO_COMPACT_UNWIND_ENTRY_SIZE,
            function,
            function_length,
            encoding,
            function_field,
            personality,
            lsda,
            fde_index: None,
        });
    }
    if !relocations.is_empty() {
        return Ok(Err(
            "added Mach-O archive member __compact_unwind has an unexpected relocation".to_owned(),
        ));
    }
    entries.sort_by_key(|entry| (entry.function.section_index, entry.function.section_offset));
    if entries
        .windows(2)
        .any(|pair| pair[0].function == pair[1].function)
    {
        return Ok(Err(
            "added Mach-O archive member compact unwind functions are ambiguous".to_owned(),
        ));
    }
    Ok(Ok(AddedMachOArchiveCompactUnwind {
        section_index: patch_section_record_index(file, section.index())?,
        entries,
    }))
}

fn added_macho_archive_eh_frame<'data>(
    file: &object::File<'data>,
    section: &object::read::macho::MachOSection64<'data, '_, object::Endianness>,
) -> Result<std::result::Result<AddedMachOArchiveEhFrame, String>> {
    let data = section
        .data()
        .context("Failed to read added Mach-O archive member __eh_frame")?;
    if data.is_empty() {
        return Ok(Err(
            "added Mach-O archive member __eh_frame is empty".to_owned()
        ));
    }
    let mut relocations = match added_macho_archive_unwind_relocations(section, data) {
        Ok(relocations) => relocations,
        Err(reason) => return Ok(Err(reason)),
    };
    let mut entries = Vec::new();
    let mut offset = 0usize;
    while offset < data.len() {
        let Some(length_bytes) = data.get(offset..offset + 4) else {
            return Ok(Err(
                "added Mach-O archive member __eh_frame length is truncated".to_owned(),
            ));
        };
        let length = read_u32_le(length_bytes).unwrap() as usize;
        if length == 0 {
            if data[offset..].iter().any(|byte| *byte != 0) {
                return Ok(Err(
                    "added Mach-O archive member __eh_frame has nonzero bytes after its terminator"
                        .to_owned(),
                ));
            }
            break;
        }
        if length == u32::MAX as usize {
            return Ok(Err(
                "added Mach-O archive member uses 64-bit __eh_frame lengths".to_owned(),
            ));
        }
        let Some(end) = offset
            .checked_add(4)
            .and_then(|entry| entry.checked_add(length))
        else {
            return Ok(Err(
                "added Mach-O archive member __eh_frame entry length overflowed".to_owned(),
            ));
        };
        if end > data.len() || length < 4 {
            return Ok(Err(
                "added Mach-O archive member __eh_frame entry extends past the section".to_owned(),
            ));
        }
        let cie_pointer = read_u32_le(&data[offset + 4..offset + 8]).unwrap();
        entries.push((offset..end, cie_pointer));
        offset = end;
    }

    let mut cies = Vec::new();
    let mut cie_indices = HashMap::new();
    for (range, cie_pointer) in &entries {
        if *cie_pointer != 0 {
            continue;
        }
        let cie = match added_macho_archive_cie(file, data, range.clone(), &mut relocations)? {
            Ok(cie) => cie,
            Err(reason) => return Ok(Err(reason)),
        };
        cie_indices.insert(range.start, cies.len());
        cies.push(cie);
    }

    let eh_frame_position = AddedMachOArchiveUnwindSectionPosition {
        section_index: patch_section_record_index(file, section.index())?,
        section_offset: 0,
    };
    let mut fdes = Vec::new();
    for (range, cie_pointer) in entries {
        if cie_pointer == 0 {
            continue;
        }
        let cie_pointer_offset = range.start + 4;
        let Some(cie_start) = cie_pointer_offset.checked_sub(cie_pointer as usize) else {
            return Ok(Err(
                "added Mach-O archive member FDE has an invalid CIE pointer".to_owned(),
            ));
        };
        let Some(&cie_index) = cie_indices.get(&cie_start) else {
            return Ok(Err(
                "added Mach-O archive member FDE references a missing CIE".to_owned(),
            ));
        };
        let fde = match added_macho_archive_fde(
            file,
            data,
            range,
            cie_index,
            &cies[cie_index],
            &eh_frame_position,
            &mut relocations,
        )? {
            Ok(fde) => fde,
            Err(reason) => return Ok(Err(reason)),
        };
        fdes.push(fde);
    }
    if !relocations.is_empty() {
        return Ok(Err(
            "added Mach-O archive member __eh_frame has an unexpected relocation".to_owned(),
        ));
    }
    Ok(Ok(AddedMachOArchiveEhFrame {
        section_index: eh_frame_position.section_index,
        data: data.to_vec(),
        cies,
        fdes,
    }))
}

fn added_macho_archive_cie(
    file: &object::File<'_>,
    data: &[u8],
    input_range: std::ops::Range<usize>,
    relocations: &mut HashMap<usize, AddedMachOArchiveUnwindRelocation>,
) -> Result<std::result::Result<AddedMachOArchiveCie, String>> {
    let mut cursor = input_range.start + 8;
    let end = input_range.end;
    let Some(&version) = data.get(cursor) else {
        return Ok(Err(
            "added Mach-O archive member CIE version is truncated".to_owned()
        ));
    };
    cursor += 1;
    if !matches!(version, 1 | 3 | 4) {
        return Ok(Err(format!(
            "added Mach-O archive member CIE version {version} is unsupported"
        )));
    }
    let Some(augmentation_end) = data[cursor..end].iter().position(|byte| *byte == 0) else {
        return Ok(Err(
            "added Mach-O archive member CIE augmentation is unterminated".to_owned(),
        ));
    };
    let augmentation = &data[cursor..cursor + augmentation_end];
    cursor += augmentation_end + 1;
    let address_size = if version == 4 {
        let Some((&address_size, rest)) = data.get(cursor..end).and_then(|data| data.split_first())
        else {
            return Ok(Err(
                "added Mach-O archive member CIE address size is truncated".to_owned(),
            ));
        };
        cursor += 1;
        let Some(&segment_size) = rest.first() else {
            return Ok(Err(
                "added Mach-O archive member CIE segment size is truncated".to_owned(),
            ));
        };
        cursor += 1;
        if !matches!(address_size, 4 | 8) || segment_size != 0 {
            return Ok(Err(
                "added Mach-O archive member CIE address or segment size is unsupported".to_owned(),
            ));
        }
        address_size
    } else {
        8
    };
    if let Err(reason) = read_added_macho_unwind_uleb(data, &mut cursor, end) {
        return Ok(Err(reason));
    }
    if let Err(reason) = read_added_macho_unwind_sleb(data, &mut cursor, end) {
        return Ok(Err(reason));
    }
    if version == 1 {
        if data.get(cursor).is_none() {
            return Ok(Err(
                "added Mach-O archive member CIE return register is truncated".to_owned(),
            ));
        }
        cursor += 1;
    } else if let Err(reason) = read_added_macho_unwind_uleb(data, &mut cursor, end) {
        return Ok(Err(reason));
    }

    let has_fde_augmentation = augmentation.first() == Some(&b'z');
    let mut fde_pointer_encoding = DW_EH_PE_ABSPTR;
    let mut has_fde_pointer_encoding = false;
    let mut lsda_pointer_encoding = None;
    let mut personality = None;
    if has_fde_augmentation {
        let augmentation_size = match read_added_macho_unwind_uleb(data, &mut cursor, end) {
            Ok(size) => match usize::try_from(size) {
                Ok(size) => size,
                Err(_) => {
                    return Ok(Err(
                        "added Mach-O archive member CIE augmentation is too large".to_owned(),
                    ));
                }
            },
            Err(reason) => return Ok(Err(reason)),
        };
        let Some(augmentation_data_end) = cursor.checked_add(augmentation_size) else {
            return Ok(Err(
                "added Mach-O archive member CIE augmentation range overflowed".to_owned(),
            ));
        };
        if augmentation_data_end > end {
            return Ok(Err(
                "added Mach-O archive member CIE augmentation extends past the entry".to_owned(),
            ));
        }
        for &kind in &augmentation[1..] {
            match kind {
                b'L' => {
                    let Some(&encoding) = data.get(cursor) else {
                        return Ok(Err(
                            "added Mach-O archive member CIE LSDA encoding is truncated".to_owned(),
                        ));
                    };
                    cursor += 1;
                    if lsda_pointer_encoding.replace(encoding).is_some() {
                        return Ok(Err(
                            "added Mach-O archive member CIE has duplicate LSDA encodings"
                                .to_owned(),
                        ));
                    }
                    if encoding != DW_EH_PE_OMIT
                        && let Err(reason) =
                            added_macho_archive_dwarf_pointer_width(encoding, address_size)
                    {
                        return Ok(Err(reason));
                    }
                }
                b'P' => {
                    let Some(&encoding) = data.get(cursor) else {
                        return Ok(Err(
                            "added Mach-O archive member CIE personality encoding is truncated"
                                .to_owned(),
                        ));
                    };
                    cursor += 1;
                    if personality.is_some() {
                        return Ok(Err(
                            "added Mach-O archive member CIE has duplicate personalities"
                                .to_owned(),
                        ));
                    }
                    let width =
                        match added_macho_archive_dwarf_pointer_width(encoding, address_size) {
                            Ok(width) => width,
                            Err(reason) => return Ok(Err(reason)),
                        };
                    personality = match added_macho_archive_unwind_pointer_field(
                        file,
                        data,
                        relocations,
                        cursor,
                        width,
                        Some(encoding),
                        true,
                    )? {
                        Ok(Some(field)) => Some(field),
                        Ok(None) => unreachable!("required CIE personality field"),
                        Err(reason) => return Ok(Err(reason)),
                    };
                    cursor += usize::from(width);
                }
                b'R' => {
                    let Some(&encoding) = data.get(cursor) else {
                        return Ok(Err(
                            "added Mach-O archive member CIE FDE encoding is truncated".to_owned(),
                        ));
                    };
                    cursor += 1;
                    if has_fde_pointer_encoding {
                        return Ok(Err(
                            "added Mach-O archive member CIE has duplicate FDE encodings"
                                .to_owned(),
                        ));
                    }
                    if let Err(reason) =
                        added_macho_archive_dwarf_pointer_width(encoding, address_size)
                    {
                        return Ok(Err(reason));
                    }
                    fde_pointer_encoding = encoding;
                    has_fde_pointer_encoding = true;
                }
                b'S' => {}
                _ => {
                    return Ok(Err(format!(
                        "added Mach-O archive member CIE augmentation `{}` is unsupported",
                        char::from(kind)
                    )));
                }
            }
        }
        if cursor != augmentation_data_end {
            return Ok(Err(
                "added Mach-O archive member CIE augmentation size is inconsistent".to_owned(),
            ));
        }
    } else if !augmentation.is_empty() {
        return Ok(Err(
            "added Mach-O archive member CIE augmentation without `z` is unsupported".to_owned(),
        ));
    }
    Ok(Ok(AddedMachOArchiveCie {
        input_range,
        address_size,
        fde_pointer_encoding,
        lsda_pointer_encoding: lsda_pointer_encoding.filter(|encoding| *encoding != DW_EH_PE_OMIT),
        personality,
        has_fde_augmentation,
    }))
}

#[allow(clippy::too_many_arguments)]
fn added_macho_archive_fde(
    file: &object::File<'_>,
    data: &[u8],
    input_range: std::ops::Range<usize>,
    cie_index: usize,
    cie: &AddedMachOArchiveCie,
    eh_frame_position: &AddedMachOArchiveUnwindSectionPosition,
    relocations: &mut HashMap<usize, AddedMachOArchiveUnwindRelocation>,
) -> Result<std::result::Result<AddedMachOArchiveFde, String>> {
    let pc_width =
        match added_macho_archive_dwarf_pointer_width(cie.fde_pointer_encoding, cie.address_size) {
            Ok(width) => width,
            Err(reason) => return Ok(Err(reason)),
        };
    let pc_offset = input_range.start + 8;
    let pc_begin = match added_macho_archive_unwind_pointer_field(
        file,
        data,
        relocations,
        pc_offset,
        pc_width,
        Some(cie.fde_pointer_encoding),
        true,
    )? {
        Ok(Some(field)) => field,
        Ok(None) => unreachable!("required FDE PC-begin field"),
        Err(reason) => return Ok(Err(reason)),
    };
    let Some(subtractor) = added_macho_archive_unwind_subtractor(&pc_begin.relocation) else {
        return Ok(Err(
            "added Mach-O archive member FDE PC-begin relocation has no subtractor".to_owned(),
        ));
    };
    if match added_macho_archive_raw_relocation_target(file, subtractor)? {
        Ok(AddedMachOArchiveUnwindTarget::Section(position)) => position != *eh_frame_position,
        Ok(AddedMachOArchiveUnwindTarget::UndefinedSymbol(_)) | Err(_) => true,
    } {
        return Ok(Err(
            "added Mach-O archive member FDE PC-begin subtractor is unsupported".to_owned(),
        ));
    }
    let function = match added_macho_archive_unwind_pointer_position(&pc_begin, false)? {
        Ok(function) => function,
        Err(reason) => return Ok(Err(reason)),
    };
    let range_offset = pc_offset + usize::from(pc_width);
    let range_width = match added_macho_archive_dwarf_pointer_width(
        cie.fde_pointer_encoding & 0x0f,
        cie.address_size,
    ) {
        Ok(width) => width,
        Err(reason) => return Ok(Err(reason)),
    };
    let function_length = match read_added_macho_unwind_pointer(data, range_offset, range_width) {
        Some(length) => match u32::try_from(length) {
            Ok(length) if length != 0 => length,
            _ => {
                return Ok(Err(
                    "added Mach-O archive member FDE function range is invalid".to_owned(),
                ));
            }
        },
        None => {
            return Ok(Err(
                "added Mach-O archive member FDE function range is truncated".to_owned(),
            ));
        }
    };
    let mut cursor = range_offset + usize::from(range_width);
    let mut lsda = None;
    if cie.has_fde_augmentation {
        let augmentation_size =
            match read_added_macho_unwind_uleb(data, &mut cursor, input_range.end) {
                Ok(size) => match usize::try_from(size) {
                    Ok(size) => size,
                    Err(_) => {
                        return Ok(Err(
                            "added Mach-O archive member FDE augmentation is too large".to_owned(),
                        ));
                    }
                },
                Err(reason) => return Ok(Err(reason)),
            };
        let Some(augmentation_end) = cursor.checked_add(augmentation_size) else {
            return Ok(Err(
                "added Mach-O archive member FDE augmentation range overflowed".to_owned(),
            ));
        };
        if augmentation_end > input_range.end {
            return Ok(Err(
                "added Mach-O archive member FDE augmentation extends past the entry".to_owned(),
            ));
        }
        if let Some(encoding) = cie.lsda_pointer_encoding {
            let width = match added_macho_archive_dwarf_pointer_width(encoding, cie.address_size) {
                Ok(width) => width,
                Err(reason) => return Ok(Err(reason)),
            };
            lsda = match added_macho_archive_unwind_pointer_field(
                file,
                data,
                relocations,
                cursor,
                width,
                Some(encoding),
                false,
            )? {
                Ok(field) => field,
                Err(reason) => return Ok(Err(reason)),
            };
            if let Some(lsda) = &lsda {
                let Some(subtractor) = added_macho_archive_unwind_subtractor(&lsda.relocation)
                else {
                    return Ok(Err(
                        "added Mach-O archive member FDE LSDA relocation has no subtractor"
                            .to_owned(),
                    ));
                };
                if match added_macho_archive_raw_relocation_target(file, subtractor)? {
                    Ok(AddedMachOArchiveUnwindTarget::Section(position)) => {
                        position != *eh_frame_position
                    }
                    Ok(AddedMachOArchiveUnwindTarget::UndefinedSymbol(_)) | Err(_) => true,
                } {
                    return Ok(Err(
                        "added Mach-O archive member FDE LSDA subtractor is unsupported".to_owned(),
                    ));
                }
            }
            cursor += usize::from(width);
        }
        if cursor != augmentation_end {
            return Ok(Err(
                "added Mach-O archive member FDE augmentation size is inconsistent".to_owned(),
            ));
        }
    }
    Ok(Ok(AddedMachOArchiveFde {
        input_range,
        cie_index,
        function,
        function_length,
        pc_begin,
        lsda,
    }))
}

fn added_macho_archive_dwarf_pointer_width(
    encoding: u8,
    address_size: u8,
) -> std::result::Result<u8, String> {
    let width = match encoding & 0x0f {
        DW_EH_PE_ABSPTR => address_size,
        DW_EH_PE_UDATA4 | DW_EH_PE_SDATA4 => 4,
        DW_EH_PE_UDATA8 | DW_EH_PE_SDATA8 => 8,
        _ => {
            return Err(format!(
                "added Mach-O archive member uses unsupported DWARF pointer encoding {encoding:#x}"
            ));
        }
    };
    matches!(width, 4 | 8).then_some(width).ok_or_else(|| {
        format!("added Mach-O archive member uses unsupported DWARF pointer width {width}")
    })
}

fn read_added_macho_unwind_uleb(
    data: &[u8],
    cursor: &mut usize,
    end: usize,
) -> std::result::Result<u64, String> {
    let mut value = 0u64;
    for shift in (0..64).step_by(7) {
        let Some(&byte) = data.get(*cursor).filter(|_| *cursor < end) else {
            return Err("added Mach-O archive member ULEB128 value is truncated".to_owned());
        };
        *cursor += 1;
        let payload = u64::from(byte & 0x7f);
        if shift == 63 && payload > 1 {
            return Err("added Mach-O archive member ULEB128 value overflowed".to_owned());
        }
        value |= payload << shift;
        if byte & 0x80 == 0 {
            return Ok(value);
        }
    }
    Err("added Mach-O archive member ULEB128 value overflowed".to_owned())
}

fn read_added_macho_unwind_sleb(
    data: &[u8],
    cursor: &mut usize,
    end: usize,
) -> std::result::Result<i64, String> {
    let mut value = 0u64;
    for shift in (0..64).step_by(7) {
        let Some(&byte) = data.get(*cursor).filter(|_| *cursor < end) else {
            return Err("added Mach-O archive member SLEB128 value is truncated".to_owned());
        };
        *cursor += 1;
        let payload = u64::from(byte & 0x7f);
        if shift == 63 && !matches!(payload, 0 | 0x7f) {
            return Err("added Mach-O archive member SLEB128 value overflowed".to_owned());
        }
        value |= payload << shift;
        if byte & 0x80 == 0 {
            let used_bits = shift + 7;
            if used_bits < 64 && byte & 0x40 != 0 {
                value |= u64::MAX << used_bits;
            }
            return Ok(value as i64);
        }
    }
    Err("added Mach-O archive member SLEB128 value overflowed".to_owned())
}

fn added_macho_archive_unwind_relocations<'data>(
    section: &object::read::macho::MachOSection64<'data, '_, object::Endianness>,
    data: &[u8],
) -> std::result::Result<HashMap<usize, AddedMachOArchiveUnwindRelocation>, String> {
    let endian = section.macho_file().endian();
    let raw_relocations = section
        .macho_relocations()
        .map_err(|error| format!("failed to read added Mach-O unwind relocations: {error}"))?;
    let mut relocations = HashMap::new();
    let mut pending = Vec::new();
    let mut explicit_addend = 0i64;
    let mut has_explicit_addend = false;
    let mut has_subtractor = false;
    for raw in raw_relocations {
        if raw.r_scattered(endian, object::macho::CPU_TYPE_ARM64) {
            return Err(
                "added Mach-O archive member unwind uses a scattered relocation".to_owned(),
            );
        }
        let info = raw.info(endian);
        let modeled = AddedMachOArchiveRawRelocation::from(info);
        if info.r_type == object::macho::ARM64_RELOC_ADDEND {
            if has_explicit_addend {
                return Err(
                    "added Mach-O archive member unwind has multiple ADDEND relocations".to_owned(),
                );
            }
            explicit_addend = i64::from(info.r_symbolnum)
                .wrapping_shl(64 - 24)
                .wrapping_shr(64 - 24);
            has_explicit_addend = true;
            pending.push(modeled);
            continue;
        }
        if info.r_type == object::macho::ARM64_RELOC_SUBTRACTOR {
            if has_subtractor {
                return Err(
                    "added Mach-O archive member unwind has multiple SUBTRACTOR relocations"
                        .to_owned(),
                );
            }
            has_subtractor = true;
            pending.push(modeled);
            continue;
        }
        if has_subtractor && info.r_type != object::macho::ARM64_RELOC_UNSIGNED {
            return Err(
                "added Mach-O archive member unwind SUBTRACTOR is not paired with UNSIGNED"
                    .to_owned(),
            );
        }
        if pending
            .iter()
            .any(|relocation| relocation.r_address != info.r_address)
        {
            return Err(
                "added Mach-O archive member unwind relocation operation has mismatched offsets"
                    .to_owned(),
            );
        }
        if pending
            .iter()
            .any(|relocation| relocation.r_length != info.r_length)
        {
            return Err(
                "added Mach-O archive member unwind relocation operation has mismatched widths"
                    .to_owned(),
            );
        }
        if has_subtractor {
            let subtractor = pending
                .iter()
                .find(|relocation| relocation.r_type == object::macho::ARM64_RELOC_SUBTRACTOR)
                .expect("tracked SUBTRACTOR relocation");
            if subtractor.r_pcrel || info.r_pcrel {
                return Err(
                    "added Mach-O archive member unwind SUBTRACTOR/UNSIGNED pair is PC-relative"
                        .to_owned(),
                );
            }
            if !subtractor.r_extern {
                return Err(
                    "added Mach-O archive member unwind SUBTRACTOR relocation is not external"
                        .to_owned(),
                );
            }
        }
        let input_offset = info.r_address as usize;
        let Some(width) = 1usize.checked_shl(u32::from(info.r_length)) else {
            return Err("added Mach-O archive member unwind relocation size is invalid".to_owned());
        };
        if input_offset
            .checked_add(width)
            .is_none_or(|end| end > data.len())
        {
            return Err(
                "added Mach-O archive member unwind relocation is outside its section".to_owned(),
            );
        }
        let Some(field_value) = read_added_macho_unwind_pointer(data, input_offset, width as u8)
        else {
            return Err(
                "added Mach-O archive member unwind relocation field is truncated".to_owned(),
            );
        };
        pending.push(modeled);
        let relocation = AddedMachOArchiveUnwindRelocation {
            input_offset,
            width: width as u8,
            explicit_addend,
            field_value,
            raw: std::mem::take(&mut pending),
            subtractor_target: None,
        };
        if relocations.insert(input_offset, relocation).is_some() {
            return Err(
                "added Mach-O archive member unwind relocation offset is ambiguous".to_owned(),
            );
        }
        explicit_addend = 0;
        has_explicit_addend = false;
        has_subtractor = false;
    }
    if !pending.is_empty() {
        return Err(
            "added Mach-O archive member unwind ends with an incomplete relocation operation"
                .to_owned(),
        );
    }
    Ok(relocations)
}

impl From<object::macho::RelocationInfo> for AddedMachOArchiveRawRelocation {
    fn from(info: object::macho::RelocationInfo) -> Self {
        Self {
            r_address: info.r_address,
            r_symbolnum: info.r_symbolnum,
            r_pcrel: info.r_pcrel,
            r_length: info.r_length,
            r_extern: info.r_extern,
            r_type: info.r_type,
        }
    }
}

fn added_macho_archive_unwind_pointer_field(
    file: &object::File<'_>,
    data: &[u8],
    relocations: &mut HashMap<usize, AddedMachOArchiveUnwindRelocation>,
    input_offset: usize,
    width: u8,
    encoding: Option<u8>,
    required: bool,
) -> Result<std::result::Result<Option<AddedMachOArchiveUnwindPointerField>, String>> {
    let Some(value) = read_added_macho_unwind_pointer(data, input_offset, width) else {
        return Ok(Err(
            "added Mach-O archive member unwind pointer field is truncated".to_owned(),
        ));
    };
    let relocation = relocations.remove(&input_offset);
    let Some(relocation) = relocation else {
        if !required && value == 0 {
            return Ok(Ok(None));
        }
        return Ok(Err(
            "added Mach-O archive member unwind pointer field has no relocation".to_owned(),
        ));
    };
    if relocation.width != width {
        return Ok(Err(format!(
            "added Mach-O archive member unwind pointer width {width} does not match relocation width {}",
            relocation.width
        )));
    }
    let Some(primary) = relocation.raw.last() else {
        return Ok(Err(
            "added Mach-O archive member unwind relocation operation is empty".to_owned(),
        ));
    };
    let target = match added_macho_archive_raw_relocation_target(file, primary)? {
        Ok(target) => target,
        Err(reason) => return Ok(Err(reason)),
    };
    let subtractor_target =
        if let Some(subtractor) = added_macho_archive_unwind_subtractor(&relocation) {
            match added_macho_archive_raw_relocation_target(file, subtractor)? {
                Ok(target) => Some(target),
                Err(reason) => return Ok(Err(reason)),
            }
        } else {
            None
        };
    Ok(Ok(Some(AddedMachOArchiveUnwindPointerField {
        input_offset,
        width,
        encoding,
        value,
        target,
        relocation: AddedMachOArchiveUnwindRelocation {
            subtractor_target,
            ..relocation
        },
    })))
}

fn added_macho_archive_unwind_subtractor(
    relocation: &AddedMachOArchiveUnwindRelocation,
) -> Option<&AddedMachOArchiveRawRelocation> {
    relocation
        .raw
        .iter()
        .find(|raw| raw.r_type == object::macho::ARM64_RELOC_SUBTRACTOR)
}

fn added_macho_archive_raw_relocation_target(
    file: &object::File<'_>,
    relocation: &AddedMachOArchiveRawRelocation,
) -> Result<std::result::Result<AddedMachOArchiveUnwindTarget, String>> {
    if relocation.r_type == object::macho::ARM64_RELOC_ADDEND {
        return Ok(Err(
            "added Mach-O archive member ADDEND relocation has no target".to_owned(),
        ));
    }
    if relocation.r_extern {
        let symbol = file.symbol_by_index(object::SymbolIndex(relocation.r_symbolnum as usize))?;
        if let Some(section_index) = symbol.section_index() {
            let section = file.section_by_index(section_index)?;
            Ok(Ok(AddedMachOArchiveUnwindTarget::Section(
                AddedMachOArchiveUnwindSectionPosition {
                    section_index: patch_section_record_index(file, section_index)?,
                    section_offset: symbol
                        .address()
                        .checked_sub(section.address())
                        .context("Added Mach-O unwind symbol precedes its section")?,
                },
            )))
        } else if symbol.is_undefined()
            && symbol.is_global()
            && !symbol.is_weak()
            && !symbol.name_bytes()?.is_empty()
        {
            Ok(Ok(AddedMachOArchiveUnwindTarget::UndefinedSymbol(
                symbol.name_bytes()?.to_vec(),
            )))
        } else {
            Ok(Err(
                "added Mach-O archive member unwind target symbol is unsupported".to_owned(),
            ))
        }
    } else {
        let section_index = object::SectionIndex(relocation.r_symbolnum as usize);
        file.section_by_index(section_index)?;
        Ok(Ok(AddedMachOArchiveUnwindTarget::Section(
            AddedMachOArchiveUnwindSectionPosition {
                section_index: patch_section_record_index(file, section_index)?,
                section_offset: 0,
            },
        )))
    }
}

fn added_macho_archive_unwind_pointer_position(
    field: &AddedMachOArchiveUnwindPointerField,
    include_field_value: bool,
) -> Result<std::result::Result<AddedMachOArchiveUnwindSectionPosition, String>> {
    let AddedMachOArchiveUnwindTarget::Section(target) = &field.target else {
        return Ok(Err(
            "added Mach-O archive member unwind function target is not section-defined".to_owned(),
        ));
    };
    let mut delta = i128::from(field.relocation.explicit_addend);
    if include_field_value {
        delta += i128::from(field.value);
    }
    let Some(section_offset) = add_signed_delta_u64(target.section_offset, delta) else {
        return Ok(Err(
            "added Mach-O archive member unwind function offset overflowed".to_owned(),
        ));
    };
    Ok(Ok(AddedMachOArchiveUnwindSectionPosition {
        section_index: target.section_index,
        section_offset,
    }))
}

fn read_added_macho_unwind_pointer(data: &[u8], offset: usize, width: u8) -> Option<u64> {
    match width {
        4 => data
            .get(offset..offset + 4)
            .and_then(read_u32_le)
            .map(u64::from),
        8 => data.get(offset..offset + 8).and_then(read_u64_le),
        _ => None,
    }
}

fn added_macho_archive_text_member(
    input_file_path: &str,
    added_member: PatchInputBytes<'_>,
    other_members: &[&[u8]],
    resolutions: &[MachOSymbolResolutionRecord],
    retiring_names: &[SharedText],
) -> Result<std::result::Result<AddedMachOArchiveTextMember, String>> {
    let file = object::File::parse(added_member.bytes)
        .context("Failed to parse added Mach-O text archive member")?;
    if !is_supported_incremental_macho_object(&file) {
        return Ok(Err(
            "added Mach-O text archive member is not a supported arm64 object".to_owned(),
        ));
    }
    let unwind = match added_macho_archive_unwind(&file)? {
        Ok(unwind) => unwind,
        Err(reason) => return Ok(Err(reason)),
    };
    let unwind_section_indices = unwind
        .as_ref()
        .into_iter()
        .flat_map(|unwind| {
            unwind
                .compact_unwind
                .iter()
                .map(|section| section.section_index)
                .chain(unwind.eh_frame.iter().map(|section| section.section_index))
        })
        .collect::<HashSet<_>>();

    let mut text_section_index = None;
    let mut allocated_sections = Vec::new();
    let mut allocated_section_indices = HashSet::new();
    let mut ignored_debug_section_indices = HashSet::new();
    for section in file.sections() {
        let section_index = patch_section_record_index(&file, section.index())?;
        if unwind_section_indices.contains(&section_index) {
            ignored_debug_section_indices.insert(section.index());
            continue;
        }
        let segment_name = section.segment_name_bytes().ok().flatten();
        let section_name = section.name_bytes().ok();
        let object::SectionFlags::MachO { flags } = section.flags() else {
            return Ok(Err(
                "added Mach-O text archive member has a non-Mach-O section".to_owned(),
            ));
        };
        if let (Some(segment_name), Some(section_name)) = (segment_name, section_name)
            && let Some(output_section_id) =
                added_macho_archive_output_section_id(segment_name, section_name, flags)
        {
            if section_name == b"__text" {
                if text_section_index.replace(section.index()).is_some() {
                    return Ok(Err(
                        "added Mach-O archive member has multiple text sections".to_owned(),
                    ));
                }
            }
            let data = section
                .data()
                .context("Failed to read added Mach-O archive member section")?;
            if data.is_empty() {
                continue;
            }
            let relocations = if section.relocations().next().is_none() {
                Vec::new()
            } else if segment_name == b"__DATA" && section_name == b"__const" {
                let Some(relocations) =
                    macho_aarch64_data_relocation_contexts(&file, &section, data)
                else {
                    return Ok(Err(
                        "added Mach-O archive member has unsupported __DATA,__const relocations"
                            .to_owned(),
                    ));
                };
                relocations
            } else if section_name == b"__text" {
                Vec::new()
            } else {
                return Ok(Err(
                    "added Mach-O archive member has unsupported auxiliary section relocations"
                        .to_owned(),
                ));
            };
            let alignment = crate::alignment::Alignment::new(section.align().max(1))
                .context("Invalid added Mach-O archive member section alignment")?;
            let data_size = u64::try_from(data.len())
                .context("Added Mach-O archive member section is too large")?;
            allocated_section_indices.insert(section.index());
            allocated_sections.push(AddedMachOArchiveSection {
                section_index,
                section_name: format!(
                    "{},{}",
                    String::from_utf8_lossy(segment_name),
                    String::from_utf8_lossy(section_name)
                ),
                output_section_id: u32::try_from(output_section_id.as_usize())
                    .context("Mach-O output section ID does not fit u32")?,
                data_hash: hash_bytes(data),
                data_size,
                alignment_exponent: alignment.exponent,
                relocations,
            });
        } else if segment_name.is_some_and(|name| name.starts_with(b"__DWARF"))
            || flags & object::macho::S_ATTR_DEBUG != 0
        {
            ignored_debug_section_indices.insert(section.index());
        } else {
            return Ok(Err(
                "added Mach-O archive member has another allocated section".to_owned(),
            ));
        }
    }
    let Some(text_section_index) = text_section_index else {
        return Ok(Err(
            "added Mach-O archive member has no regular __TEXT,__text section".to_owned(),
        ));
    };
    let text = file.section_by_index(text_section_index)?;
    let data = text
        .data()
        .context("Failed to read added Mach-O archive member text")?;
    if data.is_empty() {
        return Ok(Err("added Mach-O archive member text is empty".to_owned()));
    }
    let Some(contexts) = macho_aarch64_text_relocation_contexts(&file, &text, data) else {
        return Ok(Err(
            "added Mach-O archive member contains unsupported text relocations".to_owned(),
        ));
    };

    let mut definitions = Vec::new();
    for symbol in file.symbols() {
        let name = symbol.name_bytes()?;
        if symbol.is_undefined() {
            if !symbol.is_global() || symbol.is_weak() || name.is_empty() {
                return Ok(Err(
                    "added Mach-O archive member has unsupported undefined symbols".to_owned(),
                ));
            }
            continue;
        }
        if symbol.section_index().is_some_and(|section_index| {
            !allocated_section_indices.contains(&section_index)
                && !ignored_debug_section_indices.contains(&section_index)
        }) {
            return Ok(Err(
                "added Mach-O archive member defines a symbol outside supported sections"
                    .to_owned(),
            ));
        }
        if symbol.is_global() {
            let object::SymbolFlags::MachO { n_desc } = symbol.flags() else {
                return Ok(Err(
                    "added Mach-O archive member definition has non-Mach-O flags".to_owned(),
                ));
            };
            if symbol.section_index() != Some(text.index()) || symbol.is_weak() || name.is_empty() {
                return Ok(Err(
                    "added Mach-O archive member has an unsupported strong global definition"
                        .to_owned(),
                ));
            }
            definitions.push((
                name.to_vec(),
                symbol.address(),
                n_desc,
                symbol.scope() == object::SymbolScope::Linkage,
            ));
        } else if symbol.scope() != object::SymbolScope::Compilation || symbol.is_weak() {
            return Ok(Err(
                "added Mach-O archive member has unsupported local symbols".to_owned(),
            ));
        }
    }
    if definitions.is_empty() {
        return Ok(Err(
            "added Mach-O archive member has no strong global definition".to_owned(),
        ));
    }
    definitions.sort_by(|left, right| left.0.cmp(&right.0));
    if definitions.windows(2).any(|pair| pair[0].0 == pair[1].0) {
        return Ok(Err(
            "added Mach-O archive member definition is ambiguous".to_owned()
        ));
    }

    let data_size =
        u64::try_from(data.len()).context("Added Mach-O archive member text is too large")?;
    let mut parsed_definitions = Vec::with_capacity(definitions.len());
    for (name, address, desc, private_external) in definitions {
        let encoded_name = hex::encode(&name);
        if resolutions
            .iter()
            .any(|resolution| resolution.name.as_str() == encoded_name)
            && !retiring_names
                .iter()
                .any(|retiring| retiring.as_str() == encoded_name)
        {
            return Ok(Err(
                "added Mach-O archive member definition already has a resolution".to_owned(),
            ));
        }
        for member in other_members {
            let Ok(other) = object::File::parse(*member) else {
                continue;
            };
            if other.symbols().any(|symbol| {
                symbol.is_global()
                    && !symbol.is_undefined()
                    && symbol
                        .name_bytes()
                        .is_ok_and(|candidate| candidate == name.as_slice())
            }) {
                return Ok(Err(
                    "added Mach-O archive member definition is not unique".to_owned()
                ));
            }
        }
        let offset = address
            .checked_sub(text.address())
            .context("Added Mach-O archive member definition precedes __text")?;
        if offset >= data_size {
            return Ok(Err(
                "added Mach-O archive member definition is outside __text".to_owned(),
            ));
        }
        parsed_definitions.push(AddedMachOArchiveDefinition {
            name,
            offset,
            desc,
            private_external,
        });
    }
    let current_input_ref =
        resolved_patch_input_ref(input_file_path, input_file_path, added_member)?;
    let section_index = patch_section_record_index(&file, text.index())?;
    let text_object_section_index = relocation_target_record_index(text.index())?;
    let mut referenced_names = Vec::new();
    for context in contexts {
        let object::RelocationTarget::Symbol(symbol_index) = context.target else {
            continue;
        };
        let symbol = file.symbol_by_index(symbol_index)?;
        if symbol.is_undefined() {
            referenced_names.push(symbol.name_bytes()?.to_vec());
        }
    }
    referenced_names.sort_unstable();
    referenced_names.dedup();
    allocated_sections.sort_by_key(|section| section.section_index);
    Ok(Ok(AddedMachOArchiveTextMember {
        input: current_input_ref,
        sections: allocated_sections,
        unwind,
        text_section_index: section_index,
        text_object_section_index,
        definitions: parsed_definitions,
        referenced_names,
    }))
}

fn added_macho_archive_seed_references(
    input_file_path: &str,
    matched_sections: &[MatchedPatchSection],
    current_resolver: &PatchInputResolver<'_>,
    definitions: &HashMap<Vec<u8>, usize>,
) -> Result<std::result::Result<Vec<Vec<u8>>, String>> {
    let mut references = Vec::new();
    for matched in matched_sections {
        let Some(input_bytes) = current_resolver.resolve(
            input_file_path,
            matched.current.input.as_str(),
            PatchInputLookup::MatchArchiveMember,
        )?
        else {
            return Ok(Err(
                "could not resolve changed Mach-O archive member for selection".to_owned(),
            ));
        };
        let file = object::File::parse(input_bytes.bytes)
            .context("Failed to parse changed Mach-O archive member for selection")?;
        if !is_supported_incremental_macho_object(&file) {
            continue;
        }
        let Some(section_index) = patch_section_index(&file, &matched.current)? else {
            continue;
        };
        let section = file.section_by_index(section_index)?;
        if section.name_bytes().ok() != Some(b"__text".as_slice()) {
            continue;
        }
        for (_, relocation) in section.relocations() {
            let object::RelocationTarget::Symbol(symbol_index) = relocation.target() else {
                continue;
            };
            let symbol = file.symbol_by_index(symbol_index)?;
            if symbol.is_undefined()
                && symbol.is_global()
                && let Ok(name) = symbol.name_bytes()
                && definitions.contains_key(name)
            {
                references.push(name.to_vec());
            }
        }
    }
    references.sort_unstable();
    references.dedup();
    Ok(Ok(references))
}

fn selected_added_macho_archive_member_indices(
    members: &[AddedMachOArchiveTextMember],
    definitions: &HashMap<Vec<u8>, usize>,
    seed_references: Vec<Vec<u8>>,
) -> Vec<usize> {
    let mut pending = seed_references;
    let mut selected = HashSet::new();
    while let Some(reference) = pending.pop() {
        let Some(&member_index) = definitions.get(&reference) else {
            continue;
        };
        if selected.insert(member_index) {
            pending.extend(members[member_index].referenced_names.iter().cloned());
        }
    }
    let mut selected = selected.into_iter().collect::<Vec<_>>();
    selected.sort_unstable();
    selected
}

fn added_macho_archive_text_relocation_replays(
    current_bytes: &[u8],
    input_file_path: &str,
    members: &[AddedMachOArchiveTextMember],
    selected_indices: &[usize],
    sections: &[PatchSection],
    previous_output: &[u8],
    relocations: &[RelocationRecord],
    resolutions: &[MachOSymbolResolutionRecord],
) -> Result<std::result::Result<Vec<MachOTextRelocationReplay>, String>> {
    let resolver = PatchInputResolver::new(current_bytes, true)?;
    let resolution_lookup = MachOSymbolResolutionLookup::new(resolutions);
    let output_file = object::File::parse(previous_output)
        .context("Failed to parse previous Mach-O output for added text relocations")?;
    let mut replays = Vec::new();
    for &member_index in selected_indices {
        let member = &members[member_index];
        let Some(input_bytes) = resolver.resolve(
            input_file_path,
            member.input.as_str(),
            PatchInputLookup::MatchArchiveMember,
        )?
        else {
            return Ok(Err(
                "could not resolve added Mach-O archive member for relocation replay".to_owned(),
            ));
        };
        let file = object::File::parse(input_bytes.bytes)
            .context("Failed to parse added Mach-O archive member for relocation replay")?;
        let section_index = patch_section_object_index(&file, member.text_section_index)?;
        let section = file.section_by_index(section_index)?;
        let data = section.data()?;
        let Some(contexts) = macho_aarch64_text_relocation_contexts(&file, &section, data) else {
            return Ok(Err(
                "added Mach-O archive member contains unsupported text relocations".to_owned(),
            ));
        };
        for context in contexts {
            if context.subtractor.is_some() {
                return Ok(Err(
                    "added Mach-O archive member contains a subtractor relocation".to_owned(),
                ));
            }
            let raw_relocation = object::macho::RelocationInfo {
                r_address: 0,
                r_symbolnum: 0,
                r_pcrel: context.r_pcrel,
                r_length: 2,
                r_extern: matches!(context.target, object::RelocationTarget::Symbol(_)),
                r_type: context.r_type,
            };
            let rel_info =
                <crate::macho_aarch64::MachOAArch64 as crate::platform::Arch>::relocation_from_raw(
                    raw_relocation,
                )
                .map_err(|error| {
                    crate::error!("Failed to decode added Mach-O text relocation: {error:#?}")
                })?;
            let mut target_name = None;
            let mut target_is_global = false;
            let mut recorded_target_candidates = Vec::new();
            let target;
            let current_target_value = match context.target {
                object::RelocationTarget::Symbol(symbol_index) => {
                    let symbol = file.symbol_by_index(symbol_index)?;
                    let name = symbol.name_bytes()?.to_vec();
                    if !name.is_empty() {
                        target_name = Some(SharedText::from(hex::encode(&name)));
                        target_is_global = symbol.is_global();
                    }
                    if let Some(target_section_index) = symbol.section_index() {
                        let target_section_record_index =
                            patch_section_record_index(&file, target_section_index)?;
                        let Some(target_patch_section) = sections.iter().find(|section| {
                            section.input == member.input
                                && section.section_index == target_section_record_index
                        }) else {
                            return Ok(Err(
                                "added Mach-O text relocation targets an unallocated local section"
                                    .to_owned(),
                            ));
                        };
                        let target_section = file.section_by_index(target_section_index)?;
                        let target_offset = symbol
                            .address()
                            .checked_sub(target_section.address())
                            .context("Added Mach-O text relocation target precedes its section")?;
                        target = Some(RelocationTargetRecord {
                            input_file: input_file_path.into(),
                            input: member.input.clone().into(),
                            section_index: relocation_target_record_index(target_section_index)?,
                            section_offset: target_offset,
                        });
                        let Some(target_section_address) = macho_output_address_for_file_offset(
                            &output_file,
                            target_patch_section.output_offset,
                        ) else {
                            return Ok(Err(
                                "added Mach-O text relocation target has no output address"
                                    .to_owned(),
                            ));
                        };
                        target_section_address
                            .checked_add(target_offset)
                            .context("Added Mach-O text relocation target address overflow")?
                    } else {
                        let encoded_name = hex::encode(&name);
                        let resolution_index = match macho_symbol_resolution_index_for_name(
                            resolutions,
                            &encoded_name,
                        ) {
                            Ok(index) => index,
                            Err(reason) => return Ok(Err(reason)),
                        };
                        if let Some(resolution_index) = resolution_index {
                            let resolution = &resolutions[resolution_index];
                            let Some(value) = resolution.direct_value else {
                                return Ok(Err(
                                    "added Mach-O text relocation target has no direct value"
                                        .to_owned(),
                                ));
                            };
                            target = resolution.target.clone();
                            value
                        } else if symbol.is_undefined()
                            && symbol.is_global()
                            && symbol.address() == 0
                            && context.r_type == object::macho::ARM64_RELOC_BRANCH26
                            && context.r_pcrel
                            && let Some(encoded_name) = target_name.as_ref()
                        {
                            recorded_target_candidates = recorded_macho_import_stub_candidates(
                                relocations,
                                encoded_name,
                                context.addend,
                                previous_output,
                                &output_file,
                            );
                            if recorded_target_candidates.is_empty() {
                                return Ok(Err(format!(
                                    "missing Mach-O symbol resolution for added archive member {}",
                                    display_hex_text(&encoded_name)
                                )));
                            }
                            target = None;
                            0
                        } else {
                            return Ok(Err(format!(
                                "missing Mach-O symbol resolution for added archive member {}",
                                display_hex_text(&encoded_name)
                            )));
                        }
                    }
                }
                object::RelocationTarget::Section(target_section_index) => {
                    let target_section_record_index =
                        patch_section_record_index(&file, target_section_index)?;
                    let Some(target_patch_section) = sections.iter().find(|section| {
                        section.input == member.input
                            && section.section_index == target_section_record_index
                    }) else {
                        return Ok(Err(
                            "added Mach-O text relocation targets an unallocated local section"
                                .to_owned(),
                        ));
                    };
                    target = Some(RelocationTargetRecord {
                        input_file: input_file_path.into(),
                        input: member.input.clone().into(),
                        section_index: relocation_target_record_index(target_section_index)?,
                        section_offset: 0,
                    });
                    macho_output_address_for_file_offset(
                        &output_file,
                        target_patch_section.output_offset,
                    )
                    .context("Added Mach-O text relocation target has no output address")?
                }
                _ => {
                    return Ok(Err(
                        "unsupported added Mach-O text relocation target".to_owned()
                    ));
                }
            };
            let current_relocation_target_candidates = macho_text_relocation_target_candidates(
                resolutions,
                &resolution_lookup,
                target_name.as_deref(),
                context.r_type,
                current_target_value,
                &recorded_target_candidates,
            );
            let target_symbol_id = relocations
                .iter()
                .find(|relocation| {
                    relocation.target_name == target_name && relocation.target == target
                })
                .map_or(0, |relocation| relocation.target_symbol_id);
            replays.push(MachOTextRelocationReplay {
                relocation_index: None,
                input_file: input_file_path.into(),
                input: member.input.clone(),
                section_index: member.text_section_index,
                previous_output_offset: None,
                previous_range: None,
                current_range: context.range,
                r_type: context.r_type,
                kind: encode_macho_aarch64_relocation_kind(raw_relocation),
                rel_info,
                previous_written_value: None,
                previous_applied_target_value: None,
                current_target_value,
                current_relocation_target_candidates,
                current_target_section_offset: target
                    .as_ref()
                    .map_or(0, |target| target.section_offset),
                target_symbol_id,
                target_name,
                target_is_global,
                target,
                addend: context.addend,
                chained_rebase_output_offset: None,
                chained_rebase_value: None,
            });
        }

        for source_section in &member.sections {
            if source_section.relocations.is_empty() {
                continue;
            }
            let section_index = patch_section_object_index(&file, source_section.section_index)?;
            let Some(source_patch_section) = sections.iter().find(|section| {
                section.input == member.input
                    && section.section_index == source_section.section_index
            }) else {
                return Ok(Err(
                    "added Mach-O data relocation source section was not allocated".to_owned(),
                ));
            };
            for context in &source_section.relocations {
                let raw_relocation = object::macho::RelocationInfo {
                    r_address: 0,
                    r_symbolnum: 0,
                    r_pcrel: false,
                    r_length: 3,
                    r_extern: matches!(context.target, object::RelocationTarget::Symbol(_)),
                    r_type: object::macho::ARM64_RELOC_UNSIGNED,
                };
                let rel_info = <crate::macho_aarch64::MachOAArch64 as crate::platform::Arch>::
                    relocation_from_raw(raw_relocation)
                    .map_err(|error| {
                        crate::error!(
                            "Failed to decode added Mach-O data relocation: {error:#?}"
                        )
                    })?;
                let mut target_name = None;
                let mut target_is_global = false;
                let target;
                let current_target_value = match context.target {
                    object::RelocationTarget::Symbol(symbol_index) => {
                        let symbol = file.symbol_by_index(symbol_index)?;
                        let Some(target_section_index) = symbol.section_index() else {
                            return Ok(Err(
                                "added Mach-O data relocation targets a non-local symbol"
                                    .to_owned(),
                            ));
                        };
                        let name = symbol.name_bytes()?.to_vec();
                        if !name.is_empty() {
                            target_name = Some(SharedText::from(hex::encode(&name)));
                            target_is_global = symbol.is_global();
                        }
                        let target_section_record_index =
                            patch_section_record_index(&file, target_section_index)?;
                        let Some(target_patch_section) = sections.iter().find(|section| {
                            section.input == member.input
                                && section.section_index == target_section_record_index
                        }) else {
                            return Ok(Err(
                                "added Mach-O data relocation targets an unallocated local section"
                                    .to_owned(),
                            ));
                        };
                        let target_section = file.section_by_index(target_section_index)?;
                        let target_offset = symbol
                            .address()
                            .checked_sub(target_section.address())
                            .context("Added Mach-O data relocation target precedes its section")?;
                        target = Some(RelocationTargetRecord {
                            input_file: input_file_path.into(),
                            input: member.input.clone().into(),
                            section_index: relocation_target_record_index(target_section_index)?,
                            section_offset: target_offset,
                        });
                        let Some(target_section_address) = macho_output_address_for_file_offset(
                            &output_file,
                            target_patch_section.output_offset,
                        ) else {
                            return Ok(Err(
                                "added Mach-O data relocation target has no output address"
                                    .to_owned(),
                            ));
                        };
                        target_section_address
                            .checked_add(target_offset)
                            .context("Added Mach-O data relocation target address overflow")?
                    }
                    object::RelocationTarget::Section(target_section_index) => {
                        let target_section_record_index =
                            patch_section_record_index(&file, target_section_index)?;
                        let Some(target_patch_section) = sections.iter().find(|section| {
                            section.input == member.input
                                && section.section_index == target_section_record_index
                        }) else {
                            return Ok(Err(
                                "added Mach-O data relocation targets an unallocated local section"
                                    .to_owned(),
                            ));
                        };
                        target = Some(RelocationTargetRecord {
                            input_file: input_file_path.into(),
                            input: member.input.clone().into(),
                            section_index: relocation_target_record_index(target_section_index)?,
                            section_offset: 0,
                        });
                        macho_output_address_for_file_offset(
                            &output_file,
                            target_patch_section.output_offset,
                        )
                        .context("Added Mach-O data relocation target has no output address")?
                    }
                    _ => {
                        return Ok(Err(
                            "unsupported added Mach-O data relocation target".to_owned()
                        ));
                    }
                };
                let output_offset = source_patch_section
                    .output_offset
                    .checked_add(context.range.start as u64)
                    .context("Added Mach-O data relocation output offset overflow")?;
                replays.push(MachOTextRelocationReplay {
                    relocation_index: None,
                    input_file: input_file_path.into(),
                    input: member.input.clone(),
                    section_index: source_section.section_index,
                    previous_output_offset: None,
                    previous_range: None,
                    current_range: context.range.clone(),
                    r_type: object::macho::ARM64_RELOC_UNSIGNED,
                    kind: encode_macho_aarch64_relocation_kind(raw_relocation),
                    rel_info,
                    previous_written_value: None,
                    previous_applied_target_value: None,
                    current_target_value,
                    current_relocation_target_candidates: vec![current_target_value],
                    current_target_section_offset: target
                        .as_ref()
                        .map_or(0, |target| target.section_offset),
                    target_symbol_id: 0,
                    target_name,
                    target_is_global,
                    target,
                    addend: context.addend,
                    chained_rebase_output_offset: Some(output_offset),
                    chained_rebase_value: None,
                });
            }
            debug_assert_eq!(
                patch_section_object_index(&file, source_section.section_index)?,
                section_index
            );
        }
    }
    Ok(Ok(replays))
}

fn is_supported_incremental_macho_object(file: &object::File<'_>) -> bool {
    file.format() == object::BinaryFormat::MachO
        && file.kind() == object::ObjectKind::Relocatable
        && file.architecture() == object::Architecture::Aarch64
        && file.is_64()
        && file.is_little_endian()
}

fn hash_length_prefixed(hasher: &mut blake3::Hasher, bytes: &[u8]) {
    hasher.update(&(bytes.len() as u64).to_le_bytes());
    hasher.update(bytes);
}

fn hash_macho_relocation_target(
    hasher: &mut blake3::Hasher,
    target: object::RelocationTarget,
) -> Option<()> {
    match target {
        object::RelocationTarget::Symbol(symbol) => {
            hasher.update(&[0]);
            hasher.update(&(symbol.0 as u64).to_le_bytes());
        }
        object::RelocationTarget::Section(section) => {
            hasher.update(&[1]);
            hasher.update(&(section.0 as u64).to_le_bytes());
        }
        object::RelocationTarget::Absolute => {
            hasher.update(&[2]);
        }
        _ => return None,
    }
    Some(())
}

fn hash_macho_semantic_relocation_target(
    hasher: &mut blake3::Hasher,
    file: &object::File<'_>,
    target: object::RelocationTarget,
) -> Option<()> {
    match target {
        object::RelocationTarget::Symbol(symbol) => {
            hasher.update(&[0]);
            hash_macho_relocation_symbol(hasher, file, symbol)?;
        }
        object::RelocationTarget::Section(section) => {
            hasher.update(&[1]);
            let section = file.section_by_index(section).ok()?;
            hash_length_prefixed(hasher, section.segment_name_bytes().ok().flatten()?);
            hash_length_prefixed(hasher, section.name_bytes().ok()?);
        }
        object::RelocationTarget::Absolute => {
            hasher.update(&[2]);
        }
        _ => return None,
    }
    Some(())
}

fn hash_macho_relocation_symbol(
    hasher: &mut blake3::Hasher,
    file: &object::File<'_>,
    symbol_index: object::SymbolIndex,
) -> Option<()> {
    let symbol = file.symbol_by_index(symbol_index).ok()?;
    hash_length_prefixed(hasher, symbol.name_bytes().ok()?);
    hash_macho_symbol_section(hasher, symbol.section())?;
    let address = if let Some(section_index) = symbol.section_index() {
        symbol
            .address()
            .checked_sub(file.section_by_index(section_index).ok()?.address())?
    } else {
        symbol.address()
    };
    hasher.update(&address.to_le_bytes());
    hasher.update(&symbol.size().to_le_bytes());
    hasher.update(&[
        macho_symbol_kind_tag(symbol.kind())?,
        macho_symbol_scope_tag(symbol.scope()),
        u8::from(symbol.is_weak()),
    ]);
    let object::SymbolFlags::MachO { n_desc } = symbol.flags() else {
        return None;
    };
    hasher.update(&n_desc.to_le_bytes());
    Some(())
}

fn hash_macho_symbol_section(
    hasher: &mut blake3::Hasher,
    section: object::SymbolSection,
) -> Option<()> {
    match section {
        object::SymbolSection::Unknown => {
            hasher.update(&[0]);
        }
        object::SymbolSection::None => {
            hasher.update(&[1]);
        }
        object::SymbolSection::Undefined => {
            hasher.update(&[2]);
        }
        object::SymbolSection::Absolute => {
            hasher.update(&[3]);
        }
        object::SymbolSection::Common => {
            hasher.update(&[4]);
        }
        object::SymbolSection::Section(section) => {
            hasher.update(&[5]);
            hasher.update(&(section.0 as u64).to_le_bytes());
        }
        _ => return None,
    }
    Some(())
}

fn macho_symbol_kind_tag(kind: object::SymbolKind) -> Option<u8> {
    Some(match kind {
        object::SymbolKind::Unknown => 0,
        object::SymbolKind::Text => 1,
        object::SymbolKind::Data => 2,
        object::SymbolKind::Section => 3,
        object::SymbolKind::File => 4,
        object::SymbolKind::Label => 5,
        object::SymbolKind::Tls => 6,
        _ => return None,
    })
}

fn macho_symbol_scope_tag(scope: object::SymbolScope) -> u8 {
    match scope {
        object::SymbolScope::Unknown => 0,
        object::SymbolScope::Compilation => 1,
        object::SymbolScope::Linkage => 2,
        object::SymbolScope::Dynamic => 3,
    }
}

fn archive_member_patch_ranges_hash(
    data_offset: usize,
    data_len: usize,
    ranges: &[std::ops::Range<usize>],
) -> String {
    let data_end = data_offset + data_len;
    let mut hasher = blake3::Hasher::new();
    hasher.update(b"sld-archive-member-patch-ranges-v1");
    for range in ranges {
        if range.end <= data_offset || range.start >= data_end {
            continue;
        }
        let start = range.start.max(data_offset) - data_offset;
        let end = range.end.min(data_end) - data_offset;
        hasher.update(&(start as u64).to_le_bytes());
        hasher.update(&(end as u64).to_le_bytes());
    }
    hasher.finalize().to_hex().to_string()
}

fn update_hash_with_ranges(
    hasher: &mut blake3::Hasher,
    bytes: &[u8],
    data_offset: usize,
    ranges: &[std::ops::Range<usize>],
) {
    let data_end = data_offset + bytes.len();
    let mut position = 0;
    for range in ranges {
        if range.end <= data_offset || range.start >= data_end {
            continue;
        }
        let start = range.start.max(data_offset) - data_offset;
        let end = range.end.min(data_end) - data_offset;
        hasher.update(&bytes[position..start]);
        update_hash_with_zeroes(hasher, end - start);
        position = end;
    }
    hasher.update(&bytes[position..]);
}

fn patch_fingerprint_matches_previous_without_extra_ranges(
    previous_bytes: &[u8],
    current_fingerprint: &str,
    input_file_path: &str,
    matched_sections: &[MatchedPatchSection],
    normalize_rust_archive_patch_inputs: bool,
) -> Result<bool> {
    Ok(patch_fingerprint_with_extra_ranges_mode(
        previous_bytes,
        input_file_path,
        matched_sections
            .iter()
            .map(|section| section.previous.clone()),
        std::iter::empty(),
        normalize_rust_archive_patch_inputs,
    )?
    .as_deref()
        == Some(current_fingerprint))
}

fn normalize_patch_ranges(
    mut ranges: Vec<std::ops::Range<usize>>,
    bytes_len: usize,
) -> Option<Vec<std::ops::Range<usize>>> {
    ranges.sort_by_key(|range| range.start);
    let mut previous_end = 0;
    for range in &ranges {
        if range.start > range.end || range.end > bytes_len || range.start < previous_end {
            return None;
        }
        previous_end = range.end;
    }

    (!ranges.is_empty()).then_some(ranges)
}

#[cfg(test)]
fn match_patch_sections_from_current_hashes(
    current_bytes: &[u8],
    input_file_path: &str,
    sections: &[PatchSection],
) -> Result<Option<MatchedPatchSections>> {
    let current_resolver = PatchInputResolver::new(current_bytes, true)?;
    match_patch_sections_from_current_hashes_with_resolver(
        input_file_path,
        sections,
        &current_resolver,
    )
}

fn match_patch_sections_from_current_hashes_with_resolver(
    input_file_path: &str,
    sections: &[PatchSection],
    current_resolver: &PatchInputResolver<'_>,
) -> Result<Option<MatchedPatchSections>> {
    if sections.is_empty() || sections.iter().any(|section| section.data_hash.is_none()) {
        return Ok(None);
    }

    let Some(current_sections) = current_patch_sections_for_matching_with_resolver(
        input_file_path,
        sections,
        current_resolver,
    )?
    else {
        return Ok(None);
    };

    let mut matched_sections = Vec::with_capacity(sections.len());
    let mut changed_sections = Vec::new();
    for (previous, current) in sections.iter().cloned().zip(current_sections) {
        // A locally-generated name cannot identify a moved or changed section. It can still
        // remain at its recorded index when its content is unchanged; fingerprint validation
        // below rejects layout or non-patchable changes, and a later content change falls back
        // to reference-based matching.
        if previous.section_name.is_none() && previous.data_hash != current.data_hash {
            return Ok(None);
        }
        if previous.data_hash != current.data_hash {
            changed_sections.push(current.clone());
        }
        matched_sections.push(MatchedPatchSection { previous, current });
    }

    Ok(Some(MatchedPatchSections {
        sections: matched_sections,
        changed_sections,
    }))
}

fn current_patch_sections_for_matching_with_resolver(
    input_file_path: &str,
    sections: &[PatchSection],
    resolver: &PatchInputResolver<'_>,
) -> Result<Option<Vec<PatchSection>>> {
    let mut current_sections = std::iter::repeat_with(|| None)
        .take(sections.len())
        .collect::<Vec<_>>();
    let mut sections_by_input = HashMap::<&str, Vec<usize>>::new();
    for (section_index, section) in sections.iter().enumerate() {
        sections_by_input
            .entry(section.input.as_str())
            .or_default()
            .push(section_index);
    }

    for (input_ref, section_indices) in sections_by_input {
        let Some(input_bytes) = resolver.resolve(
            input_file_path,
            input_ref,
            PatchInputLookup::MatchArchiveMember,
        )?
        else {
            return Ok(None);
        };
        let file = object::File::parse(input_bytes.bytes)
            .context("Failed to parse changed patch input")?;
        let current_input_ref = resolved_patch_input_ref(input_file_path, input_ref, input_bytes)?;
        for stored_section_index in section_indices {
            let patch_section = &sections[stored_section_index];
            let Some(section_index) = patch_section_index(&file, patch_section)? else {
                return Ok(None);
            };
            let section = file
                .section_by_index(section_index)
                .context("Missing changed patch section")?;
            let data = section
                .data()
                .context("Failed to read changed patch section data")?;
            if !section_size_allows_direct_patching(
                section.name().ok().map(str::as_bytes),
                patch_section.input_size,
                data.len(),
            ) || data.len() > patch_section.output_size as usize
            {
                return Ok(None);
            }
            let mut current = patch_section.clone();
            current.input.clone_from(&current_input_ref);
            current.section_index = patch_section_record_index(&file, section_index)?;
            current.input_size = data.len() as u64;
            current.data_hash = Some(hash_bytes(data));
            current.cstring_nul_boundaries_hash =
                cstring_nul_boundaries_hash_for_section(section.name().ok(), data);
            current_sections[stored_section_index] = Some(current);
        }
    }

    Ok(Some(
        current_sections
            .into_iter()
            .collect::<Option<Vec<_>>>()
            .context("Missing current matched patch section")?,
    ))
}

#[cfg(test)]
fn match_patch_sections(
    state_dir: &Path,
    previous_input: &FileState,
    current_bytes: &[u8],
    sections: &[PatchSection],
) -> Result<Option<MatchedPatchSections>> {
    let Some(previous_bytes) = read_verified_input_snapshot(state_dir, previous_input)? else {
        return Ok(None);
    };
    let previous_resolver = PatchInputResolver::new(&previous_bytes, true)?;
    let current_resolver = PatchInputResolver::new(current_bytes, true)?;
    match_patch_sections_with_resolvers(
        previous_input,
        &previous_resolver,
        &current_resolver,
        sections,
    )
}

fn match_patch_sections_with_resolvers(
    previous_input: &FileState,
    previous_resolver: &PatchInputResolver<'_>,
    current_resolver: &PatchInputResolver<'_>,
    sections: &[PatchSection],
) -> Result<Option<MatchedPatchSections>> {
    let mut sections_by_input = HashMap::<&str, Vec<(usize, &PatchSection)>>::new();
    for (section_index, section) in sections.iter().enumerate() {
        sections_by_input
            .entry(section.input.as_str())
            .or_default()
            .push((section_index, section));
    }

    let mut matched_sections = vec![None; sections.len()];
    let mut changed_sections = Vec::new();
    for (input_ref, sections) in sections_by_input {
        let Some(previous_input_bytes) = previous_resolver.resolve(
            previous_input.path.as_str(),
            input_ref,
            PatchInputLookup::MatchArchiveMember,
        )?
        else {
            return Ok(None);
        };
        let Some(current_input_bytes) = current_resolver.resolve(
            previous_input.path.as_str(),
            input_ref,
            PatchInputLookup::MatchArchiveMember,
        )?
        else {
            return Ok(None);
        };
        let previous_file = object::File::parse(previous_input_bytes.bytes)
            .context("Failed to parse previous patch input")?;
        let current_file = object::File::parse(current_input_bytes.bytes)
            .context("Failed to parse current patch input")?;
        let previous_input_ref = resolved_patch_input_ref(
            previous_input.path.as_str(),
            input_ref,
            previous_input_bytes,
        )?;
        let current_input_ref =
            resolved_patch_input_ref(previous_input.path.as_str(), input_ref, current_input_bytes)?;
        let previous_references = section_reference_map(&previous_file)?;
        let current_references = section_reference_map(&current_file)?;

        for (matched_index, section) in sections {
            let Some(previous_index) = patch_section_index(&previous_file, section)? else {
                return Ok(None);
            };
            let Some(current_index) = match_current_patch_section_index(
                &current_file,
                section,
                previous_index,
                &previous_references,
                &current_references,
            )?
            else {
                return Ok(None);
            };

            let mut previous = section.clone();
            previous.input.clone_from(&previous_input_ref);
            previous.section_index = patch_section_record_index(&previous_file, previous_index)?;
            let mut current = section.clone();
            current.input.clone_from(&current_input_ref);
            current.section_index = patch_section_record_index(&current_file, current_index)?;

            let previous_section = previous_file
                .section_by_index(previous_index)
                .context("Missing previous incremental patch section")?;
            let current_section = current_file
                .section_by_index(current_index)
                .context("Missing current incremental patch section")?;
            let previous_data = previous_section
                .data()
                .context("Failed to read previous incremental patch section data")?;
            let current_data = current_section
                .data()
                .context("Failed to read current incremental patch section data")?;
            previous.input_size = previous_data.len() as u64;
            current.input_size = current_data.len() as u64;
            current.data_hash = Some(hash_bytes(current_data));
            current.cstring_nul_boundaries_hash =
                cstring_nul_boundaries_hash_for_section(current_section.name().ok(), current_data);
            if previous_data != current_data {
                changed_sections.push(current.clone());
            }

            matched_sections[matched_index] = Some(MatchedPatchSection { previous, current });
        }
    }

    Ok(Some(MatchedPatchSections {
        sections: matched_sections
            .into_iter()
            .collect::<Option<Vec<_>>>()
            .context("Missing matched incremental patch section")?,
        changed_sections,
    }))
}

fn match_current_patch_section_index(
    current_file: &object::File<'_>,
    patch_section: &PatchSection,
    previous_index: object::SectionIndex,
    previous_references: &HashMap<object::SectionIndex, Vec<SectionReference>>,
    current_references: &HashMap<object::SectionIndex, Vec<SectionReference>>,
) -> Result<Option<object::SectionIndex>> {
    if patch_section.section_name.is_some() {
        return patch_section_index(current_file, patch_section);
    }

    let Some(previous_signature) = previous_references.get(&previous_index) else {
        return Ok(None);
    };
    Ok(match_section_by_references(
        previous_signature,
        current_references,
    ))
}

fn match_section_by_references(
    previous_signature: &[SectionReference],
    current_references: &HashMap<object::SectionIndex, Vec<SectionReference>>,
) -> Option<object::SectionIndex> {
    if previous_signature.is_empty() {
        return None;
    }

    let mut matches = current_references
        .iter()
        .filter_map(|(index, signature)| (signature == previous_signature).then_some(*index));
    let index = matches.next()?;
    matches.next().is_none().then_some(index)
}

#[cfg(test)]
fn anonymous_patch_reference_counts(
    previous_index: object::SectionIndex,
    previous_references: &HashMap<object::SectionIndex, Vec<SectionReference>>,
    current_references: &HashMap<object::SectionIndex, Vec<SectionReference>>,
) -> (usize, usize) {
    let Some(previous_signature) = previous_references.get(&previous_index) else {
        return (0, 0);
    };
    (
        previous_signature.len(),
        current_references
            .values()
            .filter(|signature| *signature == previous_signature)
            .count(),
    )
}

fn section_reference_map(
    file: &object::File<'_>,
) -> Result<HashMap<object::SectionIndex, Vec<SectionReference>>> {
    let mut references = HashMap::<object::SectionIndex, Vec<SectionReference>>::new();
    for section in file.sections() {
        let Some(source_section_name) = patch_section_name_for_matching(&section) else {
            continue;
        };
        for (relocation_offset, relocation) in section.relocations() {
            let Some(target_section) = relocation_target_section(file, relocation.target())? else {
                continue;
            };
            references
                .entry(target_section)
                .or_default()
                .push(SectionReference {
                    source_section_name: source_section_name.clone(),
                    relocation_offset,
                    relocation_kind: format!("{:?}", relocation.kind()),
                    relocation_encoding: format!("{:?}", relocation.encoding()),
                    relocation_size: relocation.size(),
                    relocation_addend: relocation.addend(),
                });
        }
    }
    for signature in references.values_mut() {
        signature.sort();
    }
    Ok(references)
}

fn relocation_target_section(
    file: &object::File<'_>,
    target: object::RelocationTarget,
) -> Result<Option<object::SectionIndex>> {
    match target {
        object::RelocationTarget::Section(section) => Ok(Some(section)),
        object::RelocationTarget::Symbol(symbol) => {
            Ok(file.symbol_by_index(symbol)?.section_index())
        }
        object::RelocationTarget::Absolute => Ok(None),
        _ => Ok(None),
    }
}

#[cfg(test)]
fn changed_patch_sections(
    state_dir: &Path,
    previous_input: &FileState,
    current_bytes: &[u8],
    sections: &[MatchedPatchSection],
) -> Result<Option<Vec<PatchSection>>> {
    let Some(previous_bytes) = read_verified_input_snapshot(state_dir, previous_input)? else {
        return Ok(None);
    };
    let previous_resolver = PatchInputResolver::new(&previous_bytes, true)?;
    let current_resolver = PatchInputResolver::new(current_bytes, true)?;
    changed_patch_sections_with_resolvers(
        previous_input,
        &previous_resolver,
        &current_resolver,
        sections,
    )
}

fn changed_patch_sections_with_resolvers(
    previous_input: &FileState,
    previous_resolver: &PatchInputResolver<'_>,
    current_resolver: &PatchInputResolver<'_>,
    sections: &[MatchedPatchSection],
) -> Result<Option<Vec<PatchSection>>> {
    let mut changed_sections = Vec::new();

    let mut sections_by_input = HashMap::<&str, Vec<&MatchedPatchSection>>::new();
    for section in sections {
        sections_by_input
            .entry(section.current.input.as_str())
            .or_default()
            .push(section);
    }

    for (input_ref, sections) in sections_by_input {
        let Some(previous_input_bytes) = previous_resolver.resolve(
            previous_input.path.as_str(),
            input_ref,
            PatchInputLookup::MatchArchiveMember,
        )?
        else {
            return Ok(None);
        };
        let Some(current_input_bytes) = current_resolver.resolve(
            previous_input.path.as_str(),
            input_ref,
            PatchInputLookup::MatchArchiveMember,
        )?
        else {
            return Ok(None);
        };
        let previous_file = object::File::parse(previous_input_bytes.bytes)
            .context("Failed to parse previous patch input")?;
        let current_file = object::File::parse(current_input_bytes.bytes)
            .context("Failed to parse current patch input")?;

        for patch_section in sections {
            let Some(previous_index) =
                patch_section_index(&previous_file, &patch_section.previous)?
            else {
                return Ok(None);
            };
            let Some(current_index) = patch_section_index(&current_file, &patch_section.current)?
            else {
                return Ok(None);
            };
            let previous_section = previous_file
                .section_by_index(previous_index)
                .context("Missing previous incremental patch section")?;
            let current_section = current_file
                .section_by_index(current_index)
                .context("Missing current incremental patch section")?;
            let previous_data = previous_section
                .data()
                .context("Failed to read previous incremental patch section data")?;
            let current_data = current_section
                .data()
                .context("Failed to read current incremental patch section data")?;
            if previous_data != current_data {
                changed_sections.push(patch_section.current.clone());
            }
        }
    }

    Ok(Some(changed_sections))
}

fn matched_cstring_literal_boundaries_are_stable(
    input_file_path: &str,
    sections: &[MatchedPatchSection],
    previous_resolver: Option<&PatchInputResolver<'_>>,
    current_resolver: &PatchInputResolver<'_>,
) -> Result<bool> {
    let mut sections_by_input = HashMap::<&str, Vec<&MatchedPatchSection>>::new();
    for section in sections {
        sections_by_input
            .entry(section.current.input.as_str())
            .or_default()
            .push(section);
    }

    for (input_ref, sections) in sections_by_input {
        let Some(current_input_bytes) = current_resolver.resolve(
            input_file_path,
            input_ref,
            PatchInputLookup::MatchArchiveMember,
        )?
        else {
            return Ok(false);
        };
        let current_file = object::File::parse(current_input_bytes.bytes)
            .context("Failed to parse current cstring patch input")?;
        let previous_file = if let Some(previous_resolver) = previous_resolver {
            let Some(previous_input_bytes) = previous_resolver.resolve(
                input_file_path,
                input_ref,
                PatchInputLookup::MatchArchiveMember,
            )?
            else {
                return Ok(false);
            };
            Some(
                object::File::parse(previous_input_bytes.bytes)
                    .context("Failed to parse previous cstring patch input")?,
            )
        } else {
            None
        };

        for patch_section in sections {
            let Some(current_index) = patch_section_index(&current_file, &patch_section.current)?
            else {
                return Ok(false);
            };
            let current_section = current_file
                .section_by_index(current_index)
                .context("Missing current cstring patch section")?;
            if current_section.name().ok() != Some("__cstring") {
                continue;
            }
            let current_data = current_section
                .data()
                .context("Failed to read current cstring patch section data")?;
            if patch_section
                .previous
                .cstring_nul_boundaries_hash
                .as_deref()
                == Some(cstring_nul_boundaries_hash(current_data).as_str())
            {
                continue;
            }
            let Some(previous_file) = previous_file.as_ref() else {
                return Ok(false);
            };
            let Some(previous_index) = patch_section_index(previous_file, &patch_section.previous)?
            else {
                return Ok(false);
            };
            let previous_section = previous_file
                .section_by_index(previous_index)
                .context("Missing previous cstring patch section")?;
            if previous_section.name().ok() != Some("__cstring") {
                return Ok(false);
            }
            if !cstring_literal_boundaries_are_stable(
                previous_section
                    .data()
                    .context("Failed to read previous cstring patch section data")?,
                current_data,
            ) {
                return Ok(false);
            }
        }
    }

    Ok(true)
}

fn matched_x86_64_elf_got_relaxation_contexts_are_stable(
    previous_bytes: Option<&[u8]>,
    current_bytes: &[u8],
    input_file_path: &str,
    sections: &[MatchedPatchSection],
) -> Result<bool> {
    let mut sections_by_input = HashMap::<&str, Vec<&MatchedPatchSection>>::new();
    for section in sections {
        sections_by_input
            .entry(section.current.input.as_str())
            .or_default()
            .push(section);
    }

    for (input_ref, sections) in sections_by_input {
        let Some(current_input_bytes) =
            patch_input_bytes(current_bytes, input_file_path, input_ref)?
        else {
            return Ok(false);
        };
        let current_file = object::File::parse(current_input_bytes.bytes)
            .context("Failed to parse current x86-64 ELF GOT patch input")?;
        if current_file.format() != object::BinaryFormat::Elf
            || current_file.architecture() != object::Architecture::X86_64
        {
            continue;
        }

        let Some(previous_bytes) = previous_bytes else {
            return Ok(false);
        };
        let Some(previous_input_bytes) =
            patch_input_bytes(previous_bytes, input_file_path, input_ref)?
        else {
            return Ok(false);
        };
        let previous_file = object::File::parse(previous_input_bytes.bytes)
            .context("Failed to parse previous x86-64 ELF GOT patch input")?;
        if previous_file.format() != object::BinaryFormat::Elf
            || previous_file.architecture() != object::Architecture::X86_64
        {
            return Ok(false);
        }

        for patch_section in sections {
            let Some(previous_index) =
                patch_section_index(&previous_file, &patch_section.previous)?
            else {
                return Ok(false);
            };
            let Some(current_index) = patch_section_index(&current_file, &patch_section.current)?
            else {
                return Ok(false);
            };
            let previous_section = previous_file
                .section_by_index(previous_index)
                .context("Missing previous x86-64 ELF GOT patch section")?;
            let current_section = current_file
                .section_by_index(current_index)
                .context("Missing current x86-64 ELF GOT patch section")?;
            let Some(previous_candidates) =
                x86_64_elf_got_relaxation_candidates(&previous_section)?
            else {
                return Ok(false);
            };
            let Some(current_candidates) = x86_64_elf_got_relaxation_candidates(&current_section)?
            else {
                return Ok(false);
            };
            if previous_candidates != current_candidates {
                return Ok(false);
            }
        }
    }

    Ok(true)
}

fn x86_64_elf_got_relaxation_candidates<'data>(
    section: &impl object::ObjectSection<'data>,
) -> Result<Option<Vec<u64>>> {
    let data = section
        .data()
        .context("Failed to read x86-64 ELF GOT patch section data")?;
    let mut candidates = Vec::new();
    for (offset, relocation) in section.relocations() {
        if !matches!(
            (relocation.kind(), relocation.encoding(), relocation.size()),
            (
                object::RelocationKind::GotRelative,
                object::RelocationEncoding::Generic,
                32
            )
        ) {
            continue;
        }
        let offset_index = usize::try_from(offset)
            .context("x86-64 ELF GOT relocation offset does not fit usize")?;
        let Some(opcode) = offset_index
            .checked_sub(2)
            .and_then(|index| data.get(index))
        else {
            return Ok(None);
        };
        // Standard GOTPCREL can only relax when its instruction opcode is `mov`.
        // Other instruction-byte changes are copied directly without changing
        // the linker's relaxation decision.
        if *opcode == 0x8b {
            candidates.push(offset);
        }
    }
    Ok(Some(candidates))
}

struct PatchSectionIndexLookup {
    unique_by_name: HashMap<String, Option<object::SectionIndex>>,
}

impl PatchSectionIndexLookup {
    fn new(file: &object::File<'_>) -> Self {
        let mut unique_by_name = HashMap::new();
        for section in file.sections() {
            let Some(name) = patch_section_name_for_matching(&section) else {
                continue;
            };
            match unique_by_name.entry(name) {
                hashbrown::hash_map::Entry::Vacant(entry) => {
                    entry.insert(Some(section.index()));
                }
                hashbrown::hash_map::Entry::Occupied(mut entry) => {
                    *entry.get_mut() = None;
                }
            }
        }
        Self { unique_by_name }
    }

    fn index(
        &self,
        file: &object::File<'_>,
        patch_section: &PatchSection,
    ) -> Result<Option<object::SectionIndex>> {
        let Some(name) = patch_section.section_name.as_deref() else {
            return patch_section_object_index(file, patch_section.section_index).map(Some);
        };
        Ok(self.unique_by_name.get(name).copied().flatten())
    }
}

fn patch_section_index(
    file: &object::File<'_>,
    patch_section: &PatchSection,
) -> Result<Option<object::SectionIndex>> {
    PatchSectionIndexLookup::new(file).index(file, patch_section)
}

