    #[test]
    fn patched_section_records_follow_current_section_identity() {
        let input_file = hex::encode("input.o");
        let input_ref = input_file.clone();
        let unrelated_input = hex::encode("other.o");
        let mut records = vec![
            SectionRecord {
                input_file: input_file.clone().into(),
                input: input_ref.clone().into(),
                section_index: 3,
                output_offset: 64,
                size: 16,
            },
            SectionRecord {
                input_file: unrelated_input.into(),
                input: input_ref.clone().into(),
                section_index: 3,
                output_offset: 64,
                size: 16,
            },
        ];
        let previous = PatchSection {
            input: input_ref.clone(),
            section_index: 3,
            section_name: None,
            input_size: 8,
            output_offset: 64,
            output_size: 16,
            data_hash: None,
            cstring_nul_boundaries_hash: None,
        };
        let current = PatchSection {
            input: input_ref.clone(),
            section_index: 7,
            section_name: None,
            input_size: 9,
            output_offset: 64,
            output_size: 16,
            data_hash: None,
            cstring_nul_boundaries_hash: None,
        };

        assert!(
            update_section_records_for_matched_patches(
                &input_file,
                &[MatchedPatchSection { previous, current }],
                &mut records,
                false,
            )
            .unwrap()
        );

        assert_eq!(records[0].section_index, 7);
        assert_eq!(records[0].size, 16);
        assert_eq!(records[1].section_index, 3);
    }

    #[test]
    fn normalized_archive_member_rename_preserves_persisted_section_identity() {
        let input_file = hex::encode("libarchive.rlib");
        let persisted_input =
            hex::encode("libarchive.rlib\0crate-hash.cgu.persisted.rcgu.o\0100:200");
        let previous_input =
            hex::encode("libarchive.rlib\0crate-hash.cgu.previous.rcgu.o\0300:400");
        let current_input = hex::encode("libarchive.rlib\0crate-hash.cgu.current.rcgu.o\0500:600");
        let previous = PatchSection {
            input: previous_input.clone(),
            section_index: 3,
            section_name: Some("__TEXT,__text".to_owned()),
            input_size: 16,
            output_offset: 64,
            output_size: 16,
            data_hash: Some("previous".to_owned()),
            cstring_nul_boundaries_hash: None,
        };
        let current = PatchSection {
            input: current_input.clone(),
            data_hash: Some("current".to_owned()),
            ..previous.clone()
        };
        let matched = MatchedPatchSection { previous, current };
        let original = SectionRecord {
            input_file: input_file.clone().into(),
            input: persisted_input.clone().into(),
            section_index: 3,
            output_offset: 64,
            size: 16,
        };

        let mut normalized = vec![original.clone()];
        assert!(
            !update_section_records_for_matched_patches(
                &input_file,
                std::slice::from_ref(&matched),
                &mut normalized,
                true,
            )
            .unwrap()
        );
        assert_eq!(normalized, vec![original.clone()]);

        let mut moved = vec![original.clone()];
        let mut moved_match = matched.clone();
        moved_match.current.section_index = 7;
        assert!(
            update_section_records_for_matched_patches(
                &input_file,
                &[moved_match],
                &mut moved,
                true,
            )
            .unwrap()
        );
        assert_eq!(moved[0].input, persisted_input);
        assert_eq!(moved[0].section_index, 7);

        let mut exact = vec![original];
        assert!(
            !update_section_records_for_matched_patches(
                &input_file,
                &[matched],
                &mut exact,
                false,
            )
            .unwrap()
        );
        assert_eq!(exact[0].input, persisted_input);
        assert_eq!(exact[0].section_index, 3);
    }

