    #[test]
    fn macho_relocation_record_matches_normalized_archive_patch_section() {
        let input_file = hex::encode("libarchive.rlib");
        let persisted_input =
            hex::encode("libarchive.rlib\0crate-hash.cgu.persisted.rcgu.o\0100:200");
        let previous_input =
            hex::encode("libarchive.rlib\0crate-hash.cgu.previous.rcgu.o\0300:400");
        let mut relocation = relocation_record(
            "unused.o",
            2,
            1,
            Some(0),
            0,
            None,
            None,
            0,
            64,
            4,
            encode_macho_aarch64_relocation_kind(object::macho::RelocationInfo {
                r_address: 0,
                r_symbolnum: 0,
                r_pcrel: true,
                r_length: 2,
                r_extern: true,
                r_type: object::macho::ARM64_RELOC_PAGE21,
            }),
            0,
        );
        relocation.input_file = input_file.clone().into();
        relocation.input = persisted_input.into();
        let section = PatchSection {
            input: previous_input,
            section_index: 2,
            section_name: Some("__TEXT,__text".to_owned()),
            input_size: 4,
            output_offset: 64,
            output_size: 4,
            data_hash: None,
            cstring_nul_boundaries_hash: None,
        };

        assert!(
            macho_relocation_record_matches_patch_section(
                &input_file,
                &relocation,
                &section,
                true,
            )
            .unwrap()
        );
        assert!(
            !macho_relocation_record_matches_patch_section(
                &input_file,
                &relocation,
                &section,
                false,
            )
            .unwrap()
        );
        let mut second_relocation = relocation.clone();
        second_relocation.relocation_offset += 1;
        let relocations = [relocation.clone(), second_relocation];
        let relocation_index =
            MachORelocationSectionIndex::new(&relocations, &input_file, true).unwrap();
        assert_eq!(
            relocation_index
                .indices(&input_file, &section, true)
                .unwrap(),
            &[0, 1]
        );
        assert_eq!(relocation_index.normalized.get(&2).unwrap().len(), 1);
        assert!(
            relocation_index
                .indices(&input_file, &section, false)
                .unwrap()
                .is_empty()
        );

        let mut different_section = section.clone();
        different_section.section_index += 1;
        assert!(
            !macho_relocation_record_matches_patch_section(
                &input_file,
                &relocation,
                &different_section,
                true,
            )
            .unwrap()
        );
        assert!(
            relocation_index
                .indices(&input_file, &different_section, true)
                .unwrap()
                .is_empty()
        );

        let mut different_member = section;
        different_member.input =
            hex::encode("libarchive.rlib\0other-hash.cgu.previous.rcgu.o\0300:400");
        assert!(
            !macho_relocation_record_matches_patch_section(
                &input_file,
                &relocation,
                &different_member,
                true,
            )
            .unwrap()
        );
        assert!(
            relocation_index
                .indices(&input_file, &different_member, true)
                .unwrap()
                .is_empty()
        );
    }

    #[test]
    fn matched_rust_archive_section_refreshes_member_identity() {
        fn archive(
            input_file: &str,
            identifier: &[u8],
            metadata: &[u8],
            object: &[u8],
        ) -> (Vec<u8>, String) {
            let mut builder = ar::Builder::new(Vec::new());
            builder
                .append(
                    &ar::Header::new(b"lib.rmeta".to_vec(), metadata.len() as u64),
                    metadata,
                )
                .unwrap();
            builder
                .append(
                    &ar::Header::new(identifier.to_vec(), object.len() as u64),
                    object,
                )
                .unwrap();
            let archive = builder.into_inner().unwrap();
            let ArchiveMemberMatch::Unique(member) =
                patch_archive_member_bytes(&archive, identifier).unwrap()
            else {
                panic!("expected unique archive member");
            };
            let input_ref = resolved_patch_input_ref(input_file, input_file, member).unwrap();
            (archive, input_ref)
        }

        let input_file = hex::encode("libarchive.rlib");
        let object = test_macho_object(b"\x01\x02\x03\x04", b"\x05\x06\x07\x08", 0);
        let (_, previous_input_ref) =
            archive(&input_file, b"crate-hash.cgu.old.rcgu.o", b"old", &object);
        let (current, current_input_ref) = archive(
            &input_file,
            b"crate-hash.cgu.new.rcgu.o",
            b"new metadata with a different size",
            &object,
        );
        let section = PatchSection {
            input: previous_input_ref.clone(),
            section_index: 0,
            section_name: Some("__TEXT,__text".to_owned()),
            input_size: 4,
            output_offset: 64,
            output_size: 4,
            data_hash: Some(hash_bytes(b"\x01\x02\x03\x04")),
            cstring_nul_boundaries_hash: None,
        };
        let current_resolver = PatchInputResolver::new(&current, true).unwrap();

        let matched = match_patch_sections_from_current_hashes_with_resolver(
            &input_file,
            &[section],
            &current_resolver,
        )
        .unwrap()
        .unwrap();

        assert_eq!(matched.sections[0].previous.input, previous_input_ref);
        assert_eq!(matched.sections[0].current.input, current_input_ref);
        assert!(matched.changed_sections.is_empty());
        assert!(!matched_patch_section_preserves_relocation_record_locations(&matched.sections[0]));
        assert!(
            matched_normalized_archive_section_preserves_relocation_record_locations(
                &input_file,
                &matched.sections[0],
                true,
            )
            .unwrap()
        );
    }

    #[test]
    fn changed_patch_section_location_requires_relocation_record_replay() {
        let previous = PatchSection {
            input: hex::encode("libarchive.rlib\0crate-hash.cgu.old.rcgu.o\0100:200"),
            section_index: 1,
            section_name: Some("__TEXT,__text".to_owned()),
            input_size: 16,
            output_offset: 64,
            output_size: 16,
            data_hash: Some("same".to_owned()),
            cstring_nul_boundaries_hash: None,
        };
        assert!(matched_patch_section_preserves_relocation_record_locations(
            &MatchedPatchSection::same(previous.clone())
        ));

        let mut current = previous.clone();
        current.section_index += 1;
        assert!(
            !matched_patch_section_preserves_relocation_record_locations(&MatchedPatchSection {
                previous: previous.clone(),
                current,
            })
        );

        let mut current = previous.clone();
        current.input = hex::encode("libarchive.rlib\0crate-hash.cgu.new.rcgu.o\0300:400");
        assert!(
            !matched_patch_section_preserves_relocation_record_locations(&MatchedPatchSection {
                previous,
                current
            })
        );
    }

    #[test]
    fn normalized_archive_member_rename_preserves_relocation_record_locations() {
        let input_file = hex::encode("libarchive.rlib");
        let previous = PatchSection {
            input: hex::encode("libarchive.rlib\0crate-hash.cgu.old.rcgu.o\0100:200"),
            section_index: 2,
            section_name: Some("__DATA,__const".to_owned()),
            input_size: 8,
            output_offset: 64,
            output_size: 8,
            data_hash: Some("same".to_owned()),
            cstring_nul_boundaries_hash: None,
        };
        let mut current = previous.clone();
        current.input = hex::encode("libarchive.rlib\0crate-hash.cgu.new.rcgu.o\0300:400");
        let matched = MatchedPatchSection {
            previous: previous.clone(),
            current: current.clone(),
        };

        assert!(
            matched_normalized_archive_section_preserves_relocation_record_locations(
                &input_file,
                &matched,
                true,
            )
            .unwrap()
        );
        assert!(
            !matched_normalized_archive_section_preserves_relocation_record_locations(
                &input_file,
                &matched,
                false,
            )
            .unwrap()
        );

        current.output_offset += 8;
        assert!(
            !matched_normalized_archive_section_preserves_relocation_record_locations(
                &input_file,
                &MatchedPatchSection {
                    previous: previous.clone(),
                    current,
                },
                true,
            )
            .unwrap()
        );

        let mut current = previous.clone();
        current.input = hex::encode("libarchive.rlib\0crate-hash.cgu.new.rcgu.o\0300:400");
        current.section_index += 1;
        assert!(
            !matched_normalized_archive_section_preserves_relocation_record_locations(
                &input_file,
                &MatchedPatchSection {
                    previous: previous.clone(),
                    current,
                },
                true,
            )
            .unwrap()
        );

        let mut current = previous.clone();
        current.input = hex::encode("libarchive.rlib\0other-hash.cgu.new.rcgu.o\0300:400");
        assert!(
            !matched_normalized_archive_section_preserves_relocation_record_locations(
                &input_file,
                &MatchedPatchSection { previous, current },
                true,
            )
            .unwrap()
        );
    }

    #[test]
