    #[test]
    fn retired_macho_symbol_proof_requires_one_previous_and_zero_current_definitions() {
        let object = test_macho_object(b"\x01\x02\x03\x04", b"\x05\x06\x07\x08", 0);
        let archive = |members: &[(&[u8], &[u8])]| {
            let mut builder = ar::Builder::new(Vec::new());
            for (identifier, bytes) in members {
                builder
                    .append(
                        &ar::Header::new(identifier.to_vec(), bytes.len() as u64),
                        *bytes,
                    )
                    .unwrap();
            }
            builder.into_inner().unwrap()
        };
        let name = b"_text".to_vec();
        let names = HashSet::from([name.clone()]);
        let one = archive(&[(b"one.o", object.as_slice())]);
        let duplicate = archive(&[(b"one.o", object.as_slice()), (b"two.o", object.as_slice())]);

        assert_eq!(
            archive_macho_defined_symbol_counts(&one, &[], &names)
                .unwrap()
                .unwrap()[&name],
            1
        );
        assert_eq!(
            archive_macho_defined_symbol_counts(&duplicate, &[], &names)
                .unwrap()
                .unwrap()[&name],
            2
        );
        let one_count = archive_macho_defined_symbol_counts(&one, &[], &names)
            .unwrap()
            .unwrap();
        let duplicate_count = archive_macho_defined_symbol_counts(&duplicate, &[], &names)
            .unwrap()
            .unwrap();
        let zero_count = HashMap::from([(name.clone(), 0)]);
        assert!(macho_definition_counts_prove_retirement(
            &names,
            &one_count,
            &zero_count
        ));
        assert!(
            !macho_definition_counts_prove_retirement(&names, &duplicate_count, &zero_count),
            "duplicate previous definitions must reject retirement"
        );
        assert!(
            !macho_definition_counts_prove_retirement(&names, &one_count, &one_count),
            "current same-name reappearance must reject retirement"
        );
        assert!(macho_definition_counts_prove_restoration(
            &names,
            &zero_count,
            &one_count,
        ));
        assert!(
            !macho_definition_counts_prove_restoration(&names, &zero_count, &duplicate_count),
            "duplicate current definitions must reject restoration"
        );
        assert!(
            !macho_definition_counts_prove_restoration(&names, &one_count, &one_count),
            "previous same-name definitions must reject restoration"
        );
    }

    #[test]
    fn dormant_macho_text_section_activation_consumes_reserve_transactionally() {
        let previous = test_macho_data_object(b"\x05\x06\x07\x08", Some(b""), false);
        let current = test_macho_data_object(b"\x05\x06\x07\x08", Some(b"\x1f\x20\x03\xd5"), false);
        let input = hex::encode("input.o");
        let data = PatchSection {
            input: input.clone(),
            section_index: 0,
            section_name: Some("__DATA,__data".to_owned()),
            input_size: 4,
            output_offset: 64,
            output_size: 4,
            data_hash: Some(hash_bytes(b"\x05\x06\x07\x08")),
            cstring_nul_boundaries_hash: None,
        };
        let previous_text = PatchSection {
            input: input.clone(),
            section_index: 1,
            section_name: Some("__TEXT,__text".to_owned()),
            input_size: 0,
            output_offset: 96,
            output_size: 0,
            data_hash: Some(hash_bytes(b"")),
            cstring_nul_boundaries_hash: None,
        };
        let mut current_text = previous_text.clone();
        current_text.input_size = 4;
        current_text.data_hash = Some(hash_bytes(b"\x1f\x20\x03\xd5"));
        let matched = [
            MatchedPatchSection::same(data),
            MatchedPatchSection {
                previous: previous_text,
                current: current_text,
            },
        ];
        let reserves = [ReservedRangeRecord {
            output_section_id: crate::output_section_id::TEXT.as_usize() as u32,
            alignment_exponent: 2,
            output_offset: 128,
            size: 16,
        }];

        let activation = macho_text_section_activation(
            &previous, &current, &input, &matched, &reserves, 100, true, true,
        )
        .unwrap()
        .unwrap()
        .unwrap();

        let [activated] = activation.text_sections.as_slice() else {
            panic!("expected one activated text section");
        };
        assert_eq!(activated.section.section_index, 1);
        assert_eq!(
            activated.section.section_name.as_deref(),
            Some("__TEXT,__text")
        );
        assert_eq!(activated.section.input_size, 4);
        assert_eq!(activated.section.output_offset, 128);
        assert_eq!(activated.section.output_size, 8);
        assert_eq!(activated.matched_section_index, Some(1));
        assert!(!activation.grew_existing_sections);
        assert!(activation.appended_records.is_empty());
        assert!(activation.auxiliary_sections.is_empty());
        assert!(activation.auxiliary_patches.is_empty());
        assert_eq!(
            activation.remaining_reserved_ranges,
            vec![ReservedRangeRecord {
                output_section_id: crate::output_section_id::TEXT.as_usize() as u32,
                alignment_exponent: 2,
                output_offset: 136,
                size: 8,
            }]
        );

        let resolved =
            resolved_patch_sections_for_input(&current, &input, [activated.section.clone()])
                .unwrap()
                .unwrap();
        assert_eq!(resolved[0].patch.data, b"\x1f\x20\x03\xd5");
        assert_eq!(resolved[0].patch.size, 8);
    }

    #[test]
    fn dormant_macho_text_section_activation_rejects_unsafe_deltas() {
        let previous = test_macho_data_object(b"\x05\x06\x07\x08", Some(b""), false);
        let input = hex::encode("input.o");
        let data = PatchSection {
            input: input.clone(),
            section_index: 0,
            section_name: Some("__DATA,__data".to_owned()),
            input_size: 4,
            output_offset: 64,
            output_size: 4,
            data_hash: Some(hash_bytes(b"\x05\x06\x07\x08")),
            cstring_nul_boundaries_hash: None,
        };
        let previous_text = PatchSection {
            input: input.clone(),
            section_index: 1,
            section_name: Some("__TEXT,__text".to_owned()),
            input_size: 0,
            output_offset: 96,
            output_size: 0,
            data_hash: Some(hash_bytes(b"")),
            cstring_nul_boundaries_hash: None,
        };
        let mut current_text = previous_text.clone();
        current_text.input_size = 4;
        current_text.data_hash = Some(hash_bytes(b"\x1f\x20\x03\xd5"));
        let matched = [
            MatchedPatchSection::same(data),
            MatchedPatchSection {
                previous: previous_text,
                current: current_text,
            },
        ];
        let reserves = [ReservedRangeRecord {
            output_section_id: crate::output_section_id::TEXT.as_usize() as u32,
            alignment_exponent: 2,
            output_offset: 128,
            size: 16,
        }];

        let symbol = test_macho_data_object(b"\x05\x06\x07\x08", Some(b"\x1f\x20\x03\xd5"), true);
        assert!(
            macho_text_section_activation(
                &previous, &symbol, &input, &matched, &reserves, 100, true, true,
            )
            .unwrap()
            .err()
            .unwrap()
            .contains("changed symbols")
        );

        let mut unrelated_change =
            test_macho_data_object(b"\x05\x06\x07\x08", Some(b"\x1f\x20\x03\xd5"), false);
        unrelated_change[8] ^= 1;
        assert!(
            macho_text_section_activation(
                &previous,
                &unrelated_change,
                &input,
                &matched,
                &reserves,
                100,
                true,
                true,
            )
            .unwrap()
            .err()
            .unwrap()
            .contains("outside activated")
        );

        let current = test_macho_data_object(b"\x05\x06\x07\x08", Some(b"\x1f\x20\x03\xd5"), false);
        let insufficient = [ReservedRangeRecord {
            output_section_id: crate::output_section_id::TEXT.as_usize() as u32,
            alignment_exponent: 2,
            output_offset: 128,
            size: 4,
        }];
        assert!(
            macho_text_section_activation(
                &previous,
                &current,
                &input,
                &matched,
                &insufficient,
                100,
                true,
                true,
            )
            .unwrap()
            .err()
            .unwrap()
            .contains("insufficient incremental reserve")
        );
        assert_eq!(insufficient[0].output_offset, 128);
        assert_eq!(insufficient[0].size, 4);
    }

    #[test]
    fn grown_macho_archive_text_section_activation_consumes_reserve() {
        fn archive(input_file: &str, identifier: &[u8], object: &[u8]) -> (Vec<u8>, String) {
            let mut builder = ar::Builder::new(Vec::new());
            builder
                .append(
                    &ar::Header::new(identifier.to_vec(), object.len() as u64),
                    object,
                )
                .unwrap();
            let archive = builder.into_inner().unwrap();
            let ArchiveMemberMatch::Unique(member) =
                patch_archive_member_bytes(&archive, identifier).unwrap()
            else {
                panic!("expected unique archive member");
            };
            let input_ref = resolved_patch_input_ref(input_file, input_file, member).unwrap();
            (archive, input_ref)
        }

        let input_file = hex::encode("libarchive.rlib");
        let previous_object = test_macho_object(b"\x01\x02\x03\x04", b"\x05\x06\x07\x08", 0);
        let current_object =
            test_macho_object(b"\x01\x02\x03\x04\x09\x0a\x0b\x0c", b"\x05\x06\x07\x08", 0);
        let (previous, previous_input) =
            archive(&input_file, b"crate-hash.cgu.old.rcgu.o", &previous_object);
        let (current, current_input) =
            archive(&input_file, b"crate-hash.cgu.new.rcgu.o", &current_object);
        let previous_file = object::File::parse(previous_object.as_slice()).unwrap();
        let current_file = object::File::parse(current_object.as_slice()).unwrap();
        let previous_text = previous_file.section_by_name("__text").unwrap();
        let current_text = current_file.section_by_name("__text").unwrap();
        let previous_section = PatchSection {
            input: previous_input,
            section_index: patch_section_record_index(&previous_file, previous_text.index())
                .unwrap(),
            section_name: Some("__TEXT,__text".to_owned()),
            input_size: previous_text.size(),
            output_offset: 64,
            output_size: previous_text.size(),
            data_hash: Some(hash_bytes(previous_text.data().unwrap())),
            cstring_nul_boundaries_hash: None,
        };
        let current_section = PatchSection {
            input: current_input,
            section_index: patch_section_record_index(&current_file, current_text.index()).unwrap(),
            section_name: Some("__TEXT,__text".to_owned()),
            input_size: current_text.size(),
            output_offset: 64,
            output_size: previous_text.size(),
            data_hash: Some(hash_bytes(current_text.data().unwrap())),
            cstring_nul_boundaries_hash: None,
        };
        let matched = [MatchedPatchSection {
            previous: previous_section.clone(),
            current: current_section.clone(),
        }];
        let reserves = [ReservedRangeRecord {
            output_section_id: crate::output_section_id::TEXT.as_usize() as u32,
            alignment_exponent: 2,
            output_offset: 128,
            size: 32,
        }];

        let activation = macho_text_section_activation(
            &previous,
            &current,
            &input_file,
            &matched,
            &reserves,
            100,
            true,
            false,
        )
        .unwrap()
        .unwrap()
        .unwrap();

        let [activated] = activation.text_sections.as_slice() else {
            panic!("expected one grown text section");
        };
        assert!(activation.grew_existing_sections);
        assert_eq!(activated.matched_section_index, Some(0));
        assert_eq!(activated.section.output_offset, 128);
        assert_eq!(activated.section.output_size, 16);
        assert_eq!(
            activation.normalized_archive_identifiers,
            [b"crate-hash.cgu.rcgu.o".to_vec()]
        );
        assert_eq!(
            activation.remaining_reserved_ranges,
            vec![ReservedRangeRecord {
                output_section_id: crate::output_section_id::TEXT.as_usize() as u32,
                alignment_exponent: 2,
                output_offset: 144,
                size: 16,
            }]
        );

        let (stable_current, stable_current_input) =
            archive(&input_file, b"crate-hash.cgu.old.rcgu.o", &current_object);
        let stable_matched = [MatchedPatchSection {
            previous: previous_section,
            current: PatchSection {
                input: stable_current_input,
                ..current_section
            },
        }];
        let stable_activation = macho_text_section_activation(
            &previous,
            &stable_current,
            &input_file,
            &stable_matched,
            &reserves,
            100,
            true,
            false,
        )
        .unwrap()
        .unwrap()
        .unwrap();
        assert!(
            stable_activation.normalized_archive_identifiers.is_empty(),
            "exact-stable archive members use the ordinary masked archive fingerprint"
        );
    }

    #[test]
    fn grown_macho_archive_text_sections_activate_transactionally() {
        fn archive(input_file: &str, members: &[(&[u8], &[u8])]) -> (Vec<u8>, Vec<String>) {
            let mut builder = ar::Builder::new(Vec::new());
            for (identifier, object) in members {
                builder
                    .append(
                        &ar::Header::new(identifier.to_vec(), object.len() as u64),
                        *object,
                    )
                    .unwrap();
            }
            let archive = builder.into_inner().unwrap();
            let inputs = members
                .iter()
                .map(|(identifier, _)| {
                    let ArchiveMemberMatch::Unique(member) =
                        patch_archive_member_bytes(&archive, identifier).unwrap()
                    else {
                        panic!("expected unique archive member");
                    };
                    resolved_patch_input_ref(input_file, input_file, member).unwrap()
                })
                .collect();
            (archive, inputs)
        }

        let input_file = hex::encode("libarchive.rlib");
        let previous_objects = [
            test_macho_object(b"\x01\x02\x03\x04", b"\x11\x12\x13\x14", 0),
            test_macho_object(b"\x05\x06\x07\x08", b"\x15\x16\x17\x18", 0),
        ];
        let current_objects = [
            test_macho_object(b"\x01\x02\x03\x04\x09\x0a\x0b\x0c", b"\x11\x12\x13\x14", 0),
            test_macho_object(b"\x05\x06\x07\x08\x0d\x0e\x0f\x10", b"\x15\x16\x17\x18", 0),
        ];
        let previous_members = [
            (
                b"crate.one.old.rcgu.o".as_slice(),
                previous_objects[0].as_slice(),
            ),
            (
                b"crate.two.old.rcgu.o".as_slice(),
                previous_objects[1].as_slice(),
            ),
        ];
        let current_members = [
            (
                b"crate.one.new.rcgu.o".as_slice(),
                current_objects[0].as_slice(),
            ),
            (
                b"crate.two.new.rcgu.o".as_slice(),
                current_objects[1].as_slice(),
            ),
        ];
        let (previous, previous_inputs) = archive(&input_file, &previous_members);
        let (current, current_inputs) = archive(&input_file, &current_members);
        let matched = previous_objects
            .iter()
            .zip(&current_objects)
            .zip(previous_inputs.iter().zip(&current_inputs))
            .enumerate()
            .map(
                |(index, ((previous_object, current_object), (previous_input, current_input)))| {
                    let previous_file = object::File::parse(previous_object.as_slice()).unwrap();
                    let current_file = object::File::parse(current_object.as_slice()).unwrap();
                    let previous_text = previous_file.section_by_name("__text").unwrap();
                    let current_text = current_file.section_by_name("__text").unwrap();
                    MatchedPatchSection {
                        previous: PatchSection {
                            input: previous_input.clone(),
                            section_index: patch_section_record_index(
                                &previous_file,
                                previous_text.index(),
                            )
                            .unwrap(),
                            section_name: Some("__TEXT,__text".to_owned()),
                            input_size: previous_text.size(),
                            output_offset: 64 + index as u64 * 16,
                            output_size: previous_text.size(),
                            data_hash: Some(hash_bytes(previous_text.data().unwrap())),
                            cstring_nul_boundaries_hash: None,
                        },
                        current: PatchSection {
                            input: current_input.clone(),
                            section_index: patch_section_record_index(
                                &current_file,
                                current_text.index(),
                            )
                            .unwrap(),
                            section_name: Some("__TEXT,__text".to_owned()),
                            input_size: current_text.size(),
                            output_offset: 64 + index as u64 * 16,
                            output_size: previous_text.size(),
                            data_hash: Some(hash_bytes(current_text.data().unwrap())),
                            cstring_nul_boundaries_hash: None,
                        },
                    }
                },
            )
            .collect::<Vec<_>>();
        let reserves = [ReservedRangeRecord {
            output_section_id: crate::output_section_id::TEXT.as_usize() as u32,
            alignment_exponent: 2,
            output_offset: 128,
            size: 64,
        }];

        let activation = grown_macho_text_section_activation(
            &previous,
            &current,
            &input_file,
            &matched,
            &reserves,
            100,
            true,
        )
        .unwrap()
        .unwrap()
        .unwrap();

        assert_eq!(activation.text_sections.len(), 2);
        assert_eq!(
            activation
                .text_sections
                .iter()
                .map(|activated| (
                    activated.matched_section_index,
                    activated.section.output_offset,
                    activated.section.output_size,
                ))
                .collect::<Vec<_>>(),
            [(Some(0), 128, 16), (Some(1), 144, 16)]
        );
        assert_eq!(
            activation.normalized_archive_identifiers,
            [b"crate.one.rcgu.o".to_vec(), b"crate.two.rcgu.o".to_vec()]
        );
        assert_eq!(
            activation.remaining_reserved_ranges,
            [ReservedRangeRecord {
                output_section_id: crate::output_section_id::TEXT.as_usize() as u32,
                alignment_exponent: 2,
                output_offset: 160,
                size: 32,
            }]
        );

        let insufficient = [ReservedRangeRecord {
            output_section_id: crate::output_section_id::TEXT.as_usize() as u32,
            alignment_exponent: 2,
            output_offset: 128,
            size: 16,
        }];
        let failure = grown_macho_text_section_activation(
            &previous,
            &current,
            &input_file,
            &matched,
            &insufficient,
            100,
            true,
        )
        .unwrap()
        .err()
        .unwrap();
        assert!(failure.contains("insufficient incremental reserve"));
        assert_eq!(insufficient[0].output_offset, 128);
        assert_eq!(insufficient[0].size, 16);

        let ambiguous = [matched[0].clone(), matched[0].clone()];
        let failure = grown_macho_text_section_activation(
            &previous,
            &current,
            &input_file,
            &ambiguous,
            &reserves,
            100,
            true,
        )
        .unwrap()
        .err()
        .unwrap();
        assert!(failure.contains("multiple grown text sections in one object"));
    }

    #[test]
    fn grown_macho_archive_text_section_activation_allocates_exception_table() {
        fn archive(input_file: &str, identifier: &[u8], object: &[u8]) -> (Vec<u8>, String) {
            let mut builder = ar::Builder::new(Vec::new());
            builder
                .append(
                    &ar::Header::new(identifier.to_vec(), object.len() as u64),
                    object,
                )
                .unwrap();
            let archive = builder.into_inner().unwrap();
            let ArchiveMemberMatch::Unique(member) =
                patch_archive_member_bytes(&archive, identifier).unwrap()
            else {
                panic!("expected unique archive member");
            };
            let input_ref = resolved_patch_input_ref(input_file, input_file, member).unwrap();
            (archive, input_ref)
        }

        let input_file = hex::encode("libarchive.rlib");
        let previous_object = test_observed_049_macho_unwind_object(false);
        let current_object = test_observed_049_macho_unwind_object(true);
        let (previous, previous_input) =
            archive(&input_file, b"crate-hash.cgu.old.rcgu.o", &previous_object);
        let (current, current_input) =
            archive(&input_file, b"crate-hash.cgu.new.rcgu.o", &current_object);
        let previous_file = object::File::parse(previous_object.as_slice()).unwrap();
        let current_file = object::File::parse(current_object.as_slice()).unwrap();
        let previous_text = previous_file.section_by_name("__text").unwrap();
        let current_text = current_file.section_by_name("__text").unwrap();
        let current_gcc_except_table = current_file.section_by_name("__gcc_except_tab").unwrap();
        let text_alignment = crate::alignment::Alignment::new(current_text.align().max(1)).unwrap();
        let gcc_alignment =
            crate::alignment::Alignment::new(current_gcc_except_table.align().max(1)).unwrap();
        let previous_section = PatchSection {
            input: previous_input.clone(),
            section_index: patch_section_record_index(&previous_file, previous_text.index())
                .unwrap(),
            section_name: Some("__TEXT,__text".to_owned()),
            input_size: previous_text.size(),
            output_offset: 64,
            output_size: previous_text.size(),
            data_hash: Some(hash_bytes(previous_text.data().unwrap())),
            cstring_nul_boundaries_hash: None,
        };
        let current_section = PatchSection {
            input: current_input.clone(),
            section_index: patch_section_record_index(&current_file, current_text.index()).unwrap(),
            section_name: Some("__TEXT,__text".to_owned()),
            input_size: current_text.size(),
            output_offset: 64,
            output_size: previous_text.size(),
            data_hash: Some(hash_bytes(current_text.data().unwrap())),
            cstring_nul_boundaries_hash: None,
        };
        let matched = [MatchedPatchSection {
            previous: previous_section,
            current: current_section,
        }];
        let text_output_offset = 0x1000;
        let gcc_output_offset = 0x2000;
        let reserves = [
            ReservedRangeRecord {
                output_section_id: crate::output_section_id::TEXT.as_usize() as u32,
                alignment_exponent: text_alignment.exponent,
                output_offset: text_output_offset,
                size: current_text.size(),
            },
            ReservedRangeRecord {
                output_section_id: crate::output_section_id::GCC_EXCEPT_TABLE.as_usize() as u32,
                alignment_exponent: gcc_alignment.exponent,
                output_offset: gcc_output_offset,
                size: current_gcc_except_table.size(),
            },
        ];

        let activation = macho_text_section_activation(
            &previous,
            &current,
            &input_file,
            &matched,
            &reserves,
            0,
            true,
            false,
        )
        .unwrap()
        .unwrap()
        .unwrap();

        let [activated] = activation.text_sections.as_slice() else {
            panic!("expected one grown text section");
        };
        assert!(activation.grew_existing_sections);
        assert_eq!(activated.section.output_offset, text_output_offset);
        assert_eq!(activated.section.output_size, current_text.size());
        assert_eq!(activation.auxiliary_sections.len(), 1);
        let exception_table = &activation.auxiliary_sections[0];
        assert_eq!(exception_table.input, current_input);
        assert_eq!(
            exception_table.section_name.as_deref(),
            Some("__TEXT,__gcc_except_tab")
        );
        assert_eq!(exception_table.input_size, current_gcc_except_table.size());
        assert_eq!(exception_table.output_offset, gcc_output_offset);
        assert_eq!(
            activation.auxiliary_patches[0].data,
            current_gcc_except_table.data().unwrap()
        );
        assert_eq!(
            activation.appended_records,
            vec![SectionRecord {
                input_file: input_file.clone().into(),
                input: exception_table.input.clone().into(),
                section_index: exception_table.section_index,
                output_offset: gcc_output_offset,
                size: current_gcc_except_table.size(),
            }]
        );
        assert_eq!(
            activation.retired_record_keys,
            vec![(
                previous_input,
                patch_section_record_index(
                    &previous_file,
                    previous_file
                        .section_by_name("__gcc_except_tab")
                        .unwrap()
                        .index(),
                )
                .unwrap(),
            )]
        );
        assert!(activation.remaining_reserved_ranges.is_empty());

        let insufficient_reserves = [ReservedRangeRecord {
            output_section_id: crate::output_section_id::TEXT.as_usize() as u32,
            alignment_exponent: text_alignment.exponent,
            output_offset: text_output_offset,
            size: current_text.size(),
        }];
        let failure = macho_text_section_activation(
            &previous,
            &current,
            &input_file,
            &matched,
            &insufficient_reserves,
            0,
            true,
            false,
        )
        .unwrap()
        .err()
        .unwrap();
        assert!(failure.contains("reserve for grown Mach-O exception table"));
        assert_eq!(
            insufficient_reserves[0],
            ReservedRangeRecord {
                output_section_id: crate::output_section_id::TEXT.as_usize() as u32,
                alignment_exponent: text_alignment.exponent,
                output_offset: text_output_offset,
                size: current_text.size(),
            }
        );
    }

    #[test]
    fn current_patch_state_masks_macho_symbol_catalog_values() {
        let previous = test_macho_object(b"\x01\x02\x03\x04", b"\x05\x06\x07\x08", 0);
        let current = test_macho_object(b"\x01\x02\x03\x04", b"\x05\x06\x07\x08", 1);
        let mut input_file = crate::input_data::InputFile::for_testing();
        input_file.filename = PathBuf::from("input.o");
        let input_ref = InputRef {
            file: &input_file,
            entry: None,
        };
        let input = encode_path(&input_file.filename);
        let sections = [
            SectionRecord::new(input_ref, object::SectionIndex(0), 64, 4),
            SectionRecord::new(input_ref, object::SectionIndex(1), 128, 4),
        ];
        let sections = sections.iter().collect::<Vec<_>>();
        let mut output = vec![0; 132];
        output[64..68].copy_from_slice(b"\x01\x02\x03\x04");
        output[128..132].copy_from_slice(b"\x05\x06\x07\x08");
        let resolution = MachOSymbolResolutionRecord {
            name: SharedText::from(hex::encode("_data")),
            direct_value: Some(0x1000),
            got_address: None,
            stub_address: None,
            thunk_addresses: Vec::new(),
            target: Some(RelocationTargetRecord {
                input_file: SharedText::from(input.clone()),
                input: SharedText::from(input.clone()),
                section_index: 2,
                section_offset: 0,
            }),
        };
        let previous_patch = current_patch_state(
            &previous,
            &input,
            &output,
            &sections,
            &[],
            &[],
            &[],
            &[&resolution],
            &[],
            true,
        )
        .unwrap()
        .unwrap();
        let input_state = FileState {
            path: input.clone(),
            content: FileContentState::from_bytes(&previous),
            snapshot_identity: None,
            rustc_link_content_digest: None,
            rustc_raw_object_manifest: None,
            patch: None,
        };
        let mut current_resolutions = vec![resolution];
        let updates = update_macho_symbol_resolutions_for_input(
            &mut current_resolutions,
            &input_state,
            &current,
            false,
            None,
        )
        .unwrap()
        .unwrap();
        assert!(updates.changed);
        let current_fingerprint = patch_fingerprint_with_extra_ranges(
            &current,
            &input,
            previous_patch.sections.iter().map(|section| PatchSection {
                input: section.input.clone(),
                section_index: section.section_index,
                section_name: section.section_name.clone(),
                input_size: section.input_size,
                output_offset: section.output_offset,
                output_size: section.output_size,
                data_hash: section.data_hash.clone(),
                cstring_nul_boundaries_hash: section.cstring_nul_boundaries_hash.clone(),
            }),
            updates.input_ranges,
        )
        .unwrap()
        .unwrap();

        assert_eq!(previous_patch.fingerprint, current_fingerprint);
    }

    #[test]
    fn macho_symbol_resolution_uses_activated_output_address() {
        let object = test_macho_object(b"\x01\x02\x03\x04", b"\x05\x06\x07\x08", 0);
        let file = object::File::parse(object.as_slice()).unwrap();
        let text = file.section_by_name("__text").unwrap();
        let input_path = hex::encode("input.o");
        let output = test_macho_unwind_output(0x1000);
        let output_file = object::File::parse(output.bytes.as_slice()).unwrap();
        let previous_output_offset = output.text_offset + 0x100;
        let current_output_offset = output.text_offset + 0x500;
        let previous_value =
            macho_output_address_for_file_offset(&output_file, previous_output_offset).unwrap();
        let current_value =
            macho_output_address_for_file_offset(&output_file, current_output_offset).unwrap();
        let section_index = patch_section_record_index(&file, text.index()).unwrap();
        let matched = [MatchedPatchSection {
            previous: PatchSection {
                input: input_path.clone(),
                section_index,
                section_name: Some("__TEXT,__text".to_owned()),
                input_size: text.size(),
                output_offset: previous_output_offset,
                output_size: text.size(),
                data_hash: None,
                cstring_nul_boundaries_hash: None,
            },
            current: PatchSection {
                input: input_path.clone(),
                section_index,
                section_name: Some("__TEXT,__text".to_owned()),
                input_size: text.size(),
                output_offset: current_output_offset,
                output_size: text.size(),
                data_hash: None,
                cstring_nul_boundaries_hash: None,
            },
        }];
        let input = FileState {
            path: input_path.clone(),
            content: FileContentState::from_bytes(&object),
            snapshot_identity: None,
            rustc_link_content_digest: None,
            rustc_raw_object_manifest: None,
            patch: None,
        };
        let mut resolutions = vec![MachOSymbolResolutionRecord {
            name: SharedText::from(hex::encode("_text")),
            direct_value: Some(previous_value),
            got_address: None,
            stub_address: None,
            thunk_addresses: Vec::new(),
            target: Some(RelocationTargetRecord {
                input_file: input_path.clone().into(),
                input: input_path.into(),
                section_index: text.index().0 as u32,
                section_offset: 0,
            }),
        }];
        let updates = update_macho_symbol_resolutions_for_input(
            &mut resolutions,
            &input,
            &object,
            false,
            Some((&matched, &output.bytes)),
        )
        .unwrap()
        .unwrap();

        assert!(updates.changed);
        assert_eq!(resolutions[0].direct_value, Some(current_value));
        assert_eq!(updates.output_symbols.len(), 1);
        assert_eq!(updates.output_symbols[0].target_name, hex::encode("_text"));
        assert_eq!(
            updates.output_symbols[0].previous_target_value,
            previous_value
        );
        assert_eq!(updates.output_symbols[0].target_value, current_value);
        assert!(updates.output_symbols[0].allow_missing);
        assert_eq!(updates.moves.len(), 1);
        assert_eq!(
            updates.moves[0].name,
            SharedText::from(hex::encode("_text"))
        );
        assert_eq!(updates.moves[0].previous_value, previous_value);
        assert_eq!(updates.moves[0].current_value, current_value);
        assert_eq!(updates.moves[0].previous_target.section_offset, 0);
        assert_eq!(updates.moves[0].current_target.section_offset, 0);
    }

    #[test]
    fn moved_macho_symbol_retargets_recorded_thunk() {
        let object = test_macho_object(&[0; 32], &[0; 4], 0);
        let file = object::File::parse(object.as_slice()).unwrap();
        let text = file.section_by_name("__text").unwrap();
        let input_path = hex::encode("input.o");
        let mut output = test_macho_unwind_output(0x1000);
        let output_file = object::File::parse(output.bytes.as_slice()).unwrap();
        let previous_output_offset = output.text_offset + 0x100;
        let current_output_offset = output.text_offset + 0x500;
        let thunk_output_offset = output.text_offset + 0x700;
        let previous_value =
            macho_output_address_for_file_offset(&output_file, previous_output_offset).unwrap();
        let current_value =
            macho_output_address_for_file_offset(&output_file, current_output_offset).unwrap();
        let thunk_address =
            macho_output_address_for_file_offset(&output_file, thunk_output_offset).unwrap();
        let config =
            <crate::macho_aarch64::MachOAArch64 as crate::platform::Arch>::thunk_config().unwrap();
        let mut previous_thunk = vec![0; config.thunk_size as usize];
        <crate::macho_aarch64::MachOAArch64 as crate::platform::Arch>::write_thunk(
            thunk_address,
            previous_value,
            &mut previous_thunk,
        );
        let thunk_start = thunk_output_offset as usize;
        output.bytes[thunk_start..thunk_start + previous_thunk.len()]
            .copy_from_slice(&previous_thunk);
        let section_index = patch_section_record_index(&file, text.index()).unwrap();
        let matched = [MatchedPatchSection {
            previous: PatchSection {
                input: input_path.clone(),
                section_index,
                section_name: Some("__TEXT,__text".to_owned()),
                input_size: text.size(),
                output_offset: previous_output_offset,
                output_size: text.size(),
                data_hash: None,
                cstring_nul_boundaries_hash: None,
            },
            current: PatchSection {
                input: input_path.clone(),
                section_index,
                section_name: Some("__TEXT,__text".to_owned()),
                input_size: text.size(),
                output_offset: current_output_offset,
                output_size: text.size(),
                data_hash: None,
                cstring_nul_boundaries_hash: None,
            },
        }];
        let input = FileState {
            path: input_path.clone(),
            content: FileContentState::from_bytes(&object),
            snapshot_identity: None,
            rustc_link_content_digest: None,
            rustc_raw_object_manifest: None,
            patch: None,
        };
        let resolution = MachOSymbolResolutionRecord {
            name: SharedText::from(hex::encode("_text")),
            direct_value: Some(previous_value),
            got_address: None,
            stub_address: None,
            thunk_addresses: vec![thunk_address],
            target: Some(RelocationTargetRecord {
                input_file: input_path.clone().into(),
                input: input_path.into(),
                section_index: text.index().0 as u32,
                section_offset: 0,
            }),
        };
        let mut resolutions = vec![resolution.clone()];
        let updates = update_macho_symbol_resolutions_for_input(
            &mut resolutions,
            &input,
            &object,
            false,
            Some((&matched, &output.bytes)),
        )
        .unwrap()
        .unwrap();

        let mut expected = vec![0; config.thunk_size as usize];
        <crate::macho_aarch64::MachOAArch64 as crate::platform::Arch>::write_thunk(
            thunk_address,
            current_value,
            &mut expected,
        );
        assert_eq!(updates.thunk_patches.len(), 1);
        assert_eq!(updates.thunk_patches[0].output_offset, thunk_output_offset);
        assert_eq!(updates.thunk_patches[0].data, expected);
        assert_eq!(
            updates.reusable_branch_targets,
            vec![MachOReusableBranchTarget {
                moved: updates.moves[0].clone(),
                applied_target_value: thunk_address,
            }]
        );
        assert_eq!(resolutions[0].thunk_addresses, vec![thunk_address]);

        let mut corrupted_output = output.bytes.clone();
        corrupted_output[thunk_start] ^= 1;
        assert!(matches!(
            update_macho_symbol_resolutions_for_input(
                &mut [resolution],
                &input,
                &object,
                false,
                Some((&matched, &corrupted_output)),
            )
            .unwrap(),
            Err(reason) if reason.contains("thunk encoding changed")
        ));
    }

