    #[test]
    fn owned_macho_member_removal_composes_with_validated_unwind_ranges() {
        fn archive(members: &[(&[u8], &[u8])]) -> Vec<u8> {
            let mut builder = ar::Builder::new(Vec::new());
            for (identifier, object) in members {
                builder
                    .append(
                        &ar::Header::new(identifier.to_vec(), object.len() as u64),
                        *object,
                    )
                    .unwrap();
            }
            builder.into_inner().unwrap()
        }

        let previous_kept = test_observed_049_macho_unwind_object(false);
        let mut current_kept = previous_kept.clone();
        let eh_frame_range = {
            let file = object::File::parse(previous_kept.as_slice()).unwrap();
            let (offset, size) = file
                .section_by_name("__eh_frame")
                .unwrap()
                .file_range()
                .unwrap();
            offset as usize..(offset + size) as usize
        };
        current_kept[eh_frame_range.start] ^= 1;
        let removed = test_macho_object(&[1; 4], &[2; 4], 0);
        let kept_identifier = b"crate-hash.cgu.1.session.rcgu.o";
        let removed_identifier = b"crate-hash.cgu.2.session.rcgu.o";
        let previous = archive(&[
            (kept_identifier, previous_kept.as_slice()),
            (removed_identifier, removed.as_slice()),
        ]);
        let current = archive(&[(kept_identifier, current_kept.as_slice())]);
        let input_file = hex::encode("lib.rlib");
        let previous_member = match patch_archive_member_bytes(&previous, kept_identifier).unwrap()
        {
            ArchiveMemberMatch::Unique(member) => member,
            _ => panic!("expected unique previous archive member"),
        };
        let current_member = match patch_archive_member_bytes(&current, kept_identifier).unwrap() {
            ArchiveMemberMatch::Unique(member) => member,
            _ => panic!("expected unique current archive member"),
        };
        let previous_input =
            resolved_patch_input_ref(&input_file, &input_file, previous_member).unwrap();
        let current_input =
            resolved_patch_input_ref(&input_file, &input_file, current_member).unwrap();
        let previous_file = object::File::parse(previous_member.bytes).unwrap();
        let current_file = object::File::parse(current_member.bytes).unwrap();
        let previous_text = previous_file.section_by_name("__text").unwrap();
        let current_text = current_file.section_by_name("__text").unwrap();
        let matched = [MatchedPatchSection {
            previous: PatchSection {
                input: previous_input.into(),
                section_index: patch_section_record_index(&previous_file, previous_text.index())
                    .unwrap(),
                section_name: Some("__TEXT,__text".to_owned()),
                input_size: previous_text.size(),
                output_offset: 0,
                output_size: previous_text.size(),
                data_hash: None,
                cstring_nul_boundaries_hash: None,
            },
            current: PatchSection {
                input: current_input.into(),
                section_index: patch_section_record_index(&current_file, current_text.index())
                    .unwrap(),
                section_name: Some("__TEXT,__text".to_owned()),
                input_size: current_text.size(),
                output_offset: 0,
                output_size: current_text.size(),
                data_hash: None,
                cstring_nul_boundaries_hash: None,
            },
        }];
        let current_resolver = PatchInputResolver::new(&current, true).unwrap();
        let removed = [archive_member_patch_identifier(removed_identifier)];
        let previous_unwind = [previous_member.file_offset + eh_frame_range.start
            ..previous_member.file_offset + eh_frame_range.end];
        let current_unwind = [current_member.file_offset + eh_frame_range.start
            ..current_member.file_offset + eh_frame_range.end];

        assert!(
            !archive_diff_allows_owned_macho_member_removal(
                &previous,
                &current,
                &input_file,
                &matched,
                &current_resolver,
                &removed,
                &[],
                &[],
                &[],
            )
            .unwrap()
        );
        assert!(
            archive_diff_allows_owned_macho_member_removal(
                &previous,
                &current,
                &input_file,
                &matched,
                &current_resolver,
                &removed,
                &[],
                &previous_unwind,
                &current_unwind,
            )
            .unwrap()
        );
        let reverse_matched = [MatchedPatchSection {
            previous: matched[0].current.clone(),
            current: matched[0].previous.clone(),
        }];
        assert!(
            archive_diff_allows_owned_macho_member_addition(
                &current,
                &previous,
                &input_file,
                &reverse_matched,
                &removed,
                &current_unwind,
                &previous_unwind,
            )
            .unwrap()
        );
    }

    fn test_macho_unowned_import_object(target_name: &[u8; 5]) -> Vec<u8> {
        const SYMTAB_COMMAND: usize = 32 + 72 + 2 * 80;
        const NLIST_64_SIZE: usize = 16;

        let mut object = test_macho_object_with_options(&[0; 4], &[0; 4], None, 0, b"__data", true);
        let symoff =
            read_u32_le(&object[SYMTAB_COMMAND + 8..SYMTAB_COMMAND + 12]).unwrap() as usize;
        let stroff =
            read_u32_le(&object[SYMTAB_COMMAND + 16..SYMTAB_COMMAND + 20]).unwrap() as usize;
        let target_symbol = symoff + NLIST_64_SIZE;
        object[target_symbol + 4] = object::macho::N_UNDF | object::macho::N_EXT;
        object[target_symbol + 5] = 0;
        object[target_symbol + 6..target_symbol + 8].fill(0);
        object[target_symbol + 8..target_symbol + 16].fill(0);
        let target_name_offset = stroff + b"\0_text\0".len();
        object[target_name_offset..target_name_offset + target_name.len()]
            .copy_from_slice(target_name);
        object
    }

    fn test_macho_archive(object: &[u8]) -> (Vec<u8>, std::ops::Range<usize>) {
        let mut builder = ar::Builder::new(Vec::new());
        builder
            .append(
                &ar::Header::new(b"crate-hash.cgu.old.rcgu.o".to_vec(), object.len() as u64),
                object,
            )
            .unwrap();
        let archive = builder.into_inner().unwrap();
        let mut entries = ArchiveIterator::from_archive_bytes(&archive).unwrap();
        let ArchiveEntry::Regular(member) = entries.next().unwrap().unwrap() else {
            panic!("expected regular archive member");
        };
        let range = test_macho_section_range(member.entry_data, "__text");
        let data_offset = member.data_offset;
        (archive, data_offset + range.start..data_offset + range.end)
    }

    fn test_macho_section_range(bytes: &[u8], name: &str) -> std::ops::Range<usize> {
        let file = object::File::parse(bytes).unwrap();
        let section = file.section_by_name(name).unwrap();
        let (offset, size) = section.file_range().unwrap();
        offset as usize..(offset + size) as usize
    }

    #[test]
    fn macho_symbol_value_ranges_follow_raw_nlist_indices() {
        let mut bytes = test_macho_object(b"\x01\x02\x03\x04", b"\x05\x06\x07\x08", 1);
        let first = macho_symbol_value_field_range(&bytes, object::SymbolIndex(0)).unwrap();
        let second = macho_symbol_value_field_range(&bytes, object::SymbolIndex(1)).unwrap();

        assert_eq!(&bytes[first.clone()], &0_u64.to_le_bytes());
        assert_eq!(&bytes[second.clone()], &5_u64.to_le_bytes());

        let first_entry = first.start - 8;
        bytes[first_entry + 4] = object::macho::N_STAB;
        let file = object::File::parse(bytes.as_slice()).unwrap();
        let symbols = file.symbols().collect::<Vec<_>>();
        assert_eq!(symbols.len(), 1);
        assert_eq!(symbols[0].index(), object::SymbolIndex(1));
        assert_eq!(
            macho_symbol_value_field_range(&bytes, symbols[0].index()),
            Some(second)
        );
        assert!(macho_symbol_value_field_range(&bytes, object::SymbolIndex(2)).is_none());
    }

    #[test]
    fn output_symbol_value_patches_macho_nlist64() {
        let output = test_macho_object(b"\x01\x02\x03\x04", b"\x05\x06\x07\x08", 0);
        let value_range = macho_symbol_value_field_range(&output, object::SymbolIndex(1)).unwrap();

        let patches = output_symbol_value_patches(
            &output,
            &[RelocationTargetSymbolPatch {
                target_name: hex::encode(b"_data"),
                previous_target_value: 4,
                target_value: 8,
                allow_missing: true,
                source: "test",
            }],
        )
        .unwrap()
        .unwrap();

        assert_eq!(patches.len(), 1);
        assert_eq!(patches[0].output_offset, value_range.start as u64);
        assert_eq!(patches[0].data, 8_u64.to_le_bytes());
    }

    fn test_macho_chained_fixup_table(page_start: u16) -> Vec<u8> {
        let mut table = vec![0; 128];
        let starts_offset = 32;
        let segment_offset = 24;
        let segment_start = starts_offset + segment_offset;
        write_macho_chained_fixup_u32(&mut table, 0, 0).unwrap();
        write_macho_chained_fixup_u32(&mut table, 4, starts_offset as u32).unwrap();
        write_macho_chained_fixup_u32(
            &mut table,
            starts_offset,
            crate::macho::DEFAULT_SEGMENT_COUNT as u32,
        )
        .unwrap();
        write_macho_chained_fixup_u32(
            &mut table,
            starts_offset + 4 * (MACHO_DATA_SEGMENT_CHAIN_INDEX + 1),
            segment_offset as u32,
        )
        .unwrap();
        write_macho_chained_fixup_u32(&mut table, segment_start, 24).unwrap();
        write_macho_chained_fixup_u16(
            &mut table,
            segment_start + 4,
            crate::macho::MACHO_PAGE_SIZE as u16,
        )
        .unwrap();
        write_macho_chained_fixup_u16(
            &mut table,
            segment_start + 6,
            MACHO_CHAINED_PTR_FORMAT_64_OFFSET,
        )
        .unwrap();
        write_macho_chained_fixup_u64(&mut table, segment_start + 8, 0x4000).unwrap();
        write_macho_chained_fixup_u16(&mut table, segment_start + 20, 1).unwrap();
        write_macho_chained_fixup_u16(&mut table, segment_start + 22, page_start).unwrap();
        table
    }

    #[test]
    fn macho_chained_fixup_slots_follow_next_strides() {
        let data_address = crate::macho::MACHO_START_MEM_ADDRESS + 0x4000;
        let data_file_offset = 0x100;
        let mut output = vec![0; data_file_offset + crate::macho::MACHO_PAGE_SIZE as usize];
        let first = encode_incremental_macho_chained_rebase(data_address + 0x100, 4).unwrap();
        let second = encode_incremental_macho_chained_rebase(data_address + 0x200, 0).unwrap();
        output[data_file_offset + 0x20..data_file_offset + 0x28]
            .copy_from_slice(&first.to_le_bytes());
        output[data_file_offset + 0x30..data_file_offset + 0x38]
            .copy_from_slice(&second.to_le_bytes());

        let slots = read_macho_chained_fixup_slots(
            &output,
            &test_macho_chained_fixup_table(0x20),
            data_address,
            crate::macho::MACHO_PAGE_SIZE,
            data_file_offset as u64,
            crate::macho::MACHO_PAGE_SIZE,
        )
        .unwrap();

        assert_eq!(
            slots
                .iter()
                .map(|slot| (slot.address, slot.output_offset, slot.value))
                .collect::<Vec<_>>(),
            vec![
                (data_address + 0x20, (data_file_offset + 0x20) as u64, first),
                (
                    data_address + 0x30,
                    (data_file_offset + 0x30) as u64,
                    second
                ),
            ]
        );
    }

