    #[test]
    fn replacement_macho_unwind_entries_require_exact_owned_ranges() {
        let entry = |function_offset, length, encoding| crate::macho_writer::UnwindInfoEntry {
            function_offset,
            length,
            encoding,
            personality_offset: None,
            lsda_offset: None,
        };
        let previous = vec![
            entry(0x100, 0x20, ADDED_MACHO_UNWIND_MODE_DWARF),
            entry(0x120, 0xe0, 0),
            entry(0x200, 0x30, 0x0200_0000),
        ];
        let retired = MachOUnwindFunctionIdentity {
            function_offset: 0x100,
            length: 0x20,
        };
        let replacement = entry(0x100, 0x28, 0x0400_0000);

        assert_eq!(
            merge_macho_unwind_info_entries(previous.clone(), &[retired], vec![replacement])
                .unwrap(),
            vec![replacement, previous[2]],
        );
        assert!(
            merge_macho_unwind_info_entries(
                previous.clone(),
                &[MachOUnwindFunctionIdentity {
                    function_offset: 0x100,
                    length: 0x18,
                }],
                vec![replacement],
            )
            .unwrap_err()
            .contains("partially overlaps"),
        );
        assert!(
            merge_macho_unwind_info_entries(
                previous.clone(),
                &[MachOUnwindFunctionIdentity {
                    function_offset: 0x180,
                    length: 0x10,
                }],
                vec![replacement],
            )
            .unwrap_err()
            .contains("does not match exactly one"),
        );
        assert!(
            merge_macho_unwind_info_entries(
                previous.clone(),
                &[retired, retired],
                vec![replacement],
            )
            .unwrap_err()
            .contains("duplicate identity"),
        );
        assert!(
            merge_macho_unwind_info_entries(
                vec![previous[0], previous[0], previous[2]],
                &[retired],
                vec![replacement],
            )
            .unwrap_err()
            .contains("does not match exactly one"),
        );
        assert!(
            merge_macho_unwind_info_entries(
                previous,
                &[retired],
                vec![entry(0x1f0, 0x20, 0x0400_0000)],
            )
            .unwrap_err()
            .contains("overlaps an existing live entry"),
        );
    }

    #[test]
    fn changed_macho_archive_unwind_members_record_exact_replacement_proof() {
        let previous_object = test_observed_049_macho_unwind_object(false);
        let current_object = test_observed_049_macho_unwind_object(true);
        let input_file_path = hex::encode("input.rlib");
        let archive = |identifier: &[u8], object: &[u8]| {
            let mut builder = ar::Builder::new(Vec::new());
            builder
                .append(
                    &ar::Header::new(identifier.to_vec(), object.len() as u64),
                    object,
                )
                .unwrap();
            let bytes = builder.into_inner().unwrap();
            let mut entries = ArchiveIterator::from_archive_bytes(&bytes).unwrap();
            let ArchiveEntry::Regular(member) = entries.next().unwrap().unwrap() else {
                panic!("expected regular archive member");
            };
            let input_ref = resolved_patch_input_ref(
                &input_file_path,
                &input_file_path,
                PatchInputBytes {
                    bytes: member.entry_data,
                    file_offset: member.data_offset,
                    archive_identifier: Some(member.ident.as_slice()),
                },
            )
            .unwrap();
            (bytes, input_ref)
        };
        let previous_identifier = b"crate-hash.codegen.previous.rcgu.o";
        let current_identifier = b"crate-hash.codegen.current.rcgu.o";
        let (previous_archive, previous_input) = archive(previous_identifier, &previous_object);
        let (current_archive, current_input) = archive(current_identifier, &current_object);

        let previous_file = object::File::parse(previous_object.as_slice()).unwrap();
        let current_file = object::File::parse(current_object.as_slice()).unwrap();
        let previous_text = previous_file.section_by_name("__text").unwrap();
        let current_text = current_file.section_by_name("__text").unwrap();
        let output = test_macho_unwind_output(0x1000);
        let matched = vec![MatchedPatchSection {
            previous: PatchSection {
                input: previous_input,
                section_index: patch_section_record_index(&previous_file, previous_text.index())
                    .unwrap(),
                section_name: Some("__TEXT,__text".to_owned()),
                input_size: previous_text.size(),
                output_offset: output.text_offset + 0x100,
                output_size: previous_text.size(),
                data_hash: None,
                cstring_nul_boundaries_hash: None,
            },
            current: PatchSection {
                input: current_input,
                section_index: patch_section_record_index(&current_file, current_text.index())
                    .unwrap(),
                section_name: Some("__TEXT,__text".to_owned()),
                input_size: current_text.size(),
                output_offset: output.text_offset + 0x100,
                output_size: current_text.size(),
                data_hash: None,
                cstring_nul_boundaries_hash: None,
            },
        }];
        let current_resolver = PatchInputResolver::new(&current_archive, true).unwrap();
        let output_file = object::File::parse(output.bytes.as_slice()).unwrap();

        let changed = changed_macho_archive_unwind_members(
            &previous_archive,
            &input_file_path,
            &matched,
            &current_resolver,
            &output_file,
            &[],
        )
        .unwrap()
        .unwrap();
        assert_eq!(changed.members.len(), 1);
        assert_eq!(changed.previous_input_ranges.len(), 2);
        assert_eq!(changed.current_input_ranges.len(), 2);
        assert_eq!(changed.retired_entries.len(), 1);
        assert!(
            changed.retired_entries.windows(2).all(|pair| {
                pair[0].function_offset + pair[0].length <= pair[1].function_offset
            })
        );

        let excluded = changed_macho_archive_unwind_members(
            &previous_archive,
            &input_file_path,
            &matched,
            &current_resolver,
            &output_file,
            &[archive_member_patch_identifier(current_identifier)],
        )
        .unwrap()
        .unwrap();
        assert!(excluded.members.is_empty());
        assert!(excluded.retired_entries.is_empty());
        assert!(excluded.previous_input_ranges.is_empty());
        assert!(excluded.current_input_ranges.is_empty());
    }

    #[test]
    fn changed_macho_archive_unwind_proof_composes_with_member_set_changes() {
        let previous_object = test_observed_049_macho_unwind_object(false);
        let mut current_object = previous_object.clone();
        let (compact_length_offset, eh_frame_length_offset, text_offset) = {
            let file = object::File::parse(current_object.as_slice()).unwrap();
            let compact = file.section_by_name("__compact_unwind").unwrap();
            let eh_frame = file.section_by_name("__eh_frame").unwrap();
            let (compact_offset, _) = compact.file_range().unwrap();
            let (eh_frame_offset, _) = eh_frame.file_range().unwrap();
            (
                compact_offset as usize
                    + compact
                        .data()
                        .unwrap()
                        .windows(4)
                        .position(|bytes| bytes == 0x258_u32.to_le_bytes())
                        .unwrap(),
                eh_frame_offset as usize
                    + eh_frame
                        .data()
                        .unwrap()
                        .windows(8)
                        .position(|bytes| bytes == 0x258_u64.to_le_bytes())
                        .unwrap(),
                file.section_by_name("__text")
                    .unwrap()
                    .file_range()
                    .unwrap()
                    .0 as usize,
            )
        };
        current_object[compact_length_offset..compact_length_offset + 4]
            .copy_from_slice(&0x250_u32.to_le_bytes());
        current_object[eh_frame_length_offset..eh_frame_length_offset + 8]
            .copy_from_slice(&0x250_u64.to_le_bytes());
        current_object[text_offset] ^= 1;
        let local_entry = macho_symbol_value_field_range(&current_object, object::SymbolIndex(1))
            .unwrap()
            .start
            - 8;
        assert_eq!(current_object[local_entry + 4] & object::macho::N_EXT, 0);
        current_object[local_entry + 4] |= object::macho::N_STAB;

        let removed_object = test_macho_object(b"removed", b"data", 0);
        let previous_identifier = b"crate-hash.codegen.previous.rcgu.o";
        let current_identifier = b"crate-hash.codegen.current.rcgu.o";
        let removed_identifier = b"crate-hash.removed.previous.rcgu.o";
        let archive = |members: &[(&[u8], &[u8])]| {
            let mut builder = ar::Builder::new(Vec::new());
            for (identifier, object) in members {
                builder
                    .append(
                        &ar::Header::new(identifier.to_vec(), object.len() as u64),
                        *object,
                    )
                    .unwrap();
            }
            builder.into_inner().unwrap()
        };
        let previous_archive = archive(&[
            (previous_identifier, previous_object.as_slice()),
            (removed_identifier, removed_object.as_slice()),
        ]);
        let current_archive = archive(&[(current_identifier, current_object.as_slice())]);
        let input_file_path = hex::encode("input.rlib");
        let input_ref = |archive: &[u8], identifier: &[u8]| {
            let ArchiveMemberMatch::Unique(member) =
                patch_archive_member_bytes(archive, identifier).unwrap()
            else {
                panic!("expected unique archive member");
            };
            resolved_patch_input_ref(&input_file_path, &input_file_path, member).unwrap()
        };
        let previous_file = object::File::parse(previous_object.as_slice()).unwrap();
        let current_file = object::File::parse(current_object.as_slice()).unwrap();
        let previous_text = previous_file.section_by_name("__text").unwrap();
        let current_text = current_file.section_by_name("__text").unwrap();
        let output = test_macho_unwind_output(0x1000);
        let matched = vec![MatchedPatchSection {
            previous: PatchSection {
                input: input_ref(&previous_archive, previous_identifier),
                section_index: patch_section_record_index(&previous_file, previous_text.index())
                    .unwrap(),
                section_name: Some("__TEXT,__text".to_owned()),
                input_size: previous_text.size(),
                output_offset: output.text_offset + 0x100,
                output_size: previous_text.size(),
                data_hash: None,
                cstring_nul_boundaries_hash: None,
            },
            current: PatchSection {
                input: input_ref(&current_archive, current_identifier),
                section_index: patch_section_record_index(&current_file, current_text.index())
                    .unwrap(),
                section_name: Some("__TEXT,__text".to_owned()),
                input_size: current_text.size(),
                output_offset: output.text_offset + 0x100,
                output_size: current_text.size(),
                data_hash: None,
                cstring_nul_boundaries_hash: None,
            },
        }];
        let current_resolver = PatchInputResolver::new(&current_archive, true).unwrap();
        let output_file = object::File::parse(output.bytes.as_slice()).unwrap();
        let retired_identifiers = vec![archive_member_patch_identifier(removed_identifier)];
        let changed = changed_macho_archive_unwind_members(
            &previous_archive,
            &input_file_path,
            &matched,
            &current_resolver,
            &output_file,
            &retired_identifiers,
        )
        .unwrap()
        .unwrap();

        assert!(
            !archive_diff_allows_changed_macho_unwind(
                &previous_archive,
                &current_archive,
                &input_file_path,
                &matched,
                &current_resolver,
                &changed,
                &[],
                &[],
            )
            .unwrap(),
            "ordinary unwind replacement must not ignore removed members or local symbols",
        );
        assert!(
            archive_diff_allows_changed_macho_unwind(
                &previous_archive,
                &current_archive,
                &input_file_path,
                &matched,
                &current_resolver,
                &changed,
                &retired_identifiers,
                &[],
            )
            .unwrap(),
            "retirement proof should ignore only the retired member and masked local definition",
        );

        let reverse_matched = matched
            .iter()
            .map(|section| MatchedPatchSection {
                previous: section.current.clone(),
                current: section.previous.clone(),
            })
            .collect::<Vec<_>>();
        let reverse_resolver = PatchInputResolver::new(&previous_archive, true).unwrap();
        let reverse_changed = changed_macho_archive_unwind_members(
            &current_archive,
            &input_file_path,
            &reverse_matched,
            &reverse_resolver,
            &output_file,
            &[],
        )
        .unwrap()
        .unwrap();
        assert!(
            !archive_diff_allows_changed_macho_unwind(
                &current_archive,
                &previous_archive,
                &input_file_path,
                &reverse_matched,
                &reverse_resolver,
                &reverse_changed,
                &[],
                &[],
            )
            .unwrap(),
            "ordinary unwind replacement must not ignore added members or local symbols",
        );
        assert!(
            archive_diff_allows_changed_macho_unwind(
                &current_archive,
                &previous_archive,
                &input_file_path,
                &reverse_matched,
                &reverse_resolver,
                &reverse_changed,
                &[],
                &retired_identifiers,
            )
            .unwrap(),
            "addition proof should ignore only the added member and masked local definition",
        );
    }

    #[test]
    fn matched_macho_definition_resolution_refreshes_member_input() {
        let object = test_macho_object(b"text", b"data", 0);
        let previous_identifier = b"crate-hash.codegen.previous.rcgu.o";
        let current_identifier = b"crate-hash.codegen.current.rcgu.o";
        let mut builder = ar::Builder::new(Vec::new());
        builder
            .append(
                &ar::Header::new(current_identifier.to_vec(), object.len() as u64),
                object.as_slice(),
            )
            .unwrap();
        let archive = builder.into_inner().unwrap();
        let mut entries = ArchiveIterator::from_archive_bytes(&archive).unwrap();
        let ArchiveEntry::Regular(member) = entries.next().unwrap().unwrap() else {
            panic!("expected regular archive member");
        };
        let input_file_path = hex::encode("input.rlib");
        let stale_input = resolved_patch_input_ref(
            &input_file_path,
            &input_file_path,
            PatchInputBytes {
                bytes: member.entry_data,
                file_offset: member.data_offset,
                archive_identifier: Some(previous_identifier),
            },
        )
        .unwrap();
        let current_input = resolved_patch_input_ref(
            &input_file_path,
            &input_file_path,
            PatchInputBytes {
                bytes: member.entry_data,
                file_offset: member.data_offset,
                archive_identifier: Some(current_identifier),
            },
        )
        .unwrap();
        assert_ne!(stale_input, current_input);

        let file = object::File::parse(object.as_slice()).unwrap();
        let text = file.section_by_name("__text").unwrap();
        let output = test_macho_unwind_output(0x1000);
        let matched = vec![MatchedPatchSection {
            previous: PatchSection {
                input: stale_input.clone(),
                section_index: patch_section_record_index(&file, text.index()).unwrap(),
                section_name: Some("__TEXT,__text".to_owned()),
                input_size: text.size(),
                output_offset: output.text_offset + 0x100,
                output_size: text.size(),
                data_hash: None,
                cstring_nul_boundaries_hash: None,
            },
            current: PatchSection {
                input: stale_input,
                section_index: patch_section_record_index(&file, text.index()).unwrap(),
                section_name: Some("__TEXT,__text".to_owned()),
                input_size: text.size(),
                output_offset: output.text_offset + 0x100,
                output_size: text.size(),
                data_hash: None,
                cstring_nul_boundaries_hash: None,
            },
        }];
        let current_resolver = PatchInputResolver::new(&archive, true).unwrap();
        let output_file = object::File::parse(output.bytes.as_slice()).unwrap();

        let resolution = matched_macho_definition_resolution(
            &input_file_path,
            b"_text",
            &matched,
            &current_resolver,
            &output_file,
        )
        .unwrap()
        .unwrap()
        .unwrap();
        assert_eq!(resolution.target.unwrap().input.as_str(), current_input);
    }

    #[test]
    fn changed_macho_archive_unwind_activation_replaces_existing_entries() {
        let previous_object = test_observed_049_macho_unwind_object(false);
        let replace_unwind_length =
            |mut object: Vec<u8>, previous_length: u32, current_length: u32| {
                let (compact_length_offset, eh_frame_length_offset, text_offset) = {
                    let file = object::File::parse(object.as_slice()).unwrap();
                    let compact = file.section_by_name("__compact_unwind").unwrap();
                    let eh_frame = file.section_by_name("__eh_frame").unwrap();
                    let (compact_offset, _) = compact.file_range().unwrap();
                    let (eh_frame_offset, _) = eh_frame.file_range().unwrap();
                    let compact_length = compact
                        .data()
                        .unwrap()
                        .windows(4)
                        .position(|bytes| bytes == previous_length.to_le_bytes())
                        .unwrap();
                    let eh_frame_length = eh_frame
                        .data()
                        .unwrap()
                        .windows(8)
                        .position(|bytes| bytes == u64::from(previous_length).to_le_bytes())
                        .unwrap();
                    (
                        compact_offset as usize + compact_length,
                        eh_frame_offset as usize + eh_frame_length,
                        file.section_by_name("__text")
                            .unwrap()
                            .file_range()
                            .unwrap()
                            .0 as usize,
                    )
                };
                object[compact_length_offset..compact_length_offset + 4]
                    .copy_from_slice(&current_length.to_le_bytes());
                object[eh_frame_length_offset..eh_frame_length_offset + 8]
                    .copy_from_slice(&u64::from(current_length).to_le_bytes());
                object[text_offset] ^= 1;
                object
            };
        let current_object = replace_unwind_length(previous_object.clone(), 0x258_u32, 0x250_u32);
        let next_object = replace_unwind_length(current_object.clone(), 0x250_u32, 0x248_u32);

        let input_file_path = hex::encode("input.rlib");
        let archive = |identifier: &[u8], object: &[u8]| {
            let mut builder = ar::Builder::new(Vec::new());
            builder
                .append(
                    &ar::Header::new(identifier.to_vec(), object.len() as u64),
                    object,
                )
                .unwrap();
            let bytes = builder.into_inner().unwrap();
            let mut entries = ArchiveIterator::from_archive_bytes(&bytes).unwrap();
            let ArchiveEntry::Regular(member) = entries.next().unwrap().unwrap() else {
                panic!("expected regular archive member");
            };
            let input_ref = resolved_patch_input_ref(
                &input_file_path,
                &input_file_path,
                PatchInputBytes {
                    bytes: member.entry_data,
                    file_offset: member.data_offset,
                    archive_identifier: Some(member.ident.as_slice()),
                },
            )
            .unwrap();
            (bytes, input_ref)
        };
        let (previous_archive, previous_input) = archive(
            b"crate-hash.codegen.previous.rcgu.o",
            previous_object.as_slice(),
        );
        let (current_archive, current_input) = archive(
            b"crate-hash.codegen.current.rcgu.o",
            current_object.as_slice(),
        );
        let (next_archive, next_input) =
            archive(b"crate-hash.codegen.next.rcgu.o", next_object.as_slice());
        let previous_file = object::File::parse(previous_object.as_slice()).unwrap();
        let current_file = object::File::parse(current_object.as_slice()).unwrap();
        let next_file = object::File::parse(next_object.as_slice()).unwrap();
        let previous_text = previous_file.section_by_name("__text").unwrap();
        let current_text = current_file.section_by_name("__text").unwrap();
        let next_text = next_file.section_by_name("__text").unwrap();

        let mut output = test_macho_unwind_output(0x1000);
        let (previous_member, mut previous_sections) = test_added_macho_unwind_member(false);
        previous_sections[0].output_offset = output.text_offset + 0x100;
        let mut reserves = vec![ReservedRangeRecord {
            output_section_id: crate::output_section_id::EH_FRAME.as_usize() as u32,
            alignment_exponent: 3,
            output_offset: output.eh_frame_offset,
            size: output.eh_frame_size,
        }];
        let initial = {
            let output_file = object::File::parse(output.bytes.as_slice()).unwrap();
            added_macho_archive_unwind_activation(
                std::slice::from_ref(&previous_member),
                &[0],
                &previous_sections,
                &output_file,
                &[],
                &[],
                &mut reserves,
            )
            .unwrap()
            .unwrap()
            .unwrap()
        };
        apply_test_section_patches(&mut output.bytes, &initial.patches);
        let reserve_after_initial = reserves[0].clone();

        let matched = vec![MatchedPatchSection {
            previous: PatchSection {
                input: previous_input,
                section_index: patch_section_record_index(&previous_file, previous_text.index())
                    .unwrap(),
                section_name: Some("__TEXT,__text".to_owned()),
                input_size: previous_text.size(),
                output_offset: output.text_offset + 0x100,
                output_size: previous_text.size(),
                data_hash: None,
                cstring_nul_boundaries_hash: None,
            },
            current: PatchSection {
                input: current_input.clone(),
                section_index: patch_section_record_index(&current_file, current_text.index())
                    .unwrap(),
                section_name: Some("__TEXT,__text".to_owned()),
                input_size: current_text.size(),
                output_offset: output.text_offset + 0x100,
                output_size: current_text.size(),
                data_hash: None,
                cstring_nul_boundaries_hash: None,
            },
        }];
        let current_sections = matched
            .iter()
            .map(|section| section.current.clone())
            .collect::<Vec<_>>();
        let current_resolver = PatchInputResolver::new(&current_archive, true).unwrap();
        let activation = changed_macho_archive_unwind_activation(
            &previous_archive,
            &current_archive,
            &input_file_path,
            &matched,
            &current_sections,
            &current_resolver,
            &output.bytes,
            &[],
            &reserves,
            &[],
            &[],
            false,
            &[],
            &[],
        )
        .unwrap()
        .unwrap()
        .unwrap();

        assert_eq!(activation.patches.len(), 2);
        assert_eq!(
            activation.remaining_reserved_ranges,
            vec![ReservedRangeRecord {
                output_offset: reserve_after_initial.output_offset + 72,
                size: reserve_after_initial.size - 72,
                ..reserve_after_initial
            }]
        );
        let unwind_info = activation
            .patches
            .iter()
            .find(|patch| patch.output_offset == output.unwind_info_offset)
            .unwrap();
        let live_entries = crate::macho_writer::parse_macho_unwind_info(&unwind_info.data)
            .unwrap()
            .into_iter()
            .filter(|entry| entry.encoding != 0)
            .collect::<Vec<_>>();
        assert_eq!(live_entries.len(), 1);
        assert_eq!(live_entries[0].length, 0x250);
        apply_test_section_patches(&mut output.bytes, &activation.patches);
        assert_eq!(
            eh_frame_terminator_offset(
                &output.bytes[output.eh_frame_offset as usize
                    ..(output.eh_frame_offset + output.eh_frame_size) as usize]
            ),
            Some(144)
        );

        let next_matched = vec![MatchedPatchSection {
            previous: PatchSection {
                input: current_input.clone(),
                section_index: patch_section_record_index(&current_file, current_text.index())
                    .unwrap(),
                section_name: Some("__TEXT,__text".to_owned()),
                input_size: current_text.size(),
                output_offset: output.text_offset + 0x100,
                output_size: current_text.size(),
                data_hash: None,
                cstring_nul_boundaries_hash: None,
            },
            current: PatchSection {
                input: next_input,
                section_index: patch_section_record_index(&next_file, next_text.index()).unwrap(),
                section_name: Some("__TEXT,__text".to_owned()),
                input_size: next_text.size(),
                output_offset: output.text_offset + 0x100,
                output_size: next_text.size(),
                data_hash: None,
                cstring_nul_boundaries_hash: None,
            },
        }];
        let next_sections = next_matched
            .iter()
            .map(|section| section.current.clone())
            .collect::<Vec<_>>();
        let next_resolver = PatchInputResolver::new(&next_archive, true).unwrap();
        let next_activation = changed_macho_archive_unwind_activation(
            &current_archive,
            &next_archive,
            &input_file_path,
            &next_matched,
            &next_sections,
            &next_resolver,
            &output.bytes,
            &[],
            &activation.remaining_reserved_ranges,
            &[],
            &[],
            false,
            &[],
            &[],
        )
        .unwrap()
        .unwrap()
        .unwrap();
        assert_eq!(next_activation.patches.len(), 2);
        assert_eq!(
            next_activation.remaining_reserved_ranges,
            vec![ReservedRangeRecord {
                output_offset: reserve_after_initial.output_offset + 144,
                size: reserve_after_initial.size - 144,
                ..reserve_after_initial.clone()
            }]
        );
        let next_eh_frame = next_activation
            .patches
            .iter()
            .find(|patch| {
                patch.output_offset == reserve_after_initial.output_offset + 72 && patch.size == 72
            })
            .unwrap();
        assert_eq!(next_eh_frame.data.len(), 72);
        let next_unwind_info = next_activation
            .patches
            .iter()
            .find(|patch| patch.output_offset == output.unwind_info_offset)
            .unwrap();
        let next_live_entries =
            crate::macho_writer::parse_macho_unwind_info(&next_unwind_info.data)
                .unwrap()
                .into_iter()
                .filter(|entry| entry.encoding != 0)
                .collect::<Vec<_>>();
        assert_eq!(next_live_entries.len(), 1);
        assert_eq!(next_live_entries[0].length, 0x248);
        apply_test_section_patches(&mut output.bytes, &next_activation.patches);
        assert_eq!(
            eh_frame_terminator_offset(
                &output.bytes[output.eh_frame_offset as usize
                    ..(output.eh_frame_offset + output.eh_frame_size) as usize]
            ),
            Some(216)
        );

        let mut unrelated_change = current_object;
        unrelated_change[24] ^= 1;
        let (unrelated_archive, _) = archive(
            b"crate-hash.codegen.current.rcgu.o",
            unrelated_change.as_slice(),
        );
        let unrelated_resolver = PatchInputResolver::new(&unrelated_archive, true).unwrap();
        let unrelated = changed_macho_archive_unwind_activation(
            &previous_archive,
            &unrelated_archive,
            &input_file_path,
            &matched,
            &current_sections,
            &unrelated_resolver,
            &output.bytes,
            &[],
            &reserves,
            &[],
            &[],
            false,
            &[],
            &[],
        )
        .unwrap();
        assert!(matches!(
            unrelated,
            Err(reason)
                if reason
                    == "changed Mach-O archive member differs outside text and unwind metadata"
        ));
    }

    #[test]
    fn added_macho_archive_unwind_activation_advances_terminator_and_rolls_back() {
        let (mut member, mut sections) = test_added_macho_unwind_member(false);
        let compact = member
            .unwind
            .as_mut()
            .unwrap()
            .compact_unwind
            .as_mut()
            .unwrap();
        compact.entries[0].encoding |=
            ADDED_MACHO_UNWIND_PERSONALITY_MASK | ADDED_MACHO_UNWIND_HAS_LSDA;
        let mut output = test_macho_unwind_output(0x1000);
        sections[0].output_offset = output.text_offset + 0x100;
        let original_reserve = ReservedRangeRecord {
            output_section_id: crate::output_section_id::EH_FRAME.as_usize() as u32,
            alignment_exponent: 3,
            output_offset: output.eh_frame_offset,
            size: 144,
        };
        let mut reserves = vec![original_reserve.clone()];

        let first = {
            let output_file = object::File::parse(output.bytes.as_slice()).unwrap();
            added_macho_archive_unwind_activation(
                std::slice::from_ref(&member),
                &[0],
                &sections,
                &output_file,
                &[],
                &[],
                &mut reserves,
            )
            .unwrap()
            .unwrap()
            .unwrap()
        };
        assert_eq!(first.patches.len(), 2);
        let first_eh_frame = first
            .patches
            .iter()
            .find(|patch| patch.output_offset == output.eh_frame_offset)
            .unwrap();
        assert_eq!(first_eh_frame.size, 72);
        let first_unwind_info = first
            .patches
            .iter()
            .find(|patch| patch.output_offset == output.unwind_info_offset)
            .unwrap();
        let first_unwind_entries =
            crate::macho_writer::parse_macho_unwind_info(&first_unwind_info.data).unwrap();
        let first_live_entry = first_unwind_entries
            .iter()
            .find(|entry| entry.encoding != 0)
            .unwrap();
        assert_eq!(
            first_live_entry.encoding & ADDED_MACHO_UNWIND_MODE_MASK,
            ADDED_MACHO_UNWIND_MODE_DWARF
        );
        assert_eq!(
            first_live_entry.encoding
                & (ADDED_MACHO_UNWIND_PERSONALITY_MASK | ADDED_MACHO_UNWIND_HAS_LSDA),
            0
        );
        assert_eq!(first_live_entry.personality_offset, None);
        assert_eq!(first_live_entry.lsda_offset, None);
        assert_eq!(
            reserves,
            vec![ReservedRangeRecord {
                output_section_id: crate::output_section_id::EH_FRAME.as_usize() as u32,
                alignment_exponent: 3,
                output_offset: output.eh_frame_offset + 72,
                size: 72,
            }]
        );
        apply_test_section_patches(&mut output.bytes, &first.patches);
        assert_eq!(
            eh_frame_terminator_offset(
                &output.bytes[output.eh_frame_offset as usize
                    ..(output.eh_frame_offset + output.eh_frame_size) as usize]
            ),
            Some(72)
        );

        let overlap_reserves = reserves.clone();
        let overlap_result = {
            let output_file = object::File::parse(output.bytes.as_slice()).unwrap();
            added_macho_archive_unwind_activation(
                std::slice::from_ref(&member),
                &[0],
                &sections,
                &output_file,
                &[],
                &[],
                &mut reserves,
            )
            .unwrap()
        };
        let overlap = match overlap_result {
            Err(reason) => reason,
            Ok(_) => panic!("expected overlapping unwind activation to fail"),
        };
        assert!(overlap.contains("overlaps an existing live entry"));
        assert_eq!(reserves, overlap_reserves);

        sections[0].output_offset = output.text_offset + 0x400;
        let second = {
            let output_file = object::File::parse(output.bytes.as_slice()).unwrap();
            added_macho_archive_unwind_activation(
                std::slice::from_ref(&member),
                &[0],
                &sections,
                &output_file,
                &[],
                &[],
                &mut reserves,
            )
            .unwrap()
            .unwrap()
            .unwrap()
        };
        let second_eh_frame = second
            .patches
            .iter()
            .find(|patch| patch.output_offset == output.eh_frame_offset + 72)
            .unwrap();
        assert_eq!(second_eh_frame.size, 72);
        assert!(reserves.is_empty());
        apply_test_section_patches(&mut output.bytes, &second.patches);
        assert_eq!(
            eh_frame_terminator_offset(
                &output.bytes[output.eh_frame_offset as usize
                    ..(output.eh_frame_offset + output.eh_frame_size) as usize]
            ),
            Some(144)
        );

        let mut gapped = test_macho_unwind_output(0x1000);
        let gapped_eh_frame = gapped.eh_frame_offset as usize;
        gapped.bytes[gapped_eh_frame..gapped_eh_frame + 4].copy_from_slice(&8_u32.to_le_bytes());
        let mut gapped_reserves = vec![ReservedRangeRecord {
            output_section_id: crate::output_section_id::EH_FRAME.as_usize() as u32,
            alignment_exponent: 3,
            output_offset: gapped.eh_frame_offset + 16,
            size: 144,
        }];
        sections[0].output_offset = gapped.text_offset + 0x100;
        let gapped_activation = {
            let output_file = object::File::parse(gapped.bytes.as_slice()).unwrap();
            added_macho_archive_unwind_activation(
                std::slice::from_ref(&member),
                &[0],
                &sections,
                &output_file,
                &[],
                &[],
                &mut gapped_reserves,
            )
            .unwrap()
            .unwrap()
            .unwrap()
        };
        assert!(
            gapped_activation
                .patches
                .iter()
                .any(|patch| patch.output_offset == gapped.eh_frame_offset + 12 && patch.size == 72)
        );
        assert_eq!(
            gapped_reserves,
            vec![ReservedRangeRecord {
                output_section_id: crate::output_section_id::EH_FRAME.as_usize() as u32,
                alignment_exponent: 3,
                output_offset: gapped.eh_frame_offset + 88,
                size: 72,
            }]
        );
        apply_test_section_patches(&mut gapped.bytes, &gapped_activation.patches);
        assert_eq!(
            eh_frame_terminator_offset(
                &gapped.bytes[gapped.eh_frame_offset as usize
                    ..(gapped.eh_frame_offset + gapped.eh_frame_size) as usize]
            ),
            Some(84)
        );

        let too_small = test_macho_unwind_output(32);
        let mut insufficient_capacity_reserves = vec![ReservedRangeRecord {
            output_section_id: crate::output_section_id::EH_FRAME.as_usize() as u32,
            alignment_exponent: 3,
            output_offset: too_small.eh_frame_offset,
            size: 72,
        }];
        sections[0].output_offset = too_small.text_offset + 0x100;
        let before_failure = insufficient_capacity_reserves.clone();
        let failure_result = {
            let output_file = object::File::parse(too_small.bytes.as_slice()).unwrap();
            added_macho_archive_unwind_activation(
                std::slice::from_ref(&member),
                &[0],
                &sections,
                &output_file,
                &[],
                &[],
                &mut insufficient_capacity_reserves,
            )
            .unwrap()
        };
        let failure = match failure_result {
            Err(reason) => reason,
            Ok(_) => panic!("expected unwind-info capacity failure"),
        };
        assert!(failure.contains("__unwind_info allocation too small"));
        assert_eq!(insufficient_capacity_reserves, before_failure);
        assert_eq!(
            eh_frame_terminator_offset(
                &too_small.bytes[too_small.eh_frame_offset as usize
                    ..(too_small.eh_frame_offset + too_small.eh_frame_size) as usize]
            ),
            Some(0)
        );
    }

    #[test]
    fn added_macho_archive_unwind_activation_materializes_personality_and_lsda() {
        let (member, mut sections) = test_added_macho_unwind_member(true);
        let output = test_macho_unwind_output(0x1000);
        sections[0].output_offset = output.text_offset + 0x100;
        sections[1].output_offset = output.gcc_except_table_offset;
        let mut reserves = vec![ReservedRangeRecord {
            output_section_id: crate::output_section_id::EH_FRAME.as_usize() as u32,
            alignment_exponent: 3,
            output_offset: output.eh_frame_offset,
            size: 0x180,
        }];
        let resolution = MachOSymbolResolutionRecord {
            name: hex::encode(b"_rust_eh_personality").into(),
            direct_value: Some(crate::macho::MACHO_START_MEM_ADDRESS + 0x700),
            got_address: Some(crate::macho::MACHO_START_MEM_ADDRESS + 0x780),
            stub_address: None,
            thunk_addresses: Vec::new(),
            target: None,
        };
        let activation = {
            let output_file = object::File::parse(output.bytes.as_slice()).unwrap();
            added_macho_archive_unwind_activation(
                std::slice::from_ref(&member),
                &[0],
                &sections,
                &output_file,
                std::slice::from_ref(&resolution),
                &[],
                &mut reserves,
            )
            .unwrap()
            .unwrap()
            .unwrap()
        };
        let eh_frame_patch = activation
            .patches
            .iter()
            .find(|patch| patch.output_offset == output.eh_frame_offset)
            .unwrap();
        assert_eq!(eh_frame_patch.size, 168);
        let unwind_info_patch = activation
            .patches
            .iter()
            .find(|patch| patch.output_offset == output.unwind_info_offset)
            .unwrap();
        let entries =
            crate::macho_writer::parse_macho_unwind_info(&unwind_info_patch.data).unwrap();
        let live_entries = entries
            .iter()
            .filter(|entry| entry.encoding != 0)
            .collect::<Vec<_>>();
        assert_eq!(live_entries.len(), 2);
        assert!(live_entries.iter().any(|entry| {
            entry.personality_offset == Some(0x780) && entry.lsda_offset.is_some()
        }));

        let eh_frame = member.unwind.as_ref().unwrap().eh_frame.as_ref().unwrap();
        let personality = eh_frame
            .cies
            .iter()
            .find_map(|cie| cie.personality.as_ref())
            .unwrap();
        let personality_value = read_u32_le(
            &eh_frame_patch.data[personality.input_offset..personality.input_offset + 4],
        )
        .unwrap() as i32;
        let personality_field_address = crate::macho::MACHO_START_MEM_ADDRESS
            + output.eh_frame_offset
            + personality.input_offset as u64;
        assert_eq!(
            personality_value,
            (i128::from(resolution.got_address.unwrap())
                + i128::from(personality.relocation.explicit_addend)
                - i128::from(personality_field_address)) as i32
        );
        let lsda = eh_frame
            .fdes
            .iter()
            .find_map(|fde| fde.lsda.as_ref())
            .unwrap();
        let lsda_value =
            read_u64_le(&eh_frame_patch.data[lsda.input_offset..lsda.input_offset + 8]).unwrap();
        let AddedMachOArchiveUnwindTarget::Section(lsda_target) = &lsda.target else {
            panic!("expected section-defined LSDA target");
        };
        let signed_field_value = i64::from_le_bytes(lsda.relocation.field_value.to_le_bytes());
        let expected_lsda_value = i128::from(
            crate::macho::MACHO_START_MEM_ADDRESS
                + output.gcc_except_table_offset
                + lsda_target.section_offset,
        ) + i128::from(signed_field_value)
            + i128::from(lsda.relocation.explicit_addend)
            - i128::from(crate::macho::MACHO_START_MEM_ADDRESS + output.eh_frame_offset);
        assert_eq!(
            i128::from(i64::from_le_bytes(lsda_value.to_le_bytes())),
            expected_lsda_value
        );
    }

    fn test_added_macho_unwind_member(
        with_personality: bool,
    ) -> (AddedMachOArchiveTextMember, Vec<PatchSection>) {
        let bytes = test_observed_049_macho_unwind_object(with_personality);
        let file = object::File::parse(bytes.as_slice()).unwrap();
        let text = file.section_by_name("__text").unwrap();
        let gcc_except_table = file.section_by_name("__gcc_except_tab").unwrap();
        let unwind = added_macho_archive_unwind(&file).unwrap().unwrap().unwrap();
        let input = "added.o".to_owned();
        let text_section_index = patch_section_record_index(&file, text.index()).unwrap();
        let sections = vec![
            PatchSection {
                input: input.clone(),
                section_index: text_section_index,
                section_name: Some("__TEXT,__text".to_owned()),
                input_size: text.size(),
                output_offset: 0,
                output_size: text.size(),
                data_hash: None,
                cstring_nul_boundaries_hash: None,
            },
            PatchSection {
                input: input.clone(),
                section_index: patch_section_record_index(&file, gcc_except_table.index()).unwrap(),
                section_name: Some("__TEXT,__gcc_except_tab".to_owned()),
                input_size: gcc_except_table.size(),
                output_offset: 0,
                output_size: gcc_except_table.size(),
                data_hash: None,
                cstring_nul_boundaries_hash: None,
            },
        ];
        (
            AddedMachOArchiveTextMember {
                input,
                sections: Vec::new(),
                unwind: Some(unwind),
                text_section_index,
                text_object_section_index: relocation_target_record_index(text.index()).unwrap(),
                definitions: vec![AddedMachOArchiveDefinition {
                    name: b"_function0".to_vec(),
                    offset: 0,
                    desc: 0,
                    private_external: false,
                }],
                referenced_names: Vec::new(),
            },
            sections,
        )
    }

    struct TestMachOUnwindOutput {
        bytes: Vec<u8>,
        text_offset: u64,
        gcc_except_table_offset: u64,
        eh_frame_offset: u64,
        eh_frame_size: u64,
        unwind_info_offset: u64,
    }

    fn test_macho_unwind_output(unwind_info_size: usize) -> TestMachOUnwindOutput {
        const HEADER_SIZE: usize = 32;
        const SEGMENT_COMMAND_SIZE: usize = 72;
        const SECTION_SIZE: usize = 80;
        const SECTION_COUNT: usize = 4;
        const TEXT_SIZE: usize = 0x800;
        const GCC_EXCEPT_TABLE_SIZE: usize = 0x100;
        const EH_FRAME_SIZE: usize = 0x200;

        let commands_size = SEGMENT_COMMAND_SIZE + SECTION_COUNT * SECTION_SIZE;
        let text_offset = HEADER_SIZE + commands_size;
        let gcc_except_table_offset = text_offset + TEXT_SIZE;
        let eh_frame_offset = gcc_except_table_offset + GCC_EXCEPT_TABLE_SIZE;
        let unwind_info_offset = eh_frame_offset + EH_FRAME_SIZE;
        let file_size = unwind_info_offset + unwind_info_size;
        let image_start = crate::macho::MACHO_START_MEM_ADDRESS;
        let mut bytes = Vec::with_capacity(file_size);

        push_u32(&mut bytes, object::macho::MH_MAGIC_64);
        push_u32(&mut bytes, object::macho::CPU_TYPE_ARM64 as u32);
        push_u32(&mut bytes, object::macho::CPU_SUBTYPE_ARM64_ALL as u32);
        push_u32(&mut bytes, object::macho::MH_EXECUTE);
        push_u32(&mut bytes, 1);
        push_u32(&mut bytes, commands_size as u32);
        push_u32(&mut bytes, 0);
        push_u32(&mut bytes, 0);

        push_u32(&mut bytes, object::macho::LC_SEGMENT_64);
        push_u32(&mut bytes, commands_size as u32);
        push_fixed_name(&mut bytes, b"__TEXT");
        push_u64(&mut bytes, image_start);
        push_u64(&mut bytes, file_size as u64);
        push_u64(&mut bytes, 0);
        push_u64(&mut bytes, file_size as u64);
        push_u32(&mut bytes, 5);
        push_u32(&mut bytes, 5);
        push_u32(&mut bytes, SECTION_COUNT as u32);
        push_u32(&mut bytes, 0);

        for (name, offset, size, flags) in [
            (
                b"__text".as_slice(),
                text_offset,
                TEXT_SIZE,
                object::macho::S_REGULAR
                    | object::macho::S_ATTR_PURE_INSTRUCTIONS
                    | object::macho::S_ATTR_SOME_INSTRUCTIONS,
            ),
            (
                b"__gcc_except_tab".as_slice(),
                gcc_except_table_offset,
                GCC_EXCEPT_TABLE_SIZE,
                object::macho::S_REGULAR,
            ),
            (
                b"__eh_frame".as_slice(),
                eh_frame_offset,
                EH_FRAME_SIZE,
                object::macho::S_COALESCED,
            ),
            (
                b"__unwind_info".as_slice(),
                unwind_info_offset,
                unwind_info_size,
                object::macho::S_REGULAR,
            ),
        ] {
            push_macho_section(
                &mut bytes,
                name,
                b"__TEXT",
                image_start + offset as u64,
                size,
                offset,
                flags,
            );
        }
        bytes.resize(file_size, 0);
        TestMachOUnwindOutput {
            bytes,
            text_offset: text_offset as u64,
            gcc_except_table_offset: gcc_except_table_offset as u64,
            eh_frame_offset: eh_frame_offset as u64,
            eh_frame_size: EH_FRAME_SIZE as u64,
            unwind_info_offset: unwind_info_offset as u64,
        }
    }

    fn apply_test_section_patches(output: &mut [u8], patches: &[SectionPatch]) {
        for patch in patches {
            let start = patch.output_offset as usize;
            let end = start + patch.data.len();
            output[start..end].copy_from_slice(&patch.data);
        }
    }

    fn test_added_macho_unwind_relocation(
        width: u8,
        field_value: u64,
        explicit_addend: i64,
        primary_type: u8,
        primary_pcrel: bool,
        has_subtractor: bool,
    ) -> AddedMachOArchiveUnwindRelocation {
        let length = width.ilog2() as u8;
        let subtractor = AddedMachOArchiveRawRelocation {
            r_address: 0,
            r_symbolnum: 0,
            r_pcrel: false,
            r_length: length,
            r_extern: true,
            r_type: object::macho::ARM64_RELOC_SUBTRACTOR,
        };
        let primary = AddedMachOArchiveRawRelocation {
            r_address: 0,
            r_symbolnum: 0,
            r_pcrel: primary_pcrel,
            r_length: length,
            r_extern: true,
            r_type: primary_type,
        };
        AddedMachOArchiveUnwindRelocation {
            input_offset: 0,
            width,
            explicit_addend,
            field_value,
            raw: if has_subtractor {
                vec![subtractor, primary]
            } else {
                vec![primary]
            },
            subtractor_target: has_subtractor.then_some(AddedMachOArchiveUnwindTarget::Section(
                AddedMachOArchiveUnwindSectionPosition {
                    section_index: 0,
                    section_offset: 0,
                },
            )),
        }
    }

    #[derive(Clone, Copy)]
    enum TestMachOCompactFixture {
        None,
        NativeOnly,
        Mixed,
    }

    struct TestMachOUnwindFixture {
        bytes: Vec<u8>,
        personality_field_offset: Option<usize>,
        first_pc_field_offset: Option<usize>,
        first_lsda_field_offset: Option<usize>,
        cie_fde_encoding_offset: Option<usize>,
        cie_augmentation_size_offset: Option<usize>,
        first_pc_primary_relocation_word_offset: Option<usize>,
    }

    #[derive(Clone, Copy)]
    struct TestMachORelocation {
        offset: u32,
        symbol: u32,
        pcrel: bool,
        length: u8,
        external: bool,
        r_type: u8,
    }

    fn test_macho_unwind_object(
        compact_fixture: TestMachOCompactFixture,
        include_eh_frame: bool,
    ) -> TestMachOUnwindFixture {
        const HEADER_SIZE: usize = 32;
        const SEGMENT_COMMAND_SIZE: usize = 72;
        const SECTION_SIZE: usize = 80;
        const SYMTAB_COMMAND_SIZE: usize = 24;
        const NLIST_64_SIZE: usize = 16;

        let mut compact_unwind = Vec::new();
        let mut compact_relocation_groups = Vec::new();
        if !matches!(compact_fixture, TestMachOCompactFixture::None) {
            compact_unwind.extend_from_slice(&0_u64.to_le_bytes());
            compact_unwind.extend_from_slice(&0x20_u32.to_le_bytes());
            compact_unwind.extend_from_slice(&0x0200_0000_u32.to_le_bytes());
            compact_unwind.extend_from_slice(&[0; 16]);
            compact_relocation_groups.push(vec![TestMachORelocation {
                offset: 0,
                symbol: 0,
                pcrel: false,
                length: 3,
                external: true,
                r_type: object::macho::ARM64_RELOC_UNSIGNED,
            }]);
        }
        if matches!(compact_fixture, TestMachOCompactFixture::Mixed) {
            compact_unwind.extend_from_slice(&0_u64.to_le_bytes());
            compact_unwind.extend_from_slice(&0x20_u32.to_le_bytes());
            compact_unwind
                .extend_from_slice(&(ADDED_MACHO_UNWIND_MODE_DWARF | 0x123).to_le_bytes());
            compact_unwind.extend_from_slice(&[0; 16]);
            compact_relocation_groups.push(vec![
                test_macho_addend_relocation(0x20, 0x20, 3),
                TestMachORelocation {
                    offset: 0x20,
                    symbol: 0,
                    pcrel: false,
                    length: 3,
                    external: true,
                    r_type: object::macho::ARM64_RELOC_UNSIGNED,
                },
            ]);
        }

        let mut eh_frame = Vec::new();
        let mut eh_relocation_groups = Vec::new();
        let mut personality_field_offset = None;
        let mut first_pc_field_offset = None;
        let mut first_lsda_field_offset = None;
        let mut cie_fde_encoding_section_offset = None;
        let mut cie_augmentation_size_section_offset = None;
        if include_eh_frame {
            let cie_start = eh_frame.len();
            push_u32(&mut eh_frame, 0);
            push_u32(&mut eh_frame, 0);
            eh_frame.push(1);
            eh_frame.extend_from_slice(b"zPLR\0");
            eh_frame.extend_from_slice(&[1, 0x78, 30]);
            cie_augmentation_size_section_offset = Some(eh_frame.len());
            eh_frame.push(7);
            eh_frame.push(0x9b);
            personality_field_offset = Some(eh_frame.len());
            eh_frame.extend_from_slice(&0_u32.to_le_bytes());
            eh_frame.push(0x1b);
            cie_fde_encoding_section_offset = Some(eh_frame.len());
            eh_frame.push(0x1b);
            eh_frame.extend_from_slice(&[0x0c, 0x1f, 0]);
            write_test_eh_frame_length(&mut eh_frame, cie_start);

            let fde_start = eh_frame.len();
            push_u32(&mut eh_frame, 0);
            push_u32(&mut eh_frame, (fde_start + 4 - cie_start) as u32);
            first_pc_field_offset = Some(eh_frame.len());
            eh_frame.extend_from_slice(&0_u32.to_le_bytes());
            eh_frame.extend_from_slice(&0x20_u32.to_le_bytes());
            eh_frame.push(4);
            first_lsda_field_offset = Some(eh_frame.len());
            eh_frame.extend_from_slice(&0_u32.to_le_bytes());
            write_test_eh_frame_length(&mut eh_frame, fde_start);

            let second_fde_start = eh_frame.len();
            push_u32(&mut eh_frame, 0);
            push_u32(&mut eh_frame, (second_fde_start + 4 - cie_start) as u32);
            let second_pc_offset = eh_frame.len();
            eh_frame.extend_from_slice(&0_u32.to_le_bytes());
            eh_frame.extend_from_slice(&0x20_u32.to_le_bytes());
            eh_frame.push(4);
            eh_frame.extend_from_slice(&0_u32.to_le_bytes());
            write_test_eh_frame_length(&mut eh_frame, second_fde_start);

            let wide_cie_start = eh_frame.len();
            push_u32(&mut eh_frame, 0);
            push_u32(&mut eh_frame, 0);
            eh_frame.push(1);
            eh_frame.extend_from_slice(b"zR\0");
            eh_frame.extend_from_slice(&[1, 0x78, 30, 1, 0x10, 0]);
            write_test_eh_frame_length(&mut eh_frame, wide_cie_start);

            let wide_fde_start = eh_frame.len();
            push_u32(&mut eh_frame, 0);
            push_u32(&mut eh_frame, (wide_fde_start + 4 - wide_cie_start) as u32);
            let wide_pc_offset = eh_frame.len();
            eh_frame.extend_from_slice(&0_u64.to_le_bytes());
            eh_frame.extend_from_slice(&0x20_u64.to_le_bytes());
            eh_frame.push(0);
            write_test_eh_frame_length(&mut eh_frame, wide_fde_start);
            push_u32(&mut eh_frame, 0);

            let eh_symbol = 4;
            let personality_symbol = 5;
            eh_relocation_groups.push(vec![TestMachORelocation {
                offset: personality_field_offset.unwrap() as u32,
                symbol: personality_symbol,
                pcrel: true,
                length: 2,
                external: true,
                r_type: object::macho::ARM64_RELOC_POINTER_TO_GOT,
            }]);
            eh_relocation_groups.push(vec![
                test_macho_addend_relocation(first_pc_field_offset.unwrap() as u32, 0x20, 2),
                test_macho_subtractor_relocation(
                    first_pc_field_offset.unwrap() as u32,
                    eh_symbol,
                    2,
                ),
                test_macho_unsigned_relocation(first_pc_field_offset.unwrap() as u32, 0, 2),
            ]);
            eh_relocation_groups.push(vec![
                test_macho_addend_relocation(first_lsda_field_offset.unwrap() as u32, 4, 2),
                test_macho_subtractor_relocation(
                    first_lsda_field_offset.unwrap() as u32,
                    eh_symbol,
                    2,
                ),
                test_macho_unsigned_relocation(first_lsda_field_offset.unwrap() as u32, 3, 2),
            ]);
            eh_relocation_groups.push(vec![
                test_macho_subtractor_relocation(second_pc_offset as u32, eh_symbol, 2),
                test_macho_unsigned_relocation(second_pc_offset as u32, 2, 2),
            ]);
            eh_relocation_groups.push(vec![
                test_macho_subtractor_relocation(wide_pc_offset as u32, eh_symbol, 3),
                test_macho_unsigned_relocation(wide_pc_offset as u32, 0, 3),
            ]);
        }

        compact_relocation_groups.sort_by_key(|group| std::cmp::Reverse(group[0].offset));
        eh_relocation_groups.sort_by_key(|group| std::cmp::Reverse(group[0].offset));
        let compact_relocations = compact_relocation_groups
            .into_iter()
            .flatten()
            .collect::<Vec<_>>();
        let eh_relocations = eh_relocation_groups
            .into_iter()
            .flatten()
            .collect::<Vec<_>>();

        let text = vec![0; 0x80];
        let gcc_except_table = vec![0; 0x10];
        let has_compact = !compact_unwind.is_empty();
        let section_count = 2 + usize::from(has_compact) + usize::from(include_eh_frame);
        let commands_size =
            SEGMENT_COMMAND_SIZE + section_count * SECTION_SIZE + SYMTAB_COMMAND_SIZE;
        let text_offset = HEADER_SIZE + commands_size;
        let gcc_except_table_offset = text_offset + text.len();
        let compact_unwind_offset = gcc_except_table_offset + gcc_except_table.len();
        let eh_frame_offset = compact_unwind_offset + compact_unwind.len();
        let compact_relocation_offset = (eh_frame_offset + eh_frame.len()).next_multiple_of(8);
        let eh_relocation_offset = compact_relocation_offset + compact_relocations.len() * 8;
        let symoff = (eh_relocation_offset + eh_relocations.len() * 8).next_multiple_of(8);
        let symbol_count = 4 + usize::from(include_eh_frame) * 2;
        let stroff = symoff + symbol_count * NLIST_64_SIZE;

        let mut strings = vec![0];
        let mut add_string = |name: &[u8]| {
            let offset = strings.len() as u32;
            strings.extend_from_slice(name);
            strings.push(0);
            offset
        };
        let function0_name = add_string(b"_function0");
        let function1_name = add_string(b"_function1");
        let function2_name = add_string(b"_function2");
        let lsda_name = add_string(b"_lsda");
        let eh_frame_name = include_eh_frame.then(|| add_string(b"_eh_frame"));
        let personality_name = include_eh_frame.then(|| add_string(b"_rust_eh_personality"));

        let text_address = 0;
        let gcc_except_table_address = text.len() as u64;
        let compact_unwind_address = gcc_except_table_address + gcc_except_table.len() as u64;
        let eh_frame_address = compact_unwind_address + compact_unwind.len() as u64;
        let segment_size =
            text.len() + gcc_except_table.len() + compact_unwind.len() + eh_frame.len();
        let eh_frame_section_index = include_eh_frame.then_some(3_u8 + u8::from(has_compact));

        let mut bytes = Vec::new();
        push_u32(&mut bytes, object::macho::MH_MAGIC_64);
        push_u32(&mut bytes, object::macho::CPU_TYPE_ARM64 as u32);
        push_u32(&mut bytes, object::macho::CPU_SUBTYPE_ARM64_ALL as u32);
        push_u32(&mut bytes, object::macho::MH_OBJECT);
        push_u32(&mut bytes, 2);
        push_u32(&mut bytes, commands_size as u32);
        push_u32(&mut bytes, object::macho::MH_SUBSECTIONS_VIA_SYMBOLS);
        push_u32(&mut bytes, 0);

        push_u32(&mut bytes, object::macho::LC_SEGMENT_64);
        push_u32(
            &mut bytes,
            (SEGMENT_COMMAND_SIZE + section_count * SECTION_SIZE) as u32,
        );
        push_fixed_name(&mut bytes, b"");
        push_u64(&mut bytes, 0);
        push_u64(&mut bytes, segment_size as u64);
        push_u64(&mut bytes, text_offset as u64);
        push_u64(&mut bytes, segment_size as u64);
        push_u32(&mut bytes, 7);
        push_u32(&mut bytes, 7);
        push_u32(&mut bytes, section_count as u32);
        push_u32(&mut bytes, 0);

        push_macho_section_with_relocations(
            &mut bytes,
            b"__text",
            b"__TEXT",
            text_address,
            text.len(),
            text_offset,
            0,
            0,
            object::macho::S_REGULAR
                | object::macho::S_ATTR_PURE_INSTRUCTIONS
                | object::macho::S_ATTR_SOME_INSTRUCTIONS,
        );
        push_macho_section_with_relocations(
            &mut bytes,
            b"__gcc_except_tab",
            b"__TEXT",
            gcc_except_table_address,
            gcc_except_table.len(),
            gcc_except_table_offset,
            0,
            0,
            object::macho::S_REGULAR,
        );
        if has_compact {
            push_macho_section_with_relocations(
                &mut bytes,
                b"__compact_unwind",
                b"__LD",
                compact_unwind_address,
                compact_unwind.len(),
                compact_unwind_offset,
                compact_relocation_offset,
                compact_relocations.len(),
                object::macho::S_REGULAR | object::macho::S_ATTR_DEBUG,
            );
        }
        if include_eh_frame {
            push_macho_section_with_relocations(
                &mut bytes,
                b"__eh_frame",
                b"__TEXT",
                eh_frame_address,
                eh_frame.len(),
                eh_frame_offset,
                eh_relocation_offset,
                eh_relocations.len(),
                object::macho::S_COALESCED,
            );
        }

        push_u32(&mut bytes, object::macho::LC_SYMTAB);
        push_u32(&mut bytes, SYMTAB_COMMAND_SIZE as u32);
        push_u32(&mut bytes, symoff as u32);
        push_u32(&mut bytes, symbol_count as u32);
        push_u32(&mut bytes, stroff as u32);
        push_u32(&mut bytes, strings.len() as u32);

        assert_eq!(bytes.len(), text_offset);
        bytes.extend_from_slice(&text);
        bytes.extend_from_slice(&gcc_except_table);
        bytes.extend_from_slice(&compact_unwind);
        bytes.extend_from_slice(&eh_frame);
        bytes.resize(compact_relocation_offset, 0);
        for relocation in &compact_relocations {
            push_test_macho_relocation(&mut bytes, *relocation);
        }
        assert_eq!(bytes.len(), eh_relocation_offset);
        let mut first_pc_primary_relocation_word_offset = None;
        for relocation in &eh_relocations {
            let word_offset = bytes.len() + 4;
            if Some(relocation.offset as usize) == first_pc_field_offset
                && relocation.r_type == object::macho::ARM64_RELOC_UNSIGNED
            {
                first_pc_primary_relocation_word_offset = Some(word_offset);
            }
            push_test_macho_relocation(&mut bytes, *relocation);
        }

        bytes.resize(symoff, 0);
        push_macho_symbol(&mut bytes, function0_name, 1, text_address);
        push_macho_local_symbol(&mut bytes, function1_name, 1, text_address + 0x20);
        push_macho_local_symbol(&mut bytes, function2_name, 1, text_address + 0x40);
        push_macho_local_symbol(&mut bytes, lsda_name, 2, gcc_except_table_address);
        if include_eh_frame {
            push_macho_local_symbol(
                &mut bytes,
                eh_frame_name.unwrap(),
                eh_frame_section_index.unwrap(),
                eh_frame_address,
            );
            push_macho_undefined_symbol(&mut bytes, personality_name.unwrap());
        }
        bytes.extend_from_slice(&strings);

        TestMachOUnwindFixture {
            bytes,
            personality_field_offset,
            first_pc_field_offset,
            first_lsda_field_offset,
            cie_fde_encoding_offset: cie_fde_encoding_section_offset
                .map(|offset| eh_frame_offset + offset),
            cie_augmentation_size_offset: cie_augmentation_size_section_offset
                .map(|offset| eh_frame_offset + offset),
            first_pc_primary_relocation_word_offset,
        }
    }

    fn test_observed_049_macho_unwind_object(with_personality: bool) -> Vec<u8> {
        const HEADER_SIZE: usize = 32;
        const SEGMENT_COMMAND_SIZE: usize = 72;
        const SECTION_SIZE: usize = 80;
        const SYMTAB_COMMAND_SIZE: usize = 24;
        const NLIST_64_SIZE: usize = 16;

        let text = vec![0; if with_personality { 0x2dc } else { 0x258 }];
        let gcc_except_table = vec![0; if with_personality { 0x1c } else { 0 }];
        let compact_unwind = if with_personality {
            [
                0_u64.to_le_bytes().as_slice(),
                0x110_u32.to_le_bytes().as_slice(),
                ADDED_MACHO_UNWIND_MODE_DWARF.to_le_bytes().as_slice(),
                &[0; 16],
                0x110_u64.to_le_bytes().as_slice(),
                0x1cc_u32.to_le_bytes().as_slice(),
                ADDED_MACHO_UNWIND_MODE_DWARF.to_le_bytes().as_slice(),
                &[0; 16],
            ]
            .concat()
        } else {
            [
                0_u64.to_le_bytes().as_slice(),
                0x258_u32.to_le_bytes().as_slice(),
                ADDED_MACHO_UNWIND_MODE_DWARF.to_le_bytes().as_slice(),
                &[0; 16],
            ]
            .concat()
        };
        let eh_frame = if with_personality {
            hex::decode(concat!(
                "1000000000000000017a520001781e01100c1f00",
                "3000000018000000e4ffffffffffffff100100000000000000440e40480c1d10",
                "9e019d0202f80c1f40480e00dedd000000000000",
                "1800000000000000017a504c520001781e079ba5ffffff10100c1f00",
                "400000002000000094ffffffffffffffcc010000000000000883ffffffffffffff",
                "ff440eb0024c0c1d109e019d029b039c040a0390010c1fb0024c0e00dedddbdc",
                "440b00"
            ))
            .unwrap()
        } else {
            hex::decode(concat!(
                "1000000000000000017a520001781e01100c1f00",
                "3000000018000000e4ffffffffffffff580200000000000000440e40480c1d10",
                "9e019d020340020c1f40480e00dedd0000000000"
            ))
            .unwrap()
        };

        let section_count = 4;
        let commands_size =
            SEGMENT_COMMAND_SIZE + section_count * SECTION_SIZE + SYMTAB_COMMAND_SIZE;
        let text_offset = HEADER_SIZE + commands_size;
        let gcc_except_table_offset = text_offset + text.len();
        let compact_unwind_offset = gcc_except_table_offset + gcc_except_table.len();
        let eh_frame_offset = compact_unwind_offset + compact_unwind.len();
        let compact_relocation_count = if with_personality { 2 } else { 1 };
        let eh_frame_relocation_count = if with_personality { 7 } else { 2 };
        let compact_relocation_offset = (eh_frame_offset + eh_frame.len()).next_multiple_of(8);
        let eh_frame_relocation_offset = compact_relocation_offset + compact_relocation_count * 8;
        let symoff =
            (eh_frame_relocation_offset + eh_frame_relocation_count * 8).next_multiple_of(8);
        let symbol_count = 5;
        let stroff = symoff + symbol_count * NLIST_64_SIZE;

        let mut strings = vec![0];
        let mut add_string = |name: &[u8]| {
            let offset = strings.len() as u32;
            strings.extend_from_slice(name);
            strings.push(0);
            offset
        };
        let function0_name = add_string(b"_function0");
        let function1_name = add_string(b"_function1");
        let lsda_name = add_string(b"_lsda");
        let eh_frame_name = add_string(b"_eh_frame");
        let personality_name = add_string(b"_rust_eh_personality");

        let text_address = 0;
        let gcc_except_table_address = text.len() as u64;
        let compact_unwind_address = gcc_except_table_address + gcc_except_table.len() as u64;
        let eh_frame_address = compact_unwind_address + compact_unwind.len() as u64;
        let segment_size =
            text.len() + gcc_except_table.len() + compact_unwind.len() + eh_frame.len();

        let mut bytes = Vec::new();
        push_u32(&mut bytes, object::macho::MH_MAGIC_64);
        push_u32(&mut bytes, object::macho::CPU_TYPE_ARM64 as u32);
        push_u32(&mut bytes, object::macho::CPU_SUBTYPE_ARM64_ALL as u32);
        push_u32(&mut bytes, object::macho::MH_OBJECT);
        push_u32(&mut bytes, 2);
        push_u32(&mut bytes, commands_size as u32);
        push_u32(&mut bytes, object::macho::MH_SUBSECTIONS_VIA_SYMBOLS);
        push_u32(&mut bytes, 0);

        push_u32(&mut bytes, object::macho::LC_SEGMENT_64);
        push_u32(
            &mut bytes,
            (SEGMENT_COMMAND_SIZE + section_count * SECTION_SIZE) as u32,
        );
        push_fixed_name(&mut bytes, b"");
        push_u64(&mut bytes, 0);
        push_u64(&mut bytes, segment_size as u64);
        push_u64(&mut bytes, text_offset as u64);
        push_u64(&mut bytes, segment_size as u64);
        push_u32(&mut bytes, 7);
        push_u32(&mut bytes, 7);
        push_u32(&mut bytes, section_count as u32);
        push_u32(&mut bytes, 0);

        push_macho_section_with_relocations(
            &mut bytes,
            b"__text",
            b"__TEXT",
            text_address,
            text.len(),
            text_offset,
            0,
            0,
            object::macho::S_REGULAR
                | object::macho::S_ATTR_PURE_INSTRUCTIONS
                | object::macho::S_ATTR_SOME_INSTRUCTIONS,
        );
        push_macho_section_with_relocations(
            &mut bytes,
            b"__gcc_except_tab",
            b"__TEXT",
            gcc_except_table_address,
            gcc_except_table.len(),
            gcc_except_table_offset,
            0,
            0,
            object::macho::S_REGULAR,
        );
        push_macho_section_with_relocations(
            &mut bytes,
            b"__compact_unwind",
            b"__LD",
            compact_unwind_address,
            compact_unwind.len(),
            compact_unwind_offset,
            compact_relocation_offset,
            compact_relocation_count,
            object::macho::S_REGULAR | object::macho::S_ATTR_DEBUG,
        );
        push_macho_section_with_relocations(
            &mut bytes,
            b"__eh_frame",
            b"__TEXT",
            eh_frame_address,
            eh_frame.len(),
            eh_frame_offset,
            eh_frame_relocation_offset,
            eh_frame_relocation_count,
            0x6800_000b,
        );

        push_u32(&mut bytes, object::macho::LC_SYMTAB);
        push_u32(&mut bytes, SYMTAB_COMMAND_SIZE as u32);
        push_u32(&mut bytes, symoff as u32);
        push_u32(&mut bytes, symbol_count as u32);
        push_u32(&mut bytes, stroff as u32);
        push_u32(&mut bytes, strings.len() as u32);

        assert_eq!(bytes.len(), text_offset);
        bytes.extend_from_slice(&text);
        bytes.extend_from_slice(&gcc_except_table);
        bytes.extend_from_slice(&compact_unwind);
        bytes.extend_from_slice(&eh_frame);
        bytes.resize(compact_relocation_offset, 0);
        if with_personality {
            push_test_macho_relocation(
                &mut bytes,
                TestMachORelocation {
                    offset: 0x20,
                    symbol: 1,
                    pcrel: false,
                    length: 3,
                    external: false,
                    r_type: object::macho::ARM64_RELOC_UNSIGNED,
                },
            );
        }
        push_test_macho_relocation(
            &mut bytes,
            TestMachORelocation {
                offset: 0,
                symbol: 1,
                pcrel: false,
                length: 3,
                external: false,
                r_type: object::macho::ARM64_RELOC_UNSIGNED,
            },
        );
        assert_eq!(bytes.len(), eh_frame_relocation_offset);

        let push_subtractor_pair = |bytes: &mut Vec<u8>, offset: u32, target_symbol: u32| {
            push_test_macho_relocation(
                bytes,
                TestMachORelocation {
                    offset,
                    symbol: 3,
                    pcrel: false,
                    length: 3,
                    external: true,
                    r_type: object::macho::ARM64_RELOC_SUBTRACTOR,
                },
            );
            push_test_macho_relocation(
                bytes,
                TestMachORelocation {
                    offset,
                    symbol: target_symbol,
                    pcrel: false,
                    length: 3,
                    external: true,
                    r_type: object::macho::ARM64_RELOC_UNSIGNED,
                },
            );
        };
        if with_personality {
            push_subtractor_pair(&mut bytes, 0x7d, 2);
            push_subtractor_pair(&mut bytes, 0x6c, 1);
            push_test_macho_relocation(
                &mut bytes,
                TestMachORelocation {
                    offset: 0x5b,
                    symbol: 4,
                    pcrel: true,
                    length: 2,
                    external: true,
                    r_type: object::macho::ARM64_RELOC_POINTER_TO_GOT,
                },
            );
        }
        push_subtractor_pair(&mut bytes, 0x1c, 0);

        bytes.resize(symoff, 0);
        push_macho_symbol(&mut bytes, function0_name, 1, text_address);
        push_macho_local_symbol(
            &mut bytes,
            function1_name,
            1,
            text_address + if with_personality { 0x110 } else { 0 },
        );
        push_macho_local_symbol(&mut bytes, lsda_name, 2, gcc_except_table_address);
        push_macho_local_symbol(&mut bytes, eh_frame_name, 4, eh_frame_address);
        push_macho_undefined_symbol(&mut bytes, personality_name);
        bytes.extend_from_slice(&strings);
        bytes
    }

    fn write_test_eh_frame_length(bytes: &mut [u8], entry_start: usize) {
        let length = u32::try_from(bytes.len() - entry_start - 4).unwrap();
        bytes[entry_start..entry_start + 4].copy_from_slice(&length.to_le_bytes());
    }

