    fn test_macho_object_with_options(
        text: &[u8],
        data: &[u8],
        debug: Option<&[u8]>,
        data_symbol_offset: u64,
        data_section_name: &[u8],
        text_relocation: bool,
    ) -> Vec<u8> {
        const HEADER_SIZE: usize = 32;
        const SEGMENT_COMMAND_SIZE: usize = 72;
        const SECTION_SIZE: usize = 80;
        const SYMTAB_COMMAND_SIZE: usize = 24;
        const NLIST_64_SIZE: usize = 16;

        let section_count = 2 + usize::from(debug.is_some());
        let commands_size =
            SEGMENT_COMMAND_SIZE + section_count * SECTION_SIZE + SYMTAB_COMMAND_SIZE;
        let text_offset = HEADER_SIZE + commands_size;
        let data_offset = text_offset + text.len();
        let debug_offset = data_offset + data.len();
        let debug_len = debug.map_or(0, <[u8]>::len);
        let text_relocation_offset = (debug_offset + debug_len).next_multiple_of(8);
        let text_relocation_count = usize::from(text_relocation);
        let symoff = (text_relocation_offset + text_relocation_count * 8).next_multiple_of(8);
        let stroff = symoff + 2 * NLIST_64_SIZE;
        let strings = b"\0_text\0_data\0";
        let mut bytes = Vec::new();

        push_u32(&mut bytes, object::macho::MH_MAGIC_64);
        push_u32(&mut bytes, object::macho::CPU_TYPE_ARM64 as u32);
        push_u32(&mut bytes, object::macho::CPU_SUBTYPE_ARM64_ALL as u32);
        push_u32(&mut bytes, object::macho::MH_OBJECT);
        push_u32(&mut bytes, 2);
        push_u32(&mut bytes, commands_size as u32);
        push_u32(&mut bytes, object::macho::MH_SUBSECTIONS_VIA_SYMBOLS);
        push_u32(&mut bytes, 0);

        push_u32(&mut bytes, object::macho::LC_SEGMENT_64);
        push_u32(
            &mut bytes,
            (SEGMENT_COMMAND_SIZE + section_count * SECTION_SIZE) as u32,
        );
        push_fixed_name(&mut bytes, b"");
        push_u64(&mut bytes, 0);
        push_u64(&mut bytes, (text.len() + data.len() + debug_len) as u64);
        push_u64(&mut bytes, text_offset as u64);
        push_u64(&mut bytes, (text.len() + data.len() + debug_len) as u64);
        push_u32(&mut bytes, 7);
        push_u32(&mut bytes, 7);
        push_u32(&mut bytes, section_count as u32);
        push_u32(&mut bytes, 0);

        push_macho_section_with_relocations(
            &mut bytes,
            b"__text",
            b"__TEXT",
            0,
            text.len(),
            text_offset,
            text_relocation_offset,
            text_relocation_count,
            object::macho::S_REGULAR
                | object::macho::S_ATTR_PURE_INSTRUCTIONS
                | object::macho::S_ATTR_SOME_INSTRUCTIONS,
        );
        push_macho_section(
            &mut bytes,
            data_section_name,
            b"__DATA",
            text.len() as u64,
            data.len(),
            data_offset,
            object::macho::S_REGULAR,
        );
        if let Some(debug) = debug {
            push_macho_section(
                &mut bytes,
                b"__debug_str",
                b"__DWARF",
                (text.len() + data.len()) as u64,
                debug.len(),
                debug_offset,
                object::macho::S_REGULAR | object::macho::S_ATTR_DEBUG,
            );
        }

        push_u32(&mut bytes, object::macho::LC_SYMTAB);
        push_u32(&mut bytes, SYMTAB_COMMAND_SIZE as u32);
        push_u32(&mut bytes, symoff as u32);
        push_u32(&mut bytes, 2);
        push_u32(&mut bytes, stroff as u32);
        push_u32(&mut bytes, strings.len() as u32);

        assert_eq!(bytes.len(), text_offset);
        bytes.extend_from_slice(text);
        bytes.extend_from_slice(data);
        if let Some(debug) = debug {
            bytes.extend_from_slice(debug);
        }
        bytes.resize(text_relocation_offset, 0);
        if text_relocation {
            push_test_macho_relocation(
                &mut bytes,
                TestMachORelocation {
                    offset: 0,
                    symbol: 1,
                    pcrel: true,
                    length: 2,
                    external: true,
                    r_type: object::macho::ARM64_RELOC_PAGE21,
                },
            );
        }
        bytes.resize(symoff, 0);
        push_macho_symbol(&mut bytes, 1, 1, 0);
        push_macho_symbol(&mut bytes, 7, 2, text.len() as u64 + data_symbol_offset);
        bytes.extend_from_slice(strings);
        bytes
    }

    fn test_macho_data_object(
        data: &[u8],
        added_text: Option<&[u8]>,
        added_text_symbol: bool,
    ) -> Vec<u8> {
        const HEADER_SIZE: usize = 32;
        const SEGMENT_COMMAND_SIZE: usize = 72;
        const SECTION_SIZE: usize = 80;
        const SYMTAB_COMMAND_SIZE: usize = 24;
        const NLIST_64_SIZE: usize = 16;

        let section_count = 1 + usize::from(added_text.is_some());
        let symbol_count = 1 + usize::from(added_text.is_some()) + usize::from(added_text_symbol);
        let commands_size =
            SEGMENT_COMMAND_SIZE + section_count * SECTION_SIZE + SYMTAB_COMMAND_SIZE;
        let data_offset = HEADER_SIZE + commands_size;
        let text_offset = data_offset + data.len();
        let text_len = added_text.map_or(0, <[u8]>::len);
        let symoff = (text_offset + text_len).next_multiple_of(8);
        let stroff = symoff + symbol_count * NLIST_64_SIZE;
        let strings = b"\0_data\0ltmp0\0_added_text\0";
        let mut bytes = Vec::new();

        push_u32(&mut bytes, object::macho::MH_MAGIC_64);
        push_u32(&mut bytes, object::macho::CPU_TYPE_ARM64 as u32);
        push_u32(&mut bytes, object::macho::CPU_SUBTYPE_ARM64_ALL as u32);
        push_u32(&mut bytes, object::macho::MH_OBJECT);
        push_u32(&mut bytes, 2);
        push_u32(&mut bytes, commands_size as u32);
        push_u32(&mut bytes, object::macho::MH_SUBSECTIONS_VIA_SYMBOLS);
        push_u32(&mut bytes, 0);

        push_u32(&mut bytes, object::macho::LC_SEGMENT_64);
        push_u32(
            &mut bytes,
            (SEGMENT_COMMAND_SIZE + section_count * SECTION_SIZE) as u32,
        );
        push_fixed_name(&mut bytes, b"");
        push_u64(&mut bytes, 0);
        push_u64(&mut bytes, (data.len() + text_len) as u64);
        push_u64(&mut bytes, data_offset as u64);
        push_u64(&mut bytes, (data.len() + text_len) as u64);
        push_u32(&mut bytes, 7);
        push_u32(&mut bytes, 7);
        push_u32(&mut bytes, section_count as u32);
        push_u32(&mut bytes, 0);

        push_macho_section(
            &mut bytes,
            b"__data",
            b"__DATA",
            0,
            data.len(),
            data_offset,
            object::macho::S_REGULAR,
        );
        if let Some(text) = added_text {
            push_macho_section(
                &mut bytes,
                b"__text",
                b"__TEXT",
                data.len() as u64,
                text.len(),
                text_offset,
                object::macho::S_REGULAR
                    | object::macho::S_ATTR_PURE_INSTRUCTIONS
                    | object::macho::S_ATTR_SOME_INSTRUCTIONS,
            );
        }

        push_u32(&mut bytes, object::macho::LC_SYMTAB);
        push_u32(&mut bytes, SYMTAB_COMMAND_SIZE as u32);
        push_u32(&mut bytes, symoff as u32);
        push_u32(&mut bytes, symbol_count as u32);
        push_u32(&mut bytes, stroff as u32);
        push_u32(&mut bytes, strings.len() as u32);

        assert_eq!(bytes.len(), data_offset);
        bytes.extend_from_slice(data);
        if let Some(text) = added_text {
            bytes.extend_from_slice(text);
        }
        bytes.resize(symoff, 0);
        push_macho_symbol(&mut bytes, 1, 1, 0);
        if added_text.is_some() {
            push_macho_local_symbol(&mut bytes, 7, 2, data.len() as u64);
        }
        if added_text_symbol {
            push_macho_symbol(&mut bytes, 13, 2, data.len() as u64);
        }
        bytes.extend_from_slice(strings);
        bytes
    }

    fn push_macho_section(
        bytes: &mut Vec<u8>,
        name: &[u8],
        segment: &[u8],
        address: u64,
        size: usize,
        offset: usize,
        flags: u32,
    ) {
        push_fixed_name(bytes, name);
        push_fixed_name(bytes, segment);
        push_u64(bytes, address);
        push_u64(bytes, size as u64);
        push_u32(bytes, offset as u32);
        push_u32(bytes, 2);
        push_u32(bytes, 0);
        push_u32(bytes, 0);
        push_u32(bytes, flags);
        push_u32(bytes, 0);
        push_u32(bytes, 0);
        push_u32(bytes, 0);
    }

    #[allow(clippy::too_many_arguments)]
    fn push_macho_section_with_relocations(
        bytes: &mut Vec<u8>,
        name: &[u8],
        segment: &[u8],
        address: u64,
        size: usize,
        offset: usize,
        relocation_offset: usize,
        relocation_count: usize,
        flags: u32,
    ) {
        push_fixed_name(bytes, name);
        push_fixed_name(bytes, segment);
        push_u64(bytes, address);
        push_u64(bytes, size as u64);
        push_u32(bytes, offset as u32);
        push_u32(bytes, 2);
        push_u32(bytes, relocation_offset as u32);
        push_u32(bytes, relocation_count as u32);
        push_u32(bytes, flags);
        push_u32(bytes, 0);
        push_u32(bytes, 0);
        push_u32(bytes, 0);
    }

    fn push_macho_symbol(bytes: &mut Vec<u8>, name_offset: u32, section: u8, value: u64) {
        push_u32(bytes, name_offset);
        bytes.push(object::macho::N_SECT | object::macho::N_EXT);
        bytes.push(section);
        bytes.extend_from_slice(&0_u16.to_le_bytes());
        push_u64(bytes, value);
    }

    fn push_macho_undefined_symbol(bytes: &mut Vec<u8>, name_offset: u32) {
        push_u32(bytes, name_offset);
        bytes.push(object::macho::N_UNDF | object::macho::N_EXT);
        bytes.push(0);
        bytes.extend_from_slice(&0_u16.to_le_bytes());
        push_u64(bytes, 0);
    }

    fn push_macho_local_symbol(bytes: &mut Vec<u8>, name_offset: u32, section: u8, value: u64) {
        push_u32(bytes, name_offset);
        bytes.push(object::macho::N_SECT);
        bytes.push(section);
        bytes.extend_from_slice(&0_u16.to_le_bytes());
        push_u64(bytes, value);
    }

    fn push_fixed_name(bytes: &mut Vec<u8>, name: &[u8]) {
        assert!(name.len() <= 16);
        bytes.extend_from_slice(name);
        bytes.resize(bytes.len() + 16 - name.len(), 0);
    }

    fn push_u32(bytes: &mut Vec<u8>, value: u32) {
        bytes.extend_from_slice(&value.to_le_bytes());
    }

    fn push_u64(bytes: &mut Vec<u8>, value: u64) {
        bytes.extend_from_slice(&value.to_le_bytes());
    }

    #[test]
    fn unchanged_normalized_archive_patch_state_accepts_only_unlinked_churn() {
        let archive = |invocation: &[u8], metadata: &[u8], object: &[u8]| {
            let mut builder = ar::Builder::new(Vec::new());
            builder
                .append(
                    &ar::Header::new(b"lib.rmeta".to_vec(), metadata.len() as u64),
                    metadata,
                )
                .unwrap();
            builder
                .append(
                    &ar::Header::new(
                        [b"crate-hash.cgu.".as_slice(), invocation, b".rcgu.o"].concat(),
                        object.len() as u64,
                    ),
                    object,
                )
                .unwrap();
            builder.into_inner().unwrap()
        };
        let input_path = hex::encode("libarchive.rlib");
        let section = PatchSection {
            input: hex::encode("libarchive.rlib\0crate-hash.cgu.old.rcgu.o\00:1"),
            section_index: 1,
            section_name: Some(".data".to_owned()),
            input_size: 4,
            output_offset: 64,
            output_size: 8,
            data_hash: Some(hash_bytes(&[1, 2, 3, 4])),
            cstring_nul_boundaries_hash: None,
        };
        let previous = archive(b"old", b"previous metadata", &growable_data_elf());
        let current = archive(b"new", b"new metadata", &growable_data_elf());
        let previous_patch = PreviousPatchState {
            fingerprint: patch_fingerprint(&previous, input_path.as_str(), [section.clone()])
                .unwrap()
                .unwrap(),
            archive_member_patch_fingerprints: None,
            sections: vec![section.clone()],
        };
        let input = FileState {
            path: input_path,
            content: FileContentState::from_bytes(&previous),
            snapshot_identity: None,
            rustc_link_content_digest: None,
            rustc_raw_object_manifest: None,
            patch: None,
        };

        let state = classify_normalized_rust_archive_patch_state(&input, &current, &previous_patch)
            .unwrap();
        assert!(matches!(
            &state,
            NormalizedRustArchivePatchState::Unchanged(_)
        ));
        if let NormalizedRustArchivePatchState::Unchanged(patch) = state {
            assert_eq!(patch.fingerprint, previous_patch.fingerprint);
            assert_eq!(patch.sections.len(), 1);
        }

        let mismatched_previous_patch = PreviousPatchState {
            fingerprint: "mismatched fingerprint".to_owned(),
            archive_member_patch_fingerprints: None,
            sections: vec![section.clone()],
        };
        let mismatched_state = classify_normalized_rust_archive_patch_state(
            &input,
            &current,
            &mismatched_previous_patch,
        )
        .unwrap();
        assert!(matches!(
            &mismatched_state,
            NormalizedRustArchivePatchState::Unknown
        ));

        let mut changed_object = growable_data_elf();
        changed_object[0x40] = 9;
        let changed = archive(b"current", b"new metadata", &changed_object);
        let changed_state =
            classify_normalized_rust_archive_patch_state(&input, &changed, &previous_patch)
                .unwrap();
        assert!(matches!(
            &changed_state,
            NormalizedRustArchivePatchState::MatchedButNotUnchanged(_)
        ));
        if let NormalizedRustArchivePatchState::MatchedButNotUnchanged(matched) = changed_state {
            assert_eq!(matched.sections.len(), 1);
            assert_eq!(matched.changed_sections.len(), 1);
        }
    }

    #[test]
    fn archive_member_identifiers_track_member_set() {
        let mut builder = ar::Builder::new(Vec::new());
        builder
            .append(
                &ar::Header::new(b"first.o".to_vec(), 5),
                b"first".as_slice(),
            )
            .unwrap();
        builder
            .append(
                &ar::Header::new(b"second.o".to_vec(), 6),
                b"second".as_slice(),
            )
            .unwrap();
        let archive = builder.into_inner().unwrap();

        assert_eq!(
            archive_member_identifiers(&archive).unwrap().unwrap(),
            vec![b"first.o".to_vec(), b"second.o".to_vec()]
        );
        assert!(
            archive_member_identifiers(b"not an archive")
                .unwrap()
                .is_none()
        );
        assert_eq!(
            archive_member_patch_identifier(b"crate-hash.cgu.session.rcgu.o"),
            b"crate-hash.cgu.rcgu.o".to_vec()
        );
        assert_eq!(
            archive_member_patch_identifier(b"crate-hash.cgu.0.session.rcgu.o"),
            b"crate-hash.cgu.0.rcgu.o".to_vec()
        );
        assert_eq!(
            archive_member_patch_identifier(b"foreign-member.o"),
            b"foreign-member.o".to_vec()
        );
    }

    #[test]
    fn added_archive_members_require_a_unique_normalized_ordered_superset() {
        let archive = |members: &[(&[u8], &[u8])]| {
            let mut builder = ar::Builder::new(Vec::new());
            for (identifier, data) in members {
                builder
                    .append(
                        &ar::Header::new(identifier.to_vec(), data.len() as u64),
                        *data,
                    )
                    .unwrap();
            }
            builder.into_inner().unwrap()
        };
        let previous = archive(&[(b"crate.cgu.0.old.rcgu.o", b"root")]);
        let current = archive(&[
            (b"crate.cgu.0.new.rcgu.o", b"changed"),
            (b"crate.cgu.1.new.rcgu.o", b"added"),
        ]);
        assert_eq!(
            added_archive_member_identifiers(&previous, &current, true).unwrap(),
            Some(vec![b"crate.cgu.1.new.rcgu.o".to_vec()])
        );

        let duplicate = archive(&[
            (b"crate.cgu.0.new.rcgu.o", b"changed"),
            (b"crate.cgu.0.other.rcgu.o", b"duplicate"),
        ]);
        assert_eq!(
            added_archive_member_identifiers(&previous, &duplicate, true).unwrap(),
            None
        );

        let previous = archive(&[
            (b"crate.cgu.0.old.rcgu.o", b"zero"),
            (b"crate.cgu.2.old.rcgu.o", b"two"),
            (b"crate.cgu.4.old.rcgu.o", b"four"),
            (b"crate.cgu.6.old.rcgu.o", b"six"),
        ]);
        let four_added = archive(&[
            (b"crate.cgu.0.new.rcgu.o", b"zero"),
            (b"crate.cgu.1.new.rcgu.o", b"added"),
            (b"crate.cgu.2.new.rcgu.o", b"two"),
            (b"crate.cgu.3.new.rcgu.o", b"added"),
            (b"crate.cgu.4.new.rcgu.o", b"four"),
            (b"crate.cgu.5.new.rcgu.o", b"added"),
            (b"crate.cgu.6.new.rcgu.o", b"six"),
            (b"crate.cgu.7.new.rcgu.o", b"added"),
        ]);
        assert_eq!(
            added_archive_member_identifiers(&previous, &four_added, true).unwrap(),
            Some(vec![
                b"crate.cgu.1.new.rcgu.o".to_vec(),
                b"crate.cgu.3.new.rcgu.o".to_vec(),
                b"crate.cgu.5.new.rcgu.o".to_vec(),
                b"crate.cgu.7.new.rcgu.o".to_vec(),
            ])
        );
        assert_eq!(
            archive_member_identifier_delta(&previous, &four_added, true).unwrap(),
            Some(ArchiveMemberIdentifierDelta {
                added: vec![
                    b"crate.cgu.1.new.rcgu.o".to_vec(),
                    b"crate.cgu.3.new.rcgu.o".to_vec(),
                    b"crate.cgu.5.new.rcgu.o".to_vec(),
                    b"crate.cgu.7.new.rcgu.o".to_vec(),
                ],
                removed: Vec::new(),
            })
        );

        let removed = archive(&[
            (b"crate.cgu.0.new.rcgu.o", b"zero"),
            (b"crate.cgu.4.new.rcgu.o", b"four"),
            (b"crate.cgu.6.new.rcgu.o", b"six"),
            (b"crate.cgu.7.new.rcgu.o", b"added"),
            (b"crate.cgu.8.new.rcgu.o", b"added"),
        ]);
        assert_eq!(
            added_archive_member_identifiers(&previous, &removed, true).unwrap(),
            None
        );
        assert_eq!(
            archive_member_identifier_delta(&previous, &removed, true).unwrap(),
            Some(ArchiveMemberIdentifierDelta {
                added: vec![
                    b"crate.cgu.7.new.rcgu.o".to_vec(),
                    b"crate.cgu.8.new.rcgu.o".to_vec(),
                ],
                removed: vec![b"crate.cgu.2.old.rcgu.o".to_vec()],
            })
        );

        let reordered = archive(&[
            (b"crate.cgu.2.new.rcgu.o", b"two"),
            (b"crate.cgu.0.new.rcgu.o", b"zero"),
            (b"crate.cgu.4.new.rcgu.o", b"four"),
            (b"crate.cgu.6.new.rcgu.o", b"six"),
            (b"crate.cgu.7.new.rcgu.o", b"added"),
        ]);
        assert_eq!(
            added_archive_member_identifiers(&previous, &reordered, true).unwrap(),
            None
        );
        assert_eq!(
            archive_member_identifier_delta(&previous, &reordered, true).unwrap(),
            None
        );
    }

    #[test]
    fn owned_macho_archive_removal_requires_a_complete_active_cohort() {
        let transaction = MachOArchiveActivationState {
            kind: MachOArchiveActivationKind::AddedMembers,
            members: vec![
                MachOArchiveMemberIdentity {
                    normalized_identifier: b"crate.cgu.1.rcgu.o".to_vec(),
                    object_hash: "a".repeat(blake3::OUT_LEN * 2),
                },
                MachOArchiveMemberIdentity {
                    normalized_identifier: b"crate.cgu.2.rcgu.o".to_vec(),
                    object_hash: "b".repeat(blake3::OUT_LEN * 2),
                },
            ],
            active: true,
            sections: Vec::new(),
            relocations: Vec::new(),
            symbol_resolutions: Vec::new(),
            rollback_symbol_resolutions: Vec::new(),
            forward_patches: vec![StoredOutputPatch {
                output_offset: 64,
                data: vec![1; 4],
            }],
            rollback_patches: vec![StoredOutputPatch {
                output_offset: 64,
                data: vec![0; 4],
            }],
        };
        let dormant = MachOArchiveActivationState {
            kind: MachOArchiveActivationKind::AddedMembers,
            members: vec![MachOArchiveMemberIdentity {
                normalized_identifier: b"crate.cgu.3.rcgu.o".to_vec(),
                object_hash: "c".repeat(blake3::OUT_LEN * 2),
            }],
            active: false,
            ..transaction.clone()
        };
        let patch = FilePatchState {
            fingerprint: String::new(),
            archive_member_set_proof: None,
            archive_member_patch_fingerprints: None,
            macho_archive_members: vec![transaction, dormant],
            sections: Vec::new(),
            raw_sections: None,
        };

        let ownership = owned_macho_archive_removal_indices(
            &patch,
            &[
                b"crate.cgu.1.session.rcgu.o".to_vec(),
                b"crate.cgu.2.session.rcgu.o".to_vec(),
            ],
        )
        .unwrap();
        assert_eq!(ownership.tracked_indices, vec![0]);
        assert!(ownership.initially_owned_identifiers.is_empty());
        assert!(
            owned_macho_archive_removal_indices(&patch, &[b"crate.cgu.1.session.rcgu.o".to_vec()],)
                .unwrap_err()
                .contains("split an activation cohort")
        );
        let ownership =
            owned_macho_archive_removal_indices(&patch, &[b"crate.cgu.3.session.rcgu.o".to_vec()])
                .unwrap();
        assert!(ownership.tracked_indices.is_empty());
        assert_eq!(
            ownership.initially_owned_identifiers,
            vec![b"crate.cgu.3.rcgu.o".to_vec()]
        );
        assert_eq!(
            dormant_macho_archive_reactivation_index(
                &patch,
                &[b"crate.cgu.3.session.rcgu.o".to_vec()],
            )
            .unwrap(),
            Some(1),
        );
        assert_eq!(
            dormant_macho_archive_reactivation_index(
                &patch,
                &[b"crate.cgu.4.session.rcgu.o".to_vec()],
            )
            .unwrap(),
            None,
        );
        assert!(
            dormant_macho_archive_reactivation_index(
                &patch,
                &[b"crate.cgu.1.session.rcgu.o".to_vec()],
            )
            .unwrap_err()
            .contains("active ownership")
        );
        assert!(
            dormant_macho_archive_reactivation_index(
                &patch,
                &[
                    b"crate.cgu.3.session.rcgu.o".to_vec(),
                    b"crate.cgu.4.session.rcgu.o".to_vec(),
                ],
            )
            .unwrap_err()
            .contains("mix dormant and new ownership")
        );
        let mut incomplete = patch;
        incomplete.macho_archive_members[1].rollback_patches[0].output_offset += 1;
        assert!(
            dormant_macho_archive_reactivation_index(
                &incomplete,
                &[b"crate.cgu.3.session.rcgu.o".to_vec()],
            )
            .unwrap_err()
            .contains("transaction is incomplete")
        );
    }

    #[test]
    fn initially_owned_macho_archive_member_becomes_exact_dormant_ownership() {
        let input_file = hex::encode("libcrate.rlib");
        let previous_identifier = b"crate-hash.cgu.4.old.rcgu.o";
        let current_identifier = b"crate-hash.cgu.4.new.rcgu.o";
        let object = test_macho_object(&[1; 4], &[2; 4], 0);
        let mut builder = ar::Builder::new(Vec::new());
        builder
            .append(
                &ar::Header::new(previous_identifier.to_vec(), object.len() as u64),
                object.as_slice(),
            )
            .unwrap();
        let previous = builder.into_inner().unwrap();
        let member = match patch_archive_member_bytes(&previous, previous_identifier).unwrap() {
            ArchiveMemberMatch::Unique(member) => member,
            _ => panic!("expected unique archive member"),
        };
        let input = resolved_patch_input_ref(&input_file, &input_file, member).unwrap();
        let file = object::File::parse(member.bytes).unwrap();
        let text = file.section_by_name("__text").unwrap();
        let section = FilePatchSectionState {
            input: input.clone(),
            section_index: patch_section_record_index(&file, text.index()).unwrap(),
            section_name: Some("__TEXT,__text".to_owned()),
            input_size: text.size(),
            output_offset: 0,
            output_size: text.size(),
            data_hash: None,
            cstring_nul_boundaries_hash: None,
        };
        let patch = FilePatchState {
            fingerprint: String::new(),
            archive_member_set_proof: None,
            archive_member_patch_fingerprints: None,
            macho_archive_members: Vec::new(),
            sections: vec![section],
            raw_sections: None,
        };
        let mut state = initially_owned_macho_archive_removal_state(
            &previous,
            &input_file,
            &patch,
            &archive_member_patch_identifier(previous_identifier),
        )
        .unwrap()
        .unwrap();
        state.symbol_resolutions.push(MachOSymbolResolutionRecord {
            name: hex::encode("_text").into(),
            direct_value: Some(0),
            got_address: None,
            stub_address: None,
            thunk_addresses: Vec::new(),
            target: Some(RelocationTargetRecord {
                input_file: input_file.clone().into(),
                input: input.into(),
                section_index: text.index().0 as u32,
                section_offset: 0,
            }),
        });

        let output = test_macho_object(&[1; 4], &[2; 4], 0);
        retain_initial_macho_archive_removal_transaction(&mut state, &output).unwrap();
        assert!(macho_archive_transaction_patches_match(&state));
        assert_eq!(state.forward_patches.len(), 1);
        assert_eq!(state.rollback_patches.len(), 1);
        assert_ne!(
            state.forward_patches[0].data,
            state.rollback_patches[0].data
        );
        assert_eq!(&state.rollback_patches[0].data[..4], &[0; 4]);

        state.active = false;
        let retained = FilePatchState {
            macho_archive_members: vec![state],
            ..patch
        };
        assert_eq!(
            dormant_macho_archive_reactivation_index(&retained, &[current_identifier.to_vec()],)
                .unwrap(),
            Some(0)
        );
    }

    #[test]
    fn dormant_macho_archive_reactivation_requires_exact_members_and_refreshes_records() {
        fn archive(identifier: &[u8], data: &[u8]) -> Vec<u8> {
            let mut builder = ar::Builder::new(Vec::new());
            builder
                .append(
                    &ar::Header::new(identifier.to_vec(), data.len() as u64),
                    data,
                )
                .unwrap();
            builder.into_inner().unwrap()
        }

        fn archive_input_ref(input_file: &str, identifier: &[u8]) -> String {
            let mut bytes = hex::decode(input_file).unwrap();
            bytes.push(0);
            bytes.extend_from_slice(identifier);
            bytes.push(0);
            bytes.extend_from_slice(b"1:2");
            hex::encode(bytes)
        }

        let input_file = hex::encode("libcrate.rlib");
        let previous_identifier = b"c.1.old.rcgu.o";
        let current_identifier = b"c.1.new.rcgu.o";
        let member_bytes = b"identical object bytes";
        let current = archive(current_identifier, member_bytes);
        let resolver = PatchInputResolver::new(&current, true).unwrap();
        let previous_input = archive_input_ref(&input_file, previous_identifier);
        let rollback = MachOSymbolResolutionRecord {
            name: hex::encode("_rollback").into(),
            direct_value: Some(0x1000),
            got_address: None,
            stub_address: None,
            thunk_addresses: Vec::new(),
            target: None,
        };
        let dormant_resolution = MachOSymbolResolutionRecord {
            name: hex::encode("_reactivated").into(),
            direct_value: Some(0x2000),
            got_address: None,
            stub_address: None,
            thunk_addresses: Vec::new(),
            target: Some(RelocationTargetRecord {
                input_file: input_file.clone().into(),
                input: previous_input.clone().into(),
                section_index: 1,
                section_offset: 4,
            }),
        };
        let dormant_relocation = RelocationRecord {
            target_symbol_id: 7,
            written_value: Some(0x2000),
            target_value: 0x2000,
            applied_target_value: Some(0x2000),
            target_name: Some(hex::encode("_reactivated").into()),
            target: dormant_resolution.target.clone(),
            input_file: input_file.clone().into(),
            input: previous_input.clone().into(),
            section_index: 1,
            relocation_offset: 8,
            output_offset: 264,
            size: 4,
            kind: u32::from(object::macho::ARM64_RELOC_BRANCH26),
            addend: 0,
        };
        let dormant = MachOArchiveActivationState {
            kind: MachOArchiveActivationKind::AddedMembers,
            members: vec![MachOArchiveMemberIdentity {
                normalized_identifier: archive_member_patch_identifier(current_identifier),
                object_hash: hash_bytes(member_bytes),
            }],
            active: false,
            sections: vec![FilePatchSectionState {
                input: previous_input,
                section_index: 1,
                section_name: Some("__TEXT,__text".to_owned()),
                input_size: 16,
                output_offset: 256,
                output_size: 32,
                data_hash: Some("section-hash".to_owned()),
                cstring_nul_boundaries_hash: None,
            }],
            relocations: vec![dormant_relocation],
            symbol_resolutions: vec![dormant_resolution],
            rollback_symbol_resolutions: vec![rollback.clone()],
            forward_patches: vec![StoredOutputPatch {
                output_offset: 256,
                data: vec![1, 2, 3, 4],
            }],
            rollback_patches: vec![StoredOutputPatch {
                output_offset: 256,
                data: vec![0; 4],
            }],
        };
        let patch = FilePatchState {
            fingerprint: String::new(),
            archive_member_set_proof: None,
            archive_member_patch_fingerprints: None,
            macho_archive_members: vec![dormant],
            sections: Vec::new(),
            raw_sections: None,
        };

        let activation = reactivated_macho_archive_text_activation(
            &current,
            &input_file,
            &[current_identifier.to_vec()],
            &resolver,
            &patch,
            std::slice::from_ref(&rollback),
            &[],
        )
        .unwrap()
        .unwrap()
        .unwrap();

        assert!(activation.reactivated);
        assert!(activation.member_states[0].active);
        assert!(activation.member_states[0].relocations.is_empty());
        assert!(activation.member_states[0].symbol_resolutions.is_empty());
        assert_eq!(
            activation.recycled_symbol_resolution_names,
            vec![rollback.name.clone()]
        );
        assert_eq!(activation.reactivated_output_patches[0].data, [1, 2, 3, 4]);
        let refreshed = parse_patch_input_ref(&input_file, &activation.sections[0].input)
            .unwrap()
            .unwrap();
        assert_eq!(refreshed.identifier, current_identifier);
        let refreshed = parse_patch_input_ref(
            &input_file,
            activation.reactivated_relocations[0].input.as_str(),
        )
        .unwrap()
        .unwrap();
        assert_eq!(refreshed.identifier, current_identifier);
        let refreshed = parse_patch_input_ref(
            &input_file,
            activation.symbol_resolutions[0]
                .target
                .as_ref()
                .unwrap()
                .input
                .as_str(),
        )
        .unwrap()
        .unwrap();
        assert_eq!(refreshed.identifier, current_identifier);

        let mut changed_hash = patch.clone();
        changed_hash.macho_archive_members[0].members[0].object_hash =
            hash_bytes(b"different object bytes");
        assert!(
            reactivated_macho_archive_text_activation(
                &current,
                &input_file,
                &[current_identifier.to_vec()],
                &resolver,
                &changed_hash,
                std::slice::from_ref(&rollback),
                &[],
            )
            .unwrap()
            .err()
            .unwrap()
            .contains("changed while dormant")
        );

        let mut conflicting_rollback = rollback;
        conflicting_rollback.direct_value = Some(0x3000);
        assert!(
            reactivated_macho_archive_text_activation(
                &current,
                &input_file,
                &[current_identifier.to_vec()],
                &resolver,
                &patch,
                std::slice::from_ref(&conflicting_rollback),
                &[],
            )
            .unwrap()
            .err()
            .unwrap()
            .contains("rollback symbol changed while dormant")
        );
    }

    #[test]
    fn added_macho_archive_member_selection_follows_reference_closure() {
        let member = |definitions: &[&[u8]], references: &[&[u8]]| AddedMachOArchiveTextMember {
            input: String::new(),
            sections: Vec::new(),
            unwind: None,
            text_section_index: 0,
            text_object_section_index: 1,
            definitions: definitions
                .iter()
                .enumerate()
                .map(|(index, definition)| AddedMachOArchiveDefinition {
                    name: definition.to_vec(),
                    offset: index as u64 * 4,
                    desc: 0,
                    private_external: false,
                })
                .collect(),
            referenced_names: references
                .iter()
                .map(|reference| reference.to_vec())
                .collect(),
        };
        let members = vec![
            member(&[b"_first", b"_first_alias"], &[b"_second"]),
            member(&[b"_second"], &[b"_third"]),
            member(&[b"_third"], &[]),
            member(&[b"_unused"], &[]),
        ];
        let definitions = members
            .iter()
            .enumerate()
            .flat_map(|(index, member)| {
                member
                    .definitions
                    .iter()
                    .map(move |definition| (definition.name.clone(), index))
            })
            .collect::<HashMap<_, _>>();

        assert_eq!(
            selected_added_macho_archive_member_indices(
                &members,
                &definitions,
                vec![b"_first".to_vec()],
            ),
            vec![0, 1, 2]
        );
        assert_eq!(
            selected_added_macho_archive_member_indices(
                &members,
                &definitions,
                vec![b"_first_alias".to_vec()],
            ),
            vec![0, 1, 2]
        );
        assert_eq!(
            selected_added_macho_archive_member_indices(
                &members,
                &definitions,
                vec![b"_unused".to_vec()],
            ),
            vec![3]
        );
        assert!(
            selected_added_macho_archive_member_indices(
                &members,
                &definitions,
                vec![b"_missing".to_vec()],
            )
            .is_empty()
        );
    }

    #[test]
    fn added_macho_archive_member_parses_multiple_text_definitions() {
        let mut object = test_macho_object_with_data_section_name(&[0; 8], &[0; 4], 0, b"__const");
        let strings = b"\0_text\0_data\0";
        let string_offset = object
            .windows(strings.len())
            .position(|window| window == strings)
            .unwrap();
        let symbol_offset =
            string_offset - 2 * std::mem::size_of::<object::macho::Nlist64<object::Endianness>>();
        let second_symbol =
            symbol_offset + std::mem::size_of::<object::macho::Nlist64<object::Endianness>>();
        object[second_symbol + 5] = 1;
        object[second_symbol + 8..second_symbol + 16].copy_from_slice(&4_u64.to_le_bytes());

        let member = added_macho_archive_text_member(
            "input.o",
            PatchInputBytes {
                bytes: &object,
                file_offset: 0,
                archive_identifier: None,
            },
            &[],
            &[],
            &[],
        )
        .unwrap()
        .unwrap();

        assert_eq!(
            member.definitions,
            vec![
                AddedMachOArchiveDefinition {
                    name: b"_data".to_vec(),
                    offset: 4,
                    desc: 0,
                    private_external: false,
                },
                AddedMachOArchiveDefinition {
                    name: b"_text".to_vec(),
                    offset: 0,
                    desc: 0,
                    private_external: false,
                },
            ]
        );

        let resolution = MachOSymbolResolutionRecord {
            name: SharedText::from(hex::encode("_data")),
            direct_value: Some(0x1000),
            got_address: None,
            stub_address: None,
            thunk_addresses: Vec::new(),
            target: None,
        };
        assert!(matches!(
            added_macho_archive_text_member(
                "input.o",
                PatchInputBytes {
                    bytes: &object,
                    file_offset: 0,
                    archive_identifier: None,
                },
                &[],
                std::slice::from_ref(&resolution),
                &[],
            )
            .unwrap(),
            Err(reason) if reason.contains("already has a resolution")
        ));
        assert!(
            added_macho_archive_text_member(
                "input.o",
                PatchInputBytes {
                    bytes: &object,
                    file_offset: 0,
                    archive_identifier: None,
                },
                &[],
                std::slice::from_ref(&resolution),
                std::slice::from_ref(&resolution.name),
            )
            .unwrap()
            .is_ok()
        );
    }

    #[test]
    fn archive_patch_fingerprint_can_omit_added_members() {
        let archive = |members: &[(&[u8], &[u8])]| {
            let mut builder = ar::Builder::new(Vec::new());
            for (identifier, data) in members {
                builder
                    .append(
                        &ar::Header::new(identifier.to_vec(), data.len() as u64),
                        *data,
                    )
                    .unwrap();
            }
            builder.into_inner().unwrap()
        };
        let previous = archive(&[(b"first.o", b"first"), (b"last.o", b"last")]);
        let current = archive(&[
            (b"added-before.o", b"added"),
            (b"first.o", b"first"),
            (b"added-middle.o", b"added"),
            (b"last.o", b"last"),
            (b"added-after.o", b"added"),
        ]);
        let (previous_fingerprint, _) =
            archive_patch_fingerprint_with_previous(&previous, &[], None, false, &[], &[])
                .unwrap()
                .unwrap();
        let (current_fingerprint, _) =
            archive_patch_fingerprint_with_previous(&current, &[], None, false, &[], &[])
                .unwrap()
                .unwrap();
        let ignored = [
            b"added-before.o".to_vec(),
            b"added-middle.o".to_vec(),
            b"added-after.o".to_vec(),
        ];
        let (without_added, _) =
            archive_patch_fingerprint_with_previous(&current, &[], None, false, &ignored, &[])
                .unwrap()
                .unwrap();

        assert_ne!(previous_fingerprint, current_fingerprint);
        assert_eq!(previous_fingerprint, without_added);
    }

    #[test]
    fn archive_patch_fingerprint_can_reuse_replaced_member() {
        let previous_digest = "a".repeat(blake3::OUT_LEN * 2);
        let current_digest = "b".repeat(blake3::OUT_LEN * 2);
        let previous_identifier = b"crate-hash.cgu.old.rcgu.o";
        let current_identifier = b"crate-hash.cgu.new.rcgu.o";
        let (previous, _) = rustc_rlib_with_raw_object_manifest(&[(
            previous_identifier,
            previous_digest.as_str(),
            b"previous",
        )]);
        let (current, _) = rustc_rlib_with_raw_object_manifest(&[(
            current_identifier,
            current_digest.as_str(),
            b"current",
        )]);
        let (previous_fingerprint, previous_members) =
            archive_patch_fingerprint_with_previous(&previous, &[], None, true, &[], &[])
                .unwrap()
                .unwrap();
        let (current_fingerprint, _) = archive_patch_fingerprint_with_previous(
            &current,
            &[],
            previous_members.as_deref(),
            true,
            &[],
            &[],
        )
        .unwrap()
        .unwrap();
        let replaced = [archive_member_patch_identifier(current_identifier)];
        let (replaced_fingerprint, _) = archive_patch_fingerprint_with_previous(
            &current,
            &[],
            previous_members.as_deref(),
            true,
            &[],
            &replaced,
        )
        .unwrap()
        .unwrap();

        assert_ne!(previous_fingerprint, current_fingerprint);
        assert_eq!(previous_fingerprint, replaced_fingerprint);
    }

    #[test]
    fn rustc_rlib_link_content_digest_decoder_requires_versioned_blake3_trailer() {
        let digest = "a".repeat(blake3::OUT_LEN * 2);
        let mut metadata = b"encoded metadata".to_vec();
        metadata.extend_from_slice(RUSTC_RLIB_LINK_CONTENT_DIGEST_PREFIX);
        metadata.extend_from_slice(digest.as_bytes());
        metadata.extend_from_slice(RUSTC_SERIALIZED_METADATA_END);

        assert_eq!(
            decode_rustc_rlib_link_content_digest(&metadata),
            Some(digest)
        );
        assert_eq!(
            decode_rustc_rlib_link_content_digest(b"encoded metadatarust-end-file"),
            None
        );

        let last = metadata.len() - RUSTC_SERIALIZED_METADATA_END.len() - 1;
        metadata[last] = b'g';
        assert_eq!(decode_rustc_rlib_link_content_digest(&metadata), None);
    }

    #[test]
    fn rustc_rlib_raw_object_digest_decoder_requires_versioned_ordered_trailer() {
        let aggregate_digest = "c".repeat(blake3::OUT_LEN * 2);
        let objects = [
            (
                b"crate.cgu.0.old.rcgu.o".as_slice(),
                "a".repeat(blake3::OUT_LEN * 2),
            ),
            (
                b"crate.cgu.1.old.rcgu.o".as_slice(),
                "b".repeat(blake3::OUT_LEN * 2),
            ),
        ];
        let mut payload = Vec::new();
        payload.extend_from_slice(&(objects.len() as u64).to_le_bytes());
        for (identifier, digest) in &objects {
            payload.extend_from_slice(&(identifier.len() as u64).to_le_bytes());
            payload.extend_from_slice(identifier);
            payload.extend_from_slice(digest.as_bytes());
        }
        let mut metadata = b"encoded metadata".to_vec();
        metadata.extend_from_slice(RUSTC_RLIB_RAW_OBJECT_DIGESTS_PREFIX);
        metadata.extend_from_slice(&payload);
        metadata.extend_from_slice(&(payload.len() as u64).to_le_bytes());
        metadata.extend_from_slice(RUSTC_RLIB_LINK_CONTENT_DIGEST_PREFIX);
        metadata.extend_from_slice(aggregate_digest.as_bytes());
        metadata.extend_from_slice(RUSTC_SERIALIZED_METADATA_END);

        assert_eq!(
            decode_rustc_rlib_raw_object_digests(&metadata),
            Some(
                objects
                    .iter()
                    .map(|(identifier, digest)| RustcRlibRawObjectDigest {
                        identifier: identifier.to_vec(),
                        digest: digest.clone(),
                    })
                    .collect()
            )
        );
        assert_eq!(
            decode_rustc_rlib_link_content_digest(&metadata),
            Some(aggregate_digest)
        );

        let payload_len_offset = metadata.len()
            - RUSTC_SERIALIZED_METADATA_END.len()
            - RUSTC_RLIB_LINK_CONTENT_DIGEST_PREFIX.len()
            - blake3::OUT_LEN * 2
            - 8;
        metadata[payload_len_offset..payload_len_offset + 8]
            .copy_from_slice(&u64::MAX.to_le_bytes());
        assert_eq!(decode_rustc_rlib_raw_object_digests(&metadata), None);
        assert_eq!(
            decode_rustc_rlib_link_content_digest(&metadata),
            Some("c".repeat(blake3::OUT_LEN * 2))
        );
    }

    fn rustc_rlib_with_raw_object_manifest(
        objects: &[(&[u8], &str, &[u8])],
    ) -> (Vec<u8>, RustcRlibRawObjectManifest) {
        let ordered_objects = objects
            .iter()
            .map(|(identifier, digest, _)| RustcRlibRawObjectDigest {
                identifier: identifier.to_vec(),
                digest: (*digest).to_owned(),
            })
            .collect::<Vec<_>>();
        let link_content_digest =
            rustc_rlib_link_content_digest_from_raw_objects(&ordered_objects).unwrap();
        let mut payload = Vec::new();
        payload.extend_from_slice(&(ordered_objects.len() as u64).to_le_bytes());
        for object in &ordered_objects {
            payload.extend_from_slice(&(object.identifier.len() as u64).to_le_bytes());
            payload.extend_from_slice(&object.identifier);
            payload.extend_from_slice(object.digest.as_bytes());
        }
        let mut metadata = b"encoded metadata".to_vec();
        metadata.extend_from_slice(RUSTC_RLIB_RAW_OBJECT_DIGESTS_PREFIX);
        metadata.extend_from_slice(&payload);
        metadata.extend_from_slice(&(payload.len() as u64).to_le_bytes());
        metadata.extend_from_slice(RUSTC_RLIB_LINK_CONTENT_DIGEST_PREFIX);
        metadata.extend_from_slice(link_content_digest.as_bytes());
        metadata.extend_from_slice(RUSTC_SERIALIZED_METADATA_END);
        let metadata = rmeta_link_wrapper_elf(&metadata);
        let mut builder = ar::Builder::new(Vec::new());
        builder
            .append(
                &ar::Header::new(
                    RUSTC_RLIB_LINK_METADATA_MEMBER.to_vec(),
                    metadata.len() as u64,
                ),
                metadata.as_slice(),
            )
            .unwrap();
        for (identifier, _, data) in objects {
            builder
                .append(
                    &ar::Header::new(identifier.to_vec(), data.len() as u64),
                    *data,
                )
                .unwrap();
        }
        (
            builder.into_inner().unwrap(),
            RustcRlibRawObjectManifest {
                link_content_digest,
                ordered_objects,
            },
        )
    }

    #[test]
    fn rustc_rlib_provenance_validates_raw_object_manifest_against_archive() {
        let digest_a = "a".repeat(blake3::OUT_LEN * 2);
        let digest_b = "b".repeat(blake3::OUT_LEN * 2);
        let mut producer_contents = b"rustc-rlib-link-content-v1".to_vec();
        producer_contents.extend_from_slice(&1_u64.to_le_bytes());
        producer_contents.extend_from_slice(&(b"cgu.module.0".len() as u64).to_le_bytes());
        producer_contents.extend_from_slice(b"cgu.module.0");
        producer_contents.extend_from_slice(digest_a.as_bytes());
        assert_eq!(
            rustc_rlib_link_content_digest_from_raw_objects(&[RustcRlibRawObjectDigest {
                identifier: b"crate-hash.cgu.module.0.old.rcgu.o".to_vec(),
                digest: digest_a.clone(),
            }]),
            Some(blake3::hash(&producer_contents).to_hex().to_string())
        );
        assert_eq!(
            rustc_rlib_module_name_from_object_identifier(b"crate-hash.cgu.module.0.old.rcgu.o"),
            Some(b"cgu.module.0".as_slice())
        );
        assert_eq!(
            rustc_rlib_module_name_from_object_identifier(b"missing-module.old.rcgu.o"),
            None
        );
        assert_eq!(
            rustc_rlib_module_name_from_object_identifier(b".module.old.rcgu.o"),
            None
        );

        let (archive, expected) = rustc_rlib_with_raw_object_manifest(&[
            (
                b"crate-hash.cgu.module.0.old.rcgu.o",
                digest_a.as_str(),
                b"first",
            ),
            (
                b"crate-hash.cgu.module.1.old.rcgu.o",
                digest_b.as_str(),
                b"second",
            ),
        ]);

        let provenance = rustc_rlib_provenance(&archive).unwrap();

        assert_eq!(provenance.link_content_digest, expected.link_content_digest);
        assert_eq!(provenance.raw_object_manifest, Some(expected));

        let (reordered_archive, _) = rustc_rlib_with_raw_object_manifest(&[
            (
                b"crate-hash.cgu.module.1.old.rcgu.o",
                digest_b.as_str(),
                b"second",
            ),
            (
                b"crate-hash.cgu.module.0.old.rcgu.o",
                digest_a.as_str(),
                b"first",
            ),
        ]);
        let mut mismatched = reordered_archive;
        let first = mismatched
            .windows(b"crate-hash.cgu.module.1.old.rcgu.o".len())
            .position(|bytes| bytes == b"crate-hash.cgu.module.1.old.rcgu.o")
            .unwrap();
        mismatched[first..first + b"crate-hash.cgu.module.1.old.rcgu.o".len()]
            .copy_from_slice(b"crate-hash.cgu.module.0.old.rcgu.o");
        assert!(
            rustc_rlib_provenance(&mismatched)
                .unwrap()
                .raw_object_manifest
                .is_none()
        );
    }

