    #[test]
    fn rustc_rlib_provenance_rejects_duplicate_metadata_and_normalized_objects() {
        let digest_a = "a".repeat(blake3::OUT_LEN * 2);
        let (archive, _) = rustc_rlib_with_raw_object_manifest(&[(
            b"crate-hash.a.old.rcgu.o",
            digest_a.as_str(),
            b"first",
        )]);
        let ArchiveMemberMatch::Unique(metadata) =
            patch_archive_member_bytes(&archive, RUSTC_RLIB_LINK_METADATA_MEMBER).unwrap()
        else {
            panic!("expected metadata archive member");
        };
        let mut builder = ar::Builder::new(Vec::new());
        builder
            .append(
                &ar::Header::new(
                    RUSTC_RLIB_LINK_METADATA_MEMBER.to_vec(),
                    metadata.bytes.len() as u64,
                ),
                metadata.bytes,
            )
            .unwrap();
        builder
            .append(
                &ar::Header::new(
                    RUSTC_RLIB_LINK_METADATA_MEMBER.to_vec(),
                    metadata.bytes.len() as u64,
                ),
                metadata.bytes,
            )
            .unwrap();
        assert!(rustc_rlib_provenance(&builder.into_inner().unwrap()).is_none());

        let (duplicate_objects, _) = rustc_rlib_with_raw_object_manifest(&[
            (b"crate-hash.a.old.rcgu.o", digest_a.as_str(), b"first"),
            (b"crate-hash.a.new.rcgu.o", digest_a.as_str(), b"second"),
        ]);
        assert!(
            rustc_rlib_provenance(&duplicate_objects)
                .unwrap()
                .raw_object_manifest
                .is_none()
        );
    }

    #[test]
    fn rustc_rlib_raw_object_delta_classifies_ordered_changes() {
        let digest_a = "a".repeat(blake3::OUT_LEN * 2);
        let digest_b = "b".repeat(blake3::OUT_LEN * 2);
        let digest_c = "c".repeat(blake3::OUT_LEN * 2);
        let digest_d = "d".repeat(blake3::OUT_LEN * 2);
        let (_, previous) = rustc_rlib_with_raw_object_manifest(&[
            (b"crate-hash.a.old.rcgu.o", digest_a.as_str(), b"a"),
            (b"crate-hash.b.old.rcgu.o", digest_b.as_str(), b"b"),
        ]);
        let (_, current) = rustc_rlib_with_raw_object_manifest(&[
            (b"crate-hash.a.new.rcgu.o", digest_a.as_str(), b"a"),
            (b"crate-hash.b.new.rcgu.o", digest_c.as_str(), b"changed"),
            (b"crate-hash.c.new.rcgu.o", digest_d.as_str(), b"added"),
        ]);

        let delta = rustc_rlib_raw_object_delta(&previous, &current).unwrap();

        assert_eq!(delta.unchanged, current.ordered_objects[0..1]);
        assert_eq!(delta.changed, current.ordered_objects[1..2]);
        assert_eq!(delta.added, current.ordered_objects[2..3]);
        assert!(delta.removed.is_empty());

        let (_, removed) = rustc_rlib_with_raw_object_manifest(&[(
            b"crate-hash.a.new.rcgu.o",
            digest_a.as_str(),
            b"a",
        )]);
        let removed_delta = rustc_rlib_raw_object_delta(&previous, &removed).unwrap();
        assert_eq!(removed_delta.unchanged, removed.ordered_objects);
        assert!(removed_delta.changed.is_empty());
        assert!(removed_delta.added.is_empty());
        assert_eq!(removed_delta.removed, previous.ordered_objects[1..2]);

        let (_, reordered) = rustc_rlib_with_raw_object_manifest(&[
            (b"crate-hash.b.new.rcgu.o", digest_b.as_str(), b"b"),
            (b"crate-hash.a.new.rcgu.o", digest_a.as_str(), b"a"),
        ]);
        assert!(rustc_rlib_raw_object_delta(&previous, &reordered).is_none());
    }

    #[test]
    fn changed_rust_archive_aliases_only_unchanged_manifest_members() {
        let digest_a = "a".repeat(blake3::OUT_LEN * 2);
        let digest_b = "b".repeat(blake3::OUT_LEN * 2);
        let digest_c = "c".repeat(blake3::OUT_LEN * 2);
        let digest_d = "d".repeat(blake3::OUT_LEN * 2);
        let (previous, previous_manifest) = rustc_rlib_with_raw_object_manifest(&[
            (
                b"crate-hash.unchanged.old.rcgu.o",
                digest_a.as_str(),
                b"unchanged",
            ),
            (
                b"crate-hash.changed.same.rcgu.o",
                digest_b.as_str(),
                b"previous",
            ),
        ]);
        let (current, current_manifest) = rustc_rlib_with_raw_object_manifest(&[
            (b"crate-hash.added.new.rcgu.o", digest_c.as_str(), b"added"),
            (
                b"crate-hash.unchanged.new.rcgu.o",
                digest_a.as_str(),
                b"unchanged",
            ),
            (
                b"crate-hash.changed.same.rcgu.o",
                digest_d.as_str(),
                b"current",
            ),
        ]);
        let input_file = hex::encode("libcrate.rlib");
        let previous_resolver = PatchInputResolver::new(&previous, true).unwrap();
        let previous_input_ref = |identifier: &[u8]| {
            let mut input_ref = b"libcrate.rlib".to_vec();
            input_ref.push(0);
            input_ref.extend_from_slice(identifier);
            input_ref.extend_from_slice(b"\00:1");
            let encoded = hex::encode(input_ref);
            let input = previous_resolver
                .resolve(&input_file, &encoded, PatchInputLookup::MatchArchiveMember)
                .unwrap()
                .unwrap();
            resolved_patch_input_ref(&input_file, &encoded, input).unwrap()
        };
        let unchanged = SectionRecord {
            input_file: input_file.clone().into(),
            input: previous_input_ref(b"crate-hash.unchanged.old.rcgu.o").into(),
            section_index: 3,
            output_offset: 64,
            size: 16,
        };
        let changed = SectionRecord {
            input_file: input_file.clone().into(),
            input: previous_input_ref(b"crate-hash.changed.same.rcgu.o").into(),
            section_index: 4,
            output_offset: 80,
            size: 16,
        };

        let aliases = reusable_rust_archive_section_aliases(
            &input_file,
            &previous_manifest,
            &current_manifest,
            &current,
            &[unchanged.clone(), changed].into_iter().collect(),
        )
        .unwrap();

        assert_eq!(aliases.len(), 1);
        assert_eq!(aliases[0].section_index, unchanged.section_index);
        assert_eq!(aliases[0].output_offset, unchanged.output_offset);
        assert_eq!(aliases[0].size, unchanged.size);
        let parsed = parse_patch_input_ref(&input_file, &aliases[0].input)
            .unwrap()
            .unwrap();
        assert_eq!(
            parsed.identifier,
            b"crate-hash.unchanged.new.rcgu.o".as_slice()
        );
        assert_ne!(aliases[0].input, unchanged.input);
    }

    #[test]
    fn archive_patch_fingerprint_reuses_trusted_unchanged_rustc_object_digests() {
        let archive = |digest: &str, object: &[u8]| {
            let mut payload = Vec::new();
            payload.extend_from_slice(&1_u64.to_le_bytes());
            payload.extend_from_slice(&(b"crate.cgu.0.old.rcgu.o".len() as u64).to_le_bytes());
            payload.extend_from_slice(b"crate.cgu.0.old.rcgu.o");
            payload.extend_from_slice(digest.as_bytes());
            let mut metadata = b"encoded metadata".to_vec();
            metadata.extend_from_slice(RUSTC_RLIB_RAW_OBJECT_DIGESTS_PREFIX);
            metadata.extend_from_slice(&payload);
            metadata.extend_from_slice(&(payload.len() as u64).to_le_bytes());
            metadata.extend_from_slice(RUSTC_RLIB_LINK_CONTENT_DIGEST_PREFIX);
            metadata.extend_from_slice("c".repeat(blake3::OUT_LEN * 2).as_bytes());
            metadata.extend_from_slice(RUSTC_SERIALIZED_METADATA_END);
            let metadata = rmeta_link_wrapper_elf(&metadata);
            let mut builder = ar::Builder::new(Vec::new());
            builder
                .append(
                    &ar::Header::new(
                        RUSTC_RLIB_LINK_METADATA_MEMBER.to_vec(),
                        metadata.len() as u64,
                    ),
                    metadata.as_slice(),
                )
                .unwrap();
            builder
                .append(
                    &ar::Header::new(b"crate.cgu.0.old.rcgu.o".to_vec(), object.len() as u64),
                    object,
                )
                .unwrap();
            builder.into_inner().unwrap()
        };
        let digest = "a".repeat(blake3::OUT_LEN * 2);
        let previous = archive(&digest, b"object");
        let changed_with_same_digest = archive(&digest, b"mutant");
        let changed_with_changed_digest = archive(&"b".repeat(blake3::OUT_LEN * 2), b"mutant");
        let (previous_fingerprint, previous_members) =
            archive_patch_fingerprint_with_previous(&previous, &[], None, true, &[], &[])
                .unwrap()
                .unwrap();
        let (reused_fingerprint, _) = archive_patch_fingerprint_with_previous(
            &changed_with_same_digest,
            &[],
            previous_members.as_deref(),
            true,
            &[],
            &[],
        )
        .unwrap()
        .unwrap();
        let (changed_fingerprint, _) = archive_patch_fingerprint_with_previous(
            &changed_with_changed_digest,
            &[],
            previous_members.as_deref(),
            true,
            &[],
            &[],
        )
        .unwrap()
        .unwrap();

        assert_eq!(previous_fingerprint, reused_fingerprint);
        assert_ne!(previous_fingerprint, changed_fingerprint);
        assert_eq!(
            archive_patch_fingerprint(&previous, &[]).unwrap(),
            Some(previous_fingerprint)
        );
    }

    #[test]
    fn archive_patch_fingerprint_reuses_shifted_unchanged_rustc_members() {
        let unchanged_digest = "a".repeat(blake3::OUT_LEN * 2);
        let added_digest = "b".repeat(blake3::OUT_LEN * 2);
        let unchanged_identifier = b"crate.cgu.0.old.rcgu.o";
        let added_identifier = b"crate.cgu.added.old.rcgu.o";
        let (previous, _) = rustc_rlib_with_raw_object_manifest(&[(
            unchanged_identifier,
            unchanged_digest.as_str(),
            b"object",
        )]);
        let (current, _) = rustc_rlib_with_raw_object_manifest(&[
            (added_identifier, added_digest.as_str(), b"added"),
            (unchanged_identifier, unchanged_digest.as_str(), b"mutant"),
        ]);
        let (previous_fingerprint, previous_members) =
            archive_patch_fingerprint_with_previous(&previous, &[], None, true, &[], &[])
                .unwrap()
                .unwrap();
        let ignored = [archive_member_patch_identifier(added_identifier)];
        let (current_fingerprint, current_members) = archive_patch_fingerprint_with_previous(
            &current,
            &[],
            previous_members.as_deref(),
            true,
            &ignored,
            &[],
        )
        .unwrap()
        .unwrap();

        assert_eq!(previous_fingerprint, current_fingerprint);
        let current_members = current_members.unwrap();
        assert_eq!(current_members.len(), 1);
        assert_eq!(current_members[0].archive_member_index, 2);
        assert_eq!(
            current_members[0].identifier,
            archive_member_patch_identifier(unchanged_identifier)
        );
    }

    #[test]
    fn rustc_rlib_link_content_digest_reads_metadata_archive_member() {
        let archive = |digest: &str| {
            let mut metadata = b"encoded metadata".to_vec();
            metadata.extend_from_slice(RUSTC_RLIB_LINK_CONTENT_DIGEST_PREFIX);
            metadata.extend_from_slice(digest.as_bytes());
            metadata.extend_from_slice(RUSTC_SERIALIZED_METADATA_END);
            let metadata = rmeta_link_wrapper_elf(&metadata);
            let mut builder = ar::Builder::new(Vec::new());
            builder
                .append(
                    &ar::Header::new(
                        RUSTC_RLIB_LINK_METADATA_MEMBER.to_vec(),
                        metadata.len() as u64,
                    ),
                    metadata.as_slice(),
                )
                .unwrap();
            builder.into_inner().unwrap()
        };
        let previous_digest = "a".repeat(blake3::OUT_LEN * 2);
        let current_digest = "b".repeat(blake3::OUT_LEN * 2);
        let previous = archive(&previous_digest);
        let current = archive(&current_digest);
        let input = FileState {
            path: hex::encode("libarchive.rlib"),
            content: FileContentState::from_bytes(&previous),
            snapshot_identity: None,
            rustc_link_content_digest: None,
            rustc_raw_object_manifest: None,
            patch: Some(FilePatchState {
                fingerprint: String::new(),
                archive_member_set_proof: archive_member_set_proof(&previous).unwrap(),
                archive_member_patch_fingerprints: None,
                macho_archive_members: Vec::new(),
                sections: Vec::new(),
                raw_sections: None,
            }),
        };

        assert_eq!(
            rustc_rlib_link_content_digest(&previous),
            Some(previous_digest.clone())
        );
        assert!(rustc_rlib_link_content_digest_matches_previous(
            &input, &previous
        ));
        assert!(!rustc_rlib_link_content_digest_matches_previous(
            &input, &current
        ));

        let dir = tempfile::tempdir().unwrap();
        let path = dir.path().join("libarchive.rlib");
        std::fs::write(&path, &previous).unwrap();
        let content = rustc_rlib_link_content_digest_matches_previous_path(&input, &path).unwrap();
        assert_eq!(content.len, previous.len() as u64);
        assert!(content.hash.is_empty());
        assert!(content.identity.is_some());

        std::fs::write(&path, &current).unwrap();
        assert!(rustc_rlib_link_content_digest_matches_previous_path(&input, &path).is_none());

        let padded_bsd_archive = {
            let mut metadata = b"encoded metadata".to_vec();
            metadata.extend_from_slice(RUSTC_RLIB_LINK_CONTENT_DIGEST_PREFIX);
            metadata.extend_from_slice(previous_digest.as_bytes());
            metadata.extend_from_slice(RUSTC_SERIALIZED_METADATA_END);
            let metadata = rmeta_link_wrapper_elf(&metadata);
            let member_name = [RUSTC_RLIB_LINK_METADATA_MEMBER, b"\0\0"].concat();
            let member_size = member_name.len() + metadata.len();
            let mut archive = b"!<arch>\n".to_vec();
            let mut append_field = |value: &[u8], width: usize| {
                archive.extend_from_slice(value);
                archive.resize(archive.len() + width - value.len(), b' ');
            };
            append_field(b"#1/16", 16);
            append_field(b"0", 12);
            append_field(b"0", 6);
            append_field(b"0", 6);
            append_field(b"100644", 8);
            append_field(member_size.to_string().as_bytes(), 10);
            archive.extend_from_slice(b"`\n");
            archive.extend_from_slice(&member_name);
            archive.extend_from_slice(&metadata);
            if member_size % 2 != 0 {
                archive.push(b'\n');
            }
            archive
        };
        std::fs::write(&path, &padded_bsd_archive).unwrap();
        let content = rustc_rlib_link_content_digest_matches_previous_path(&input, &path).unwrap();
        assert_eq!(content.len, padded_bsd_archive.len() as u64);
    }

    fn rustc_rlib_with_link_content_digest(
        invocation: &[u8],
        digest: &str,
        object: &[u8],
    ) -> Vec<u8> {
        let mut metadata = b"encoded metadata".to_vec();
        metadata.extend_from_slice(RUSTC_RLIB_LINK_CONTENT_DIGEST_PREFIX);
        metadata.extend_from_slice(digest.as_bytes());
        metadata.extend_from_slice(RUSTC_SERIALIZED_METADATA_END);
        let metadata = rmeta_link_wrapper_elf(&metadata);
        let mut builder = ar::Builder::new(Vec::new());
        builder
            .append(
                &ar::Header::new(
                    [b"crate.cgu.0.".as_slice(), invocation, b".rcgu.o"].concat(),
                    object.len() as u64,
                ),
                object,
            )
            .unwrap();
        builder
            .append(
                &ar::Header::new(
                    RUSTC_RLIB_LINK_METADATA_MEMBER.to_vec(),
                    metadata.len() as u64,
                ),
                metadata.as_slice(),
            )
            .unwrap();
        builder.into_inner().unwrap()
    }

