    #[test]
    fn reserved_range_allocation_is_exact_part_first_fit() {
        let output = [0; 96];
        let mut state = state("args", &output, &[("a.o", b"a")]);
        state.reserved_ranges = vec![
            ReservedRangeRecord {
                output_section_id: 4,
                alignment_exponent: 2,
                output_offset: 64,
                size: 16,
            },
            ReservedRangeRecord {
                output_section_id: 5,
                alignment_exponent: 2,
                output_offset: 16,
                size: 16,
            },
            ReservedRangeRecord {
                output_section_id: 4,
                alignment_exponent: 3,
                output_offset: 32,
                size: 16,
            },
            ReservedRangeRecord {
                output_section_id: 4,
                alignment_exponent: 2,
                output_offset: 48,
                size: 8,
            },
        ];

        assert_eq!(
            allocate_reserved_range(&mut state.reserved_ranges, 4, 2, 5).unwrap(),
            Some(ReservedRangeAllocation {
                output_offset: 48,
                size: 8,
            })
        );
        assert_eq!(
            allocate_reserved_range(&mut state.reserved_ranges, 4, 2, 9).unwrap(),
            Some(ReservedRangeAllocation {
                output_offset: 64,
                size: 12,
            })
        );
        assert_eq!(
            allocate_reserved_range(&mut state.reserved_ranges, 4, 3, 8).unwrap(),
            Some(ReservedRangeAllocation {
                output_offset: 32,
                size: 8,
            })
        );
        assert_eq!(
            state.reserved_ranges,
            vec![
                ReservedRangeRecord {
                    output_section_id: 4,
                    alignment_exponent: 2,
                    output_offset: 76,
                    size: 4,
                },
                ReservedRangeRecord {
                    output_section_id: 4,
                    alignment_exponent: 3,
                    output_offset: 40,
                    size: 8,
                },
                ReservedRangeRecord {
                    output_section_id: 5,
                    alignment_exponent: 2,
                    output_offset: 16,
                    size: 16,
                },
            ]
        );
    }

    #[test]
    fn unavailable_reserved_range_allocation_does_not_mutate_state() {
        let output = [0; 64];
        let mut state = state("args", &output, &[("a.o", b"a")]);
        state.reserved_ranges = vec![ReservedRangeRecord {
            output_section_id: 4,
            alignment_exponent: 2,
            output_offset: 16,
            size: 8,
        }];
        let previous = state.reserved_ranges.clone();

        assert_eq!(
            allocate_reserved_range(&mut state.reserved_ranges, 4, 2, 9).unwrap(),
            None
        );
        assert_eq!(
            allocate_reserved_range(&mut state.reserved_ranges, 4, 3, 8).unwrap(),
            None
        );
        assert_eq!(
            allocate_reserved_range(&mut state.reserved_ranges, 5, 2, 8).unwrap(),
            None
        );
        assert_eq!(
            allocate_reserved_range(&mut state.reserved_ranges, 4, 2, 0).unwrap(),
            None
        );
        assert_eq!(state.reserved_ranges, previous);

        state.reserved_ranges[0].alignment_exponent = 3;
        let previous = state.reserved_ranges.clone();
        assert_eq!(
            allocate_reserved_range(&mut state.reserved_ranges, 4, 2, 8).unwrap(),
            None
        );
        assert_eq!(state.reserved_ranges, previous);
    }

