    #[test]
    fn persisted_state_round_trips_macho_archive_member_ownership() {
        let mut state = state("args", b"output", &[("libarchive.rlib", b"archive")]);
        let input_file = state.input_files[0].path.clone();
        let identifier = b"crate.cgu.old.rcgu.o";
        let normalized_identifier = archive_member_patch_identifier(identifier);
        let mut member_input = b"libarchive.rlib".to_vec();
        member_input.push(0);
        member_input.extend_from_slice(identifier);
        member_input.push(0);
        member_input.extend_from_slice(b"64:128");
        let member_input = hex::encode(member_input);
        let section = FilePatchSectionState {
            input: member_input.clone(),
            section_index: 1,
            section_name: Some("__TEXT,__text".to_owned()),
            input_size: 16,
            output_offset: 256,
            output_size: 32,
            data_hash: Some("section-hash".to_owned()),
            cstring_nul_boundaries_hash: None,
        };
        let dormant_relocation = RelocationRecord {
            target_symbol_id: 7,
            written_value: Some(0x1000),
            target_value: 0x2000,
            applied_target_value: Some(0x2000),
            target_name: Some(hex::encode("_target").into()),
            target: Some(RelocationTargetRecord {
                input_file: input_file.clone().into(),
                input: member_input.clone().into(),
                section_index: 1,
                section_offset: 4,
            }),
            input_file: input_file.clone().into(),
            input: member_input.clone().into(),
            section_index: 1,
            relocation_offset: 8,
            output_offset: 264,
            size: 4,
            kind: u32::from(object::macho::ARM64_RELOC_BRANCH26),
            addend: 0,
        };
        let dormant_resolution = MachOSymbolResolutionRecord {
            name: hex::encode("_target").into(),
            direct_value: Some(0x2000),
            got_address: None,
            stub_address: None,
            thunk_addresses: Vec::new(),
            target: Some(RelocationTargetRecord {
                input_file: input_file.into(),
                input: member_input.into(),
                section_index: 1,
                section_offset: 4,
            }),
        };
        let dormant_section = FilePatchSectionState {
            input: section
                .input
                .replace(&hex::encode(identifier), &hex::encode("dormant.member.o")),
            ..section.clone()
        };
        state.input_files[0].patch = Some(FilePatchState {
            fingerprint: "patch-hash".to_owned(),
            archive_member_set_proof: None,
            archive_member_patch_fingerprints: None,
            macho_archive_members: vec![
                MachOArchiveActivationState {
                    kind: MachOArchiveActivationKind::AddedMembers,
                    members: vec![MachOArchiveMemberIdentity {
                        normalized_identifier,
                        object_hash: "a".repeat(blake3::OUT_LEN * 2),
                    }],
                    active: true,
                    sections: vec![section.clone()],
                    relocations: Vec::new(),
                    symbol_resolutions: Vec::new(),
                    rollback_symbol_resolutions: vec![dormant_resolution.clone()],
                    forward_patches: vec![StoredOutputPatch {
                        output_offset: 256,
                        data: vec![1, 2, 3, 4],
                    }],
                    rollback_patches: vec![StoredOutputPatch {
                        output_offset: 256,
                        data: vec![0; 4],
                    }],
                },
                MachOArchiveActivationState {
                    kind: MachOArchiveActivationKind::AddedMembers,
                    members: vec![MachOArchiveMemberIdentity {
                        normalized_identifier: b"dormant.member.o".to_vec(),
                        object_hash: "b".repeat(blake3::OUT_LEN * 2),
                    }],
                    active: false,
                    sections: vec![dormant_section],
                    relocations: vec![dormant_relocation],
                    symbol_resolutions: vec![dormant_resolution.clone()],
                    rollback_symbol_resolutions: vec![dormant_resolution],
                    forward_patches: vec![StoredOutputPatch {
                        output_offset: 512,
                        data: vec![5, 6, 7, 8],
                    }],
                    rollback_patches: vec![StoredOutputPatch {
                        output_offset: 512,
                        data: vec![0; 4],
                    }],
                },
            ],
            sections: Vec::new(),
            raw_sections: None,
        });

        let rendered = state.render();
        assert_eq!(PersistedState::parse(&rendered).unwrap(), state);

        let current_members = render_macho_archive_member_states(
            &state.input_files[0]
                .patch
                .as_ref()
                .unwrap()
                .macho_archive_members,
        );
        let mut incomplete_members = state.input_files[0]
            .patch
            .as_ref()
            .unwrap()
            .macho_archive_members
            .clone();
        incomplete_members[0].rollback_patches[0].output_offset += 1;
        let incomplete_members = render_macho_archive_member_states(&incomplete_members);
        assert!(
            parse_macho_archive_member_states(
                state.input_files[0].path.as_str(),
                &incomplete_members,
            )
            .unwrap_err()
            .to_string()
            .contains("transaction is incomplete")
        );
        let legacy_members = current_members
            .split(';')
            .map(|member| {
                let parts = member.split(':').collect::<Vec<_>>();
                assert_eq!(parts.len(), 8);
                [
                    parts[0], parts[1], parts[2], parts[3], parts[4], parts[6], parts[7],
                ]
                .join(":")
            })
            .collect::<Vec<_>>()
            .join(";");
        let mut expected_v43_members = state.input_files[0]
            .patch
            .as_ref()
            .unwrap()
            .macho_archive_members
            .clone();
        for member in &mut expected_v43_members {
            member.rollback_symbol_resolutions.clear();
        }
        assert_eq!(
            parse_macho_archive_member_states(state.input_files[0].path.as_str(), &legacy_members,)
                .unwrap(),
            expected_v43_members,
        );
    }

    #[test]
    fn persisted_state_round_trips_changed_macho_definition_ownership() {
        let mut state = state("args", b"output", &[("libarchive.rlib", b"archive")]);
        let resolution = MachOSymbolResolutionRecord {
            name: hex::encode("_added_private").into(),
            direct_value: Some(0x1000),
            got_address: None,
            stub_address: None,
            thunk_addresses: Vec::new(),
            target: Some(RelocationTargetRecord {
                input_file: hex::encode("libarchive.rlib").into(),
                input: hex::encode("member.o").into(),
                section_index: 1,
                section_offset: 4,
            }),
        };
        state.input_files[0].patch = Some(FilePatchState {
            fingerprint: "patch-hash".to_owned(),
            archive_member_set_proof: None,
            archive_member_patch_fingerprints: None,
            macho_archive_members: vec![MachOArchiveActivationState {
                kind: MachOArchiveActivationKind::ChangedDefinitions,
                members: vec![MachOArchiveMemberIdentity {
                    normalized_identifier: b"member.o".to_vec(),
                    object_hash: "a".repeat(blake3::OUT_LEN * 2),
                }],
                active: true,
                sections: Vec::new(),
                relocations: Vec::new(),
                symbol_resolutions: vec![resolution],
                rollback_symbol_resolutions: Vec::new(),
                forward_patches: vec![StoredOutputPatch {
                    output_offset: 256,
                    data: vec![1, 2, 3, 4],
                }],
                rollback_patches: vec![StoredOutputPatch {
                    output_offset: 256,
                    data: vec![0; 4],
                }],
            }],
            sections: Vec::new(),
            raw_sections: None,
        });

        let rendered = state.render();

        assert!(rendered.contains(&hex::encode("definitions|")));
        assert_eq!(PersistedState::parse(&rendered).unwrap(), state);

        let mut unwind_state = state.clone();
        let ownership = &mut unwind_state.input_files[0]
            .patch
            .as_mut()
            .unwrap()
            .macho_archive_members[0];
        ownership.kind = MachOArchiveActivationKind::ChangedDefinitionsWithUnwind;
        ownership.forward_patches.push(StoredOutputPatch {
            output_offset: 512,
            data: vec![5, 6, 7, 8],
        });
        ownership.rollback_patches.push(StoredOutputPatch {
            output_offset: 512,
            data: vec![0; 4],
        });
        let rendered = unwind_state.render();

        assert!(rendered.contains(&hex::encode("definitions-unwind|")));
        assert_eq!(PersistedState::parse(&rendered).unwrap(), unwind_state);
    }

