    #[test]
    fn macho_target_move_prefers_layout_aware_symbol_resolution() {
        let previous = test_macho_object(&[0; 4], &[0; 8], 0);
        let current = test_macho_object(&[0; 4], &[0; 8], 124);
        let mut state = state("args", b"output", &[("target.o", &previous)]);
        let input = state.input_files.remove(0);
        let raw_relocation = object::macho::RelocationInfo {
            r_address: 0,
            r_symbolnum: 0,
            r_pcrel: true,
            r_length: 2,
            r_extern: true,
            r_type: object::macho::ARM64_RELOC_BRANCH26,
        };
        let name = SharedText::from(hex::encode("_data"));
        let previous_target = RelocationTargetRecord {
            input_file: SharedText::from(hex::encode("target.o")),
            input: SharedText::from(hex::encode("target.o")),
            section_index: 2,
            section_offset: 0,
        };
        let current_target = RelocationTargetRecord {
            input: SharedText::from(hex::encode("current.o")),
            section_offset: 124,
            ..previous_target.clone()
        };
        let previous_value = 0x101b_24f0c;
        let provisional_value = previous_value + 124;
        let moved_value = 0x10e7_e18bc;
        let mut relocation = relocation_record(
            "target.o",
            1,
            42,
            Some(0),
            previous_value,
            Some("_data"),
            Some(("target.o", 2, 0)),
            0,
            300,
            4,
            encode_macho_aarch64_relocation_kind(raw_relocation),
            0,
        );
        relocation.input = hex::encode("caller.o").into();
        let mut relocations = [relocation];
        let patches = relocation_target_patches_for_input(&mut relocations, &input, &current)
            .unwrap()
            .unwrap();

        assert_eq!(patches.macho_target_moves.len(), 1);
        assert!(patches.output_symbols.is_empty());

        let moves = vec![MachOSymbolResolutionMove {
            name: name.clone(),
            previous_value,
            current_value: moved_value,
            previous_target: previous_target.clone(),
            current_target: current_target.clone(),
        }];

        let moved = matching_macho_symbol_resolution_move(
            &moves,
            name.as_str(),
            &previous_target,
            previous_value,
            124,
        )
        .unwrap()
        .unwrap();

        assert_ne!(provisional_value, moved.current_value);
        assert_eq!(moved.current_value, moved_value);
        assert_eq!(moved.current_target, current_target);
        let target_move = MachORelocationTargetMove {
            relocation_index: 0,
            current_section_offset: 124,
            current_target_value: provisional_value,
            current_input: None,
        };
        let (resolved_value, resolved_target) = resolved_macho_relocation_target(
            previous_value,
            Some(previous_target.clone()),
            Some(target_move.clone()),
            Some(moved),
        );
        assert_eq!(resolved_value, moved_value);
        assert_eq!(resolved_target, Some(current_target.clone()));

        let (provisional_value, provisional_target) = resolved_macho_relocation_target(
            previous_value,
            Some(previous_target.clone()),
            Some(target_move),
            None,
        );
        assert_eq!(provisional_value, previous_value + 124);
        assert_eq!(
            provisional_target,
            Some(RelocationTargetRecord {
                section_offset: 124,
                ..previous_target.clone()
            })
        );
        assert!(
            matching_macho_symbol_resolution_move(
                &moves,
                name.as_str(),
                &previous_target,
                previous_value,
                120,
            )
            .unwrap()
            .is_none()
        );

        let mut ambiguous = moves.clone();
        ambiguous.extend(moves);
        assert!(
            matching_macho_symbol_resolution_move(
                &ambiguous,
                name.as_str(),
                &previous_target,
                previous_value,
                124,
            )
            .is_err()
        );
    }

    #[test]
    fn macho_cross_input_branch_reuses_forwarding_target() {
        let previous = test_macho_object(&[0; 4], &[0; 8], 0);
        let current = test_macho_object(&[0; 4], &[0; 8], 4);
        let mut state = state("args", b"output", &[("target.o", &previous)]);
        let input = state.input_files.remove(0);
        let raw_relocation = object::macho::RelocationInfo {
            r_address: 0,
            r_symbolnum: 0,
            r_pcrel: true,
            r_length: 2,
            r_extern: true,
            r_type: object::macho::ARM64_RELOC_BRANCH26,
        };
        let previous_target_value = 0x2000;
        let current_target_value = 0x8000;
        let previous_target = RelocationTargetRecord {
            input_file: SharedText::from(hex::encode("target.o")),
            input: SharedText::from(hex::encode("target.o")),
            section_index: 2,
            section_offset: 0,
        };
        let current_target = RelocationTargetRecord {
            section_offset: 4,
            ..previous_target.clone()
        };
        let relocation = relocation_record(
            "caller.o",
            1,
            42,
            Some(0x1000),
            previous_target_value,
            Some("_data"),
            Some(("target.o", 2, 0)),
            0,
            300,
            4,
            encode_macho_aarch64_relocation_kind(raw_relocation),
            0,
        );
        let mut relocations = vec![relocation.clone()];
        let mut patches = relocation_target_patches_for_input(&mut relocations, &input, &current)
            .unwrap()
            .unwrap();

        assert!(patches.output_patches.is_empty());
        assert_eq!(patches.macho_cross_input_target_moves.len(), 1);
        assert_eq!(relocations[0].target_value, previous_target_value);
        let moved = MachOSymbolResolutionMove {
            name: SharedText::from(hex::encode("_data")),
            previous_value: previous_target_value,
            current_value: current_target_value,
            previous_target,
            current_target: current_target.clone(),
        };
        finish_macho_cross_input_target_moves(
            &mut relocations,
            &mut patches,
            std::slice::from_ref(&moved),
            &[MachOReusableBranchTarget {
                moved: moved.clone(),
                applied_target_value: previous_target_value,
            }],
            true,
            true,
            &input,
        )
        .unwrap()
        .unwrap();

        assert!(patches.output_patches.is_empty());
        assert!(patches.macho_cross_input_target_moves.is_empty());
        assert_eq!(relocations[0].written_value, Some(0x1000));
        assert_eq!(relocations[0].target_value, current_target_value);
        assert_eq!(
            relocations[0].applied_target_value,
            Some(previous_target_value)
        );
        assert_eq!(relocations[0].target.as_ref(), Some(&current_target));

        let recorded_thunk = 0x3000;
        let mut thunk_relocation = relocation.clone();
        thunk_relocation.applied_target_value = Some(recorded_thunk);
        let mut thunk_relocations = vec![thunk_relocation];
        let mut thunk_patches =
            relocation_target_patches_for_input(&mut thunk_relocations, &input, &current)
                .unwrap()
                .unwrap();
        finish_macho_cross_input_target_moves(
            &mut thunk_relocations,
            &mut thunk_patches,
            std::slice::from_ref(&moved),
            &[MachOReusableBranchTarget {
                moved: moved.clone(),
                applied_target_value: recorded_thunk,
            }],
            true,
            true,
            &input,
        )
        .unwrap()
        .unwrap();
        assert!(thunk_patches.output_patches.is_empty());
        assert_eq!(thunk_relocations[0].target_value, current_target_value);
        assert_eq!(
            thunk_relocations[0].applied_target_value,
            Some(recorded_thunk)
        );
        assert_eq!(thunk_relocations[0].target.as_ref(), Some(&current_target));

        let mut direct_relocations = vec![relocation];
        let mut direct_patches =
            relocation_target_patches_for_input(&mut direct_relocations, &input, &current)
                .unwrap()
                .unwrap();
        finish_macho_cross_input_target_moves(
            &mut direct_relocations,
            &mut direct_patches,
            &[],
            &[],
            false,
            true,
            &input,
        )
        .unwrap()
        .unwrap();
        assert_eq!(direct_patches.output_patches.len(), 1);
        assert_eq!(
            direct_relocations[0].target_value,
            previous_target_value + 4
        );
        assert_eq!(
            direct_relocations[0].applied_target_value,
            Some(previous_target_value + 4)
        );
    }

    #[test]
    fn macho_cross_input_target_lookup_rejects_duplicate_defined_names() {
        let mut bytes = test_macho_object(b"\0\0\0\0", b"\0\0\0\0", 0);
        const SYMTAB_COMMAND_OFFSET: usize = 32 + 72 + 2 * 80;
        let symoff = u32::from_le_bytes(
            bytes[SYMTAB_COMMAND_OFFSET + 8..SYMTAB_COMMAND_OFFSET + 12]
                .try_into()
                .unwrap(),
        ) as usize;
        let stroff = u32::from_le_bytes(
            bytes[SYMTAB_COMMAND_OFFSET + 16..SYMTAB_COMMAND_OFFSET + 20]
                .try_into()
                .unwrap(),
        ) as usize;
        let duplicate_symbol = bytes[symoff + 16..symoff + 32].to_vec();
        bytes.splice(stroff..stroff, duplicate_symbol);
        bytes[SYMTAB_COMMAND_OFFSET + 12..SYMTAB_COMMAND_OFFSET + 16]
            .copy_from_slice(&3_u32.to_le_bytes());
        bytes[SYMTAB_COMMAND_OFFSET + 16..SYMTAB_COMMAND_OFFSET + 20]
            .copy_from_slice(&((stroff + 16) as u32).to_le_bytes());
        let file = object::File::parse(bytes.as_slice()).unwrap();

        let result =
            unique_symbol_position_by_name(&bytes, 0, &file, &hex::encode(b"_data")).unwrap();

        assert!(matches!(
            result,
            Err(reason) if reason == "ambiguous cross-input Mach-O relocation target symbol"
        ));
        let data_name = SharedText::from(hex::encode(b"_data"));
        let indexed =
            indexed_unique_symbol_positions(&bytes, 0, &file, std::slice::from_ref(&data_name))
                .unwrap();
        assert!(matches!(
            indexed.get(&data_name),
            Some(IndexedSymbolPosition::Ambiguous)
        ));
    }

    #[test]
    fn indexed_macho_symbol_positions_omit_unrequested_names() {
        let bytes = test_macho_object(b"\0\0\0\0", b"\0\0\0\0", 0);
        let file = object::File::parse(bytes.as_slice()).unwrap();
        let data_name = SharedText::from(hex::encode(b"_data"));
        let text_name = SharedText::from(hex::encode(b"_text"));

        let indexed =
            indexed_unique_symbol_positions(&bytes, 0, &file, std::slice::from_ref(&data_name))
                .unwrap();

        assert_eq!(indexed.len(), 1);
        assert!(matches!(
            indexed.get(&data_name),
            Some(IndexedSymbolPosition::Unique(_))
        ));
        assert!(!indexed.contains_key(&text_name));
    }

    #[test]
    fn cstring_patches_require_stable_literal_boundaries() {
        assert!(cstring_literal_boundaries_are_stable(
            b"first\0second\0",
            b"FIRST\0SECOND\0"
        ));
        assert!(!cstring_literal_boundaries_are_stable(
            b"first\0second\0",
            b"first second\0"
        ));
        assert!(!cstring_literal_boundaries_are_stable(
            b"first\0",
            b"first\0\0"
        ));
        assert_eq!(
            cstring_nul_boundaries_hash(b"first\0second\0"),
            cstring_nul_boundaries_hash(b"FIRST\0SECOND\0")
        );
        assert_ne!(
            cstring_nul_boundaries_hash(b"first\0second\0"),
            cstring_nul_boundaries_hash(b"first second\0")
        );
    }

    #[test]
    fn build_id_hash_tree_matches_full_hash() {
        for len in [
            BUILD_ID_HASH_GROUP_LEN + 1,
            2 * BUILD_ID_HASH_GROUP_LEN,
            2 * BUILD_ID_HASH_GROUP_LEN + 17,
            5 * BUILD_ID_HASH_GROUP_LEN + 100,
        ] {
            let output = (0..len).map(|i| (i % 251) as u8).collect::<Vec<_>>();
            let build_id_range = 100..148;
            let nodes = build_id_hash_node_count(output.len()).unwrap();
            let tree = build_id_hash_tree(&output, &build_id_range).unwrap();
            let state = BuildIdHashState {
                output_len: output.len() as u64,
                nodes,
                tree_hash: Some(build_id_hash_tree_hash(&tree)),
            };
            let mut expected = output;
            expected[build_id_range].fill(0);

            assert_eq!(tree.len(), nodes);
            assert_eq!(
                build_id_from_hash_tree(&state, &tree).unwrap(),
                blake3::hash(&expected)
            );
        }
    }

    #[test]
    fn build_id_hash_tree_updates_changed_chunks() {
        let mut output = (0..5 * BUILD_ID_HASH_GROUP_LEN + 100)
            .map(|i| (i % 251) as u8)
            .collect::<Vec<_>>();
        let build_id_range = 1500..1548;
        let nodes = build_id_hash_node_count(output.len()).unwrap();
        let mut tree = build_id_hash_tree(&output, &build_id_range).unwrap();
        let mut state = BuildIdHashState {
            output_len: output.len() as u64,
            nodes,
            tree_hash: Some(build_id_hash_tree_hash(&tree)),
        };

        let changed_range = 2 * BUILD_ID_HASH_GROUP_LEN + 100..2 * BUILD_ID_HASH_GROUP_LEN + 110;
        output[changed_range.clone()].copy_from_slice(b"0123456789");
        let changed_chunks = touched_build_id_chunks(&[changed_range], output.len()).unwrap();
        assert!(update_build_id_hash_tree(
            &mut state,
            &mut tree,
            &output,
            &build_id_range,
            &changed_chunks,
        ));
        let mut expected = output;
        expected[build_id_range].fill(0);

        assert_eq!(
            build_id_from_hash_tree(&state, &tree).unwrap(),
            blake3::hash(&expected)
        );
        assert_eq!(
            state.tree_hash.as_deref(),
            Some(build_id_hash_tree_hash(&tree).as_str())
        );
    }

    #[test]
    #[cfg_attr(target_os = "wasi", ignore = "wasi doesn't have a temp dir")]
    fn build_id_hash_tree_must_match_state_hash() {
        let dir = tempfile::tempdir().unwrap();
        let output_len = 5 * BUILD_ID_HASH_GROUP_LEN + 100;
        let nodes = build_id_hash_node_count(output_len).unwrap();
        let tree = vec![[1; blake3::OUT_LEN]; nodes];
        write_build_id_hash_tree(dir.path(), Some(&tree)).unwrap();
        let state = BuildIdHashState {
            output_len: output_len as u64,
            nodes,
            tree_hash: Some("wrong-hash".to_owned()),
        };

        let error = read_build_id_hash_tree(dir.path(), &state).unwrap_err();

        assert!(
            error
                .to_string()
                .contains("does not match its recorded hash")
        );
    }

    #[test]
    fn try_reuse_section_requires_unchanged_input_and_matching_record() {
        let mut input_file = crate::input_data::InputFile::for_testing();
        input_file.filename = PathBuf::from("a.o");
        let input = InputRef {
            file: &input_file,
            entry: None,
        };
        let record = SectionRecord::new(input, object::SectionIndex(3), 64, 16);
        let state = PreparedState {
            mode: IncrementalMode::Relink {
                reason: "input file changed: b.o".to_owned(),
                can_reuse_unchanged_sections: true,
            },
            current: CurrentState {
                state_dir: PathBuf::new(),
                args_hash: "args".to_owned(),
                link_options_hash: "args".to_owned(),
                input_order_hash: String::new(),
                sld_version: "sld-test".to_owned(),
                link_start: None,
                input_files: Vec::new(),
            },
            retained_output_to_restore: None,
            reusable_inputs: [encode_path(Path::new("a.o"))].into_iter().collect(),
            reusable_changed_sections: HashSet::new(),
            previous_sections: [record].into_iter().collect(),
            previous_relocations: Vec::new(),
            previous_macho_symbol_resolutions_file: None,
            previous_fdes: Vec::new(),
            previous_dynamic_relocations: Vec::new(),
            previous_reserved_ranges: Vec::new(),
            current_sections: RecordBuffers::default(),
            current_relocations: RecordBuffers::default(),
            current_macho_symbol_resolutions: RecordBuffers::default(),
            current_fdes: RecordBuffers::default(),
            current_dynamic_relocations: RecordBuffers::default(),
            current_reserved_ranges: RecordBuffers::default(),
            record_texts: RecordTextInterner::default(),
            reused_sections: AtomicUsize::new(0),
            prepared_fast_build_id_state: Mutex::new(None),
        };

        assert!(state.try_reuse_section(input, object::SectionIndex(3), 64, 16, true, true));
        assert!(!state.try_reuse_section(input, object::SectionIndex(3), 80, 16, true, true));
        assert_eq!(state.reused_sections.load(Ordering::Relaxed), 1);
        assert_eq!(state.current_sections.take_all().len(), 2);
    }

